namespace Wolf.Core
{
	public class ClosedCaptionsLanguagesDetector : Java.Lang.Object, IClosedCaptionsLanguagesDetector, IPlayerEventListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private TaskCompletionSource<bool> tracksTcs;

		public async Task<bool> CurrentVideoHasCaptions(ICombinedAudioVideoPlayer videoPlayer)
		{
			CombinedAudioVideoPlayer combinedAudioVideoPlayer = videoPlayer as CombinedAudioVideoPlayer;
			if (combinedAudioVideoPlayer?.VideoPlayer == null)
			{
				return false;
			}
			tracksTcs = new TaskCompletionSource<bool>();
			SimpleExoPlayer videoPlayer2 = combinedAudioVideoPlayer.VideoPlayer;
			videoPlayer2.AddListener(this);
			return await tracksTcs.Task;
		}

		public void OnTracksChanged(TrackGroupArray trackGroups, TrackSelectionArray trackSelections)
		{
			TaskCompletionSource<bool> taskCompletionSource = tracksTcs;
			tracksTcs = null;
			bool result = trackGroups.Length >= 3;
			taskCompletionSource?.TrySetResult(result);
		}

		public void OnEvents(IPlayer player, PlayerEvents events)
		{
		}

