namespace Wolf.Core.Converters
{
	public class INCListNullVisibilityGoneValueConverter<T> : MvxValueConverter<INCList<T>, ViewStates>
	{
		protected override ViewStates Convert(INCList<T> value, Type targetType, object parameter, CultureInfo culture)
		{
			if (value?.Value != null)
			{
				return ViewStates.Visible;
			}
			return ViewStates.Gone;
		}
	}
}
