	public class IfitFragmentPagerAdapter : FragmentPagerAdapter
	{
		private readonly List<AndroidX.Fragment.App.Fragment> fragments;

		public override int Count => fragments.Count;

		public IfitFragmentPagerAdapter(AndroidX.Fragment.App.FragmentManager fragmentManager, List<AndroidX.Fragment.App.Fragment> fragments)
			: base(fragmentManager)
		{
			this.fragments = fragments;
		}

		public override Java.Lang.Object InstantiateItem(ViewGroup container, int position)
		{
			container.Tag = fragments[position].Id;
			return base.InstantiateItem(container, position);
		}

		public override AndroidX.Fragment.App.Fragment GetItem(int position)
		{
			return fragments[position];
		}

		public override void DestroyItem(ViewGroup container, int position, Java.Lang.Object @object)
		{
			try
			{
				container.RemoveView((View)container.GetChildAt(position).Tag);
			}
			catch (Java.Lang.Exception)
			{
			}
		}

		public void AddAdapterData(AndroidX.Fragment.App.Fragment fragment)
		{
			fragments.Add(fragment);
			NotifyDataSetChanged();
		}
	}
	public class InWorkoutLineChart : BaseLineChart
	{
		public InWorkoutLineChart(Context context)
			: base(context)
		{
		}

		public override void InitializeChartView()
		{
			base.InitializeChartView();
			base.LineChart.AxisRight.SetLabelCount(6, force: false);
			base.LineChart.AxisRight.SetDrawTopYLabelEntry(enabled: true);
		}

		public YAxis.AxisDependency GetMetricAxis(bool isLeft)
		{
			if (!isLeft)
			{
				return YAxis.AxisDependency.Right;
			}
			return YAxis.AxisDependency.Left;
		}

		public void StyleAxisLabels(AxisBase axis)
		{
			axis.TextSize = 14f;
			axis.TextColor = Colors.Named575A5C.ToNative();
			axis.Typeface = IfitTypeface.GetCustomTypeface(IfitTypeface.Type.ProximaRegular);
		}

		public void StyleAxisLabels(AxisBase axis, global::Android.Graphics.Color color)
		{
			axis.TextSize = 14f;
			axis.TextColor = color;
			axis.Typeface = IfitTypeface.GetCustomTypeface(IfitTypeface.Type.ProximaRegular);
		}

		public void StyleCurrentValue(LineDataSet set, ChartMetricConfiguration config)
		{
			if (config != null)
			{
				set.SetColor(global::Android.Graphics.Color.Transparent, global::Android.Graphics.Color.Transparent.A);
				set.CircleRadius = 10f;
				set.CircleHoleRadius = 4f;
				set.SetDrawValues(enabled: false);
				set.SetCircleColor(config.CircleColor.ToNative());
				set.SetCircleColorHole(config.LineColor.ToNative());
			}
		}

		public void StyleMetric(LineDataSet set, ChartMetricConfiguration config)
		{
			if (config != null)
			{
				global::Android.Graphics.Color color = config.LineColor.ToNative();
				int lineWidth = (config.IsPredictedLine ? 2 : 4);
				switch (config.RenderStyle)
				{
				case ChartRenderType.Filled:
					StyleFilledDataSet(set, color);
					break;
				case ChartRenderType.Stepped:
					StyleSteppedDataSet(set, color, lineWidth);
					break;
				default:
					StyleDefaultDataSet(set, color, lineWidth);
					break;
				}
			}
		}

		private void StyleSteppedDataSet(LineDataSet set, global::Android.Graphics.Color color, int lineWidth)
		{
			set.SetColor(color, color.A);
			set.SetMode(LineDataSet.Mode.Stepped);
			set.SetDrawCircles(enabled: false);
			set.SetDrawValues(enabled: false);
			set.LineWidth = lineWidth;
			if (set is StrokeCapJoinLineDataSet strokeCapJoinLineDataSet)
			{
				strokeCapJoinLineDataSet.StrokeCap = Paint.Cap.Square;
			}
		}

		private void StyleDefaultDataSet(LineDataSet set, global::Android.Graphics.Color color, int lineWidth)
		{
			set.SetColor(color, color.A);
			set.SetDrawCircles(enabled: false);
			set.SetDrawValues(enabled: false);
			set.LineWidth = lineWidth;
		}

		private void StyleFilledDataSet(LineDataSet set, global::Android.Graphics.Color color)
		{
			set.SetColor(color, color.A);
			set.FillColor = color;
			set.FillAlpha = color.A;
			set.FillFormatter = new CustomChartFillFormatter();
			set.SetDrawFilled(filled: true);
			set.SetDrawCircles(enabled: false);
			set.SetDrawValues(enabled: false);
		}
	}
