	public class FeatureFlagVisibilityConverter : MvxValueConverter<bool, ViewStates>
	{
		private readonly FeatureFlag _flag;

		private readonly IFeatureFlagManager featureFlagManager;

		public FeatureFlagVisibilityConverter(FeatureFlag flag, IFeatureFlagManager featureFlagManager)
		{
			_flag = flag;
			this.featureFlagManager = featureFlagManager;
		}

		protected override ViewStates Convert(bool value, Type targetType, object parameter, CultureInfo culture)
		{
			if (!value || !featureFlagManager.IsFeatureEnabled(_flag))
			{
				return ViewStates.Gone;
			}
			return ViewStates.Visible;
		}
	}
	public class MapViewVisibilityConverter : MvxValueConverter<MapView, ViewStates>
	{
		private MapView _displayMapViews;

		public MapViewVisibilityConverter(MapView displayMapViews)
		{
			_displayMapViews |= displayMapViews;
		}

		protected override ViewStates Convert(MapView value, Type targetType, object parameter, CultureInfo culture)
		{
			if ((_displayMapViews & value) != 0)
			{
				return ViewStates.Visible;
			}
			return ViewStates.Gone;
		}
	}
