	internal class ToolBoxModeDisplayConverter : MvxValueConverter<DrawMapViewModel.ToolBoxMode, ViewStates>
	{
		protected override ViewStates Convert(DrawMapViewModel.ToolBoxMode value, Type targetType, object parameter, CultureInfo culture)
		{
			switch (value)
			{
			case DrawMapViewModel.ToolBoxMode.Small:
				if (!(parameter is DrawMapSearchBar))
				{
					return ViewStates.Gone;
				}
				return ViewStates.Visible;
			case DrawMapViewModel.ToolBoxMode.Large:
				if (!(parameter is DrawMapToolBox))
				{
					return ViewStates.Gone;
				}
				return ViewStates.Visible;
			case DrawMapViewModel.ToolBoxMode.Sidebar:
				if (!(parameter is DrawMapLeftMenu))
				{
					return ViewStates.Gone;
				}
				return ViewStates.Visible;
			default:
				return ViewStates.Gone;
			}
		}
	}
