	public class DeviceInformation : BaseDeviceInformation, IDeviceInformation
	{
		private const float AndroidDensityCoefficient = 160f;

		private const double TabletInchesThreshold = 6.9;

		private const int BytesInKilobyte = 1024;

		private const string Tag = "DeviceInformation";

		private readonly string[] edgeCaseTabletModels = new string[2] { "Lenovo TB-8504F", "Lenovo TB-X104F" };

		private IBlobCacheService cacheService;

		private ActivityManager activityManager;

		private ActivityManager.MemoryInfo memoryInfo;

		private bool _isStrengthMirror;

		private bool _isBuiltIn;

		private string _lastBuiltInOSVersion;

		private int? _latestSoftwareNumber;

		private int _buildNumber;

		private bool _forceHeadlessBike;

		public bool IsTablet { get; }

		public double DisplaySizeInches { get; private set; }

		public override double DisplayWidthPixels => Resources.System.DisplayMetrics.WidthPixels;

		public override double DisplayHeightPixels => Resources.System.DisplayMetrics.HeightPixels;

		public string DeviceName { get; }

		public double? FontScale
		{
			get
			{
				if (Resources.System?.Configuration == null)
				{
					return null;
				}
				return System.Math.Round((Resources.System.Configuration?.FontScale).Value, 2);
			}
		}

		public int? DpiDensity => (int?)Resources.System?.DisplayMetrics?.DensityDpi;

		public long TotalMemory { get; }

		public long AvailableMemory => GetAvailableMemory();

		public long LowMemoryThreshold => GetLowMemoryThreshold();

		public bool IsStrengthMirror
		{
			get
			{
				return _isStrengthMirror;
			}
			set
			{
				if (_isStrengthMirror != value)
				{
					_isStrengthMirror = value;
					if (cacheService != null || Mvx.TryResolve<IBlobCacheService>(out cacheService))
					{
						cacheService?.Flush(_isStrengthMirror, "_isStrengthMirror", "DeviceInformation");
					}
				}
			}
		}

		public bool UseHeadlessBikeTheme { get; set; }

		public bool IsBuiltIn
		{
			get
			{
				return _isBuiltIn;
			}
			set
			{
				if (_isBuiltIn != value)
				{
					_isBuiltIn = value;
					if (cacheService != null || Mvx.TryResolve<IBlobCacheService>(out cacheService))
					{
						cacheService?.Flush(_isBuiltIn, "_isBuiltIn", "DeviceInformation");
					}
				}
			}
		}

		public BuiltInType BuiltInType { get; set; }

		public int ScreenWidth { get; set; }

		public int ScreenHeight { get; set; }

		public int PixelScreenWidth { get; set; }

		public int PixelScreenHeight { get; set; }

		public int PixelSafeAreaWidth { get; set; }

		public int PixelSafeAreaHeight { get; set; }

		public float ScreenPixelDensity { get; set; }

		public int WolfDefaultSoftwareNumber => 424992;

		public int HeadlessBikeVaultSoftwareNumber => 439110;

		public int? SpoofedSoftwareNumber { get; set; }

		public int SoftwareNumber => SpoofedSoftwareNumber ?? LatestSoftwareNumber ?? WolfDefaultSoftwareNumber;

		public bool IsHeadlessBikeVault => SoftwareNumber == HeadlessBikeVaultSoftwareNumber;

		public string LastBuiltInOSVersion
		{
			get
			{
				return _lastBuiltInOSVersion;
			}
			set
			{
				if (value == null || !value.Equals(_lastBuiltInOSVersion))
				{
					_lastBuiltInOSVersion = value;
					if (cacheService != null || Mvx.TryResolve<IBlobCacheService>(out cacheService))
					{
						cacheService?.Flush(_lastBuiltInOSVersion, "_lastBuiltInOSVersion", "DeviceInformation");
					}
				}
			}
		}

		public int? LatestSoftwareNumber
		{
			get
			{
				return SpoofedSoftwareNumber ?? _latestSoftwareNumber;
			}
			set
			{
				if (_latestSoftwareNumber != value)
