		public DeviceInformation(Application application)
		{
			DeviceName = Build.Model;
			double num = DetermineDiagonalInches();
			IsTablet = Shire.Android.Util.DeviceInfo.IsBuiltIn() || num >= 6.9;
			activityManager = application.GetSystemService("activity") as ActivityManager;
			memoryInfo = new ActivityManager.MemoryInfo();
			activityManager?.GetMemoryInfo(memoryInfo);
			TotalMemory = memoryInfo.TotalMem / 1024;
		}

		public void LoadFromCache()
		{
			cacheService = Mvx.Resolve<IBlobCacheService>();
			_lastBuiltInOSVersion = cacheService.GetFromCache<string>("_lastBuiltInOSVersion", "DeviceInformation").Result;
			_latestSoftwareNumber = cacheService.GetFromCache<int?>("_latestSoftwareNumber", "DeviceInformation").Result;
			_buildNumber = cacheService.GetFromCache("_buildNumber", "DeviceInformation", "", temp: false, 0).Result;
			_numberOfWorkouts = cacheService.GetFromCache("_numberOfWorkouts", "DeviceInformation", "", temp: false, 0u).Result;
			_isBuiltIn = cacheService.GetFromCache("_isBuiltIn", "DeviceInformation", "", temp: false, defaultValue: false).Result;
			_isStrengthMirror = cacheService.GetFromCache("_isStrengthMirror", "DeviceInformation", "", temp: false, defaultValue: false).Result;
			_forceHeadlessBike = cacheService.GetFromCache("_forceHeadlessBike", "DeviceInformation", "", temp: false, defaultValue: false).Result;
		}

		private double DetermineDiagonalInches()
		{
			if (Resources.System?.DisplayMetrics == null)
			{
				return 0.0;
			}
			DisplayMetrics displayMetrics = Resources.System.DisplayMetrics;
			float num = displayMetrics.Density * 160f;
			float num2 = (float)displayMetrics.HeightPixels / num;
			float num3 = (float)displayMetrics.WidthPixels / num;
			double num4 = System.Math.Sqrt(num3 * num3 + num2 * num2);
			float num5 = (float)displayMetrics.HeightPixels / displayMetrics.Ydpi;
			float num6 = (float)displayMetrics.WidthPixels / displayMetrics.Xdpi;
			DisplaySizeInches = System.Math.Sqrt(num6 * num6 + num5 * num5);
			if (num4 > 6.9 != DisplaySizeInches > 6.9)
			{
				string text = "There is a significant difference in calculated display sizes - " + string.Format("{0}: {1}in, {2}: {3}in. ", "overallDensitySize", num4, "DisplaySizeInches", DisplaySizeInches) + "This might cause the device to be classified incorrectly (tablet vs phone). The model is " + DeviceName;
				iFit.Logger.Log.Warn("DeviceInformation", text);
			}
			iFit.Logger.Log.Trace("DeviceInformation", $"Display Size: {DisplaySizeInches} in");
			iFit.Logger.Log.Trace("DeviceInformation", $"Overall Density Size: {num4} in");
			iFit.Logger.Log.Trace("DeviceInformation", $"Width Pixels: {displayMetrics.WidthPixels} px");
			iFit.Logger.Log.Trace("DeviceInformation", $"Height Pixels: {displayMetrics.HeightPixels} px");
			iFit.Logger.Log.Trace("DeviceInformation", $"Screen Density DPI - {(int)displayMetrics.DensityDpi}dpi {displayMetrics.DensityDpi}");
			if (edgeCaseTabletModels.Contains(Shire.Android.Util.DeviceInfo.GetModel()))
			{
				iFit.Logger.Log.Trace("DeviceInformation", "This tablet is included in the hard coded list of tablets so we are returning the screen size as the tablet threshold");
				return 6.9;
			}
			return System.Math.Sqrt(num6 * num3 + num5 * num2);
		}

		public void LogDeviceInfo()
		{
			iFit.Logger.Log.Trace("DeviceInformation", "******************* LOGGING ANDROID DEVICE INFO *****************");
			iFit.Logger.Log.Trace("DeviceInformation", "Manufacturer - " + Shire.Android.Util.DeviceInfo.GetManufacturer());
			iFit.Logger.Log.Trace("DeviceInformation", "Display - " + Shire.Android.Util.DeviceInfo.GetDisplay());
			iFit.Logger.Log.Trace("DeviceInformation", "Board - " + Shire.Android.Util.DeviceInfo.GetBoard());
			iFit.Logger.Log.Trace("DeviceInformation", "Product - " + Shire.Android.Util.DeviceInfo.GetProduct());
			iFit.Logger.Log.Trace("DeviceInformation", "Model - " + Shire.Android.Util.DeviceInfo.GetModel());
			DetermineDiagonalInches();
			iFit.Logger.Log.Trace("DeviceInformation", $"Font scale - {FontScale}");
			iFit.Logger.Log.Trace("DeviceInformation", "******************* DONE LOGGING ANDROID DEVICE INFO *****************");
		}

