	public class PermissionsActivity : AppCompatActivity
	{
		private readonly TaskCompletionSource<bool> permissionRequest = new TaskCompletionSource<bool>();

		private string[] Permissions { get; set; }

		protected override void OnCreate(Bundle savedInstanceState)
		{
			if (Shire.Android.Util.DeviceInfo.IsStrengthMirrorUnit)
			{
				((Context)(object)this).SetTheme(2132017617);
			}
			Permissions = GetRequiredPermissions();
			System.Threading.Tasks.Task.Run(async delegate
			{
				TimedEvent timedEvent = await EventService.Instance.CreateAsync("App Launch Time").ConfigureAwait(continueOnCapturedContext: false);
				if (timedEvent != null)
				{
					timedEvent.Properties["previouslyAcceptedPermissions"] = PermissionsGranted(Permissions);
				}
				else
				{
					iFit.Logger.Log.Trace("Startup", "App start event was null");
				}
			});
			((Activity)(object)this).OnCreate(savedInstanceState);
			RequestAllPermissions();
			Platform.Init((Activity)(object)this, savedInstanceState);
		}

		protected override void OnNewIntent(Intent intent)
		{
			((Activity)(object)this).OnNewIntent(intent);
			ActivityMediator.Instance.Send(intent.DataString);
			((Activity)(object)this).Intent = intent;
		}

		private bool PermissionsGranted(string[] permissions)
		{
			if (Build.VERSION.SdkInt < BuildVersionCodes.M || permissions == null)
			{
				return true;
			}
			return permissions.All((string x) => ContextCompat.CheckSelfPermission((Context)(object)this, x) == Permission.Granted);
		}

		private string[] GetRequiredPermissions()
		{
			if (!Shire.Android.Util.DeviceInfo.IsBuiltIn())
			{
				return new string[0];
			}
			return new string[4] { "android.permission.WRITE_EXTERNAL_STORAGE", "android.permission.READ_EXTERNAL_STORAGE", "android.permission.ACCESS_FINE_LOCATION", "android.permission.ACCESS_COARSE_LOCATION" };
		}

		private void RequestAllPermissions()
		{
			System.Threading.Tasks.Task.Run(async delegate
			{
				bool wasGranted = await permissionRequest.Task;
				((Activity)(object)this).RunOnUiThread((System.Action)delegate
				{
					if (!wasGranted)
					{
						Toast.MakeText((Context)(object)this, Wolf.Core.Resources.AppStrings.permissions_required, ToastLength.Long).Show();
					}
					else
					{
						Intent intent = new Intent((Context)(object)this, typeof(SplashScreen));
						if (((Activity)(object)this).Intent.Data != null && "ifitcardio".StartsWith(((Activity)(object)this).Intent.Data.Scheme.ToLowerInvariant()) && !((Activity)(object)this).Intent.Flags.HasFlag(ActivityFlags.LaunchedFromHistory))
						{
							intent.PutExtra("DeepLinkIntentKey", ((Activity)(object)this).Intent.Data.ToString());
						}
						((Context)(object)this).StartActivity(intent);
					}
					((Activity)(object)this).Finish();
				});
			});
			RequestPermission();
		}

		private void RequestPermission()
		{
			if (PermissionsGranted(Permissions))
			{
				permissionRequest.TrySetResult(result: true);
			}
			else if (Permissions.Any(((Activity)(object)this).ShouldShowRequestPermissionRationale))
			{
				Snackbar.Make(((Activity)(object)this).FindViewById(16908290), Wolf.Core.Resources.AppStrings.permissions_required, -2).SetAction(Wolf.Core.Resources.AppStrings.ok.ToUpper(), delegate
				{
					ActivityCompat.RequestPermissions((Activity)(object)this, Permissions, 2346);
				}).Show();
			}
			else
			{
				ActivityCompat.RequestPermissions((Activity)(object)this, Permissions, 2346);
			}
		}

		public override void OnRequestPermissionsResult(int requestCode, string[] permissions, Permission[] grantResults)
		{
			((Activity)(object)this).OnRequestPermissionsResult(requestCode, permissions, grantResults);
			if (requestCode == 2346 && grantResults.CountSafe() != 0)
			{
				bool flag = grantResults?.All((Permission x) => x >= Permission.Granted) ?? false;
				permissionRequest.TrySetResult(flag);
				iFit.Logger.Log.Trace("Settings", "Obtaining permissions was " + (flag ? "successful" : "unsuccessful"));
			}
		}

		protected override void OnResume()
		{
			((Activity)(object)this).OnResume();
			iFit.Logger.Log.Trace("Navigation", "Checking for deep link");
			DeepLinkService.TryHandlingDeepLink(((Activity)(object)this).Intent);
		}
	}
