				Mvx.RegisterSingleton((IMediaSourceEventListener)androidMediaAnalyticsService.MediaSourceEventListener);
				Mvx.RegisterSingleton((IPlayerEventListener)androidMediaAnalyticsService.PlayerEventListener);
				Mvx.RegisterSingleton((IVideoListener)androidMediaAnalyticsService.VideoListener);
				iFit.Logger.Log.Trace("Startup", "Registering VideoSyncService");
				Mvx.LazyConstructAndRegisterSingleton<IVideoSyncService, VideoSyncService>();
				Mvx.RegisterSingleton((IAppLinking)AppLinkingService.Instance);
				Mvx.ConstructAndRegisterSingleton<IAppDeepLinks, AppDeepLinks>();
				Mvx.LazyConstructAndRegisterSingleton<IWebAuthenticatorService, WebAuthenticatorService>();
				iFit.Logger.Log.Trace("Startup", "Registering AndroidThemeService");
				AndroidThemeService service13 = Mvx.IocConstruct<AndroidThemeService>();
				Mvx.RegisterSingleton((IAndroidThemeService)service13);
				Mvx.RegisterSingleton((IThemeService)service13);
				if (Mvx.Resolve<ICurrentConsoleService>().IsBuiltinClub && Mvx.TryResolve<IFeatureFlagManager>(out var service14))
				{
					service14.SetBoolFlagTemporarily(FeatureFlags.EmbeddedBluetoothHeadphoneFeature, enable: true);
				}
				Mvx.ConstructAndRegisterSingleton<IRetailDemoLocalWorkoutService, RetailDemoLocalWorkoutService>();
				await CommonWolfAppSetup.SharedFinalSetup();
				Mvx.RegisterType<HeadphoneDeviceFilterBase, HeadphoneDeviceFilter>();
				Mvx.RegisterType<IHeadphoneScanner, HeadphoneScanner>();
				Mvx.ConstructAndRegisterSingleton<HeadphoneConnectionHelperBase, WolfHeadphoneConnectionHelper>();
				Mvx.RegisterType<IAndroidActivityLifetimeFocusService, AndroidActivityLifetimeFocusService>();
				Mvx.TryResolve<ILaunchBehaviorService>(out var service15);
				RunNecessaryPlatformLaunchBehaviors(settings, service15);
				Mvx.TryResolve<IAppFinishedStartup>(out var service16);
				service16.FinishedStartUp();
				iFit.Logger.Log.Trace("Startup", "Wolf app setup complete");
			}
			catch (SQLiteException exception)
			{
				iFit.Logger.Log.Fatal("Startup", "SQLiteException when trying to initialize: {0}", exception);
				blobCacheFileManager?.NukeSQLDB();
				JavaSystem.Exit(0);
			}
			catch (System.Exception ex)
			{
				iFit.Logger.Log.Error("Startup", "Exception in Wolf App Setup", ex);
				iFit.Logger.Log.Error("Startup", ex.StackTrace);
			}
			static bool EnableBasedOnFeatureFlagUriString(string uri)
			{
				if (string.IsNullOrEmpty(uri))
				{
					return true;
				}
				System.Uri result;
				return System.Uri.TryCreate(uri, UriKind.Absolute, out result);
			}
		}

		private static void RunNecessaryPlatformLaunchBehaviors(ILocalSettings settings, ILaunchBehaviorService launchBehaviorService)
		{
			CommonWolfAppSetup.RunAndSetLaunchBehaviorIfNecessary(settings, launchBehaviorService, LaunchBehaviorFlag.DefaultSystemVolumeApplication, SetInitialSystemVolumeIfNecessary);
		}

		public IIfitEnvironment DetermineEnvironment(IRaygunInfo raygunInfo, ILocalSettings localSettings)
		{
			IIfitEnvironment ifitEnvironment;
			switch (localSettings.EnvironmentToUse)
			{
			case Environments.Prod:
				ifitEnvironment = new WolfProdAndroidEnvironment(raygunInfo);
				iFit.Logger.Log.Trace("Startup", "Using Android Prod environment.");
				break;
			case Environments.Test:
				ifitEnvironment = new WolfTestAndroidEnvironment(raygunInfo);
				iFit.Logger.Log.Trace("Startup", "Using Android Test environment.");
				break;
			case Environments.Dev:
				ifitEnvironment = new WolfDevAndroidEnvironment(raygunInfo);
				iFit.Logger.Log.Trace("Startup", "Using Android Dev environment.");
				break;
			default:
				ifitEnvironment = new WolfTestAndroidEnvironment(raygunInfo);
				if (!string.IsNullOrEmpty(localSettings.CustomApiUrl))
				{
					ifitEnvironment.ConfigureViperSettings(localSettings.CustomApiUrl);
					iFit.Logger.Log.Trace("Startup", "Overwriting environment with CustomApi: " + localSettings.CustomApiUrl);
				}
				else
				{
					iFit.Logger.Log.Error("Startup", "ERROR: No Api specified. Defaulting to Test.");
				}
				break;
			}
			return ifitEnvironment;
		}

		private static void SetInitialSystemVolumeIfNecessary(ILocalSettings settings)
		{
			IPlatformMediaVolumeService platformMediaVolumeService = null;
			if (Mvx.TryResolve<IPlatformMediaVolumeService>(out var service))
			{
				platformMediaVolumeService = service;
				iFit.Logger.Log.Trace("Startup", "IPlatformMediaVolumeService resolved.");
			}
			Mvx.TryResolve<ICurrentConsoleService>(out var service2);
			Mvx.TryResolve<IDeviceInformation>(out var service3);
			Mvx.TryResolve<IMediaSettings>(out var service4);
			if (!service3.IsBuiltIn && !service3.IsStrengthMirror)
			{
				return;
			}
			Mvx.TryResolve<IVolumeFacade>(out var service5);
			InWorkoutSystemVolumeInteractor inWorkoutSystemVolumeInteractor = new InWorkoutSystemVolumeInteractor(service2, service3, service4, platformMediaVolumeService, service5, 200L);
			iFit.Logger.Log.Trace("Startup", string.Format("Attempting to set initial media volume level to {0}/100 with {1}...", 50, "IInWorkoutSystemVolumeInteractor"));
			inWorkoutSystemVolumeInteractor.SetConsoleVolume(50);
			if (inWorkoutSystemVolumeInteractor.IsProcessingVolumeChanges)
			{
				iFit.Logger.Log.Trace("Startup", "inWorkoutSystemVolumeInteractor is attempting to set console volume asynchronously...");
				inWorkoutSystemVolumeInteractor.WhenVolumeChangeCompleted.Take(1).SubscribeWithErrorLogging(delegate(bool result)
				{
					iFit.Logger.Log.Trace("Startup", string.Format("{0} fired {1}: {2}", "inWorkoutSystemVolumeInteractor", "WhenVolumeChangeCompleted", result));
					inWorkoutSystemVolumeInteractor?.Dispose();
					inWorkoutSystemVolumeInteractor = null;
				});
			}
			else
			{
				iFit.Logger.Log.Trace("Startup", "inWorkoutSystemVolumeInteractor updated volume synchronously.");
				inWorkoutSystemVolumeInteractor.Dispose();
			}
		}

