		private static void CheckStrengthMirrorConfig(IDeviceInformation deviceInformation, IStrengthMirrorFileService strengthMirrorFileService, ICurrentConsoleService currentConsoleService)
		{
			if (strengthMirrorFileService != null && strengthMirrorFileService.IsConfigDisabled)
			{
				if (!Shire.Android.Util.DeviceInfo.IsStrengthMirrorUnit)
				{
					iFit.Logger.Log.Trace("Startup", string.Format("Strength Mirror config explicitly set as inactive, setting {0}={1}", "IsStrengthMirror", deviceInformation.IsStrengthMirror));
					return;
				}
				iFit.Logger.Log.Trace("Startup", "Strength Mirror config explicitly set as inactive, but this is a strength mirror. Rebuilding the .activeConfig file.");
				strengthMirrorFileService.DeleteActiveConfig();
			}
			strengthMirrorFileService?.PrepareActiveDirectory();
			if (strengthMirrorFileService?.CurrentActiveConfig != null)
			{
				currentConsoleService.Console = GetStrengthMirrorConsole(strengthMirrorFileService.CurrentActiveConfig.PartNumber, strengthMirrorFileService.CurrentActiveConfig.ModelNumber);
				deviceInformation.IsStrengthMirror = true;
				iFit.Logger.Log.Trace("Startup", string.Format("Valid Strength Mirror config file found, setting {0}={1}, PartNumber={2}", "IsStrengthMirror", deviceInformation.IsStrengthMirror, strengthMirrorFileService.CurrentActiveConfig.PartNumber));
				iFit.Logger.Log.Trace("Startup", $"Strength Mirror file info: {strengthMirrorFileService.CurrentActiveConfig}");
				if (deviceInformation.ForceHeadlessBikeVault && !deviceInformation.IsHeadlessBikeVault)
				{
					deviceInformation.SpoofedSoftwareNumber = deviceInformation.HeadlessBikeVaultSoftwareNumber;
				}
				if (deviceInformation.IsHeadlessBikeVault)
				{
					deviceInformation.UseHeadlessBikeTheme = true;
				}
			}
			else
			{
				iFit.Logger.Log.Trace("Startup", string.Format("Strength Mirror config file not found, setting {0}={1}", "IsStrengthMirror", deviceInformation.IsStrengthMirror));
			}
		}

		private static IFitnessConsole GetStrengthMirrorConsole(int partNumber, string modelNumber)
		{
			MockFitnessConsoleOptions options = new MockFitnessConsoleOptions();
			return new NonconnectedMirrorFitnessConsole(options, partNumber, modelNumber);
		}

		private async System.Threading.Tasks.Task CheckBuiltIn(ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IWolfAnalytics analytics)
		{
			iFit.Logger.Log.Trace("Startup", "Checking built-in status and connection");
			iFit.Logger.Log.Trace("Startup", "Device Info - Manufacturer: " + Shire.Android.Util.DeviceInfo.GetManufacturer() + "\tModel: " + Shire.Android.Util.DeviceInfo.GetModel());
			deviceInformation.IsBuiltIn = Shire.Android.Util.DeviceInfo.IsBuiltIn() || deviceInformation.IsStrengthMirror;
			deviceInformation.BuiltInType = Shire.Android.Util.DeviceInfo.BuiltInType;
			analytics.IsBuiltInDidChange();
			Mvx.ConstructAndRegisterSingleton<ISendBroadcastService, SendBroadcastService>();
			if (!deviceInformation.IsBuiltIn && !deviceInformation.IsStrengthMirror)
			{
				iFit.Logger.Log.Trace("Startup", "Standalone device");
				Mvx.ConstructAndRegisterSingleton<IBleDeviceSupplementaryDataService, FitProDeviceSupplementaryDataService>();
				iFit.Logger.Log.Trace("Startup", "Registered supplementary data service");
				Mvx.LazyConstructAndRegisterSingleton<IBleRadioStatusService, StandaloneBleRadioStatusService>();
				Mvx.LazyConstructAndRegisterSingleton<ICheckUpdateService, CheckUpdateBleService>();
				Mvx.LazyConstructAndRegisterSingleton<ILaunchUpdate, LaunchBleUpdateService>();
				iFit.Logger.Log.Trace("Startup", "Empty ScreenSaver is registered");
				Mvx.ConstructAndRegisterSingleton<IScreenSaverHandler, EmptyScreenSaverHandler>();
				RegisterBleUpdater();
				return;
			}
			deviceInformation.LastBuiltInOSVersion = Build.VERSION.Incremental;
			Mvx.LazyConstructAndRegisterSingleton<IBleRadioStatusService, BleRadioStatusService>();
			Mvx.LazyConstructAndRegisterSingleton<ICheckUpdateService, CheckUpdateUsbService>();
			Mvx.LazyConstructAndRegisterSingleton<ILaunchUpdate, LaunchEruUpdateService>();
			Mvx.RegisterSingleton(() => iFit.Files.FileSystem.Current);
			ConsoleUpdateInfo consoleUpdateInfo = new ConsoleUpdateInfo(Mvx.Resolve<iFit.Files.IFileSystem>());
			Mvx.RegisterSingleton((IConsoleUpdateInfo)consoleUpdateInfo);
			await analytics.SetConsoleUuid(consoleUpdateInfo);
			ScreenBrightness service = new ScreenBrightness();
			Mvx.RegisterSingleton((IScreenBrightness)service);
			LastTouch service2 = new LastTouch();
			Mvx.RegisterSingleton((ILastTouch)service2);
			SetTimeZone service3 = new SetTimeZone();
			Mvx.RegisterSingleton((ISetTimeZone)service3);
			iFit.Logger.Log.Trace("Startup", "Registering ScreenSaverHandler");
			Mvx.ConstructAndRegisterSingleton<ITouchMonitor, TouchMonitor>();
			Mvx.ConstructAndRegisterSingleton<IScreenSaverHandler, ScreenSaverHandler>();
			await GetEruVersion(deviceInformation.IsBuiltIn);
			if (deviceInformation.IsStrengthMirror && !deviceInformation.IsHeadlessBikeVault)
			{
				iFit.Logger.Log.Trace("Startup", "Skipping USB connection because it is a Non-headless-bike StrengthMirror");
				return;
			}
			iFit.Logger.Log.Trace("Startup", "Preparing for console connection");
			Mvx.TryResolve<IFatalityService>(out var fatalityService);
			IUsbPermissionService usbPermissionService = ((!EruUsbPermissionService.IsSupported()) ? ((BaseUsbPermissionService)new UsbManagerUsbPermissionService()) : ((BaseUsbPermissionService)new EruUsbPermissionService()));
			Mvx.RegisterSingleton(usbPermissionService);
			WolfUsbDevice device = new WolfUsbDevice(usbPermissionService, fatalityService);
			TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
			iFit.Logger.Log.Trace("Startup", "Initiating console connection");
			currentConsoleService.ConnectAndRememberUsbMachine(device, (WolfUsbDevice usbDevice) => CreateConsole(usbDevice, Mvx.Resolve<ISindarinEventHandler>(), fatalityService, Mvx.Resolve<ILogFileService>(), currentConsoleService, analytics), taskCompletionSource);
			iFit.Logger.Log.Trace("Startup", "Awaiting console connection");
			bool flag;
			if (deviceInformation.IsHeadlessBikeVault)
			{
				flag = taskCompletionSource.Task.Wait(TimeSpan.FromSeconds(10.0));
				iFit.Logger.Log.Trace("Startup", $"Headless bike connected: {flag}");
			}
			else
			{
				flag = taskCompletionSource.Task.Wait(TimeSpan.FromSeconds(60.0));
				if (flag)
				{
					iFit.Logger.Log.Trace("Startup", "Console connected!");
				}
				else
				{
					if (Mvx.TryResolve<IAppSetupFatalityHandler>(out var service4))
					{
						FatalEvent fatalEvent = new FatalEvent(ErrorCode.BrainboardConnectTimeout.HumanReadable() + " " + Wolf.Core.Resources.AppStrings.power_cycle_message2, typeof(PlatformWolfAppSetup), isPermanent: true);
						service4.OnAppSetupFatality(fatalEvent);
					}
					iFit.Logger.Log.Trace("Startup", $"{ErrorCode.BrainboardConnectTimeout.HumanReadable()} {ErrorCode.BrainboardConnectTimeout}: Console did not connect correctly so a restart is most likely necessary.");
				}
			}
			if (flag)
			{
				Application.Context.SendBroadcast(new Intent("com.ifit.eru.FITPRO_ATTACHED"));
			}
			if (currentConsoleService.IsBuiltinClub)
			{
				Mvx.ConstructAndRegisterSingleton<IIdleLogoutService, IdleLogoutService>();
			}
		}

		private IFitnessConsole CreateConsole(BaseAndroidUsbDevice device, ISindarinEventHandler eventHandler, IFatalityService fatalityService, ILogFileService logFileService, ICurrentConsoleService currentConsoleService, IWolfAnalytics analytics)
		{
			UsbProduct productId = device.ProductId;
			UsbConsoleConnection connection = new UsbConsoleConnection(device, analytics);
			IFitProBytesLogger fitProBytesLogger = FitProBytesLoggerFactory.Create(logFileService);
			return productId switch
			{
				UsbProduct.FitPro1 => FitPro1UsbConsoleFactory.Create(connection, eventHandler, fatalityService, fitProBytesLogger), 
				UsbProduct.FitPro2 => FitPro2UsbConsoleFactory.Create(connection, fatalityService, fitProBytesLogger, currentConsoleService.FitnessConsoleManager), 
				_ => throw new ArgumentException($"No FitPro Console with id {productId}"), 
			};
		}

		private async System.Threading.Tasks.Task GetEruVersion(bool isBuiltIn)
		{
			if (isBuiltIn && Mvx.TryResolve<IIpcVersionInfo>(out var ipcVersionInfo))
			{
				if (ipcVersionInfo.EruVersion == "Unknown")
				{
					await ipcVersionInfo.GetVersions().ConfigureAwait(continueOnCapturedContext: false);
				}
				iFit.Logger.Log.Trace("Startup", "Eru version: " + ipcVersionInfo.EruVersion);
			}
		}

		private void LogCacheSizeAndNukeIfTooLarge(IBlobCacheFileManager blobCacheFileManager)
		{
			if (Mvx.TryResolve<IBlobCacheService>(out var _))
			{
				blobCacheFileManager.LogCacheInformation();
				bool flag = blobCacheFileManager.NukeCacheDirIfTooLarge(BlobCacheType.LocalMachine, 100000000);
				if (flag | blobCacheFileManager.NukeCacheDirIfTooLarge(BlobCacheType.Secure, 100000000))
				{
					new ApplicationRestarter().ScheduleToRestartAndKillApp(TimeSpan.Zero);
				}
			}
		}
	}
	public class Presenter : ShirePresenter
	{
		private readonly IPresentationFilterResolver presentationFilterResolver;

		public Presenter(IViewTypeLookup viewTypeLookup, IPresentationFilterResolver presentationFilterResolver)
			: base(viewTypeLookup, typeof(BaseViewModel).Assembly)
		{
			this.presentationFilterResolver = presentationFilterResolver;
		}

		public override void ChangePresentation(MvxPresentationHint hint)
		{
			BaseActivity baseActivity = base.Activity as BaseActivity;
			if (hint is ClearDialogsPresentationHint)
			{
				baseActivity?.CloseAllDialogs();
				return;
			}
			if (hint is ShowPreviousOverlayPresentationHint showPreviousOverlayPresentationHint && baseActivity?.ViewModel is InWorkoutViewModel inWorkoutViewModel)
			{
				inWorkoutViewModel.ShowPreviousOverlayScreen(showPreviousOverlayPresentationHint.OverlaySource);
			}
			base.ChangePresentation(hint);
		}

		public override void Show(MvxViewModelRequest request)
		{
			presentationFilterResolver.OnClosing(base.CurrentMainViewModel);
			request = presentationFilterResolver.OnShowing(request);
			if (!MainApplication.ApplicationInForeground || !DrawerRequestedWhenAlreadyExists(request))
			{
				if (IsModalActivity(request.ViewModelType) && base.Activity is BaseActivity baseActivity)
				{
					baseActivity.SuppressMainLayoutAnimationsOnce();
				}
				base.Show(request);
			}
		}

		private bool DrawerRequestedWhenAlreadyExists(MvxViewModelRequest request)
		{
			try
			{
				if (Mvx.TryResolve<IMvxAndroidCurrentTopActivity>(out var service))
				{
					bool? obj;
					if (request == null)
					{
						obj = null;
					}
					else
					{
						IDictionary<string, string> presentationValues = request.PresentationValues;
						obj = ((presentationValues != null) ? new bool?(!presentationValues.ContainsKey("replaceDialogContent")) : ((bool?)null));
					}
					if ((obj ?? true) && request?.PresentationValues?["dialogViewModel"] == typeof(NavigationDrawerViewModel).FullName)
					{
						return NavigationDrawerViewFragmentExists(service);
					}
				}
			}
			catch (KeyNotFoundException)
			{
			}
			return false;
		}

		private bool NavigationDrawerViewFragmentExists(IMvxAndroidCurrentTopActivity topActivity)
		{
			if (!(topActivity?.Activity is ShireMvxFragmentActivity { SupportFragmentManager: var supportFragmentManager }))
			{
				return false;
			}
			AndroidX.Fragment.App.Fragment fragment = supportFragmentManager?.FindFragmentByTag(string.Format("dialog_fragment_{0}", "NavigationDrawerViewModel"));
			return fragment != null;
		}

		public override void Close(IMvxViewModel viewModel)
		{
			BaseActivity baseActivity = base.Activity as BaseActivity;
			Type type = viewModel?.GetType();
			iFit.Logger.Log.Trace("Navigation", "Presenter closing view model " + type?.FullName);
			Type type2 = viewTypeLookup?.GetFragmentType(type);
			if (type2 != null)
			{
				baseActivity?.CloseFragment(viewModel);
				ProcessDialogQueue(type?.FullName);
				return;
			}
			Type type3 = viewTypeLookup?.GetDialogFragmentType(type);
			if (type3 != null)
			{
				baseActivity?.CloseDialogFragment(viewModel);
				if (type3 == typeof(NavigationDrawerView) && viewModel != null && viewModel.RequestedBy?.Type == MvxRequestedByType.Other && baseActivity is IDismissible dismissible)
				{
					dismissible.Dismiss();
				}
				ProcessDialogQueue(type?.FullName);
			}
			else
			{
				base.Close(viewModel);
			}
		}

		protected override void Show(Intent intent)
		{
			base.Activity?.StartActivity(intent);
		}

		private bool IsModalActivity(Type viewModelType)
		{
			return viewTypeLookup.GetActivityType(viewModelType).GetInterfaces().Any((Type x) => x == typeof(IModalActivity));
		}
	}
