	public class Setup : MvxAndroidSetup
	{
		private const string Tag = "Startup";

		private readonly string logFolder;

		private readonly string eruLogFolder;

		private FileTarget fileTarget;

		public static bool AppIsAlive { get; private set; }

		public static INC<bool> MvxSetupComplete { get; } = new NC<bool>();

		protected override IDictionary<string, string> ViewNamespaceAbbreviations
		{
			get
			{
				IDictionary<string, string> viewNamespaceAbbreviations = base.ViewNamespaceAbbreviations;
				viewNamespaceAbbreviations["wolf"] = "Wolf.Android.Controls";
				viewNamespaceAbbreviations["shire"] = "Shire.Android.Controls";
				viewNamespaceAbbreviations["join"] = "Wolf.Android.Views.Prelogin.Join";
				return viewNamespaceAbbreviations;
			}
		}

		public Setup(Context applicationContext)
			: base(applicationContext)
		{
			IfitTypeface.Init(applicationContext);
			logFolder = FolderPath.WolfLogProd;
			eruLogFolder = FolderPath.EruLog;
		}

		protected override IMvxApplication CreateApp()
		{
			TaskScheduler.UnobservedTaskException += async delegate(object sender, UnobservedTaskExceptionEventArgs e)
			{
				if (!CommonWolfAppSetup.IsIgnorableException(e?.Exception?.InnerException) && Mvx.TryResolve<ICrashReporter>(out var service))
				{
					await service.ReportError(new List<string> { "UnobservedTaskException" }, sender?.ToString() ?? "UnhandledException", e?.Exception, includeLogFiles: true, isManualLog: false);
				}
			};
			AndroidEnvironment.UnhandledExceptionRaiser += async delegate(object sender, RaiseThrowableEventArgs e)
			{
				if (e?.Exception != null)
				{
					ICrashReporter service;
					if (e.Exception.AnyMessageContains("Unable to resolve host \"feed.fm\": No address associated with hostname"))
					{
						e.Handled = true;
					}
					else if (Mvx.TryResolve<ICrashReporter>(out service))
					{
						await service.PersistError("AndroidUnhandledException", sender?.ToString() ?? "UnhandledException", e.Exception);
					}
				}
			};
			return new App();
		}

		public override void InitializePrimary()
		{
			AppIsAlive = true;
			base.InitializePrimary();
		}

		protected override void InitializeDebugServices()
		{
			try
			{
				base.InitializeDebugServices();
			}
			catch (MvxException)
			{
			}
		}

		protected override IMvxTrace CreateDebugTrace()
		{
			return new DebugTrace();
		}

		protected override IMvxAndroidViewPresenter CreateViewPresenter()
		{
			ViewTypeLookup service = new ViewTypeLookup(typeof(BaseActivity).Assembly, typeof(BaseViewModel).Assembly);
			Mvx.RegisterSingleton((IViewTypeLookup)service);
			Presenter presenter = Mvx.IocConstruct<Presenter>();
			Mvx.RegisterSingleton((IMvxAndroidViewPresenter)presenter);
			Mvx.RegisterSingleton((IDialogPresenter)presenter);
			return presenter;
		}

		protected override void InitializeIoC()
		{
			base.InitializeIoC();
			Mvx.ConstructAndRegisterSingleton<IAppFinishedStartup, AppFinishedStartup>();
			Mvx.ConstructAndRegisterSingleton<IAppVersionService, AppVersionService>();
			Mvx.RegisterSingleton((IDeviceInformation)new DeviceInformation(base.ApplicationContext as MainApplication));
			Mvx.RegisterSingleton((IPlatformWolfAppSetup)new PlatformWolfAppSetup(base.ApplicationContext));
			Mvx.RegisterSingleton((ISchedulerService)new SchedulerService());
			Mvx.RegisterSingleton((IHardwareInfo)new HardwareInfo(base.ApplicationContext));
