		protected override void InitializeLastChance()
		{
			IPlatformWolfAppSetup platformWolfAppSetup = Mvx.Resolve<IPlatformWolfAppSetup>();
			platformWolfAppSetup.SetupWolfApp().Wait();
			IFeatureFlagManager featureFlagManager = Mvx.Resolve<IFeatureFlagManager>();
			try
			{
				if (!featureFlagManager.GetBool(FeatureFlags.LogToFileEnabled, fallback: true))
				{
					iFit.Logger.Log.Trace("Startup", "Disabling file logs");
					LogManager.Configuration.RemoveTarget(fileTarget.GetType().Name);
				}
				else
				{
					iFit.Logger.Log.Trace("Startup", "Log to file enabled");
				}
			}
			catch (System.Exception ex)
			{
				iFit.Logger.Log.Error("Startup", $"Error configuring file logging: {ex}", ex);
			}
			InitializeAppMonitors(featureFlagManager);
			ILocalSettings localSettings = Mvx.Resolve<ILocalSettings>();
			IDeviceInformation deviceInformation = Mvx.Resolve<IDeviceInformation>();
			if (!deviceInformation.IsBuiltIn)
			{
				IPushNotificationService pushNotificationService = Mvx.Resolve<IPushNotificationService>();
				pushNotificationService.InitializeOneSignal(HandleNotification);
				pushNotificationService.InitNotificationHandling(enable: true);
				OneSignalService.Initialize();
				OneSignal.Default.PromptForPushNotificationsWithUserResponse();
			}
			MvxSetupComplete.Value = true;
			base.InitializeLastChance();
		}

		private void HandleNotification(NotificationOpenedResult result)
		{
			IPushNotificationHandlingService pushNotificationHandlingService = Mvx.Resolve<IPushNotificationHandlingService>();
			pushNotificationHandlingService.HandlePushNotification(delegate
			{
				HandleNotificationWithDeepLinks(result);
			});
		}

		private void HandleNotificationWithDeepLinks(NotificationOpenedResult result)
		{
			OneSignalSDK.Xamarin.Core.Notification notification = result.notification;
			Mvx.Resolve<IWolfAnalytics>().OnPushNotificationOpened(result);
			Dictionary<string, object> additionalData = notification.additionalData;
			if (additionalData != null && additionalData.ContainsKey("branch"))
			{
				string text = additionalData["branch"].ToString();
				iFit.Logger.Log.Trace("OneSignal", "OneSignal notification containing Branch Link Selected. Branch Link: " + text);
				DeepLinkService.TryHandlingDeepLink(global::Android.Net.Uri.Parse(text));
			}
		}

