	public class RepeatTouchListener : Java.Lang.Object, View.IOnTouchListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private Subject<RepeatTouchListener> whenTouchEnded = new Subject<RepeatTouchListener>();

		private View view;

		private int initialDelayMs;

		private int normalDelayMs;

		private int accelDelayMs;

		private int clicksBeforeAccelDelay;

		private int clicks;

		private System.Timers.Timer timer;

		public IObservable<RepeatTouchListener> WhenTouchEnded => whenTouchEnded;

		public RepeatTouchListener(int initialDelayMs = 700, int normalDelayMs = 250, int accelDelayMs = 100, int clicksBeforeAccelDelay = 5)
		{
			this.initialDelayMs = initialDelayMs;
			this.normalDelayMs = normalDelayMs;
			this.accelDelayMs = accelDelayMs;
			this.clicksBeforeAccelDelay = clicksBeforeAccelDelay;
			timer = new System.Timers.Timer();
			timer.Elapsed += HandleTimerElapsed;
		}

		private void HandleTimerElapsed(object sender, ElapsedEventArgs e)
		{
			InvokeClickListener();
		}

		private void InvokeInitialClickListener()
		{
			clicks = 1;
			view.CallOnClick();
		}

		private void InvokeClickListener()
		{
			if (!view.Enabled)
			{
				timer.Stop();
				return;
			}
			if (clicks == 1)
			{
				timer.Interval = normalDelayMs;
			}
			else if (clicks == clicksBeforeAccelDelay)
			{
				timer.Interval = accelDelayMs;
			}
			clicks++;
			view.Post(delegate
			{
				view.CallOnClick();
			});
		}

		public bool OnTouch(View v, MotionEvent e)
		{
			view = v;
			switch (e.Action)
			{
			case MotionEventActions.Down:
				view.Pressed = true;
				timer.Interval = initialDelayMs;
				timer.Start();
				InvokeInitialClickListener();
				return true;
			case MotionEventActions.Up:
			case MotionEventActions.Cancel:
				view.Pressed = false;
				timer.Stop();
				whenTouchEnded.OnNext(this);
				return true;
			default:
				return false;
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				whenTouchEnded?.Dispose();
				whenTouchEnded = null;
				if (timer != null)
				{
					timer.Elapsed -= HandleTimerElapsed;
				}
				timer?.Dispose();
				timer = null;
			}
			base.Dispose(disposing);
		}
	}
	[Activity(Theme = "@style/SettingsTheme.Light", ScreenOrientation = ScreenOrientation.Behind, ConfigurationChanges = (ConfigChanges.Keyboard | ConfigChanges.KeyboardHidden | ConfigChanges.UiMode))]
	public class CloseableWebViewView : BaseFullScreenWebViewView<CloseableWebViewViewModel>
	{
		protected override int LayoutResId => 2131624003;

		protected override bool ShowWhoopsViewCloseButton => false;

		protected override void SetupView()
		{
			base.SetupView();
			Mvx.TryResolve<IDeviceInformation>(out var service);
			((Activity)(object)this).RequestedOrientation = (((!base.IsTablet && (service == null || !service.IsBuiltIn)) || (service != null && service.IsStrengthMirror)) ? ScreenOrientation.Portrait : ScreenOrientation.SensorLandscape);
			base.Toolbar.BackButtonView.Click -= HandleBackPressed;
			base.Toolbar.BackButtonView.Click += HandleBackPressed;
		}

		protected override ShireWebView SetupWebView(bool requiresRefresh = false)
		{
			ShireWebView shireWebView = base.SetupWebView(requiresRefresh);
			if (shireWebView != null)
			{
				shireWebView.Settings.SetSupportMultipleWindows(support: false);
				shireWebView.HideLoadingViewWhenWebViewIsReady = false;
			}
			return shireWebView;
		}

		public override void OnBackPressed()
		{
			DoBackPressed();
		}

		private void HandleBackPressed(object sender, EventArgs e)
		{
			DoBackPressed();
		}

		private void DoBackPressed()
		{
			ShireWebView webView = WebView;
			if (webView != null && webView.CanGoBack())
			{
				WebView?.GoBack();
				return;
			}
			ShireWebView webView2 = WebView;
			if (webView2 == null || webView2.CurrentState != WebViewState.Loaded)
			{
				ShireWebView webView3 = WebView;
				if (webView3 == null || webView3.CurrentState != WebViewState.Errored)
				{
					return;
				}
			}
			base.ViewModel?.BackPressed?.SafeExecute();
		}

		protected override void CleanUp()
		{
			base.Toolbar.BackButtonView.Click -= HandleBackPressed;
			base.CleanUp();
		}
	}
