	[Application(AllowBackup = true, Label = "@string/app_name")]
	[MetaData("io.branch.sdk.auto_link_disable", Value = "false")]
	[MetaData("io.branch.sdk.BranchKey", Value = "@string/branch_key")]
	public class MainApplication : Application, Application.IActivityLifecycleCallbacks, IJavaObject, IDisposable, IJavaPeerable
	{
		private const string TagString = "MainApplication";

		private IDisposable appEnteredBackgroundSub;

		private IDisposable appEnteredForegroundSub;

		private ILocalSettings localSettings;

		private IBleConsoleService bleConsoleService;

		private IWolfAnalytics analytics;

		public BackgroundHandler BackgroundHandler { get; private set; }

		public static bool ApplicationInForeground { get; private set; }

		private IWolfAnalytics Analytics => analytics ?? (analytics = Mvx.Resolve<IWolfAnalytics>());

		public MainApplication(IntPtr handle, JniHandleOwnership transfer)
			: base(handle, transfer)
		{
		}

		public override void OnCreate()
		{
			base.OnCreate();
			global::Android.Util.Log.Info("MainApplication", "Initializing WorkManager");
			AndroidX.Work.Configuration configuration = new AndroidX.Work.Configuration.Builder().Build();
			WorkManager.Initialize(ApplicationContext, configuration);
			global::Android.Util.Log.Info("MainApplication", "Initializing firebase");
			FirebaseApp firebaseApp = FirebaseApp.InitializeApp(this);
			if (firebaseApp != null)
			{
				global::Android.Util.Log.Info("MainApplication", "Firebase app appears to be initialized: " + firebaseApp.Name + " (" + firebaseApp.Options.ApplicationId + ")");
			}
			else
			{
				global::Android.Util.Log.Error("MainApplication", "Firebase app does not appear to have initialized correctly. Errors may occur with deep linking.");
			}
			AppLinkingService.Instance.WaitForApplicationReadyForLink().ContinueWith(delegate(System.Threading.Tasks.Task t)
			{
				if (t.IsCompletedSuccessfully && Mvx.TryResolve<ILocalSettings>(out localSettings) && Mvx.TryResolve<IDeviceInformation>(out var service) && !service.IsBuiltIn && Mvx.TryResolve<IWolfAnalytics>(out var _))
				{
					iFit.Logger.Log.Trace("Branch", "Link service initialized");
				}
				else
				{
					iFit.Logger.Log.Error("Branch", "Unable to initialize deep link service");
				}
			}).ConfigureAwait(continueOnCapturedContext: false);
			BackgroundHandler = new BackgroundHandler();
			CrossCurrentActivity.Current.Init(this);
			RegisterActivityLifecycleCallbacks(this);
			RegisterActivityLifecycleCallbacks(BackgroundHandler);
			appEnteredBackgroundSub?.Dispose();
			appEnteredBackgroundSub = BackgroundHandler.WhenAppEnteredBackground.SubscribeWithErrorLogging(delegate
			{
				BackgroundStateChanged(enteredBackground: true);
			});
			appEnteredForegroundSub?.Dispose();
			appEnteredForegroundSub = BackgroundHandler.WhenAppEnteredForeground.SubscribeWithErrorLogging(delegate
			{
				BackgroundStateChanged(enteredBackground: false);
			});
		}

		private void BackgroundStateChanged(bool enteredBackground)
		{
			ApplicationInForeground = !enteredBackground;
			iFit.Logger.Log.Trace("MainApplication", $"Activity background state changed, ApplicationInForeground is now {ApplicationInForeground}");
			if (Mvx.TryResolve<IAppLifecycleService>(out var service))
			{
				if (enteredBackground)
				{
					service.AppPaused();
				}
				else
				{
					service.AppResumed();
				}
			}
			if ((localSettings == null || bleConsoleService == null) && Mvx.TryResolve<ILocalSettings>(out localSettings))
			{
				Mvx.TryResolve<IBleConsoleService>(out bleConsoleService);
			}
		}

		public override void OnTerminate()
		{
			iFit.Logger.Log.Trace("MainApplication", "Activity is being terminated");
			base.OnTerminate();
			UnregisterActivityLifecycleCallbacks(this);
			if (BackgroundHandler != null)
			{
				UnregisterActivityLifecycleCallbacks(BackgroundHandler);
			}
			appEnteredBackgroundSub?.Dispose();
			appEnteredForegroundSub?.Dispose();
		}

		public void OnActivityStopped(Activity activity)
		{
			iFit.Logger.Log.Trace("MainApplication", activity?.GetType().Name + " is being stopped");
		}

		public void OnActivityCreated(Activity activity, Bundle savedInstanceState)
		{
			CrossCurrentActivity.Current.Activity = activity;
			iFit.Logger.Log.Trace("MainApplication", $"{activity?.GetType().Name} is being created, Bundle is {savedInstanceState}");
		}

		public void OnActivityDestroyed(Activity activity)
		{
			iFit.Logger.Log.Trace("MainApplication", activity?.GetType().Name + " is being destroyed");
		}

		public void OnActivityPaused(Activity activity)
		{
			iFit.Logger.Log.Trace("MainApplication", activity?.GetType().Name + " is being paused");
		}

		public void OnActivityResumed(Activity activity)
		{
			CrossCurrentActivity.Current.Activity = activity;
			iFit.Logger.Log.Trace("MainApplication", activity?.GetType().Name + " is being resumed");
		}

		public void OnActivitySaveInstanceState(Activity activity, Bundle outState)
		{
			iFit.Logger.Log.Trace("MainApplication", $"{activity?.GetType().Name}.OnActivitySaveInstanceState, Bundle is {outState}");
		}

		public void OnActivityStarted(Activity activity)
		{
			CrossCurrentActivity.Current.Activity = activity;
			iFit.Logger.Log.Trace("MainApplication", activity?.GetType().Name + " is being started");
		}

		public override void OnTrimMemory(TrimMemory level)
		{
			base.OnTrimMemory(level);
			if (!MemoryStatusShouldBeReported(level))
			{
				return;
			}
			System.Threading.Tasks.Task.Run(async delegate
			{
				if (Mvx.TryResolve<IWolfAnalytics>(out var service))
				{
					string name = Platform.CurrentActivity.GetType().Name;
					await service.MemoryStatusAlert(level.ToString(), name);
				}
			});
		}

		private bool MemoryStatusShouldBeReported(TrimMemory memoryStatus)
		{
			if (TrimMemory.RunningModerate < memoryStatus && TrimMemory.RunningLow < memoryStatus)
			{
				return TrimMemory.RunningCritical >= memoryStatus;
			}
			return true;
		}
	}
