		private void FocusSecurity(object sender, TextView.EditorActionEventArgs e)
		{
			if (e.ActionId == ImeAction.Next)
			{
				ssid.EditText.ClearFocus();
				securitySpinner.RequestFocus();
				securitySpinner.PerformClick();
				InputMethodManager inputMethodManager = (InputMethodManager)((Context)(object)this).GetSystemService("input_method");
				inputMethodManager.HideSoftInputFromWindow(ssid.EditText.WindowToken, HideSoftInputFlags.None);
			}
		}

		private void FocusIdentity(object sender, AdapterView.ItemSelectedEventArgs e)
		{
			if (e.View is WifiSecurityItem wifiSecurityItem)
			{
				TextInputLayout textInputLayout = password;
				if (WifiNetworkInfo.SecurityType.WpaEnt.ToString().ToUpper() == wifiSecurityItem.DataContext.ToString())
				{
					textInputLayout = identity;
				}
				else if (WifiNetworkInfo.SecurityType.None.ToString().ToUpper() == wifiSecurityItem.DataContext.ToString())
				{
					return;
				}
				securitySpinner.ClearFocus();
				textInputLayout.RequestFocus();
				InputMethodManager inputMethodManager = (InputMethodManager)((Context)(object)this).GetSystemService("input_method");
				inputMethodManager.ShowSoftInput(textInputLayout.EditText, ShowFlags.Implicit);
			}
		}

