			DoBindingSet();
		}

		private void DoBindingSet()
		{
			MvxFluentBindingDescriptionSet<ShopQRCodeView, ShopQRCodeViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<ShopQRCodeView, ShopQRCodeViewModel>();
			ShopTitle.SetTypeface(IfitTypeface.GetCustomTypeface(IfitTypeface.Type.ProximaBlack), TypefaceStyle.BoldItalic);
			mvxFluentBindingDescriptionSet.Bind(ShopSubTitle).For((TextView x) => x.Text).To((ShopQRCodeViewModel vm) => vm.ShopSubTitle);
			bool flag = Build.VERSION.SdkInt <= BuildVersionCodes.LollipopMr1;
			ShopTitle.TextFormatted = (flag ? Html.FromHtml(Wolf.Core.Resources.AppStrings.shop_qr_code_title) : Html.FromHtml(Wolf.Core.Resources.AppStrings.shop_qr_code_title, FromHtmlOptions.ModeLegacy));
			ShopFooter.TextFormatted = (flag ? Html.FromHtml(Wolf.Core.Resources.AppStrings.shop_qr_code_footer) : Html.FromHtml(Wolf.Core.Resources.AppStrings.shop_qr_code_footer, FromHtmlOptions.ModeLegacy));
			QRCodeImage.SetImageBitmap(GetQrCodeImage());
			mvxFluentBindingDescriptionSet.Apply();
		}

		private Bitmap GetQrCodeImage()
		{
			if (base.ViewModel?.QrCodeArgs == null)
			{
				return null;
			}
			BarcodeWriter barcodeWriter = new BarcodeWriter
			{
				Format = BarcodeFormat.QR_CODE,
				Options = new EncodingOptions
				{
					Width = base.ViewModel.QrCodeArgs.Width,
					Height = base.ViewModel.QrCodeArgs.Height,
					Margin = base.ViewModel.QrCodeArgs.Margin
				}
			};
			return barcodeWriter.Write(base.ViewModel.QrCodeArgs.Url);
		}
	}
