namespace Wolf.Android.Util
{
	public static class AndroidBindingNames
	{
		public static string VisibilityInvisible => "VisibilityInvisible";
	}
	public static class AndroidViewExtensions
	{
		public static View FindAbsoluteParentView(this View view)
		{
			ViewGroup viewGroup = view.Parent as ViewGroup;
			if (viewGroup == null)
			{
				return view;
			}
			while (viewGroup.Parent is ViewGroup viewGroup2)
			{
				viewGroup = viewGroup2;
			}
			return viewGroup;
		}
	}
	public static class AnimatorExtensions
	{
		private class AnimatorEndTcsListener : Java.Lang.Object, Animator.IAnimatorListener, IJavaObject, IDisposable, IJavaPeerable
		{
			private readonly TaskCompletionSource<object> tcs;

			public AnimatorEndTcsListener(TaskCompletionSource<object> tcs)
			{
				this.tcs = tcs;
			}

			public void OnAnimationCancel(Animator animation)
			{
				tcs.TrySetCanceled();
			}

			public void OnAnimationEnd(Animator animation)
			{
				tcs.TrySetResult(null);
			}

			public void OnAnimationRepeat(Animator animation)
			{
			}

			public void OnAnimationStart(Animator animation)
			{
			}
		}

		public static async System.Threading.Tasks.Task StartWithDisposal(this ViewPropertyAnimator animator, System.Threading.CancellationToken token = default(System.Threading.CancellationToken))
		{
			if (animator == null)
			{
				return;
			}
			CancellationTokenRegistration registration = token.Register(delegate
			{
				try
				{
					animator.Cancel();
				}
				catch (ObjectDisposedException)
				{
				}
			});
			try
			{
				TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
				animator.SetListener(new AnimatorEndTcsListener(taskCompletionSource)).Start();
				await taskCompletionSource.Task;
			}
			catch (TaskCanceledException arg)
			{
				iFit.Logger.Log.Debug("Animator", $"AnimatorExtensions - TaskCanceledException in StartWithDisposal {arg}");
			}
			finally
			{
				registration.Dispose();
				animator = iFit.Extensions.Android.JavaExtensions.DisposeSafe(animator);
			}
		}

		public static async System.Threading.Tasks.Task StartWithDisposal(this Animator animator, System.Threading.CancellationToken token = default(System.Threading.CancellationToken))
		{
			if (animator == null)
			{
				return;
			}
			CancellationTokenRegistration registration = token.Register(delegate
			{
				try
				{
					animator.Cancel();
				}
				catch (ObjectDisposedException)
				{
				}
			});
			try
			{
				TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
				animator.AddListener(new AnimatorEndTcsListener(taskCompletionSource));
				animator.Start();
				await taskCompletionSource.Task;
			}
			catch (TaskCanceledException)
			{
			}
			finally
			{
				registration.Dispose();
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(animator);
			}
		}
	}
	[BroadcastReceiver(Enabled = true, Name = "com.ifit.standalone.StandaloneBounceReceiver")]
	public class StandaloneBounceReceiver : BroadcastReceiver
	{
		public override void OnReceive(Context context, Intent intent)
		{
			iFit.Logger.Log.Trace("StandaloneBounceReceiver", "Received bounce broadcast, preparing for bounce");
			Mvx.TryResolve<IIfitApiService>(out var service);
			service?.PrepareForBounce();
		}
	}
	public class ApplicationRestarter : IApplicationRestarter
	{
		public bool WaitingToRestart { get; set; }

		public void ScheduleToRestart(TimeSpan wait)
		{
			iFit.Logger.Log.Trace("DeviceAdmin", "Scheduling app to reawake in " + wait);
			long triggerAtMillis = SystemClock.ElapsedRealtime() + (long)wait.TotalMilliseconds;
			AlarmManager alarmManager = (AlarmManager)Application.Context.GetSystemService("alarm");
			Intent intent = new Intent(Application.Context, typeof(ApplicationRestartReceiver));
			PendingIntent broadcast = PendingIntent.GetBroadcast(Application.Context, 0, intent, (PendingIntentFlags)0);
			alarmManager.Set(AlarmType.ElapsedRealtimeWakeup, triggerAtMillis, broadcast);
		}

		public void ScheduleToRestartAndKillApp(TimeSpan wait)
		{
			WaitingToRestart = false;
			ScheduleToRestart(wait);
			global::Android.OS.Process.KillProcess(global::Android.OS.Process.MyPid());
		}

		public void RestartAppIfWaiting()
		{
			if (WaitingToRestart)
			{
				iFit.Logger.Log.Trace("DeviceAdmin", "App waiting to restart, scheduling restart and killing now...");
				ScheduleToRestartAndKillApp(TimeSpan.Zero);
			}
		}
	}
	[BroadcastReceiver]
	public class ApplicationRestartReceiver : BroadcastReceiver
	{
		public override void OnReceive(Context context, Intent intent)
		{
			Intent intent2 = new Intent(context.ApplicationContext, typeof(SplashScreen));
			intent2.SetFlags(ActivityFlags.NewTask);
			context.StartActivity(intent2);
		}
	}
	public interface IBackgroundHandler
	{
		Shire.Core.Util.NonGenericObservable WhenAppEnteredBackground { get; }

		Shire.Core.Util.NonGenericObservable WhenAppEnteredForeground { get; }
	}
	public class BackgroundHandler : Java.Lang.Object, Application.IActivityLifecycleCallbacks, IJavaObject, IDisposable, IJavaPeerable, IBackgroundHandler
	{
		private readonly Shire.Core.Util.NonGenericSubject _whenAppEnteredBackground = new Shire.Core.Util.NonGenericSubject();

		private readonly Shire.Core.Util.NonGenericSubject _whenAppEnteredForeground = new Shire.Core.Util.NonGenericSubject();

		public Shire.Core.Util.NonGenericObservable WhenAppEnteredBackground => _whenAppEnteredBackground;

		public Shire.Core.Util.NonGenericObservable WhenAppEnteredForeground => _whenAppEnteredForeground;

		public int ActivitiesStarted { get; private set; }

		public void OnActivityCreated(Activity activity, Bundle savedInstanceState)
		{
		}

		public void OnActivityDestroyed(Activity activity)
		{
		}

		public void OnActivityPaused(Activity activity)
		{
		}

		public void OnActivityResumed(Activity activity)
		{
		}

		public void OnActivitySaveInstanceState(Activity activity, Bundle outState)
		{
		}

		public void OnActivityStarted(Activity activity)
		{
			if (ActivitiesStarted == 0)
			{
				_whenAppEnteredForeground.OnNext();
			}
			ActivitiesStarted++;
		}

		public void OnActivityStopped(Activity activity)
		{
			ActivitiesStarted--;
			if (ActivitiesStarted == 0)
			{
				_whenAppEnteredBackground.OnNext();
			}
		}
	}
