		private readonly int[] strengthMirrorScreenSaverImages = new int[3] { 2131231924, 2131231925, 2131231926 };

		private readonly int[] preparingWorkoutImages = new int[4] { 2131231728, 2131231729, 2131231730, 2131231731 };

		private readonly int[] treadmillLegalImages = new int[3] { 2131231947, 2131231948, 2131231949 };

		private readonly int[] ellipticalLegalImages = new int[4] { 2131231068, 2131231069, 2131231070, 2131231071 };

		private readonly int[] bikeLegalImages = new int[4] { 2131230847, 2131230848, 2131230849, 2131230850 };

		private readonly int[] rowerLegalImages = new int[4] { 2131231873, 2131231874, 2131231875, 2131231876 };

		private readonly int[] strengthLegalImages = new int[4] { 2131231916, 2131231917, 2131231918, 2131231919 };

		private readonly int[] strengthMirrorLegalImages = new int[1] { 2131231923 };

		public BackgroundImageUtil(IDeviceInformation deviceInformation, ICurrentConsoleService currentConsoleService)
		{
			this.deviceInformation = deviceInformation;
			this.currentConsoleService = currentConsoleService;
