	public class BlobCacheFileManager : BlobCacheFileManagerBase
	{
		protected override string GetCacheDir(BlobCacheType cacheType)
		{
			string text = ((cacheType == BlobCacheType.Secure) ? CommonWolfAppSetup.SecureCacheDirectory : CommonWolfAppSetup.LocalMachineCacheDirectory);
			iFit.Logger.Log.Trace("CacheFileManager", $"{cacheType} Cache Directory is {text}.");
			return new DirectoryInfo(text).FullName;
		}

		protected override IEnumerable<string> GetCacheFiles(BlobCacheType cacheType)
		{
			string cacheDir = GetCacheDir(cacheType);
			if (Directory.Exists(cacheDir))
			{
				return Directory.GetFiles(cacheDir).ToList();
			}
			iFit.Logger.Log.Trace("CacheFileManager", $"{cacheType} cache size is unknown - directory {cacheDir} does not exist.");
			return Enumerable.Empty<string>();
		}

		protected override void DeleteFiles(IEnumerable<string> files)
		{
			foreach (string file in files)
			{
				try
				{
					System.IO.File.Delete(file);
				}
				catch (System.IO.IOException ex)
				{
					iFit.Logger.Log.Trace("CacheFileManager", "Nuke failed for file " + file + ": " + ex);
				}
			}
		}

		protected override void CorruptCache(string cacheDir, string dbFilename)
		{
			iFit.Logger.Log.Trace("CacheFileManager", "Intentionally corrupting cache files at " + cacheDir + "/" + dbFilename);
			string text = System.IO.Path.Combine(new string[2] { cacheDir, dbFilename });
			string text2 = System.IO.Path.Combine(new string[2]
			{
				cacheDir,
				dbFilename + "-shm"
			});
			string text3 = System.IO.Path.Combine(new string[2]
			{
				cacheDir,
				dbFilename + "-wal"
			});
			string[] array = new string[3] { text, text2, text3 };
			foreach (string path in array)
			{
				StreamWriter streamWriter = new StreamWriter(path, append: false);
				streamWriter.Write("corruptdb");
				streamWriter.Flush();
				streamWriter.Dispose();
				streamWriter = null;
			}
		}

		protected override long GetCacheFilesSize(BlobCacheType cacheType, IEnumerable<string> files = null, bool logInfo = false)
		{
			try
			{
				List<string> list = new List<string>(files ?? GetCacheFiles(cacheType));
				if (list.IsNullOrEmpty())
				{
					if (logInfo)
					{
						iFit.Logger.Log.Trace("CacheFileManager", $"There are no files for the {cacheType} cache.");
					}
					return 0L;
				}
				long num = list.Sum((string f) => new System.IO.FileInfo(f).Length);
				int count = list.Count;
				if (logInfo)
				{
					iFit.Logger.Log.Trace("CacheFileManager", $"Cache size for {cacheType} is {num} B in {count} files");
				}
				return num;
			}
			catch (SecurityException ex)
			{
				iFit.Logger.Log.Trace("CacheFileManager", $"{cacheType} size is unknown - you do not have required permission to access secure cache directory: " + ex);
			}
			catch (UnauthorizedAccessException ex2)
			{
				iFit.Logger.Log.Trace("CacheFileManager", $"{cacheType} size is unknown - you do not have required permission to access secure cache directory: " + ex2);
			}
			return 0L;
		}

		protected override void LogDriveInfo()
		{
			List<string> list = new List<string>
			{
				CommonWolfAppSetup.LocalMachineCacheDirectory,
				CommonWolfAppSetup.SecureCacheDirectory
			};
			DriveInfo[] drives = DriveInfo.GetDrives();
			HashSet<DriveInfo> hashSet = new HashSet<DriveInfo>();
			foreach (string item in list)
			{
				int num = 0;
				DriveInfo driveInfo = null;
				DriveInfo[] array = drives;
				foreach (DriveInfo driveInfo2 in array)
				{
					if (item.StartsWith(driveInfo2.Name, StringComparison.Ordinal) && driveInfo2.Name.Length > num)
					{
						num = driveInfo2.Name.Length;
						driveInfo = driveInfo2;
					}
				}
				if (driveInfo != null)
				{
					hashSet.Add(driveInfo);
				}
			}
			IEnumerable<DriveInfo> enumerable = hashSet.Where((DriveInfo d) => d.IsReady);
			if (!enumerable.Any())
			{
				enumerable = drives.Where((DriveInfo d) => d.IsReady);
			}
			foreach (DriveInfo item2 in enumerable)
			{
				iFit.Logger.Log.Trace("CacheFileManager", "Drive " + item2.Name);
				iFit.Logger.Log.Trace("CacheFileManager", $"  Drive type: {item2.DriveType}");
				iFit.Logger.Log.Trace("CacheFileManager", $"  Available space for user: {item2.AvailableFreeSpace,15} B");
				iFit.Logger.Log.Trace("CacheFileManager", $"  Total available space:    {item2.TotalFreeSpace,15} B");
				iFit.Logger.Log.Trace("CacheFileManager", $"  Total size of drive:      {item2.TotalSize,15} B ");
			}
		}
	}
