	public class IFitAnrListener : ANRWatchDog.IANRListener
	{
		private const string AnrTag = "ANR";

		private readonly IFeatureFlagManager flagManager;

		public IFitAnrListener(IFeatureFlagManager flagManager)
		{
			this.flagManager = flagManager;
		}

		public async void OnAppNotResponding(ANRError error)
		{
			try
			{
				string text = "NOT_FOUND";
				string text2 = error.StackTrace.Split("Caused by: ").FirstOrDefault((string threadStack) => threadStack.Contains("Thread: main "));
				if (!string.IsNullOrWhiteSpace(text2))
				{
					text = text2;
				}
				bool flag = flagManager?.IsFeatureEnabled(FeatureFlags.ANRLoggingFeature) ?? false;
				iFit.Logger.Log.Trace("ANR", $"App not responding for {error.Duration} ms. ViewModel: {CrashReporterUtil.Instance.CurrentViewModelName()}. " + $"{FeatureFlags.ANRLoggingFeature.Key} enabled: {flag}. " + "Main thread java stack trace:\n" + text);
				if (flag)
				{
					await PersistANR(error).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("ANR", "Error processing ANR", exception);
			}
		}

		private async System.Threading.Tasks.Task PersistANR(ANRError error)
		{
			iFit.Logger.Log.Trace("ANR", "Starting ANR error report");
			iFitAnrError iFitAnrError2 = new iFitAnrError(error.Message, error.InnerException);
			iFitAnrError2.SetStackTrace(error.StackTrace);
			string wolfLog = FolderPath.WolfLog;
			string crashDirectoryPath = System.IO.Path.Combine(wolfLog, "crashes");
			string version = "Unknown";
			if (Mvx.TryResolve<IAppVersionService>(out var service))
			{
				version = service.MainAppVersionInfo.FullAppVersion;
			}
			iFitAnrError2.Data.Add("duration", error.Duration);
			await CrashReporterUtil.Instance.PersistError(crashDirectoryPath, "ANR", version, $"ANR Duration: {error.Duration} ms", iFitAnrError2).ConfigureAwait(continueOnCapturedContext: false);
			iFit.Logger.Log.Trace("ANR", "ANR error report persisted locally for submitting later");
		}
	}
	public static class ImageUtil
	{
		public static Bitmap CreateBitmap(Context context, int width, int height, int resId, double scalingFactor = 1.0)
		{
			BitmapFactory.Options options = new BitmapFactory.Options
			{
				InJustDecodeBounds = true
			};
			BitmapFactory.DecodeResource(context.Resources, resId, options);
			options.InSampleSize = CalculateInSampleSize(options, (int)((double)width / scalingFactor), (int)((double)height / scalingFactor));
			options.InPreferQualityOverSpeed = false;
			options.OutHeight = height;
			options.OutWidth = width;
			options.InJustDecodeBounds = false;
			return BitmapFactory.DecodeResource(context.Resources, resId, options);
		}

		public static int CalculateInSampleSize(BitmapFactory.Options options, int reqWidth, int reqHeight)
		{
			int outHeight = options.OutHeight;
			int outWidth = options.OutWidth;
			int num = 1;
			if (outHeight > reqHeight || outWidth > reqWidth)
			{
				int num2 = outHeight / 2;
				int num3 = outWidth / 2;
				while (num2 / num > reqHeight && num3 / num > reqWidth)
				{
					num *= 2;
				}
			}
			return num;
		}

		public static ImageView CleanUpBitmapImageView(this ImageView imageView)
		{
			if (imageView == null)
			{
				return null;
			}
			try
			{
				if (imageView.Drawable is BitmapDrawable bitmapDrawable)
				{
					bitmapDrawable.Bitmap?.Recycle();
				}
				imageView.SetImageBitmap(null);
				imageView.Dispose();
			}
			catch
			{
			}
			return null;
		}

		public static GradientDrawable FeedFmNewLabelBorder(global::Android.Graphics.Color backgroundColor, global::Android.Graphics.Color borderColor, int borderRadius, int borderWidth)
		{
			GradientDrawable gradientDrawable = new GradientDrawable();
			gradientDrawable.SetColor(backgroundColor);
			gradientDrawable.SetCornerRadius(borderRadius);
			gradientDrawable.SetStroke(borderWidth, borderColor);
			return gradientDrawable;
		}
	}
