	public static class LocationServicesUtil
	{
		private const int RequestIntervalMs = 10000;

		public static async System.Threading.Tasks.Task PromptForLocationServices(Activity activity, Context context, bool checkLocEnabled = true)
		{
			if ((!checkLocEnabled || !IsLocationServicesEnabled(context)) && Build.VERSION.SdkInt >= BuildVersionCodes.M)
			{
				GoogleApiClient googleApiClient = new GoogleApiClient.Builder(context).AddApi(LocationServices.API).Build();
				googleApiClient.Connect();
				LocationRequest locationRequest = LocationRequest.Create();
				locationRequest.SetPriority(100);
				locationRequest.SetInterval(10000L);
				locationRequest.SetFastestInterval(5000L);
				LocationSettingsRequest.Builder builder = new LocationSettingsRequest.Builder().AddLocationRequest(locationRequest);
				builder.SetAlwaysShow(p0: true);
				Statuses status = (await LocationServices.SettingsApi.CheckLocationSettingsAsync(googleApiClient, builder.Build()).ConfigureAwait(continueOnCapturedContext: false)).Status;
				if (status.StatusCode == 6)
				{
					status.StartResolutionForResult(activity, 0);
				}
			}
		}

		public static bool IsLocationServicesEnabled(Context context)
		{
			if (!(context.GetSystemService("location") is LocationManager locationManager))
			{
				return true;
			}
			bool flag = false;
			bool flag2 = false;
			try
			{
				flag = locationManager.IsProviderEnabled("gps");
				flag2 = locationManager.IsProviderEnabled("network");
			}
			catch (System.Exception ex)
			{
				iFit.Logger.Log.Trace("Ble", "Failure in IsLocationServicesEnabled - Exception: " + ex.Message);
			}
			return flag && flag2;
		}
	}
