	public class SoftKeyboardListener
	{
		private static readonly int SoftKeyboardHeightDPThreshold = 128;

		private readonly Activity activity;

		protected View RootView => activity.Window.DecorView.RootView;

		public event EventHandler KeyboardDidAppear;

		public event EventHandler KeyboardDidDisappear;

		public SoftKeyboardListener(Activity activity)
		{
			activity.ThrowIfNull("activity");
			this.activity = activity;
		}

		public void BeginTrackKeyboard()
		{
			RootView.ViewTreeObserver.GlobalLayout += ViewTreeObserverGlobalLayout;
		}

		public void EndTrackKeyboard()
		{
			RootView.ViewTreeObserver.GlobalLayout -= ViewTreeObserverGlobalLayout;
		}

		private void ViewTreeObserverGlobalLayout(object sender, EventArgs e)
		{
			Rect rect = new Rect();
			View rootView = RootView;
			rootView.GetWindowVisibleDisplayFrame(rect);
			DisplayMetrics displayMetrics = rootView.Resources.DisplayMetrics;
			int num = rootView.Bottom - rect.Bottom;
			if ((float)num > (float)SoftKeyboardHeightDPThreshold * displayMetrics.Density)
			{
				this.KeyboardDidAppear?.Invoke(this, e);
			}
			else
			{
				this.KeyboardDidDisappear?.Invoke(this, e);
			}
		}
	}
	public class UserAvatarImageFactory : BaseUserAvatarImageFactory, IUserAvatarImage
	{
		private readonly SemaphoreSlim creatingUserImage = new SemaphoreSlim(1, 1);

		public Dictionary<string, IBitmap> AvatarDictionary { get; set; }

		public UserAvatarImageFactory(IBlobCacheService cacheService)
		{
			base.BlobCacheService = cacheService;
			AvatarDictionary = new Dictionary<string, IBitmap>();
		}

		public async Task<IBitmap> UserAvatarImageForUser(User user)
		{
			await GenerateUserAvatarForUser(user);
			string keyForUser = BaseUserAvatarImageFactory.GetKeyForUser(user);
			return AvatarDictionary[keyForUser];
		}

		public async System.Threading.Tasks.Task GenerateUserAvatarForUser(User user)
		{
			await creatingUserImage.WaitAsync();
			try
			{
				string key = BaseUserAvatarImageFactory.GetKeyForUser(user);
				if (AvatarDictionary.ContainsKey(key))
				{
					return;
				}
				if (user == null)
				{
					IBitmap value = await BitmapLoader.Current.LoadFromResource("icn_user", null, null);
					AvatarDictionary.Add(key, value);
					return;
				}
				if (string.IsNullOrWhiteSpace(user.ImageUrl))
				{
					IBitmap value2 = await CreateGeneratedAvatar(user);
					AvatarDictionary.Add(key, value2);
					return;
				}
				IBitmap bitmap = await user.GetImage();
				if (bitmap == null)
				{
					IBitmap value3 = await CreateGeneratedAvatar(user);
					AvatarDictionary.Add(key, value3);
				}
				else
				{
					AvatarDictionary.Add(key, bitmap);
				}
			}
			finally
			{
				creatingUserImage.Release();
			}
		}

		private async Task<IBitmap> CreateGeneratedAvatar(User user)
		{
			string initialsForUser = BaseUserAvatarImageFactory.GetInitialsForUser(user);
			global::Android.Graphics.Color color = BaseUserAvatarImageFactory.GetBGColorForUser(user).ToNative();
			Paint paint = new Paint();
			paint.Color = color;
			paint.AntiAlias = true;
			paint.SetStyle(Paint.Style.Fill);
			Bitmap bitmap = Bitmap.CreateBitmap(BaseUserAvatarImageFactory.ImageSize, BaseUserAvatarImageFactory.ImageSize, Bitmap.Config.Argb8888);
			Canvas canvas = new Canvas(bitmap);
			RectF rect = new RectF(0f, 0f, BaseUserAvatarImageFactory.ImageSize, BaseUserAvatarImageFactory.ImageSize);
			canvas.DrawRoundRect(rect, 6f, 6f, paint);
			if (!string.IsNullOrWhiteSpace(initialsForUser))
			{
				Paint paint2 = new Paint();
				paint2.Color = BaseUserAvatarImageFactory.FontColor.ToNative();
				paint2.SetStyle(Paint.Style.Fill);
				paint2.TextSize = BaseUserAvatarImageFactory.FontSize;
				paint2.AntiAlias = true;
				paint2.SetTypeface(IfitTypeface.GetCustomTypeface(IfitTypeface.Type.ProximaBold));
				float num = paint2.MeasureText(initialsForUser);
				canvas.DrawText(initialsForUser, (float)(BaseUserAvatarImageFactory.ImageSize / 2) - num / 2f, (float)(BaseUserAvatarImageFactory.ImageSize / 2) + paint2.TextSize / 3f, paint2);
			}
			MemoryStream memoryStream = new MemoryStream();
			bitmap.Compress(Bitmap.CompressFormat.Png, 100, memoryStream);
			memoryStream.Seek(0L, SeekOrigin.Begin);
			return await BitmapLoader.Current.Load(memoryStream, null, null);
		}
	}
