	public class CpuUtilizationMonitor : WorkoutPeriodicMonitor, ICpuUtilizationMonitor
	{
		private const string LogTag = "CpuUtilizationMonitor";

		private const int JiffySize = 100;

		private const int DefaultCpuHighUsageThreshold = 100;

		private const string ProcSelfStatPath = "/proc/self/stat";

		private ulong lastUserTime;

		private ulong lastUpTime;

		private readonly uint numCpuCores;

		private CpuUtilizationReport cpuUtilReport;

		private int cpuHighUsageThreshold = 100;

		public CpuUtilizationMonitor()
		{
			Init();
			numCpuCores = Convert.ToUInt32(Java.Lang.Runtime.GetRuntime().AvailableProcessors());
		}

		public override void TrySetSamplingParams()
		{
			if (Mvx.TryResolve<IFeatureFlagManager>(out var service) && service.IsFeatureEnabled(FeatureFlags.CpuUtilizationMonitoring))
			{
				base.samplingInterval = TimeSpan.FromMilliseconds(service.GetInt(FeatureFlags.CpuUtilizationMonitoringIntervalMs));
				cpuHighUsageThreshold = service.GetInt(FeatureFlags.CpuHighUsageThreshold);
			}
		}

		protected override void StartNewReport()
		{
			cpuUtilReport = cpuUtilReport ?? new CpuUtilizationReport(base.samplingInterval, cpuHighUsageThreshold);
		}

		protected override void ResetReport()
		{
			cpuUtilReport.Warmup.Reset();
			cpuUtilReport.InWorkout.Reset();
			cpuUtilReport.Cooldown.Reset();
			cpuUtilReport.IsRecoveryWorkout = null;
			cpuUtilReport.WorkoutCategory = null;
			cpuUtilReport.WorkoutId = null;
		}

		protected override async System.Threading.Tasks.Task AddStartingSample(MonitoringReportTypes reportType)
		{
			GetAppCpuUtilization();
			await System.Threading.Tasks.Task.Delay(TimeSpan.FromMilliseconds(25.0)).ConfigureAwait(continueOnCapturedContext: false);
			AddSample(reportType);
		}

		protected override void AddSample(MonitoringReportTypes reportType)
		{
			double appCpuUtilization = GetAppCpuUtilization();
			switch (reportType)
			{
			case MonitoringReportTypes.Warmup:
				cpuUtilReport.Warmup.AddSample(appCpuUtilization, cpuHighUsageThreshold);
				break;
			case MonitoringReportTypes.InWorkout:
				cpuUtilReport.InWorkout.AddSample(appCpuUtilization, cpuHighUsageThreshold);
				break;
			case MonitoringReportTypes.Cooldown:
				cpuUtilReport.Cooldown.AddSample(appCpuUtilization, cpuHighUsageThreshold);
				break;
			}
		}

		public override void PopulateWorkoutInfo(IWorkoutSettings workoutSettings)
		{
			cpuUtilReport?.PopulateWorkoutInfo(workoutSettings);
		}

		protected override async System.Threading.Tasks.Task FinalizeReport()
		{
			if (Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				await service.SendCpuUtilizationReport(cpuUtilReport).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private double GetAppCpuUtilization()
		{
			double num = 0.0;
			try
			{
				(ulong, ulong) tuple = ReadTimesForCpuUtilization();
				ulong num2 = tuple.Item1 - lastUserTime;
				ulong num3 = (tuple.Item2 - lastUpTime) * numCpuCores;
				num = (double)num2 / (double)num3;
				(lastUserTime, lastUpTime) = tuple;
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Trace("CpuUtilizationMonitor", "Exception calculating CPU utilization", exception);
			}
			return num * 100.0;
		}

		private (ulong userTime, ulong upTime) ReadTimesForCpuUtilization()
		{
			ulong item = ReadUserTimeForApplication();
			ulong item2 = ReadSystemUpTime();
			return (userTime: item, upTime: item2);
		}

		private ulong ReadUserTimeForApplication()
		{
			using (StreamReader streamReader = System.IO.File.OpenText("/proc/self/stat"))
			{
				string text = streamReader.ReadLine();
				string[] array = text.Split(" ");
				if (ulong.TryParse(array[13], out var result))
				{
					return result;
				}
			}
			throw new MonitoringException("Unknown error reading User time from /proc/self/stat");
		}

		private ulong ReadSystemUpTime()
		{
			double num = (double)SystemClock.UptimeMillis() / 1000.0;
			double num2 = num * 100.0;
			return (ulong)num2;
		}
	}
