	public class MemoryUtilizationMonitor : WorkoutPeriodicMonitor, IMemoryUtilizationMonitor
	{
		private const string LogTag = "MemoryUtilizationMonitor";

		private const int BytesInKilobyte = 1024;

		private const string ProcMemInfoPath = "/proc/meminfo";

		private const string ProcSelfStatM = "/proc/self/statm";

		private readonly int[] processIDs;

		private readonly ActivityManager activityManager;

		private readonly ActivityManager.MemoryInfo memInfo;

		private readonly MemoryUtilizationReport.MemorySample currMemoryUtilization;

		private MemoryUtilizationReport memUtilReport;

		public MemoryUtilizationMonitor(Application app)
		{
			if (app == null)
			{
				throw new ArgumentNullException("app");
			}
			activityManager = app.GetSystemService("activity") as ActivityManager;
			memInfo = new ActivityManager.MemoryInfo();
			ActivityManager.RunningAppProcessInfo runningAppProcessInfo = new ActivityManager.RunningAppProcessInfo();
			ActivityManager.GetMyMemoryState(runningAppProcessInfo);
			processIDs = new int[1] { runningAppProcessInfo.Pid };
			currMemoryUtilization = new MemoryUtilizationReport.MemorySample();
			Init();
		}

		public override void TrySetSamplingParams()
		{
			if (Mvx.TryResolve<IFeatureFlagManager>(out var service) && service.IsFeatureEnabled(FeatureFlags.MemoryUtilizationMonitoring))
			{
				base.samplingInterval = TimeSpan.FromMilliseconds(service.GetInt(FeatureFlags.MemoryUtilizationMonitoringIntervalMs));
			}
		}

		protected override void StartNewReport()
		{
			memUtilReport = memUtilReport ?? new MemoryUtilizationReport(base.samplingInterval);
		}

		protected override void ResetReport()
		{
			memUtilReport.AndroidThresholdMemoryKb = 0L;
			memUtilReport.AndroidTotalMemoryKb = 0L;
			memUtilReport.Warmup.Reset();
			memUtilReport.InWorkout.Reset();
			memUtilReport.Cooldown.Reset();
			memUtilReport.IsRecoveryWorkout = null;
			memUtilReport.WorkoutCategory = null;
			memUtilReport.WorkoutId = null;
		}

		protected override async System.Threading.Tasks.Task AddStartingSample(MonitoringReportTypes reportType)
		{
			activityManager.GetMemoryInfo(memInfo);
			memUtilReport.AndroidTotalMemoryKb = memInfo.TotalMem / 1024;
			memUtilReport.AndroidThresholdMemoryKb = memInfo.Threshold / 1024;
			if (memUtilReport.AndroidTotalMemoryKb == 0L)
			{
				memUtilReport.AndroidTotalMemoryKb = GetTotalKbUsableRAM();
			}
			AddSample(reportType);
			await System.Threading.Tasks.Task.CompletedTask;
		}

		protected override void AddSample(MonitoringReportTypes reportType)
		{
			MemoryUtilizationReport.MemorySample memoryUtilization = GetMemoryUtilization();
			switch (reportType)
			{
			case MonitoringReportTypes.Warmup:
				memUtilReport.Warmup.AddSample(memoryUtilization);
				break;
			case MonitoringReportTypes.InWorkout:
				memUtilReport.InWorkout.AddSample(memoryUtilization);
				break;
			case MonitoringReportTypes.Cooldown:
				memUtilReport.Cooldown.AddSample(memoryUtilization);
				break;
			}
		}

		private MemoryUtilizationReport.MemorySample GetMemoryUtilization()
		{
			long monoTotalManagedMemoryKb = GC.GetTotalMemory(forceFullCollection: false) / 1024;
			int appResidentMemoryKb = GetAppResidentMemoryKb();
			activityManager.GetMemoryInfo(memInfo);
			long androidAvailableMemoryKb = memInfo.AvailMem / 1024;
			global::Android.OS.Debug.MemoryInfo memoryInfo = activityManager.GetProcessMemoryInfo(processIDs)[0];
			currMemoryUtilization.AndroidTotalProportionalSetSizeKb = memoryInfo.TotalPss;
			currMemoryUtilization.AndroidTotalPrivateDirtyKb = memoryInfo.TotalPrivateDirty;
			currMemoryUtilization.AndroidAvailableMemoryKb = androidAvailableMemoryKb;
			currMemoryUtilization.LinuxResidentSetSizePages = appResidentMemoryKb;
			currMemoryUtilization.MonoTotalManagedMemoryKb = monoTotalManagedMemoryKb;
			return currMemoryUtilization;
		}

		public override void PopulateWorkoutInfo(IWorkoutSettings workoutSettings)
		{
			memUtilReport?.PopulateWorkoutInfo(workoutSettings);
		}

		protected override async System.Threading.Tasks.Task FinalizeReport()
		{
			if (Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				await service.SendMemoryUtilizationReport(memUtilReport).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private int GetTotalKbUsableRAM()
		{
			int result = 0;
			if (System.IO.File.Exists("/proc/meminfo"))
			{
				try
				{
					using StreamReader streamReader = System.IO.File.OpenText("/proc/meminfo");
					string text = streamReader.ReadLine();
					string[] array = text.Split(" ");
					if (int.TryParse(array[8], out var result2))
					{
						result = result2;
					}
				}
				catch (System.Exception exception)
				{
					iFit.Logger.Log.Trace("MemoryUtilizationMonitor", "Exception reading /proc/meminfo", exception);
				}
			}
			else
			{
				iFit.Logger.Log.Trace("MemoryUtilizationMonitor", "GetTotalKbUsableRAM: /proc/meminfo not found");
			}
			return result;
		}

		private int GetAppResidentMemoryBytes()
		{
			int result = 0;
			if (System.IO.File.Exists("/proc/self/statm"))
			{
				try
				{
					using StreamReader streamReader = System.IO.File.OpenText("/proc/self/statm");
					string text = streamReader.ReadLine();
					string[] array = text.Split(" ");
					if (int.TryParse(array[1], out var result2))
					{
						result = result2 * System.Environment.SystemPageSize;
					}
				}
				catch (System.Exception exception)
				{
					iFit.Logger.Log.Trace("MemoryUtilizationMonitor", "Exception reading /proc/self/statm", exception);
				}
			}
			else
			{
				iFit.Logger.Log.Trace("MemoryUtilizationMonitor", "GetAppResidentMemoryBytes: /proc/self/statm file not found");
			}
			return result;
		}

		private int GetAppResidentMemoryKb()
		{
			return GetAppResidentMemoryBytes() / 1024;
		}
	}
}
