	public class WolfAndroidAuthenticatedHttpClientHandler : iFit.Api.AuthenticatedHttpClientHandler
	{
		private IMvxAndroidCurrentTopActivity _app;

		private IMvxMainThreadDispatcher _mainThread;

		private readonly IApplicationRestarter appRestarter;

		private IMvxAndroidCurrentTopActivity App => _app ?? (_app = Mvx.Resolve<IMvxAndroidCurrentTopActivity>());

		private IMvxMainThreadDispatcher MainThread => _mainThread ?? (_mainThread = Mvx.Resolve<IMvxMainThreadDispatcher>());

		public WolfAndroidAuthenticatedHttpClientHandler(IIfitApiService ifitApiService, IApplicationRestarter appRestarter)
			: base(ifitApiService)
		{
			this.appRestarter = appRestarter;
		}

		protected override async Task<HttpResponseMessage> SendAsync(HttpRequestMessage request, System.Threading.CancellationToken cancellationToken)
		{
			try
			{
				return await System.Threading.Tasks.Task.Run(async () => await base.SendAsync(request, cancellationToken));
			}
			catch (FieldAccessException)
			{
				MainThread.RequestMainThreadAction(delegate
				{
					Toast.MakeText(App.Activity, Wolf.Core.Resources.AppStrings.invalid_state_restart, ToastLength.Long).Show();
				});
				await System.Threading.Tasks.Task.Delay(3500);
				appRestarter.ScheduleToRestart(TimeSpan.FromSeconds(5.0));
				global::Android.OS.Process.KillProcess(global::Android.OS.Process.MyPid());
			}
			catch (ConnectivityException ex2)
			{
				iFit.Logger.Log.Error("Api", "Unable to connect to internet: " + ex2.Message);
				throw;
			}
			return null;
		}
	}
