	public class AppReviewService : AppReviewServiceBase
	{
		private static readonly int[] WorkoutReviewCounts = new int[3] { 10, 25, 50 };

		public AppReviewService(IDeviceInformation deviceInformation, IDialogPresenter presenter, IWolfAnalytics analytics, IWolfTrackingService trackingService, IBranchService branchService = null)
			: base(deviceInformation, presenter, analytics, trackingService, branchService)
		{
		}

		protected override bool ShouldRequestReview()
		{
			return WorkoutReviewCounts.Any((int count) => deviceInformation.NumberOfWorkouts == count);
		}

		protected override void RequestPlatformReview()
		{
			string packageName = Application.Context.PackageName;
			if (string.IsNullOrWhiteSpace(packageName))
			{
				return;
			}
			global::Android.Net.Uri uri = global::Android.Net.Uri.Parse("market://details?id=" + packageName);
			iFit.Logger.Log.Trace("AppReviewService", $"Uri: {uri}");
			Intent intent = new Intent("android.intent.action.VIEW", uri);
			if (!Application.Context.TryResolveActivity(intent, out var resultingPackages))
			{
				uri = global::Android.Net.Uri.Parse("https://play.google.com/store/apps/details?id=" + packageName);
				iFit.Logger.Log.Trace("AppReviewService", $"Uri: {uri}");
				intent = new Intent("android.intent.action.VIEW", uri);
				if (!Application.Context.TryResolveActivity(intent, out resultingPackages))
				{
					return;
				}
			}
			try
			{
				intent.AddFlags(ActivityFlags.ClearWhenTaskReset | ActivityFlags.MultipleTask | ActivityFlags.NewTask | ActivityFlags.NoHistory);
				Application.Context.StartActivity(intent);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("AppReviewService", "Unable to start market activity", exception);
			}
		}
	}
	public class BackgroundEmailerService : BaseBackgroundEmailerService
	{
		public override void SendEmail(EmailCredentials credentials, EmailRecipient recipient, string subject, string body)
		{
			if (string.IsNullOrWhiteSpace(credentials.Address) || credentials.Password == null || credentials.Password.Length == 0)
			{
				throw new ArgumentException("Must have valid authentication information to continue.");
			}
			MimeMessage message = BuildMessage(credentials, recipient, subject, body);
			SendMessage(credentials, message);
		}

		private static MimeMessage BuildMessage(EmailCredentials credentials, EmailRecipient recipient, string subject, string body)
		{
			MimeMessage mimeMessage = new MimeMessage();
			mimeMessage.From.Add(new MailboxAddress(credentials.Name, credentials.Address));
			mimeMessage.To.Add(new MailboxAddress(recipient.Name, recipient.Address));
			mimeMessage.Subject = subject;
			mimeMessage.Body = new TextPart(TextFormat.Plain)
			{
				Text = body
			};
			return mimeMessage;
		}

		private static void SendMessage(EmailCredentials credentials, MimeMessage message)
		{
			using SmtpClient smtpClient = new SmtpClient();
			smtpClient.ServerCertificateValidationCallback = (RemoteCertificateValidationCallback)Delegate.Combine(smtpClient.ServerCertificateValidationCallback, new RemoteCertificateValidationCallback(OnServerCertificateValidation));
			smtpClient.Connect("smtp.gmail.com", 465, useSsl: true);
			smtpClient.Authenticate(credentials.Address, iFit.Extensions.StringExtensions.TransformString(credentials.Password));
			smtpClient.Send(message);
			smtpClient.Disconnect(quit: true);
		}

		private static bool OnServerCertificateValidation(object sender, X509Certificate certificate, X509Chain chain, SslPolicyErrors errors)
		{
			if (errors != SslPolicyErrors.None)
			{
				return errors == SslPolicyErrors.RemoteCertificateNameMismatch;
			}
			return true;
		}
	}
