	public static class DeepLinkService
	{
		private class LinkListener : Java.Lang.Object, IOnSuccessListener, IJavaObject, IDisposable, IJavaPeerable, IOnFailureListener
		{
			private const string LogTag = "DeepLinkListener";

			private readonly global::Android.Net.Uri linkUri;

			public LinkListener(Intent intent)
			{
				linkUri = global::Android.Net.Uri.Parse(intent.DataString ?? string.Empty);
			}

			public LinkListener(global::Android.Net.Uri linkUri)
			{
				this.linkUri = linkUri;
			}

			public void OnSuccess(Java.Lang.Object result)
			{
				PendingDynamicLinkData pendingDynamicLinkData = global::Android.Runtime.Extensions.JavaCast<PendingDynamicLinkData>(result);
				IBranchService branchService;
				if (pendingDynamicLinkData != null)
				{
					iFit.Logger.Log.Trace("DeepLinkListener", $"Firebase deep link navigation received: {pendingDynamicLinkData.Link}");
					AppLinkingService instance = AppLinkingService.Instance;
					instance.HandleExternalLinkRequest(pendingDynamicLinkData.Link.ToString());
				}
				else if (Mvx.TryResolve<IBranchService>(out branchService))
				{
					if (!Mvx.TryResolve<IBranchConfigService>(out var branchConfigService))
					{
						return;
					}
					System.Threading.Tasks.Task.Run(async delegate
					{
						string text = await branchService.ResolveBranchLink(linkUri?.ToString(), branchConfigService.GetApiKey(), "Android");
						if (text != null)
						{
							iFit.Logger.Log.Trace("DeepLinkListener", "Branch deep link navigation received: " + text);
							AppLinkingService instance2 = AppLinkingService.Instance;
							instance2.HandleExternalLinkRequest(text);
						}
					});
				}
				else
				{
					iFit.Logger.Log.Error("DeepLinkListener", "Could not resolve IBranchService");
				}
			}

			public void OnFailure(Java.Lang.Exception e)
			{
				iFit.Logger.Log.Error("DeepLinkListener", "Failed to get dynamic link", e);
			}
		}

		private const string LogTag = "DeepLinkService";

		public static void TryHandlingDeepLink(global::Android.Net.Uri linkUri)
		{
			System.Threading.Tasks.Task.Run(async delegate
			{
				try
				{
					await AppLinkingService.Instance.WaitForApplicationReadyForLink();
					FirebaseDynamicLinks.Instance.GetDynamicLink(linkUri).AddOnSuccessListener(new LinkListener(linkUri));
				}
				catch (IllegalStateException exception)
				{
					iFit.Logger.Log.Error("DeepLinkService", "Error trying to handle deep link from url", exception);
				}
			});
		}

		public static void TryHandlingDeepLink(Intent intent)
		{
			System.Threading.Tasks.Task.Run(async delegate
			{
				try
				{
					await AppLinkingService.Instance.WaitForApplicationReadyForLink();
					FirebaseDynamicLinks.Instance.GetDynamicLink(intent).AddOnSuccessListener(new LinkListener(intent));
				}
				catch (IllegalStateException exception)
				{
					iFit.Logger.Log.Error("DeepLinkService", "Error trying to handle deep link from intent", exception);
				}
			});
		}
	}
