			try
			{
				subscriptionStatus = await GetSubscriptionStatus();
			}
			catch (System.Exception ex)
			{
				throw new SubscriptionStatusException(ex.Message);
			}
			if (subscriptionStatus == SubscriptionStatus.Active)
			{
				throw new SubscriptionActiveException(string.Format(Wolf.Core.Resources.AppStrings.onboarding_payment_subscription_active, Wolf.Core.Resources.AppStrings.onboarding_store_android));
			}
			androidPurchase = null;
			currentSku = sku;
			return await RetryWithExponentialBackoff(() => base.MakePurchase(sku), "MakePurchase");
		}

		private async Task<TRESULT> RetryWithExponentialBackoff<TRESULT>(Func<Task<TRESULT>> billingCall, string description)
		{
			iFit.Logger.Log.Trace("InAppPurchase", "IAP> calling " + description + ".");
			TRESULT val = await billingCall.RetryWithExponentialBackoff(null, ShouldRetryOnException);
			iFit.Logger.Log.Trace("InAppPurchase", $"IAP> {description} completed with {val}.");
			return val;
			bool ShouldRetryOnException(System.Exception exception)
			{
				if (exception is InAppBillingPurchaseException ex)
				{
					if (ex.PurchaseError == PurchaseError.ServiceDisconnected)
					{
						iFit.Logger.Log.Trace("InAppPurchase", "IAP> " + description + " failed with PurchaseError.ServiceDisconnected.");
						return true;
					}
					iFit.Logger.Log.Error("InAppPurchase", $"IAP> {description} error {ex.PurchaseError}", exception);
					return false;
				}
				iFit.Logger.Log.Error("InAppPurchase", "IAP> " + description + " error " + exception.GetType().Name, exception);
				return false;
			}
		}

		protected override string GetSignedDataFromPurchase(InAppBillingPurchase purchase)
		{
			return purchase.OriginalJson;
		}

		public override async System.Threading.Tasks.Task ProcessPurchase(string paymentType, string itemId)
		{
			await base.ProcessPurchase(paymentType, itemId);
			await TryContinueWithAndroidPurchase(null, currentPurchase.PurchaseToken, currentSku, paymentType, itemId);
		}

		public override async Task<bool> VerifyPurchase(string signedData, string signature, string productId = null, string transactionId = null)
		{
			IDictionary<string, string> dictionary = JsonConvert.DeserializeObject<IDictionary<string, string>>(signedData);
			await TryContinueWithAndroidPurchase(dictionary["packageName"]);
			iFit.Logger.Log.Trace("InAppPurchase", "IAP> One of two post-IAP functions completed");
			return true;
		}

		public override System.Threading.Tasks.Task CloseConnection()
		{
			androidPurchase = null;
			currentSku = string.Empty;
			return base.CloseConnection();
		}

		public override async Task<SubscriptionStatus> GetSubscriptionStatus()
		{
			SubscriptionStatus currentStatus = SubscriptionStatus.None;
			try
			{
				IEnumerable<InAppBillingPurchase> source = await RetryWithExponentialBackoff(() => CrossInAppBilling.Current.GetPurchasesAsync(ItemType.Subscription), "GetPurchasesAsync");
				if (source.Any((InAppBillingPurchase x) => x.State == PurchaseState.Purchased || x.State == PurchaseState.PaymentPending || x.State == PurchaseState.Purchasing || x.State == PurchaseState.Deferred))
				{
					currentStatus = SubscriptionStatus.Active;
				}
				else if (source.Any((InAppBillingPurchase x) => x.State != PurchaseState.Failed))
				{
					currentStatus = SubscriptionStatus.Expired;
				}
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("InAppPurchase", "Exception getting IAP purchase history", exception);
			}
			return currentStatus;
		}

		protected override async System.Threading.Tasks.Task SyncPurchase(InAppPurchaseOrder order)
		{
			InAppPurchaseAndroid androidMembership = order.GetPurchase() as InAppPurchaseAndroid;
			await apiService.Service.PurchaseAndroidMembership(androidMembership);
		}

		private async Task<bool> TryContinueWithAndroidPurchase(string packageName = null, string purchaseToken = null, string productId = null, string paymentType = null, string kitOrItemId = null)
		{
			if (androidPurchase == null)
			{
				androidPurchase = new InAppPurchaseAndroid();
			}
			if (packageName != null)
			{
				androidPurchase.PackageName = packageName;
			}
			if (purchaseToken != null)
			{
				androidPurchase.PurchaseToken = purchaseToken;
			}
			if (productId != null)
			{
				androidPurchase.ProductId = productId;
			}
			if (paymentType != null)
			{
				androidPurchase.PaymentType = paymentType;
			}
			if (kitOrItemId != null)
			{
				androidPurchase.KitOrItemId = kitOrItemId;
			}
			if (androidPurchase.PackageName != null && androidPurchase.PurchaseToken != null && androidPurchase.ProductId != null && androidPurchase.PaymentType != null && androidPurchase.KitOrItemId != null)
			{
				try
				{
					iFit.Logger.Log.Trace("InAppPurchase", "IAP> Syncing Android purchase");
					await apiService.Service.PurchaseAndroidMembership(androidPurchase);
					await PurchaseSyncCompleted();
					androidPurchase = null;
					return true;
				}
				catch (System.Exception ex)
				{
					wolfAnalytics.SuccessfulIapFailedApi(new Dictionary<string, string>
					{
						["productId"] = androidPurchase.ProductId,
						["packageName"] = androidPurchase.PackageName,
						["kitOrItemId"] = androidPurchase.KitOrItemId
					});
					iFit.Logger.Log.Error("InAppPurchase", "Error making purchase", ex);
					InAppPurchaseOrder purchaseOrder = new InAppPurchaseOrder(androidPurchase);
					androidPurchase = null;
					await PurchaseSyncFailed(purchaseOrder, ex);
				}
			}
			return false;
		}
	}
	public class LaunchEruUpdateService : ILaunchUpdate
	{
		public void RecoverMachine(int softwareNumber, string pairKey = null)
		{
			UpdateConnectedMachine();
		}

		public void UpdateConnectedMachine(bool _ = false)
		{
			if (!Mvx.TryResolve<IAppLauncherService>(out var launcher) || !Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				return;
			}
			try
			{
				service.RequestMainThreadAction(delegate
				{
					launcher.LaunchApp(LaunchableApp.EruUpdate);
				});
			}
			catch (ActivityNotFoundException)
			{
				iFit.Logger.Log.Trace("Settings", "Could not find activity for Eru update launch");
			}
			catch (System.Exception arg)
			{
				iFit.Logger.Log.Trace("Settings", $"Exception launching Eru update: {arg}");
			}
		}
	}
	public class LogFileServiceConfig : ILogFileServiceConfig
	{
		private readonly string CustomLogTag = "Setup";

		public string LogDirPath { get; }

		public double MaxLogFolderSizeMB => 250.0;

		public int MaxDaysToKeepLogs => 4;

		public string EruLogPath { get; private set; }

		public LogFileServiceConfig(string logDirPath, string eruLogFolder)
		{
			LogDirPath = logDirPath;
			EruLogPath = TryGetEruLogPath(eruLogFolder);
		}

		private string TryGetEruLogPath(string eruLogFolder)
		{
			string result = string.Empty;
			try
			{
				Java.IO.File file = new Java.IO.File(eruLogFolder);
				if (file.Exists() && file.IsDirectory)
				{
					result = eruLogFolder;
				}
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(CustomLogTag, "LogFileServiceConfig - failed to check for existing eruLogFolder folder.", exception);
			}
			return result;
		}
	}
	public class StandaloneBleRadioStatusService : BleRadioStatusService
	{
		private readonly IMvxMainThreadDispatcher dispatch;

		private readonly IDialogPresenter dialogPresenter;

		public StandaloneBleRadioStatusService(IMvxMainThreadDispatcher dispatch, IDialogPresenter dialogPresenter)
		{
			this.dispatch = dispatch;
			this.dialogPresenter = dialogPresenter;
		}

		public override void RequestEnableBluetooth(bool notifyIfCannotEnable, string currentScreen = null, System.Action onCancel = null)
		{
			if (isCyclingRadio)
			{
				iFit.Logger.Log.Trace("Ble", "Already attempting to cycle ble radio");
				return;
			}
			BluetoothAdapter defaultAdapter = BluetoothAdapter.DefaultAdapter;
			if (defaultAdapter == null)
			{
				iFit.Logger.Log.Error("Ble", "Default Bluetooth Adapter was null");
			}
			else if (!defaultAdapter.IsEnabled)
			{
				Func<System.Threading.CancellationToken, Task<object>> enableFunc = delegate
				{
					EnableBleRadio();
					return System.Threading.Tasks.Task.FromResult<object>(null);
				};
				dispatch?.RequestMainThreadAction(delegate
				{
					ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(Shire.Core.Resources.AppStrings.ble_error, Wolf.Core.Resources.AppStrings.can_we_turn_on_ble, enableFunc, cancellableOperation: false, null, Wolf.Core.Resources.AppStrings.no, Wolf.Core.Resources.AppStrings.yes, OnConfirmActionTiming.AfterClose, null, onCancel);
					dialogPresenter?.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: false, arbitraryData);
				});
			}
		}
	}
	public class WebAuthenticatorService : IWebAuthenticatorService
	{
		public Task<WebAuthenticatorResult> AuthenticateAsync(System.Uri url, System.Uri callbackUrl)
		{
			try
			{
				typeof(CustomTabsActivityManager).GetField("instance", System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.NonPublic)?.SetValue(null, null);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("WebAuthenticator", "Failed to reset CustomTabsActivityManager instance.", exception);
			}
			return WebAuthenticator.AuthenticateAsync(url, callbackUrl);
		}
	}
	public class WolfAppVersionService : AppVersionService
	{
		private const string EruPackageName = "com.ifit.eru";

		private const string LauncherPackageName = "com.ifit.launcher";

		public WolfAppVersionService()
		{
			SafelyAddSupplementalPackage("com.ifit.eru", "eruVersion");
			SafelyAddSupplementalPackage("com.ifit.launcher", "launcherVersion");
		}

		private void SafelyAddSupplementalPackage(string packageName, string key)
		{
			VersionInfo versionInfo = GetVersionInfo(packageName);
			if (versionInfo != null)
			{
				base.SupplementalVersionInfo.TryAdd(key, versionInfo);
			}
		}
	}
	public class FacebookIdService : IFacebookIdService
	{
		private readonly IDisposable environmentChanged;

		public string FacebookAppId => Mvx.Resolve<ILocalSettings>().EnvironmentToUse.FacebookAppId();

		public FacebookIdService()
		{
			if (Mvx.TryResolve<IIfitApiService>(out var service))
			{
				environmentChanged?.Dispose();
				environmentChanged = service.WhenApiEnvironmentChanged.Subscribe(delegate(IIfitEnvironment env)
				{
					string facebookAppId = env.FacebookAppId;
					iFit.Logger.Log.Info("Api", "Facebook App ID changing due to environment change: " + facebookAppId);
				});
			}
			else
			{
				iFit.Logger.Log.Error("Api", "Facebook App ID changes failed to set up");
			}
		}
	}
}
