		public AndroidThemeService(IDeviceInformation deviceInfo, IFeatureFlagManager featureFlagManager, IBlobCacheService cacheService)
			: base(deviceInfo, featureFlagManager, cacheService)
		{
			headlessBikeModeStyles = (from keyValue in headlessBikeModeStyles.Concat(strengthMirrorModeStyles)
				group keyValue by keyValue.Key).ToDictionary((IGrouping<Type, KeyValuePair<Type, int>> merged) => merged.Key, (IGrouping<Type, KeyValuePair<Type, int>> merged) => merged.First().Value);
			themeMapping = new Dictionary<Wolf.Core.Services.Theming.Theme, Dictionary<Type, int>>
			{
				{
					Wolf.Core.Services.Theming.Theme.Light,
					lightModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.Dark,
					darkModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.StrengthMirror,
					strengthMirrorModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.Rainbow,
					rainbowModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.StrengthHeadlessBike,
					headlessBikeModeStyles
				}
			};
			fragmentThemeMapping = new Dictionary<Wolf.Core.Services.Theming.Theme, Dictionary<Type, int>>
			{
				{
					Wolf.Core.Services.Theming.Theme.Light,
					fragmentLightModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.Dark,
					fragmentDarkModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.StrengthMirror,
					fragmentStrengthMirrorModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.Rainbow,
					fragmentRainbowStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.StrengthHeadlessBike,
					fragmentStrengthMirrorModeStyles
				}
			};
			viewThemeMapping = new Dictionary<Wolf.Core.Services.Theming.Theme, Dictionary<Type, int>>
			{
				{
					Wolf.Core.Services.Theming.Theme.Light,
					viewLightModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.Dark,
					viewDarkModeStyles
				},
				{
					Wolf.Core.Services.Theming.Theme.Rainbow,
					viewRainbowStyles
				}
			};
		}

		public int? GetStyleForActivity(Activity activity)
		{
			Wolf.Core.Services.Theming.Theme key = CurrentTheme();
			if (themeMapping.TryGetValue(key, out var value) && value.TryGetValue(activity.GetType(), out var value2))
			{
				return value2;
			}
			return null;
		}

		public int? GetStyleForFragment(AndroidX.Fragment.App.Fragment fragment, Wolf.Core.Services.Theming.Theme? theme = null)
		{
			if (fragmentThemeMapping.TryGetValue(theme ?? CurrentTheme(), out var value) && value.TryGetValue(fragment.GetType(), out var value2))
			{
				return value2;
			}
			return null;
		}

		public int? GetStyleForView(View view)
		{
			Wolf.Core.Services.Theming.Theme key = CurrentTheme();
			if (viewThemeMapping.TryGetValue(key, out var value) && value.TryGetValue(view.GetType(), out var value2))
			{
				return value2;
			}
			return null;
		}
	}
