namespace Wolf.Android.Services.Platform
{
	public interface IAndroidActivityLifetimeFocusService : IDisposable
	{
		void SetFocusForActivityIfLost(Activity activity);

		void UnsetActivityRefocusListener();
	}
	public class AndroidActivityLifetimeFocusService : IAndroidActivityLifetimeFocusService, IDisposable
	{
		private bool isDisposed;

		private Activity activity;

		private ShireAndroidLifetimeMonitor activityLifetimeListener;

		public AndroidActivityLifetimeFocusService(IMvxAndroidActivityLifetimeListener activityLifetimeListener = null)
		{
			this.activityLifetimeListener = activityLifetimeListener as ShireAndroidLifetimeMonitor;
		}

		public void SetFocusForActivityIfLost(Activity activity)
		{
			UnsetActivityRefocusListener();
			this.activity = activity;
			if (activityLifetimeListener != null)
			{
				activityLifetimeListener.OnActivityChanged += HandleActivityChanged;
			}
		}

		public void UnsetActivityRefocusListener()
		{
			activity = null;
			if (activityLifetimeListener != null)
			{
				activityLifetimeListener.OnActivityChanged -= HandleActivityChanged;
			}
		}

		protected virtual void HandleActivityChanged(object sender, Activity activity)
		{
			if (activityLifetimeListener != null && activityLifetimeListener.Activity == null && this.activity != null)
			{
				activityLifetimeListener.OnViewNewIntent(this.activity);
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		private void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					UnsetActivityRefocusListener();
					activityLifetimeListener = null;
				}
				isDisposed = true;
			}
		}
	}
	public class AndroidPlatformMediaVolumeService : IPlatformMediaVolumeService
	{
		private const float SystemVolumeMaxPercent = 1f;

		private const int DefaultSystemVolumeIndex = 1;

		private AudioManager audioManager;

		private readonly int maxSystemVolumeIndex;

		public AndroidPlatformMediaVolumeService()
		{
			audioManager = (AudioManager)Application.Context.GetSystemService("audio");
			maxSystemVolumeIndex = audioManager?.GetStreamMaxVolume(global::Android.Media.Stream.Music) ?? 1;
		}

		public void SetPlatformMediaVolume(float volume)
		{
			try
			{
				if (audioManager == null)
				{
					iFit.Logger.Log.Error("Workout", "Audio Manager is null. Cannot adjust platform media volume.");
					return;
				}
				int index = (volume.Clamp(0f, 1f) * (float)maxSystemVolumeIndex * 1f).RoundToNearest(1.0);
				audioManager?.SetStreamVolume(global::Android.Media.Stream.Music, index, VolumeNotificationFlags.PlaySound);
			}
			catch (InvalidOperationException exception)
			{
				iFit.Logger.Log.Error("Workout", "Failed to obtain maximum system volume. Cannot adjust platform media volume.", exception);
			}
		}

		public float GetPlatformMediaVolume()
		{
			return 1f * (float)(audioManager?.GetStreamVolume(global::Android.Media.Stream.Music) ?? 1) / (float)maxSystemVolumeIndex * 1f;
		}
	}
	public class AndroidSystemAccessibilityOptions : ISystemAccessibilityOptions
	{
		private CaptioningManager captioningManager;

		public bool IsClosedCaptionsOn => GetClosedCaptionsOn();

		public AndroidSystemAccessibilityOptions(IMvxMainThreadDispatcher mvxMainThreadDispatcher)
		{
			mvxMainThreadDispatcher.RequestMainThreadAction(delegate
			{
				Java.Lang.Object systemService = Application.Context.GetSystemService("captioning");
				captioningManager = systemService as CaptioningManager;
			});
		}

		private bool GetClosedCaptionsOn()
		{
			return captioningManager?.IsEnabled ?? false;
		}
	}
}
namespace Wolf.Android.Services.File
{
	public class ApplicationFileService : IApplicationFileService
	{
		public void Clear()
		{
			string folderPath = System.Environment.GetFolderPath(System.Environment.SpecialFolder.MyDocuments);
			DirectoryInfo parent = Directory.GetParent(folderPath);
			if (!parent.Exists)
			{
				return;
			}
			DirectoryInfo[] directories = parent.GetDirectories();
			DirectoryInfo[] array = directories;
			foreach (DirectoryInfo directoryInfo in array)
			{
				if (!directoryInfo.Name.ToLowerInvariant().Equals("lib") && !directoryInfo.Name.EndsWith("files"))
				{
					ClearDirectory(directoryInfo);
				}
			}
		}

		private void ClearDirectory(DirectoryInfo directory)
		{
			if (directory.Name.Contains("exo_player_exo_cache"))
			{
				return;
			}
			System.IO.FileInfo[] files = directory.GetFiles();
			foreach (System.IO.FileInfo fileInfo in files)
			{
				if (!fileInfo.Name.Contains("exoplayer_internal"))
				{
					fileInfo.Delete();
				}
			}
			DirectoryInfo[] directories = directory.GetDirectories();
			foreach (DirectoryInfo directory2 in directories)
			{
				ClearDirectory(directory2);
			}
		}
	}
}
namespace Wolf.Android.Services.Configuration
{
	public abstract class AndroidConfigurationFileServiceBase<TConfigData> : ConfigurationFileServiceBase<TConfigData> where TConfigData : class
	{
		protected override string MainAppStoragePath => global::Android.OS.Environment.ExternalStorageDirectory.AbsolutePath;

		protected override string ReadAllFileContent(string filePath)
		{
			try
			{
				return System.IO.File.ReadAllText(filePath);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(LogTag, "Error in " + GetType().Name + " ReadAllFileContent method.", exception);
			}
			return null;
		}

		protected override void WriteAllFileContent(string filePath, string content)
		{
			try
			{
				System.IO.File.WriteAllText(filePath, content);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(LogTag, "Error in " + GetType().Name + " WriteAllFileContent method.", exception);
			}
		}

		protected override bool DoesFileExist(string filePath)
		{
			try
			{
				return System.IO.File.Exists(filePath);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(LogTag, "Error in " + GetType().Name + " DoesFileExist method.", exception);
			}
			return false;
		}

		protected override bool DoesDirectoryExist(string folderPath)
		{
			try
			{
				return Directory.Exists(folderPath);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(LogTag, "Error in " + GetType().Name + " DoesDirectoryExist method.", exception);
			}
			return false;
		}

		protected override void DeleteFile(string filePath)
