	public class StrengthMirrorFileService : AndroidConfigurationFileServiceBase<StrengthMirrorConfigFile>, IStrengthMirrorFileService, IConfigurationFileService<StrengthMirrorConfigFile>
	{
		public static readonly StrengthMirrorFileService Shared = new StrengthMirrorFileService();

		private readonly Regex StrengthMirrorConfigFilePattern = new Regex("((vault)|((strength)?[_-]?mirror))([_-]?([A-Za-z0-9]+)?)?\\.json$", RegexOptions.IgnoreCase);

		protected override string LogTag => "StrengthMirrorFileService";

		protected override string ActiveConfigFileName => "vault.config.json";

		public override StrengthMirrorConfigFile DefaultConfig => StrengthMirrorConfigFile.Defaults;

		private StrengthMirrorFileService()
		{
		}

		private System.IO.FileInfo FindFirstStrengthMirrorConfigFileOrDefault()
		{
			return FindStrengthMirrorConfigFiles()?.FirstOrDefault();
		}

		private IEnumerable<System.IO.FileInfo> FindStrengthMirrorConfigFiles()
		{
			if (!DoesDirectoryExist(base.StorageDirectoryPath))
			{
				return new System.IO.FileInfo[0];
			}
			try
			{
				DirectoryInfo directoryInfo = new DirectoryInfo(base.StorageDirectoryPath);
				if (!directoryInfo.Exists)
				{
					return new System.IO.FileInfo[0];
				}
				return from x in directoryInfo.GetFiles()
					where x != null && x.Exists && StrengthMirrorConfigFilePattern.IsMatch(x.Name)
					orderby x.Name
					select x;
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(LogTag, "Could not find strength mirror configuration files in " + GetType().Name + " FindStrengthMirrorConfigFiles.", exception);
			}
			return new System.IO.FileInfo[0];
		}

		protected override string GetStoredConfigFilePathOrDefault(string defaultResult = null)
		{
			return FindFirstStrengthMirrorConfigFileOrDefault()?.FullName ?? defaultResult;
		}
	}
