namespace Wolf.Android.Services.Broadcast
{
	public abstract class Broadcast
	{
		protected abstract string Action { get; }

		protected abstract Dictionary<string, string> Extras { get; set; }

		public void SendBroadcast(Context context)
		{
			context.SendBroadcast(GetIntent());
		}

		private Intent GetIntent()
		{
			Intent intent = new Intent(Action);
			foreach (KeyValuePair<string, string> extra in Extras)
			{
				intent.PutExtra(extra.Key, extra.Value);
			}
			return intent;
		}
	}
	public class SendBroadcastService : ISendBroadcastService
	{
