namespace Wolf.Android.Raygun
{
	public class RaygunClient : BaseRaygunClient
	{
		private const string Tag = "Raygun";

		private const string UnknownDeviceName = "Unknown";

		public override string FullAppVersion { get; }

		public RaygunClient(IAppVersionService appVersionService)
		{
			FullAppVersion = appVersionService.MainAppVersionInfo.FullAppVersion;
		}

		public override void SetupAndAttachPulse(string clientId)
		{
			iFit.Logger.Log.Trace("Raygun", "Initializing Wolf Raygun client");
			try
			{
				Mindscape.Raygun4Net.RaygunClient.Initialize(clientId);
				if (Platform.CurrentActivity != null)
				{
					iFit.Logger.Log.Trace("Raygun", "Current Activity Is Not Null, Setting RUM pulse.");
					Mindscape.Raygun4Net.RaygunClient.Current.AttachPulse(Platform.CurrentActivity);
				}
				else
				{
					iFit.Logger.Log.Trace("Raygun", "Current Activity Is Null, Will Set RUM pulse at a later point.");
					Platform.ActivityStateChanged -= OnCurrentOnActivityStateChanged;
					Platform.ActivityStateChanged += OnCurrentOnActivityStateChanged;
				}
				Mindscape.Raygun4Net.RaygunClient.Current.CustomGroupingKey += iFitAnrErrorUtil.AnrErrorGroupingKey;
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("Raygun", "couldn't attach pulse", exception);
			}
		}

		private static void OnCurrentOnActivityStateChanged(object sender, ActivityStateChangedEventArgs e)
		{
			if (e.State == ActivityState.Created)
			{
				iFit.Logger.Log.Trace("Raygun", "Current Activity Has Been Set, Setting RUM pulse.");
				Mindscape.Raygun4Net.RaygunClient.Current.AttachPulse(Platform.CurrentActivity);
				Platform.ActivityStateChanged -= OnCurrentOnActivityStateChanged;
			}
		}

		protected override void ClientOnSendingMessage(object sender, RaygunSendingMessageEventArgs e)
		{
			if (e?.Message?.Details != null)
			{
				e.Message.Details.MachineName = BluetoothAdapter.DefaultAdapter?.Name ?? "Unknown";
			}
			base.ClientOnSendingMessage(sender, e);
		}
	}
