	public class FeedFmNotificationView : BaseFragment<FeedFmNotificationViewModel>, IAsyncViewCreator
	{
		private FeedFmWidget feedFmWidget;

		private IDisposable feedFmWidgetMarqueeFinishedSub;

		protected override int LayoutId => 2131624091;

		public TaskCompletionSource<bool> ViewCreated { get; set; } = new TaskCompletionSource<bool>();

		public AudioTrack AudioTrack => base.ViewModel.AudioTrack.Value;

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			feedFmWidget = view.FindViewById<FeedFmWidget>(2131428059);
			if (feedFmWidget != null)
			{
				feedFmWidget.Touch -= HandleNotificationTapped;
				feedFmWidget.Touch += HandleNotificationTapped;
				feedFmWidget?.ShowAsNotification(base.ViewModel?.AudioTrack.Value);
				feedFmWidgetMarqueeFinishedSub = feedFmWidget.WhenMarqueeIsFinished.Subscribe(DismissNotification);
			}
			BindControls();
			ViewCreated.SetResult(result: true);
		}

		private void HandleNotificationTapped(object sender, View.TouchEventArgs e)
		{
			base.ViewModel?.HandleNotificationTap();
		}

		private void BindControls()
		{
			MvxFluentBindingDescriptionSet<FeedFmNotificationView, FeedFmNotificationViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<FeedFmNotificationView, FeedFmNotificationViewModel>();
			mvxFluentBindingDescriptionSet.Bind(feedFmWidget).For((FeedFmWidget v) => v.AudioTrack).To((FeedFmNotificationViewModel vm) => vm.AudioTrack)
				.OneWay();
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void DismissNotification(object _)
		{
			base.ViewModel?.DismissNotification();
		}

		protected override void CleanUp()
		{
			base.ViewModel?.DismissNotification();
			if (feedFmWidget != null)
			{
				feedFmWidget.Touch -= HandleNotificationTapped;
				feedFmWidget = iFit.Extensions.Android.JavaExtensions.DisposeSafe(feedFmWidget);
			}
			feedFmWidgetMarqueeFinishedSub?.Dispose();
			feedFmWidgetMarqueeFinishedSub = null;
		}

		public void ShowAsNotification(AudioTrack audioTrackValue)
		{
			feedFmWidget?.ShowAsNotification(audioTrackValue);
		}

		public void ReloadNotificationContent(string guid)
		{
			base.ViewModel.ReloadNotificationContent(guid);
		}

		public async System.Threading.Tasks.Task Init(string guidId)
		{
			await base.ViewModel.Init(guidId);
		}
	}
