	public class FeedFmToggleWidget : ConstraintLayout
	{
		private bool isDisposed;

		private AppCompatTextView infoTitle;

		private AppCompatTextView infoDescription;

		private IMusicService musicService;

		private IMediaSettings mediaSettings;

		private IDisposable liveWorkoutMusicStateChangedSub;

		private IDisposable feedFmToggledSub;

		private MusicState currentState = MusicState.Unavailable;

		private bool _checked;

		public SwitchCompat FeedFmToggle { get; private set; }

		public MusicState CurrentState
		{
			get
			{
				return currentState;
			}
			set
			{
				if (!isDisposed)
				{
					currentState = value;
					UpdateUi();
				}
			}
		}

		private int Layout(bool isTablet)
		{
			if (!isTablet)
			{
				return 2131624090;
			}
			return 2131624089;
		}

		private void UpdateUi()
		{
			if (musicService.LiveWorkoutMusicState == LiveWorkoutMusicState.Other || mediaSettings.HasDisabledFeedFmPlayback)
			{
				try
				{
					switch (currentState)
					{
					case MusicState.PausedForMusicRegion:
					case MusicState.Playing:
						SetUiToggleAvailable();
						break;
					case MusicState.PausedManually:
						SetUiToggleAvailable();
						break;
					case MusicState.PausedDisabled:
						SetUiForDisabled();
						break;
					case MusicState.Loading:
					case MusicState.Unavailable:
						SetUiForOff();
						break;
					default:
						throw new ArgumentOutOfRangeException();
					}
					return;
				}
				catch (System.Exception ex)
				{
					global::Android.Util.Log.Error("Audio", ex.GetType().Name + " occurred in updating FeedFmToggleWidget UI from CurrentState.", ex);
					return;
				}
			}
			if (musicService.LiveWorkoutMusicState == LiveWorkoutMusicState.TssStartingSoon)
			{
				SetUiForTssStartingSoon();
			}
			else if (musicService.LiveWorkoutMusicState == LiveWorkoutMusicState.StationChangerStartingSoon)
			{
				SetUiForStationChangerStartingSoon();
			}
		}

		private void SetUiForOff()
		{
			Visibility = ViewStates.Invisible;
		}

		private void SetUiForDisabled()
		{
			Visibility = ViewStates.Visible;
			FeedFmToggle.Visibility = ViewStates.Gone;
			infoTitle.Text = Wolf.Core.Resources.AppStrings.feed_fm.ToUpperInvariant();
			infoTitle.Visibility = ViewStates.Visible;
			infoDescription.Text = Wolf.Core.Resources.AppStrings.feed_fm_unavailable_for_workout;
			infoDescription.Visibility = ViewStates.Visible;
		}

		private void SetUiToggleAvailable()
		{
			Visibility = ViewStates.Visible;
			FeedFmToggle.Visibility = ViewStates.Visible;
			infoTitle.Visibility = ViewStates.Gone;
			infoDescription.Visibility = ViewStates.Gone;
		}

		private void SetUiForTssStartingSoon()
		{
			Visibility = ViewStates.Visible;
			FeedFmToggle.Visibility = ViewStates.Gone;
			infoTitle.Text = Wolf.Core.Resources.AppStrings.feed_fm.ToUpperInvariant();
			infoTitle.Visibility = ViewStates.Visible;
			infoDescription.Text = Wolf.Core.Resources.AppStrings.feed_fm_trainer_select_station_starting_soon;
			infoDescription.Visibility = ViewStates.Visible;
		}

		private void SetUiForStationChangerStartingSoon()
		{
			Visibility = ViewStates.Visible;
			FeedFmToggle.Visibility = ViewStates.Gone;
			infoTitle.Text = Wolf.Core.Resources.AppStrings.feed_fm.ToUpperInvariant();
			infoTitle.Visibility = ViewStates.Visible;
			infoDescription.Text = Wolf.Core.Resources.AppStrings.feed_fm_non_tss_live_workout_starting_soon;
			infoDescription.Visibility = ViewStates.Visible;
		}

		public FeedFmToggleWidget(Context context)
			: base(context)
		{
			Init(context);
		}

		public FeedFmToggleWidget(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context);
		}

		public FeedFmToggleWidget(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context);
		}

		private void Init(Context context)
		{
			bool isTablet = true;
			if (Mvx.TryResolve<IDeviceInformation>(out var service))
			{
				isTablet = service?.IsTablet ?? false;
			}
			View view = LayoutInflater.From(context).Inflate(Layout(isTablet), this, attachToRoot: true);
			base.ClipToOutline = true;
			FeedFmToggle = view.FindViewById<SwitchCompat>(2131428053);
			FeedFmToggle.Text = Wolf.Core.Resources.AppStrings.feed_fm.ToUpperInvariant();
			infoTitle = view.FindViewById<AppCompatTextView>(2131428061);
			infoDescription = view.FindViewById<AppCompatTextView>(2131428060);
			musicService = Mvx.Resolve<IMusicService>();
			mediaSettings = Mvx.Resolve<IMediaSettings>();
			liveWorkoutMusicStateChangedSub?.Dispose();
			liveWorkoutMusicStateChangedSub = musicService.LiveWorkoutMusicStateChanged.Subscribe(delegate
			{
				UpdateUi();
			});
			IMvxMessenger mvxMessenger = Mvx.Resolve<IMvxMessenger>();
			feedFmToggledSub = mvxMessenger.Subscribe<InWorkoutMusicControlsViewModel.InWorkoutFeedFmMusicToggledMessage>(delegate
			{
				UpdateUi();
			});
		}

		protected override void Dispose(bool disposing)
		{
			isDisposed = true;
			if (disposing)
			{
				liveWorkoutMusicStateChangedSub?.Dispose();
				liveWorkoutMusicStateChangedSub = null;
				feedFmToggledSub?.Dispose();
				feedFmToggledSub = null;
			}
			base.Dispose(disposing);
		}
	}
	public class FeedFmWidget : CardView, View.IOnTouchListener, IJavaObject, IDisposable, IJavaPeerable
	{
		protected AppCompatTextView titleTextView;

		protected AppCompatTextView artistAlbumTextView;

		protected HorizontalScrollView titleTextScrollView;

		protected HorizontalScrollView artistAlbumScrollView;

		private const int DelayBeforeMarqueeScrollMs = 2000;

		private const float PixelsPerSecond = 50f;

		private const int MinimumNotificationTimeMs = 6500;

		private const int DelayBeforeScrollBack = 2000;

		private const int SecondsBetweenAutoScroll = 20;

		private const int SecondsBetweenPancakeAutoScroll = 2;

		private bool showingAsNotification;

		protected bool isDisposed;

		private IMainThreadService mainThreadService;

		protected CancellationTokenSource animationCts;

		private Subject<object> whenMarqueeIsFinished = new Subject<object>();

		public bool IsMarqueeAnimating { get; set; }

		protected virtual int LayoutResId => 2131624086;

		public bool IsTrainerSelectStation { get; set; }

		public AudioTrack AudioTrack { get; set; }

		public IObservable<object> WhenMarqueeIsFinished => whenMarqueeIsFinished;

		public virtual MusicState CurrentState { get; set; }

		public string TitleText
		{
			get
			{
				return titleTextView?.Text;
			}
			set
			{
				if (!isDisposed && titleTextView != null)
				{
					if (string.IsNullOrWhiteSpace(value))
					{
						titleTextView.Visibility = ViewStates.Gone;
						return;
					}
					titleTextView.Visibility = ViewStates.Visible;
					titleTextView.Text = value;
				}
			}
		}

		public string ArtistAlbumText
		{
			get
			{
				return artistAlbumTextView?.Text;
			}
			set
			{
				if (!isDisposed && artistAlbumTextView != null)
				{
					if (string.IsNullOrWhiteSpace(value))
					{
						artistAlbumTextView.Visibility = ViewStates.Gone;
						return;
					}
					artistAlbumTextView.Visibility = ViewStates.Visible;
					artistAlbumTextView.Text = value;
				}
			}
		}

		public override ViewStates Visibility
		{
			get
			{
				return base.Visibility;
			}
			set
			{
				if (isDisposed || base.Visibility == value)
				{
					return;
				}
				if (AudioTrack == null && showingAsNotification)
				{
					global::Android.Util.Log.Debug("Audio", $"FeedFm Widget - tried to change visibility to {value} when AudioTrack was null");
					base.Visibility = ViewStates.Gone;
					return;
				}
				base.Visibility = value;
				if (!showingAsNotification)
				{
					CancelAnimation();
					animationCts = new CancellationTokenSource();
					if (value == ViewStates.Visible)
					{
						ForceUpdateViews();
						AnimateMarqueeAfterTime(animationCts.Token);
					}
				}
			}
		}

		public FeedFmWidget(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public FeedFmWidget(Context context)
			: base(context)
		{
			Init(context, null);
		}

		public FeedFmWidget(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public FeedFmWidget(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context, attrs);
		}

		protected virtual void Init(Context context, IAttributeSet attrs)
		{
			InitDependencies();
			bool flag = true;
			if (Mvx.TryResolve<IDeviceInformation>(out var service))
			{
				flag = service.IsTablet;
			}
			LayoutInflater.From(context)?.Inflate(LayoutResId, this, attachToRoot: true);
			ConstraintLayout constraintLayout = FindViewById<ConstraintLayout>(2131428057);
			if (!flag)
			{
				constraintLayout?.SetBackgroundColor(context.GetColorCompat(2131099955));
			}
			titleTextView = FindViewById<AppCompatTextView>(2131428051);
			titleTextScrollView = FindViewById<HorizontalScrollView>(2131428052);
			titleTextScrollView?.SetOnTouchListener(this);
			artistAlbumTextView = FindViewById<AppCompatTextView>(2131428041);
			artistAlbumScrollView = FindViewById<HorizontalScrollView>(2131428042);
			artistAlbumScrollView?.SetOnTouchListener(this);
		}

		protected void InitDependencies()
		{
			Mvx.TryResolve<IMainThreadService>(out mainThreadService);
		}

		public void SetTrackInfo(AudioTrack audioTrack)
		{
			if (isDisposed || titleTextView == null || artistAlbumTextView == null)
			{
				return;
			}
			if ((audioTrack != null && audioTrack.Title?.IsNullOrEmpty() == true) || (audioTrack != null && audioTrack.Artist?.IsNullOrEmpty() == true))
			{
				global::Android.Util.Log.Error("Audio", string.Format("{0} called with empty values for {1}: {2}", "SetTrackInfo", "audioTrack", audioTrack));
				titleTextView.Text = string.Empty;
				artistAlbumTextView.Text = string.Empty;
				return;
			}
			AudioTrack = audioTrack;
			titleTextView.Text = audioTrack?.Title;
			if (audioTrack != null && audioTrack.Album?.IsNullOrEmpty() == true)
			{
				artistAlbumTextView.Text = audioTrack.Artist;
			}
			else
			{
				artistAlbumTextView.Text = audioTrack?.Artist + " - " + audioTrack?.Album;
			}
			ForceUpdateViews();
			if (this is PancakeFeedFmWidget && Visibility == ViewStates.Visible)
			{
				CancelAnimation();
				animationCts = new CancellationTokenSource();
				AnimateMarqueeAfterTime(animationCts.Token, 2);
			}
		}

		public void ResetAnimation()
		{
			CancelAnimation();
			animationCts = new CancellationTokenSource();
			ForceUpdateViews();
			AnimateMarqueeAfterTime(animationCts.Token, 2);
		}

		protected async System.Threading.Tasks.Task AnimateMarqueeAfterTime(System.Threading.CancellationToken ctx, int timeDelay = 20)
		{
			_ = 2;
			try
			{
				await System.Threading.Tasks.Task.Delay(TimeSpan.FromSeconds(timeDelay), ctx);
				if (animationCts != null)
				{
					bool flag = await AnimateMarquees(ctx);
					IsMarqueeAnimating = false;
					if (flag && !ctx.IsCancellationRequested)
					{
						await AnimateMarqueeAfterTime(ctx);
					}
				}
			}
			catch (System.OperationCanceledException)
			{
				IsMarqueeAnimating = false;
			}
		}

		public async System.Threading.Tasks.Task ShowAsNotification(AudioTrack audioTrack)
		{
			showingAsNotification = true;
			CancelAnimation();
			animationCts = new CancellationTokenSource();
			System.Threading.CancellationToken ctx = animationCts.Token;
			SetTrackInfo(audioTrack);
			try
			{
				await System.Threading.Tasks.Task.Delay(2000, ctx);
				Task<bool> task = AnimateMarquees(ctx);
				System.Threading.Tasks.Task task2 = System.Threading.Tasks.Task.Delay(6500, ctx);
				await System.Threading.Tasks.Task.WhenAll(task, task2);
			}
			catch (System.OperationCanceledException)
			{
			}
			finally
			{
				IsMarqueeAnimating = false;
				if (!isDisposed && !ctx.IsCancellationRequested)
				{
					showingAsNotification = false;
					whenMarqueeIsFinished.OnNext(null);
				}
			}
		}

		protected virtual async Task<bool> AnimateMarquees(System.Threading.CancellationToken ctx)
		{
			if (isDisposed)
			{
				return false;
			}
			Task<bool> top = AnimateMarquee(titleTextScrollView, ctx);
			Task<bool> bottom = AnimateMarquee(artistAlbumScrollView, ctx);
			try
			{
				await System.Threading.Tasks.Task.WhenAll<bool>(top, bottom);
			}
			catch (System.OperationCanceledException)
			{
				if (isDisposed)
				{
					return false;
				}
				ForceUpdateViews();
				return false;
			}
			return top.Result || bottom.Result;
		}

		protected virtual void ForceUpdateViews()
		{
			if (!isDisposed)
			{
				titleTextView.ForceLayout();
				titleTextScrollView.ScrollX = 0;
				titleTextScrollView.Invalidate();
				titleTextScrollView.RequestLayout();
				artistAlbumTextView.ForceLayout();
				artistAlbumScrollView.ScrollX = 0;
				artistAlbumScrollView.Invalidate();
				artistAlbumScrollView.RequestLayout();
			}
		}

		protected async Task<bool> AnimateMarquee(HorizontalScrollView scrollView, System.Threading.CancellationToken ctx)
		{
			View childAt = scrollView.GetChildAt(0);
			if (childAt == null)
			{
				return false;
			}
			ViewTreeObserver viewTreeObserver;
			TaskCompletionSource<bool> taskCompletionSource;
			if (childAt.Width <= 0)
			{
				viewTreeObserver = childAt.ViewTreeObserver;
				if (viewTreeObserver == null)
				{
					return false;
				}
				taskCompletionSource = new TaskCompletionSource<bool>();
				viewTreeObserver.GlobalLayout += OnGlobalLayout;
				return await taskCompletionSource.Task;
			}
			int num = childAt.Width - scrollView.Width;
			if (scrollView.HorizontalFadingEdgeEnabled)
			{
				num += scrollView.HorizontalFadingEdgeLength;
			}
			if (num <= 0)
			{
				return false;
			}
			scrollView.ScrollTo(0, 0);
			IsMarqueeAnimating = true;
			long duration = (long)System.Math.Round((float)num / 50f * 1000f);
			Animator animator = ObjectAnimator.OfInt(scrollView, "scrollX", num).SetDuration(duration);
			animator.SetInterpolator(new LinearInterpolator());
			Animator animator2 = ObjectAnimator.OfInt(scrollView, "scrollX", default(int)).SetDuration(duration);
			animator2.SetInterpolator(new LinearInterpolator());
			animator2.StartDelay = 2000L;
			AnimatorSet animatorSet = new AnimatorSet();
			animatorSet.PlaySequentially(animator, animator2);
			await mainThreadService.InvokeOnMainThreadAsync(async delegate
			{
				await animatorSet.StartWithDisposal(ctx);
			});
			return true;
			async void OnGlobalLayout(object sender, EventArgs e)
			{
				viewTreeObserver.GlobalLayout -= OnGlobalLayout;
				try
				{
					bool result = await AnimateMarquee(scrollView, ctx);
					taskCompletionSource.SetResult(result);
				}
				catch (System.OperationCanceledException arg)
				{
					ForceUpdateViews();
					global::Android.Util.Log.Debug("Audio", $"FeedFm Widget - TaskCanceledException in AnimateMarquee {arg}");
				}
			}
		}

		private void CancelAnimation()
		{
			animationCts?.Cancel();
			animationCts?.Dispose();
			animationCts = null;
			IsMarqueeAnimating = false;
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !isDisposed)
			{
				CancelAnimation();
				isDisposed = true;
			}
			base.Dispose(disposing);
		}

		public bool OnTouch(View v, MotionEvent e)
		{
			return true;
		}

		public override bool OnInterceptTouchEvent(MotionEvent? ev)
		{
			return true;
		}
	}
