	public class StaticFeedFmWidget : FeedFmWidget
	{
		private AppCompatTextView informationBox;

		private AppCompatTextView currentlyPlayingTextView;

		private ImageView feedFmLogo;

		protected CircularLoadingView loadingView;

		private MusicState currentState = MusicState.Unavailable;

		private IDisposable liveWorkoutMusicStateChangedSub;

		private IDisposable feedFmToggledSub;

		protected IDeviceInformation DeviceInfo { get; private set; }

		protected IMediaSettings MediaSettings { get; private set; }

		protected IMusicService MusicService { get; private set; }

		public override MusicState CurrentState
		{
			get
			{
				return currentState;
			}
			set
			{
				if (!isDisposed && currentState != value)
				{
					currentState = value;
					UpdateUi();
				}
			}
		}

		protected override int LayoutResId => 2131624420;

		private void UpdateUi()
		{
			try
			{
				if (MusicService == null)
				{
					SetUiForUnavailable();
				}
				else if (MediaSettings.HasDisabledFeedFmPlayback)
				{
					SetUiForOff();
				}
				else if (MusicService.LiveWorkoutMusicState == LiveWorkoutMusicState.Other)
				{
					switch (currentState)
					{
					case MusicState.Playing:
						SetUiForPlaying();
						break;
					case MusicState.PausedForMusicRegion:
						SetUiForPaused();
						break;
					case MusicState.PausedDisabled:
						SetUiForDisabled();
						break;
					case MusicState.Ready:
						if (MediaSettings == null)
						{
							SetUiForUnavailable();
						}
						else
						{
							SetUiForLoading();
						}
						break;
					case MusicState.Loading:
						SetUiForLoading();
						break;
					case MusicState.PausedManually:
					case MusicState.Off:
						SetUiForOff();
						break;
					case MusicState.Unavailable:
						SetUiForUnavailable();
						break;
					default:
						throw new ArgumentOutOfRangeException();
					}
				}
				else if (MusicService.LiveWorkoutMusicState == LiveWorkoutMusicState.TssStartingSoon || MusicService.LiveWorkoutMusicState == LiveWorkoutMusicState.StationChangerStartingSoon)
				{
					SetUiForOff();
				}
			}
			catch (System.Exception ex)
			{
				global::Android.Util.Log.Error("Audio", ex.GetType().Name + " occurred in updating StaticFeedFmWidget UI from CurrentState.", ex);
			}
		}

		protected virtual void SetUiForOff()
		{
			Visibility = ViewStates.Invisible;
			currentlyPlayingTextView.Visibility = ViewStates.Invisible;
			informationBox.Visibility = ViewStates.Invisible;
			feedFmLogo.Visibility = ViewStates.Invisible;
			titleTextScrollView.Visibility = ViewStates.Invisible;
			artistAlbumScrollView.Visibility = ViewStates.Invisible;
			loadingView.Visibility = ViewStates.Gone;
		}

		protected virtual void SetUiForDisabled()
		{
			Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Text = Wolf.Core.Resources.AppStrings.feed_fm_currently_unavailable;
			informationBox.Text = Wolf.Core.Resources.AppStrings.feed_fm_unavailable_for_workout;
			informationBox.Visibility = ViewStates.Visible;
			feedFmLogo.Visibility = ViewStates.Visible;
			titleTextScrollView.Visibility = ViewStates.Invisible;
			artistAlbumScrollView.Visibility = ViewStates.Invisible;
			loadingView.Visibility = ViewStates.Gone;
		}

		private void SetUiForUnavailable()
		{
			Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Text = Wolf.Core.Resources.AppStrings.feed_fm_currently_unavailable;
			informationBox.Text = Wolf.Core.Resources.AppStrings.feed_fm_unavailable_for_workout;
			informationBox.Visibility = ViewStates.Visible;
			feedFmLogo.Visibility = ViewStates.Visible;
			titleTextScrollView.Visibility = ViewStates.Invisible;
