		protected virtual void SetUiForPaused()
		{
			Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Text = Wolf.Core.Resources.AppStrings.feed_fm_currently_paused;
			informationBox.Text = Wolf.Core.Resources.AppStrings.feed_fm_paused_description;
			informationBox.Visibility = ViewStates.Visible;
			feedFmLogo.Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Visibility = ViewStates.Visible;
			titleTextScrollView.Visibility = ViewStates.Invisible;
			artistAlbumScrollView.Visibility = ViewStates.Invisible;
			loadingView.Visibility = ViewStates.Gone;
		}

		protected virtual void SetUiForPlaying()
		{
			Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Text = (base.IsTrainerSelectStation ? Wolf.Core.Resources.AppStrings.feed_fm_simulcast_playing_trainer_select_station : Wolf.Core.Resources.AppStrings.feed_fm_currently_playing);
			informationBox.Visibility = ViewStates.Gone;
			feedFmLogo.Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Visibility = ViewStates.Visible;
			titleTextScrollView.Visibility = ViewStates.Visible;
			artistAlbumScrollView.Visibility = ViewStates.Visible;
			loadingView.Visibility = ViewStates.Gone;
			if (!base.IsMarqueeAnimating)
			{
				ResetAnimation();
			}
		}

		protected virtual void SetUiForLoading()
		{
			Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Text = Wolf.Core.Resources.AppStrings.feed_fm_currently_loading;
			informationBox.Visibility = ViewStates.Invisible;
			feedFmLogo.Visibility = ViewStates.Visible;
			currentlyPlayingTextView.Visibility = ViewStates.Visible;
			titleTextScrollView.Visibility = ViewStates.Invisible;
