		}

		public StaticFeedFmWidget(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
			ResolveServices();
		}

		public StaticFeedFmWidget(Context context)
			: base(context)
		{
			ResolveServices();
		}

		public StaticFeedFmWidget(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			ResolveServices();
		}

		public StaticFeedFmWidget(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			ResolveServices();
		}

		protected override void Init(Context context, IAttributeSet attrs)
		{
			base.Init(context, attrs);
			ResolveServices();
			currentlyPlayingTextView = FindViewById<AppCompatTextView>(2131428043);
			if (currentlyPlayingTextView != null)
			{
				currentlyPlayingTextView.Text = Wolf.Core.Resources.AppStrings.feed_fm_currently_playing;
				currentlyPlayingTextView.Visibility = ViewStates.Invisible;
			}
			feedFmLogo = FindViewById<ImageView>(2131429371);
			informationBox = FindViewById<AppCompatTextView>(2131428044);
			loadingView = FindViewById<CircularLoadingView>(2131428050);
			IDeviceInformation deviceInfo = DeviceInfo;
			if (deviceInfo != null && deviceInfo.UseHeadlessBikeTheme)
			{
				feedFmLogo?.SetColorFilter(context.GetColorCompat(2131100396));
				currentlyPlayingTextView?.SetTextColor(context.GetColorCompat(2131100396));
				titleTextView?.SetTextColor(context.GetColorCompat(2131100394));
				artistAlbumTextView?.SetTextColor(context.GetColorCompat(2131100394));
				informationBox?.SetTextColor(context.GetColorCompat(2131100394));
			}
			else
			{
				currentlyPlayingTextView?.SetTextColor(context.GetColorCompat(2131100455));
				titleTextView?.SetTextColor(context.GetColorCompat(2131100449));
				artistAlbumTextView?.SetTextColor(context.GetColorCompat(2131100455));
				informationBox?.SetTextColor(context.GetColorCompat(2131100457));
			}
			liveWorkoutMusicStateChangedSub?.Dispose();
			liveWorkoutMusicStateChangedSub = MusicService?.LiveWorkoutMusicStateChanged?.Subscribe(delegate
			{
				UpdateUi();
			});
		}

		protected void ResolveServices()
		{
			SetUpMediaSettings();
			SetUpMusicService();
			SetUpDeviceInfoService();
			SetUpFeedFmMusicToggledSub();
		}

		private void SetUpMediaSettings()
		{
			if (MediaSettings == null)
			{
				if (Mvx.TryResolve<IMediaSettings>(out var service))
				{
					MediaSettings = service;
				}
				else
				{
					iFit.Logger.Log.Error("Audio", "Could not resolve IMediaSettings in SetUpMediaSettings");
				}
			}
		}

		private void SetUpMusicService()
		{
			if (MusicService == null)
			{
				if (Mvx.TryResolve<IMusicService>(out var service))
				{
					MusicService = service;
				}
				else
				{
					iFit.Logger.Log.Error("Audio", "Could not resolve IMusicService in SetUpMusicService");
				}
			}
		}

		private void SetUpDeviceInfoService()
		{
			if (DeviceInfo == null)
			{
				if (Mvx.TryResolve<IDeviceInformation>(out var service))
				{
					DeviceInfo = service;
				}
				else
				{
					iFit.Logger.Log.Error("Audio", "Could not resolve IDeviceInformation in SetUpDeviceInfoService");
				}
			}
		}

		private void SetUpFeedFmMusicToggledSub()
		{
			if (feedFmToggledSub == null)
			{
				IMvxMessenger mvxMessenger = Mvx.Resolve<IMvxMessenger>();
				feedFmToggledSub = mvxMessenger.Subscribe<InWorkoutMusicControlsViewModel.InWorkoutFeedFmMusicToggledMessage>(delegate
				{
					UpdateUi();
				});
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				loadingView?.Dispose();
				loadingView = null;
				liveWorkoutMusicStateChangedSub?.Dispose();
				liveWorkoutMusicStateChangedSub = null;
				feedFmToggledSub?.Dispose();
				feedFmToggledSub = null;
				MediaSettings = null;
				MusicService = null;
				DeviceInfo = null;
				base.Dispose(disposing);
			}
		}
	}
