		protected override async Task<bool> AnimateMarquees(System.Threading.CancellationToken ctx)
		{
			Task<bool> fullAnimation = AnimateMarquee(scrollView, ctx);
			try
			{
				await System.Threading.Tasks.Task.WhenAll<bool>(fullAnimation);
			}
			catch (System.OperationCanceledException)
			{
				if (isDisposed)
				{
					return false;
				}
				ForceUpdateViews();
				return false;
			}
			finally
			{
				base.IsMarqueeAnimating = false;
			}
			return fullAnimation.Result;
		}

		protected override void ForceUpdateViews()
		{
			if (!isDisposed)
			{
				scrollView.ForceLayout();
				scrollView.ScrollX = 0;
				scrollView.Invalidate();
				scrollView.RequestLayout();
			}
		}
	}
