					{
						ObjectAnimator animator = ObjectAnimator.OfFloat(feedFmWidget, "alpha", 1f, 0f);
						ObjectAnimator fadeIn = ObjectAnimator.OfFloat(feedFmWidget, "alpha", 0f, 1f);
						await animator.StartWithDisposal();
						if (feedFmWidget == null || isDisposed)
						{
							return;
						}
						feedFmWidget?.SetTrackInfo(currentAudioTrack);
						await fadeIn.StartWithDisposal();
						goto IL_0203;
					}
				}
				feedFmWidget?.SetTrackInfo(currentAudioTrack);
				hasFeedFmWidgetDisplayed |= currentAudioTrack != null;
				goto IL_0203;
				IL_0203:
				if (!feedFmWidget.IsMarqueeAnimating)
				{
					feedFmWidget.ResetAnimation();
				}
			}
			catch (System.Exception ex)
			{
				iFit.Logger.Log.Error("Audio", ex.GetType().Name + " occurred in UpdateCurrentAudioTrackAnimated.", ex);
			}
