					viewPager.SmoothTransitions = false;
					viewPager.SwipeLocked = true;
					viewPager.BindAdapter(viewPagerAdapter, base.ChildFragmentManager);
					if (oldAdapter != null && oldAdapter != viewPagerAdapter)
					{
						oldAdapter.Dispose();
					}
				}
			});
			await System.Threading.Tasks.Task.Yield();
			((Activity)(object)base.Activity)?.RunOnUiThread((System.Action)delegate
			{
