			float num = (float)point.Y / base.Resources.DisplayMetrics.Density;
			return num < 600f;
		}

		private void SetHitboxDelegate(View button)
		{
			int increaseSize = (int)base.Resources.GetDimension(2131165295);
			constraintLayout.Post(delegate
			{
				Rect rect = new Rect();
				button.GetHitRect(rect);
				rect.Top -= increaseSize;
				rect.Bottom += increaseSize;
				if (button != musicTabButton)
				{
					rect.Right += increaseSize;
				}
				if (button != volumeMixerTabButton)
				{
					rect.Left -= increaseSize;
				}
				if (button.Parent is View view)
				{
					view.TouchDelegate = new TouchDelegate(rect, button);
				}
			});
		}

