			ConstraintLayout obj2 = constraintLayout;
			constraintLayout = ((obj2 != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(obj2) : null);
			whenSettingsTabTappedSub?.Dispose();
			whenSettingsTabTappedSub = null;
			if (_animateVisibility != null)
			{
				_animateVisibility.Requested -= OnVisibilityAnimationRequested;
			}
		}

