	[IpcMethod]
	public class GetConsoleState : BaseIpcMethod
	{
		protected enum EruConsoleState
		{
			UNKNOWN = 0,
			IDLE = 1,
			RUNNING = 2,
			PAUSE = 3,
			RESULTS = 4,
			DEBUG = 5,
			LOG = 6,
			MAINTENANCE = 7,
			DMK = 8,
			DEMO = 9,
			WARM_UP = 10,
			COOL_DOWN = 11,
			SLEEP = 12,
			RESUME = 13,
			LOCKED = 14,
			ERROR = 15,
			PAUSE_OVERRIDE = 20
		}

		private readonly ISharedPreferences prefs = PreferenceManager.GetDefaultSharedPreferences(Application.Context);

		private static bool appIsAlive = Setup.AppIsAlive;

		public override bool ShouldKillProcessWhenDone => !appIsAlive;

		public GetConsoleState(IpcObject ipcObject)
			: base(ipcObject)
		{
		}

		protected override bool DeserializeDataJson(string json)
		{
			return true;
		}

		protected override Task<IpcObject> Execute(IpcObject ipcObject)
		{
			ConsoleState consoleState = ConsoleState.Unknown;
			if (IpcMethodsHelper.IsMvxSetup)
			{
				consoleState = GetState();
			}
			EruConsoleState eruConsoleState = EruConsoleStateExtension(consoleState);
			ipcObject.Data = JsonConvert.SerializeObject(eruConsoleState);
			if (consoleState == ConsoleState.Unknown)
			{
				ipcObject.Error = "Could not obtain console state, returning unknown state";
			}
			return System.Threading.Tasks.Task.FromResult(ipcObject);
		}

		protected static EruConsoleState EruConsoleStateExtension(ConsoleState consoleState)
		{
			return consoleState switch
			{
				ConsoleState.Idle => EruConsoleState.IDLE, 
				ConsoleState.Workout => EruConsoleState.RUNNING, 
				ConsoleState.Paused => EruConsoleState.PAUSE, 
				ConsoleState.WorkoutResults => EruConsoleState.RESULTS, 
				ConsoleState.SafetyKeyRemoved => EruConsoleState.DMK, 
				ConsoleState.Demo => EruConsoleState.DEMO, 
				ConsoleState.WarmUp => EruConsoleState.WARM_UP, 
				ConsoleState.CoolDown => EruConsoleState.COOL_DOWN, 
				ConsoleState.Sleep => EruConsoleState.SLEEP, 
				ConsoleState.Resume => EruConsoleState.RESUME, 
				ConsoleState.Locked => EruConsoleState.LOCKED, 
				ConsoleState.PauseOverride => EruConsoleState.PAUSE_OVERRIDE, 
				ConsoleState.Error => EruConsoleState.ERROR, 
				_ => EruConsoleState.UNKNOWN, 
			};
		}

		private ConsoleState GetState()
		{
			ConsoleState result = ConsoleState.Unknown;
			try
			{
				result = Mvx.Resolve<ICurrentConsoleService>().Console.LatestBasicInfo.CurrentState;
			}
			catch (System.Exception)
			{
			}
			return result;
		}
	}
