	[IpcMethod]
	public class GetUserInfo : BaseIpcMethod
	{
		private class MinimumUserInfo
		{
			public string Email { get; set; }

			public string FirstName { get; set; }

			public string LastName { get; set; }

			public string City { get; set; }

			public string State { get; set; }

			public string Zip { get; set; }

			public string Address { get; set; }

			public bool IsPremium { get; set; }

			public List<UserInfoFlag> LaunchDarklyFlags { get; set; }
		}

		private class UserInfoFlag
		{
			public string Key { get; set; }

			public string Value { get; set; }
		}

		private IIfitApiService _apiService;

		private IFeatureFlagManager _featureFlagManager;

		private static bool appIsAlive = Setup.AppIsAlive;

		public override bool ShouldKillProcessWhenDone => !appIsAlive;

		public GetUserInfo(IpcObject ipcObject)
			: base(ipcObject)
		{
			Mvx.TryResolve<IIfitApiService>(out _apiService);
			Mvx.TryResolve<IFeatureFlagManager>(out _featureFlagManager);
		}

		protected override bool DeserializeDataJson(string json)
		{
			return true;
		}

		protected override Task<IpcObject> Execute(IpcObject ipcObject)
		{
			if (_apiService == null)
			{
				Mvx.TryResolve<IIfitApiService>(out _apiService);
			}
			if (IpcMethodsHelper.IsMvxSetup && _apiService != null && _apiService.CurrentlyAuthenticatedUser != null)
			{
				User currentlyAuthenticatedUser = _apiService.CurrentlyAuthenticatedUser;
				MinimumUserInfo value = new MinimumUserInfo
				{
					Email = (currentlyAuthenticatedUser.Email ?? ""),
					FirstName = (currentlyAuthenticatedUser.Firstname ?? ""),
					LastName = (currentlyAuthenticatedUser.Lastname ?? ""),
					City = (currentlyAuthenticatedUser.Billing?.City ?? ""),
					State = (currentlyAuthenticatedUser.Billing?.State ?? ""),
					Zip = (currentlyAuthenticatedUser.Billing?.Zip ?? ""),
					Address = (currentlyAuthenticatedUser.Billing?.Address ?? ""),
					IsPremium = (currentlyAuthenticatedUser.Premium == true),
					LaunchDarklyFlags = GetFeatureFlags()
				};
				ipcObject.Data = JsonConvert.SerializeObject(value);
			}
			else
			{
				ipcObject.Data = "";
				ipcObject.Error = "No currently authenticated user found";
			}
			return System.Threading.Tasks.Task.FromResult(ipcObject);
		}

		private List<UserInfoFlag> GetFeatureFlags()
		{
			if (_featureFlagManager == null)
			{
				Mvx.TryResolve<IFeatureFlagManager>(out _featureFlagManager);
			}
			IReadOnlyList<FeatureFlag> allFlags = FeatureFlags.AllFlags;
			List<UserInfoFlag> list = new List<UserInfoFlag>();
			if (IpcMethodsHelper.IsMvxSetup && _featureFlagManager != null)
			{
				foreach (FeatureFlag item in allFlags)
				{
					switch (item.Type)
					{
					case FeatureFlagType.Bool:
						list.Add(new UserInfoFlag
						{
							Key = item.Key,
							Value = _featureFlagManager.IsFeatureEnabled(item).ToString()
						});
						break;
					case FeatureFlagType.Int:
						list.Add(new UserInfoFlag
						{
							Key = item.Key,
							Value = _featureFlagManager.GetInt(item).ToString()
						});
						break;
					case FeatureFlagType.String:
					case FeatureFlagType.WebviewUrl:
						list.Add(new UserInfoFlag
						{
							Key = item.Key,
							Value = _featureFlagManager.GetString(item).ToString()
						});
						break;
					}
				}
			}
			return list;
		}
	}
