	public class SetScreenBrightness : BaseWolfIpcClient
	{
		private class SetBrightnessOject
		{
			public float Brightness { get; set; }

			public bool ShouldSaveBrightness { get; set; }
		}

		private static SetScreenBrightness client;

		private SetScreenBrightness()
		{
		}

		private async System.Threading.Tasks.Task SetTheBrightness(float percentage, bool saveValue)
		{
			bool flag = !base.IsConnected;
			bool flag2 = flag;
			if (flag2)
			{
				flag2 = !(await Connect().ConfigureAwait(continueOnCapturedContext: false));
			}
			if (flag2)
			{
				throw new IpcException("Could not connect to service");
			}
			SetBrightnessOject brightnessObj = new SetBrightnessOject
			{
				Brightness = percentage,
				ShouldSaveBrightness = saveValue
			};
			System.Threading.Tasks.Task timeoutTask = System.Threading.Tasks.Task.Delay(5000);
			try
			{
				Task<float?> currentScreenBrightnessAsync = GetCurrentScreenBrightness.GetCurrentScreenBrightnessAsync();
				await System.Threading.Tasks.Task.WhenAny(currentScreenBrightnessAsync, timeoutTask);
				if (!timeoutTask.IsCompleted)
				{
					IpcObject ipcObject = new IpcObject("SetScreenBrightness", brightnessObj);
					Task<IpcObject> task = ExecuteRemoteMethodInternal(ipcObject);
					await System.Threading.Tasks.Task.WhenAny(task, timeoutTask);
					if (timeoutTask.IsCompleted)
					{
						iFit.Logger.Log.Debug("Settings", "Eru not responding. Timed out while attempting setting screen brightness with the new style.");
					}
					return;
				}
			}
			catch (System.Exception)
			{
				iFit.Logger.Log.Trace("Settings", "Exception while attempting setting screen brightness with the new style. Falling back to old style.");
			}
			IpcObject ipcObject2 = new IpcObject("SetScreenBrightness", percentage);
			Task<IpcObject> task2 = ExecuteRemoteMethodInternal(ipcObject2);
			await System.Threading.Tasks.Task.WhenAny(task2, timeoutTask);
			if (timeoutTask.IsCompleted)
			{
				iFit.Logger.Log.Debug("Settings", "Eru not responding. Timed out while attempting setting screen brightness with the old style.");
			}
		}

		public static async System.Threading.Tasks.Task SetScreenBrightnessAsync(float percentage, bool saveValue = false)
		{
			if (client == null)
			{
				client = new SetScreenBrightness();
			}
			try
			{
				await client.SetTheBrightness(percentage, saveValue);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("DeviceAdmin", "Failed to set screen brightness", exception);
			}
		}
	}
