namespace Wolf.Android.Interpolators
{
	public class CustomBounceInterpolator : Java.Lang.Object, IInterpolator, ITimeInterpolator, IJavaObject, IDisposable, IJavaPeerable
	{
		private readonly int bounces;

		private readonly double energy;

		public CustomBounceInterpolator()
			: this(3)
		{
		}

		public CustomBounceInterpolator(int bounces)
			: this(bounces, 0.30000001192092896)
		{
		}

		public CustomBounceInterpolator(int bounces, double energyFactor)
		{
			this.bounces = bounces;
			energy = energyFactor + 0.5;
		}

		public float GetInterpolation(float x)
		{
			return (float)(1.0 + (0.0 - System.Math.Abs(System.Math.Cos((double)(x * 10f * (float)bounces) / System.Math.PI))) * GetCurveAdjustment(x));
		}

		private double GetCurveAdjustment(double x)
		{
			return 0.0 - (2.0 * (1.0 - x) * x * energy + x * x) + 1.0;
		}
	}
}
