		protected void AdjustFontScale(global::Android.Content.Res.Configuration configuration)
		{
			iFit.Logger.Log.Info("Workout", $"AdjustFontScale: current={configuration?.FontScale}" + $" metrics={((Context)(object)this).Resources?.DisplayMetrics} build version={(int)Build.VERSION.SdkInt}");
			if (configuration == null || !((double)configuration.FontScale > 1.0))
			{
				return;
			}
			configuration.FontScale = 1f;
			DisplayMetrics displayMetrics = ((Context)(object)this).Resources?.DisplayMetrics;
			((Activity)(object)this).WindowManager?.DefaultDisplay?.GetMetrics(displayMetrics);
			if (displayMetrics != null)
			{
				displayMetrics.ScaledDensity = configuration.FontScale * displayMetrics.Density;
				if (Build.VERSION.SdkInt >= BuildVersionCodes.NMr1)
				{
					((Context)(object)this).CreateConfigurationContext(configuration);
