	public sealed class AndroidBug5497WorkaroundForXamarinAndroid : IDisposable
	{
		private BaseWebViewViewModel viewModel;

		private readonly View mChildOfContent;

		private int usableHeightPrevious;

		private ViewGroup.LayoutParams relativeLayoutParams;

		private ViewGroup content;

		private Rect r;

		private readonly bool shouldResizeNatively;

		private ViewTreeObserver viewTreeObserver => mChildOfContent?.ViewTreeObserver;

		public static AndroidBug5497WorkaroundForXamarinAndroid AssistActivity(Activity activity, BaseWebViewViewModel model, bool shouldResizeNatively = true, int layoutId = 0)
		{
			return new AndroidBug5497WorkaroundForXamarinAndroid(activity, model, shouldResizeNatively, layoutId);
		}

		private AndroidBug5497WorkaroundForXamarinAndroid(Activity activity, BaseWebViewViewModel model, bool shouldResizeNatively = true, int layoutId = 0)
		{
			viewModel = model;
			this.shouldResizeNatively = shouldResizeNatively;
			layoutId = ((layoutId == 0) ? 2131428588 : layoutId);
			content = (ViewGroup)activity.FindViewById(layoutId);
			mChildOfContent = content.GetChildAt(0);
			ViewTreeObserver viewTreeObserver = mChildOfContent.ViewTreeObserver;
			if (viewTreeObserver != null)
			{
				viewTreeObserver.GlobalLayout -= OnGlobalLayout;
				viewTreeObserver.GlobalLayout += OnGlobalLayout;
			}
			relativeLayoutParams = mChildOfContent.LayoutParameters;
			usableHeightPrevious = ComputeUsableHeight();
		}

		private void OnGlobalLayout(object sender, EventArgs e)
		{
			PossiblyResizeChildOfContent();
		}

		private void PossiblyResizeChildOfContent()
		{
			try
			{
				int num = ComputeUsableHeight();
				int num2 = System.Math.Abs(num - usableHeightPrevious);
				if (num2 > 150)
				{
					int height = mChildOfContent.RootView.Height;
					int num3 = height - num;
					if (num3 > height / 4)
					{
						if (shouldResizeNatively)
						{
							relativeLayoutParams.Height = height - num3;
						}
						viewModel.UpdateKeyboardState(isOpen: true, num3);
					}
					else
					{
						if (shouldResizeNatively)
						{
							relativeLayoutParams.Height = height;
						}
						viewModel.UpdateKeyboardState(isOpen: false);
					}
					mChildOfContent.RequestLayout();
				}
				usableHeightPrevious = num;
			}
			catch (ObjectDisposedException exception)
			{
				iFit.Logger.Log.Error("WebView", "Error accessing object that has already been disposed", exception);
			}
		}

		private int ComputeUsableHeight()
		{
			r = new Rect();
			mChildOfContent.GetWindowVisibleDisplayFrame(r);
			return r.Bottom;
		}

		public void Dispose()
		{
			try
			{
				ViewTreeObserver viewTreeObserver = this.viewTreeObserver;
				if (viewTreeObserver != null)
				{
					viewTreeObserver.GlobalLayout -= OnGlobalLayout;
				}
			}
			catch (ObjectDisposedException exception)
			{
				iFit.Logger.Log.Error("WebView", "Error accessing object that has already been disposed", exception);
			}
			viewModel = null;
			relativeLayoutParams?.Dispose();
			relativeLayoutParams = null;
			content?.Dispose();
			content = null;
			r?.Dispose();
			r = null;
		}
	}
