	public abstract class BaseSwappingBackgroundView<T> : BaseFullScreenDialogView<T> where T : BaseSwappingBackgroundViewModel, IMvxViewModel
	{
		private int _currentImageIndex;

		protected LinearLayout contentView;

		protected SwappingImageView backgroundImage;

		protected IBackgroundImageUtil backgroundImageUtil;

		private AlphaAnimation fadeOut;

		private AlphaAnimation fadeIn;

		private int _currentPositionIndex;

		private int[] xOffsets;

		private int[] yOffsets;

		public int CurrentImageIndex
		{
			get
			{
				return _currentImageIndex;
			}
			set
			{
				_currentImageIndex = value;
