			}
		}

		protected abstract int[] imageResources { get; }

		protected abstract float dpWidth { get; set; }

		protected abstract float dpHeight { get; set; }

		protected abstract float boxWidth { get; set; }

		protected abstract float boxHeight { get; set; }

		public int CurrentPositionIndex
		{
			get
			{
				return _currentPositionIndex;
			}
			set
			{
