		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			if (Mvx.TryResolve<IBackgroundImageUtil>(out var service))
			{
				backgroundImageUtil = service;
			}
			Cancelable = false;
			fadeOut = new AlphaAnimation(1f, 0f);
			fadeOut.Duration = 500L;
			fadeIn = new AlphaAnimation(0f, 1f);
			fadeIn.Duration = 500L;
			if (base.ViewModel.IsStrengthMirror)
			{
				InitializeStrengthMirrorBoxPositions();
			}
			else
			{
				InitializeBoxPositions();
			}
			MoveBoxToPosition(0);
			BindViewModel();
		}

		protected abstract void BindViewModel();

		private void InitializeBoxPositions()
		{
			int num = (int)((double)(dpWidth - boxWidth) / 4.0);
			int num2 = (int)((double)(dpHeight - boxHeight) / 4.0);
			xOffsets = new int[5];
			yOffsets = new int[5];
			xOffsets[0] = 0;
			yOffsets[0] = num2;
			xOffsets[1] = -num;
			yOffsets[1] = -num2;
			xOffsets[2] = num;
			yOffsets[2] = 0;
			xOffsets[3] = -num;
			yOffsets[3] = 0;
			xOffsets[4] = num;
			yOffsets[4] = -num2;
		}

		private void InitializeStrengthMirrorBoxPositions()
		{
			xOffsets = new int[5];
			yOffsets = new int[5];
			xOffsets[0] = -25;
			yOffsets[0] = 0;
			xOffsets[1] = -25;
			yOffsets[1] = -(int)Utils.ConvertDpToPixel(164f);
			xOffsets[2] = -25;
			yOffsets[2] = (int)Utils.ConvertDpToPixel(328f);
			xOffsets[3] = -25;
			yOffsets[3] = (int)Utils.ConvertDpToPixel(164f);
			xOffsets[4] = -25;
			yOffsets[4] = -(int)Utils.ConvertDpToPixel(290f);
		}

		private void MoveBoxToPosition(int position)
		{
			((Activity)(object)base.Activity).RunOnUiThread((System.Action)delegate
			{
				try
				{
					contentView.StartAnimation(fadeOut);
					int num = xOffsets[position];
					int num2 = yOffsets[position];
					RelativeLayout.LayoutParams layoutParams = contentView.LayoutParameters as RelativeLayout.LayoutParams;
					if (base.ViewModel.IsStrengthMirror)
					{
						layoutParams.TopMargin = (int)((dpHeight - boxHeight) / 2f * base.Resources.DisplayMetrics.Density) + num2;
					}
					else
					{
						layoutParams.TopMargin = (int)(((dpHeight - boxHeight) / 2f + (float)num2) * base.Resources.DisplayMetrics.Density);
					}
					layoutParams.LeftMargin = (int)(((dpWidth - boxWidth) / 2f + (float)num) * base.Resources.DisplayMetrics.Density);
					contentView.LayoutParameters = layoutParams;
					contentView.Parent.RequestLayout();
					contentView.StartAnimation(fadeIn);
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		private void AnimateToNewPosition()
		{
			MoveBoxToPosition(CurrentPositionIndex);
		}
	}
