		private bool InitializeWhoopsView(MvxFluentBindingDescriptionSet<BaseWebViewView<TViewModel>, BaseWebViewViewModel> bindingSet, VisibilityGoneValueConverter visibilityGone)
		{
			whoopsView = ((Activity)(object)this).FindViewById<RelativeLayout>(2131429773);
