			tryAgainBtn = ((Activity)(object)this).FindViewById<IfitTextView>(2131429645);
			if (whoopsViewError == null || tryAgainBtn == null || whoopsView == null)
			{
				return false;
			}
			whoopsViewError.Text = Wolf.Core.Resources.AppStrings.whoops_view_error;
			tryAgainBtn.Text = Wolf.Core.Resources.AppStrings.whoops_view_try_again;
			bindingSet.Bind(tryAgainBtn).For(tryAgainBtn.ClickEvent()).To((BaseWebViewViewModel vm) => vm.TryAgainClicked);
			bindingSet.Bind(whoopsView).For("Visibility").To((BaseWebViewViewModel vm) => vm.WebviewLoadErrored)
				.WithConversion(visibilityGone);
