		}

		private void CheckAndAlertWebViewVersion()
		{
			IDeviceInformation service;
			bool flag = Mvx.TryResolve<IDeviceInformation>(out service);
			IWebviewSettings service2;
			bool flag2 = Mvx.TryResolve<IWebviewSettings>(out service2);
			if (!flag || !flag2 || service.IsBuiltIn || service2.IgnoreOutdatedWebviewEngine)
			{
				return;
			}
			string text = WebView?.Settings?.UserAgentString;
			Regex regex = new Regex("(?:Chrome\\/)(\\d+)", RegexOptions.Compiled);
			Match match = regex.Match(text);
			IFeatureFlagManager service3;
			if (match.Groups.Count != 2 || !int.TryParse(match.Groups[1].Value, out var result))
			{
				iFit.Logger.Log.Warn("WebView", "Could not extract Chrome version for agent string : " + text);
			}
			else if (Mvx.TryResolve<IFeatureFlagManager>(out service3))
			{
				int num = service3.GetInt(FeatureFlags.MinAndroidWebViewEngineVersion);
				iFit.Logger.Log.Trace("WebView", $"Minimum supported webview engine version: {num}, current version: {result}");
				if (result < num)
				{
					CheckBox checkBox = new CheckBox((Context)(object)this);
					checkBox.SetText(Wolf.Core.Resources.AppStrings.dont_show_again, TextView.BufferType.Normal);
					checkBox.CheckedChange += DontShowAgainChanged;
					global::Android.App.AlertDialog.Builder builder = new global::Android.App.AlertDialog.Builder((Context)(object)this);
					global::Android.App.AlertDialog alertDialog = builder.SetMessage(Wolf.Core.Resources.AppStrings.outdated_webview_message).SetView(checkBox).SetPositiveButton(Wolf.Core.Resources.AppStrings.ok.ToUpperInvariant(), (IDialogInterfaceOnClickListener)null)
						.Create();
					alertDialog.Show();
					if (checkBox.LayoutParameters is ViewGroup.MarginLayoutParams marginLayoutParams)
					{
						int marginEnd = (marginLayoutParams.MarginStart = (marginLayoutParams.TopMargin = ((Context)(object)this).Resources.GetDimensionPixelSize(2131165286)));
						marginLayoutParams.MarginEnd = marginEnd;
						checkBox.LayoutParameters = marginLayoutParams;
					}
				}
			}
			else
			{
				iFit.Logger.Log.Warn("WebView", "Could not resolve minimum webview engine version feature flag");
			}
		}

		private void DontShowAgainChanged(object sender, CompoundButton.CheckedChangeEventArgs e)
		{
			if (Mvx.TryResolve<IWebviewSettings>(out var service))
			{
				service.IgnoreOutdatedWebviewEngine = e.IsChecked;
			}
		}

		private void HandleOpenNativeDialog(object sender, OpenNativeDialogEventArgs args)
		{
			global::Android.App.AlertDialog.Builder builder = new global::Android.App.AlertDialog.Builder((Context)(object)this);
			builder.SetCancelable(args.Cancelable);
			builder.SetMessage(args.Message);
			EditText editText = null;
			if (args.ShowDialogInput)
			{
				editText = new EditText((Context)(object)this);
				editText.Hint = args.InputPlaceholder;
				builder.SetView(editText);
			}
			builder.SetTitle(args.Title);
			OpenNativeDialogResponse response = new OpenNativeDialogResponse();
			for (int i = 0; i < args.Actions.Length; i++)
			{
				string action = args.Actions[i];
				switch (i)
				{
				case 0:
					builder.SetPositiveButton(action, delegate
					{
						response.Action = action;
						if (args.ShowDialogInput)
						{
							response.SendDialogInput = args.ShowDialogInput;
							response.TextInput = editText?.Text;
						}
						base.ViewModel.NativeDialogResponse.SafeExecute(response);
					});
					break;
				case 1:
					builder.SetNegativeButton(action, delegate
					{
						response.Action = action;
						base.ViewModel.NativeDialogResponse.SafeExecute(response);
					});
					break;
				case 2:
					builder.SetNeutralButton(action, delegate
					{
						response.Action = action;
						base.ViewModel.NativeDialogResponse.SafeExecute(response);
					});
					break;
				}
			}
			builder.Create().Show();
		}
	}
