	internal class ToolbarModeConverter : MvxValueConverter<MainToolbarViewModel.ToolbarMode, int>
	{
		private readonly MainToolbarViewModel.ToolbarMode mode;

		private readonly int unFocused;

		public ToolbarModeConverter(MainToolbarViewModel.ToolbarMode mode, int unFocused)
		{
			this.mode = mode;
			this.unFocused = unFocused;
		}

		protected override int Convert(MainToolbarViewModel.ToolbarMode value, Type targetType, object parameter, CultureInfo culture)
		{
			if (value != mode)
			{
				return unFocused;
			}
			switch (value)
			{
			case MainToolbarViewModel.ToolbarMode.CalendarOrFeed:
			{
				if (Mvx.TryResolve<IDeviceInformation>(out var service) && service.IsTablet)
				{
					return 2131231434;
				}
				return 2131231470;
			}
			case MainToolbarViewModel.ToolbarMode.Dashboard:
				return 2131231481;
			case MainToolbarViewModel.ToolbarMode.DrawMap:
				return 2131231494;
			case MainToolbarViewModel.ToolbarMode.Library:
				return 2131231486;
			case MainToolbarViewModel.ToolbarMode.Live:
				return 2131231488;
			case MainToolbarViewModel.ToolbarMode.Challenges:
				return 2131231438;
			default:
				return unFocused;
			}
		}
	}
	public abstract class MapActivity<TViewModel> : MainToolbarView<TViewModel> where TViewModel : MainToolbarViewModel, IMvxViewModel
