	[Activity(Label = "iFIT", Icon = "@mipmap/ic_launcher", NoHistory = true, LaunchMode = LaunchMode.SingleTask, ScreenOrientation = ScreenOrientation.Locked, ConfigurationChanges = (ConfigChanges.Keyboard | ConfigChanges.KeyboardHidden | ConfigChanges.Orientation | ConfigChanges.ScreenSize | ConfigChanges.UiMode), Theme = "@style/LightNoActionBarTheme.NoAnimation")]
	public class SplashScreen : MvxSplashScreenActivity
	{
		private const string Tag = "SplashScreen";

		private IDisposable whenFatalityHappened;

		private Snackbar fatalSnackbar;

		private bool isStrengthMirror;

		private bool shouldNavigate;

		private View fullLogo;

		private ImageView arrow;

		private ValueAnimator revealAnimator;

		private Animator pulseAnimator;

		private AnimatorSet animatorSet;

		protected int RevealAnimation
		{
			get
			{
				if (!isStrengthMirror)
				{
					return 2130837534;
				}
				return 2130837541;
			}
		}

		public SplashScreen()
			: base(Shire.Android.Util.DeviceInfo.IsStrengthMirrorUnit ? 2131624177 : 2131624176)
		{
		}

		protected override void OnCreate(Bundle bundle)
		{
			isStrengthMirror = Shire.Android.Util.DeviceInfo.IsStrengthMirrorUnit;
			if (isStrengthMirror)
			{
				SetTheme(2132017617);
			}
			base.OnCreate(bundle);
			fullLogo = FindViewById(2131428483);
			arrow = FindViewById<BasicImageView>(2131428481);
			if (!IsTaskRoot)
			{
				Finish();
				return;
			}
			if (Window?.Attributes != null)
			{
				Window.Attributes.RotationAnimation = WindowRotationAnimation.Rotate;
			}
			if (Mvx.TryResolve<IAppSetupFatalityHandler>(out var service))
			{
				whenFatalityHappened?.Dispose();
				whenFatalityHappened = service.WhenAppSetupFatality.Subscribe(OnFatality);
			}
			IDeviceInformation service2;
			if (isStrengthMirror)
			{
				RequestedOrientation = ScreenOrientation.SensorPortrait;
			}
			else if (Mvx.TryResolve<IDeviceInformation>(out service2))
			{
				RequestedOrientation = (service2.IsTablet ? ScreenOrientation.SensorLandscape : ScreenOrientation.SensorPortrait);
			}
			Window.DecorView.SystemUiVisibility = (StatusBarVisibility)9472;
			View view = FindViewById(2131428484);
			if (isStrengthMirror)
			{
				view.SetBackgroundColor(global::Android.Graphics.Color.Black);
				arrow.SetImageDrawable(GetDrawable(2131231407));
				pulseAnimator = AnimatorInflater.LoadAnimator(this, 2130837540);
			}
			else
			{
				view.SetBackgroundColor(global::Android.Graphics.Color.White);
				pulseAnimator = AnimatorInflater.LoadAnimator(this, 2130837533);
			}
			if (pulseAnimator != null)
			{
				pulseAnimator.SetTarget(arrow);
				pulseAnimator.AnimationEnd -= HandleAnimationEnd;
				pulseAnimator.AnimationEnd += HandleAnimationEnd;
				pulseAnimator.Start();
			}
			animatorSet = new AnimatorSet();
			ObjectAnimator objectAnimator = ObjectAnimator.OfFloat(fullLogo, "alpha", default(float));
			objectAnimator.SetDuration(400L);
			objectAnimator.StartDelay = 750L;
			revealAnimator = (ValueAnimator)AnimatorInflater.LoadAnimator(this, RevealAnimation);
			revealAnimator.SetTarget(fullLogo);
			revealAnimator.Update -= UpdateRevealAnimation;
			revealAnimator.Update += UpdateRevealAnimation;
			try
			{
				_ = BitmapLoader.Current.LoadFromResource("IcBike.png", null, null).Result;
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("SplashScreen", "Error occurred in BitmapLoader LoadFromResource call.", exception);
			}
			animatorSet.PlaySequentially(revealAnimator, objectAnimator);
			revealAnimator.AnimationEnd -= HandleRevealAnimationEnd;
			revealAnimator.AnimationEnd += HandleRevealAnimationEnd;
		}

		private void HandleRevealAnimationEnd(object sender, EventArgs update)
		{
			base.InitializationComplete();
		}

		private void UpdateRevealAnimation(object sender, ValueAnimator.AnimatorUpdateEventArgs update)
		{
			if (fullLogo == null)
			{
				iFit.Logger.Log.Warn("Navigation", "Tried to update reveal animation, but fullLogo was null.");
				return;
			}
			ViewGroup.LayoutParams layoutParameters = fullLogo.LayoutParameters;
			layoutParameters.Width = (int)update.Animation.AnimatedValue;
			fullLogo.LayoutParameters = layoutParameters;
		}

		private void HandleAnimationEnd(object sender, EventArgs e)
		{
			try
			{
				CheckRepeatPulse();
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("SplashScreen", "Error occurred in " + GetType().Name + " HandleAnimationEnd call.", exception);
			}
		}

		private void CheckRepeatPulse()
		{
			if (shouldNavigate && arrow != null)
			{
				arrow.Alpha = 1f;
				revealAnimator?.Start();
			}
			else
			{
				pulseAnimator?.Start();
			}
		}

		private void OnFatality(FatalEvent fatalEvent)
		{
			RunOnUiThread(delegate
			{
				if (fatalSnackbar != null)
				{
					fatalSnackbar.SetText(fatalEvent.Message);
				}
				else
				{
					fatalSnackbar = Snackbar.Make(FindViewById(2131428484), fatalEvent.Message, -2);
					fatalSnackbar.Show();
				}
			});
		}

		public override void InitializationComplete()
		{
			iFit.Logger.Log.Trace("SplashScreen", "Mvx Setup complete, initializing app");
			if (Mvx.TryResolve<IDeviceInformation>(out var service) && Mvx.TryResolve<ICurrentConsoleService>(out var service2))
			{
				iFit.Logger.Log.Trace("SplashScreen", "Resolving screen sizes");
				SetSettingsScreenSizes(service);
				CheckForX22FirmwareMismatch(service, service2);
			}
			if (Mvx.TryResolve<IAppLinking>(out var service3))
			{
				string stringExtra = base.Intent.GetStringExtra("DeepLinkIntentKey");
				if (stringExtra != null)
				{
					if (service3 is AppLinkingService appLinkingService)
					{
						appLinkingService.InitializeLink(stringExtra);
					}
				}
				else
				{
					service3.InitializeLink(string.Empty);
				}
			}
			iFit.Logger.Log.Trace("SplashScreen", "Navigating to first screen");
			shouldNavigate = true;
			if (Mvx.TryResolve<IScreenSaverHandler>(out var service4))
			{
				service4.Touched();
			}
		}

		private void SetSettingsScreenSizes(IDeviceInformation deviceInformation)
		{
			DisplayMetrics displayMetrics = new DisplayMetrics();
			global::Android.Runtime.Extensions.JavaCast<IWindowManager>(GetSystemService("window")).DefaultDisplay.GetMetrics(displayMetrics);
			int num = ((displayMetrics.WidthPixels >= displayMetrics.HeightPixels) ? displayMetrics.WidthPixels : displayMetrics.HeightPixels);
			int num2 = ((displayMetrics.WidthPixels >= displayMetrics.HeightPixels) ? displayMetrics.HeightPixels : displayMetrics.WidthPixels);
			deviceInformation.ScreenPixelDensity = displayMetrics.Density;
			ScreenOrientation[] source = new ScreenOrientation[4]
			{
				ScreenOrientation.Portrait,
				ScreenOrientation.ReversePortrait,
				ScreenOrientation.SensorPortrait,
				ScreenOrientation.UserPortrait
			};
			bool flag = source.Contains(RequestedOrientation);
			if (StrengthMirrorFileService.Shared.StoredOrActiveConfigFileExists())
			{
				flag = deviceInformation.IsStrengthMirror;
			}
			deviceInformation.PixelScreenWidth = (flag ? num2 : num);
			deviceInformation.PixelScreenHeight = (flag ? num : num2);
			deviceInformation.ScreenWidth = Java.Lang.Math.Round((float)deviceInformation.PixelScreenWidth / deviceInformation.ScreenPixelDensity);
			deviceInformation.ScreenHeight = Java.Lang.Math.Round((float)deviceInformation.PixelScreenHeight / deviceInformation.ScreenPixelDensity);
			int num3 = 0;
			int num4 = 0;
			int num5 = 0;
			int num6 = 0;
			if (Build.VERSION.SdkInt >= BuildVersionCodes.P)
			{
				num3 = (Window?.DecorView?.RootWindowInsets?.DisplayCutout?.SafeInsetBottom).GetValueOrDefault();
				num4 = (Window?.DecorView?.RootWindowInsets?.DisplayCutout?.SafeInsetTop).GetValueOrDefault();
				num5 = (Window?.DecorView?.RootWindowInsets?.DisplayCutout?.SafeInsetLeft).GetValueOrDefault();
				num6 = (Window?.DecorView?.RootWindowInsets?.DisplayCutout?.SafeInsetRight).GetValueOrDefault();
			}
			deviceInformation.PixelSafeAreaWidth = displayMetrics.WidthPixels - num5 - num6;
			deviceInformation.PixelSafeAreaHeight = displayMetrics.HeightPixels - num4 - num3;
		}

		private void CheckForX22FirmwareMismatch(IDeviceInformation deviceInformation, ICurrentConsoleService currentConsoleService)
		{
			int num = 384970;
			if (!deviceInformation.IsBuiltIn)
			{
				return;
			}
			IFitnessConsole console = currentConsoleService.Console;
			if (console != null && console.ConsoleInfo?.PartNumber == num)
			{
				iFit.Logger.Log.Trace("SplashScreen", "Check x11i built-in for screen size mismatch");
				DisplayMetrics displayMetrics = new DisplayMetrics();
				global::Android.Runtime.Extensions.JavaCast<IWindowManager>(GetSystemService("window")).DefaultDisplay.GetMetrics(displayMetrics);
				double x = System.Math.Round((float)displayMetrics.WidthPixels / displayMetrics.Xdpi);
				double x2 = System.Math.Round((float)displayMetrics.HeightPixels / displayMetrics.Ydpi);
				double num2 = System.Math.Round(System.Math.Sqrt(System.Math.Pow(x, 2.0) + System.Math.Pow(x2, 2.0)));
				if (num2 >= 20.0 && Mvx.TryResolve<IWolfAnalytics>(out var service))
				{
					iFit.Logger.Log.Trace("SplashScreen", "Screen size mismatched, sending analytics");
					service.X22WithX11Firmware();
				}
			}
		}

		protected override void OnDestroy()
		{
			base.OnDestroy();
			ImageView imageView = arrow;
			arrow = ((imageView != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(imageView) : null);
			whenFatalityHappened?.Dispose();
			whenFatalityHappened = null;
			if (revealAnimator != null)
			{
				revealAnimator.Update -= UpdateRevealAnimation;
				revealAnimator.AnimationEnd -= HandleRevealAnimationEnd;
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(revealAnimator);
				revealAnimator = null;
			}
			if (pulseAnimator != null)
			{
				pulseAnimator.AnimationEnd -= HandleAnimationEnd;
				pulseAnimator.RemoveAllListeners();
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(pulseAnimator);
				pulseAnimator = null;
			}
			AnimatorSet obj = animatorSet;
			if (obj != null)
			{
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(obj);
			}
			animatorSet = null;
		}
	}
}
