	public abstract class BaseSettingsDialogView<T> : BaseDialogFragment<T> where T : BaseViewModel
	{
		protected ProgressDialog progressDialog;

		protected abstract int MeasuredWidthDimenRes { get; }

		public bool ShowProgressDialog
		{
			get
			{
				return progressDialog?.IsShowing ?? false;
			}
			set
			{
				if (value != ShowProgressDialog)
				{
					if (value)
					{
						progressDialog.Show();
					}
					else
					{
						progressDialog.Dismiss();
					}
				}
			}
		}

		public string ProgressText
		{
			get
			{
				return string.Empty;
			}
			set
			{
				progressDialog?.SetMessage(value);
			}
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			view.Post(SetLayoutDimens);
		}

		protected void SetLayoutDimens()
		{
			Dialog.Window.SetLayout((int)base.Resources.GetDimension(MeasuredWidthDimenRes), -2);
		}

		protected void CreateProgressDialog(string text, bool cancelable)
		{
			progressDialog = new ProgressDialog((Context)(object)base.Activity);
			progressDialog.SetMessage(text);
			progressDialog.SetProgressStyle(ProgressDialogStyle.Spinner);
			progressDialog.SetCancelable(cancelable);
		}
	}
