		private void OnUuidClick(object sender, EventArgs e)
		{
			uuidClickCounter++;
			if (uuidClickCounter > 3)
			{
				OpenEruAdmin();
				uuidClickCounter = 0;
			}
		}

		private void OpenEruAdmin()
		{
			Intent launchIntentForPackage = ((Context)(object)this).PackageManager.GetLaunchIntentForPackage(AppFqn.Eru);
			((Context)(object)this).StartActivity(launchIntentForPackage);
		}

		protected override void OnPause()
		{
			base.OnPause();
			if (base.ViewModel.IsBuiltIn && consoleGuid != null)
			{
				consoleGuid.Click -= OnUuidClick;
			}
		}

		protected override void OnResume()
		{
			base.OnResume();
			if (base.ViewModel.IsBuiltIn && consoleGuid != null)
			{
				consoleGuid.Click -= OnUuidClick;
				consoleGuid.Click += OnUuidClick;
			}
		}

