			ItemTemplateId = ((service != null && service.IsTablet) ? 2131624334 : 2131624333);
			DropDownItemTemplateId = 2131624332;
		}

		public InWorkoutSpinnerAdapter(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		protected override IMvxListItemView CreateViewBasedOnInfo(object dataContext, int templateId)
		{
			TextSpinnerItem textSpinnerItem = new TextSpinnerItem(base.Context, templateId);
			Children.Add(textSpinnerItem);
			textSpinnerItem.DataContext = dataContext;
			return textSpinnerItem;
		}

		protected override int GetTemplateIdForPosition(int position)
		{
			return ItemTemplateId;
