	[Activity(Theme = "@style/SettingsTheme.Light", ScreenOrientation = ScreenOrientation.Behind, ConfigurationChanges = (ConfigChanges.Keyboard | ConfigChanges.KeyboardHidden | ConfigChanges.Orientation | ConfigChanges.ScreenSize | ConfigChanges.UiMode))]
	public class ContentDisplayView : BaseActivity<ContentDisplayViewModel>
	{
		private global::Android.Graphics.Color backgroundColor;

		private global::Android.Graphics.Color textColor;

		private global::Android.Graphics.Color linkColor;

		protected override int LayoutResId
		{
			get
			{
				if (!base.IsTablet)
				{
					return 2131624361;
				}
				return 2131624362;
			}
		}

		protected override void SetupView()
		{
			base.SetupView();
			TypedArray typedArray = ((Context)(object)this).ObtainStyledAttributes(Resource.Styleable.SettingsStyle);
			if (typedArray != null)
			{
				backgroundColor = typedArray.GetColor(13, ((Context)(object)this).GetColorCompat(2131100361));
				textColor = typedArray.GetColor(17, ((Context)(object)this).GetColorCompat(2131100363));
				linkColor = typedArray.GetColor(9, ((Context)(object)this).GetColorCompat(2131100358));
			}
			else
			{
				backgroundColor = ((Context)(object)this).GetColorCompat(2131100361);
				textColor = ((Context)(object)this).GetColorCompat(2131100363);
				linkColor = ((Context)(object)this).GetColorCompat(2131100358);
			}
			typedArray?.Recycle();
			WebView webView = ((Activity)(object)this).FindViewById<WebView>(2131428255);
			switch (base.ViewModel.WhatToDisplay)
			{
			case ContentDisplayViewModel.DisplayType.LegalMedicalDisclaimer:
				DisplayContent(webView, Wolf.Core.Resources.AppStrings.settings_legal_medicaldisclaimer_title, "MedicalDisclaimer.html");
				break;
			case ContentDisplayViewModel.DisplayType.SubscriptionTerms:
				DisplayContent(webView, Wolf.Core.Resources.AppStrings.settings_legal_subscription_title, "SubscriptionTerms.html");
				break;
			case ContentDisplayViewModel.DisplayType.MusicDisclaimer:
				DisplayContent(webView, Wolf.Core.Resources.AppStrings.settings_legal_music_title, "MusicDisclaimer.html");
				break;
			}
			if (!base.ViewModel.IsTablet)
			{
				webView.SetBackgroundColor(global::Android.Graphics.Color.Transparent);
			}
			else
			{
				webView.SetBackgroundColor(backgroundColor);
			}
			MvxFluentBindingDescriptionSet<ContentDisplayView, ContentDisplayViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<ContentDisplayView, ContentDisplayViewModel>();
			mvxFluentBindingDescriptionSet.Bind(base.Toolbar.BackButtonView).For(base.Toolbar.BackButtonView.ClickEvent()).To((ContentDisplayViewModel vm) => vm.CloseViewModel);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void DisplayContent(WebView htmlContent, string title, string html)
		{
			base.Toolbar.TitleText = title;
			htmlContent.LoadData(ChangeColors(SetFonts(FilterLinks(html))).Base64Encode(), "text/html", "base64");
		}

		private string ChangeColors(string html)
		{
			html = html.Replace("#000000", "#" + Integer.ToHexString(textColor.ToArgb()).Substring(2));
			html = html.Replace("#333333", "#" + Integer.ToHexString(textColor.ToArgb()).Substring(2));
			html = html.Replace("#1155cc", "#" + Integer.ToHexString(linkColor.ToArgb()).Substring(2));
			return html;
		}

		private string SetFonts(string html)
		{
			if (base.ViewModel.IsStrengthMirror && base.ViewModel.WhatToDisplay == ContentDisplayViewModel.DisplayType.LegalMedicalDisclaimer)
			{
				html = html.Replace("<p>", "<p style=\"font-family: ProximaNova-Regular; font-size: 16px; font-weight: normal; letter-spacing: 0.3px;line-height: 24px;\">");
			}
			return html;
		}

		private string FilterLinks(string html)
		{
			string resourceName = "Wolf.Core.Source.ViewModels.Settings.Legal.Content." + html;
			string text = EmbeddedResourceUtil.ReadEmbeddedResourceText(typeof(ContentDisplayViewModel), resourceName);
			if (base.ViewModel.IsBuiltIn)
			{
				Regex regex = new Regex("<a\\s+href=\"(.*?)\">");
				Regex regex2 = new Regex("</a>");
				return regex2.Replace(regex.Replace(text, ""), "");
			}
			return text;
		}
	}
