		private void OnToastMessage(ToastMessage toastMessage)
		{
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				Toast.MakeText((Context)(object)this, toastMessage.Text, ToastLength.Long).Show();
			});
		}

		protected override void SetupBindings<TView, TViewModeParam>(IMvxAndroidBindingContext bindingContext, MvxFluentBindingDescriptionSet<TView, TViewModeParam> bindingSet)
		{
			base.SetupBindings(bindingContext, bindingSet);
			string customTitle = ((base.ViewModel.CurrentSettingsState == SettingsViewModel.SettingsState.BuiltInClubSignedOut) ? string.Empty : null);
			accountSettings.Init(SettingsCollection.SettingsCollectionType.Account, bindingContext, bindingSet, customTitle);
			aboutSettings.Init(SettingsCollection.SettingsCollectionType.About, bindingContext, bindingSet);
			bindingSet.Bind(aboutSettings).For("Visibility").To((TViewModeParam vm) => vm.AboutList)
				.WithConversion(new INCListNullVisibilityGoneValueConverter<SettingsCollectionCellModel>());
		}

		private void OnClubOwnerGesturePerformed()
		{
			base.ViewModel.OpenClubOwnerSettings.Execute(null);
		}

