			aboutSettings = null;
			settingsContainer?.Dispose();
			settingsContainer = null;
			settingsCollectionContainer?.Dispose();
			settingsCollectionContainer = null;
			scrollview?.Dispose();
			scrollview = null;
			frameLayout?.Dispose();
			frameLayout = null;
		}
	}
	internal class ClubOwnerGesturePerformedListener : Java.Lang.Object, GestureOverlayView.IOnGesturePerformedListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private GestureLibrary gestureLibrary;

		private System.Action onSuccess;

		public ClubOwnerGesturePerformedListener(GestureLibrary library, System.Action onSuccess)
		{
			gestureLibrary = library;
			this.onSuccess = onSuccess;
		}

		public void OnGesturePerformed(GestureOverlayView overlay, Gesture gesture)
		{
			try
			{
				IList<Prediction> list = gestureLibrary.Recognize(gesture);
				if (list.Count > 0 && list.First().Score > 1.0)
				{
					onSuccess?.Invoke();
				}
			}
			catch (IndexOutOfRangeException exception)
			{
				iFit.Logger.Log.Error("Settings", "Settings Error", exception);
			}
			catch (IndexOutOfBoundsException exception2)
			{
				iFit.Logger.Log.Error("Settings", "Settings Error", exception2);
			}
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			gestureLibrary?.Dispose();
			gestureLibrary = null;
			onSuccess = null;
		}
	}
