		protected override void DialogClosed(ShireDialogFragment dialogFragment)
		{
			if (dialogFragment is DatePickerDialogView { Saved: not false } datePickerDialogView)
			{
				if (base.ViewModel.IsValidBirthdate(datePickerDialogView.DatePickerBinder))
				{
					base.ViewModel.Birthdate.Value = datePickerDialogView.DatePickerBinder;
				}
				else
				{
					Toast.MakeText((Context)(object)this, "The date you selected is invalid. Please select a valid date.", ToastLength.Long).Show();
				}
			}
			if (dialogFragment is FullNameDialogView { Saved: not false } fullNameDialogView)
			{
				base.ViewModel.FirstName.Value = fullNameDialogView.FirstName;
				base.ViewModel.LastName.Value = fullNameDialogView.LastName;
			}
			base.DialogClosed(dialogFragment);
		}

		private void Gender_Clicked(object sender, EventArgs e)
		{
			global::Android.App.AlertDialog.Builder builder = new global::Android.App.AlertDialog.Builder((Context)(object)this, 2132017854);
			List<string> choices = new List<string>();
			base.ViewModel.GenderData.DoForEach(delegate(GenderSpinnerModel x)
			{
				choices.Add(x.Caption);
			});
			builder.SetTitle(Wolf.Core.Resources.AppStrings.settings_myprofile_gender);
			builder.SetSingleChoiceItems(choices.ToArray(), base.ViewModel.SelectedGender.Value.Index, delegate(object s1, DialogClickEventArgs e2)
			{
				if (base.ViewModel.GenderData.Count > e2.Which && e2.Which >= 0)
				{
					base.ViewModel.SelectedGender.Value = base.ViewModel.GenderData[e2.Which];
				}
				if (s1 is global::Android.App.AlertDialog alertDialog)
				{
					alertDialog.Cancel();
				}
			});
			builder.Show();
		}

		private void Height_Clicked(object sender, EventArgs e)
		{
			global::Android.App.AlertDialog.Builder builder = new global::Android.App.AlertDialog.Builder((Context)(object)this, 2132017854);
			builder.SetTitle(Wolf.Core.Resources.AppStrings.settings_myprofile_height);
			List<string> choices = new List<string>();
			base.ViewModel.HeightData.DoForEach(delegate(HeightSpinnerModel x)
			{
				choices.Add(x.Caption);
			});
			NumberPicker picker = new NumberPicker((Context)(object)this);
			picker.MinValue = 0;
			picker.MaxValue = base.ViewModel.HeightData.Count - 1;
			picker.Value = base.ViewModel.SelectedHeightIndex;
			picker.SetDisplayedValues(choices.ToArray());
			picker.DescendantFocusability = DescendantFocusability.BlockDescendants;
			builder.SetView(picker);
