		private void Weight_Clicked(object sender, EventArgs e)
		{
			global::Android.App.AlertDialog.Builder builder = new global::Android.App.AlertDialog.Builder((Context)(object)this, 2132017854);
			builder.SetTitle(Wolf.Core.Resources.AppStrings.settings_myprofile_weight);
			List<string> choices = new List<string>();
			base.ViewModel.WeightData.DoForEach(delegate(WeightSpinnerModel x)
			{
				choices.Add(x.Caption);
			});
			NumberPicker picker = new NumberPicker((Context)(object)this);
			picker.MinValue = 0;
			picker.MaxValue = base.ViewModel.WeightData.Count - 1;
			picker.Value = base.ViewModel.SelectedWeightIndex;
			picker.SetDisplayedValues(choices.ToArray());
			picker.DescendantFocusability = DescendantFocusability.BlockDescendants;
			builder.SetView(picker);
			builder.SetPositiveButton(Wolf.Core.Resources.AppStrings.settings_dialog_Save, delegate
			{
				base.ViewModel.SelectedWeight.Value = base.ViewModel.WeightData[picker.Value];
			});
			builder.Show();
		}

		private void Bio_Tablet_Clicked(object sender, EventArgs e)
		{
			if (Wolf.Core.Resources.AppStrings.settings_myprofile_edit.Equals(bio.Content))
			{
				bio.Content = Wolf.Core.Resources.AppStrings.settings_bio_done;
				editBio.EditText.Text = base.ViewModel.Bio.Value;
				editBio.Visibility = ViewStates.Visible;
				editBio.RequestFocus();
			}
			else
			{
				((Activity)(object)this).DismissKeyboard();
				bio.Content = Wolf.Core.Resources.AppStrings.settings_myprofile_edit;
				editBio.Visibility = ViewStates.Gone;
				base.ViewModel.Bio.Value = editBio.EditText.Text;
			}
		}

		private void BioPhone_Clicked(object sender, EventArgs e)
		{
			bio.Visibility = ViewStates.Gone;
			bioTextInput.Visibility = ViewStates.Visible;
			saveBio.Visibility = ViewStates.Visible;
			bioTextInputLayout.Visibility = ViewStates.Visible;
			if (string.IsNullOrWhiteSpace(base.ViewModel.Bio?.Value))
			{
				bioTextInput.Text = string.Empty;
			}
			else
			{
				bioTextInput.Text = base.ViewModel.Bio.Value;
			}
		}

		private void BioPhoneSave_Clicked(object sender, EventArgs e)
		{
			((Activity)(object)this).DismissKeyboard();
			bio.Visibility = ViewStates.Visible;
			bioTextInput.Visibility = ViewStates.Gone;
			saveBio.Visibility = ViewStates.Gone;
			bioTextInputLayout.Visibility = ViewStates.Gone;
			base.ViewModel.Bio.Value = bioTextInput.Text;
		}

		private void SetItemInfo(BaseSettingsItem item, string title, string content = null)
		{
			item.Title = title;
			if (content != null)
			{
				item.Content = content;
			}
		}
	}
