	public abstract class PrimarySettingsView<TViewModel> : BaseActivity<TViewModel> where TViewModel : PrimarySettingsViewModel
	{
		protected SettingsCollection equipmentSettings;

		protected IfitTextView environmentLabel;

		protected abstract string TitleText { get; }

		protected override void OnResume()
		{
			base.OnResume();
			equipmentSettings?.VerifyHeight();
		}

		protected override void SetupView()
		{
			base.SetupView();
			base.Toolbar.TitleText = TitleText;
			environmentLabel = ((Activity)(object)this).FindViewById<IfitTextView>(2131427941);
			equipmentSettings = ((Activity)(object)this).FindViewById<SettingsCollection>(2131427945);
		}

		protected virtual void SetupBindings<TView, TViewModeParam>(IMvxAndroidBindingContext bindingContext, MvxFluentBindingDescriptionSet<TView, TViewModeParam> bindingSet) where TView : PrimarySettingsView<TViewModeParam> where TViewModeParam : PrimarySettingsViewModel
		{
			equipmentSettings.Init(SettingsCollection.SettingsCollectionType.Equipment, bindingContext, bindingSet);
			bindingSet.Bind(base.Toolbar.BackButtonView).For(base.Toolbar.BackButtonView.ClickEvent()).To((TViewModeParam vm) => vm.CloseViewModel);
			bindingSet.Bind(environmentLabel).For((IfitTextView v) => v.Visibility).To((TViewModeParam vm) => vm.ShouldShowEnvironmentLabel)
				.WithConversion(new VisibilityGoneValueConverter());
			bindingSet.Bind(environmentLabel).For((IfitTextView v) => v.Text).To((TViewModeParam vm) => vm.EnvironmentString);
			bindingSet.Bind(equipmentSettings).For("Visibility").To((TViewModeParam vm) => vm.EquipmentList)
				.WithConversion(new INCListNullVisibilityGoneValueConverter<SettingsCollectionCellModel>());
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			equipmentSettings?.CleanUp();
			equipmentSettings?.Dispose();
			equipmentSettings = null;
			environmentLabel?.Dispose();
			environmentLabel = null;
		}
	}
	public class TextSpinnerItem : LinearLayout, IMvxListItem, IMvxBindingContextOwner, IMvxListItemView, IMvxDataConsumer
	{
		private IMvxBindingContext _bindingContext;

		public IMvxBindingContext BindingContext
		{
			get
			{
				return _bindingContext;
			}
			set
			{
				throw new NotImplementedException();
			}
		}

		public int TemplateId
		{
			get
			{
				Mvx.TryResolve<IDeviceInformation>(out var service);
				if (service == null || !service.IsTablet)
				{
					return 2131624333;
				}
				return 2131624334;
			}
		}

		public object DataContext
		{
			get
			{
				return _bindingContext.DataContext;
			}
			set
			{
				if (_bindingContext.DataContext != value)
				{
					_bindingContext.DataContext = value;
				}
			}
		}

		public TextSpinnerItem(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
		}

		public TextSpinnerItem(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public TextSpinnerItem(Context context, int templateId)
			: base(context)
		{
			Init(context, templateId);
		}

		private void Init(Context context, int templateId)
		{
			LayoutInflater.From(context).Inflate(templateId, this, attachToRoot: true);
			IfitTextView spinnerText = FindViewById<IfitTextView>(2131427729);
			_bindingContext = new MvxAndroidBindingContext(base.Context, (IMvxLayoutInflaterHolder)base.Context);
			_bindingContext.DelayBind(delegate
			{
				MvxFluentBindingDescriptionSet<TextSpinnerItem, string> mvxFluentBindingDescriptionSet = this.CreateBindingSet<TextSpinnerItem, string>();
				mvxFluentBindingDescriptionSet.Bind(spinnerText).For((IfitTextView x) => x.Text).To((string x) => x);
				mvxFluentBindingDescriptionSet.Apply();
			});
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			_bindingContext?.ClearAllBindings();
			_bindingContext = null;
		}
	}
}
