		private async System.Threading.Tasks.Task StartShareLogsIntent()
		{
			CircularLoadingView emailProcessingIndicator = ((Activity)(object)this).FindViewById<CircularLoadingView>(2131429177).DisposeWith(Disposables);
			try
			{
				EmailLogsButton.Visibility = ViewStates.Invisible;
				emailProcessingIndicator.Visibility = ViewStates.Visible;
				iFit.Logger.Log.Trace("SecretSettings", "button \"EMAIL LOGS\" tapped");
				string text = null;
				ILogFileService service;
				bool flag = Mvx.TryResolve<ILogFileService>(out service);
				bool flag2 = flag;
				if (flag2)
				{
					flag2 = !string.IsNullOrEmpty(text = await service.UploadLogsToS3AndCreateDescription());
				}
				if (flag2)
				{
					text = text?.Replace("\n", "\n\n");
					Intent intent = new Intent("android.intent.action.SENDTO");
					intent.SetType("message/rfc822");
					intent.SetData(global::Android.Net.Uri.Parse("mailto:"));
					intent.PutExtra("android.intent.extra.SUBJECT", "Wolf Logs");
					intent.PutExtra("android.intent.extra.TEXT", text);
					if (!((Context)(object)this).TryResolveActivity(intent, out var resultingPackages))
					{
						try
						{
							global::Android.Content.ClipboardManager clipboardManager = global::Android.Runtime.Extensions.JavaCast<global::Android.Content.ClipboardManager>(((Context)(object)this).GetSystemService("clipboard"));
							clipboardManager.PrimaryClip = ClipData.NewPlainText("Log URL", text);
							ShowMessage("Log urls copied to clipboard");
							Intent intent2 = new Intent("android.intent.action.VIEW");
							intent2.SetData(global::Android.Net.Uri.Parse("https://www.gmail.com"));
							if (((Context)(object)this).TryResolveActivity(intent2, out resultingPackages))
							{
								((Context)(object)this).StartActivity(intent2);
							}
							return;
						}
						catch (System.Exception exception)
						{
							iFit.Logger.Log.Error("Settings", "Failed to share logs", exception);
							return;
						}
					}
					((Context)(object)this).StartActivity(Intent.CreateChooser(intent, "Send logs via:"));
				}
				else
				{
					ShowMessage("Log URLs were not available. Try again later.");
				}
			}
			finally
			{
				emailProcessingIndicator.Visibility = ViewStates.Gone;
				EmailLogsButton.Visibility = ViewStates.Visible;
			}
		}

		private void HandleAllowSubmitChanged(object sender, EventArgs e)
		{
			ChangeButton.Clickable = base.ViewModel.AllowSubmit.Value;
			ChangeButton.Alpha = (base.ViewModel.AllowSubmit.Value ? 1f : 0.4f);
		}

		private void EditTextView_EditorAction(object sender, TextView.EditorActionEventArgs e)
		{
			if (base.ViewModel.AllowSubmit.Value)
			{
				((Activity)(object)this).DismissKeyboard();
				base.ViewModel.ChangeAPI.Execute(null);
			}
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			Disposables?.Dispose();
		}
	}
