	public class FeatureFlagViewerListItem : RelativeLayout, IMvxListItem, IMvxBindingContextOwner, IMvxListItemView, IMvxDataConsumer
	{
		private IfitButton editButton;

		private IfitTextView flagNameView;

		private IfitEditTextView flagValueView;

		private MvxListView flagsList;

		private IMvxBindingContext _bindingContext;

		private global::Android.Graphics.Color editTextColor;

		private global::Android.Graphics.Color saveTextColor;

		private global::Android.Graphics.Color editButtonBackground;

		private global::Android.Graphics.Color saveButtonBackground;

		public IMvxBindingContext BindingContext
		{
			get
			{
				return _bindingContext;
			}
			set
			{
				throw new NotImplementedException();
			}
		}

		public int TemplateId => 2131624083;

		public object DataContext
		{
			get
			{
				return _bindingContext.DataContext;
			}
			set
			{
				if (_bindingContext.DataContext != value)
				{
					_bindingContext.DataContext = value;
				}
			}
		}

		public FeatureFlagViewerListItem(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public FeatureFlagViewerListItem(Context context)
			: base(context)
		{
			Init(context);
		}

		private void Init(Context context)
		{
			LayoutInflater.From(context).Inflate(TemplateId, this, attachToRoot: true);
			TypedArray typedArray = context.ObtainStyledAttributes(Resource.Styleable.FeatureFlagViewerStyle);
			try
			{
				editTextColor = typedArray.GetColor(1, global::Android.Graphics.Color.Black);
				saveTextColor = typedArray.GetColor(3, global::Android.Graphics.Color.White);
				editButtonBackground = typedArray.GetColor(0, global::Android.Graphics.Color.LightGray);
				saveButtonBackground = typedArray.GetColor(2, Colors.Named27E0A5.ToNative());
			}
			finally
			{
				typedArray?.Recycle();
			}
			flagNameView = FindViewById<IfitTextView>(2131428675);
			flagValueView = FindViewById<IfitEditTextView>(2131429723);
			editButton = FindViewById<IfitButton>(2131427920);
			flagsList = ((Activity)(object)(base.Context as BaseActivity)).FindViewById<MvxListView>(2131428034);
			flagValueView.EditorAction -= HandleButtonClicked;
			flagValueView.EditorAction += HandleButtonClicked;
			flagValueView.InputType = InputTypes.TextFlagNoSuggestions;
			flagValueView.Enabled = false;
			editButton.Click -= HandleButtonClicked;
			editButton.Click += HandleButtonClicked;
			_bindingContext = new MvxAndroidBindingContext(base.Context, (IMvxLayoutInflaterHolder)base.Context);
			MvxFluentBindingDescriptionSet<FeatureFlagViewerListItem, FeatureFlagItemViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<FeatureFlagViewerListItem, FeatureFlagItemViewModel>();
			mvxFluentBindingDescriptionSet.Bind(flagNameView).For(flagNameView.Text).To((FeatureFlagItemViewModel vm) => vm.FeatureFlagName)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(flagValueView).For(flagValueView.Text).To((FeatureFlagItemViewModel vm) => vm.DisplayValue)
				.OneWay();
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void HandleButtonClicked(object sender, EventArgs e)
		{
			FeatureFlagItemViewModel featureFlagItemViewModel = (FeatureFlagItemViewModel)DataContext;
			if (featureFlagItemViewModel.FeatureFlagType == FeatureFlagType.Bool)
			{
				featureFlagItemViewModel.ToggleBooleanValue();
			}
			else if (flagValueView.Enabled)
			{
				try
				{
					if (featureFlagItemViewModel.FeatureFlagType == FeatureFlagType.WebviewUrl || featureFlagItemViewModel.FeatureFlagType == FeatureFlagType.String)
					{
						featureFlagItemViewModel.SetStringValue(flagValueView.Text);
					}
					else if (featureFlagItemViewModel.FeatureFlagType == FeatureFlagType.Int)
					{
						featureFlagItemViewModel.SetIntValue(int.Parse(flagValueView.Text));
					}
				}
				catch (System.Exception arg)
				{
					flagValueView.Text = featureFlagItemViewModel.DisplayValue;
					iFit.Logger.Log.Trace("FeatureFlags", $"FeatureFlag {featureFlagItemViewModel.FeatureFlagName} failed to save:\n {arg}");
				}
				flagValueView.ClearFocus();
				flagValueView.Enabled = false;
				((InputMethodManager)base.Context.GetSystemService("input_method")).HideSoftInputFromWindow(WindowToken, HideSoftInputFlags.None);
				editButton.Text = "Edit";
				editButton.SetTextColor(editTextColor);
				editButton.SetBackgroundColor(editButtonBackground);
			}
			else
			{
				flagsList.ScrollTo(0, base.Top);
				flagValueView.Enabled = true;
				flagValueView.RequestFocus();
				((InputMethodManager)base.Context.GetSystemService("input_method")).ShowSoftInput(flagValueView, ShowFlags.Implicit);
				editButton.Text = "Save";
				editButton.SetTextColor(saveTextColor);
				editButton.SetBackgroundColor(saveButtonBackground);
			}
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			_bindingContext?.ClearAllBindings();
			editButton?.Dispose();
			editButton = null;
			flagNameView?.Dispose();
			flagNameView = null;
			flagValueView?.Dispose();
			flagValueView = null;
			flagsList?.Dispose();
			flagsList = null;
		}
	}
