					addAccountItem.Description = Wolf.Core.Resources.AppStrings.settings_add_account_dynamic_one_description;
					break;
				case 2:
					addAccountItem.Description = string.Format(Wolf.Core.Resources.AppStrings.settings_add_account_dynamic_description, Wolf.Core.Resources.AppStrings.settings_add_account_dynamic_two);
