			else
			{
				addAccountDrawable = 2131231221;
			}
			typedArray?.Recycle();
			ManageAccountsViewModel.IsPrimaryToRightImageValueConverter isPrimaryToRightImageValueConverter = new ManageAccountsViewModel.IsPrimaryToRightImageValueConverter();
			base.Toolbar.TitleText = Wolf.Core.Resources.AppStrings.settings_manage_accounts;
