			noSecondaryUsers = ((Activity)(object)this).FindViewById<SettingsAddAccountItem>(2131428696);
			users = ((Activity)(object)this).FindViewById<MvxRecyclerView>(2131428525);
			users.SetLayoutManager(new LinearLayoutManager((Context)(object)this));
			ifitTextView.Text = Wolf.Core.Resources.AppStrings.settings_secondary_users;
			manageDescription.Text = Wolf.Core.Resources.AppStrings.settings_secondary_user_description;
			addAccountItem.LeftImageSource = addAccountDrawable;
