		private void DoBindingSet()
		{
			MvxFluentBindingDescriptionSet<ManageAccountsView, ManageAccountsViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<ManageAccountsView, ManageAccountsViewModel>();
			mvxFluentBindingDescriptionSet.Bind(users).For((MvxRecyclerView v) => v.ItemsSource).To((ManageAccountsViewModel x) => x.Users);
			users.Adapter = new UsersAdapter(base.BindingContext as IMvxAndroidBindingContext);
