			mvxFluentBindingDescriptionSet.Bind(addAccountItem).For(addAccountItem.ClickEvent()).To((ManageAccountsViewModel vm) => vm.ShowAddUserCmd);
			mvxFluentBindingDescriptionSet.Bind(base.Toolbar.BackButtonView).For(base.Toolbar.BackButtonView.ClickEvent()).To((ManageAccountsViewModel vm) => vm.CloseViewModel);
			mvxFluentBindingDescriptionSet.Bind(this).For("Message").To((ManageAccountsViewModel vm) => vm.ToastMessage);
			mvxFluentBindingDescriptionSet.Bind(this).For((ManageAccountsView x) => x.InvitesLeft).To((ManageAccountsViewModel vm) => vm.InvitesLeft);
			mvxFluentBindingDescriptionSet.Apply();
