	[Activity(Theme = "@style/SettingsTheme.Light", ConfigurationChanges = (ConfigChanges.Keyboard | ConfigChanges.KeyboardHidden | ConfigChanges.Orientation | ConfigChanges.ScreenSize | ConfigChanges.UiMode))]
	public class SettingsUpdateView : BaseActivity<SettingsUpdateViewModel>
	{
		private class AnimateBottomVisibilityConverter : MvxValueConverter<bool, ViewStates>
		{
			private readonly ViewGroup root;

			private readonly View affected;

			public AnimateBottomVisibilityConverter(ViewGroup root, View affected)
			{
				this.root = root;
				this.affected = affected;
			}

			protected override ViewStates Convert(bool value, Type targetType, object parameter, CultureInfo culture)
			{
				bool flag = affected.Visibility == ViewStates.Visible;
				if (value != flag)
				{
					Slide slide = new Slide(GravityFlags.Bottom);
					slide.SetDuration(500L);
					global::Android.Transitions.TransitionManager.BeginDelayedTransition(root, slide);
				}
				else
				{
					global::Android.Transitions.TransitionManager.EndTransitions(root);
				}
				if (!value)
				{
					return ViewStates.Gone;
				}
				return ViewStates.Visible;
			}
		}

		protected override int LayoutResId => 2131624405;

		protected override void SetupView()
		{
			base.SetupView();
			base.Toolbar.TitleText = Wolf.Core.Resources.AppStrings.update;
