		private void SetUpSmartAdjustActivePulse()
		{
			bool smartAdjustFeatureEnabled = base.ViewModel.SmartAdjustFeatureEnabled;
			bool activePulseFeatureEnabled = base.ViewModel.ActivePulseFeatureEnabled;
			if (!smartAdjustFeatureEnabled || !base.IsTablet)
			{
				smartAdjust.Visibility = ViewStates.Gone;
			}
			if (!activePulseFeatureEnabled || !base.IsTablet)
			{
				smartHRtraining.Visibility = ViewStates.Gone;
				heartRateZones.Visibility = ViewStates.Gone;
			}
			if ((!smartAdjustFeatureEnabled && !activePulseFeatureEnabled) || !base.IsTablet)
			{
				heartRateTitle.Visibility = ViewStates.Gone;
				if (maxTreadmillSpeedPicker != null)
				{
					maxTreadmillSpeedPicker.Visibility = ViewStates.Gone;
				}
				((Activity)(object)this).FindViewById<View>(2131427897).Visibility = ViewStates.Gone;
			}
		}

