	[Activity(Theme = "@style/SettingsTheme.Light", ScreenOrientation = ScreenOrientation.Behind, ConfigurationChanges = (ConfigChanges.Keyboard | ConfigChanges.KeyboardHidden | ConfigChanges.Orientation | ConfigChanges.ScreenSize | ConfigChanges.UiMode))]
	public class FeedbackView : BaseKeyboardResizingView<FeedbackViewModel>, ISettingsMessage
	{
		private RelativeLayout activityIndicator;

		private LabelledTextEntry feedbackContainer;

		private LabelledTextEntry firstNameContainer;

		private LabelledTextEntry lastNameContainer;

		private LabelledTextEntry addressContainer;

		private LabelledTextEntry cityContainer;

		private LabelledTextEntry stateContainer;

		private LabelledTextEntry postalCodeContainer;

		private LabelledTextEntry phoneNumberContainer;

		private LabelledTextEntry emailContainer;

		private LabelledTextEntry serialContainer;

		private LabelledTextEntry modelContainer;

		private LabelledTextEntry purchaseLocationContainer;

		private LabelledTextEntry purchaseDateContainer;

		private View purchaseDateMask;

		private bool isDisposed;

		private IMvxInteraction<object> refreshUser;

		protected override int LayoutResId
		{
			get
			{
				if (!base.IsTablet)
				{
					return 2131624359;
				}
				return 2131624360;
			}
		}

		public IMvxInteraction<object> UserInteraction
		{
			get
			{
				return refreshUser;
			}
			set
			{
				if (refreshUser != null)
				{
					refreshUser.Requested -= OnUserRefreshed;
				}
				refreshUser = value;
				refreshUser.Requested += OnUserRefreshed;
			}
		}

		protected override void SetupView()
		{
			base.SetupView();
			base.Toolbar.TitleText = Wolf.Core.Resources.AppStrings.settings_feedback;
			SetRootLayout(2131428065);
			IfitTextView ifitTextView = ((Activity)(object)this).FindViewById<IfitTextView>(2131428063);
			ifitTextView.Text = Wolf.Core.Resources.AppStrings.feedbackview_feedback_header;
			activityIndicator = ((Activity)(object)this).FindViewById<RelativeLayout>(2131428321);
			IfitTextView ifitTextView2 = ((Activity)(object)this).FindViewById<IfitTextView>(2131427434);
			ifitTextView2.Text = Wolf.Core.Resources.AppStrings.feedbackview_additional_information_title;
			IfitTextView ifitTextView3 = ((Activity)(object)this).FindViewById<IfitTextView>(2131427433);
			ifitTextView3.Text = Wolf.Core.Resources.AppStrings.feedbackview_additional_information_description;
			firstNameContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428085);
			lastNameContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428480);
			addressContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131427436);
			cityContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131427663);
			stateContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131429367);
			postalCodeContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131429833);
			phoneNumberContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428801);
			emailContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131427928);
			serialContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131429198);
			modelContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428653);
			purchaseLocationContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428929);
			purchaseDateContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428927);
			feedbackContainer = ((Activity)(object)this).FindViewById<LabelledTextEntry>(2131428062);
			feedbackContainer?.Setup(emailContainer, Wolf.Core.Resources.AppStrings.feedback_label, Wolf.Core.Resources.AppStrings.feedback_hint, null);
			purchaseDateMask = ((Activity)(object)this).FindViewById<View>(2131428928);
			base.Toolbar.RightTextButton.Text = Wolf.Core.Resources.AppStrings.send.ToUpper();
			base.Toolbar.RightTextButton.Click -= OnSendClicked;
			base.Toolbar.RightTextButton.Click += OnSendClicked;
			DoBindingSet();
		}

		private void DoBindingSet()
		{
			NegateBoolValueConverter converter = new NegateBoolValueConverter();
			MvxFluentBindingDescriptionSet<FeedbackView, FeedbackViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<FeedbackView, FeedbackViewModel>();
			mvxFluentBindingDescriptionSet.Bind(this).For((FeedbackView x) => x.UserInteraction).To((FeedbackViewModel vm) => vm.UserRefreshed)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(base.Toolbar.RightTextButton).For((IfitTextView x) => x.Enabled).To((FeedbackViewModel vm) => vm.ShowActivityIndicator)
				.WithConversion(converter);
			mvxFluentBindingDescriptionSet.Bind(activityIndicator).For((RelativeLayout x) => x.Visibility).To((FeedbackViewModel vm) => vm.ShowActivityIndicator)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(this).For("SettingsMessage").To((FeedbackViewModel vm) => vm.SendFeedbackMessage)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(base.Toolbar.BackButtonView).For(base.Toolbar.BackButtonView.ClickEvent()).To((FeedbackViewModel vm) => vm.CloseViewModel);
			mvxFluentBindingDescriptionSet.Bind(purchaseDateMask).For(purchaseDateMask.ClickEvent()).To((FeedbackViewModel vm) => vm.EditDate);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void OnUserRefreshed(object sender, MvxValueEventArgs<object> e)
		{
			if (firstNameContainer != null)
			{
				emailContainer.Setup(firstNameContainer, base.ViewModel.EmailHintStr, Wolf.Core.Resources.AppStrings.feedbackview_email_placeholder, base.ViewModel?.FeedbackInfo?.EmailAddress, InputTypes.DatetimeVariationTime);
				firstNameContainer.Setup(lastNameContainer, Wolf.Core.Resources.AppStrings.feedbackview_firstname_hint, Wolf.Core.Resources.AppStrings.feedbackview_firstname_placeholder, base.ViewModel?.FeedbackInfo?.FirstName);
				lastNameContainer.Setup(addressContainer, Wolf.Core.Resources.AppStrings.feedbackview_lastname_hint, Wolf.Core.Resources.AppStrings.feedbackview_lastname_placeholder, base.ViewModel?.FeedbackInfo?.LastName);
				addressContainer.Setup(cityContainer, Wolf.Core.Resources.AppStrings.feedbackview_address_hint, Wolf.Core.Resources.AppStrings.feedbackview_address_placeholder, base.ViewModel?.FeedbackInfo?.StreetAddress);
				cityContainer.Setup(stateContainer, Wolf.Core.Resources.AppStrings.feedbackview_city_hint, Wolf.Core.Resources.AppStrings.feedbackview_city_placeholder, base.ViewModel?.FeedbackInfo?.City);
				stateContainer.Setup(postalCodeContainer, Wolf.Core.Resources.AppStrings.feedbackview_state_hint, Wolf.Core.Resources.AppStrings.feedbackview_state_placeholder, base.ViewModel?.FeedbackInfo?.State);
				postalCodeContainer.Setup(phoneNumberContainer, Wolf.Core.Resources.AppStrings.feedbackview_zipcode_hint, Wolf.Core.Resources.AppStrings.feedbackview_zipcode_placeholder, base.ViewModel?.FeedbackInfo?.PostalCode, InputTypes.ClassNumber);
				phoneNumberContainer.Setup(serialContainer, Wolf.Core.Resources.AppStrings.feedbackview_phone_number_hint, Wolf.Core.Resources.AppStrings.feedbackview_phone_number_placeholder, base.ViewModel?.FeedbackInfo?.PhoneNumber, InputTypes.ClassPhone);
				serialContainer.Setup(modelContainer, Wolf.Core.Resources.AppStrings.feedbackview_serial_number_hint, Wolf.Core.Resources.AppStrings.feedbackview_serial_number_placeholder, base.ViewModel?.FeedbackInfo?.SerialNumber);
				modelContainer.Setup(purchaseLocationContainer, Wolf.Core.Resources.AppStrings.feedbackview_model_number_hint, Wolf.Core.Resources.AppStrings.feedbackview_model_number_placeholder, base.ViewModel?.FeedbackInfo?.ModelNumber);
				purchaseLocationContainer.Setup(purchaseDateContainer, Wolf.Core.Resources.AppStrings.feedbackview_purchase_location_hint, Wolf.Core.Resources.AppStrings.feedbackview_purchase_location_placeholder, base.ViewModel?.FeedbackInfo?.PurchaseLocation);
				purchaseDateContainer.Setup(feedbackContainer, Wolf.Core.Resources.AppStrings.feedbackview_purchase_date_hint, Wolf.Core.Resources.AppStrings.feedbackview_purchase_date_placeholder, base.ViewModel?.FeedbackInfo?.PurchaseDate);
			}
			else
			{
				iFit.Logger.Log.Error("FeedbackView", "firstNameContainer is null!");
			}
		}

		private void OnSendClicked(object sender, EventArgs args)
		{
			ValidateFileds();
			base.ViewModel.DoSend(new FeedbackInfo
			{
				Description = feedbackContainer.Text,
				FirstName = firstNameContainer.Text,
				LastName = lastNameContainer.Text,
				StreetAddress = addressContainer.Text,
				City = cityContainer.Text,
				State = stateContainer.Text,
				PostalCode = postalCodeContainer.Text,
				PhoneNumber = phoneNumberContainer.Text,
				EmailAddress = emailContainer.Text,
				SerialNumber = serialContainer.Text,
				ModelNumber = modelContainer.Text,
				PurchaseLocation = purchaseLocationContainer.Text,
				PurchaseDate = purchaseDateContainer.Text
			});
		}

		private void ValidateFileds()
		{
			if (!base.ViewModel.IsEmailValid(emailContainer.Text))
			{
				emailContainer.ShowError(isVisible: true);
			}
		}

		public async System.Threading.Tasks.Task ShowSettingsMessage(string message)
		{
			ConstraintLayout root = ((Activity)(object)this).FindViewById<ConstraintLayout>(2131428065);
			IfitTextView messageView = ((Activity)(object)this).FindViewById<IfitTextView>(2131428064);
			if (!isDisposed && messageView != null)
			{
				messageView.Text = message;
				Slide slide = new Slide(GravityFlags.Bottom);
				slide.SetDuration(500L);
				global::Android.Transitions.TransitionManager.BeginDelayedTransition(root, slide);
				messageView.Visibility = ViewStates.Visible;
				await System.Threading.Tasks.Task.Delay(TimeSpan.FromSeconds(3.0));
				if (!isDisposed)
				{
					global::Android.Transitions.TransitionManager.BeginDelayedTransition(root, slide);
					messageView.Visibility = ViewStates.Gone;
					base.ViewModel.CloseViewModel.SafeExecute();
				}
			}
		}

		public override bool DispatchTouchEvent(MotionEvent ev)
		{
			bool flag = base.Toolbar.RightTextButton.ContainsTouch(ev);
			bool flag2 = base.Toolbar.BackButtonView.ContainsTouch(ev);
			if (flag || flag2)
			{
				((Activity)(object)this).DismissKeyboard();
			}
			return ((Activity)(object)this).DispatchTouchEvent(ev);
		}

		protected override void OnPause()
		{
			base.OnPause();
			base.Toolbar.RightTextButton.Click -= OnSendClicked;
		}

		protected override void OnResume()
		{
			base.OnResume();
			base.Toolbar.RightTextButton.Click -= OnSendClicked;
			base.Toolbar.RightTextButton.Click += OnSendClicked;
		}

		protected override void CleanUp()
		{
			isDisposed = true;
			base.CleanUp();
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(feedbackContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(firstNameContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(lastNameContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(addressContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(cityContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(stateContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(postalCodeContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(phoneNumberContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(emailContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(serialContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(modelContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(purchaseLocationContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(purchaseDateContainer);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(activityIndicator);
		}

		protected override void DialogClosed(ShireDialogFragment dialogFragment)
		{
			if (dialogFragment is DatePickerDialogView { Saved: not false } datePickerDialogView)
			{
				purchaseDateContainer.SetText(datePickerDialogView.DatePickerBinder.ToShortDateString());
			}
			base.DialogClosed(dialogFragment);
		}
	}
}
