			tvClosedCaptions?.Dispose();
			tvClosedCaptions = null;
			tvAutotune?.Dispose();
			tvAutotune = null;
		}

		protected override void OnResume()
		{
			base.OnResume();
			SetupScreenBrightness();
		}

		private async System.Threading.Tasks.Task SetupScreenBrightness()
		{
			screenBrightness.State = SettingsScreenBrightness.SupportState.Checking;
			try
			{
				float? num = await GetCurrentScreenBrightness.GetCurrentScreenBrightnessAsync();
				if (!num.HasValue)
				{
					screenBrightness.State = SettingsScreenBrightness.SupportState.NotSupported;
				}
				screenBrightness.State = SettingsScreenBrightness.SupportState.Supported;
				screenBrightness.InitialBrightnessPercentage = num.Value;
			}
			catch (System.Exception)
			{
				screenBrightness.State = SettingsScreenBrightness.SupportState.NotSupported;
			}
		}
	}
