	public class AppInfoView : BaseActivity<AppInfoViewModel>
	{
		private BaseSettingsItem appVersion;

		private BaseSettingsItem firmwareVersion;

		private BaseSettingsItem brainboardVersion;

		private BaseSettingsItem ipAddress;

		private BaseSettingsItem eruVersion;

		protected override int LayoutResId
		{
			get
