		protected override void SetupView()
		{
			base.SetupView();
			base.Toolbar.TitleText = Wolf.Core.Resources.AppStrings.settings_app_info;
			MvxFluentBindingDescriptionSet<AppInfoView, AppInfoViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<AppInfoView, AppInfoViewModel>();
			appVersion = ((Activity)(object)this).FindViewById<BaseSettingsItem>(2131428352);
			firmwareVersion = ((Activity)(object)this).FindViewById<BaseSettingsItem>(2131428373);
			brainboardVersion = ((Activity)(object)this).FindViewById<BaseSettingsItem>(2131428359);
			ipAddress = ((Activity)(object)this).FindViewById<BaseSettingsItem>(2131428378);
			WifiManager wifiManager = ((Context)(object)this).GetSystemService("wifi") as WifiManager;
			appVersion.Title = Wolf.Core.Resources.AppStrings.settings_app_version;
			appVersion.Content = base.ViewModel.AppVersionService.MainAppVersionInfo.FullAppVersion;
			if (base.ViewModel.IsBuiltIn)
			{
				eruVersion = ((Activity)(object)this).FindViewById<BaseSettingsItem>(2131427957);
				if (eruVersion != null)
				{
					eruVersion.Title = Wolf.Core.Resources.AppStrings.settings_eru_version;
					eruVersion.Content = base.ViewModel.IpcVersionInfo.EruVersion;
					eruVersion.Visibility = ViewStates.Visible;
				}
			}
			firmwareVersion.Title = Wolf.Core.Resources.AppStrings.settings_firmware_version;
			firmwareVersion.Content = $"{Build.VERSION.Release} {Build.VERSION.Incremental}";
			mvxFluentBindingDescriptionSet.Bind(brainboardVersion).For((BaseSettingsItem x) => x.Title).To((AppInfoViewModel vm) => vm.BrainboardVersion.Title)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(brainboardVersion).For((BaseSettingsItem x) => x.Content).To((AppInfoViewModel vm) => vm.BrainboardVersion.Value)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(brainboardVersion).For((BaseSettingsItem x) => x.Visibility).To((AppInfoViewModel vm) => vm.IsStrengthMirror)
				.WithConversion(new VisibilityGoneValueConverter(isReversed: true))
				.OneWay();
			ipAddress.Title = Wolf.Core.Resources.AppStrings.settings_ip_address;
			ipAddress.Content = GetIp();
			mvxFluentBindingDescriptionSet.Bind(base.Toolbar.BackButtonView).For(base.Toolbar.BackButtonView.ClickEvent()).To((AppInfoViewModel vm) => vm.CloseViewModel);
			mvxFluentBindingDescriptionSet.Bind(this).For("Message").To((AppInfoViewModel vm) => vm.ErrorMessage)
				.OneWay();
			mvxFluentBindingDescriptionSet.Apply();
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			appVersion?.Dispose();
			appVersion = null;
			firmwareVersion?.Dispose();
			firmwareVersion = null;
			brainboardVersion?.Dispose();
			brainboardVersion = null;
			ipAddress?.Dispose();
			ipAddress = null;
			eruVersion?.Dispose();
			eruVersion = null;
		}

		private string GetIp()
		{
			return (NetworkInterface.GetAllNetworkInterfaces()?.Where((NetworkInterface x) => (x != null && x.NetworkInterfaceType == NetworkInterfaceType.Wireless80211) || (x != null && x.NetworkInterfaceType == NetworkInterfaceType.Ethernet))?.SelectMany((NetworkInterface x) => x.GetIPProperties()?.UnicastAddresses)?.FirstOrDefault((UnicastIPAddressInformation x) => x != null && x.Address?.AddressFamily == AddressFamily.InterNetwork))?.Address?.ToString() ?? Wolf.Core.Resources.AppStrings.not_available;
		}
	}
