	public class TurnOnAICoachView : BaseDialogFragment<TurnOnAICoachViewModel>
	{
		private IfitTextView tvHeader;

		private IfitTextView tvBody;

		private ImageView qrCodeImage;

		private string _qrCode;

		protected override int LayoutId => 2131624441;

		public string QrCode
		{
			get
			{
				return _qrCode;
			}
			set
			{
				if (!(_qrCode == value))
				{
					_qrCode = value;
					GenerateQRImage(_qrCode);
				}
			}
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			tvHeader = view.FindViewById<IfitTextView>(2131429651);
			tvHeader.Text = Wolf.Core.Resources.AppStrings.turn_on_ai_coach_header;
			tvBody = view.FindViewById<IfitTextView>(2131429650);
			tvBody.Text = Wolf.Core.Resources.AppStrings.turn_on_ai_coach_body;
			qrCodeImage = view.FindViewById<ImageView>(2131428930);
			MvxFluentBindingDescriptionSet<TurnOnAICoachView, TurnOnAICoachViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<TurnOnAICoachView, TurnOnAICoachViewModel>();
			mvxFluentBindingDescriptionSet.Bind(this).For((TurnOnAICoachView v) => v.QrCode).To((TurnOnAICoachViewModel vm) => vm.QRCodeUrl);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void GenerateQRImage(string url)
		{
			try
			{
				BitMatrix bitMatrix = null;
				int width = qrCodeImage.LayoutParameters.Width;
				int height = qrCodeImage.LayoutParameters.Height;
				bitMatrix = new MultiFormatWriter().encode(url, BarcodeFormat.QR_CODE, width, height);
				Bitmap bitmap = Bitmap.CreateBitmap(width, height, Bitmap.Config.Argb8888);
				for (int i = 0; i < width; i++)
				{
					for (int j = 0; j < height; j++)
					{
						bitmap.SetPixel(i, j, bitMatrix[i, j] ? global::Android.Graphics.Color.Black : global::Android.Graphics.Color.White);
					}
				}
				qrCodeImage.SetImageBitmap(bitmap);
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("TurnOnAICoachView", "GenerateQRImage error", exception);
			}
		}
	}
