			chartController.LineChart.SetTouchEnabled(enabled: false);
			ChartContainer.AddView(chartController.LineChart);
			chartController.XAxisFormatter = new XAxisValueFormatter(base.ViewModel.XAxisFormatter);
			chartController.ShowLeftAxis = true;
			chartController.ShowRightAxis = false;
			chartController.LeftAxisIsPercent = IsPercent;
			chartController.Metric1.CustomStyleMetric = StyleLine;
			chartController.Metric1.ShowMetric = true;
			chartController.Metric1.Axis = YAxis.AxisDependency.Left;
