			chartController.LineChart.AxisLeft.GridColor = Colors.Named15151520.ToArgb();
			chartController.LineChart.AxisLeft.TextColor = Colors.Named1515158A.ToArgb();
			chartController.LineChart.XAxis.TextColor = Colors.Named1515158A.ToArgb();
			chartController.LineChart.AxisLeft.Granularity = 0.01f;
			chartController.LineChart.AxisLeft.GranularityEnabled = true;
			MvxFluentBindingDescriptionSet<PreWorkoutGraphPageView<TViewModel>, TViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<PreWorkoutGraphPageView<TViewModel>, TViewModel>();
