		}

		protected virtual void BindControls(MvxFluentBindingDescriptionSet<PreWorkoutGraphPageView<TViewModel>, TViewModel> bindingSet)
		{
			bindingSet.Bind(chartController).For((BaseLineChart x) => x.LeftAxisMin).To((TViewModel vm) => vm.MinValue);
			bindingSet.Bind(chartController).For((BaseLineChart x) => x.LeftAxisMax).To((TViewModel vm) => vm.MaxValue);
			bindingSet.Bind(chartController).For((BaseLineChart x) => x.MaxXValue).To((TViewModel vm) => vm.MaxXValue);
			bindingSet.Bind(chartController.XAxisFormatter).For((XAxisValueFormatter x) => x.IsMetric).To((TViewModel vm) => vm.IsMetric);
			bindingSet.Bind(chartController).For((BaseLineChart x) => x.IsChartInitialized).To((TViewModel vm) => vm.ChartInitialized);
			bindingSet.Bind(ChartTitle).For((IfitTextView x) => x.Text).To((TViewModel vm) => vm.Title);
		}

		protected void StyleLine(LineDataSet set)
		{
			set.SetColor(LineColor.ToArgb(), LineColor.A);
			set.SetDrawCircles(enabled: false);
			set.SetDrawValues(enabled: false);
			set.SetMode(LineDataSet.Mode.Stepped);
		}
	}
