	{
		protected override int LayoutId => 2131624276;

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			MapMaker mapMaker = view.FindViewById<MapMaker>(2131428867);
			mapContainer = mapMaker.MapView;
			mapContainer.OnCreate(savedInstanceState);
			map = mapMaker.GetMap();
			map.MapIsEditable = false;
			map.MapMovementAnimates = false;
			map.RouteColor = Colors.Named0069D2;
			map.SetStartMarkerIcon(Shire.Android.Util.ImageUtil.DrawableToBytesArr(base.Resources, 2131231684), 0.5f, 0.4f);
			map.SetEndMarkerIcon(Shire.Android.Util.ImageUtil.DrawableToBytesArr(base.Resources, 2131231473), 0.5f, 0.4f);
			map.MapPadding = new MapPadding(36);
			if (map.IsReady)
			{
				OnMapIsLoaded(this, null);
			}
		}

		public override void OnResume()
		{
			base.OnResume();
			map.OnMapIsLoaded += OnMapIsLoaded;
		}

		public override void OnPause()
		{
			base.OnPause();
			map.OnMapIsLoaded -= OnMapIsLoaded;
		}

		private async void OnMapIsLoaded(object sender, MapIsReadyEventArgs e)
		{
			await map.SetRoute(base.ViewModel.Route).ConfigureAwait(continueOnCapturedContext: false);
			map.SetZoomLevelFromRoute();
		}

		protected override void CleanUp()
		{
			base.CleanUp();
		}
	}
