			base.ViewModel.StreetViewImageWidth.Value = right;
		}

		private void RecreatePages()
		{
			if (_pagerTypes == null)
			{
				return;
			}
			if (_pagerTypes.Length == 0)
			{
				pagerContainer.Visibility = ViewStates.Gone;
				return;
			}
			pagerContainer.Visibility = ViewStates.Visible;
			flipper.ItemCount = _pagerTypes.Length;
			flipper.SelectedItem = 0;
			MvxViewPagerFragmentAdapter.FragmentInfo[] fragments = _pagerTypes.Select(delegate(Type modelType)
			{
				string text = modelType.Name.Substring(0, modelType.Name.Length - 5);
				string typeName = "Wolf.Android.Views.PreWorkout." + text;
				Type type = Type.GetType(typeName);
				return new MvxViewPagerFragmentAdapter.FragmentInfo(type, modelType, PagerInitMap[modelType.FullName]);
			}).ToArray();
			MvxViewPagerFragmentAdapter adapter = new MvxViewPagerFragmentAdapter((Context)(object)this, fragments, SupportFragmentManager);
			pager.OffscreenPageLimit = 3;
			pager.Adapter = adapter;
			pager.CurrentItem = 0;
		}

		private void UpdateStars()
		{
			if (ratingControl != null)
			{
				bool flag = _userWorkoutRating >= 1.0;
				ratingControl.RatingBar.SetRatingBarColors(flag ? goldStarColor : blueStarColor, emptyStarColor);
				ratingControl.RatingBar.Rating = (float)(flag ? _userWorkoutRating : _avgWorkoutRating);
			}
		}

		private async System.Threading.Tasks.Task InitMap(BaseViewModel model)
		{
			PreWorkoutMapPageViewModel preWorkoutMapPageViewModel = model as PreWorkoutMapPageViewModel;
			preWorkoutMapPageViewModel.Route = base.ViewModel.Route;
		}

		private async System.Threading.Tasks.Task InitChart(BaseViewModel model)
		{
			PreWorkoutGraphPageViewModel preWorkoutGraphPageViewModel = model as PreWorkoutGraphPageViewModel;
			await preWorkoutGraphPageViewModel.InitializeChart(base.ViewModel.RequestedWorkout);
		}

		public void OnOffsetChanged(AppBarLayout appBarLayout, int verticalOffset)
		{
			if (startText != null)
			{
				AdjustStartButton(startText, appBarLayout, verticalOffset);
			}
			else if (startButton != null)
			{
				AdjustStartButton(startButton, appBarLayout, verticalOffset);
			}
		}

		public void AdjustStartButton(View button, AppBarLayout layout, int verticalOffset)
		{
			int measuredHeight = appBar.MeasuredHeight;
			ViewStates viewStates = ((verticalOffset > -measuredHeight + button.Height) ? ViewStates.Gone : ViewStates.Visible);
			floatingButton.Visibility = viewStates;
			if (viewStates == ViewStates.Visible)
			{
				button.Visibility = ViewStates.Gone;
			}
			else
			{
				button.Visibility = ViewStates.Visible;
			}
		}
	}
