	public abstract class ClubEmailProcessingDialogView<TView, TViewModel> : ClubUnitPreloginBaseDialogView<TView, TViewModel> where TView : ClubUnitPreloginBaseDialogView<TView, TViewModel>, IMvxBindingContextOwner where TViewModel : ClubEmailProcessingDialogViewModel, IMvxViewModel
	{
		protected Button submitButton;

