		protected TextInputLayout email;

		protected ImageView successImage;

		protected AppCompatTextView title;

		protected AppCompatTextView tagline;

		protected AppCompatTextView successTitle;

		protected VisibilityGoneValueConverter goneWhenSuccessfulConverter = new VisibilityGoneValueConverter(isReversed: true);

		protected VisibilityGoneValueConverter visibleWhenSuccessfulConverter = new VisibilityGoneValueConverter();

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			submitButton = view.FindViewById<Button>(2131429474);
			email = view.FindViewById<TextInputLayout>(2131427924);
			title = view.FindViewById<AppCompatTextView>(2131429572);
			tagline = view.FindViewById<AppCompatTextView>(2131429519);
			successImage = view.FindViewById<ImageView>(2131429479);
			successTitle = view.FindViewById<AppCompatTextView>(2131429485);
			okButton = view.FindViewById<Button>(2131429481);
		}

		protected override void SetupBindings(MvxFluentBindingDescriptionSet<TView, TViewModel> bindingSet)
		{
			base.SetupBindings(bindingSet);
			submitButton.Click -= OnSubmitButtonClicked;
			submitButton.Click += OnSubmitButtonClicked;
			bindingSet.Bind(submitButton).For((Button x) => x.Text).To((TViewModel vm) => vm.SubmitButtonTitle)
				.OneTime();
			bindingSet.Bind(submitButton).For((Button x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(goneWhenSuccessfulConverter);
			bindingSet.Bind(submitButton).For((Button x) => x.Enabled).To((TViewModel vm) => vm.SubmitButtonEnabled);
			email.EditText.FocusChange -= OnEmailFocusChange;
			email.EditText.FocusChange += OnEmailFocusChange;
			bindingSet.Bind(email.EditText).For((EditText x) => x.Text).To((TViewModel vm) => vm.Email);
			bindingSet.Bind(email).For((TextInputLayout x) => x.Error).To((TViewModel vm) => vm.EmailError);
			bindingSet.Bind(email).For((TextInputLayout x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(goneWhenSuccessfulConverter);
			bindingSet.Bind(title).For((AppCompatTextView x) => x.Text).To((TViewModel vm) => vm.Title)
				.OneTime();
			bindingSet.Bind(title).For((AppCompatTextView x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(goneWhenSuccessfulConverter);
			bindingSet.Bind(tagline).For((AppCompatTextView x) => x.Text).To((TViewModel vm) => vm.Tagline)
				.OneTime();
			bindingSet.Bind(tagline).For((AppCompatTextView x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(goneWhenSuccessfulConverter);
			bindingSet.Bind(successImage).For("ImageViewFromResource").To((TViewModel vm) => vm.SuccessImageResourceName)
				.WithConversion(stringToDrawableConverter);
			bindingSet.Bind(successImage).For((ImageView x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(visibleWhenSuccessfulConverter);
			bindingSet.Bind(successTitle).For((AppCompatTextView x) => x.Text).To((TViewModel vm) => vm.SuccessTitle)
				.OneTime();
			bindingSet.Bind(successTitle).For((AppCompatTextView x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(visibleWhenSuccessfulConverter);
			bindingSet.Bind(okButton).For((Button x) => x.Text).To((TViewModel vm) => vm.OkButtonTitle)
				.OneTime();
			bindingSet.Bind(okButton).For(okButton.ClickEvent()).To((TViewModel vm) => vm.CloseViewModel);
			bindingSet.Bind(okButton).For((Button x) => x.Visibility).To((TViewModel vm) => vm.SuccessVisible)
				.WithConversion(visibleWhenSuccessfulConverter);
		}

		protected override void ShowKeyboard()
		{
			EditText editText = email?.EditText;
			ShowKeyboard(editText);
		}

		protected override void HideKeyboard()
		{
			InputMethodManager inputMethod = GetInputMethod(email?.EditText);
			if (inputMethod != null && inputMethod.IsActive)
			{
				CloseKeyboard(inputMethod);
			}
		}

		protected virtual void OnEmailFocusChange(object sender, View.FocusChangeEventArgs e)
		{
		}

		protected virtual void OnSubmitButtonClicked(object sender, EventArgs e)
		{
			EditText editText = email?.EditText;
			if (editText != null)
			{
				editText.FocusableInTouchMode = false;
				editText.ClearFocus();
				editText.FocusableInTouchMode = true;
			}
			HideKeyboard();
			base.ViewModel?.Submit.Execute(null);
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			if (submitButton != null)
			{
				submitButton.Click -= OnSubmitButtonClicked;
			}
			DisposeForegroundBackground(submitButton);
			submitButton?.Dispose();
			submitButton = null;
			DisposeForegroundBackground(okButton);
			okButton?.Dispose();
			okButton = null;
			if (email?.EditText != null)
			{
				email.EditText.FocusChange -= OnEmailFocusChange;
			}
			email?.Dispose();
			email = null;
			successImage?.SetImageDrawable(null);
			successImage?.Dispose();
			successImage = null;
			title?.Dispose();
			title = null;
			tagline?.Dispose();
			tagline = null;
			successTitle?.Dispose();
			successTitle = null;
		}
	}
