			customTypefaceSpan?.Dispose();
			customTypefaceSpan = null;
			if (keyboardListener != null)
			{
				keyboardListener.EndTrackKeyboard();
				keyboardListener.KeyboardDidAppear -= OnKeyboardDidAppear;
				keyboardListener.KeyboardDidDisappear -= OnKeyboardDidDisappear;
			}
		}
	}
	public abstract class ClubUnitPreloginBaseDialogView<TView, TViewModel> : ClubTabletFullScreenDialogView<TView, TViewModel> where TView : BaseDialogFragment, IMvxBindingContextOwner where TViewModel : ClubUnitPreloginBaseDialogViewModel, IMvxViewModel
	{
		protected ConstraintLayout backgroundView;

		protected ImageButton closeButton;

		protected ImageView logo;

		protected BlockedLoadingView loadingView;

		protected StringToDrawableConverter stringToDrawableConverter;

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			backgroundView = view.FindViewById<ConstraintLayout>(2131427487);
			closeButton = view.FindViewById<ImageButton>(2131427590);
			logo = view.FindViewById<ImageView>(2131428574);
			loadingView = view.FindViewById<BlockedLoadingView>(2131428537);
		}

		protected override void SetupBindings(MvxFluentBindingDescriptionSet<TView, TViewModel> bindingSet)
		{
			stringToDrawableConverter = new StringToDrawableConverter(logo.Context);
			bindingSet.Bind(backgroundView).For(backgroundView.ClickEvent()).To((TViewModel vm) => vm.CloseViewModel);
			bindingSet.Bind(closeButton).For(closeButton.ClickEvent()).To((TViewModel vm) => vm.CloseViewModel);
			bindingSet.Bind(logo).For("ImageViewFromResource").To((TViewModel vm) => vm.LogoResource)
				.WithConversion(stringToDrawableConverter);
			bindingSet.Bind(loadingView).For((BlockedLoadingView x) => x.Visibility).To((TViewModel vm) => vm.Loading)
				.WithConversion(new VisibilityGoneValueConverter());
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			backgroundView?.Dispose();
			backgroundView = null;
			DisposeForegroundBackground(closeButton);
			closeButton?.SetImageDrawable(null);
			closeButton?.Dispose();
			closeButton = null;
			logo?.SetImageDrawable(null);
			logo?.Dispose();
			logo = null;
			loadingView?.Dispose();
			loadingView = null;
			stringToDrawableConverter?.Dispose();
			stringToDrawableConverter = null;
		}

		protected void DisposeForegroundBackground(View view)
		{
			try
			{
				if (view.Foreground != null)
				{
					view.Foreground.Dispose();
					view.Foreground = null;
				}
			}
			catch (NoSuchMethodError)
			{
			}
			if (view.Background != null)
			{
				view.Background.Dispose();
				view.Background = null;
			}
		}

		public override void OnResume()
		{
			base.OnResume();
			WindowManagerLayoutParams attributes = Dialog.Window.Attributes;
			attributes.Width = -1;
			attributes.Height = -1;
			Dialog.Window.Attributes = attributes;
			ShowKeyboard();
		}

		public override void OnDismiss(IDialogInterface dialog)
		{
			HideKeyboard();
			base.OnDismiss(dialog);
		}

		protected virtual void ShowKeyboard()
		{
		}

		protected void ShowKeyboard(EditText editText)
		{
			editText?.Post(delegate
			{
				editText?.RequestFocus();
				GetInputMethod(editText)?.ShowSoftInput(editText, ShowFlags.Implicit);
			});
		}

		protected virtual void HideKeyboard()
		{
			InputMethodManager inputManager = (InputMethodManager)View.Context.GetSystemService("input_method");
			CloseKeyboard(inputManager);
		}

		protected void CloseKeyboard(InputMethodManager inputManager)
		{
			inputManager?.HideSoftInputFromWindow(View.WindowToken, HideSoftInputFlags.None);
		}

		protected InputMethodManager GetInputMethod(View view)
		{
			return view?.Context?.GetSystemService("input_method") as InputMethodManager;
		}
	}
}
