	public class JoinUserDetailsView : BaseFragment<JoinUserDetailsViewModel>, DatePickerDialog.IOnDateSetListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private class DatePickerDialogFragment : AndroidX.Fragment.App.DialogFragment
		{
			private readonly Context context;

			private readonly DateTime date;

			private readonly DatePickerDialog.IOnDateSetListener listener;

			public DatePickerDialogFragment(Context context, DateTime date, DatePickerDialog.IOnDateSetListener listener)
			{
				this.context = context;
				this.date = date;
				this.listener = listener;
			}

			public override Dialog OnCreateDialog(Bundle savedInstanceState)
			{
				DatePickerDialog datePickerDialog = new DatePickerDialog(context, listener, date.Year, date.Month - 1, date.Day);
				datePickerDialog.DatePicker.MaxDate = setMaxDate(13);
				return datePickerDialog;
			}

			private long setMaxDate(int minYearsOld)
			{
				DateTime dateTime = new DateTime(1970, 1, 1);
				return (long)(DateTime.Today.AddYears(-1 * minYearsOld).AddDays(1.0) - dateTime).TotalMilliseconds;
			}
		}

