		private ICharSequence CreateFormattedActivationCodeText()
		{
			string activation_link = Wolf.Core.Resources.AppStrings.activation_link;
			SpannableString spannableString = new SpannableString(activation_link);
			spannableString.SetSpan(new IfitCustomTypefaceSpan(IfitTypeface.Type.ProximaSemibold), 15, activation_link.Length, SpanTypes.ExclusiveExclusive);
			spannableString.SetSpan(new ForegroundColorSpan(global::Android.Graphics.Color.Argb(255, 0, 105, 210)), 15, activation_link.Length, SpanTypes.ExclusiveExclusive);
			return spannableString;
		}

