			{
				if (((Context)(object)base.Activity).GetSystemService("input_method") is InputMethodManager inputMethodManager)
				{
					inputMethodManager.HideSoftInputFromWindow(birthdayEditText.WindowToken, HideSoftInputFlags.None);
