	public class TriangleView : View
	{
		private global::Android.Graphics.Path path;

		private Paint paint;

		private float scale;

		public TriangleView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize(context, attrs);
		}

		public TriangleView(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize(context, attrs);
		}

		private void Initialize(Context context, IAttributeSet attrs)
		{
			TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.TriangleView);
			global::Android.Graphics.Color color = typedArray.GetColor(0, base.Context.GetColorCompat(2131099832));
			scale = base.Context.Resources.DisplayMetrics.Density;
			path = new global::Android.Graphics.Path();
			paint = new Paint(PaintFlags.AntiAlias);
			paint.Color = color;
			paint.SetStyle(Paint.Style.FillAndStroke);
			paint.StrokeJoin = Paint.Join.Round;
			paint.StrokeCap = Paint.Cap.Round;
			paint.SetPathEffect(new CornerPathEffect(2f));
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			path.MoveTo(0f, 0f);
			path.LineTo(canvas.Width / 2, canvas.Height);
			path.LineTo(canvas.Width, 0f);
			path.LineTo(0f, 0f);
			canvas.DrawPath(path, paint);
		}
	}
}
