	public class BleOnboardingWebView : OnboardingWebView<BleOnboardingWebViewModel>
	{
		private IDisposable userWantsPairSub;

		protected override StatusTextColorOptions StatusTextColor => StatusTextColorOptions.White;

		protected override void OnCreate(Bundle bundle)
		{
			base.OnCreate(bundle);
			userWantsPairSub = base.ViewModel.WhenUserWantsPair.SubscribeAsync(PromptForPermissionsIfNeeded);
		}

		protected override void OnActivityResult(int requestCode, global::Android.App.Result resultCode, Intent data)
		{
			base.OnActivityResult(requestCode, resultCode, data);
		}

		protected override void OnNewIntent(Intent intent)
		{
			base.OnNewIntent(intent);
			ActivityMediator.Instance.Send(intent.DataString);
		}

		protected override void OnResume()
		{
			base.OnResume();
			ActivityMediator.Instance.Cancel();
		}

		public override void OnBackPressed()
		{
			base.ViewModel?.BackPressed?.SafeExecute();
		}

		private async System.Threading.Tasks.Task PromptForPermissionsIfNeeded(bool _)
		{
			PermissionType[] blePermissions = PermissionsServiceAndroid.BlePermissions;
			await RequestPermissions(blePermissions);
		}

		private async System.Threading.Tasks.Task RequestPermissions(PermissionType[] permissions)
		{
			if (Mvx.TryResolve<IPermissionsService>(out var service) && !base.ViewModel.IsRoboRunMode)
			{
				if (service.HasPermissions(permissions))
				{
					base.ViewModel?.LocationServicesEnabled.Execute();
					await PromptForLocationServicesIfNeeded((Context)(object)this);
				}
				else
				{
					((Activity)(object)this).RequestPermissions(service.GetStrings(permissions), 2346);
				}
			}
		}

		public override async void OnRequestPermissionsResult(int requestCode, string[] permissions, Permission[] grantResults)
		{
			((Activity)(object)this).OnRequestPermissionsResult(requestCode, permissions, grantResults);
			if (requestCode == 2346 && grantResults.CountSafe() != 0 && !(grantResults?.Any((Permission x) => x < Permission.Granted) ?? false))
			{
				base.ViewModel?.LocationServicesEnabled.Execute();
				await PromptForLocationServicesIfNeeded((Context)(object)this);
			}
		}

		private async System.Threading.Tasks.Task PromptForLocationServicesIfNeeded(Context context)
		{
			if (!LocationServicesUtil.IsLocationServicesEnabled(context) && base.ViewModel != null)
			{
				await LocationServicesUtil.PromptForLocationServices((Activity)(object)this, context, checkLocEnabled: false).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			userWantsPairSub?.Dispose();
			userWantsPairSub = null;
		}
	}
