	[Activity(Theme = "@style/LightNoActionBarTheme", ConfigurationChanges = (ConfigChanges.Keyboard | ConfigChanges.KeyboardHidden | ConfigChanges.Orientation | ConfigChanges.ScreenSize | ConfigChanges.UiMode))]
	public class OnBoardingSetupView : BaseActivity<OnBoardingSetupViewModel>
	{
		private const float FragmentLandscapeHeightPercent = 0.7f;

		private const float FragmentLandscapeWidthPercent = 0.5f;

		private const float FragmentStrengthMirrorLandscapeWidthPercent = 0.82f;

		private FrameLayout fragmentView;

		private Button skipWifiButton;

		private BetterImageView backgroundImage;

		private IMvxViewModel currentFragmentVm;

		protected override int LayoutResId => 2131624244;

		protected override StatusTextColorOptions StatusTextColor => StatusTextColorOptions.White;

		protected override void SetupView()
		{
			base.SetupView();
			if (base.ViewModel.IsStrengthMirror)
			{
				((Activity)(object)this).FindViewById<RelativeLayout>(2131427424).SetBackgroundColor(global::Android.Graphics.Color.Black);
			}
			MvxFluentBindingDescriptionSet<OnBoardingSetupView, OnBoardingSetupViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<OnBoardingSetupView, OnBoardingSetupViewModel>();
			SetupBackground();
			SetupFragment();
			skipWifiButton = ((Activity)(object)this).FindViewById<Button>(2131428694);
			VisibilityInvisibleValueConverter converter = new VisibilityInvisibleValueConverter();
			mvxFluentBindingDescriptionSet.Bind(skipWifiButton).For((Button btn) => btn.Text).To((OnBoardingSetupViewModel vm) => vm.NextButtonTitle);
			mvxFluentBindingDescriptionSet.Bind(skipWifiButton).For(skipWifiButton.ClickEvent()).To((OnBoardingSetupViewModel vm) => vm.SkipWifiButton);
			mvxFluentBindingDescriptionSet.Bind(skipWifiButton).For((Button x) => x.Visibility).To((OnBoardingSetupViewModel x) => x.SkipWifiVisible)
				.WithConversion(converter);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void SetupBackground()
		{
			backgroundImage = ((Activity)(object)this).FindViewById<BetterImageView>(2131428723);
			if (base.ViewModel.IsStrengthMirror)
			{
				backgroundImage.ResourceId = 2131231967;
				int right = (int)Utils.ConvertDpToPixel(200f);
				RelativeLayout.LayoutParams layoutParams = new RelativeLayout.LayoutParams(-1, -1);
				layoutParams.SetMargins(0, 0, right, 0);
				backgroundImage.LayoutParameters = layoutParams;
			}
			else
			{
				backgroundImage.ResourceId = 2131231877;
			}
		}

		private void SetupFragment()
		{
			fragmentView = ((Activity)(object)this).FindViewById<FrameLayout>(2131428720);
			PercentRelativeLayout.LayoutParams layoutParams = (PercentRelativeLayout.LayoutParams)fragmentView.LayoutParameters;
			if (base.ViewModel.IsStrengthMirror)
			{
				layoutParams.PercentLayoutInfo.HeightPercent = 0.5f;
				layoutParams.PercentLayoutInfo.WidthPercent = 0.82f;
			}
			else
			{
				layoutParams.PercentLayoutInfo.HeightPercent = 0.7f;
				layoutParams.PercentLayoutInfo.WidthPercent = 0.5f;
			}
			fragmentView.RequestLayout();
		}

		protected override void OnResume()
		{
			base.OnResume();
			skipWifiButton.Click -= SkipWifiButton_Click;
			skipWifiButton.Click += SkipWifiButton_Click;
		}

		protected override void OnPause()
		{
			base.OnPause();
			skipWifiButton.Click -= SkipWifiButton_Click;
		}

		public override void OnBackPressed()
		{
		}

		private void SkipWifiButton_Click(object sender, EventArgs e)
		{
			if (currentFragmentVm is WifiSelectionViewModel wifiSelectionViewModel)
			{
				wifiSelectionViewModel.HasSkippedWifi = true;
			}
		}

		protected override void AddFragment(ShireFragment fragment)
		{
			if (isCleanedUp)
			{
				return;
			}
			SupportFragmentManager.BeginTransaction().Replace(2131428720, fragment).CommitAllowingStateLoss();
			UpdateViewState(fragment.ViewModel);
			if (fragment.ViewModel.GetType() == typeof(LanguageSelectionViewModel))
			{
				base.ViewModel.IsWifiComplete.Value = false;
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Language;
			}
			else if (fragment.ViewModel.GetType() == typeof(MeasurementSelectionViewModel))
			{
				base.ViewModel.IsWifiComplete.Value = true;
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Units;
			}
			else if (fragment.ViewModel.GetType() == typeof(EmbeddedUpdateCheckViewModel))
			{
				if (fragmentView != null)
				{
					fragmentView.Background = null;
				}
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Update;
			}
		}

		private void UpdateViewState(IMvxViewModel vm)
		{
			Type type = vm.GetType();
			if (type == typeof(WifiSelectionViewModel))
			{
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Wifi;
			}
			else if (type == typeof(LanguageSelectionViewModel))
			{
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Language;
			}
			else if (type == typeof(MeasurementSelectionViewModel))
			{
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Units;
			}
			else if (type == typeof(EmbeddedUpdateCheckViewModel))
			{
				base.ViewModel.CurrentView = OnBoardingSetupViewModel.ViewState.Update;
			}
			currentFragmentVm = vm;
		}

		protected override void CleanUp()
		{
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(backgroundImage);
			backgroundImage = null;
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(skipWifiButton);
			skipWifiButton = null;
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(fragmentView);
			fragmentView = null;
			currentFragmentVm = null;
			base.CleanUp();
		}
	}
