				{
					_demoModeButtonVisible = value;
					FadeDemoButton(_demoModeButtonVisible);
				}
			}
		}

		protected override void OnCreate(Bundle savedInstanceState)
		{
			base.OnCreate(savedInstanceState);
			base.AssistActivity = AndroidBug5497WorkaroundForXamarinAndroid.AssistActivity((Activity)(object)this, base.ViewModel);
			Button button = enableDemoButton;
			T viewModel = base.ViewModel;
			button.Visibility = ((viewModel == null || !viewModel.ShouldShowDemoModeEntryButton) ? ViewStates.Gone : ViewStates.Visible);
		}

		protected override void SetupView()
		{
			base.SetupView();
			enableDemoButton = ((Activity)(object)this).FindViewById<Button>(2131428719);
			enableDemoButton.Click += EnableDemoButtonClicked;
			enableDemoButton.Text = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_enable;
		}

		private void FadeDemoButton(bool isVisible)
		{
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (isVisible)
				{
					enableDemoButton.Animate().Alpha(1f).SetDuration(500L)
						.WithEndAction(new AndroidRunnable(delegate
						{
							enableDemoButton.Enabled = true;
						}))
						.Start();
				}
				else
				{
					enableDemoButton.Enabled = false;
					enableDemoButton.Animate().Alpha(0f).SetDuration(100L)
						.Start();
				}
			});
		}

		private void EnableDemoButtonClicked(object sender, EventArgs e)
		{
			base.ViewModel.DoEnableDemoMode.Execute(null);
		}

		protected override void HandleWebViewOverScrollEvent(object sender, ShireWebView.OnOverScrolledEventArgs e)
		{
			base.HandleWebViewOverScrollEvent(sender, e);
			T viewModel = base.ViewModel;
			if (viewModel != null && viewModel.ShouldShowDemoModeEntryButton)
			{
				DemoModeButtonVisible = e.ClampedY && e.ScrollY > 0;
			}
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			if (enableDemoButton != null)
			{
				enableDemoButton.Click -= EnableDemoButtonClicked;
			}
		}
	}
