	public abstract class BaseContentView<T> : BaseFragment<T> where T : BaseContentViewModel
	{
		protected ValueAnimator animator;

		protected int topMargin;

		protected abstract bool UseBaseAnimator { get; }

		protected virtual int AnimationDurationMS => 0;

		protected void UpdateViewTopMargin(View view, int value)
		{
			ViewGroup.MarginLayoutParams marginLayoutParams = (ViewGroup.MarginLayoutParams)view.LayoutParameters;
			marginLayoutParams.TopMargin = value;
			view.LayoutParameters = marginLayoutParams;
		}

		protected void UpdateViewBottomMargin(View view, int value)
		{
			ViewGroup.MarginLayoutParams marginLayoutParams = (ViewGroup.MarginLayoutParams)view.LayoutParameters;
			marginLayoutParams.BottomMargin = value;
			view.LayoutParameters = marginLayoutParams;
		}

		public override void OnActivityCreated(Bundle savedInstanceState)
		{
			base.OnActivityCreated(savedInstanceState);
			if (UseBaseAnimator)
			{
				animator = ValueAnimator.OfInt(topMargin, 0);
				animator.Update -= OnAnimationUpdate;
				animator.Update += OnAnimationUpdate;
				animator.SetDuration(AnimationDurationMS);
				animator.Start();
			}
		}

		protected override void CleanUp()
		{
			if (animator != null)
			{
				animator.Update -= OnAnimationUpdate;
				animator.Dispose();
				animator = null;
			}
		}

		protected abstract void OnAnimationUpdate(object sender, ValueAnimator.AnimatorUpdateEventArgs e);
	}
	public abstract class BaseNavigationDrawerView<T> : BaseDialogFragment<T>, IProfileToolbarDialog where T : BaseViewModel, IMvxViewModel
	{
		private const StatusBarVisibility HiddenSystemUiVisibility = (StatusBarVisibility)5380;

		private StatusBarVisibility previousRootVisibility;

		private View root;

		private ColorDrawable dimDrawable;

		private global::Android.Graphics.Color scrimColor;

		private const int FadeAnimationDuration = 200;

		private const int FadeInDelay = 350;

		public override void OnCreate(Bundle savedInstanceState)
		{
			base.OnCreate(savedInstanceState);
			root = ((Activity)(object)base.Activity).Window.DecorView.FindViewById(16908290);
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			TypedArray typedArray = ThemeWrapper.ObtainStyledAttributes(Resource.Styleable.NavigationDrawerStyle);
			if (typedArray != null)
			{
				scrimColor = typedArray.GetColor(0, -1);
				typedArray.Recycle();
			}
		}

		public override void OnResume()
		{
			base.OnResume();
			ShowOverlay();
			HideStatusBar();
		}

		public override void OnPause()
		{
			base.OnPause();
			HideOverlay();
			RestoreStatusBar();
		}

		private void ShowOverlay()
		{
			if (root != null)
			{
				dimDrawable = new ColorDrawable(scrimColor);
				dimDrawable.SetBounds(0, 0, root.Width, root.Height);
				dimDrawable.Alpha = 0;
				ViewOverlay overlay = root.Overlay;
				if (overlay != null)
				{
					Dialog.Window.ClearFlags(WindowManagerFlags.DimBehind);
					overlay.Add(dimDrawable);
					ObjectAnimator objectAnimator = ObjectAnimator.OfPropertyValuesHolder(dimDrawable, PropertyValuesHolder.OfInt("alpha", 0, 255));
					objectAnimator.SetTarget(dimDrawable);
					objectAnimator.SetDuration(200L);
					objectAnimator.StartDelay = 350L;
					objectAnimator.Start();
				}
			}
		}

		private void HideOverlay()
		{
			if (dimDrawable != null)
			{
				ObjectAnimator objectAnimator = ObjectAnimator.OfPropertyValuesHolder(dimDrawable, PropertyValuesHolder.OfInt("alpha", 255, 0));
				objectAnimator.SetTarget(dimDrawable);
				objectAnimator.SetDuration(200L);
				objectAnimator.AnimationEnd += OnAnimationEnd;
				iFit.Logger.Log.Trace("Navigation", "Starting HideOverlay animation in " + typeof(BaseNavigationDrawerView<>));
				objectAnimator.Start();
			}
		}

		private void OnAnimationEnd(object sender, EventArgs args)
		{
			if (dimDrawable == null)
			{
				iFit.Logger.Log.Trace("Navigation", "Not disposing dimDrawable as it was already null");
				return;
			}
			iFit.Logger.Log.Trace("Navigation", "Removing and disposing dimDrawable in " + typeof(BaseNavigationDrawerView<>));
			root?.Overlay?.Remove(dimDrawable);
			dimDrawable = iFit.Extensions.Android.JavaExtensions.DisposeSafe(dimDrawable);
		}

		private void HideStatusBar()
		{
			global::Android.Views.Window window = Dialog?.Window;
			if (window != null)
			{
				window.SetGravity(GravityFlags.Start | GravityFlags.Top);
				if (window?.Attributes != null)
				{
					window.Attributes.WindowAnimations = 2132017475;
				}
				if (Build.VERSION.SdkInt >= BuildVersionCodes.M && window?.DecorView != null)
				{
					window.DecorView.SystemUiVisibility = (StatusBarVisibility)5380;
					previousRootVisibility = root.SystemUiVisibility;
					root.SystemUiVisibility = (StatusBarVisibility)5380;
				}
			}
		}

		private void RestoreStatusBar()
		{
			if (Build.VERSION.SdkInt >= BuildVersionCodes.M && root != null)
			{
				root.SystemUiVisibility = previousRootVisibility;
			}
		}
	}
