namespace Wolf.Android.Views.LaunchScreen
{
	public class BaseLaunchScreenView<T> : BaseActivity<T> where T : LaunchScreenViewModel
	{
		private bool shouldNavigate;

		private const string Tag = "LaunchScreen";

		protected override int LayoutResId => 0;

		public bool ShouldNavigate
		{
			get
			{
				return shouldNavigate;
			}
			set
			{
				shouldNavigate = value;
				if (shouldNavigate)
				{
					NavigateToNextScreen();
				}
			}
		}

		private void NavigateToNextScreen()
		{
			if (Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				int num = global::Android.Provider.Settings.Global.GetInt(((Context)(object)this).ContentResolver, "adb_enabled", 0);
				int num2 = global::Android.Provider.Settings.Global.GetInt(((Context)(object)this).ContentResolver, "development_settings_enabled", 0);
				iFit.Logger.Log.Trace("LaunchScreen", "Sending ADB report");
				service.ReportAdbInfo(num != 0, num2 != 0);
			}
			if (base.ViewModel == null)
			{
				iFit.Logger.Log.Error("LaunchScreen", ((object)this).GetType().Name + " - ViewModel is null while attempting NavigateToNextScreen");
				return;
			}
			string externalUriString = null;
			if (Mvx.TryResolve<IAppLinking>(out var service2))
			{
				externalUriString = service2.ExternalUriString;
			}
			base.ViewModel.NavigateToNextScreen(externalUriString);
		}
	}
