		{
			base.SetupView();
			MvxFluentBindingDescriptionSet<DrawMapView, DrawMapViewModel> bindingSet = this.CreateBindingSet<DrawMapView, DrawMapViewModel>();
			DrawMapBindingSetWrapper drawMapBindingSetWrapper = new DrawMapBindingSetWrapper(bindingSet);
			MapMaker mapMaker = ((Activity)(object)this).FindViewById<MapMaker>(2131428603);
			mapContainer = mapMaker.MapView;
			mapContainer.OnCreate(createBundle);
			map = mapMaker.GetMap();
			map.MapIsEditable = true;
			map.RoadSnapOn = true;
			map.CurrentMapType = base.ViewModel.ViewMode.Value;
			map.RouteColor = Colors.DefaultMapRoute;
			map.SetStartMarkerIcon(Shire.Android.Util.ImageUtil.DrawableToBytesArr(((Context)(object)this).Resources, 2131231684), 0.5f, 0.4f);
			map.SetEndMarkerIcon(Shire.Android.Util.ImageUtil.DrawableToBytesArr(((Context)(object)this).Resources, 2131231473), 0.5f, 0.4f);
			base.ViewModel.StreetViewImageWidth = ((Context)(object)this).Resources.GetDimensionPixelSize(2131165812);
			base.ViewModel.StreetViewImageHeight = ((Context)(object)this).Resources.GetDimensionPixelSize(2131165811);
			smallBox = ((Activity)(object)this).FindViewById<DrawMapSearchBar>(2131429165);
			largeBox = ((Activity)(object)this).FindViewById<DrawMapToolBox>(2131429588);
			fullSideBox = ((Activity)(object)this).FindViewById<DrawMapLeftMenu>(2131428504);
			smallBox.Setup(this, drawMapBindingSetWrapper, map, base.ViewModel);
			largeBox.Setup(this, drawMapBindingSetWrapper, map);
			fullSideBox.Setup(this, drawMapBindingSetWrapper, map, base.ViewModel);
			drawMapBindingSetWrapper.Bind(this).For((DrawMapView x) => x.FABMenuIsOpen).To((DrawMapViewModel vm) => vm.FABMenuIsOpen);
			drawMapBindingSetWrapper.Bind(map).For((IMap v) => v.CurrentMapType).To((DrawMapViewModel vm) => vm.ViewMode);
			fabMenu = ((Activity)(object)this).FindViewById<DrawMapFabMenu>(2131428104);
			fabMenu.AddBindings(drawMapBindingSetWrapper);
			drawMapBindingSetWrapper.Bind(this).For((DrawMapView v) => v.AskLocation).To((DrawMapViewModel vm) => vm.AskLocation)
				.OneWay();
			drawMapBindingSetWrapper.Bind(this).For("CenterMap").To((DrawMapViewModel vm) => vm.MapCenter)
				.OneWay();
			drawMapBindingSetWrapper.Bind(this).For("ToolBoxMode").To((DrawMapViewModel vm) => vm.CurrentToolBoxMode)
				.OneWay();
			drawMapBindingSetWrapper.Bind(this).For("DisplayMessageToUser").To((DrawMapViewModel vm) => vm.MsgToUser)
				.OneWay();
			AddToolbarBindings(bindingSet);
			drawMapBindingSetWrapper.Apply("SetupView");
