		protected override ShireWebView SetupWebView(bool requiresRefresh = false)
		{
			return null;
		}

		public override void WhenNeedsWebViewSetup(bool hasInternet)
		{
		}

		protected override void OnResume()
		{
			base.OnResume();
			map.OnMapIsLoaded += OnMapIsLoaded;
			map.OnMapClicked += OnMapClicked;
			map.RoutePoints.CollectionChanged += PointsChanged;
			smallBox.OnShown();
			largeBox.OnShown();
			fullSideBox.OnShown();
		}

		protected override void OnPause()
		{
			base.OnPause();
			map.OnMapIsLoaded -= OnMapIsLoaded;
			map.OnMapClicked -= OnMapClicked;
			map.RoutePoints.CollectionChanged -= PointsChanged;
			smallBox.OnHidden();
			largeBox.OnHidden();
			fullSideBox.OnHidden();
			navigateAwayCancellation.Cancel();
		}

		protected override void AddFragment(ShireFragment fragment)
		{
			SaveFragment = (SaveDrawMapView)fragment;
			if (SaveFragment != null)
			{
				SupportFragmentManager.BeginTransaction().Replace(2131429146, fragment).Commit();
			}
		}

		public override void CloseFragment(IMvxViewModel fragmentViewModel)
		{
			SupportFragmentManager.BeginTransaction().Remove(SaveFragment).Commit();
			SaveFragment = null;
		}

		private void OnMapIsLoaded(object sender, MapIsReadyEventArgs e)
		{
			CenterMapAtLocation(e?.Map?.MapCenter);
		}

		private void PointsChanged(object sender, NotifyCollectionChangedEventArgs e)
		{
			base.ViewModel.RoutePoints.Value = map.RoutePoints.ToList();
		}

		public void CenterMapAtLocation(iFit.Api.Google.LatLng location)
		{
			if (!(location == null))
			{
				centerLocation = location;
				map.ClearRoute();
				map.MapCenter = location;
				map.ZoomLevel = 16f;
			}
		}

		private async void OnMapClicked(object sender, MapClickedEventArgs e)
		{
			try
			{
				System.Threading.CancellationToken token = navigateAwayCancellation.Token;
				bool flag = await map.AddRoutePoint(e.Point);
				if (token.IsCancellationRequested)
				{
					return;
				}
				if (!flag)
				{
					Activity activity = (Activity)(object)this;
					activity.RunOnUiThread(delegate
					{
						Toast.MakeText(activity, Wolf.Core.Resources.AppStrings.draw_map_point_error, ToastLength.Long).Show();
					});
				}
			}
			catch (MaxWorkoutDistanceExceededException)
			{
				View view = ((Activity)(object)this).FindViewById<View>(2131429494);
				if (view != null)
				{
					view.Alpha = 0f;
				}
				Activity activity2 = (Activity)(object)this;
				activity2.RunOnUiThread(delegate
				{
					Toast.MakeText(activity2, Wolf.Core.Resources.AppStrings.draw_map_max_workout_length_error, ToastLength.Long).Show();
				});
			}
			((InputMethodManager)((Context)(object)this).GetSystemService("input_method")).HideSoftInputFromWindow(smallBox.InputEditText.WindowToken, HideSoftInputFlags.None);
		}

		public void SwitchToToolboxMode(DrawMapViewModel.ToolBoxMode mode)
		{
			switch (mode)
			{
			case DrawMapViewModel.ToolBoxMode.Small:
			case DrawMapViewModel.ToolBoxMode.SmallSearch:
				SafeUpdateToolboxVisibility(smallBox, ViewStates.Visible);
				SafeUpdateToolboxVisibility(largeBox, ViewStates.Gone);
				SafeUpdateToolboxVisibility(fullSideBox, ViewStates.Gone);
				break;
			case DrawMapViewModel.ToolBoxMode.Large:
				SafeUpdateToolboxVisibility(smallBox, ViewStates.Visible);
				SafeUpdateToolboxVisibility(largeBox, ViewStates.Visible);
				SafeUpdateToolboxVisibility(fullSideBox, ViewStates.Gone);
				break;
			case DrawMapViewModel.ToolBoxMode.Sidebar:
				SafeUpdateToolboxVisibility(smallBox, ViewStates.Gone);
				SafeUpdateToolboxVisibility(largeBox, ViewStates.Gone);
				SafeUpdateToolboxVisibility(fullSideBox, ViewStates.Visible);
				break;
			}
		}

		private void SetUIVisibility()
		{
			SystemUiFlags systemUiVisibility = SystemUiFlags.Fullscreen | SystemUiFlags.HideNavigation | SystemUiFlags.Immersive | SystemUiFlags.ImmersiveSticky | SystemUiFlags.LayoutFullscreen | SystemUiFlags.LayoutStable;
			((Activity)(object)this).Window.DecorView.SystemUiVisibility = (StatusBarVisibility)systemUiVisibility;
		}

		private void SafeUpdateToolboxVisibility(BaseDrawMapToolBox view, ViewStates state)
		{
			view.Visibility = state;
		}

		public void DisplayMessageToUser(string msg)
		{
			if (!string.IsNullOrWhiteSpace(msg))
			{
				Toast.MakeText(((ContextWrapper)(object)this).BaseContext, msg, ToastLength.Short).Show();
			}
		}

		private void OnAskLocationRequested(object sender, MvxValueEventArgs<object> e)
		{
			if (Mvx.TryResolve<IPermissionsService>(out var service))
			{
				PermissionType[] permissions = new PermissionType[2]
				{
					PermissionType.AccessCoarseLocation,
					PermissionType.AccessFineLocation
				};
				((Activity)(object)this).RequestPermissions(service.GetStrings(permissions), 2346);
			}
		}

		public override void OnRequestPermissionsResult(int requestCode, string[] permissions, Permission[] grantResults)
		{
			((Activity)(object)this).OnRequestPermissionsResult(requestCode, permissions, grantResults);
			if (requestCode == 2346 && grantResults.CountSafe() != 0 && grantResults != null && grantResults.All((Permission x) => x >= Permission.Granted))
			{
				base.ViewModel.ContinueFindUserCurrentLocation();
			}
		}

		public void Dismiss()
		{
			base.ViewModel.CloseViewModel.Execute();
		}

		protected override void CleanUp()
		{
			smallBox?.Dispose();
			smallBox = null;
			base.CleanUp();
		}
	}
