		private EquipmentSelectorButton equipmentSelectorButton;

		private EquipmentSelectorView equipmentSelectionOverlay;

		private Dictionary<MockType, ImageButton> nonConnectedEquipmentButtons = new Dictionary<MockType, ImageButton>();

		private View subHeaderContainer;

		private MockType _selectedNonconnectedConsoleType;

		private int originalStatusBarColor;

		private double fontScale;

		protected override int LayoutResId
		{
