			}
		}

		protected override int? MainLayoutId => 2131429766;

		protected override int? ShowAnimationId => 2130772020;

		protected override int? HideAnimationId => 2130772022;

		public MockType SelectedNonconnectedConsoleType
		{
			get
			{
				return _selectedNonconnectedConsoleType;
			}
			set
			{
				_selectedNonconnectedConsoleType = value;
				((Activity)(object)this).RunOnUiThread((System.Action)UpdateCurrentNonconnectedConsoleButtonView);
			}
		}

		public override bool ShowFooterShadow => base.IsTablet;

		public override bool ShowHeaderDivider => false;

		public override void OnBackPressed()
		{
			((Activity)(object)this).MoveTaskToBack(true);
		}

		public override void OnConfigurationChanged(global::Android.Content.Res.Configuration newConfig)
		{
			if (System.Math.Abs(fontScale - (double)newConfig.FontScale) > 0.001)
			{
				base.ViewModel.HardResetNavigation(showWallOnBle: false, forceLoggedInUserToDashboard: true);
			}
			((Activity)(object)this).OnConfigurationChanged(newConfig);
		}

		protected override void SetupView()
		{
			base.SetupView();
			fontScale = ((Context)(object)this).Resources?.Configuration?.FontScale ?? 1f;
			VisibilityGoneValueConverter visibilityGone = new VisibilityGoneValueConverter();
			MvxFluentBindingDescriptionSet<DashboardView, DashboardViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<DashboardView, DashboardViewModel>();
			InitializeManualWorkoutTextView(mvxFluentBindingDescriptionSet, visibilityGone);
			subHeaderContainer = ((Activity)(object)this).FindViewById(2131427798);
			mvxFluentBindingDescriptionSet.Bind(base.Toolbar).For((IfitToolbar x) => x.TitleText).To((DashboardViewModel vm) => vm.HeaderToolbarText);
			mvxFluentBindingDescriptionSet.Bind(footerToolbarContainer).For("Visibility").To((DashboardViewModel vm) => vm.ShowLoadingContainer)
				.OneWay()
				.WithConversion(new VisibilityGoneValueConverter(isReversed: true));
			if (!base.IsTablet)
			{
				mvxFluentBindingDescriptionSet.Bind(subHeaderContainer).For("Visibility").To((DashboardViewModel vm) => vm.ShowModalitySelector)
					.OneWay()
					.WithConversion(new VisibilityGoneValueConverter());
			}
			iFit.Logger.Log.Trace("Dashboard", "SetupView - SetupWebView");
			SetupWebView();
			FrameLayout childTarget = ((Activity)(object)this).FindViewById<FrameLayout>(2131428892);
			mvxFluentBindingDescriptionSet.Bind(childTarget).For("Visibility").To((DashboardViewModel vm) => vm.IsLocked)
				.WithConversion(new VisibilityInvisibleValueConverter());
			if (base.IsTablet)
			{
				base.Toolbar.ToolbarItems = ToolbarItemType.Hamburger | ToolbarItemType.Title | ToolbarItemType.Logo | ToolbarItemType.RightText;
			}
			SetupNonconnectedConsoleBindings(mvxFluentBindingDescriptionSet);
			AddToolbarBindings(mvxFluentBindingDescriptionSet);
			mvxFluentBindingDescriptionSet.Apply();
			originalStatusBarColor = ((Activity)(object)this).Window.StatusBarColor;
		}

		protected override ShireWebView SetupWebView(bool requiresRefresh = false)
		{
			ShireWebView shireWebView = base.SetupWebView(requiresRefresh);
			shireWebView?.SetBackgroundColor(global::Android.Graphics.Color.Transparent);
			shireWebView?.ForceShowLoadingAnimation();
			return shireWebView;
		}

		private void SetupNonconnectedConsoleBindings(MvxFluentBindingDescriptionSet<DashboardView, DashboardViewModel> bindingSet)
		{
			if (base.ViewModel.ShouldShowNonConnectedSelector)
			{
				if (base.IsTablet)
				{
					SetupNonconnectedConsoleTypeButtonsTablet(bindingSet);
				}
				else
				{
					SetupNonconnectedConsoleTypeButtonsPhone(bindingSet);
				}
				bindingSet.Bind(this).For((DashboardView x) => x.SelectedNonconnectedConsoleType).To((DashboardViewModel vm) => vm.SelectedNonconnectedConsoleType)
					.OneWay();
			}
		}

		private void SetupNonconnectedConsoleTypeButtonsTablet(MvxFluentBindingDescriptionSet<DashboardView, DashboardViewModel> bindingSet)
		{
			equipmentSelectorButton = ((Activity)(object)this).FindViewById<EquipmentSelectorButton>(2131427948);
			if (equipmentSelectorButton != null)
			{
				bindingSet.Bind(equipmentSelectorButton).For("Visibility").To((DashboardViewModel vm) => vm.ShowModalitySelector)
					.OneWay()
					.WithConversion(new VisibilityGoneValueConverter());
				equipmentSelectorButton.Click -= EquipmentSelectorButton_Click;
				equipmentSelectorButton.Click += EquipmentSelectorButton_Click;
			}
			else
			{
				iFit.Logger.Log.Error("Dashboard", "DashboardViewModel - equipmentSelectorButton is null");
			}
			equipmentSelectionOverlay = ((Activity)(object)this).FindViewById<EquipmentSelectorView>(2131427949);
			if (equipmentSelectionOverlay != null)
			{
				nonConnectedEquipmentButtons = equipmentSelectionOverlay.NonConnectedEquipmentButtons;
				foreach (ImageButton value in nonConnectedEquipmentButtons.Values)
				{
					value.Click -= NonConnectedEquipmentButton_Clicked;
					value.Click += NonConnectedEquipmentButton_Clicked;
				}
				equipmentSelectionOverlay.CloseButton.Click -= CloseButton_Click;
				equipmentSelectionOverlay.CloseButton.Click += CloseButton_Click;
			}
			else
			{
				iFit.Logger.Log.Error("Dashboard", "DashboardViewModel - equipmentSelectionOverlay is null");
			}
		}

		private void EquipmentSelectorButton_Click(object sender, EventArgs e)
		{
			equipmentSelectionOverlay?.Show();
			ChangeStatusBarColor(showingOverlay: true);
		}

		private void CloseButton_Click(object sender, EventArgs e)
		{
			equipmentSelectionOverlay?.Hide();
			ChangeStatusBarColor(showingOverlay: false);
		}

		private void ChangeStatusBarColor(bool showingOverlay)
		{
			if (((Activity)(object)this).Window?.DecorView == null || Build.VERSION.SdkInt < BuildVersionCodes.M)
			{
				return;
			}
			global::Android.Graphics.Color statusBarColor = new global::Android.Graphics.Color(originalStatusBarColor);
			if (showingOverlay)
			{
				TypedArray typedArray = ((Context)(object)this).ObtainStyledAttributes(Resource.Styleable.EquipmentSelectorScreen);
				if (typedArray != null)
				{
					statusBarColor = typedArray.GetColor(0, ((Context)(object)this).GetColorCompat(2131099908));
				}
			}
			((Activity)(object)this).Window.SetStatusBarColor(statusBarColor);
		}

		private void SetupNonconnectedConsoleTypeButtonsPhone(MvxFluentBindingDescriptionSet<DashboardView, DashboardViewModel> bindingSet)
		{
			bindingSet.Bind(((Activity)(object)this).FindViewById<IfitTextView>(2131429641)).For((IfitTextView x) => x.Text).To((DashboardViewModel vm) => vm.NonConnectedTreadmillText)
				.OneWay();
			bindingSet.Bind(((Activity)(object)this).FindViewById<IfitTextView>(2131427771)).For((IfitTextView x) => x.Text).To((DashboardViewModel vm) => vm.NonConnectedCycleText)
				.OneWay();
			bindingSet.Bind(((Activity)(object)this).FindViewById<IfitTextView>(2131429130)).For((IfitTextView x) => x.Text).To((DashboardViewModel vm) => vm.NonConnectedRowText)
				.OneWay();
			bindingSet.Bind(((Activity)(object)this).FindViewById<IfitTextView>(2131427923)).For((IfitTextView x) => x.Text).To((DashboardViewModel vm) => vm.NonConnectedEllipticalText)
				.OneWay();
			bindingSet.Bind(((Activity)(object)this).FindViewById<IfitTextView>(2131429464)).For((IfitTextView x) => x.Text).To((DashboardViewModel vm) => vm.NonConnectedStrengthText)
				.OneWay();
			ImageButton value = ((Activity)(object)this).FindViewById<ImageButton>(2131427585);
			ImageButton value2 = ((Activity)(object)this).FindViewById<ImageButton>(2131427578);
			ImageButton value3 = ((Activity)(object)this).FindViewById<ImageButton>(2131427583);
			ImageButton value4 = ((Activity)(object)this).FindViewById<ImageButton>(2131427580);
			ImageButton value5 = ((Activity)(object)this).FindViewById<ImageButton>(2131427584);
			nonConnectedEquipmentButtons.Clear();
			nonConnectedEquipmentButtons.Add(MockType.Treadmill, value);
			nonConnectedEquipmentButtons.Add(MockType.Bike, value2);
			nonConnectedEquipmentButtons.Add(MockType.Rower, value3);
			nonConnectedEquipmentButtons.Add(MockType.Elliptical, value4);
			nonConnectedEquipmentButtons.Add(MockType.Strength, value5);
			foreach (ImageButton value6 in nonConnectedEquipmentButtons.Values)
			{
				value6.Click -= NonConnectedEquipmentButton_Clicked;
				value6.Click += NonConnectedEquipmentButton_Clicked;
			}
		}

		private void NonConnectedEquipmentButton_Clicked(object sender, EventArgs e)
		{
			MockType key = nonConnectedEquipmentButtons.FirstOrDefault((KeyValuePair<MockType, ImageButton> x) => x.Value == sender).Key;
			base.ViewModel.NonconnectedConsoleTypeSwitch.SafeExecute(key);
			CloseButton_Click(sender, e);
		}

		private void UpdateCurrentNonconnectedConsoleButtonView()
		{
			if (!base.ViewModel.ShouldShowNonConnectedSelector)
			{
				return;
			}
			if (equipmentSelectionOverlay != null && equipmentSelectionOverlay.Visibility == ViewStates.Visible)
			{
				equipmentSelectionOverlay.HideAfterDelay().ContinueWith(delegate
				{
					((Activity)(object)this).RunOnUiThread((System.Action)delegate
					{
						ChangeStatusBarColor(showingOverlay: false);
					});
				});
			}
			if (equipmentSelectorButton != null)
			{
				equipmentSelectorButton.DeviceType = _selectedNonconnectedConsoleType;
			}
			nonConnectedEquipmentButtons?.DoForEach(delegate(KeyValuePair<MockType, ImageButton> x)
			{
				x.Value.Selected = x.Key == _selectedNonconnectedConsoleType;
			});
		}

		private void InitializeManualWorkoutTextView(MvxFluentBindingDescriptionSet<DashboardView, DashboardViewModel> bindingSet, VisibilityGoneValueConverter visibilityGone)
		{
			manualWorkoutTextView = ((Activity)(object)this).FindViewById<IfitTextView>(2131429595);
			if (manualWorkoutTextView != null)
			{
				manualWorkoutTextView.Text = Wolf.Core.Resources.AppStrings.dashboard_manual_start.ToUpperInvariant();
				bindingSet.Bind(manualWorkoutTextView).For(manualWorkoutTextView.ClickEvent()).To((DashboardViewModel vm) => vm.StartManualWorkout);
				bindingSet.Bind(manualWorkoutTextView).For("Visibility").To((DashboardViewModel vm) => vm.ShouldShowManualWorkoutButton)
					.WithConversion(visibilityGone);
				bindingSet.Bind(manualWorkoutTextView).For((IfitTextView x) => x.Enabled).To((DashboardViewModel vm) => vm.IsManualButtonEnabled);
			}
			else
			{
				iFit.Logger.Log.Error("Dashboard", "DashboardViewModel - manualWorkoutTextView is null");
			}
		}

		public void Dismiss()
		{
			((Activity)(object)this).Intent.Extras.Clear();
			DismissNavigationDrawer(typeof(NavigationDrawerViewModel));
		}

		private void DismissNavigationDrawer(Type viewmodelType)
		{
			string tag = ShireDialogFragmentUtil.GetTag(viewmodelType.FullName);
			frag = SupportFragmentManager.FindFragmentByTag(tag);
			(frag as BaseDialogFragment)?.Dismiss();
		}

		protected override void CleanUp()
		{
			iFit.Logger.Log.Trace("Dashboard", "DashboardView Cleanup");
			base.CleanUp();
			frag?.Dispose();
			frag = null;
			manualWorkoutTextView?.Dispose();
			manualWorkoutTextView = null;
			subHeaderContainer?.Dispose();
			subHeaderContainer = null;
			nonConnectedEquipmentButtons?.Values?.DoForEach(delegate(ImageButton obj)
			{
				obj.Click -= NonConnectedEquipmentButton_Clicked;
				obj?.Dispose();
			});
			nonConnectedEquipmentButtons?.Clear();
			nonConnectedEquipmentButtons = null;
			equipmentSelectionOverlay?.Dispose();
			equipmentSelectionOverlay = null;
			equipmentSelectorButton?.Dispose();
			equipmentSelectorButton = null;
		}
	}
