	internal class PickerIconTypeConverter : MvxValueConverter<PickerIconType, int>
	{
		private readonly Theme appTheme;

		public PickerIconTypeConverter(Theme appTheme)
		{
			this.appTheme = appTheme;
		}

		protected override int Convert(PickerIconType value, Type targetType, object parameter, CultureInfo culture)
		{
			switch (value)
			{
			case PickerIconType.HeadphoneConnected:
				if (appTheme != Theme.Light)
				{
					return 2131231548;
				}
				return 2131231549;
			case PickerIconType.HeadphoneOthers:
				if (appTheme != Theme.Light)
				{
					return 2131231555;
				}
				return 2131231552;
			case PickerIconType.HeartRateConnected:
				if (appTheme != Theme.Light)
				{
					return 2131231510;
				}
				return 2131231511;
			case PickerIconType.HeartRateOthers:
				if (appTheme != Theme.Light)
				{
					return 2131231514;
				}
				return 2131231515;
			case PickerIconType.HeartRateDisabled:
				if (appTheme != Theme.Light)
				{
					return 2131231512;
				}
				return 2131231513;
			case PickerIconType.HeadphoneDisabled:
				if (appTheme != Theme.Light)
				{
					return 2131231553;
				}
				return 2131231554;
			default:
				throw new System.Exception(string.Format("Unknown value={0} to convert to a drawable resource within {1} class.", value, "PickerIconTypeConverter"));
			}
		}
	}
	internal class PickerIconTypeColorConverter : MvxValueConverter<PickerIconType, int>
	{
		private readonly Theme appTheme;

		public PickerIconTypeColorConverter(Theme appTheme)
		{
			this.appTheme = appTheme;
		}

		protected override int Convert(PickerIconType value, Type targetType, object parameter, CultureInfo culture)
		{
			switch (value)
			{
			case PickerIconType.HeartRateConnected:
			case PickerIconType.HeadphoneConnected:
				if (appTheme != Theme.Light && appTheme != Theme.StrengthMirror)
				{
					return 2131100180;
				}
				return 2131100162;
			case PickerIconType.HeartRateOthers:
			case PickerIconType.HeadphoneOthers:
				if (appTheme != Theme.Light && appTheme != Theme.StrengthMirror)
				{
					return 2131099761;
				}
				return 2131100190;
			case PickerIconType.HeartRateDisabled:
			case PickerIconType.HeadphoneDisabled:
				if (appTheme != Theme.Light && appTheme != Theme.StrengthMirror)
				{
					return 2131099825;
				}
				return 2131099758;
			default:
				throw new System.Exception(string.Format("Unknown value={0} to convert to a drawable resource within {1} class.", value, "PickerIconTypeColorConverter"));
			}
		}
	}
