			bindingSet.Bind(mvxRecyclerView).For((MvxRecyclerView x) => x.ItemClick).To((TViewModel x) => x.HandleConnection);
			bindingSet.Bind(appCompatTextView3).For((AppCompatTextView x) => x.Visibility).To((TViewModel x) => x.OtherAccessories.Count)
				.WithConversion(converter);
			bindingSet.Bind(childTarget).For((CircularLoadingView x) => x.Visibility).To((TViewModel x) => x.OtherAccessories.Count)
				.WithConversion(converter);
			return mvxRecyclerView;
