			}
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			if (LottieAnimationView == null)
			{
				LottieAnimationView = View.FindViewById<LottieAnimationView>(2131427453);
				LottieAnimationView.AddAnimatorListener(this);
				PlayAnimation(BleAnimationSequence.Tablet);
			}
		}

		protected override void ApplyBindings(bool canClose)
		{
			if (!bindingsApplied)
			{
				bindingsApplied = true;
				Cancelable = false;
				ImageButton childTarget = View.FindViewById<ImageButton>(2131427517);
				titleTextView = View.FindViewById<IfitTextView>(2131429583);
				IfitTextView childTarget2 = View.FindViewById<IfitTextView>(2131427497);
				IfitTextView childTarget3 = View.FindViewById<IfitTextView>(2131428841);
				IfitTextView childTarget4 = View.FindViewById<IfitTextView>(2131427524);
				MvxFluentBindingDescriptionSet<BleConnectingView, BleConnectingViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<BleConnectingView, BleConnectingViewModel>();
				mvxFluentBindingDescriptionSet.Bind(childTarget).For(childTarget.ClickEvent()).To((BleConnectingViewModel vm) => vm.UserDisconnectDuringConnectingStep);
				mvxFluentBindingDescriptionSet.Bind(titleTextView).For((IfitTextView v) => v.Text).To((BleConnectingViewModel vm) => vm.TitleText)
					.OneTime();
				mvxFluentBindingDescriptionSet.Bind(childTarget2).For((IfitTextView v) => v.Text).To((BleConnectingViewModel vm) => vm.BeSureText)
					.OneTime();
				mvxFluentBindingDescriptionSet.Bind(childTarget3).For((IfitTextView v) => v.Text).To((BleConnectingViewModel vm) => vm.PowerOnText)
					.OneTime();
				mvxFluentBindingDescriptionSet.Bind(childTarget4).For((IfitTextView v) => v.Text).To((BleConnectingViewModel vm) => vm.BleOnText)
					.OneTime();
				mvxFluentBindingDescriptionSet.Bind(childTarget).For((ImageButton v) => v.Visibility).To((BleConnectingViewModel vm) => vm.CanClose)
					.WithConversion(new MvxVisibilityValueConverter());
				mvxFluentBindingDescriptionSet.Bind(this).For((BleConnectingView v) => v.AnimationState).To((BleConnectingViewModel vm) => vm.AnimationState);
				mvxFluentBindingDescriptionSet.Apply();
			}
		}

		protected override void CleanUp()
		{
			if (LottieAnimationView != null)
			{
				LottieAnimationView.RemoveAnimatorListener(this);
				LottieAnimationView = null;
			}
		}

		public void OnAnimationRepeat(Animator animation)
		{
			if (CurrentAnimationSequence == BleAnimationSequence.Tablet)
			{
				PlayAnimation(BleAnimationSequence.Search);
			}
		}

		public void OnAnimationCancel(Animator animation)
		{
		}

		public void OnAnimationEnd(Animator animation)
		{
		}

		public void OnAnimationStart(Animator animation)
		{
		}

		private void PlayAnimation(BleAnimationSequence sequence)
		{
			if (LottieAnimationView != null)
			{
				LottieAnimationView.PauseAnimation();
				LottieAnimationView.SetMinAndMaxProgress(base.ViewModel.AnimationDictionary[sequence].Item1, base.ViewModel.AnimationDictionary[sequence].Item2);
				switch (sequence)
				{
				case BleAnimationSequence.Tablet:
					LottieAnimationView.Loop(loop: true);
					break;
				case BleAnimationSequence.Search:
					LottieAnimationView.Loop(loop: true);
					break;
				case BleAnimationSequence.Success:
					LottieAnimationView.Loop(loop: false);
					break;
				case BleAnimationSequence.Error:
					LottieAnimationView.Loop(loop: false);
					break;
				}
				LottieAnimationView.Progress = 0f;
				LottieAnimationView.ResumeAnimation();
				CurrentAnimationSequence = sequence;
			}
		}

		private void AnimationStateChanged()
		{
			switch (_animationState)
			{
			case BleAnimationState.Success:
				titleTextView.Text = Wolf.Core.Resources.AppStrings.ble_dialog_connecting_success_title;
				PlayAnimation(BleAnimationSequence.Success);
				break;
			case BleAnimationState.Error:
				PlayAnimation(BleAnimationSequence.Error);
				break;
			}
		}
	}
