			if (isTablet && Mvx.TryResolve<IAndroidThemeService>(out var service))
			{
				ContextThemeWrapper contextThemeWrapper = new ContextThemeWrapper(context, service.GetStyleForView(this).Value);
				TypedArray typedArray = contextThemeWrapper.ObtainStyledAttributes(Resource.Styleable.BleFoundListItem);
				realDeviceColor = typedArray.GetColor(1, base.Context.GetColorCompat(2131099690));
				mockDeviceColor = typedArray.GetColor(0, base.Context.GetColorCompat(2131099690));
