				mvxFluentBindingDescriptionSet.Bind(connectButton).For((IfitTextView x) => x.Text).To((IBleDevice x) => x.State)
					.WithConversion(statePairStringConverter);
				mvxFluentBindingDescriptionSet.Bind(this).For((BleFoundListItem x) => x.IsMockDevice).To((IBleDevice x) => x.IsMock);
				mvxFluentBindingDescriptionSet.Apply();
			});
		}

		protected override void Dispose(bool disposing)
		{
			if (!(base.Handle == IntPtr.Zero))
			{
				base.Dispose(disposing);
				_bindingContext?.ClearAllBindings();
			}
