		public void OnAnimationRepeat(Animator animation)
		{
			if (CurrentAnimationSequence == BleAnimationSequence.Tablet)
			{
				PlayAnimation(BleAnimationSequence.Search);
			}
		}

		private void PromptForPermissionsIfNeeded()
		{
			PermissionType[] blePermissions = PermissionsServiceAndroid.BlePermissions;
			RequestPermissions(blePermissions);
		}

		private void RequestPermissions(PermissionType[] permissions)
		{
			if (Mvx.TryResolve<IPermissionsService>(out var service) && !base.ViewModel.IsRoboRunMode)
			{
				if (service.HasPermissions(permissions))
				{
					PromptForLocationServicesIfNeeded(View.Context);
				}
				else
				{
					RequestPermissions(service.GetStrings(permissions), 2346);
				}
			}
		}

		public override void OnRequestPermissionsResult(int requestCode, string[] permissions, Permission[] grantResults)
		{
			base.OnRequestPermissionsResult(requestCode, permissions, grantResults);
			if (requestCode != 2346 || grantResults.CountSafe() == 0)
			{
				return;
			}
			if (grantResults != null && grantResults.All((Permission x) => x >= Permission.Granted))
			{
				System.Threading.Tasks.Task.Run(async delegate
				{
					await System.Threading.Tasks.Task.Delay(500).ConfigureAwait(continueOnCapturedContext: false);
					if (base.ViewModel != null)
					{
						base.ViewModel.RestartScan.Execute();
					}
				});
				PromptForLocationServicesIfNeeded(View.Context);
			}
			else
			{
				base.ViewModel.CloseViewModel.Execute();
			}
		}

		private void PromptForLocationServicesIfNeeded(Context context)
		{
			if (LocationServicesUtil.IsLocationServicesEnabled(context))
			{
				return;
			}
			System.Threading.Tasks.Task.Run(async delegate
			{
				await System.Threading.Tasks.Task.Delay(500).ConfigureAwait(continueOnCapturedContext: false);
				if (base.ViewModel != null)
				{
					await LocationServicesUtil.PromptForLocationServices((Activity)(object)base.Activity, context, checkLocEnabled: false).ConfigureAwait(continueOnCapturedContext: false);
					base.ViewModel.CancelScan();
				}
			});
		}

		public void OnAnimationCancel(Animator animation)
		{
		}

		public void OnAnimationEnd(Animator animation)
		{
		}

		public void OnAnimationStart(Animator animation)
		{
		}

		protected override void CleanUp()
		{
			if (LottieAnimationView != null)
			{
				LottieAnimationView.CancelAnimation();
				LottieAnimationView.RemoveAnimatorListener(this);
				LottieAnimationView.Dispose();
				LottieAnimationView = null;
			}
		}
	}
