	public abstract class BaseConsoleErrorDialogView<TViewModel> : BaseSwappingBackgroundView<TViewModel> where TViewModel : BaseSwappingBackgroundViewModel
	{
		protected class SecondsRemainingConverter : MvxValueConverter<int, SpannableString>
		{
			private readonly string prefix;

			public SecondsRemainingConverter(string prefix = null)
			{
				this.prefix = prefix ?? string.Empty;
			}

			protected override SpannableString Convert(int value, Type targetType, object parameter, CultureInfo culture)
			{
				string text = ValueFormatters.SecondsFormatter.Format(value);
				string text2 = prefix + text;
				SpannableString spannableString = new SpannableString(text2);
				spannableString.SetSpan(new StyleSpan(TypefaceStyle.Bold), prefix.Length, text2.Length, (SpanTypes)0);
				return spannableString;
			}
		}

