	internal class DatePickerDialogFragment : AndroidX.Fragment.App.DialogFragment
	{
		private readonly Context context;

		private readonly DateTime date;

		private readonly DateTime maxDate;

		private readonly DateTime minDate;

		private readonly DatePickerDialog.IOnDateSetListener listener;

		public DatePickerDialogFragment(Context context, DateTime date, DateTime maxDate, DateTime minDate, DatePickerDialog.IOnDateSetListener listener)
		{
			this.context = context;
			this.date = date;
			this.listener = listener;
			this.maxDate = maxDate;
			this.minDate = minDate;
		}

		public override Dialog OnCreateDialog(Bundle savedInstanceState)
		{
			DatePickerDialog datePickerDialog = new DatePickerDialog(context, listener, date.Year, date.Month, date.Day);
			datePickerDialog.DatePicker.MaxDate = JavaDateTimeToTimeStamp(maxDate);
			datePickerDialog.DatePicker.MinDate = JavaDateTimeToTimeStamp(minDate);
			return datePickerDialog;
		}

		private static long JavaDateTimeToTimeStamp(DateTime dt2)
		{
			long ticks = dt2.Ticks;
			long ticks2 = new DateTime(1970, 1, 1, 0, 0, 0).Ticks;
			return (ticks - ticks2) / 10000;
		}
	}
	public class DatePickerDialogView : BaseDialogFragment<DatePickerDialogViewModel>, DatePicker.IOnDateChangedListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private bool isInitialized;

		private DatePicker datePicker;

		public bool Saved { get; private set; }

		public DateTime DatePickerBinder
		{
			get
			{
				return new DateTime(base.ViewModel.Date.Value.Year, base.ViewModel.Date.Value.Month, base.ViewModel.Date.Value.Day);
			}
			set
			{
				if (isInitialized)
				{
					base.ViewModel.Date.Value = value;
					return;
				}
				isInitialized = true;
				datePicker.Init(value.Year, value.Month - 1, value.Day, this);
			}
		}

		protected override int LayoutId => 2131624029;

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			MvxFluentBindingDescriptionSet<DatePickerDialogView, DatePickerDialogViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<DatePickerDialogView, DatePickerDialogViewModel>();
			datePicker = view.FindViewById<DatePicker>(2131427821);
			DatePickerBinder = base.ViewModel.Date.Value;
			DateTime dateTime = new DateTime(1970, 1, 1);
			datePicker.MinDate = (long)(base.ViewModel.MinDate - dateTime).TotalMilliseconds;
			datePicker.MaxDate = (long)(base.ViewModel.MaxDate - dateTime).TotalMilliseconds;
			TypefaceButton typefaceButton = view.FindViewById<TypefaceButton>(2131427605);
			typefaceButton.Text = Wolf.Core.Resources.AppStrings.cancel;
			typefaceButton.Click += delegate
			{
				DoClose(save: false);
			};
			TypefaceButton typefaceButton2 = view.FindViewById<TypefaceButton>(2131429140);
			typefaceButton2.Text = Wolf.Core.Resources.AppStrings.settings_dialog_Save;
			typefaceButton2.Click += delegate
			{
				DoClose(save: true);
			};
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void DoClose(bool save)
		{
			Saved = save;
			base.ViewModel.CloseViewModel.Execute(null);
		}

		public void OnDateChanged(DatePicker view, int year, int monthOfYear, int dayOfMonth)
		{
			DatePickerBinder = new DateTime(year, monthOfYear + 1, dayOfMonth);
		}

		protected override void CleanUp()
		{
		}
	}
