	public class FullNameDialogView : BaseDialogFragment<FullNameDialogViewModel>, IShowMessage, IMvxBindingContextOwner
	{
		private TextInputLayout firstNameView;

		private TextInputLayout lastNameView;

		private IfitEditTextView phoneFirstname;

		private IfitEditTextView phoneLastName;

		private DialogFragmentPlacementKeyboardUtil keyboardUtil;

		protected override int LayoutId
		{
			get
			{
				if (!base.IsTablet)
				{
					return 2131624097;
				}
				return 2131624098;
			}
		}

		public string FirstName
		{
			get
			{
				if (!base.IsTablet)
				{
					return CapFirstLetter(phoneFirstname.Text);
				}
				return CapFirstLetter(firstNameView.EditText.Text);
			}
		}

		public string LastName
		{
			get
			{
				if (!base.IsTablet)
				{
					return CapFirstLetter(phoneLastName.Text);
				}
				return CapFirstLetter(lastNameView.EditText.Text);
			}
		}

		public bool Saved { get; set; }

		public string CapFirstLetter(string name)
		{
			if (name.IsNullOrEmpty())
			{
				return string.Empty;
			}
			if (char.IsUpper(name, 0))
			{
				return name;
			}
			char[] array = name.ToCharArray();
			array[0] = char.ToUpper(array[0]);
			return new string(array);
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			IfitTextView ifitTextView = view.FindViewById<IfitTextView>(2131429572);
