		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			background = view.FindViewById<ConstraintLayout>(2131427487);
			title = view.FindViewById<IfitTextView>(2131429572);
			subtitle = view.FindViewById<IfitTextView>(2131429477);
			button = view.FindViewById<Button>(2131427742);
			InitializeTouchDelegate(button);
		}

		protected void InitializeTouchDelegate(Button button)
		{
			View.Post(delegate
			{
				int num = (int)base.Resources.GetDimension(2131165506);
				Rect rect = new Rect();
				button.GetHitRect(rect);
				rect.Top -= num;
				rect.Left -= num;
				rect.Bottom += num;
				rect.Right += num;
				if (button.Parent is View view)
				{
					view.TouchDelegate = new TouchDelegate(rect, button);
				}
			});
		}

		protected override void SetupBindings(MvxFluentBindingDescriptionSet<TView, TViewModel> bindingSet)
		{
			if (!isModal)
			{
				bindingSet.Bind(background).For(background.ClickEvent()).To((TViewModel vm) => vm.Continue);
			}
			bindingSet.Bind(title).For((IfitTextView x) => x.Text).To((TViewModel vm) => vm.Title)
				.OneTime();
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			ConstraintLayout constraintLayout = background;
			background = ((constraintLayout != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(constraintLayout) : null);
			IfitTextView ifitTextView = title;
