			IfitTextView ifitTextView2 = subtitle;
			subtitle = ((ifitTextView2 != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(ifitTextView2) : null);
			Button obj = button;
			button = ((obj != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(obj) : null);
		}
	}
