		{
			bool showCentered = base.ViewModel.ShowCentered;
			GravityFlags gravityFlags = (showCentered ? GravityFlags.Center : (GravityFlags.End | GravityFlags.Bottom));
			iFit.Logger.Log.Trace("Wifi", $"dialogPosition: {gravityFlags}");
			global::Android.Views.Window window = Dialog.Window;
			Dialog.SetCanceledOnTouchOutside(base.ViewModel.Dismissible);
			window.SetGravity(gravityFlags);
			if (!showCentered)
			{
				window.ClearFlags(WindowManagerFlags.DimBehind);
				WindowManagerLayoutParams attributes = window.Attributes;
				attributes.Y += (int)base.Resources.GetDimension(2131166873);
				attributes.X += (int)base.Resources.GetDimension(2131166874);
