	public class ClosedCaptionsView : BaseFragment
	{
		private const string LogTag = "ClosedCaptionsView";

		private const int defaultTextSize = 21;

		private const int minPhoneFontSize = 16;

		private const int maxPhoneFontSize = 26;

		private const int minTabletFontSize = 22;

		private const int maxTabletFontSize = 32;

		private const int minTabletScreenWidth = 600;

		private const int maxTabletScreenWidth = 1280;

		private const int minPhoneScreenWidth = 360;

		private const int maxPhoneScreenWidth = 480;

		private const int phoneScalingFactor = 12;

		private const int tabletScalingFactor = 68;

		private IfitTextView textView;

		private bool isCaptionDisplayed;

		private CancellationTokenSource textViewAnimationCts;

		private ConstraintLayout captionsLayout;

		protected override int LayoutId => 2131624004;

		public bool IsCaptionVisible
		{
			set
			{
				if (isCaptionDisplayed != value)
				{
					AnimateCaptions(value);
				}
			}
		}

		public string ClosedCaptions
		{
			get
			{
				return textView.Text;
			}
			set
			{
				if (value != null)
				{
					string text = " " + value + " ";
					SpannableString spannableString = new SpannableString(text);
					global::Android.Graphics.Color color = new global::Android.Graphics.Color(ContextCompat.GetColor(Context, 2131099694));
					spannableString.SetSpan(new ForegroundColorSpan(global::Android.Graphics.Color.White), 0, text.Length, SpanTypes.ExclusiveExclusive);
					spannableString.SetSpan(new BackgroundColorSpan(color), 0, text.Length, SpanTypes.ExclusiveExclusive);
					textView.SpannableText = spannableString;
				}
				else
				{
					textView.SpannableText = null;
				}
			}
		}

		public async void ConfigureFullScreenState(bool isFullScreen)
		{
			if (Context == null)
			{
				return;
			}
			float bottomOffset = (isFullScreen ? (base.Resources.GetDimension(2131168126) - (float)DisplayMetricsUtil.DpToPx(Context, 20)) : 0f);
			try
			{
				System.Threading.Tasks.Task task = AnimateClosedCaptionsBottomPosition(bottomOffset);
				if (task != null)
				{
					await task;
				}
			}
			catch (global::Android.OS.OperationCanceledException)
			{
			}
			catch (TaskCanceledException)
			{
			}
			catch
			{
				textView?.Animate()?.TranslationY(bottomOffset)?.SetDuration(0L)?.Start();
			}
		}

		private System.Threading.Tasks.Task AnimateClosedCaptionsBottomPosition(float offset)
		{
			textViewAnimationCts?.Cancel();
			textViewAnimationCts = new CancellationTokenSource();
			return textView?.Animate()?.TranslationY(offset)?.SetDuration(200L)?.SetInterpolator(new AccelerateDecelerateInterpolator()).StartWithDisposal(textViewAnimationCts.Token);
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			captionsLayout = view.FindViewById<ConstraintLayout>(2131427682);
			textView = view.FindViewById<IfitTextView>(2131427683);
			bool isStrengthMirror = ((InWorkoutViewModel)ViewModel).IsStrengthMirror;
			iFit.Logger.Log.Trace("ClosedCaptionsView", string.Format("{0} - {1}", "isStrengthMirror", isStrengthMirror));
			if (!isStrengthMirror)
			{
				Mvx.TryResolve<IDeviceInformation>(out var service);
				bool flag = service?.IsTablet ?? false;
				iFit.Logger.Log.Trace("ClosedCaptionsView", string.Format("{0} - {1}", "isTablet", flag));
				int id = (flag ? 2131165494 : 2131165492);
				int id2 = (flag ? 2131165495 : 2131165493);
				ConstraintSet constraintSet = new ConstraintSet();
				constraintSet.Clone(captionsLayout);
				constraintSet.SetGuidelinePercent(2131428164, base.Resources.GetFloat(id));
				constraintSet.SetGuidelinePercent(2131428165, base.Resources.GetFloat(id2));
				constraintSet.ApplyTo(captionsLayout);
				int num = ((service == null) ? 21 : GetBestFittingTextSize(flag));
				iFit.Logger.Log.Trace("ClosedCaptionsView", string.Format("{0} - {1}", "textSize", num));
				textView.SetTextSize(ComplexUnitType.Sp, num);
			}
			MvxFluentBindingDescriptionSet<ClosedCaptionsView, InWorkoutViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<ClosedCaptionsView, InWorkoutViewModel>();
			mvxFluentBindingDescriptionSet.Bind(this).For((ClosedCaptionsView v) => v.ClosedCaptions).To((InWorkoutViewModel x) => x.ClosedCaptions)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(this).For("IsCaptionVisible").To((InWorkoutViewModel vm) => vm.IsClosedCaptionsVisible)
				.OneWay();
			mvxFluentBindingDescriptionSet.Apply();
		}

		protected override void CleanUp()
		{
