		private async System.Threading.Tasks.Task AnimateCaptions(bool isCaptionsVisible)
		{
			try
			{
				float value = (isCaptionsVisible ? 1f : 0f);
				textView.Alpha = (isCaptionsVisible ? 0f : 1f);
				textView.Visibility = ((!isCaptionsVisible) ? ViewStates.Gone : ViewStates.Visible);
				await textView.Animate().Alpha(value).SetDuration(100L)
					.WithLayer()
					.StartWithDisposal();
				isCaptionDisplayed = isCaptionsVisible;
			}
			catch
			{
				textView.Visibility = ((!isCaptionsVisible) ? ViewStates.Gone : ViewStates.Visible);
				textView.Alpha = (isCaptionsVisible ? 1f : 0f);
			}
		}

		private int GetBestFittingTextSize(bool isTablet)
		{
			if (Mvx.TryResolve<IDeviceInformation>(out var service))
			{
				int num = (isTablet ? (22 + (service.ScreenWidth - 600) / 68) : (16 + (service.ScreenWidth - 360) / 12));
				iFit.Logger.Log.Trace("ClosedCaptionsView", string.Format("{0} - {1}", "ScreenWidth", service.ScreenWidth));
				iFit.Logger.Log.Trace("ClosedCaptionsView", string.Format("{0} - {1}", "bestFontSize", num));
				return num;
			}
			if (!isTablet)
			{
				return 16;
			}
			return 22;
		}
	}
