	public class WidgetAnimator : IWidgetAnimator, IDisposable
	{
		private const int BasicAnimationDuration = 200;

		private const int RubberBandEffectConst = 3;

		private readonly Activity activity;

		protected ShireFragment fragment;

		private AndroidX.Fragment.App.FragmentManager fragmentManager;

		protected readonly View view;

		private readonly int offscreenPosition;

		private readonly bool animateFadeOut;

		private readonly IWolfAnalytics analytics;

		private readonly IWorkoutSettings workoutSettings;

		private CancellationTokenSource animationCts;

		private bool destroyed;

		private WidgetState _state;

		private Subject<bool> _onVisible = new Subject<bool>();

		private Subject<IWidgetAnimator> _willMove = new Subject<IWidgetAnimator>();

		private Subject<IWidgetAnimator> _onMoved = new Subject<IWidgetAnimator>();

		public bool _Visible;

		public WidgetState State
		{
			get
			{
				return _state;
			}
			private set
			{
				_state = value;
				if (_state == WidgetState.On)
				{
					Visible = true;
				}
				else
				{
					Visible = false;
				}
				AnimationInProgressToState = WidgetState.None;
			}
		}

		public WidgetLocation Location { get; set; }

		public bool CanSwipeOn { get; set; } = true;

		public string Debug { get; set; }

		public bool GesturesEnabled { get; set; } = true;

		public IObservable<bool> OnVisible => _onVisible;

		public IObservable<IWidgetAnimator> WillMove => _willMove;

		public IObservable<IWidgetAnimator> OnMoved => _onMoved;

		public virtual bool Visible
		{
			get
			{
				return _Visible;
			}
			set
			{
				if (value != _Visible)
				{
					_Visible = value;
					_onVisible.OnNext(value);
				}
				UpdateViewVisible();
			}
		}

		public WidgetState AnimationInProgressToState { get; private set; }

		public bool DestroyViewWhenOff { get; set; }

		public System.Action OnDestroyAction { private get; set; }

		public bool UnloadViewWhenOff { get; set; }

		public System.Action OnUnloadAction { private get; set; }

		public bool CreateViewWhenOn { get; set; }

		public System.Action OnCreateAction { private get; set; }

		public WidgetAnimator(Activity activity, View view, int offscreenPosition, WidgetState state, bool animateFadeOut = false)
		{
			this.activity = activity;
			this.view = view;
			this.offscreenPosition = offscreenPosition;
			this.animateFadeOut = animateFadeOut;
			State = state;
			if (Mvx.TryResolve<IWorkoutSettings>(out var service))
			{
				workoutSettings = service;
			}
			if (Mvx.TryResolve<IWolfAnalytics>(out var service2))
			{
				analytics = service2;
			}
			UpdateViewVisible();
		}

		public WidgetAnimator(Activity activity, ShireFragment fragment, int offscreenPosition, WidgetState state, bool animateFadeOut = false)
		{
			this.activity = activity;
			this.fragment = fragment;
			fragmentManager = fragment.FragmentManager;
			view = fragment.View;
			this.offscreenPosition = offscreenPosition;
			this.animateFadeOut = animateFadeOut;
			State = state;
			if (Mvx.TryResolve<IWorkoutSettings>(out var service))
			{
				workoutSettings = service;
			}
			if (Mvx.TryResolve<IWolfAnalytics>(out var service2))
			{
				analytics = service2;
			}
			UpdateViewVisible();
		}

		public System.Threading.Tasks.Task MoveTo(WidgetState pos)
		{
			return MoveTo(pos, animated: true);
		}

		public void DragTo(float offset)
		{
			int offset2 = ((State == WidgetState.On) ? ((Location != WidgetLocation.Left && Location != WidgetLocation.Top) ? ((int)offset) : (-(int)offset)) : ((Location != WidgetLocation.Left && Location != WidgetLocation.Top) ? (offscreenPosition - (int)offset) : (offscreenPosition + (int)offset)));
			TranslateTo(RubberBandEffect(offset2));
		}

		public System.Threading.Tasks.Task CancelMove()
		{
			return MoveTo(State, animated: true);
		}

		public System.Threading.Tasks.Task CompleteMove()
		{
			WidgetState widgetState = ((State != WidgetState.On) ? WidgetState.On : WidgetState.Off);
			if (widgetState == WidgetState.Off)
			{
				if (DestroyViewWhenOff)
				{
					widgetState = WidgetState.OffAndDestroy;
				}
				else if (UnloadViewWhenOff)
				{
					widgetState = WidgetState.OffAndUnload;
				}
			}
			analytics.InWorkoutWidgetInteraction(workoutSettings.WorkoutContainer.Workout, "Swipe", widgetState == WidgetState.On, Debug);
			return MoveTo(widgetState, animated: true);
		}

		private async System.Threading.Tasks.Task MoveTo(WidgetState stateTo, bool animated)
		{
			try
			{
				AnimationInProgressToState = stateTo;
				_willMove.OnNext(this);
				int translation = ((stateTo != WidgetState.On) ? offscreenPosition : 0);
				if (animated)
				{
					await AnimateTo(translation, 200, stateTo);
				}
				else
				{
					TranslateTo(translation);
				}
				if (!destroyed)
				{
					WidgetState state = State;
					State = stateTo;
					if (State == WidgetState.On && CreateViewWhenOn && state != WidgetState.On && state != WidgetState.OffDuringFullScreen)
					{
						OnCreateAction?.Invoke();
					}
					if (stateTo == WidgetState.OffAndDestroy)
					{
						Destroy();
					}
					if (stateTo == WidgetState.OffAndUnload)
					{
						OnUnloadAction?.Invoke();
					}
					_onMoved.OnNext(this);
				}
			}
			catch (ObjectDisposedException)
			{
			}
		}

		private async System.Threading.Tasks.Task AnimateTo(int translation, int durationMS, WidgetState stateTo)
		{
			try
			{
				TaskCompletionSource<bool> uiTcs = new TaskCompletionSource<bool>();
				Visible = true;
				animationCts?.Cancel();
				animationCts = new CancellationTokenSource();
				if (view == null)
				{
					iFit.Logger.Log.Error("Workout", "Notification view is null");
					return;
				}
				activity?.RunOnUiThread(async delegate
				{
					_ = 1;
					try
					{
						if (Location == WidgetLocation.Left || Location == WidgetLocation.Right)
						{
							await AnimateLeftRightWidget(translation, durationMS);
						}
						else
						{
							await AnimateTopBottomWidget(translation, durationMS, stateTo);
						}
					}
					catch (TaskCanceledException)
					{
					}
					catch (ObjectDisposedException)
					{
					}
					finally
					{
						uiTcs.SetResult(result: true);
					}
				});
				await uiTcs.Task;
			}
			catch (System.OperationCanceledException)
			{
				TranslateTo(translation);
			}
		}

		private async System.Threading.Tasks.Task AnimateLeftRightWidget(int translation, int durationMS)
		{
			await view.Animate().TranslationX(translation).SetDuration(durationMS)
				.SetInterpolator(new AccelerateDecelerateInterpolator())
				.StartWithDisposal(animationCts.Token);
		}

		private async System.Threading.Tasks.Task AnimateTopBottomWidget(int translation, int durationMS, WidgetState stateTo)
		{
			float value = 1f;
			if (animateFadeOut && stateTo == WidgetState.Off)
			{
				value = 0f;
			}
			await view.Animate().Alpha(value).TranslationY(translation)
				.SetDuration(durationMS)
				.SetInterpolator(new AccelerateDecelerateInterpolator())
				.StartWithDisposal(animationCts.Token);
		}

		private void TranslateTo(int translation)
		{
			animationCts?.Cancel();
			activity.RunOnUiThread(delegate
			{
				Visible = true;
				try
				{
					if (Location == WidgetLocation.Left || Location == WidgetLocation.Right)
					{
						view.Animate().TranslationX(translation).SetDuration(0L);
					}
					else
					{
						view.Animate().TranslationY(translation).SetDuration(0L);
					}
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		public bool ViewContains(System.Drawing.PointF point)
		{
			bool result = false;
			try
			{
				int[] array = new int[2];
				view.GetLocationOnScreen(array);
				int width = view.Width;
				int height = view.Height;
				result = point.X >= (float)array[0] && point.X <= (float)(array[0] + width) && point.Y >= (float)array[1] && point.Y <= (float)(array[1] + height);
			}
			catch (ObjectDisposedException)
			{
				iFit.Logger.Log.Debug("Workout", "View was disposed before checking for a touch, returning false from ViewContains");
			}
			return result;
		}

		public virtual bool IsTouchSuppressed(System.Drawing.PointF point)
		{
			return false;
		}

		private int RubberBandEffect(int offset)
		{
			if ((Location == WidgetLocation.Left && offset > 0) || (Location == WidgetLocation.Right && offset < 0))
			{
				offset /= 3;
			}
			else if ((Location == WidgetLocation.Top && offset > 0) || (Location == WidgetLocation.Bottom && offset < 0))
			{
				offset = 0;
			}
			return offset;
		}

		private void UpdateViewVisible()
		{
			activity.RunOnUiThread(delegate
			{
				try
				{
					if (Visible)
					{
						view.Visibility = ViewStates.Visible;
					}
					else
					{
						view.Visibility = ViewStates.Gone;
					}
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		private void Destroy()
		{
			try
			{
				if (destroyed)
				{
					return;
				}
				destroyed = true;
				CrossCurrentActivity.Current?.Activity?.RunOnUiThread(delegate
				{
					animationCts?.Cancel();
					animationCts = null;
					OnDestroyAction?.Invoke();
					if (view != null)
					{
						view.Visibility = ViewStates.Gone;
					}
					if (fragment != null && fragmentManager != null)
					{
						if (!fragmentManager.IsDestroyed)
						{
							fragmentManager.BeginTransaction().Remove(fragment).CommitAllowingStateLoss();
						}
						fragment = null;
						fragmentManager = null;
					}
				});
			}
			catch (ObjectDisposedException arg)
			{
				iFit.Logger.Log.Error("Workout", $"Cannot access a disposed object. ex={arg}.");
			}
			catch (System.Exception arg2)
			{
				iFit.Logger.Log.Error("Workout", $"Unable to destroy widget animator. ex={arg2}");
			}
		}

		public void Dispose()
		{
			Destroy();
		}
	}
