			wattsValue = view.FindViewById<IfitTextView>(2131429529);
			targetWattsLabel = view.FindViewById<IfitTextView>(2131429530);
			increaseButton = view.FindViewById<InWorkoutConstantWattsButton>(2131428319);
			decreaseButton = view.FindViewById<InWorkoutConstantWattsButton>(2131427841);
			increaseButtonContainer = view.FindViewById<ConstraintLayout>(2131428318);
			decreaseButtonContainer = view.FindViewById<ConstraintLayout>(2131427840);
			wattsValue.Text = _currentValue.ToString();
			SetupButtons();
			SetupTouchDelegate(increaseButtonContainer, increaseButton);
			SetupTouchDelegate(decreaseButtonContainer, decreaseButton);
			MvxFluentBindingDescriptionSet<InWorkoutConstantWattsView, InWorkoutViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<InWorkoutConstantWattsView, InWorkoutViewModel>();
			mvxFluentBindingDescriptionSet.Bind(constantWattsTitle).For((IfitTextView x) => x.Text).To((InWorkoutViewModel vm) => vm.ConstantWattsTitle)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(targetWattsLabel).For((IfitTextView x) => x.Text).To((InWorkoutViewModel vm) => vm.ConstantWattsTargetLabel)
				.OneWay();
			mvxFluentBindingDescriptionSet.Apply();
			UpdateEnableStatus();
		}

		public void SetupViewModel(InWorkoutViewModel viewModel)
		{
			this.viewModel = viewModel;
			_currentValue = viewModel.ConstantWattsModel.TargetWattsValue;
		}

		private void SetupButtons()
		{
			decrementButtonTouched = decreaseButton.WhenTouched.Subscribe(delegate
			{
				DecrementButtonTouched();
			});
			incrementButtonTouched = increaseButton.WhenTouched.Subscribe(delegate
			{
				IncrementButtonTouched();
			});
		}

		private void IncrementButtonTouched()
		{
			if (_currentValue < viewModel.ConstantWattsModel.MaxTarget && !decreaseButton.IsHolding)
			{
				IncrementDecrementButtonHeld(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.IncrementButton);
			}
		}

		private void IncrementDecrementButtonReleased()
		{
			System.Threading.Tasks.Task.Run(async delegate
			{
				Guid currentTap = lastTap;
				await System.Threading.Tasks.Task.Delay(500);
				if (currentTap.Equals(lastTap))
				{
					viewModel.SendConstantWattsTarget(_currentValue);
					((Activity)(object)base.Activity).RunOnUiThread((System.Action)delegate
					{
						UpdateWattsLabel(_currentValue);
						UpdateEnableStatus();
					});
				}
			});
		}

		private void DecrementButtonTouched()
		{
			if (_currentValue > viewModel.ConstantWattsModel.MinTarget && !increaseButton.IsHolding)
			{
				IncrementDecrementButtonHeld(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.DecrementButton);
			}
		}

		private void IncrementDecrementButtonHeld(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType buttonType)
		{
			if (IsOtherButtonHeldDown(buttonType))
			{
				return;
			}
			Guid newTap = Guid.NewGuid();
			lastTap = newTap;
			_currentValue = GetNextValue(buttonType);
			UpdateWattsLabel(_currentValue);
			if (IsValueAtEndOfRange(buttonType))
			{
				SendCurrentValueAndRelease(buttonType);
				return;
			}
			System.Threading.Tasks.Task.Run(async delegate
			{
				await System.Threading.Tasks.Task.Delay(700);
				int ticks = 0;
				int currentHoldDelayMs = 250;
				while (IsThisButtonHeldDown(buttonType))
				{
					if (newTap != lastTap)
					{
						return;
					}
					_currentValue = GetNextValue(buttonType);
					((Activity)(object)base.Activity)?.RunOnUiThread((System.Action)delegate
					{
						UpdateWattsLabel(_currentValue);
						UpdateEnableStatus();
					});
					if (IsValueAtEndOfRange(buttonType))
					{
						SendCurrentValueAndRelease(buttonType);
						break;
					}
					ticks = (ticks + 1) % 5;
					if (ticks == 0)
					{
						currentHoldDelayMs = System.Math.Max((int)((float)currentHoldDelayMs / 1.2f), 100);
					}
					await System.Threading.Tasks.Task.Delay(currentHoldDelayMs);
				}
				IncrementDecrementButtonReleased();
			});
		}

		private void SendCurrentValueAndRelease(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType buttonType)
		{
			_currentValue = GetMinOrMaxByButtonType(buttonType);
			((Activity)(object)base.Activity).RunOnUiThread((System.Action)delegate
			{
				UpdateWattsLabel(_currentValue);
				UpdateEnableStatus();
			});
			IncrementDecrementButtonReleased();
		}

		private int GetMinOrMaxByButtonType(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType type)
		{
			if (type != InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.DecrementButton)
			{
				return viewModel.ConstantWattsModel.MaxTarget;
			}
			return viewModel.ConstantWattsModel.MinTarget;
		}

		private bool IsValueAtEndOfRange(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType buttonType)
		{
			if (buttonType != InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.DecrementButton || !IsDecrementButtonAtMinimum())
			{
				if (buttonType == InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.IncrementButton)
				{
					return IsIncrementButtonAtMaximum();
				}
				return false;
			}
			return true;
		}

		private bool IsIncrementButtonAtMaximum()
		{
			return _currentValue > viewModel.ConstantWattsModel.MaxTarget - viewModel.ConstantWattsModel.StepInterval;
		}

		private bool IsDecrementButtonAtMinimum()
		{
			return _currentValue < viewModel.ConstantWattsModel.MinTarget + viewModel.ConstantWattsModel.StepInterval;
		}

		private int GetNextValue(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType buttonType)
		{
			if (buttonType != InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.DecrementButton)
			{
				return _currentValue + viewModel.ConstantWattsModel.StepInterval;
			}
			return _currentValue - viewModel.ConstantWattsModel.StepInterval;
		}

		private bool IsThisButtonHeldDown(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType buttonType)
		{
			if (buttonType != InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.DecrementButton)
			{
				return increaseButton.IsHolding;
			}
			return decreaseButton.IsHolding;
		}

		private bool IsOtherButtonHeldDown(InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType buttonType)
		{
			if (buttonType != InWorkoutConstantWattsButton.InWorkoutConstantWattsButtonType.DecrementButton)
			{
				return decreaseButton.IsHolding;
			}
			return increaseButton.IsHolding;
		}

		private void UpdateWattsLabel(int value)
		{
			wattsValue.Text = value.ToString();
		}

		private void UpdateEnableStatus()
		{
			increaseButton.Enabled = !IsIncrementButtonAtMaximum();
			decreaseButton.Enabled = !IsDecrementButtonAtMinimum();
		}

		protected override void CleanUp()
		{
			increaseButton = iFit.Extensions.Android.JavaExtensions.DisposeSafe(increaseButton);
			decreaseButton = iFit.Extensions.Android.JavaExtensions.DisposeSafe(decreaseButton);
			constantWattsTitle = iFit.Extensions.Android.JavaExtensions.DisposeSafe(constantWattsTitle);
			wattsValue = iFit.Extensions.Android.JavaExtensions.DisposeSafe(wattsValue);
			targetWattsLabel = iFit.Extensions.Android.JavaExtensions.DisposeSafe(targetWattsLabel);
			increaseButtonContainer = iFit.Extensions.Android.JavaExtensions.DisposeSafe(increaseButtonContainer);
			decreaseButtonContainer = iFit.Extensions.Android.JavaExtensions.DisposeSafe(decreaseButtonContainer);
			decrementButtonTouched.Dispose();
			decrementButtonTouched = null;
			incrementButtonTouched.Dispose();
			incrementButtonTouched = null;
			viewModel?.Dispose();
			viewModel = null;
		}

		public void SetupTouchDelegate(View parentView, InWorkoutConstantWattsButton button)
		{
			parentView.Post(delegate
			{
				Rect rect = new Rect();
				Rect rect2 = new Rect();
				button.GetHitRect(rect);
				parentView.GetHitRect(rect2);
				rect.Right += rect2.Width();
				rect.Left -= rect2.Width();
				if (button.Parent is View view)
				{
					view.TouchDelegate = new TouchDelegate(rect, button);
				}
			});
		}
	}
