		private void AnimateFabContainerRaise(long customAnimTime = 150L)
		{
			InitFabButtons();
			ConstraintSet constraintSet = new ConstraintSet();
			constraintSet.Clone(fabContainer);
			constraintSet.Connect(backgroundView.Id, 3, fabContainer.Id, 3);
			constraintSet.Connect(raiseFabButton.Id, 3, backgroundView.Id, 4);
			constraintSet.Clear(raiseFabButton.Id, 4);
			global::Android.Transitions.AutoTransition autoTransition = new global::Android.Transitions.AutoTransition();
			autoTransition.SetDuration(customAnimTime);
			global::Android.Transitions.TransitionManager.BeginDelayedTransition(fabContainer, autoTransition);
			constraintSet.ApplyTo(fabContainer);
		}

		private void AnimateFabContainerLower(long customAnimTime = 150L)
		{
			ConstraintSet constraintSet = new ConstraintSet();
			constraintSet.Clone(fabContainer);
			constraintSet.Connect(backgroundView.Id, 3, fabContainer.Id, 4);
			constraintSet.Connect(raiseFabButton.Id, 3, fabContainer.Id, 3);
			constraintSet.Connect(raiseFabButton.Id, 4, fabContainer.Id, 4);
			global::Android.Transitions.AutoTransition autoTransition = new global::Android.Transitions.AutoTransition();
			autoTransition.SetDuration(customAnimTime);
			global::Android.Transitions.TransitionManager.BeginDelayedTransition(fabContainer, autoTransition);
			constraintSet.ApplyTo(fabContainer);
		}

		private async System.Threading.Tasks.Task AnimatePlusButtonIn()
		{
			try
			{
				fabContainer.ScaleX = 0f;
				fabContainer.ScaleY = 0f;
				fabContainer.Visibility = ViewStates.Visible;
				await fabContainer.Animate().SetStartDelay(1000L).ScaleX(1f)
					.ScaleY(1f)
					.SetDuration(1250L)
					.WithLayer()
					.StartWithDisposal();
			}
			catch (global::Android.OS.OperationCanceledException)
			{
				fabContainer.Visibility = ViewStates.Gone;
				fabContainer.ScaleX = 1f;
				fabContainer.ScaleY = 1f;
			}
		}

		private void InitFabButtons()
		{
			ConstraintSet constraintSet = new ConstraintSet();
			constraintSet.Clone(View as ConstraintLayout);
			List<InWorkoutNavigationItem> list = new InWorkoutNavigationItem[5] { heartRateButton, statsButton, chartsButton, leaderboardButton, constantWattsButton }.Where((InWorkoutNavigationItem x) => x.Exists).ToList();
			View view = null;
			int count = list.Count;
			List<int> list2 = new List<int>();
			for (int num = 0; num < count; num++)
			{
				InWorkoutNavigationItem inWorkoutNavigationItem = list[num];
				list2.Add(inWorkoutNavigationItem.Id);
				constraintSet.Connect(inWorkoutNavigationItem.Id, 3, backgroundView.Id, 3);
				constraintSet.Connect(inWorkoutNavigationItem.Id, 4, backgroundView.Id, 4);
				if (num == 0)
				{
					constraintSet.Connect(inWorkoutNavigationItem.Id, 1, backgroundView.Id, 1);
				}
				else
				{
					constraintSet.Connect(inWorkoutNavigationItem.Id, 1, view.Id, 2);
				}
				if (num == count - 1)
				{
					constraintSet.Connect(inWorkoutNavigationItem.Id, 2, backgroundView.Id, 2);
				}
				view = inWorkoutNavigationItem;
			}
			if (list2.Count > 1)
			{
				constraintSet.CreateHorizontalChain(backgroundView.Id, 1, backgroundView.Id, 2, list2.ToArray(), null, 0);
			}
			constraintSet.ApplyTo(fabContainer);
		}
	}
