			PageTypes = new List<InWorkoutHeaderHudType>();
			if (ViewPager != null && base.ViewModel != null)
			{
				List<MvxViewPagerFragmentAdapter.FragmentInfo> list = base.ViewModel.HeaderPages.Value.Distinct().Select(delegate(InWorkoutHeaderHudType screenType)
				{
					PageTypes.Add(screenType);
					return CreatePage(screenType);
				}).ToList();
				if (PageTypes.Contains(InWorkoutHeaderHudType.Stats))
				{
					ViewPager.CurrentItem = PageTypes.IndexOf(InWorkoutHeaderHudType.Stats);
				}
				ViewPager.OffscreenPageLimit = list.Count;
				adapter = new MvxViewPagerFragmentAdapter(((Context)(object)base.Activity).ApplicationContext, list, base.FragmentManager);
				ViewPager.Adapter = adapter;
				ViewPager.PageSelected -= PageSelected;
				ViewPager.PageSelected += PageSelected;
				ViewPager.AddOnPageChangeListener(this);
				if (list.Count < 2)
				{
					paginationView.Visibility = ViewStates.Gone;
				}
				UpdateButtons(ViewPager.CurrentItem);
				_whenViewPagerReady.OnNext(ViewPager);
			}
		}

		public void OnPageSelected(int position)
		{
			if (position == 0)
			{
				paginationView.SelectedIndicator = InWorkoutHeaderPaginationView.Indicator.Left;
			}
			else
			{
				paginationView.SelectedIndicator = InWorkoutHeaderPaginationView.Indicator.Right;
			}
		}

		public void OnPageScrolled(int position, float positionOffset, int positionOffsetPixels)
		{
		}

		public void OnPageScrollStateChanged(int state)
		{
		}

		protected override void CleanUp()
		{
			if (PageTypes != null)
			{
				PageTypes.Clear();
				PageTypes = null;
			}
			if (_whenViewPagerReady != null)
			{
				_whenViewPagerReady.Dispose();
				_whenViewPagerReady = null;
			}
			if (_whenPageChanged != null)
			{
				_whenPageChanged.Dispose();
				_whenPageChanged = null;
			}
			if (_whenMusicButtonClicked != null)
			{
				_whenMusicButtonClicked.Dispose();
				_whenMusicButtonClicked = null;
			}
			if (ViewPager != null)
			{
				ViewPager.RemoveOnPageChangeListener(this);
				ViewPager.PageSelected -= PageSelected;
				ViewPager.Dispose();
				ViewPager = null;
			}
			if (adapter != null)
			{
				adapter.Dispose();
				adapter = null;
			}
			if (leftPageButton != null)
			{
				leftPageButton.ClearAnimation();
				leftPageButton.Click -= LeftPageButtonClicked;
				leftPageButton = iFit.Extensions.Android.JavaExtensions.DisposeSafe(leftPageButton);
			}
			if (rightPageButton != null)
			{
				rightPageButton.ClearAnimation();
				rightPageButton.Click -= RightPageButtonClicked;
				rightPageButton = iFit.Extensions.Android.JavaExtensions.DisposeSafe(rightPageButton);
			}
			InWorkoutHeaderPaginationView inWorkoutHeaderPaginationView = paginationView;
			paginationView = ((inWorkoutHeaderPaginationView != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(inWorkoutHeaderPaginationView) : null);
		}

		public override void OnResume()
		{
			base.OnResume();
			leftPageButton.Click -= LeftPageButtonClicked;
			leftPageButton.Click += LeftPageButtonClicked;
			rightPageButton.Click -= RightPageButtonClicked;
			rightPageButton.Click += RightPageButtonClicked;
		}

		public override void OnPause()
		{
			base.OnPause();
			leftPageButton.Click -= LeftPageButtonClicked;
			rightPageButton.Click -= RightPageButtonClicked;
		}

		private void LeftPageButtonClicked(object sender, EventArgs e)
		{
			if (ViewPager.CurrentItem > 0)
			{
				ScrollViewPager(-1);
			}
		}

		private void RightPageButtonClicked(object sender, EventArgs e)
		{
			if (ViewPager.CurrentItem < adapter.Count)
			{
				ScrollViewPager(1);
			}
		}

		private void ScrollViewPager(int offset)
		{
			paginationView.SelectedIndicator = ((offset > 0) ? InWorkoutHeaderPaginationView.Indicator.Right : InWorkoutHeaderPaginationView.Indicator.Left);
			int num = ViewPager.CurrentItem + offset;
			ViewPager.SetCurrentItem(num, smoothScroll: true);
			UpdateButtons(num);
		}

		private async void PageSelected(object sender, ViewPager.PageSelectedEventArgs e)
		{
			UpdateButtons(e.Position);
			_whenPageChanged.OnNext(CurrentPageType);
			await ChartFragmentSelected();
		}

		private async System.Threading.Tasks.Task ChartFragmentSelected()
		{
			if (adapter?.Fragments?.FirstOrDefault((MvxViewPagerFragmentAdapter.FragmentInfo f) => f.FragmentType == typeof(ChartsHeaderPageView))?.CachedFragment is ChartsHeaderPageView chartFragment)
			{
				if (CurrentPageType == InWorkoutHeaderHudType.Charts)
				{
					await chartFragment.InflateView();
				}
				UpdateChartFragmentInvalidation(chartFragment);
			}
		}

		private void UpdateChartFragmentInvalidation(ChartsHeaderPageView chartFragment)
		{
			chartFragment.ShouldBeInvalidatingChart = CurrentPageType == InWorkoutHeaderHudType.Charts;
			if (chartFragment.ShouldBeInvalidatingChart)
			{
				chartFragment.ForceUpdateChart();
			}
		}

		private void UpdateButtons(int pageIndex)
		{
			if (base.ViewModel.IsInStrengthWorkout)
			{
				EnableDisableViewAnimated(leftPageButton, enabled: false);
				EnableDisableViewAnimated(rightPageButton, enabled: false);
				return;
			}
			if (pageIndex == 0)
			{
				EnableDisableViewAnimated(leftPageButton, enabled: false);
				EnableDisableViewAnimated(rightPageButton, enabled: true, chartsButton);
			}
			if (pageIndex == 1)
			{
				EnableDisableViewAnimated(leftPageButton, enabled: true, statsButton);
				EnableDisableViewAnimated(rightPageButton, enabled: false);
			}
		}

		private void EnableDisableViewAnimated(ImageButton button, bool enabled, int resource = 0)
		{
			AndroidRunnable runnable = new AndroidRunnable(delegate
			{
				if (resource == -1)
				{
					button.SetImageResource(2131100437);
				}
				else if (resource != 0)
				{
					button.SetImageResource(resource);
				}
				if (enabled)
				{
					button.Visibility = ViewStates.Visible;
				}
			});
			AndroidRunnable runnable2 = new AndroidRunnable(delegate
			{
				try
				{
					if (!enabled && !base.IsCleanedUp && button != null)
					{
						button.Visibility = ViewStates.Invisible;
					}
				}
				catch (ObjectDisposedException)
				{
				}
			});
			button?.Animate().Alpha(enabled ? 1f : 0f).WithStartAction(runnable)
				.WithEndAction(runnable2)
				.SetDuration(100L)
				.Start();
		}

		private MvxViewPagerFragmentAdapter.FragmentInfo CreatePage(InWorkoutHeaderHudType headerPageType)
		{
			InWorkoutHeaderPageViewMapper singleton = Mvx.GetSingleton<InWorkoutHeaderPageViewMapper>();
			Type viewModelForType = singleton.GetViewModelForType(headerPageType);
			string text = viewModelForType.Name.Replace("Model", string.Empty);
			Type type = Type.GetType("Wolf.Android.Views.InWorkout.Header.Pages." + text);
			return new MvxViewPagerFragmentAdapter.FragmentInfo(type, viewModelForType);
		}
	}
