		private void SeekBar_ProgressChanged(object sender, SeekBar.ProgressChangedEventArgs e)
		{
			int num = e.Progress;
			if (base.ViewModel.IsAndroidBuiltIn())
			{
				num = SystemVolumeHelper.MapVolume((float)num / 100f);
				systemVolumeSeekBar.SeekBar.SetProgress(num, animate: false);
			}
			base.ViewModel.SystemVolumeFromSlider.Value = (float)num / 100f;
		}

		protected override void CleanUp()
		{
			isDisposed = true;
			if (systemVolumeSeekBar?.SeekBar != null)
			{
				systemVolumeSeekBar.SeekBar.StartTrackingTouch -= SystemVolumeSeekBarOnStartTrackingTouch;
				systemVolumeSeekBar.SeekBar.StopTrackingTouch -= SystemVolumeSeekBarOnStopTrackingTouch;
				systemVolumeSeekBar.SeekBar.ProgressChanged -= SeekBar_ProgressChanged;
				SeekBar seekBar = systemVolumeSeekBar.SeekBar;
				if (seekBar != null)
				{
					iFit.Extensions.Android.JavaExtensions.DisposeSafe(seekBar);
				}
				systemVolumeSeekBar = null;
			}
			if (musicSeekBar?.SeekBar != null)
			{
				musicSeekBar.SeekBar.StartTrackingTouch -= MusicVolumeSeekBarOnStartTrackingTouch;
				musicSeekBar.SeekBar.StopTrackingTouch -= MusicVolumeSeekBarOnStopTrackingTouch;
				SeekBar seekBar2 = musicSeekBar.SeekBar;
				if (seekBar2 != null)
				{
					iFit.Extensions.Android.JavaExtensions.DisposeSafe(seekBar2);
				}
				musicSeekBar = null;
			}
			if (trainerSeekBar?.SeekBar != null)
			{
				trainerSeekBar.SeekBar.StartTrackingTouch -= TrainerVolumeSeekBarOnStartTrackingTouch;
				trainerSeekBar.SeekBar.StopTrackingTouch -= TrainerVolumeSeekBarOnStopTrackingTouch;
				SeekBar seekBar3 = trainerSeekBar.SeekBar;
				if (seekBar3 != null)
				{
					iFit.Extensions.Android.JavaExtensions.DisposeSafe(seekBar3);
				}
				trainerSeekBar = null;
			}
			StaticFeedFmWidget obj = staticFeedFmWidget;
			staticFeedFmWidget = ((obj != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(obj) : null);
			Button button = headphonesButton;
			if (button != null)
			{
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(button);
