			if (_animateVisibility != null)
			{
				_animateVisibility.Requested -= OnVisibilityAnimationRequested;
			}
		}

		private async System.Threading.Tasks.Task UpdateCurrentAudioTrackAnimated()
		{
			_ = 1;
			try
			{
				if (isDisposed || staticFeedFmWidget == null)
				{
					return;
				}
				if (hasStaticWidgetDisplayed)
				{
					InWorkoutMusicControlsViewModel viewModel = base.ViewModel;
					if (viewModel != null && viewModel.FeedFmMusicState?.Value == MusicState.Playing)
					{
						ObjectAnimator animator = ObjectAnimator.OfFloat(staticFeedFmWidget, "alpha", 1f, 0f);
						ObjectAnimator fadeIn = ObjectAnimator.OfFloat(staticFeedFmWidget, "alpha", 0f, 1f);
						await animator.StartWithDisposal();
						if (staticFeedFmWidget != null && !isDisposed)
						{
							staticFeedFmWidget.SetTrackInfo(currentAudioTrack);
							await fadeIn.StartWithDisposal();
						}
						return;
					}
				}
				InWorkoutMusicControlsViewModel viewModel2 = base.ViewModel;
				if (viewModel2 != null && viewModel2.FeedFmMusicState?.Value == MusicState.Unavailable)
				{
					staticFeedFmWidget.CurrentState = MusicState.Unavailable;
					return;
				}
				staticFeedFmWidget.SetTrackInfo(currentAudioTrack);
				hasStaticWidgetDisplayed |= currentAudioTrack != null;
			}
			catch (System.Exception ex)
			{
				iFit.Logger.Log.Error("Audio", ex.GetType().Name + " occurred in UpdateCurrentAudioTrackAnimated.", ex);
			}
		}

		private void MusicVolumeSeekBarOnStopTrackingTouch(object sender, SeekBar.StopTrackingTouchEventArgs e)
		{
			base.ViewModel?.MusicVolumeReleased();
		}

		private void MusicVolumeSeekBarOnStartTrackingTouch(object sender, SeekBar.StartTrackingTouchEventArgs e)
		{
			base.ViewModel?.MusicVolumeTouched();
		}

		private void TrainerVolumeSeekBarOnStopTrackingTouch(object sender, SeekBar.StopTrackingTouchEventArgs e)
		{
			base.ViewModel?.TrainerVolumeReleased();
