			{
				if (value == null)
				{
					_pages.Clear();
				}
				else
				{
					if (_pages != null && value.SequenceEqual(_pages))
					{
						return;
					}
					if (!value.First().Equals(typeof(InWorkoutStreamingVideoViewModel)))
					{
						_pages = value.ToList();
					}
					else
					{
						_pages?.Clear();
					}
				}
				RecreatePages();
			}
		}

