		public AudioTrack CurrentAudioTrack
		{
			get
			{
				return currentAudioTrack;
			}
			set
			{
				if (currentAudioTrack == value)
				{
					return;
				}
				currentAudioTrack = value;
				if (!feedFmWidgetSetupCompleted && currentAudioTrack != null)
				{
					SetupFeedFmStaticWidgetTouchEvents();
				}
				((Activity)(object)this).RunOnUiThread((System.Action)delegate
				{
					if (feedFmNotification != null)
					{
						if (currentAudioTrack == null)
						{
							feedFmNotification.Visibility = ViewStates.Gone;
							AdjustSlidersForSevenInch(feedFmShowing: false, leftSlider);
							AdjustSlidersForSevenInch(feedFmShowing: false, rightSlider);
						}
						else
						{
							pauseFeedFmWidget?.SetTrackInfo(currentAudioTrack);
							musicService?.DismissFeedFmNotification();
							HandleAudioTrackChange();
						}
					}
				});
			}
		}

		public MusicState FeedMusicState
		{
			get
			{
				return feedMusicState;
			}
			set
			{
				if (feedMusicState == value)
				{
					return;
				}
				feedMusicState = value;
				switch (feedMusicState)
				{
				case MusicState.Playing:
					HandleAudioTrackChange();
					break;
				case MusicState.PausedManually:
				case MusicState.PausedForMusicRegion:
				case MusicState.PausedDisabled:
					musicService?.DismissFeedFmNotification();
					break;
				case MusicState.Unavailable:
					musicService?.DismissFeedFmNotification();
					((Activity)(object)this).RunOnUiThread((System.Action)delegate
					{
						Toast.MakeText((Context)(object)this, Wolf.Core.Resources.AppStrings.feed_fm_temp_unavailable, ToastLength.Long)?.Show();
					});
					pauseFeedFmWidget.CurrentState = MusicState.Unavailable;
					break;
				}
				if (pauseResumeScreen != null)
				{
					ResetPauseOverlayTimer();
					((Activity)(object)this).RunOnUiThread((System.Action)UpdateFeedMusicStateUi);
				}
			}
		}

