		public bool ResumeQuitScreenShown
		{
			get
			{
				return _resumeQuitScreenShown;
			}
			set
			{
				if (value == _resumeQuitScreenShown)
				{
					return;
				}
				iFit.Logger.Log.Trace("Workout", string.Format("Setting {0} to {1}.", "ResumeQuitScreenShown", value));
				_resumeQuitScreenShown = value;
				if (pauseResumeScreen == null)
				{
					InflatePauseResumeScreen();
				}
				SafeRunOnUiThread(delegate
				{
					pauseResumeScreen.Visibility = ((!_resumeQuitScreenShown) ? ViewStates.Gone : ViewStates.Visible);
					pauseContainer.Visibility = (_resumeQuitScreenShown ? ViewStates.Gone : ViewStates.Visible);
					if (_resumeQuitScreenShown && PauseScreenShown)
					{
						_pauseScreenShown = false;
						overlayNotifier?.SetIsShowing(Wolf.Core.Util.OverlayType.Pause, isShowing: false);
					}
					resumeQuitButtonsContainer.Visibility = ((!_resumeQuitScreenShown) ? ViewStates.Gone : ViewStates.Visible);
					if (!_resumeQuitScreenShown && !_pauseScreenShown)
					{
						feedFmNotification.Visibility = ViewStates.Visible;
						ShowElementsForOverlay(OverlayType.Pause);
					}
				});
			}
		}

		public bool PauseScreenShown
		{
			get
			{
				return _pauseScreenShown;
			}
			set
			{
				if (value == _pauseScreenShown)
				{
					return;
				}
				ToggleHudSwiping(value);
				iFit.Logger.Log.Trace("Workout", string.Format("Setting {0} to {1}.", "PauseScreenShown", value));
				_pauseScreenShown = value;
				base.ViewModel.UpdateActivePulseToggleVisibility();
				base.ViewModel.UpdateSmartAdjustToggleVisibility();
				if (pauseResumeScreen == null)
				{
					InflatePauseResumeScreen();
				}
				if (overlayNotifier == null)
				{
					Mvx.TryResolve<IOverlayNotifier>(out overlayNotifier);
				}
				overlayNotifier?.SetIsShowing(Wolf.Core.Util.OverlayType.Pause, value);
				try
				{
					SafeRunOnUiThread(delegate
					{
						pauseResumeScreen.Visibility = ((!_pauseScreenShown) ? ViewStates.Gone : ViewStates.Visible);
						pauseContainer.Visibility = ((!_pauseScreenShown) ? ViewStates.Gone : ViewStates.Visible);
						resumeQuitButtonsContainer.Visibility = (_pauseScreenShown ? ViewStates.Gone : ViewStates.Visible);
						feedFmNotification.Visibility = (_pauseScreenShown ? ViewStates.Gone : ViewStates.Visible);
						if (_pauseScreenShown)
						{
							ResetPauseOverlayTimer();
							HideElementsForOverlay(OverlayType.Pause);
							UpdatePauseOverlayVolumeSlider();
							pauseFeedFmWidget?.ResetAnimation();
						}
						else
						{
							if (!base.ViewModel.VolumeScreenCurrentlyUp)
							{
								ShowElementsForOverlay(OverlayType.Pause);
							}
							base.ViewModel?.CommitVolumeChange?.Execute(null);
						}
					});
				}
				catch (ObjectDisposedException)
				{
				}
			}
		}

