				return musicOverlayShowing;
			}
			set
			{
				bool flag = entireHeaderView.Visibility == ViewStates.Visible;
				if (value == musicOverlayShowing)
				{
					if (!flag && !value)
					{
						ShowElementsForOverlay(OverlayType.Music);
					}
					return;
				}
				musicOverlayShowing = value;
				if (value)
				{
					HideElementsForOverlay(OverlayType.Music);
				}
				else
				{
					ShowElementsForOverlay(OverlayType.Music);
				}
			}
		}

