				((Activity)(object)this).RunOnUiThread((System.Action)async delegate
				{
					followWorkoutAnimCts?.Cancel();
					followWorkoutAnimCts = new CancellationTokenSource();
					try
					{
						await AnimateFollowWorkoutButton(value, followWorkoutAnimCts.Token);
						_followWorkoutButtonVisible = value;
						followWorkoutAnimCts = null;
					}
					catch (System.OperationCanceledException)
					{
					}
					catch (NullReferenceException exception)
					{
						if (!isDisposed)
						{
							iFit.Logger.Log.Fatal("Workout", "Caught NRE in AnimateFollowWorkoutButton, and InWorkoutView has not been disposed yet", exception);
						}
					}
				});
			}
		}

