		private void UpdateFeedMusicStateUi()
		{
			if (isDisposed || pauseFeedFmWidget == null)
			{
				return;
			}
			try
			{
				ViewStates visibility = ViewStates.Gone;
				switch (musicService.LiveWorkoutMusicState)
				{
				case LiveWorkoutMusicState.TssStartingSoon:
				case LiveWorkoutMusicState.StationChangerStartingSoon:
					visibility = ViewStates.Invisible;
					break;
				case LiveWorkoutMusicState.Other:
					switch (feedMusicState)
					{
					case MusicState.PausedManually:
					case MusicState.PausedForMusicRegion:
					case MusicState.PausedDisabled:
					case MusicState.Playing:
						visibility = ViewStates.Visible;
						break;
					case MusicState.Loading:
					case MusicState.Unavailable:
					case MusicState.Off:
						visibility = ViewStates.Invisible;
						break;
					default:
						throw new ArgumentOutOfRangeException();
					}
					break;
				}
				pauseFeedFmWidget.Visibility = visibility;
			}
			catch (Java.Lang.Exception ex)
			{
				iFit.Logger.Log.Error("Audio", ex.GetType().Name + " occurred in UpdateFeedMusicStateUi.", ex);
			}
		}

		private void AdjustSlidersForSevenInch(bool feedFmShowing, WorkoutSliderView slider)
		{
			if (slider != null)
			{
				int num = (feedFmShowing ? ((Context)(object)this).Resources.GetDimensionPixelSize(2131168181) : ((Context)(object)this).Resources.GetDimensionPixelSize(2131168126));
				ViewGroup.MarginLayoutParams marginLayoutParams = (ViewGroup.MarginLayoutParams)slider.LayoutParameters;
				if (marginLayoutParams.BottomMargin != num)
				{
					marginLayoutParams.BottomMargin = num;
					slider.LayoutParameters = marginLayoutParams;
					slider.RequestLayout();
				}
			}
		}

