		private void HideElementsForOverlay(OverlayType overlayType)
		{
			GetElementsToHideWithOverlay(overlayType)?.DoForEach(delegate(View v)
			{
				if (v != null && v.Alpha > 0f)
				{
					v.Alpha = 0f;
				}
			});
		}

		private void ShowElementsForOverlay(OverlayType overlayType)
		{
			if (_resumeQuitScreenShown || _pauseScreenShown)
			{
				return;
			}
			if (overlayType == OverlayType.Pause && hudIsDown)
			{
				GetElementsToShowOnHud()?.DoForEach(delegate(View v)
				{
					if (v != null)
					{
						v.Alpha = 1f;
					}
				});
				return;
			}
			GetElementsToHideWithOverlay(overlayType)?.DoForEach(delegate(View v)
			{
				if (v != null)
				{
					float alpha = ((v == leftSlider || v == rightSlider) ? 0.8f : 1f);
					v.Alpha = alpha;
				}
			});
		}

		private IReadOnlyList<View> GetElementsToHideWithOverlay(OverlayType overlayType)
		{
			List<View> list = new List<View>
			{
				leaderBoardContainer,
				leftSlider,
				rightSlider,
				constantWattsContainer,
				followWorkoutButtonContainer,
				entireHeaderView,
				fabContainer,
				hrTargetContainer,
				closedCaptionsContainer,
				coachingNotificationPresenter?.NotificationView?.View
			};
			if (overlayType == OverlayType.Pause || overlayType == OverlayType.Music)
			{
				list.Add(feedFmNotification);
			}
			if (HRBadgeState != HRBadgeState.None)
			{
				list.Add(widgetBadge);
			}
			if ((fragmentInfos?.Count ?? 0) > 0)
			{
				BaseClickableFragment baseClickableFragment = fragmentInfos?[0]?.CachedFragment as BaseClickableFragment;
				if (baseClickableFragment is IInWorkoutPage inWorkoutPage)
				{
					inWorkoutPage?.ElementsHiddenFromPauseOverlay?.DoForEach(delegate(View v)
					{
						if (v != null)
						{
							list.Add(v);
						}
					});
				}
			}
			return list.AsReadOnly();
		}

		private IReadOnlyList<View> GetElementsToShowOnHud()
		{
			List<View> list = new List<View> { feedFmNotification };
			return list.AsReadOnly();
		}

		private void ToggleFragmentsFullScreen(bool on)
		{
			if ((fragmentInfos?.Count ?? 0) > 0)
			{
				activeFragment = fragmentInfos?[0]?.CachedFragment as BaseClickableFragment;
			}
			if (activeFragment != null)
			{
				(activeFragment as IInWorkoutPage)?.ToggleFullscreenMode(on);
			}
			else
			{
				iFit.Logger.Log.Error("Workout", "Unknown InWorkoutPageView");
			}
			(videoFragment as IInWorkoutPage)?.ToggleFullscreenMode(on);
			closedCaptionsView?.ConfigureFullScreenState(on);
		}

		private void UpdateHRBadge()
		{
			float newAlphaValue = 0f;
			bool flag = false;
			if ((IsHRWidgetVisible && HRBadgeState == HRBadgeState.ActivePulseOn) || HRBadgeState.AlwaysHidden())
			{
				flag = true;
			}
			else if ((!IsHRWidgetVisible && !HRBadgeState.AlwaysHidden()) || (IsHRWidgetVisible && HRBadgeState.AlwaysShown()))
			{
				newAlphaValue = 1f;
				flag = true;
			}
			widgetBadge.Invalidate();
			if (!flag)
			{
				return;
			}
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				try
				{
					animationActivePulseBadCts?.Cancel();
				}
				catch (System.OperationCanceledException)
				{
				}
				animationActivePulseBadCts = new CancellationTokenSource();
				widgetBadge.Animate().SetDuration(200L).Alpha(newAlphaValue)
					.SetInterpolator(new AccelerateDecelerateInterpolator())
					.StartWithDisposal(animationActivePulseBadCts.Token);
			});
		}

		protected override void SetupView()
		{
			base.SetupView();
			oldConfig = ((Context)(object)this).Resources?.Configuration?.ToString() ?? "null";
			widgetManager = base.ViewModel?.widgetManager;
			bindingSet = this.CreateBindingSet<InWorkoutView, InWorkoutViewModel>();
			SetupHeader();
			SetupAndBindPauseResumeExit();
			SetupFeedFM();
			SetupDebugActivePulseViewVisible();
			BindErrorMessages();
			SetupAndBindWorkoutButtons();
			SetupAndBindPagingAndPopups();
			SetupAndBindWidgetSwiping();
			SetupUploadingLogsStub();
			bindingSet.Bind(this).For((InWorkoutView v) => v.ShouldCleanupLeaderboard).To((InWorkoutViewModel vm) => vm.CooldownEntered)
				.OneWay();
			bindingSet.Bind(this).For((InWorkoutView v) => v.IsInFullscreenMode).To((InWorkoutViewModel vm) => vm.widgetManager.IsFullScreen)
				.OneWay();
			bindingSet.Bind(this).For((InWorkoutView v) => v.ActiveHRwidget).To((InWorkoutViewModel vm) => vm.ActiveHRwidget)
				.OneWay();
			bindingSet.Bind(this).For((InWorkoutView x) => x.IsFabVisible).To((InWorkoutViewModel vm) => vm.FabButtonVisible)
				.OneWay();
			bindingSet.Bind(this).For((InWorkoutView v) => v.PauseScreenShown).To((InWorkoutViewModel vm) => vm.PauseScreenShown)
				.TwoWay();
			bindingSet.Bind(this).For((InWorkoutView v) => v.MusicOverlayShowing).To((InWorkoutViewModel vm) => vm.MusicOverlayShowing)
				.OneWay();
			bindingSet.Bind(this).For((InWorkoutView x) => x.HeaderViewContainerVisible).To((InWorkoutViewModel vm) => vm.HeaderViewContainerVisible)
				.OneWay();
			System.Threading.Tasks.Task.Run(delegate
			{
				bindingSet.Apply();
			});
			InWorkoutViewModel viewModel = base.ViewModel;
			if (viewModel != null && viewModel.IsVideoWorkout)
			{
				InWorkoutViewModel viewModel2 = base.ViewModel;
				if (viewModel2 == null || viewModel2.WorkoutMode.Value != ConsoleState.CoolDown)
				{
					CreateTargetFragment(typeof(InWorkoutStreamingVideoView).FullName, typeof(InWorkoutStreamingVideoViewModel).FullName, ((object)this).GetType().FullName, CreateParametersBundleFromIntent());
				}
			}
			InWorkoutViewModel viewModel3 = base.ViewModel;
			if (viewModel3 != null && viewModel3.UseVideoBackgroundService)
			{
				iFit.Logger.Log.Trace("Video", "Setting up WolfBackgroundVideoService");
				StartVideoBackgroundService();
				videoCleanupSub?.Dispose();
				videoCleanupSub = base.ViewModel?.WhenVideoServiceCleaned?.Subscribe(StopVideoBackgroundService);
			}
			else
			{
				iFit.Logger.Log.Trace("Video", "Not setting up WolfBackgroundVideoService");
			}
			SetupNotificationPresenter();
			InWorkoutViewModel viewModel4 = base.ViewModel;
			if (viewModel4 != null && viewModel4.InRetailDemo && pauseResumeScreen == null)
			{
				InflatePauseResumeScreen();
			}
			inWorkoutRoot = ((Activity)(object)this).FindViewById<ConstraintLayout>(2131428307);
			System.Threading.Tasks.Task.Run((System.Action)ScheduleLazyViewInflation);
		}

		private void ScheduleLazyViewInflation()
		{
			lazyViewInflationQueue.Enqueue(SetupLeftWidgets);
			lazyViewInflationQueue.Enqueue(SetupRightWidgets);
			lazyViewInflationQueue.Enqueue(SetupSliders);
			lazyViewInflationQueue.Enqueue(SetupAndBindConstantWatts);
			lazyViewInflationQueue.Enqueue(SetupMockHRUI);
			lazyViewInflationQueue.Enqueue(SetupClosedCaptions);
			inWorkoutRoot?.ViewTreeObserver?.AddOnGlobalLayoutListener(this);
		}

		public void OnGlobalLayout()
		{
			inWorkoutRoot?.ViewTreeObserver?.RemoveOnGlobalLayoutListener(this);
			if (lazyViewInflationQueue.Count != 0)
			{
				System.Action action = lazyViewInflationQueue.Dequeue();
				if (action != null)
				{
					action();
					inWorkoutRoot?.ViewTreeObserver?.AddOnGlobalLayoutListener(this);
				}
			}
		}

