		private void InflateAndBindUploadingLogs()
		{
			if (uploadingLoadingAnimation == null)
			{
				uploadingLogContainer = (FrameLayout)uploadingLogContainerStub.Inflate();
				uploadingText = uploadingLogContainer.FindViewById<IfitTextView>(2131427534);
				uploadingText.Text = base.ViewModel.UploadingLogsText;
				backgroundImageView = uploadingLogContainer.FindViewById<ImageView>(2131428886);
				if (Mvx.TryResolve<IBackgroundImageUtil>(out var service))
				{
					int[] preparingWorkoutImages = service.GetPreparingWorkoutImages();
					int imageResource = preparingWorkoutImages[new Random().Next(preparingWorkoutImages.Length)];
					backgroundImageView.SetImageResource(imageResource);
				}
				bindingSet = this.CreateBindingSet<InWorkoutView, InWorkoutViewModel>();
				bindingSet.Bind(uploadingLogContainer).For((FrameLayout x) => x.Visibility).To((InWorkoutViewModel vm) => vm.UploadingLogsAndCleaningWorkout)
					.WithConversion("Visibility")
					.OneWay();
				uploadingLoadingAnimation = uploadingLogContainer.FindViewById<CircularLoadingView>(2131429709);
				bindingSet.Bind(uploadingLoadingAnimation).For((CircularLoadingView x) => x.Visibility).To((InWorkoutViewModel vm) => vm.UploadingLogsAndCleaningWorkout)
					.WithConversion("Visibility")
					.OneWay();
				bindingSet.Apply();
				if (feedFmNotification != null)
				{
					feedFmNotification.Visibility = ViewStates.Gone;
				}
			}
		}

		private void StartVideoBackgroundService()
		{
			Intent intent = new Intent(((Context)(object)this).ApplicationContext, typeof(WolfBackgroundVideoService));
			intent.SetAction("Wolf.VideoPlayback.Start");
			platformServiceComponentName = ((Context)(object)this).StartService(intent);
		}

		private void StopVideoBackgroundService(bool _)
		{
			try
			{
				if (videoCleanupSub != null && !(platformServiceComponentName.Handle == IntPtr.Zero) && ((Context)(object)this).ApplicationContext != null)
				{
					videoCleanupSub?.Dispose();
					videoCleanupSub = null;
					Intent intent = new Intent(((Context)(object)this).ApplicationContext, typeof(WolfBackgroundVideoService));
					intent.SetAction("Wolf.VideoPlayback.Stop");
					((Context)(object)this).StopService(intent);
				}
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("Workout", "InWorkoutView couldn't stop Android Service", exception);
			}
		}

		protected override void OnResume()
		{
			if (forceRecreate)
			{
				forceRecreate = false;
				RecreatePages();
