			base.OnResume();
			base.ViewModel.UploadingLogsAndCleaningWorkout.Changed -= OnUploadingLogsAndCleaningWorkoutChanged;
			base.ViewModel.UploadingLogsAndCleaningWorkout.Changed += OnUploadingLogsAndCleaningWorkoutChanged;
			OnUploadingLogsAndCleaningWorkoutChanged(base.ViewModel.UploadingLogsAndCleaningWorkout, EventArgs.Empty);
			base.ViewModel.Reconnecting.Changed -= OnReconnectingChanged;
			base.ViewModel.Reconnecting.Changed += OnReconnectingChanged;
			RepositionRightWidgetsOnResume();
		}

