		private void RepositionRightWidgetsOnResume()
		{
			if (leaderboardWidgetAnimator != null && rightSliderAnimator != null)
			{
				IWorkoutSettings service;
				if (pauseOverlayLeftNavItem != null && !widgetManager.WorkoutControlsVisible.Value)
				{
					bool flag = widgetManager.LastVisibleRightWidgetBeforeEnteringFullscreen.Value == WidgetType.Leaderboard;
					leaderboardWidgetAnimator?.MoveTo(flag ? WidgetState.OffDuringFullScreen : WidgetState.Off);
					rightSliderAnimator?.MoveTo(flag ? WidgetState.Off : WidgetState.OffDuringFullScreen);
				}
				else if (Mvx.TryResolve<IWorkoutSettings>(out service))
				{
					bool flag2 = service.PreferredRightWorkoutWidget == WidgetType.Leaderboard;
					leaderboardWidgetAnimator?.MoveTo(flag2 ? WidgetState.On : WidgetState.Off);
					rightSliderAnimator?.MoveTo((!flag2) ? WidgetState.On : WidgetState.Off);
				}
			}
		}

