		private void CreateLeaderboardWebview()
		{
			if (leaderBoardContainer == null)
			{
				return;
			}
			UnloadLeaderboard();
			iFit.Logger.Log.Info("Workout", "Creating Leaderboard webview");
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (leaderboardAnalytics == null)
				{
					leaderboardAnalytics = Mvx.Create<ILeaderboardAnalyticTracker>();
				}
				leaderboardWebViewDelegate?.Dispose();
				leaderboardWebViewDelegate = Mvx.IocConstruct<LeaderboardWebViewDelegate>();
				leaderboardWebViewDelegate.Init(widgetManager, base.ViewModel.WorkoutID, base.ViewModel.IsLiveWorkout, base.ViewModel.OnWebViewRenderProcessGone, () => IsInFullscreenMode, () => base.ViewModel.WorkoutMode.Value, leaderboardAnalytics);
				webviewHolder = (Mvx.Resolve<IWebviewHolderFactory>() as WebviewHolderFactory).FetchOrCreateWebviewHolderByUrl(leaderboardWebViewDelegate.WebviewUrl, new WebviewHolderCreationOptions
				{
					ShouldCacheWebPages = true,
					EnableChromeDebugging = (Mvx.Resolve<ILocalSettings>().InDebugMode || Mvx.Resolve<IWebviewSettings>().IsWebviewVerboseMode),
					LogTag = "leaderboardWebView"
				});
				webviewHolder.WebviewFinishedNavigating += leaderboardWebViewDelegate.OnWebviewFinishedNavigating;
				webviewHolder.WebviewFinishedNavigating += ClearLeaderboardBackground;
				webviewHolder.WebviewErrorLoading += leaderboardWebViewDelegate.OnWebViewErrorLoading;
				leaderboardWebView = webviewHolder.WebView as ShireWebView;
				leaderboardWebViewDelegate.GetViewUrl = () => leaderboardWebView?.Url;
				leaderboardWebViewDelegate.RetryLoadWebView = delegate
				{
					((Activity)(object)this).RunOnUiThread((System.Action)delegate
					{
						webviewHolder.WebviewFinishedNavigating -= leaderboardWebViewDelegate.OnWebviewFinishedNavigating;
						webviewHolder.WebviewFinishedNavigating -= ClearLeaderboardBackground;
						webviewHolder.WebviewErrorLoading -= leaderboardWebViewDelegate.OnWebViewErrorLoading;
						leaderBoardContainer?.RemoveView(leaderboardWebView);
						(Mvx.Resolve<IWebviewHolderFactory>() as WebviewHolderFactory).WebviewHolderStore.FlushByKey(webviewHolder.Key);
						webviewHolder = null;
						leaderboardWebView?.Dispose();
						leaderboardWebView = null;
						CreateLeaderboard(createWebView: true);
					});
				};
				leaderboardWebView.HideLoadingViewWhenWebViewIsReady = false;
				leaderboardWebView.EnableChromeDebugging(leaderboardWebViewDelegate.EnableChromeDebugging);
				leaderboardWebViewDelegate.BuildBridge(webviewHolder.WebView.Bridge);
				leaderboardWebView.SetBackgroundColor(new global::Android.Graphics.Color(ContextCompat.GetColor(((Context)(object)this).ApplicationContext, 2131100088)));
				leaderBoardContainer?.SetBackgroundColor(global::Android.Graphics.Color.Transparent);
				leaderboardWebView.VerticalScrollBarEnabled = false;
				leaderboardWebView.HorizontalScrollBarEnabled = false;
				leaderboardLayoutParams = new FrameLayout.LayoutParams(-1, -1);
				leaderBoardContainer?.AddView(leaderboardWebView, leaderboardLayoutParams);
			});
		}

		private void ClearLeaderboardBackground(object sender, EventArgs e)
		{
			leaderboardWebView.SetBackgroundColor(global::Android.Graphics.Color.Argb(1, 0, 0, 0));
		}

		private void DestroyLeaderboard()
		{
			UnloadLeaderboard();
			if (leaderBoardContainer != null)
			{
				iFit.Logger.Log.Info("Workout", "Destroying Leaderboard container");
				leaderBoardContainer.Dispose();
				leaderBoardContainer = null;
			}
		}

		private void UnloadLeaderboard()
		{
			if (leaderboardWebView != null)
			{
				webviewHolder.WebviewFinishedNavigating -= leaderboardWebViewDelegate.OnWebviewFinishedNavigating;
				webviewHolder.WebviewFinishedNavigating -= ClearLeaderboardBackground;
				webviewHolder.WebviewErrorLoading -= leaderboardWebViewDelegate.OnWebViewErrorLoading;
				iFit.Logger.Log.Info("Workout", "Unloading Leaderboard webview");
				leaderboardLayoutParams?.Dispose();
				leaderboardLayoutParams = null;
				leaderBoardContainer?.RemoveView(leaderboardWebView);
				(Mvx.Resolve<IWebviewHolderFactory>() as WebviewHolderFactory).WebviewHolderStore.FlushByKey(webviewHolder.Key);
				webviewHolder = null;
				leaderboardWebView.Dispose();
				leaderboardWebView = null;
			}
		}

