		private void SetupHudPages()
		{
			viewPagerReadySub?.Dispose();
			if (HudFragments != null || _hudScreenTypes == null)
			{
				return;
			}
			HudFragments = new List<IHudView>();
			if (headerView != null)
			{
				base.ViewModel.HudScreenType.Value = headerView.CurrentPageType;
			}
			try
			{
				foreach (InWorkoutHeaderHudType hudScreenType in _hudScreenTypes)
				{
					IHudView hudView = CreateHud(hudScreenType);
					HudFragments.Add(hudView);
					AddHudFragment(hudView as ShireFragment);
					if (hudView?.PageType == base.ViewModel.HudScreenType.Value)
					{
						HudView = hudView;
					}
				}
			}
			catch (IllegalStateException)
			{
				HudFragments = null;
				return;
			}
			headerPageChanged = headerView?.WhenViewPageChanged.Subscribe(delegate(InWorkoutHeaderHudType pageType)
			{
				base.ViewModel.HudScreenType.Value = pageType;
				SetCurrentHud(canBeVisible: false);
			});
		}

		private void SetCurrentHud(bool canBeVisible = true)
		{
			if (HudFragments == null)
			{
				return;
			}
			foreach (IHudView hudFragment in HudFragments)
			{
				bool flag = base.ViewModel.HudScreenType.Value == hudFragment.PageType;
				hudFragment.HudVisible = canBeVisible && flag;
				hudFragment.IsEnabled = flag;
				if (flag)
				{
					HudView = hudFragment;
				}
			}
		}

