				}
				InWorkoutViewModel viewModel2 = base.ViewModel;
				viewModel2.ConsoleStateChanged = (EventHandler<ConsoleStateEventArgs>)Delegate.Remove(viewModel2.ConsoleStateChanged, new EventHandler<ConsoleStateEventArgs>(InitializeLeaderboard));
				InWorkoutViewModel viewModel3 = base.ViewModel;
				viewModel3.ConsoleStateChanged = (EventHandler<ConsoleStateEventArgs>)Delegate.Combine(viewModel3.ConsoleStateChanged, new EventHandler<ConsoleStateEventArgs>(InitializeLeaderboard));
			}
		}

