		private void CreateNativeLeaderboard()
		{
			if (leaderboardWidgetAnimator == null && leaderBoardContainer != null)
			{
				if (leaderboardAnalytics == null)
				{
					leaderboardAnalytics = Mvx.Resolve<ILeaderboardAnalyticTracker>();
				}
				if (!leaderboardAnalytics.IsInitialized)
				{
					leaderboardAnalytics.Initialize();
				}
				((Activity)(object)this).RunOnUiThread((System.Action)delegate
				{
					ViewGroup.LayoutParams layoutParameters = leaderBoardContainer.LayoutParameters;
					layoutParameters.Width = ((Context)(object)this).Resources.GetDimensionPixelSize(2131166801);
					leaderBoardContainer.LayoutParameters = layoutParameters;
					leaderBoardContainer.TranslationX += leaderboardNativeTranslationX;
					leaderboardWidgetAnimator = new LeaderboardWidgetAnimator((Activity)(object)this, leaderBoardContainer, leaderboardNativeTranslationX, WidgetState.Off);
					leaderboardWidgetAnimator.Debug = "Leaderboard";
					leaderboardWidgetAnimator.Location = WidgetLocation.Right;
					widgetManager?.Add(WidgetType.Leaderboard, leaderboardWidgetAnimator);
					CreateTargetFragment(typeof(NativeLeaderboardView).FullName, typeof(NativeLeaderboardViewModel).FullName, ((object)this).GetType().FullName, CreateParametersBundleFromIntent());
				});
			}
		}

		private void CreateLeaderboard(bool createWebView)
		{
			InWorkoutViewModel viewModel = base.ViewModel;
			if (viewModel == null || !viewModel.LeaderboardExistsForWorkout || ShouldCleanupLeaderboard)
			{
				return;
			}
			if (!base.ViewModel.CompetitionsIsReady || leaderBoardContainer == null)
			{
				leaderBoardContainer?.PostDelayed(delegate
				{
					CreateLeaderboard(createWebView);
				}, 250L);
				return;
			}
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (leaderboardWidgetAnimator == null && leaderBoardContainer != null)
				{
					leaderBoardContainer.TranslationX += leaderboardTranslationX;
					leaderboardWidgetAnimator = new LeaderboardWidgetAnimator((Activity)(object)this, leaderBoardContainer, leaderboardTranslationX, WidgetState.Off);
					leaderboardWidgetAnimator.Debug = "Leaderboard";
					leaderboardWidgetAnimator.Location = WidgetLocation.Right;
					leaderboardWidgetAnimator.OnDestroyAction = DestroyLeaderboard;
					leaderboardWidgetAnimator.OnUnloadAction = UnloadLeaderboard;
					leaderboardWidgetAnimator.OnCreateAction = CreateLeaderboardWebview;
					leaderboardWidgetAnimator.CreateViewWhenOn = true;
					leaderboardWidgetAnimator.UnloadViewWhenOff = true;
					widgetManager?.Add(WidgetType.Leaderboard, leaderboardWidgetAnimator);
					if (leaderboardAnalytics == null)
					{
						leaderboardAnalytics = Mvx.Resolve<ILeaderboardAnalyticTracker>();
					}
					if (!leaderboardAnalytics.IsInitialized)
					{
						leaderboardAnalytics.Initialize();
					}
					if (createWebView)
