			pauseResumeScreen = pauseResumeScreenStub.Inflate();
			pauseContainer = pauseResumeScreen.FindViewById<ConstraintLayout>(2131428766);
			pauseOverlayLeftNavItem = pauseResumeScreen.FindViewById<InWorkoutNavigationItem>(2131428769);
			pauseButton = pauseResumeScreen.FindViewById<InWorkoutCircleActionButton>(2131428759);
			clubEndButton = pauseResumeScreen.FindViewById<InWorkoutCircleActionButton>(2131427689);
			pauseOverlayRightNavItem = pauseResumeScreen.FindViewById<InWorkoutNavigationItem>(2131428771);
			pauseOverlayFullScreenNavItem = pauseResumeScreen.FindViewById<InWorkoutNavigationItem>(2131428768);
			pauseOverlaySmartAdjustItem = pauseResumeScreen.FindViewById<InWorkoutNavigationItem>(2131428772);
			pauseOverlayCCNavItem = pauseResumeScreen.FindViewById<InWorkoutNavigationItem>(2131428767);
			goToCooldownButton = pauseResumeScreen.FindViewById<IfitTextView>(2131428139);
			goToLockScreenButton = pauseResumeScreen.FindViewById<MaterialButton>(2131428140);
			cooldownArrow = pauseResumeScreen.FindViewById<ImageView>(2131427741);
			resumeQuitButtonsContainer = pauseResumeScreen.FindViewById<ConstraintLayout>(2131428978);
			resumeMovementTextView = pauseResumeScreen.FindViewById<TextView>(2131428977);
			finishButton = pauseResumeScreen.FindViewById<InWorkoutCircleActionButton>(2131428778);
			resumeButton = pauseResumeScreen.FindViewById<InWorkoutCircleActionButton>(2131428779);
			resumeQuitWorkoutEndsInLabel = pauseResumeScreen.FindViewById<TextView>(2131428979);
			pauseTimeoutRemainingLabel = pauseResumeScreen.FindViewById<TextView>(2131428761);
			audioSettingsButton = pauseResumeScreen.FindViewById<MaterialButton>(2131428763);
			if (ShouldUseSmallerTabletLayout())
			{
				pauseFeedFmWidget = new PancakeFeedFmWidget(((Context)(object)this).ApplicationContext);
			}
			else
			{
				pauseFeedFmWidget = new StaticFeedFmWidget(((Context)(object)this).ApplicationContext);
			}
			pauseFeedFmWidget.SetBackgroundColor(global::Android.Graphics.Color.Transparent);
			pauseFeedFmWidget.Id = View.GenerateViewId();
			pauseFeedFmWidget.LayoutParameters = new ConstraintLayout.LayoutParams(0, -2);
			pauseFeedFmWidget.IsTrainerSelectStation = base.ViewModel.TrainerSelectStationEnabled.Value;
			volumeSeekBar = pauseResumeScreen.FindViewById<VolumeSeekBar>(2131428777);
			ConstraintLayout constraintLayout = pauseResumeScreen.FindViewById<ConstraintLayout>(2131428766);
			ConstraintSet constraintSet = new ConstraintSet();
			if (constraintLayout != null)
			{
				constraintLayout.AddView(pauseFeedFmWidget, 0);
				constraintSet.ConstrainDefaultWidth(pauseFeedFmWidget.Id, 0);
				constraintSet.Clone(constraintLayout);
				constraintSet.Clear(2131428777, 3);
				constraintSet.Connect(2131428777, 3, pauseFeedFmWidget.Id, 4, 0);
				constraintSet.Connect(pauseFeedFmWidget.Id, 3, constraintLayout.Id, 3, (int)((Context)(object)this).Resources.GetDimension(2131167871));
				constraintSet.Connect(pauseFeedFmWidget.Id, 6, volumeSeekBar.Id, 6, 0);
				constraintSet.Connect(pauseFeedFmWidget.Id, 7, volumeSeekBar.Id, 7, 0);
				constraintSet.Connect(volumeSeekBar.Id, 3, pauseFeedFmWidget.Id, 4, (int)((Context)(object)this).Resources.GetDimension(2131167036));
				constraintSet.ApplyTo(constraintLayout);
			}
			else
			{
				iFit.Logger.Log.Error("Audio", "constraintLayout was null in InWorkoutView.");
			}
			if (!musicService.IsUsingFeedFmAudioServiceForMusic)
			{
				pauseFeedFmWidget.Visibility = ViewStates.Invisible;
			}
			else if (currentAudioTrack != null)
			{
				pauseFeedFmWidget?.SetTrackInfo(currentAudioTrack);
				SetupFeedFmStaticWidgetTouchEvents();
				FeedMusicState = feedMusicState;
			}
			SetupAndBindPauseResumeItems();
			UpdateFeedMusicStateUi();
		}

