				bindingSet.Bind(pauseButton).For(pauseButton.ClickEvent()).To((InWorkoutViewModel vm) => vm.PauseButtonTapped);
			}
			resumeMovementTextView.Text = Wolf.Core.Resources.AppStrings.resume_movement_to_continue.ToUpper();
			resumeQuitWorkoutEndsInLabel.Text = Wolf.Core.Resources.AppStrings.workout_ends_in.Trim().ToUpper();
			InWorkoutViewModel viewModel2 = base.ViewModel;
			bool? obj;
			if (viewModel2 == null)
			{
				obj = null;
			}
			else
			{
				INC<bool> useResumablePauseScreen = viewModel2.UseResumablePauseScreen;
				obj = ((useResumablePauseScreen != null) ? new bool?(!useResumablePauseScreen.Value) : ((bool?)null));
			}
			bool? flag = obj;
			if (flag == true)
			{
				finishButton.ButtonColor = Colors.Named0069D2.ToNative();
				finishButton.IconTint = Colors.NamedFFFFFF.ToNative();
			}
			bindingSet.Apply();
		}

