		private void SetupAndBindPauseCaptions(MvxFluentBindingDescriptionSet<InWorkoutView, InWorkoutViewModel> pauseBindingSet)
		{
			VisibilityGoneValueConverter converter = new VisibilityGoneValueConverter();
			closedCaptionConstraintLayout = ((Activity)(object)this).FindViewById<ConstraintLayout>(2131427681);
			closedCaptionToggle = ((Activity)(object)this).FindViewById<SwitchCompat>(2131427684);
			closedCaptionsToggleText = ((Activity)(object)this).FindViewById<IfitTextView>(2131427609);
			closedCaptionToggle.Text = Wolf.Core.Resources.AppStrings.closed_captions.ToUpperInvariant();
			IDemoModeService service;
			bool flag = Mvx.TryResolve<IDemoModeService>(out service) && service.IsInDemoMode;
			if ((base.IsStrengthMirror && !base.UseHeadlessBikeTheme) || flag)
			{
				closedCaptionConstraintLayout.Visibility = ViewStates.Gone;
				closedCaptionToggle.Visibility = ViewStates.Gone;
				closedCaptionsToggleText.Visibility = ViewStates.Gone;
