			{
				closedCaptionConstraintLayout.Visibility = ViewStates.Gone;
				closedCaptionsToggleText.Visibility = ViewStates.Gone;
				pauseOverlayCCNavItem.NavigationLabelText = Wolf.Core.Resources.AppStrings.closed_captions.ToUpperInvariant();
				pauseOverlayCCNavItem.SetPrimaryTextColor(Colors.Shark80Alpha.ToNative());
				pauseOverlayCCNavItem.SetSecondaryTextColor(Colors.Shark80Alpha.ToNative());
				pauseOverlayCCNavItem.SetDisabledAlpha(0.5f);
				pauseBindingSet.Bind(pauseOverlayCCNavItem.NavigationButton).For(pauseOverlayCCNavItem.NavigationButton.ClickEvent()).To((InWorkoutViewModel vm) => vm.ToggleClosedCaptions);
				pauseBindingSet.Bind(pauseOverlayCCNavItem.NavigationButton).For((FabNavCircleButton x) => x.Selected).To((InWorkoutViewModel vm) => vm.IsClosedCaptionsVisible);
				pauseBindingSet.Bind(pauseOverlayCCNavItem).For((InWorkoutNavigationItem x) => x.Enabled).To((InWorkoutViewModel vm) => vm.ClosedCaptionsButtonEnabled);
				pauseBindingSet.Bind(pauseOverlayCCNavItem).For((InWorkoutNavigationItem x) => x.Visibility).To((InWorkoutViewModel vm) => vm.ClosedCaptionsButtonVisible)
					.WithConversion(converter);
				pauseBindingSet.Bind(pauseOverlayCCNavItem.NavigationSecondaryLabel).For((IfitTextView x) => x.Text).To((InWorkoutViewModel vm) => vm.CaptionsUnavailableInPreferredLanguageString);
				pauseBindingSet.Bind(pauseOverlayCCNavItem.NavigationSecondaryLabel).For((IfitTextView x) => x.Visibility).To((InWorkoutViewModel vm) => vm.ClosedCaptionsPreferredLanguageUnavailableVisible)
					.WithConversion(converter);
			}
			else
			{
				pauseOverlayCCNavItem.Visibility = ViewStates.Gone;
				pauseBindingSet.Bind(closedCaptionConstraintLayout).For((ConstraintLayout x) => x.Visibility).To((InWorkoutViewModel vm) => vm.ClosedCaptionsButtonVisible)
