		private void PauseVolumeSettings_Click(object sender, EventArgs e)
		{
			base.ViewModel?.DoShowMusicControls();
			pauseScreenTimer?.Stop();
			HidePauseWithDelay();
		}

		private async System.Threading.Tasks.Task HidePauseWithDelay()
		{
			await System.Threading.Tasks.Task.Delay(200).ConfigureAwait(continueOnCapturedContext: false);
			PauseScreenShown &= ResumeQuitScreenShown;
		}

		private void SetUpLeftPauseOverlayNavButton(VisibilityGoneValueConverter visibilityConverter)
		{
			if (base.IsStrengthMirror && !base.UseHeadlessBikeTheme)
			{
				pauseOverlayLeftNavItem.SetStateIcons(2131231236, 2131231236);
				pauseOverlayLeftNavItem.Selected = true;
				bindingSet.Bind(pauseOverlayLeftNavItem.NavigationButton).For(pauseOverlayLeftNavItem.NavigationButton.ClickEvent()).To((InWorkoutViewModel vm) => vm.ToggleClosedCaptions);
				bindingSet.Bind(pauseOverlayLeftNavItem.NavigationButton).For((FabNavCircleButton x) => x.Selected).To((InWorkoutViewModel vm) => vm.IsClosedCaptionsVisible);
				bindingSet.Bind(pauseOverlayLeftNavItem).For((InWorkoutNavigationItem x) => x.Enabled).To((InWorkoutViewModel vm) => vm.ClosedCaptionsButtonEnabled);
				pauseOverlayLeftNavItem.NavigationLabelText = Wolf.Core.Resources.AppStrings.closed_captions.ToUpper();
				bindingSet.Bind(this).For("ToggleLeftNavVisibilityAndConstraintsOnStrengthMirror").To((InWorkoutViewModel vm) => vm.ClosedCaptionsButtonVisible)
					.OneWay();
				return;
			}
			if (base.ViewModel.IsStrengthWorkout || base.UseHeadlessBikeTheme)
			{
				pauseOverlayLeftNavItem.Enabled = false;
			}
			else
			{
				bindingSet.Bind(pauseOverlayLeftNavItem.NavigationButton).For((FabNavCircleButton x) => x.Selected).To((InWorkoutViewModel x) => x.widgetManager.WorkoutControlsVisible);
				bindingSet.Bind(pauseOverlayLeftNavItem.NavigationButton).For((FabNavCircleButton x) => x.Enabled).To((InWorkoutViewModel x) => x.widgetManager.CanToggleWorkoutControls)
					.OneWay();
				pauseOverlayLeftNavItem.NavigationButton.Click += ToggleWorkoutControls;
			}
			bindingSet.Bind(pauseOverlayLeftNavItem).For((InWorkoutNavigationItem v) => v.Visibility).To((InWorkoutViewModel vm) => vm.ShowWorkoutSliderButton)
				.WithConversion(new VisibilityGoneValueConverter());
			pauseOverlayLeftNavItem.NavigationLabelText = Wolf.Core.Resources.AppStrings.controls.ToUpper();
		}

