		private void ContentClicked(object sender, EventArgs e)
		{
			bool flag = false;
			if (pauseResumeScreen != null)
			{
				flag = pauseResumeScreen.Visibility == ViewStates.Visible;
			}
			if (!ResumeQuitScreenShown && !flag)
			{
				if (base.ViewModel.NavContainerOpen.Value)
				{
					iFit.Logger.Log.Trace("Workout", "Hiding NavMenu from ViewPagerClicked");
					base.ViewModel.CloseNavMenu.Execute(null);
				}
				else
				{
					iFit.Logger.Log.Trace("Workout", "Showing PauseResumeScreen from ViewPagerClicked");
					PauseScreenShown = true;
				}
			}
		}

		private void PauseResumeScreenDismiss(object sender, EventArgs e)
		{
			if (base.ViewModel.CanClickMusicControls.Value)
			{
				iFit.Logger.Log.Trace("Workout", "PauseResumeScreenDismiss");
				pauseScreenTimer.Stop();
				if (!ResumeQuitScreenShown)
				{
					PauseScreenShown = false;
				}
			}
		}

		private void PauseResumeScreenDismissFromTimer(object sender, EventArgs e)
		{
			iFit.Logger.Log.Trace("Workout", "PauseResumeScreenDismissFromTimer");
			SafeRunOnUiThread(delegate
			{
				if (pauseFeedFmWidget.IsMarqueeAnimating)
				{
					ResetPauseOverlayTimer();
				}
				else if (!ResumeQuitScreenShown)
				{
					PauseScreenShown = false;
				}
			});
		}

