		protected override void AddFragment(ShireFragment fragment)
		{
			base.AddFragment(fragment);
			if (fragment is InWorkoutHeaderView)
			{
				AddHeaderFragment(fragment);
			}
			else if (fragment is InWorkoutFabView)
			{
				AddFabFragment(fragment);
			}
			else if (fragment is IHudView)
			{
				AddHudFragment(fragment);
			}
			else if (fragment is InWorkoutStreamingVideoView)
			{
				AddVideoFragment(fragment);
			}
			else if (fragment is HRZoneWidgetContainerView)
			{
				AddHRTargetFragment(fragment);
			}
			else if (fragment is HRZoneMyZonesView)
			{
				AddHRMyZonesFragment(fragment);
			}
			else if (fragment is HRZoneLineChartView)
			{
				AddHRZoneLineChartFragment(fragment);
			}
			else if (fragment is HRZoneSimpleFirstChartView)
			{
				AddHRZoneSimpleFirstChartFragment(fragment);
			}
			else if (fragment is DebugPulseChangeLevelView)
			{
				AddDebugActivePulseFragment(fragment);
			}
			else if (fragment is InWorkoutConstantWattsView)
			{
				AddConstantWattsFragment(fragment);
			}
			else if (fragment is ClosedCaptionsView fragment2)
			{
				AddClosedCaptionsFragment(fragment2);
			}
			else if (fragment is NativeLeaderboardView)
			{
				AddNativeLeaderboardFragment(fragment);
			}
		}

		private void AddHeaderFragment(ShireFragment fragment)
		{
			headerView = fragment as InWorkoutHeaderView;
			entireHeaderView = ((Activity)(object)this).FindViewById<LinearLayout>(2131428174);
			entireHeaderView.Visibility = ViewStates.Gone;
			headerAnimator = new WidgetAnimator((Activity)(object)this, entireHeaderView, -HeaderHeight, WidgetState.On);
			headerAnimator.Location = WidgetLocation.Top;
			headerAnimator.Debug = "Header";
			headerAnimator.CanSwipeOn = false;
			widgetManager.Add(WidgetType.Header, headerAnimator);
			if (headerView != null)
			{
				headerView.WhenViewPagerReady.Take(1).Subscribe(delegate
				{
					swipeHelper?.Dispose();
					swipeHelper = new InWorkoutViewSwipeHelper(this, headerView);
					MvxFluentBindingDescriptionSet<InWorkoutView, InWorkoutViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<InWorkoutView, InWorkoutViewModel>();
					mvxFluentBindingDescriptionSet.Bind(swipeHelper).For((InWorkoutViewSwipeHelper h) => h.SwipingEnabled).To((InWorkoutViewModel vm) => vm.HudDropDownEnabled)
						.OneWay();
					mvxFluentBindingDescriptionSet.Bind(swipeHelper).For((InWorkoutViewSwipeHelper h) => h.PageSwipingEnabled).To((InWorkoutViewModel vm) => vm.HeaderPageSwipeEnabled)
						.OneWay();
					mvxFluentBindingDescriptionSet.Apply();
					RegisterWithSwipeHelper(swipeHelper);
					RegisterSwipeAnalytics(swipeHelper);
				});
			}
			AndroidX.Fragment.App.FragmentTransaction fragmentTransaction = SupportFragmentManager.BeginTransaction().Replace(2131428170, fragment);
			if (hasBeenAdded)
			{
				fragmentTransaction.AddToBackStack(null).Commit();
				return;
			}
			hasBeenAdded = true;
			fragmentTransaction.Commit();
		}

		private void RegisterWithSwipeHelper(InWorkoutViewSwipeHelper helper)
		{
			hudSwipedOpen?.Dispose();
			hudSwipedOpen = helper?.WhenSwipedOpen?.SubscribeAsync(WhenHudSwiped);
		}

		private void RegisterSwipeAnalytics(InWorkoutViewSwipeHelper helper)
		{
			hudSwipedOpenAnalytics?.Dispose();
			hudSwipedOpenAnalytics = helper?.WhenSwipedOpenAnalytics?.Subscribe(WhenHudSwipedAnalytics);
		}

		public async System.Threading.Tasks.Task WhenHudSwiped(bool isOpen)
		{
			if (base.ViewModel != null && HudView != null)
			{
				if (isOpen && !hudIsDown)
				{
					DropHud(isMismatched: false);
					await System.Threading.Tasks.Task.Delay(200);
					UpdateHudActiveStates(forceActive: false);
				}
				else if (!isOpen && !hudIsDown)
				{
					DropHud(isMismatched: true);
					UpdateHudActiveStates(forceActive: false);
				}
				else if (!isOpen && hudIsDown)
				{
					hudIsDown = false;
					ShowElementsForOverlay(OverlayType.Pause);
					await System.Threading.Tasks.Task.Delay(200);
					base.ViewModel.HudScreenType.Value = headerView.CurrentPageType;
					SetCurrentHud();
					UpdateHudActiveStates(forceActive: false);
				}
				HideUnhideWidgetBadge(hudIsDown);
				base.ViewModel?.HudStateChange.Execute(hudIsDown);
			}
		}

		private void WhenHudSwipedAnalytics(bool isOpen)
		{
			if (base.ViewModel != null && HudView != null)
			{
				base.ViewModel.SendSwipeAnalytics(isOpen, base.ViewModel.HudScreenType.Value.ToString());
			}
		}

		private void DropHud(bool isMismatched)
		{
			if (base.ViewModel.NavContainerOpen.Value)
			{
				base.ViewModel.NavContainerOpen.SwitchValue();
			}
			HudView.HudVisible = true;
			if (!isMismatched)
			{
				hudIsDown = true;
				HideElementsForOverlay(OverlayType.ChartStats);
			}
		}

		public void UpdateHudActiveStates(bool forceActive)
		{
			if (HudFragments == null)
			{
				return;
			}
			foreach (IHudView hudFragment in HudFragments)
			{
				bool flag = base.ViewModel.HudScreenType.Value == hudFragment.PageType;
				hudFragment.SetHudActiveState((flag && hudIsDown) || forceActive);
			}
		}

