		private void ClearViewPager()
		{
			(from x in fragmentInfos
				where x.CachedFragment != null
				select x.CachedFragment).ToList().ForEach(delegate(AndroidX.Fragment.App.Fragment f)
			{
				SupportFragmentManager.BeginTransaction().Remove(f).Commit();
			});
			fragmentInfos.Clear();
		}

		private void RecreatePages()
		{
			if (fragmentInfos != null && fragmentInfos.Count > 0)
			{
				try
				{
					ClearViewPager();
				}
				catch (Java.Lang.Exception exception)
				{
					iFit.Logger.Log.Trace("Workout", "Error clearing ViewPager. App likely backgrounded.", exception);
					forceRecreate = true;
					return;
				}
			}
			fragmentInfos = _pages.Select(CreatePage).ToList();
			MvxViewPagerFragmentAdapter mvxViewPagerFragmentAdapter = new MvxViewPagerFragmentAdapter((Context)(object)this, fragmentInfos, SupportFragmentManager);
			mvxViewPagerFragmentAdapter.ItemClicked -= ContentClicked;
			mvxViewPagerFragmentAdapter.ItemClicked += ContentClicked;
			viewPager.Adapter = mvxViewPagerFragmentAdapter;
			viewPager.OffscreenPageLimit = fragmentInfos.Count();
			if (mvxViewPagerFragmentAdapter.Fragments.Count > 0 && mvxViewPagerFragmentAdapter.GetItem(0) is IInWorkoutPage inWorkoutPage)
			{
				inWorkoutPage.ToggleFullscreenMode(IsInFullscreenMode);
			}
		}

		private void PageSelected(object sender, ViewPager.PageSelectedEventArgs e)
		{
			for (int i = 0; i < fragmentInfos.Count; i++)
			{
				if (((fragmentInfos[i]?.CachedFragment is BaseFragment baseFragment) ? baseFragment.ViewModel : null) is InWorkoutPageViewModel inWorkoutPageViewModel)
				{
					inWorkoutPageViewModel.PageIsVisible.Value = i == e.Position;
				}
			}
		}

		private MvxViewPagerFragmentAdapter.FragmentInfo CreatePage(Type viewModelType)
		{
			string text = viewModelType.Name.Replace("Model", string.Empty);
			Type type = Type.GetType("Wolf.Android.Views.InWorkout.Pages." + text);
			return new MvxViewPagerFragmentAdapter.FragmentInfo(type, viewModelType);
		}

		private IHudView CreateHud(InWorkoutHeaderHudType pageType)
		{
			InWorkoutHudViewMapper singleton = Mvx.GetSingleton<InWorkoutHudViewMapper>();
			IMvxViewModel viewModelForType = singleton.GetViewModelForType(pageType);
			if (viewModelForType == null)
			{
				throw new ArgumentException($"Provided InWorkoutHeaderHudType {pageType} does not have a corresponding ViewModel");
			}
			string text = viewModelForType.GetType().Name.Replace("Model", string.Empty);
			Type type = Type.GetType("Wolf.Android.Views.InWorkout.Hud." + text);
			if (type != null)
			{
				BaseFragment baseFragment = (BaseFragment)Activator.CreateInstance(type);
				baseFragment.ViewModel = viewModelForType;
				if (viewModelForType is BaseHudViewModel baseHudViewModel)
				{
					System.Threading.Tasks.Task.Run((Func<System.Threading.Tasks.Task>)baseHudViewModel.Init);
					baseHudViewModel.WorkoutID = base.ViewModel.WorkoutID;
				}
				return baseFragment as IHudView;
			}
			return null;
		}

		private void RemoveSliderSubs()
		{
			if (leftSliderTouchedSub != null)
			{
				leftSliderTouchedSub.Dispose();
				leftSliderTouchedSub = null;
			}
			if (rightSliderTouchedSub != null)
			{
				rightSliderTouchedSub.Dispose();
				rightSliderTouchedSub = null;
			}
		}

		private void SetupAndBindSlidersIfNeeded()
		{
			if (((base.ViewModel.LeftSliderModel == null || leftSlider != null) && (base.ViewModel.RightSliderModel == null || rightSlider != null)) || base.UseHeadlessBikeTheme)
			{
				return;
			}
			iFit.Logger.Log.Trace("Workout", "Inflating, setting up, and binding sliders");
			MvxFluentBindingDescriptionSet<InWorkoutView, InWorkoutViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<InWorkoutView, InWorkoutViewModel>();
			RemoveSliderSubs();
			if (!(base.DataContext is InWorkoutViewModel inWorkoutViewModel))
			{
				return;
			}
			int dimensionPixelOffset = ((Context)(object)this).Resources.GetDimensionPixelOffset(2131168200);
			leftSliderStub = ((Activity)(object)this).FindViewById<ViewStub>(2131428507);
			rightSliderStub = ((Activity)(object)this).FindViewById<ViewStub>(2131429122);
			NegateBoolValueConverter converter = new NegateBoolValueConverter();
			if (inWorkoutViewModel.LeftSliderModel != null)
			{
				leftSliderStub?.Inflate();
				leftSlider = ((Activity)(object)this).FindViewById<WorkoutSliderView>(2131428506);
				leftSlider.TranslationX = ((Context)(object)this).Resources.GetDimension(2131168201);
				leftSlider.Alpha = 0.8f;
				leftSlider.SliderModel = inWorkoutViewModel.LeftSliderModel;
				leftSliderAnimator = new WidgetAnimator((Activity)(object)this, leftSlider, -dimensionPixelOffset, WidgetState.Off);
				leftSliderAnimator.Location = WidgetLocation.Left;
				leftSliderAnimator.CanSwipeOn = false;
				leftSliderAnimator.Debug = "Left Slider";
				widgetManager.Add(WidgetType.LeftSlider, leftSliderAnimator);
				mvxFluentBindingDescriptionSet.Bind(leftSlider).For((WorkoutSliderView x) => x.Enabled).To((InWorkoutViewModel vm) => vm.LeftSliderModel.UserInitiatedChangePending)
					.WithConversion(converter);
				leftSlider.SliderActivity -= SliderActivityOccurred;
				leftSlider.SliderActivity += SliderActivityOccurred;
				leftSlider.CurrentValueChanged -= SliderControlValueChanged;
				leftSlider.CurrentValueChanged += SliderControlValueChanged;
				leftSliderTouchedSub = leftSlider.WhenSliderTouched.ObserveOn(NewThreadScheduler.Default).SubscribeWithErrorLogging(delegate
				{
					base.ViewModel.SliderTouched(leftSlider.SliderModel);
				});
			}
			if (inWorkoutViewModel.RightSliderModel != null)
			{
				rightSliderStub?.Inflate();
				rightSlider = ((Activity)(object)this).FindViewById<WorkoutSliderView>(2131429121);
				rightSlider.SliderModel = inWorkoutViewModel.RightSliderModel;
				rightSliderAnimator = new WidgetAnimator((Activity)(object)this, rightSlider, dimensionPixelOffset, WidgetState.Off);
				rightSliderAnimator.Location = WidgetLocation.Right;
				rightSliderAnimator.CanSwipeOn = false;
				rightSliderAnimator.Debug = "Right Slider";
				widgetManager.Add(WidgetType.RightSlider, rightSliderAnimator);
				mvxFluentBindingDescriptionSet.Bind(rightSlider).For((WorkoutSliderView x) => x.Enabled).To((InWorkoutViewModel vm) => vm.RightSliderModel.UserInitiatedChangePending)
					.WithConversion(converter);
				rightSlider.SliderActivity -= SliderActivityOccurred;
				rightSlider.SliderActivity += SliderActivityOccurred;
				rightSlider.CurrentValueChanged -= SliderControlValueChanged;
				rightSlider.CurrentValueChanged += SliderControlValueChanged;
				rightSliderTouchedSub = rightSlider.WhenSliderTouched.ObserveOn(NewThreadScheduler.Default).SubscribeWithErrorLogging(delegate
				{
					base.ViewModel.SliderTouched(rightSlider.SliderModel);
				});
			}
			mvxFluentBindingDescriptionSet.Apply();
			sliderActivityTimer.Elapsed -= SliderFadeFromTimer;
			sliderActivityTimer.Elapsed += SliderFadeFromTimer;
			if (inWorkoutViewModel.RightSliderModel != null)
			{
				SliderActivityOccurred(rightSlider, null);
			}
		}

