		private void SliderActivityOccurred(object sender, EventArgs e)
		{
			if (sliderActivityTimer != null)
			{
				sliderActivityTimer.Interval = 10000.0;
				sliderActivityTimer.Start();
			}
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (rightSlider != null)
				{
					rightSlider.Alpha = 0.8f;
				}
				if (leftSlider != null)
				{
					leftSlider.Alpha = 0.8f;
				}
			});
		}

		private void SliderFadeFromTimer(object sender, EventArgs e)
		{
			sliderActivityTimer?.Stop();
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (leftSlider != null)
				{
					leftSlider.Alpha = 0.56f;
				}
				if (rightSlider != null)
				{
					rightSlider.Alpha = 0.56f;
				}
			});
		}

		public override void OnBackPressed()
		{
			if (!base.ViewModel.IsScreenLocked)
			{
				iFit.Logger.Log.Trace("Workout", "Shows PauseScreen/Resume InWorkout from OnBackPressed");
				if (!PauseScreenShown)
				{
					PauseScreenShown = true;
				}
				if (ResumeQuitScreenShown)
				{
					base.ViewModel.ResumeButtonTapped.Execute(null);
				}
			}
		}

		private void SetupNotificationPresenter()
		{
			int notificationDismissDistance;
			WidgetLocation widgetLocation;
			if (base.UseHeadlessBikeTheme)
			{
				ViewStub viewStub = ((Activity)(object)this).FindViewById<ViewStub>(2131427551);
				viewStub.Inflate();
				notificationDismissDistance = DpToPx(400f);
				widgetLocation = WidgetLocation.Bottom;
				LinearLayout view = ((Activity)(object)this).FindViewById<LinearLayout>(2131428704);
				notificationAnimator = new NotificationContainerWidgetAnimator((Activity)(object)this, view, 0, WidgetState.On);
				notificationAnimator.Location = WidgetLocation.Bottom;
				notificationAnimator.Debug = "Notification Container";
				notificationAnimator.CanSwipeOn = false;
				widgetManager.Add(WidgetType.CenterNotifications, notificationAnimator);
			}
			else if (UseLeftSideForNotifications())
			{
				notificationDismissDistance = DpToPx(308f);
				widgetLocation = WidgetLocation.Left;
				widgetManager.PauseNotificationsOnHRToggle = false;
			}
			else
			{
