		private async System.Threading.Tasks.Task AnimateFollowWorkoutButton(bool visible, System.Threading.CancellationToken token)
		{
			if (isDisposed)
			{
				return;
			}
			CheckAndInflateFollowWorkoutButton();
			if (followWorkoutButton == null)
			{
				return;
			}
			if (visible)
			{
				followWorkoutButton.Alpha = 1f;
				followWorkoutButtonContainer.Visibility = ViewStates.Visible;
				followWorkoutButtonText.Alpha = 0f;
				float startTranslation = ((Context)(object)this).Resources.GetDimension(2131166411);
				await followWorkoutButton.Animate().ScaleX(1f).ScaleY(1f)
					.WithStartAction(new Runnable(delegate
					{
						followWorkoutButton.TranslationY = startTranslation;
					}))
					.TranslationY(0f)
					.SetDuration(300L)
					.SetInterpolator(new OvershootInterpolator(1f))
					.WithLayer()
					.StartWithDisposal(token);
				await System.Threading.Tasks.Task.Delay(100, token);
				System.Threading.Tasks.Task expandTask = AnimateFollowTextExpansion(visible: true, token);
				await System.Threading.Tasks.Task.Delay(150, token);
				ObjectAnimator objectAnimator = ObjectAnimator.OfFloat(followWorkoutButtonText, "alpha", 0f, 1f);
				objectAnimator.SetDuration(300L);
				await System.Threading.Tasks.Task.WhenAll(objectAnimator.StartWithDisposal(token), expandTask);
			}
			else
			{
				System.Threading.Tasks.Task expandTask = AnimateFollowTextExpansion(visible: false, token);
				await System.Threading.Tasks.Task.Delay(400, token);
				System.Threading.Tasks.Task task = followWorkoutButton.Animate().Alpha(0f).ScaleX(0f)
					.ScaleY(0f)
					.SetDuration(300L)
					.SetInterpolator(new OvershootInterpolator(1f))
					.WithLayer()
					.StartWithDisposal(token);
				await System.Threading.Tasks.Task.WhenAll(expandTask, task);
				followWorkoutButton.ScaleX = 0f;
				followWorkoutButton.ScaleY = 0f;
				followWorkoutButtonContainer.Visibility = ViewStates.Invisible;
			}
		}

		private async System.Threading.Tasks.Task AnimateFollowTextExpansion(bool visible, System.Threading.CancellationToken token)
		{
			int num = (visible ? 300 : 350);
			AndroidX.Transitions.AutoTransition autoTransition = new AndroidX.Transitions.AutoTransition();
			autoTransition.SetDuration(num);
			System.Threading.Tasks.Task task;
			if (visible)
			{
				followWorkoutButtonText.Visibility = ViewStates.Visible;
				float translationX = ((followWorkoutButtonText.Width == 0) ? (-1f * ((Context)(object)this).Resources.GetDimension(2131166412)) : ((float)(-1 * followWorkoutButtonText.Width)));
				followWorkoutButtonText.TranslationX = translationX;
				task = followWorkoutButtonText.Animate().TranslationX(0f).SetDuration(num)
					.SetInterpolator(new FastOutSlowInInterpolator())
					.WithLayer()
					.StartWithDisposal(token);
			}
			else
			{
				followWorkoutButtonText.Visibility = ViewStates.Gone;
				task = System.Threading.Tasks.Task.Delay(num, token);
			}
			AndroidX.Transitions.TransitionManager.BeginDelayedTransition(followWorkoutButton, autoTransition);
			await task;
		}

