		private void SeekBar_ProgressChanged(object sender, SeekBar.ProgressChangedEventArgs e)
		{
			int num = e.Progress;
			if (base.ViewModel.IsAndroidBuiltIn() && base.ViewModel.WorkoutPauseVolumeType == VolumeType.System)
			{
				num = SystemVolumeHelper.MapVolume((float)num / 100f);
				volumeSeekBar.SeekBar.SetProgress(num, animate: false);
			}
			HandlePauseOverlayVolumeChanged((float)num / 100f);
		}

		private void SystemVolumeSeekBarOnStopTrackingTouch(object sender, SeekBar.StopTrackingTouchEventArgs stopTrackingTouchEventArgs)
		{
			base.ViewModel?.SystemVolumeReleased();
		}

		private void SystemVolumeSeekBarOnStartTrackingTouch(object sender, SeekBar.StartTrackingTouchEventArgs stopTrackingTouchEventArgs)
		{
			base.ViewModel?.SystemVolumeSlidingStarted();
		}

		private void HandlePauseOverlayVolumeChanged(float newVolume)
		{
			if (!isDisposed)
			{
				base.ViewModel?.UpdateVolume?.Execute(newVolume);
				ResetPauseOverlayTimer();
			}
		}

		private void ResetPauseOverlayTimer()
		{
			pauseScreenTimer?.Stop();
			pauseScreenTimer?.Start();
		}

		private void UpdatePauseOverlayVolumeSlider()
		{
			if (!isDisposed && volumeSeekBar != null && volumeSeekBar.SeekBar != null)
			{
				volumeSeekBar.Text = string.Empty;
				volumeSeekBar.SetVolumeSeekBarType(PauseOverlayVolumeSliderType, base.ViewModel.IsStrengthMirror, base.UseHeadlessBikeTheme);
				volumeSeekBar.SeekBar.StopTrackingTouch -= SystemVolumeSeekBarOnStopTrackingTouch;
				volumeSeekBar.SeekBar.StartTrackingTouch -= SystemVolumeSeekBarOnStartTrackingTouch;
				volumeSeekBar.SeekBar.ProgressChanged -= SeekBar_ProgressChanged;
				float val = 1f;
				switch (PauseOverlayVolumeSliderType)
				{
				case VolumeType.Master:
					val = base.ViewModel.LastMasterVolume;
					break;
				case VolumeType.System:
					val = base.ViewModel.LastSystemVolume;
					break;
				}
				volumeSeekBar.SeekBar.Progress = (int)System.Math.Round(val.Clamp(0f, 1f) * 100f);
				volumeSeekBar.SeekBar.StopTrackingTouch += SystemVolumeSeekBarOnStopTrackingTouch;
				volumeSeekBar.SeekBar.StartTrackingTouch += SystemVolumeSeekBarOnStartTrackingTouch;
				volumeSeekBar.SeekBar.ProgressChanged += SeekBar_ProgressChanged;
			}
		}

		private void HandleFullScreenChange(bool isFullScreen)
		{
