					widgetBadge.Visibility = ViewStates.Gone;
				}
			}
		}
	}
	public class InWorkoutViewSwipeHelper : Java.Lang.Object
	{
		private const int ScrollAnimationMillis = 200;

		private const int NoAnimationMillis = 0;

		private const double FlingThreshold = 0.1;

		private readonly float clickRadius;

		private Subject<bool> whenSwipedOpen = new Subject<bool>();

		private Subject<bool> whenSwipedOpenAnalytics = new Subject<bool>();

		private InWorkoutView inWorkoutView;

		private InWorkoutHeaderView inWorkoutHeaderView;

		private SwipeDetector swipeDetector;

		private IfitImageButton closeHudBtn;

		private View headerContainerWithShadow;

		private ConstraintLayout slidingContainer;

		private int slidingContainerMarginTop;

		private int slidingContainerHeight;

		private int headerContainerHeight;

		private int headerContainerWithShadowHeight;

		private int shadowHeight;

		private double maxSlidingContainerTranslationY;

		private bool isVerticalHudSwipe;

		private bool isClosed;

		private IDisposable swipingSub;

		private IDisposable swipedSub;

		public IObservable<bool> WhenSwipedOpen => whenSwipedOpen;

		public IObservable<bool> WhenSwipedOpenAnalytics => whenSwipedOpenAnalytics;

		public bool SwipingEnabled { get; set; } = true;

		public bool PageSwipingEnabled { get; set; } = true;

		public InWorkoutViewSwipeHelper(InWorkoutView inWorkoutView, InWorkoutHeaderView inWorkoutHeaderView)
		{
			this.inWorkoutView = inWorkoutView;
			this.inWorkoutHeaderView = inWorkoutHeaderView;
			headerContainerWithShadow = ((Activity)(object)inWorkoutView).FindViewById(2131428174);
			slidingContainer = ((Activity)(object)inWorkoutView).FindViewById<ConstraintLayout>(2131429282);
			closeHudBtn = ((Activity)(object)inWorkoutView).FindViewById<IfitImageButton>(2131427679);
			inWorkoutHeaderView.ViewPager.Post(SetupDimensions);
			inWorkoutHeaderView.ViewPager.Touch += OnViewPagerTouch;
			slidingContainer.Touch += OnContainerTouch;
			clickRadius = TypedValue.ApplyDimension(ComplexUnitType.Dip, 10f, ((Context)(object)inWorkoutHeaderView.Activity).Resources.DisplayMetrics);
		}

		private void SetupDimensions()
		{
			View view = ((Activity)(object)inWorkoutView).FindViewById(2131428170);
			headerContainerWithShadowHeight = headerContainerWithShadow.Height;
			headerContainerHeight = view.Height;
			shadowHeight = headerContainerWithShadowHeight - headerContainerHeight;
			slidingContainerHeight = slidingContainer.Height;
			maxSlidingContainerTranslationY = slidingContainerHeight;
			slidingContainerMarginTop = (slidingContainer.LayoutParameters as ConstraintLayout.LayoutParams).TopMargin;
			SetupSwiping();
			Close(animate: false);
			inWorkoutHeaderView?.ViewPager.Post(delegate
			{
				inWorkoutView?.UpdateHudActiveStates(forceActive: false);
			});
		}

		public void Close(bool animate)
		{
			closeHudBtn.Visibility = ViewStates.Invisible;
			int num = (animate ? 200 : 0);
			slidingContainer.Animate().TranslationY(-slidingContainerHeight).WithLayer()
				.SetDuration(num)
				.Start();
			isClosed = true;
			whenSwipedOpen.OnNext(value: false);
		}

		public void Open(bool animate)
		{
			closeHudBtn.Visibility = ViewStates.Visible;
			int num = (animate ? 200 : 0);
			slidingContainer.Animate().TranslationY(0f).WithLayer()
				.SetDuration(num)
				.Start();
			isClosed = false;
			whenSwipedOpen.OnNext(value: true);
		}

		private void SendSwipeOpenAnalytics()
		{
			if (isClosed)
			{
				whenSwipedOpenAnalytics.OnNext(value: true);
			}
		}

		private void SendSwipeCloseAnalytics()
		{
			whenSwipedOpenAnalytics.OnNext(value: false);
		}

		private void SetupSwiping()
		{
			swipeDetector = new SwipeDetector((Context)(object)inWorkoutView);
			swipingSub = swipeDetector.WhenSwiping.Subscribe(OnSwiping);
			swipedSub = swipeDetector.WhenSwipeEnded.Subscribe(OnSwipeEnded);
		}

		private void OnSwiping(SwipeEvent e)
		{
			if (SwipingEnabled && (isVerticalHudSwipe || !SwipeIsOnlyInHeader(e) || !(System.Math.Abs(e.DistanceY) <= (float)(headerContainerWithShadowHeight / 2))))
			{
				isVerticalHudSwipe = true;
				int num = (int)e.End.RawY;
				int num2 = -(slidingContainerHeight - num + slidingContainerMarginTop + shadowHeight);
				if (num2 <= 0 && !((double)num2 < 0.0 - maxSlidingContainerTranslationY))
				{
					inWorkoutView?.WhenHudSwiped(isOpen: true);
				}
			}
		}

		private void OnSwipeEnded(SwipeEvent e)
		{
			if (SwipingEnabled && isVerticalHudSwipe)
			{
				float num = e.DistanceY / (float)slidingContainerHeight;
				if ((double)num > 0.1)
				{
					SendSwipeOpenAnalytics();
					Open(animate: true);
				}
				else if ((double)num < -0.1)
				{
					Close(animate: true);
					SendSwipeCloseAnalytics();
				}
				else if (0f - slidingContainer.TranslationY > 0f && 0f - slidingContainer.TranslationY < (float)(slidingContainerHeight / 2))
				{
					SendSwipeOpenAnalytics();
					Open(animate: true);
				}
				else if (0f - slidingContainer.TranslationY < 0f && 0f - slidingContainer.TranslationY > (float)(slidingContainerHeight / 2))
				{
					Close(animate: true);
					SendSwipeCloseAnalytics();
				}
				else if (slidingContainer.TranslationY > (float)(-slidingContainerHeight / 2))
				{
					if (isClosed)
					{
						SendSwipeOpenAnalytics();
						Open(animate: true);
					}
				}
				else
				{
					Close(animate: true);
					SendSwipeCloseAnalytics();
				}
			}
			if (!(e.DistanceX < clickRadius) || !(e.DistanceY < clickRadius))
			{
				return;
			}
			IHudView hudView = inWorkoutView.HudView;
			if (hudView == null || !hudView.HandleTouchedInHeader(e.Start, e.End))
			{
				if (!isClosed)
				{
					slidingContainer.PerformClick();
				}
				else
				{
					inWorkoutHeaderView.HandleTouchedInHeader(e.Start, e.End);
				}
			}
		}

		private bool SwipeIsOnlyInHeader(SwipeEvent e)
		{
			return headerContainerWithShadow.ContainsStartAndEndTouch(e.Start, e.End);
		}

		private void OnContainerTouch(object sender, View.TouchEventArgs e)
		{
			swipeDetector?.HandleTouchEvent(e.Event);
		}

		private void OnViewPagerTouch(object sender, View.TouchEventArgs e)
		{
			try
			{
				if (e.Event.Action == MotionEventActions.Down)
				{
					isVerticalHudSwipe = false;
				}
				swipeDetector.HandleTouchEvent(e.Event);
				if (!PageSwipingEnabled || isVerticalHudSwipe)
				{
					MotionEvent motionEvent = MotionEvent.Obtain(e.Event);
					motionEvent.Action = MotionEventActions.Cancel;
					inWorkoutHeaderView.ViewPager.OnTouchEvent(motionEvent);
				}
				else
				{
					inWorkoutHeaderView.ViewPager.OnTouchEvent(e.Event);
				}
			}
			catch (IllegalArgumentException exception)
			{
				if (Mvx.TryResolve<IWolfAnalytics>(out var service))
				{
					service.HandledViewPagerBug(exception);
				}
				iFit.Logger.Log.Error("InWorkoutViewSwipeHelper", "Caught the Android ViewPager.OnTouchEvent bug", exception);
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				if (swipedSub != null)
				{
					swipedSub.Dispose();
					swipedSub = null;
				}
				if (swipingSub != null)
				{
					swipingSub.Dispose();
					swipingSub = null;
				}
				if (whenSwipedOpen != null)
				{
					whenSwipedOpen.Dispose();
					whenSwipedOpen = null;
				}
				if (whenSwipedOpenAnalytics != null)
				{
					whenSwipedOpenAnalytics.Dispose();
					whenSwipedOpenAnalytics = null;
				}
				swipeDetector = iFit.Extensions.Android.JavaExtensions.DisposeSafe(swipeDetector);
				if (slidingContainer != null)
				{
					slidingContainer.Touch -= OnContainerTouch;
					slidingContainer = iFit.Extensions.Android.JavaExtensions.DisposeSafe(slidingContainer);
				}
				if (inWorkoutHeaderView?.ViewPager != null)
				{
					inWorkoutHeaderView.ViewPager.Touch -= OnViewPagerTouch;
					inWorkoutHeaderView.ViewPager.Dispose();
					inWorkoutHeaderView = null;
				}
				inWorkoutView = null;
				inWorkoutHeaderView = null;
			}
			base.Dispose(disposing);
		}
	}
