		private void HandleTouchEvent(object sender, View.TouchEventArgs e)
		{
			switch (e.Event.ActionMasked)
			{
			case MotionEventActions.Down:
				touchStartEvent = MotionEvent.Obtain(e.Event);
				break;
			case MotionEventActions.Cancel:
				touchStartEvent = null;
				break;
			case MotionEventActions.Up:
				e.Handled = View.TouchesRepresentClick(touchStartEvent, e.Event) && StatsView.EvaluateClick(touchStartEvent, e.Event);
				touchStartEvent = null;
				break;
			case MotionEventActions.Move:
				break;
			}
		}

