	public class PhoneInWorkoutViewSwipeHelper : Java.Lang.Object
	{
		private bool _isDrawerOpen;

		private PhoneInWorkoutView inWorkoutView;

		private SwipeDetector swipeDetector;

		private bool? swipingVertically;

		private FrameLayout slidingContainer;

		private IDisposable swipingSub;

		private IDisposable swipedSub;

		private bool isDisposed;

		public bool SwipingEnabled { get; set; }

		public bool IsSwiping { get; private set; }

