		public bool IsDrawerOpen
		{
			get
			{
				return _isDrawerOpen;
			}
			private set
			{
				if (value != _isDrawerOpen)
				{
					_isDrawerOpen = value;
					DrawerOpenChanged.OnNext(value);
				}
			}
		}

		private int settingsContainerWidth => ((Context)(object)inWorkoutView)?.Resources.GetDimensionPixelSize(2131168177) ?? 1;

		public PhoneInWorkoutViewSwipeHelper(PhoneInWorkoutView inWorkoutView)
		{
			this.inWorkoutView = inWorkoutView;
			slidingContainer = ((Activity)(object)inWorkoutView).FindViewById<FrameLayout>(2131429282);
			SetupSwiping();
		}

		public void OnViewPagerTouched(object sender, MotionEvent ev)
		{
			swipeDetector.HandleTouchEvent(ev);
		}

		public void CloseDrawer()
		{
			ShiftView(inWorkoutView.ContentContainer, 0f, viewShiftedLeft: false, isAnimated: true, runEndAction: true);
			ShiftView(inWorkoutView.ControlsContainer, 0f, viewShiftedLeft: true, isAnimated: true);
			inWorkoutView.SettingsContainer.Animate().Alpha(1f);
			inWorkoutView.MapTypeSelector.Animate().Alpha(0f);
		}

		private void SetupSwiping()
		{
			swipeDetector = new SwipeDetector((Context)(object)inWorkoutView);
			swipingSub = swipeDetector.WhenSwiping.Subscribe(OnSwiping);
			swipedSub = swipeDetector.WhenSwipeEnded.Subscribe(OnSwipeEnded);
		}

		private void OnSwiping(SwipeEvent e)
		{
			swipingVertically = (swipingVertically.HasValue ? swipingVertically : new bool?(e.IsVertical));
			if (!e.IsVertical && !swipingVertically.Value)
			{
				OnSwipingHorizontal(e);
			}
		}

		private void OnSwipeEnded(SwipeEvent e)
		{
			if (swipingVertically.HasValue)
			{
				if (!swipingVertically.Value)
				{
					OnSwipeEndedHorizontal(e);
				}
				swipingVertically = null;
			}
		}

		private void OnSwipingHorizontal(SwipeEvent e)
		{
			if (SwipingEnabled)
			{
				IsSwiping = true;
				float num = System.Math.Abs((float)System.Math.Round(e.End.RawX - e.Start.RawX));
				double num2 = 0.15;
				float val = (float)(num2 * (double)inWorkoutView.ContentContainer.Width);
				float num3 = System.Math.Min(val, num);
				bool flag = e.End.RawX - e.Start.RawX < 0f;
				bool flag2 = num <= (float)settingsContainerWidth;
				if (flag && flag2 && !IsDrawerOpen)
				{
					ShiftView(inWorkoutView.ContentContainer, num3, viewShiftedLeft: true, isAnimated: false);
					ShiftView(inWorkoutView.ControlsContainer, num, viewShiftedLeft: false, isAnimated: false);
					float num4 = num / (float)settingsContainerWidth;
					inWorkoutView.MapTypeSelector.Alpha = num4;
					inWorkoutView.SettingsContainer.Alpha = 1f - num4;
				}
				else if (flag && !IsDrawerOpen)
				{
					ShiftView(inWorkoutView.ContentContainer, num3, viewShiftedLeft: true, isAnimated: false);
					ShiftView(inWorkoutView.ControlsContainer, settingsContainerWidth, viewShiftedLeft: false, isAnimated: false);
					inWorkoutView.MapTypeSelector.Alpha = 1f;
					inWorkoutView.SettingsContainer.Alpha = 0f;
				}
				else if (flag)
				{
					ShiftView(inWorkoutView.ContentContainer, (float)settingsContainerWidth + num3, viewShiftedLeft: true, isAnimated: false);
					ShiftView(inWorkoutView.ControlsContainer, settingsContainerWidth, viewShiftedLeft: false, isAnimated: false);
					inWorkoutView.MapTypeSelector.Alpha = 1f;
					inWorkoutView.SettingsContainer.Alpha = 0f;
				}
				else if (!flag && flag2 && IsDrawerOpen)
				{
					ShiftView(inWorkoutView.ContentContainer, (float)settingsContainerWidth - num3, viewShiftedLeft: true, isAnimated: false);
					ShiftView(inWorkoutView.ControlsContainer, (float)settingsContainerWidth - num, viewShiftedLeft: false, isAnimated: false);
					float num5 = num / (float)settingsContainerWidth;
					inWorkoutView.SettingsContainer.Alpha = num5;
					inWorkoutView.MapTypeSelector.Alpha = 1f - num5;
				}
				else if (!flag && IsDrawerOpen)
				{
					ShiftView(inWorkoutView.ContentContainer, num3 - (float)settingsContainerWidth, viewShiftedLeft: false, isAnimated: false);
					ShiftView(inWorkoutView.ControlsContainer, 0f, viewShiftedLeft: true, isAnimated: false);
					inWorkoutView.MapTypeSelector.Alpha = 0f;
					inWorkoutView.SettingsContainer.Alpha = 1f;
				}
				else
				{
					ShiftView(inWorkoutView.ContentContainer, num3, viewShiftedLeft: false, isAnimated: false);
					ShiftView(inWorkoutView.ControlsContainer, 0f, viewShiftedLeft: true, isAnimated: false);
					inWorkoutView.MapTypeSelector.Alpha = 0f;
					inWorkoutView.SettingsContainer.Alpha = 1f;
				}
			}
		}

		private void OnSwipeEndedHorizontal(SwipeEvent e)
		{
			if (SwipingEnabled)
			{
				float num = System.Math.Abs((float)System.Math.Round(e.End.RawX - e.Start.RawX));
				bool flag = e.End.RawX - e.Start.RawX < 0f;
				bool flag2 = num <= (float)settingsContainerWidth;
				if (flag && flag2 && !IsDrawerOpen)
				{
					CloseDrawer();
				}
				else if (flag)
				{
					ShiftView(inWorkoutView.ContentContainer, settingsContainerWidth, viewShiftedLeft: true, isAnimated: true, runEndAction: true);
				}
				else
				{
					CloseDrawer();
				}
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !isDisposed)
			{
				inWorkoutView = null;
				swipedSub?.Dispose();
				swipedSub = null;
				swipingSub?.Dispose();
				swipingSub = null;
				swipeDetector?.Dispose();
				swipeDetector = null;
				isDisposed = true;
			}
			base.Dispose(disposing);
		}

		private void ShiftView(View view, float finalTranslation, bool viewShiftedLeft, bool isAnimated, bool runEndAction = false)
		{
			if (isDisposed)
			{
				return;
			}
			float num = (viewShiftedLeft ? (0f - finalTranslation) : finalTranslation);
			if (isAnimated && runEndAction)
			{
				view.Animate().TranslationX(num).WithEndAction(new Runnable(delegate
				{
					IsDrawerOpen = System.Math.Abs(inWorkoutView.ContentContainer.TranslationX).AlmostEqual(settingsContainerWidth);
					IsSwiping = false;
				}));
			}
			else if (isAnimated)
			{
				view.Animate().TranslationX(num);
			}
			else
			{
				view.TranslationX = num;
			}
		}
	}
