					if (_pages != null && value.SequenceEqual(_pages))
					{
						return;
					}
					_pages = value.ToList();
				}
				if (isInBackground)
				{
					pagesChangedWhileInBackground = true;
					iFit.Logger.Log.Info("Workout", "Workout pages changed while app in background. Will recreate pages when user returns to app");
				}
				else
				{
					RecreatePages();
				}
			}
		}

