		public bool ResumeQuitScreenShown
		{
			get
			{
				return _resumeQuitScreenShown;
			}
			set
			{
				iFit.Logger.Log.Trace("Workout", $"Setting PauseScreenShown to {value}. _pauseScreenShown is {_resumeQuitScreenShown}");
				_resumeQuitScreenShown = value;
				SafeRunOnUiThread(delegate
				{
					InWorkoutViewModel viewModel = base.ViewModel;
					if (viewModel != null && viewModel.IsClubBle)
					{
						clubQuitContainer.Visibility = (_resumeQuitScreenShown ? ViewStates.Gone : ViewStates.Visible);
					}
					else
					{
						pauseContainer.Visibility = (_resumeQuitScreenShown ? ViewStates.Gone : ViewStates.Visible);
						resumeQuitButtonsContainer.Visibility = ((!_resumeQuitScreenShown) ? ViewStates.Gone : ViewStates.Visible);
					}
				});
				if (_resumeQuitScreenShown)
				{
					pauseScreenTimer.Stop();
					FadeShowPauseResumeScreen(200L);
				}
				else
				{
					FadeHidePauseResumeScreen(200L);
				}
			}
		}

		public bool ExpandView
		{
			get
			{
				return _expandView;
			}
			set
			{
				iFit.Logger.Log.Trace("Workout", $"Setting ExpandView to {value}. _expandView is {_expandView}");
				_expandView = value;
				SafeRunOnUiThread(delegate
				{
					if (fragmentInfos.CountSafe() > 0)
					{
						MvxViewPagerFragmentAdapter.FragmentInfo fragmentInfo = fragmentInfos[0];
						if (fragmentInfo.CachedFragment is IInWorkoutPage inWorkoutPage)
						{
							inWorkoutPage.ToggleFullscreenMode(value);
						}
					}
					ControlsContainer.Visibility = (_expandView ? ViewStates.Invisible : ViewStates.Visible);
					ViewGroup.MarginLayoutParams marginLayoutParams = (ViewGroup.MarginLayoutParams)ContentContainer.LayoutParameters;
					marginLayoutParams.RightMargin = ((!_expandView) ? ((Context)(object)this).Resources.GetDimensionPixelSize(2131168177) : 0);
					ContentContainer.RequestLayout();
					headerView.IsHeaderVisible = !_expandView;
					swipeHelper.CloseDrawer();
				});
			}
		}

		public AudioTrack CurrentAudioTrack
		{
			get
			{
				return currentAudioTrack;
			}
			set
			{
				currentAudioTrack = value;
				SafeRunOnUiThread(delegate
				{
					if (feedFmNotification != null)
					{
						if (value == null)
						{
							feedFmNotification.Visibility = ViewStates.Gone;
						}
						else
						{
							musicService?.DismissFeedFmNotification();
							HandleAudioTrackChange();
						}
					}
				});
				SafeRunOnUiThread(delegate
				{
					if (staticFeedFmWidget != null)
					{
						if (value == null)
						{
							staticFeedFmWidget.Visibility = ViewStates.Gone;
						}
						else
						{
							staticFeedFmWidget.Animate()?.Alpha(0f)?.SetDuration(200L);
							staticFeedFmWidget.Animate()?.StartWithDisposal();
							staticFeedFmWidget.SetTrackInfo(currentAudioTrack);
							staticFeedFmWidget.Visibility = ViewStates.Visible;
							staticFeedFmWidget.Animate()?.Alpha(1f)?.SetDuration(200L);
							staticFeedFmWidget.Animate()?.StartWithDisposal();
						}
					}
				});
			}
		}

		public bool MusicOverlayShowing
		{
			get
			{
				return musicOverlayShowing;
			}
			set
			{
				if (value != musicOverlayShowing)
				{
					musicOverlayShowing = value;
					if (value)
					{
						HideSliderControls(this, EventArgs.Empty);
					}
				}
			}
		}

