		public override void OnConfigurationChanged(global::Android.Content.Res.Configuration newConfig)
		{
			iFit.Logger.Log.Trace("Workout", "OnConfigurationChanged() called with\noldConfig: " + oldConfig + "\n" + string.Format("{0}: {1}", "newConfig", newConfig));
			oldConfig = newConfig.ToString();
			((Activity)(object)this).OnConfigurationChanged(newConfig);
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			base.ViewModel.WorkoutMode.Changed -= HandleSwipeEnablingChanges;
			base.ViewModel.NavContainerOpen.Changed -= HandleSwipeEnablingChanges;
			if (pauseScreenTimer != null)
			{
				pauseScreenTimer.Elapsed -= PauseResumeScreenDismiss;
				pauseScreenTimer.Dispose();
			}
			if (viewPager != null)
			{
				viewPager.PageSelected -= PageSelected;
				viewPager.PageScrolled -= PageScrolled;
			}
			if (sliderControlsButton != null)
			{
				sliderControlsButton.Click -= ShowSliderControls;
				sliderControlsButton = iFit.Extensions.Android.JavaExtensions.DisposeSafe(sliderControlsButton);
			}
			if (feedFmNotificationPresenter != null)
			{
				feedFmNotificationPresenter.Dispose();
				feedFmNotificationPresenter = null;
			}
			if (musicControlsButton != null)
			{
				musicControlsButton.Click -= PauseResumeScreenDismissHideNotification;
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(musicControlsButton);
			}
			ccButton?.Dispose();
			ccButton = null;
			swipeHelper?.Dispose();
			swipeHelper = null;
			fragmentInfos?.Clear();
			Pages?.Clear();
			fullScreenToggleSub?.Dispose();
			fullScreenToggleSub = null;
			mapTypeChangedSub?.Dispose();
			mapTypeChangedSub = null;
			pageIndicatorVisibilitySub?.Dispose();
			pageIndicatorVisibilitySub = null;
			MapTypeSelector?.CleanUp();
			MapTypeSelector?.Dispose();
			MapTypeSelector = null;
			phoneSliderTop?.Dispose();
			phoneSliderTop = null;
			phoneSliderBottom?.Dispose();
			phoneSliderBottom = null;
			drawerOpenChangedSub?.Dispose();
			drawerOpenChangedSub = null;
			if (staticFeedFmWidget != null)
			{
				staticFeedFmWidget.Touch -= HandleStaticFeedFmWidgetTapped;
				iFit.Extensions.Android.JavaExtensions.DisposeSafe(staticFeedFmWidget);
				if (feedFmStaticWidgetTitleText != null)
				{
					feedFmStaticWidgetTitleText.Touch -= HandleStaticFeedFmWidgetTapped;
					iFit.Extensions.Android.JavaExtensions.DisposeSafe(feedFmStaticWidgetTitleText);
				}
				if (feedFmStaticWidgetArtistText != null)
				{
					feedFmStaticWidgetArtistText.Touch -= HandleStaticFeedFmWidgetTapped;
					iFit.Extensions.Android.JavaExtensions.DisposeSafe(feedFmStaticWidgetArtistText);
				}
			}
			FrameLayout frameLayout = feedFmNotification;
			feedFmNotification = ((frameLayout != null) ? iFit.Extensions.Android.JavaExtensions.DisposeSafe(frameLayout) : null);
			if (backgroundImageView != null)
			{
				backgroundImageView.SetImageDrawable(null);
				backgroundImageView = iFit.Extensions.Android.JavaExtensions.DisposeSafe(backgroundImageView);
			}
		}

