		private void SetupAndBindPauseResumeExit(MvxFluentBindingDescriptionSet<PhoneInWorkoutView, InWorkoutViewModel> bindingSet)
		{
			VisibilityGoneValueConverter converter = new VisibilityGoneValueConverter();
			InvertedVisibilityGoneValueConverter converter2 = new InvertedVisibilityGoneValueConverter();
			bool flag = false;
			if (Mvx.TryResolve<IDeviceInformation>(out var service) && Mvx.TryResolve<ICurrentConsoleService>(out var service2))
			{
				flag = service2.Console?.ConsoleInfo?.IsClub == true && !service.IsBuiltIn;
			}
			if (flag)
			{
				clubQuitContainer = ((Activity)(object)this).FindViewById<RelativeLayout>(2131427687);
				InWorkoutCircleActionButton inWorkoutCircleActionButton = ((Activity)(object)this).FindViewById<InWorkoutCircleActionButton>(2131427686);
				IfitTextView ifitTextView = ((Activity)(object)this).FindViewById<IfitTextView>(2131427685);
				inWorkoutCircleActionButton.ButtonText = Wolf.Core.Resources.AppStrings.end.ToUpper();
				bindingSet.Bind(inWorkoutCircleActionButton).For(inWorkoutCircleActionButton.ClickEvent()).To((InWorkoutViewModel vm) => vm.StopButtonTapped);
				bindingSet.Bind(ifitTextView).For((IfitTextView x) => x.Visibility).To((InWorkoutViewModel vm) => vm.GoToCooldownButtonVisible)
