		private void SetupMapControls(InWorkoutMapView mapView)
		{
			mapTypeChangedSub?.Dispose();
			mapTypeChangedSub = null;
			if (mapView == null)
			{
				return;
			}
			if (Mvx.TryResolve<ILocalSettings>(out var service))
			{
				MapTypeSelector.SetMapMode(service.MapViewOption);
			}
			mapTypeChangedSub = MapTypeSelector.WhenMapModeChanged.Subscribe(delegate(MapViewOption mapType)
			{
				switch (mapType)
				{
				case MapViewOption.StreetView:
					mapView.ViewModel.DisplayStreetView.Execute(null);
					break;
				case MapViewOption.Map:
					mapView.ViewModel.DisplayMapView.Execute(null);
					break;
				case MapViewOption.Satellite:
					mapView.ViewModel.DisplaySatelliteView.Execute(null);
					break;
				case MapViewOption.Cycle:
					mapView.ViewModel.CycleMapViews.Execute(null);
					break;
				}
			});
		}

		private void DrawerOpenChanged(bool open)
		{
			if (open)
			{
				tapOverlay.Touch += HandleTapOverlayTouchEvent;
			}
			else
			{
				tapOverlay.Touch -= HandleTapOverlayTouchEvent;
			}
		}

		private void HandleTapOverlayTouchEvent(object sender, View.TouchEventArgs e)
		{
			OnViewPagerClicked(sender, e);
		}

		private void OnViewPagerClicked(object sender, EventArgs e)
		{
			if (swipeHelper.IsDrawerOpen && !swipeHelper.IsSwiping)
			{
				swipeHelper.CloseDrawer();
			}
			else if (!swipeHelper.IsSwiping)
			{
				View view = ((!base.ViewModel.IsClubBle) ? ((ViewGroup)pauseResumeScreen) : ((ViewGroup)clubQuitContainer));
				if (!ResumeQuitScreenShown && view != null && ViewStates.Gone == view.Visibility)
				{
					iFit.Logger.Log.Trace("Workout", "Showing PauseResumeScreen from OnPageViewClicked");
					pauseScreenTimer.Start();
					FadeShowPauseResumeScreen(200L);
				}
			}
		}

		private void HandleSwipeEnablingChanges(object sender, EventArgs e)
		{
			swipeHelper.SwipingEnabled = IsSwipeEnabled();
		}

		private bool IsSwipeEnabled()
		{
			if (!base.ViewModel.NavContainerOpen.Value && pageIndicator.SelectedItem == 0 && base.ViewModel.IsMapWorkout)
			{
				return base.ViewModel.WorkoutMode.Value == ConsoleState.Workout;
			}
			return false;
		}

		private void FadeHidePauseResumeScreen(long fadeTimeMilliseconds = 200L, bool hideNotification = false)
		{
			iFit.Logger.Log.Trace("Workout", "FadeHidePauseResumeScreen");
			SafeRunOnUiThread(delegate
			{
				if (!hideNotification)
				{
					feedFmNotification.Visibility = ViewStates.Visible;
				}
				InWorkoutViewModel viewModel = base.ViewModel;
				if (viewModel != null && viewModel.IsClubBle)
				{
					if (ViewStates.Gone == clubQuitContainer.Visibility)
					{
						return;
					}
					ViewAnimatorEndAction viewAnimatorEndAction = new ViewAnimatorEndAction();
					viewAnimatorEndAction.AnimationEnd += delegate
					{
						clubQuitContainer.Visibility = ViewStates.Gone;
						if (hideNotification)
						{
							feedFmNotification.Visibility = ViewStates.Visible;
						}
					};
					clubQuitContainer.Animate().SetDuration(fadeTimeMilliseconds).Alpha(0f)
						.SetListener(null)
						.WithEndAction(viewAnimatorEndAction)
						.Start();
				}
				else
				{
					if (ViewStates.Gone == pauseResumeScreen.Visibility)
					{
						return;
					}
					ViewAnimatorEndAction viewAnimatorEndAction2 = new ViewAnimatorEndAction();
					viewAnimatorEndAction2.AnimationEnd += delegate
					{
						pauseResumeScreen.Visibility = ViewStates.Gone;
						if (hideNotification)
						{
							feedFmNotification.Visibility = ViewStates.Visible;
						}
					};
					pauseResumeScreen.Animate().SetDuration(fadeTimeMilliseconds).Alpha(0f)
						.SetListener(null)
						.WithEndAction(viewAnimatorEndAction2)
						.Start();
				}
				iFit.Logger.Log.Trace("Workout", "Done hiding PauseResumeScreen");
			});
		}

		private void FadeShowPauseResumeScreen(long fadeTimeMilliseconds = 200L)
		{
			iFit.Logger.Log.Trace("Workout", "FadeShowPauseResumeScreen");
			SafeRunOnUiThread(delegate
			{
				feedFmNotification.Visibility = ViewStates.Invisible;
				staticFeedFmWidget?.ResetAnimation();
				InWorkoutViewModel viewModel = base.ViewModel;
				if (viewModel != null && viewModel.IsClubBle)
				{
					clubQuitContainer.Alpha = 0f;
					clubQuitContainer.Visibility = ViewStates.Visible;
					clubQuitContainer.Animate().SetDuration(fadeTimeMilliseconds).Alpha(1f)
						.SetListener(null)
						.Start();
				}
				else
				{
					pauseResumeScreen.Alpha = 0f;
					pauseResumeScreen.Visibility = ViewStates.Visible;
					pauseResumeScreen.Animate().SetDuration(fadeTimeMilliseconds).Alpha(1f)
						.SetListener(null)
						.Start();
				}
				iFit.Logger.Log.Trace("Workout", "Done showing PauseResumeScreen");
			});
		}

		private void PauseResumeScreenDismissHideNotification(object sender, EventArgs e)
		{
			if (pauseResumeScreen != null && ViewStates.Gone != pauseResumeScreen.Visibility)
			{
				iFit.Logger.Log.Trace("Workout", "ResetPauseScreenTimer");
				pauseScreenTimer.Stop();
				base.ViewModel?.MediaService.Music.DismissFeedFmNotification();
				if (!ResumeQuitScreenShown)
				{
					FadeHidePauseResumeScreen(200L, hideNotification: true);
				}
			}
		}

		private void PauseResumeScreenDismiss(object sender, EventArgs e)
		{
			iFit.Logger.Log.Trace("Workout", "PauseResumeScreenDismiss");
			pauseScreenTimer.Stop();
			if (!ResumeQuitScreenShown)
			{
				FadeHidePauseResumeScreen(200L);
			}
		}

		private void PauseResumeScreenDismissFromTimer(object sender, EventArgs e)
		{
			iFit.Logger.Log.Trace("Workout", "PauseResumeScreenDismissFromTimer");
			SafeRunOnUiThread(delegate
			{
				if (staticFeedFmWidget.IsMarqueeAnimating)
				{
					ResetPauseOverlayTimer();
				}
				else if (!ResumeQuitScreenShown)
				{
					FadeHidePauseResumeScreen(500L);
				}
			});
		}

		private void ResetPauseOverlayTimer()
		{
			pauseScreenTimer?.Stop();
			pauseScreenTimer?.Start();
		}

		private void SetupFab()
		{
			CreateTargetFragment(typeof(PhoneInWorkoutFabView).FullName, base.ViewModel);
		}

		protected override void AddFragment(ShireFragment fragment)
		{
			if (!(fragment is PhoneInWorkoutHeaderView))
			{
				if (!(fragment is PhoneInWorkoutFabView phoneInWorkoutFabView))
				{
					if (!(fragment is InWorkoutStreamingVideoView))
					{
						if (fragment is ClosedCaptionsView fragment2)
						{
							AddClosedCaptionsFragment(fragment2);
						}
					}
					else
					{
						AddVideoFragment(fragment);
					}
				}
				else
				{
					fullScreenToggleSub = phoneInWorkoutFabView.WhenFullscreenButtonTapped.Subscribe(OnFullscreenToggled);
					AddFabFragment(phoneInWorkoutFabView);
				}
			}
			else
			{
				AddHeaderFragment(fragment);
			}
		}

		private void AddHeaderFragment(ShireFragment fragment)
		{
			headerView = fragment as PhoneInWorkoutHeaderView;
			if (headerView != null)
			{
				headerView.IsHeaderVisible = !ExpandView;
			}
		}

		private void AddFabFragment(ShireFragment fragment)
		{
			AndroidX.Fragment.App.FragmentTransaction fragmentTransaction = SupportFragmentManager.BeginTransaction().Replace(2131428022, fragment);
			fragmentTransaction.Commit();
		}

		protected virtual void OnFullscreenToggled(bool fullscreenEnabled)
		{
			ExpandView = fullscreenEnabled;
			closedCaptionsView?.ConfigureFullScreenState(fullscreenEnabled);
		}

		private void AddVideoFragment(ShireFragment fragment)
		{
			videoView = fragment as InWorkoutStreamingVideoView;
			SetupClosedCaptions();
		}

		private void ClearViewPager()
		{
			(from x in fragmentInfos
				where x.CachedFragment != null
				select x.CachedFragment).ToList().ForEach(delegate(AndroidX.Fragment.App.Fragment f)
			{
				SupportFragmentManager.BeginTransaction().Remove(f).Commit();
			});
			fragmentInfos.Clear();
		}

		private void RecreatePages()
		{
			iFit.Logger.Log.Trace("Workout", "Recreating PhoneInWorkoutView pages");
			if (fragmentInfos != null && fragmentInfos.Count > 0)
			{
				if (fragmentInfos[0].CachedFragment is IInWorkoutPage inWorkoutPage)
				{
					inWorkoutPage.RemovePhoneHeader();
					inWorkoutPage.PhoneHeader = null;
				}
				ClearViewPager();
			}
			fragmentInfos = _pages.Select(CreatePage).ToList();
			MvxViewPagerFragmentAdapter.FragmentInfo fragmentInfo = fragmentInfos[0];
			Type fragmentType = fragmentInfo.FragmentType;
			Type type = Type.GetType("Wolf.Android.Views.InWorkout.Pages.InWorkoutWarmCoolView,Wolf.Android");
			if (!base.ViewModel.IsStrengthWorkout && fragmentType != type)
			{
				fragmentInfos.Add(CreateHudPage());
			}
			if (fragmentType == typeof(InWorkoutStreamingVideoView))
			{
				fragmentInfo.CachedFragment = videoView;
			}
			fragmentAdapter = new MvxViewPagerFragmentAdapter((Context)(object)this, fragmentInfos, SupportFragmentManager);
			fragmentAdapter.ItemClicked -= OnViewPagerClicked;
			fragmentAdapter.ItemClicked += OnViewPagerClicked;
			viewPager.Adapter = fragmentAdapter;
			viewPager.OffscreenPageLimit = fragmentInfos.Count();
			if (fragmentAdapter.GetItem(0) is InWorkoutMapView mapView)
			{
				SetupMapControls(mapView);
			}
			else
			{
				SetupMapControls(null);
			}
			if (fragmentAdapter.GetItem(0) is IInWorkoutPage inWorkoutPage2)
			{
				SetupHeader();
				inWorkoutPage2.PhoneHeader = headerView;
				if (inWorkoutPage2.PageVisible)
				{
					inWorkoutPage2.LoadPhoneHeader();
				}
				if (_expandView)
				{
					inWorkoutPage2.ToggleFullscreenMode(_expandView);
				}
				if (inWorkoutPage2 is InWorkoutStreamingVideoView inWorkoutStreamingVideoView)
				{
					inWorkoutStreamingVideoView.ClosedCaptionsView = closedCaptionsView;
				}
			}
			if (fragmentAdapter.Count > 1)
			{
				AndroidX.Fragment.App.Fragment item = fragmentAdapter.GetItem(1);
				if (item?.View != null)
				{
					item.View.Visibility = ViewStates.Visible;
				}
			}
		}

		private void PageSelected(object sender, ViewPager.PageSelectedEventArgs e)
		{
			pageIndicator.SelectedItem = e.Position;
			for (int i = 0; i < fragmentInfos.Count; i++)
			{
				if (((fragmentInfos[i]?.CachedFragment is BaseFragment baseFragment) ? baseFragment.ViewModel : null) is InWorkoutPageViewModel inWorkoutPageViewModel)
				{
					inWorkoutPageViewModel.PageIsVisible.Value = i == e.Position;
				}
			}
			swipeHelper.SwipingEnabled = fragmentInfos[e.Position].FragmentType == typeof(InWorkoutMapView) && !base.ViewModel.NavContainerOpen.Value;
		}

		private void PageScrolled(object sender, ViewPager.PageScrolledEventArgs e)
		{
			if (e.Position == 0)
			{
				base.ViewModel.FabExpandEnabled.Value = true;
			}
			else
			{
				base.ViewModel.FabExpandEnabled.Value = false;
			}
		}

		private MvxViewPagerFragmentAdapter.FragmentInfo CreatePage(Type viewModelType)
		{
			IViewTypeLookup viewTypeLookup = Mvx.Resolve<IViewTypeLookup>();
			Type fragmentType = viewTypeLookup.GetFragmentType(viewModelType);
			return new MvxViewPagerFragmentAdapter.FragmentInfo(fragmentType, viewModelType);
		}

		private MvxViewPagerFragmentAdapter.FragmentInfo CreateHudPage()
		{
			Type type = Type.GetType("Wolf.Android.Views.InWorkout.Hud.PhoneInWorkoutStatsHudView,Wolf.Android");
			Type type2 = Type.GetType("Wolf.Core.ViewModels.InWorkout.Hud.InWorkoutStatsHudViewModel,Wolf.Core");
			return new MvxViewPagerFragmentAdapter.FragmentInfo(type, type2);
		}

		public override void OnBackPressed()
		{
			iFit.Logger.Log.Trace("Workout", "Showing PauseResumeScreen from OnBackPressed");
			FadeShowPauseResumeScreen(200L);
		}

		private void ShowSliderControls(object sender, EventArgs e)
		{
			if (!Mvx.TryResolve<ILocalSettings>(out var service) || !service.IsRoboRunMode)
			{
				phoneSliderControls.Alpha = 0f;
				phoneSliderControls.TranslationY = phoneSliderControls.Height;
				phoneSliderControls.Visibility = ViewStates.Visible;
				phoneSliderControls.Animate()?.SetDuration(200L)?.TranslationY(0f)?.Alpha(1f)?.SetListener(null)?.Start();
			}
		}

		private void HideSliderControls(object sender, EventArgs e)
		{
			phoneSliderControls?.Animate()?.SetDuration(200L)?.TranslationY(phoneSliderControls.Height)?.Alpha(0f)?.SetListener(null)?.WithEndAction(new AndroidRunnable(delegate
			{
				phoneSliderControls.Visibility = ViewStates.Gone;
			}))?.Start();
		}

		public override void OnWindowFocusChanged(bool hasFocus)
		{
			((Activity)(object)this).OnWindowFocusChanged(hasFocus);
			if (hasFocus)
			{
				RemoveAllSystemUi();
			}
		}
	}
