	public class WidgetSwipeInterceptingContainer : ConstraintLayout
	{
		private InWorkoutViewModel viewModel;

		private WidgetManager widgetManager;

		private WidgetGesture widgetGesture;

		private System.Drawing.PointF startPoint;

		private bool gestureDirectionNeeded;

		private int headerHeight;

		public WidgetSwipeInterceptingContainer(Context context)
			: base(context)
		{
		}

		public WidgetSwipeInterceptingContainer(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
		}

		public WidgetSwipeInterceptingContainer(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
		}

		public void SetupSwiping(InWorkoutViewModel viewModel, int headerHeight)
		{
			this.viewModel = viewModel;
			widgetManager = viewModel.widgetManager;
			this.headerHeight = headerHeight;
		}

		public override bool OnInterceptTouchEvent(MotionEvent ev)
		{
			if (viewModel.WorkoutMode.Value != ConsoleState.WarmUp && viewModel.WorkoutMode.Value != ConsoleState.Workout && viewModel.WorkoutMode.Value != ConsoleState.CoolDown)
			{
				return false;
			}
			bool result = false;
			if (ev.Action == MotionEventActions.Down)
			{
				startPoint = new System.Drawing.PointF(ev.GetX(), ev.GetY());
				gestureDirectionNeeded = true;
				widgetGesture = null;
			}
			else if (ev.Action == MotionEventActions.Move)
			{
				float x = ev.GetX();
				float y = ev.GetY();
				if (gestureDirectionNeeded)
				{
					SwipeDirection swipeDirection = WidgetGesture.GetSwipeDirection(startPoint, new System.Drawing.PointF(x, y));
					if (swipeDirection != SwipeDirection.NotFarEnough)
					{
						switch (swipeDirection)
						{
						case SwipeDirection.Up:
							viewModel.upSwipeTime = DateTime.Now;
							break;
						case SwipeDirection.Down:
							viewModel.downSwipeTime = DateTime.Now;
							break;
						}
						TimeSpan timeSpan = viewModel.downSwipeTime - viewModel.upSwipeTime;
						if (timeSpan.TotalMilliseconds >= 0.0 && timeSpan.TotalMilliseconds < 400.0)
						{
							iFit.Logger.Log.Trace("WidgetSwipeInterceptingContainer", "Swipe too fast - return false");
							return false;
						}
						gestureDirectionNeeded = false;
						widgetGesture = widgetManager.StartPossibleWidgetGesture(swipeDirection, startPoint, base.Width, base.Height, headerHeight);
					}
				}
				result = widgetGesture?.GestureChanged(new System.Drawing.PointF(x, y)) ?? false;
			}
			return result;
		}

		public override bool OnTouchEvent(MotionEvent e)
		{
			if (e.Action == MotionEventActions.Move)
			{
				widgetGesture?.GestureChanged(new System.Drawing.PointF(e.GetX(), e.GetY()));
			}
			else if (e.Action == MotionEventActions.Up)
			{
				widgetGesture?.GestureEnded(new System.Drawing.PointF(e.GetX(), e.GetY()));
				widgetGesture = null;
			}
			return true;
		}
	}
}
namespace Wolf.Android.Views.InWorkout.Tablet.Notifications
{
	public abstract class BaseNotificationPresenter<TViewModel, TPresenterModel, TData> : IDisposable where TViewModel : NotificationViewModel<TData> where TPresenterModel : BaseNotificationPresenterModel where TData : NotificationData
	{
		private const int DefaultMargin = 8;

		protected readonly BaseActivity View;

		protected readonly WidgetManager WidgetManager;

		private readonly ConcurrentDictionary<string, System.Threading.Tasks.Task> guidsToTasks = new ConcurrentDictionary<string, System.Threading.Tasks.Task>();

		private WidgetLocation _widgetLocation;

		private NotificationWidgetAnimator animator;

		protected bool IsPhone { get; private set; }

		private bool IsActive
		{
			get
			{
				BaseActivity view = View;
				if (view != null && !((Activity)(object)view).IsDestroyed)
				{
					BaseActivity view2 = View;
					if (view2 == null)
					{
						return false;
					}
					return !view2.SupportFragmentManager.IsDestroyed;
				}
				return false;
			}
		}

		public BaseFragment<TViewModel> NotificationView { get; private set; }

		public WidgetLocation WidgetLocation
		{
			get
			{
				return _widgetLocation;
			}
			set
			{
				if (value != _widgetLocation)
				{
					_widgetLocation = value;
					OnWidgetLocationChange(_widgetLocation);
				}
			}
		}

		protected abstract string AnimatorDebugMessage { get; }

		protected int NotificationDismissDistance { get; set; }

		protected abstract bool IsSwipeable { get; }

		protected abstract Type ViewType { get; }

		public TPresenterModel Model { get; protected set; }

		protected BaseNotificationPresenter(BaseActivity workoutView)
		{
			View = workoutView;
			if (!(workoutView is InWorkoutView inWorkoutView))
			{
				if (workoutView is PhoneInWorkoutView phoneInWorkoutView)
				{
					WidgetManager = phoneInWorkoutView.widgetManager;
					IsPhone = true;
				}
			}
			else
			{
				WidgetManager = inWorkoutView.widgetManager;
				IsPhone = false;
			}
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				((Java.Lang.Object)(object)View)?.Dispose();
				Model?.Dispose();
				Model = null;
				NotificationView?.Dispose();
				NotificationView = null;
				WidgetManager?.Remove(animator);
				animator?.Dispose();
				animator = null;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void OnShow(NotificationData notificationData)
		{
		}

		protected virtual void OnDismiss(NotificationData notificationData)
		{
		}

		protected virtual void OnWidgetLocationChange(WidgetLocation widgetLocation)
		{
		}

		private async System.Threading.Tasks.Task CreateNotificationView(string guid)
		{
			if (!IsActive)
			{
				return;
			}
			NotificationView = Activator.CreateInstance(ViewType) as BaseFragment<TViewModel>;
			if (NotificationView == null)
			{
				return;
			}
			NotificationView.ViewModel = Mvx.IocConstruct<TViewModel>();
			await NotificationView.ViewModel.Init(guid);
			if (!IsActive)
			{
				NotificationView.Dispose();
				NotificationView.ViewModel.Dispose();
				return;
			}
			FrameLayout frameLayout = CreateNotificationContainer(guid);
			View.SupportFragmentManager.BeginTransaction().Add(frameLayout.Id, NotificationView).Commit();
			if (NotificationView is IAsyncViewCreator asyncViewCreator)
			{
				await asyncViewCreator.ViewCreated.Task;
			}
		}

		protected abstract ViewGroup GetParentView();

		private void SetupViewMarginTranslations(View view)
		{
			RelativeLayout.LayoutParams layoutParams = new RelativeLayout.LayoutParams(-1, -2);
			layoutParams.MarginStart = 8;
			if (WidgetLocation == WidgetLocation.Left)
			{
				view.TranslationX = -NotificationDismissDistance;
			}
			else if (WidgetLocation == WidgetLocation.Top)
			{
				view.TranslationY = -NotificationDismissDistance;
				layoutParams.TopMargin = 8;
			}
			ViewGroup parentView = GetParentView();
			MainThread.BeginInvokeOnMainThread(delegate
			{
				parentView.AddView(view, layoutParams);
			});
		}

		private void SetupAnimator(string guid)
		{
			animator = new NotificationWidgetAnimator((Activity)(object)View, NotificationView, -NotificationDismissDistance, WidgetState.Off, animateFadeOut: true);
			animator.DestroyViewWhenOff = false;
			animator.Debug = AnimatorDebugMessage + " " + guid;
			animator.Location = WidgetLocation;
			animator.CanSwipeOn = IsSwipeable;
			WidgetManager.Add(WidgetType.Notification, animator);
		}

		private FrameLayout CreateNotificationContainer(string guidId)
		{
			FrameLayout frameLayout = new FrameLayout((Context)(object)View);
			int.TryParse(guidId, out var result);
			frameLayout.Id = result;
			return frameLayout;
		}

		protected void ShowNotification(NotificationData notificationData)
		{
			string guid = notificationData.Id;
			MainThread.InvokeOnMainThreadAsync(async delegate
			{
				TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
				try
				{
					if (guidsToTasks.TryAdd(guid, tcs.Task))
					{
						if (NotificationView != null)
						{
							await ReloadNotification(guid);
						}
						else
						{
							await CreateNotificationView(guid);
							SetupViewMarginTranslations(NotificationView.View);
							SetupAnimator(guid);
						}
						OnShow(notificationData);
						animator?.MoveTo(WidgetState.On);
					}
				}
				catch (System.Exception ex)
				{
					iFit.Logger.Log.Error("Workout", $"Unable to show notification: {ex}", ex);
				}
				finally
				{
					tcs.SetResult(result: true);
				}
			});
		}

		protected void DismissNotification(NotificationData notificationData)
		{
			string guid = notificationData.Id;
			MainThread.InvokeOnMainThreadAsync(async delegate
			{
				TaskCompletionSource<bool> dismissCompletionSource = new TaskCompletionSource<bool>();
				try
				{
					if (guidsToTasks.TryRemove(guid, out var value))
					{
						await value;
						OnDismiss(notificationData);
						animator?.MoveTo(WidgetState.Off);
					}
				}
				catch (System.Exception ex)
				{
					iFit.Logger.Log.Error("Workout", $"Unable to dismiss notification: {ex}", ex);
				}
				finally
				{
					dismissCompletionSource.SetResult(result: true);
				}
			});
		}

		protected abstract System.Threading.Tasks.Task ReloadNotification(string guid);
	}
	public class CoachingNotificationPresenter : BaseNotificationPresenter<CoachingNotificationViewModel, CoachingNotificationsPresenterModel, CoachingMessageNotificationData>
	{
		private readonly bool shouldAutomaticallyShowHeartRateWidget;

		private IDisposable subLeftSideWidgetVisible;

		private NotificationData data;

		protected override string AnimatorDebugMessage => "Coach Notification";

		protected override bool IsSwipeable => true;

		protected override Type ViewType => typeof(CoachingNotificationView);

		public CoachingNotificationPresenter(InWorkoutView inWorkoutView, int notificationDismissDistance, bool shouldAutomaticallyShowHeartRateWidget)
			: base((BaseActivity)inWorkoutView)
		{
			this.shouldAutomaticallyShowHeartRateWidget = shouldAutomaticallyShowHeartRateWidget;
			base.NotificationDismissDistance = notificationDismissDistance;
			base.WidgetLocation = WidgetLocation.Left;
			base.Model = new CoachingNotificationsPresenterModel(Mvx.Resolve<IInAppNotificationService>())
			{
				OnShow = base.ShowNotification,
				OnDismiss = base.DismissNotification
			};
		}

		protected override void OnWidgetLocationChange(WidgetLocation widgetLocation)
		{
			base.OnWidgetLocationChange(widgetLocation);
			subLeftSideWidgetVisible?.Dispose();
			subLeftSideWidgetVisible = null;
			if (widgetLocation == WidgetLocation.Left)
			{
				subLeftSideWidgetVisible = WidgetManager.LeftSideWidgetVisible.Subscribe(OnLeftSideWidgetVisible);
			}
		}

		protected override ViewGroup GetParentView()
		{
			if (base.WidgetLocation == WidgetLocation.Left)
			{
				return ((Activity)(object)View).FindViewById<RelativeLayout>(2131428249);
			}
			return ((Activity)(object)View).FindViewById<LinearLayout>(2131428704);
		}

		protected override void OnShow(NotificationData notificationData)
		{
			base.OnShow(notificationData);
			if (base.WidgetLocation == WidgetLocation.Left)
			{
				data = notificationData;
				WidgetManager.HideLeftSideWidget();
			}
		}

		protected override void OnDismiss(NotificationData notificationData)
		{
			base.OnDismiss(notificationData);
			if (base.WidgetLocation != WidgetLocation.Left)
			{
				return;
			}
			CoachingNotificationsPresenterModel model = base.Model;
			if (model != null && !model.IsRunning)
			{
				data = null;
				CoachingMessageNotificationData coachingMessageNotificationData = notificationData as CoachingMessageNotificationData;
				if (coachingMessageNotificationData.IsMessage(HowlSmartAdjustType.StartOfWarmup) && shouldAutomaticallyShowHeartRateWidget)
				{
					WidgetManager.ToggleHRWidget();
				}
				else
				{
					WidgetManager.RestoreLeftSideWidget();
				}
			}
		}

		protected override async System.Threading.Tasks.Task ReloadNotification(string guid)
		{
			CoachingNotificationView coachingNotificationView = base.NotificationView as CoachingNotificationView;
			await coachingNotificationView.ReloadNotificationData(guid);
			bool isSystemNotification = coachingNotificationView.IsSystemNotification;
			coachingNotificationView.SetTrainingAvatar(isSystemNotification);
		}

		private void OnLeftSideWidgetVisible(bool visible)
		{
			if (visible && data != null)
			{
				DismissNotification(data);
			}
		}
	}
	public class CoachingNotificationView : BaseFragment<CoachingNotificationViewModel>, IAsyncViewCreator
	{
		private const double slop = 8.0;

		private new const string Tag = "CoachingNotificationView";

		private BasicImageView headerIcon;

		private BasicImageView arrowIcon;

		private BasicImageView trainerAvatar;

		private IfitTextView trainerName;

		private View littleCircle;

		private IfitTextView message;

		private BasicImageView messageIcon;

		private IfitTextView notificationTypeText;

		private IfitTextView actionItem;

		private global::Android.Graphics.PointF down = new global::Android.Graphics.PointF();

		private readonly SemaphoreSlim getTrainerImageLock = new SemaphoreSlim(1, 1);

		protected override int LayoutId => 2131624010;

		private Bitmap CachedTrainerBitmap { get; set; }

		public bool IsSystemNotification => base.ViewModel.IsSystemNotification;

		public TaskCompletionSource<bool> ViewCreated { get; set; } = new TaskCompletionSource<bool>();

		public CoachingNotificationArrow Arrow
		{
			get
			{
				return CoachingNotificationArrow.None;
			}
			set
			{
				switch (value)
				{
				case CoachingNotificationArrow.Up:
					arrowIcon.ResourceId = 2131231615;
					break;
				case CoachingNotificationArrow.Down:
					arrowIcon.ResourceId = 2131231612;
					break;
				}
			}
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			trainerAvatar = view.FindViewById<BasicImageView>(2131429627);
			trainerName = view.FindViewById<IfitTextView>(2131429629);
			littleCircle = view.FindViewById<View>(2131428528);
			headerIcon = view.FindViewById<BasicImageView>(2131428181);
			arrowIcon = view.FindViewById<BasicImageView>(2131427461);
			message = view.FindViewById<IfitTextView>(2131428636);
			messageIcon = view.FindViewById<BasicImageView>(2131428637);
			notificationTypeText = view.FindViewById<IfitTextView>(2131428708);
			actionItem = view.FindViewById<IfitTextView>(2131427402);
			MvxFluentBindingDescriptionSet<CoachingNotificationView, CoachingNotificationViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<CoachingNotificationView, CoachingNotificationViewModel>();
			mvxFluentBindingDescriptionSet.Bind(notificationTypeText).For((IfitTextView x) => x.Text).To((CoachingNotificationViewModel vm) => vm.NotificationType);
			mvxFluentBindingDescriptionSet.Bind(trainerAvatar).For((BasicImageView x) => x.Visibility).To((CoachingNotificationViewModel vm) => vm.IsAlertNotification)
				.WithConversion(new InvertedVisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(trainerName).For((IfitTextView x) => x.Text).To((CoachingNotificationViewModel vm) => vm.HeaderTitle);
			mvxFluentBindingDescriptionSet.Bind(littleCircle).For((View x) => x.Visibility).To((CoachingNotificationViewModel vm) => vm.IsAlertNotification)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(this).For((CoachingNotificationView x) => x.Arrow).To((CoachingNotificationViewModel vm) => vm.Arrow)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(message).For((IfitTextView x) => x.Text).To((CoachingNotificationViewModel vm) => vm.Message);
			mvxFluentBindingDescriptionSet.Bind(actionItem).For((IfitTextView x) => x.Visibility).To((CoachingNotificationViewModel vm) => vm.IsActionVisible)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(actionItem).For((IfitTextView x) => x.Text).To((CoachingNotificationViewModel vm) => vm.ActionMessage);
			mvxFluentBindingDescriptionSet.Bind(arrowIcon).For((BasicImageView x) => x.Visibility).To((CoachingNotificationViewModel vm) => vm.IsArrowVisible)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(headerIcon).For((BasicImageView x) => x.ResourceId).To((CoachingNotificationViewModel vm) => vm.TriggerType)
				.WithConversion(new CoachingNotificationIconTypeConverter());
			mvxFluentBindingDescriptionSet.Apply();
			View.Touch -= HandleTouch;
			View.Touch += HandleTouch;
			System.Threading.Tasks.Task.Run(async delegate
			{
				await SetTrainingAvatar(base.ViewModel.IsSystemNotification).ConfigureAwait(continueOnCapturedContext: false);
			});
			ViewCreated.SetResult(result: true);
		}

		private void HandleTouch(object s, View.TouchEventArgs e)
		{
			if (e.Event.Action == MotionEventActions.Up)
			{
				float num = down.X - e.Event.GetX();
				float num2 = down.Y - e.Event.GetY();
				double num3 = System.Math.Sqrt(num * num + num2 * num2);
				if (num3 < 8.0)
				{
					base.ViewModel.ActionSelected.Execute(null);
					e.Handled = true;
				}
				else
				{
					base.ViewModel?.DismissNotification();
				}
			}
			else if (e.Event.Action == MotionEventActions.Down)
			{
				down.X = e.Event.GetX();
				down.Y = e.Event.GetY();
			}
		}

		private async System.Threading.Tasks.Task SetupCoachImage()
		{
			if (!string.IsNullOrEmpty(base.ViewModel.TrainerImageUrl.Value))
			{
				float dimension = base.Resources.GetDimension(2131166911);
				try
				{
					CachedTrainerBitmap = await Shire.Android.Util.ImageUtil.DownloadImage(base.ViewModel.TrainerImageUrl.Value, (int)dimension, (int)dimension);
				}
				catch (System.Exception arg)
				{
					CachedTrainerBitmap = null;
					iFit.Logger.Log.Error("Images", $"Exception thrown and caught while downloading trainer image. {arg}");
				}
			}
		}

		public async System.Threading.Tasks.Task SetTrainingAvatar(bool isSystemNotification)
		{
			if (CachedTrainerBitmap == null)
			{
				await SetupCoachImage();
			}
			Drawable notificationImage = null;
			if (isSystemNotification || CachedTrainerBitmap == null)
			{
				notificationImage = base.Resources.GetDrawable(2131231647, null);
			}
			else
			{
				notificationImage = new BitmapDrawable(base.Resources, CachedTrainerBitmap);
			}
			MainThread.BeginInvokeOnMainThread(delegate
			{
				trainerAvatar.SetImageDrawable(notificationImage);
			});
		}

		public async System.Threading.Tasks.Task Init(string guid)
		{
			await base.ViewModel.Init(guid);
		}

		public async System.Threading.Tasks.Task ReloadNotificationData(string guid)
		{
			await base.ViewModel.ReloadNotificationContent(guid);
		}

		public void ViewModelDispose()
		{
			base.ViewModel.Dispose();
		}

		protected override void CleanUp()
		{
			base.ViewModel?.DismissNotification();
			trainerAvatar?.Dispose();
			trainerAvatar = null;
			headerIcon?.Dispose();
			headerIcon = null;
			arrowIcon?.Dispose();
			arrowIcon = null;
			trainerName?.Dispose();
			trainerName = null;
			littleCircle?.Dispose();
			littleCircle = null;
			message?.Dispose();
			message = null;
			messageIcon?.Dispose();
			messageIcon = null;
			notificationTypeText?.Dispose();
			notificationTypeText = null;
			actionItem?.Dispose();
			actionItem = null;
			CachedTrainerBitmap?.Dispose();
			CachedTrainerBitmap = null;
			if (View != null)
			{
				View.Touch -= HandleTouch;
			}
		}
	}
