namespace Wolf.Android.Views.InWorkout.Pages
{
	public interface IInWorkoutPage
	{
		PhoneInWorkoutHeaderView PhoneHeader { get; set; }

		bool PageVisible { get; }

		IReadOnlyList<View> ElementsHiddenFromPauseOverlay { get; }

		void LoadPhoneHeader();

		void RemovePhoneHeader();

		System.Threading.Tasks.Task ToggleFullscreenMode(bool goFullScreen);
	}
	public abstract class BaseInWorkoutPageView<TViewModel> : BaseClickableFragment<TViewModel>, IInWorkoutPage where TViewModel : InWorkoutPageViewModel
	{
		public bool PageVisible => base.IsVisible;

		public PhoneInWorkoutHeaderView PhoneHeader { get; set; }

		public virtual IReadOnlyList<View> ElementsHiddenFromPauseOverlay => new List<View>();

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			if (!base.IsTablet)
			{
				LoadPhoneHeader();
			}
		}

		public void LoadPhoneHeader()
		{
			if (PhoneHeader != null)
			{
				try
				{
					base.Activity?.SupportFragmentManager.BeginTransaction().Replace(2131428802, PhoneHeader).Commit();
				}
				catch (System.Exception exception)
				{
					iFit.Logger.Log.Error("Workout", "Error loading header in phone workout page", exception);
				}
			}
		}

		public void RemovePhoneHeader()
		{
			if (PhoneHeader != null)
			{
				base.Activity?.SupportFragmentManager?.BeginTransaction().Remove(PhoneHeader).Commit();
				PhoneHeader = null;
			}
		}

		public virtual System.Threading.Tasks.Task ToggleFullscreenMode(bool goFullScreen)
		{
			return System.Threading.Tasks.Task.CompletedTask;
		}
	}
	[FragmentPresentation(typeof(InWorkoutViewModel), 2131429759, true)]
	public class GuestWeightLogModalView : BaseFragment<GuestWeightLogModalViewModel>
	{
		private NumberPicker weightAmountPicker;

		private EditText weightAmountPickerEditText;

		private NumberPicker weightUnitOfMeasurePicker;

		private EditText weightUnitOfMeasurePickerEditText;

		private Button getResultsButton;

		private AppCompatTextView headerText;

		protected override int LayoutId => 2131624102;

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			weightAmountPicker = view.FindViewById<NumberPicker>(2131428159);
			weightUnitOfMeasurePicker = view.FindViewById<NumberPicker>(2131428161);
			getResultsButton = view.FindViewById<Button>(2131428136);
			headerText = view.FindViewById<AppCompatTextView>(2131428160);
			getResultsButton.Text = base.ViewModel.ButtonText;
			headerText.Text = base.ViewModel.HeaderText;
			MvxFluentBindingDescriptionSet<GuestWeightLogModalView, GuestWeightLogModalViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<GuestWeightLogModalView, GuestWeightLogModalViewModel>();
			mvxFluentBindingDescriptionSet.Bind(getResultsButton).For(getResultsButton.ClickEvent()).To((GuestWeightLogModalViewModel vm) => vm.SaveWeight);
			mvxFluentBindingDescriptionSet.Bind(weightAmountPicker).For((NumberPicker x) => x.MinValue).To((GuestWeightLogModalViewModel vm) => vm.WeightMinValue);
			mvxFluentBindingDescriptionSet.Bind(weightAmountPicker).For((NumberPicker x) => x.MaxValue).To((GuestWeightLogModalViewModel vm) => vm.WeightMaxValue);
			mvxFluentBindingDescriptionSet.Bind(weightAmountPicker).For((NumberPicker x) => x.Value).To((GuestWeightLogModalViewModel vm) => vm.SelectedWeight);
			mvxFluentBindingDescriptionSet.Bind(weightAmountPicker).For("NumberPickerChangedValue").To((GuestWeightLogModalViewModel vm) => vm.ValueChanged);
			mvxFluentBindingDescriptionSet.Bind(weightUnitOfMeasurePicker).For("Items").To((GuestWeightLogModalViewModel vm) => vm.WeightUnitOfMeasure)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(weightUnitOfMeasurePicker).For("SelectedItem").To((GuestWeightLogModalViewModel vm) => vm.SelectedUnitOfMeasure);
			mvxFluentBindingDescriptionSet.Apply();
			weightAmountPickerEditText = GetNumberPickerEditText(weightAmountPicker);
			ChangeNumberPickerInputType(weightAmountPickerEditText);
			weightUnitOfMeasurePickerEditText = GetNumberPickerEditText(weightUnitOfMeasurePicker);
			DisableEditTextEditability(weightUnitOfMeasurePickerEditText);
			StyleNumberPickers();
		}

		protected override void CleanUp()
		{
			weightAmountPicker = iFit.Extensions.Android.JavaExtensions.DisposeSafe(weightAmountPicker);
			weightAmountPickerEditText = iFit.Extensions.Android.JavaExtensions.DisposeSafe(weightAmountPickerEditText);
			weightUnitOfMeasurePicker = iFit.Extensions.Android.JavaExtensions.DisposeSafe(weightUnitOfMeasurePicker);
			weightUnitOfMeasurePickerEditText = iFit.Extensions.Android.JavaExtensions.DisposeSafe(weightUnitOfMeasurePickerEditText);
			getResultsButton = iFit.Extensions.Android.JavaExtensions.DisposeSafe(getResultsButton);
			headerText = iFit.Extensions.Android.JavaExtensions.DisposeSafe(headerText);
		}

		private void StyleNumberPickers()
		{
			global::Android.Graphics.Color textColor = new global::Android.Graphics.Color(ContextCompat.GetColor(Context, 2131100449));
			SetNumberPickerTextColor(weightAmountPicker, weightAmountPickerEditText, textColor);
			SetNumberPickerTextColor(weightUnitOfMeasurePicker, weightUnitOfMeasurePickerEditText, textColor);
			static void SetNumberPickerTextColor(NumberPicker picker, EditText pickerEditText, global::Android.Graphics.Color color)
			{
				pickerEditText?.SetTextColor(color);
				try
				{
					Field declaredField = picker.Class.GetDeclaredField("mSelectorWheelPaint");
					declaredField.Accessible = true;
					if (declaredField.Get(picker) is Paint paint)
					{
						paint.Color = color;
					}
					picker.Invalidate();
				}
				catch (NoSuchFieldException)
				{
					iFit.Logger.Log.Error("GuestWeightModal", "SelectorWheelPaint field not found on NumberPicker");
				}
				try
				{
					Field declaredField2 = picker.Class.GetDeclaredField("mSelectionDivider");
					bool accessible = declaredField2.Accessible;
					declaredField2.Accessible = true;
					declaredField2.Set(picker, new ColorDrawable(color));
					declaredField2.Accessible = accessible;
					picker.Invalidate();
				}
				catch (NoSuchFieldException)
				{
					iFit.Logger.Log.Error("GuestWeightModal", "Divider field not found on NumberPicker");
				}
			}
		}

		private EditText GetNumberPickerEditText(NumberPicker picker)
		{
			int childCount = picker.ChildCount;
			return Enumerable.Range(0, childCount).Select(picker.GetChildAt).FirstOrDefault((View x) => x.GetType() == typeof(EditText)) as EditText;
		}

		private void ChangeNumberPickerInputType(EditText editText)
		{
			editText.InputType = InputTypes.ClassNumber;
		}

		private void DisableEditTextEditability(EditText editText)
		{
			editText.Clickable = false;
			editText.Focusable = false;
		}
	}
