		private async void OnMapIsLoaded(object sender, MapIsReadyEventArgs e)
		{
			mapIsLoaded = true;
			map.CurrentMapType = MapType;
			await map.SetRoute(base.ViewModel.Route).ConfigureAwait(continueOnCapturedContext: false);
			map.SetZoomLevelFromRoute();
			if (base.ViewModel?.CurrentMapView != null)
			{
				_currentMapView = base.ViewModel.CurrentMapView.Value;
				UpdateMapView();
			}
		}

		private void UpdateMapView()
		{
			switch (_currentMapView)
			{
			case MapView.Map:
				MapType = MapType.Normal;
				break;
			case MapView.Satellite:
				MapType = MapType.Satellite;
				break;
			}
		}

		private void SubscribeToUserUpdates()
		{
			foreach (IUserPositionUpdate userUpdate in base.ViewModel.UserUpdates)
			{
				userUpdate.PropertyChanged += UpdateMarker;
			}
		}

		private void UnsubscribeFromUserUpdates()
		{
			foreach (IUserPositionUpdate userUpdate in base.ViewModel.UserUpdates)
			{
				userUpdate.PropertyChanged -= UpdateMarker;
			}
		}

		protected async void UpdateMarker(object sender, PropertyChangedEventArgs e)
		{
			await System.Threading.Tasks.Task.Run(() => InWorkoutUserMarker.UpdateMarker(map, sender, e, userToMarkerMap, mapIsLoaded, pageIsActive, Shire.Android.Util.ImageUtil.DrawableToBytesArr(base.Resources, 2131231737)));
		}

		public void LoadPhoneHeader()
		{
			if (PhoneHeader != null)
			{
				try
				{
					AndroidX.Fragment.App.FragmentTransaction fragmentTransaction = base.FragmentManager.BeginTransaction().Replace(2131428802, PhoneHeader);
					fragmentTransaction.Commit();
				}
				catch (System.Exception ex)
				{
					global::Android.Util.Log.Error("Workout", "Error loading header in phone workout page", ex);
				}
			}
		}

		public void RemovePhoneHeader()
		{
			if (PhoneHeader != null)
			{
				AndroidX.Fragment.App.FragmentTransaction fragmentTransaction = base.FragmentManager.BeginTransaction().Remove(PhoneHeader);
				fragmentTransaction.Commit();
				PhoneHeader = null;
			}
		}

		public async System.Threading.Tasks.Task ToggleFullscreenMode(bool goFullScreen)
		{
			if (base.IsAdded && mapViewOptionsContainer != null)
			{
				fullScreenCts?.Cancel();
				fullScreenCts = new CancellationTokenSource();
				int num = (int)(-1f * (base.Resources.GetDimension(2131168152) + base.Resources.GetDimension(2131166666) + 2f * base.Resources.GetDimension(2131166668)));
				await mapViewOptionsContainer.Animate().TranslationY(goFullScreen ? num : 0).SetDuration(200L)
					.SetInterpolator(new AccelerateDecelerateInterpolator())
					.StartWithDisposal(fullScreenCts.Token);
			}
		}

		public override void OnResume()
		{
			base.OnResume();
			map.OnMapIsLoaded += OnMapIsLoaded;
			pageIsActive = true;
			SubscribeToUserUpdates();
			clickRegion.Click += base.OnClick;
			streetViewSwitcher.Click += base.OnClick;
		}

		public override void OnPause()
		{
			base.OnPause();
			map.OnMapIsLoaded -= OnMapIsLoaded;
			pageIsActive = false;
			UnsubscribeFromUserUpdates();
			clickRegion.Click -= base.OnClick;
			streetViewSwitcher.Click -= base.OnClick;
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			if (userToMarkerMap != null)
			{
				userToMarkerMap.Clear();
				userToMarkerMap = null;
			}
		}
	}
