				ConstraintLayout.LayoutParams layoutParams = guideline.LayoutParameters as ConstraintLayout.LayoutParams;
				layoutParams.TopMargin = ((!goFullScreen) ? ((int)base.Resources.GetDimension(2131168152)) : 0);
				guideline.LayoutParameters = layoutParams;
				AndroidX.Transitions.AutoTransition autoTransition = new AndroidX.Transitions.AutoTransition();
				autoTransition.SetDuration(125L);
				AndroidX.Transitions.TransitionManager.BeginDelayedTransition(trackLayout, autoTransition);
				constraintSet.ApplyTo(trackLayout);
			}
			else
			{
				Guideline guideline2 = View.FindViewById<Guideline>(2131427554);
				ConstraintLayout.LayoutParams layoutParams2 = (ConstraintLayout.LayoutParams)guideline2.LayoutParameters;
				Guideline guideline3 = View.FindViewById<Guideline>(2131428508);
				ConstraintLayout.LayoutParams layoutParams3 = (ConstraintLayout.LayoutParams)guideline3.LayoutParameters;
