					base.Resources.GetValue(2131165598, typedValue2, resolveRefs: true);
				}
				layoutParams3.GuidePercent = typedValue2.Float;
				guideline2.LayoutParameters = layoutParams2;
				guideline3.LayoutParameters = layoutParams3;
			}
			return System.Threading.Tasks.Task.CompletedTask;
		}

