		public override System.Threading.Tasks.Task ToggleFullscreenMode(bool goFullScreen)
		{
			if (root == null)
			{
				return System.Threading.Tasks.Task.FromResult(0);
			}
			using (ConstraintSet constraintSet = new ConstraintSet())
			{
				constraintSet.Clone(root);
				if (goFullScreen)
				{
					constraintSet.SetGuidelineBegin(2131428180, 0);
				}
				else
				{
					constraintSet.SetGuidelineBegin(2131428180, workoutHeaderHeightPixels);
				}
				AndroidX.Transitions.AutoTransition autoTransition = new AndroidX.Transitions.AutoTransition();
				autoTransition.SetDuration(125L);
				AndroidX.Transitions.TransitionManager.BeginDelayedTransition(root, autoTransition);
				constraintSet.ApplyTo(root);
			}
			return System.Threading.Tasks.Task.CompletedTask;
		}

		public override void OnConfigurationChanged(global::Android.Content.Res.Configuration newConfig)
		{
			base.OnConfigurationChanged(newConfig);
			if (base.ViewModel.IsStrengthMirror && newConfig.Orientation == global::Android.Content.Res.Orientation.Portrait && newConfig.SmallestScreenWidthDp > 800)
			{
				ConstraintSet constraintSet = new ConstraintSet();
				constraintSet.Clone(root);
				constraintSet.SetGuidelinePercent(2131428492, base.Resources.GetFloat(2131168093));
				constraintSet.SetGuidelinePercent(2131429108, base.Resources.GetFloat(2131168088));
				constraintSet.SetGuidelinePercent(2131429763, base.Resources.GetFloat(2131168094));
				constraintSet.SetGuidelinePercent(2131429764, base.Resources.GetFloat(2131168096));
				constraintSet.SetGuidelinePercent(2131429762, base.Resources.GetFloat(2131168095));
				constraintSet.Clear(2131429741, 4);
				constraintSet.Clear(2131428290, 3);
				constraintSet.Connect(2131428290, 3, 2131428180, 3);
				constraintSet.ApplyTo(root);
			}
		}

		private void BoldText(IfitTextView textView, string fullStr, string highlightPart)
		{
			SpannableStringBuilder spannableStringBuilder = new SpannableStringBuilder(fullStr);
			if (fullStr.Contains(highlightPart))
			{
				int num = fullStr.IndexOf(highlightPart);
				int end = num + highlightPart.Length;
				IfitCustomTypefaceSpan what = new IfitCustomTypefaceSpan(IfitTypeface.Type.ProximaBold);
				spannableStringBuilder.SetSpan(what, num, end, SpanTypes.InclusiveInclusive);
			}
			textView.TextFormatted = spannableStringBuilder;
		}

		protected override void CleanUp()
		{
			headerLabel?.Dispose();
			headerLabel = null;
			remainingTime?.Dispose();
			remainingTime = null;
			skipButton?.Dispose();
			skipButton = null;
			loadingVideoProgress?.Dispose();
			loadingVideoProgress = null;
			badConnectionLabel?.Dispose();
			badConnectionLabel = null;
			addWeightButton?.Dispose();
			addWeightButton = null;
			bluetoothButton?.Dispose();
			bluetoothButton = null;
			if (modalContainer != null)
			{
				modalContainer.Visibility = ViewStates.Gone;
				modalContainer.Dispose();
				modalContainer = null;
			}
		}
	}
