		public override RecyclerView.ViewHolder OnCreateViewHolder(ViewGroup parent, int viewType)
		{
			MvxAndroidBindingContext mvxAndroidBindingContext = new MvxAndroidBindingContext(parent.Context, base.BindingContext.LayoutInflaterHolder);
			View itemView = InflateViewForHolder(parent, viewType, mvxAndroidBindingContext);
			LeaderboardParticipantItemView leaderboardParticipantItemView = new LeaderboardParticipantItemView(itemView, mvxAndroidBindingContext)
			{
				Click = base.ItemClick,
				LongClick = base.ItemLongClick
			};
			participants.Add(leaderboardParticipantItemView);
			return leaderboardParticipantItemView;
		}

		protected override View InflateViewForHolder(ViewGroup parent, int viewType, IMvxAndroidBindingContext bindingContext)
		{
			return bindingContext.BindingInflate(2131624179, parent, attachToParent: false);
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				foreach (LeaderboardParticipantItemView participant in participants)
				{
					participant.DisposeIfDisposable();
				}
			}
			base.Dispose(disposing);
		}
