namespace Wolf.Android.Views.InWorkout.Hud
{
	public class BackgroundHeartRateZonesYAxisRenderer : BackgroundLimitLineYAxisRenderer
	{
		private readonly int hrMax;

		private Paint BackgroundPaint { get; set; }

		private Paint BorderPaint { get; set; }

		public BackgroundHeartRateZonesYAxisRenderer(ViewPortHandler viewPortHandler, YAxis yAxis, Transformer trans, int hrMax)
			: base(viewPortHandler, yAxis, trans)
		{
			BackgroundPaint = new Paint();
			BackgroundPaint.SetStyle(Paint.Style.Fill);
			BorderPaint = new Paint();
			BorderPaint.SetStyle(Paint.Style.Stroke);
			this.hrMax = hrMax;
		}

		public override void RenderLimitLines(Canvas canvas)
		{
			IList<LimitLine> limitLines = base.MYAxis.LimitLines;
			if (limitLines == null || limitLines.Count <= 0)
			{
				return;
			}
			float[] array = new float[2] { 0f, hrMax };
			base.MTrans.PointValuesToPixel(array);
			float num = array[1];
			float num2 = base.MLimitLinePaint.MeasureText(limitLines.Last().Label);
			foreach (LimitLine item in limitLines.OrderByDescending((LimitLine limitLine) => limitLine.Limit))
			{
				if (!item.Enabled)
				{
					continue;
				}
				base.MLimitLinePaint.SetStyle(Paint.Style.Fill);
				base.MLimitLinePaint.Color = new global::Android.Graphics.Color(item.LineColor);
				base.MLimitLinePaint.StrokeWidth = item.LineWidth;
				base.MLimitLinePaint.SetPathEffect(item.DashPathEffect);
				array[1] = item.Limit;
				base.MTrans.PointValuesToPixel(array);
				canvas.DrawRect(base.MViewPortHandler.ContentLeft(), num, base.MViewPortHandler.ContentRight(), array[1], base.MLimitLinePaint);
				string label = item.Label;
				if (string.IsNullOrEmpty(label))
				{
					continue;
				}
				BackgroundLimitLine backgroundLimitLine = item as BackgroundLimitLine;
				float num3 = 0f;
				float num4 = 0f;
				float num5 = 0f;
				if (backgroundLimitLine != null)
				{
					BackgroundPaint.Color = backgroundLimitLine.BackgroundColor;
					BorderPaint.Color = backgroundLimitLine.BorderColor;
					num3 = Utils.ConvertDpToPixel(backgroundLimitLine.PaddingHorizontal);
					num4 = num3 * 2f;
					num5 = num2;
				}
				base.MLimitLinePaint.SetStyle(item.TextStyle);
				base.MLimitLinePaint.SetPathEffect(null);
				base.MLimitLinePaint.Color = new global::Android.Graphics.Color(item.TextColor);
				base.MLimitLinePaint.SetTypeface(item.Typeface);
				base.MLimitLinePaint.StrokeWidth = 0.5f;
				base.MLimitLinePaint.TextSize = item.TextSize;
				float num6 = Utils.CalcTextHeight(base.MLimitLinePaint, label);
				float num7 = array[1] - num;
				float num8 = num7 * 0.28f;
				float num9 = Utils.ConvertDpToPixel(4f) + item.XOffset;
				LimitLine.LimitLabelPosition labelPosition = item.LabelPosition;
				if (labelPosition == LimitLine.LimitLabelPosition.RightTop)
				{
					base.MLimitLinePaint.TextAlign = Paint.Align.Left;
					float num10 = base.MViewPortHandler.ContentRight() - num9;
					float num11 = num + num8;
					float num12 = array[1] - num8;
					if (backgroundLimitLine != null)
					{
						float left = num10 - num5 - num4;
						canvas.DrawRoundRect(left, num11, num10, num12, 1f, 1f, BackgroundPaint);
						canvas.DrawRoundRect(left, num11, num10, num12, 1f, 1f, BorderPaint);
					}
					float num13 = num12 - num11;
					float num14 = (num13 - num6) / 2f;
					float x = num10 - num5 - num3;
					float y = num12 - num14;
					canvas.DrawText(label, x, y, base.MLimitLinePaint);
				}
				num = array[1];
			}
		}
	}
	public interface IHudView : IDisposable
	{
		InWorkoutHeaderHudType PageType { get; }

		bool HudVisible { get; set; }

		bool IsEnabled { get; set; }

		bool HandleTouchedInHeader(MotionEvent start, MotionEvent end);

		void SetHudActiveState(bool active);
	}
	public abstract class BaseHudView<TViewModel> : BaseFragment<TViewModel>, IHudView, IDisposable where TViewModel : BaseHudViewModel
	{
		private bool _isVisible;

		private bool _isEnabled;

		protected ViewStub viewStub;

		protected bool isInflated;

		public abstract InWorkoutHeaderHudType PageType { get; }

		public bool HudVisible
		{
			get
			{
				return _isVisible;
			}
			set
			{
				_isVisible = value;
				if (_isVisible && !isInflated)
				{
					InflateIfNeeded();
					if (isInflated)
					{
						SetupViewAndBind();
					}
				}
				if (View != null)
				{
					View.Visibility = ((!_isVisible) ? ViewStates.Invisible : ViewStates.Visible);
				}
			}
		}

		public bool IsEnabled
		{
			get
			{
				return _isEnabled;
			}
			set
			{
				_isEnabled = value;
				if (View != null)
				{
					View.Enabled = value;
				}
			}
		}

		protected bool IsActive { get; set; }

		protected virtual int? viewStubId { get; }

		public abstract bool HandleTouchedInHeader(MotionEvent start, MotionEvent end);

		public override View OnCreateView(LayoutInflater inflater, ViewGroup container, Bundle savedInstanceState)
		{
			View view = base.OnCreateView(inflater, container, savedInstanceState);
			if (viewStubId.HasValue)
			{
				viewStub = view.FindViewById<ViewStub>(viewStubId.Value);
				InflateIfNeeded();
			}
			else
			{
				isInflated = true;
			}
			return view;
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			if (isInflated)
			{
				SetupViewAndBind();
			}
			View.Visibility = ((!HudVisible) ? ViewStates.Invisible : ViewStates.Visible);
			View.Enabled = IsEnabled;
		}

		private void InflateIfNeeded()
		{
			if (viewStub != null && !isInflated && HudVisible)
			{
				iFit.Logger.Log.Trace("Workout", "Inflating ViewStub for layout " + base.Resources.GetResourceEntryName(viewStub.LayoutResource));
				viewStub.Inflate();
				viewStub = null;
				isInflated = true;
			}
		}

		protected abstract void SetupViewAndBind();

		protected virtual void MadeActive()
		{
		}

		protected virtual void MadeInactive()
		{
		}

		public void SetHudActiveState(bool active)
		{
			if (active)
			{
				IsActive = true;
				MadeActive();
			}
			else
			{
				IsActive = false;
				MadeInactive();
			}
		}
	}
