		private void SetupSwitch(IfitSwitch toggle, ICommand toggleCommand, string text, SplatColor color)
		{
			toggle.Text = text;
			toggle.TrackTintMode = PorterDuff.Mode.SrcIn;
			toggle.TrackTintList = new ColorStateList(new int[2][]
			{
				new int[1] { 16842912 },
				new int[0]
			}, new int[2]
			{
				color.ToNative(),
				HexColorCache.Get("DFE2E4").ToNative()
			});
			Observables.Add(Observable.FromEventPattern(delegate(EventHandler<CompoundButton.CheckedChangeEventArgs> h)
			{
				toggle.CheckedChange += h;
			}, delegate(EventHandler<CompoundButton.CheckedChangeEventArgs> h)
			{
				toggle.CheckedChange -= h;
			}).Subscribe(delegate(EventPattern<CompoundButton.CheckedChangeEventArgs> e)
			{
				toggleCommand.Execute(new ToggleViewToggledEventArgs(e.EventArgs.IsChecked, byUserTap: true));
			}));
		}

		private void StyleChart()
		{
			ViewPortHandler viewPortHandler = chartController.LineChart.ViewPortHandler;
			YAxis axisRight = chartController.LineChart.AxisRight;
			Transformer transformer = chartController.LineChart.RendererRightYAxis.Transformer;
			ChartAnimator animator = chartController.LineChart.Animator;
			chartController.LineChart.RendererRightYAxis = new BackgroundHeartRateZonesYAxisRenderer(viewPortHandler, axisRight, transformer, base.ViewModel.HrMax);
			chartController.LineChart.Renderer = new StrokeCapJoinLineChartRenderer(chartController.LineChart, animator, viewPortHandler);
			chartController.XAxisFormatter = new XAxisValueFormatter(base.ViewModel.XAxisFormatter);
			chartController.ShowLeftAxis = true;
			chartController.ShowRightAxis = true;
			chartController.LineChart.AxisLeft.AxisLineColor = inWorkoutChartAxisColor;
			chartController.LineChart.AxisLeft.AxisLineWidth = 1f;
			chartController.LineChart.AxisLeft.SetDrawAxisLine(enabled: true);
			chartController.LineChart.AxisRight.AxisLineColor = inWorkoutChartAxisColor;
			chartController.LineChart.AxisRight.AxisLineWidth = 1f;
			chartController.LineChart.AxisRight.SetDrawAxisLine(enabled: true);
			chartController.CurrentLimitLineColor = Colors.NamedBFBFC0.ToNative();
			ConfigureMetricStyle(chartController.Metric1, chartController, 0);
			ConfigureMetricStyle(chartController.Metric2, chartController, 1);
			ConfigureMetricStyle(chartController.Metric3, chartController, 2);
			ConfigureMetricStyle(chartController.Metric4, chartController, 3);
			ConfigureMetricStyle(chartController.Metric5, chartController, 4);
			ConfigureMetricStyle(chartController.Metric6, chartController, 5);
			ConfigureMetricStyle(chartController.Metric7, chartController, 6);
			ConfigureMetricStyle(chartController.Metric8, chartController, 7);
			ConfigureMetricStyle(chartController.Metric9, chartController, 8);
			if (base.ViewModel.IsHeartRateZoneFeatureEnabled)
			{
				ConfigureMetricStyle(chartController.Metric10, chartController, 9);
			}
			ConfigureCurrentStyle(chartController.CurrentMetric, chartController, 0);
			ConfigureCurrentStyle(chartController.CurrentMetric2, chartController, 1);
			ConfigureCurrentStyle(chartController.CurrentMetric3, chartController, 2);
			ConfigureCurrentStyle(chartController.CurrentMetric4, chartController, 3);
			ConfigureCurrentStyle(chartController.CurrentMetric5, chartController, 4);
			ConfigureCurrentStyle(chartController.CurrentMetric6, chartController, 5);
			ConfigureMetricAxis(chartController.Metric1, chartController, 0);
			ConfigureMetricAxis(chartController.Metric2, chartController, 1);
			ConfigureMetricAxis(chartController.Metric3, chartController, 2);
			ConfigureMetricAxis(chartController.Metric4, chartController, 3);
			ConfigureMetricAxis(chartController.Metric5, chartController, 4);
			ConfigureMetricAxis(chartController.Metric6, chartController, 5);
			ConfigureMetricAxis(chartController.Metric7, chartController, 6);
			ConfigureMetricAxis(chartController.Metric8, chartController, 7);
			ConfigureMetricAxis(chartController.Metric9, chartController, 8);
			ConfigureCurrentAxis(chartController.CurrentMetric, chartController, 0);
			ConfigureCurrentAxis(chartController.CurrentMetric2, chartController, 1);
			ConfigureCurrentAxis(chartController.CurrentMetric3, chartController, 2);
			ConfigureCurrentAxis(chartController.CurrentMetric4, chartController, 3);
			ConfigureCurrentAxis(chartController.CurrentMetric5, chartController, 4);
			ConfigureCurrentAxis(chartController.CurrentMetric6, chartController, 5);
			chartController.LineChart.ExtraBottomOffset = 4f;
			chartController.StyleAxisLabels(chartController.LineChart.AxisLeft, inWorkoutChartHudTextColor);
			chartController.StyleAxisLabels(chartController.LineChart.AxisRight, inWorkoutChartHudTextColor);
			chartController.StyleAxisLabels(chartController.LineChart.XAxis, inWorkoutChartHudTextColor);
			if (base.ViewModel.IsHeartRateZoneFeatureEnabled)
			{
				ConfigureMetricStyle(chartController.Metric10, chartController, 9);
				chartController.Metric10.CustomStyleMetric = delegate(LineDataSet lineSet)
				{
					chartController.StyleMetric(lineSet, base.ViewModel.HRPredictedModel.DataConfig);
				};
				chartController.Metric10.Axis = chartController.GetMetricAxis(!base.ViewModel.HRPredictedModel.DataConfig.IsLeftAxis);
			}
		}

		private void ConfigureMetricStyle(ChartMetric metric, InWorkoutLineChart chart, int index)
		{
			metric.CustomStyleMetric = delegate(LineDataSet lineSet)
			{
				chartController.StyleMetric(lineSet, base.ViewModel.ChartData.MetricModels[index]?.DataConfig);
			};
		}

		private void ConfigureCurrentStyle(ChartMetric metric, InWorkoutLineChart chart, int index)
		{
			metric.CustomStyleMetric = delegate(LineDataSet lineSet)
			{
				chart.StyleCurrentValue(lineSet, base.ViewModel.ChartData.CurrentMetrics[index]?.DataConfig);
			};
		}

		private void ConfigureMetricAxis(ChartMetric metric, InWorkoutLineChart chart, int index)
		{
			metric.Axis = chart.GetMetricAxis(base.ViewModel.ChartData.MetricModels[index]?.DataConfig.IsLeftAxis ?? true);
		}

		private void ConfigureCurrentAxis(ChartMetric metric, InWorkoutLineChart chart, int index)
		{
			metric.Axis = chart.GetMetricAxis(base.ViewModel.ChartData.CurrentMetrics[index]?.DataConfig.IsLeftAxis ?? true);
		}

		private void OnHRZonesUpdated(IReadOnlyList<UserHeartRateZone> zones)
		{
			zoneLines?.ForEach(delegate(BackgroundLimitLine x)
			{
				chartController.RemoveLimitLine(YAxis.AxisDependency.Right, x);
			});
			zoneLines = new List<BackgroundLimitLine>();
			foreach (UserHeartRateZone zone in zones)
			{
				string label = string.Format(Wolf.Core.Resources.AppStrings.zone_num, zone.ZoneNumber).ToUpperInvariant();
				BackgroundLimitLine item = new BackgroundLimitLine(zone.MinBpm, label)
				{
					LineColor = ((zones.GetPosition(zone) % 2 == 1) ? global::Android.Graphics.Color.Transparent : inWorkoutChartHudLimitColor),
					BackgroundColor = zone.GetColorForTargetWidget().ToNative(),
					TextColor = global::Android.Graphics.Color.White,
					Typeface = IfitTypeface.GetCustomTypeface(IfitTypeface.Type.ProximaSemibold),
					TextSize = base.Resources.GetInteger(2131492896),
					PaddingVertical = base.Resources.GetInteger(2131492895),
					PaddingHorizontal = base.Resources.GetInteger(2131492894),
					LineWidth = 2f
				};
				zoneLines.Add(item);
			}
			if (_showZoneLines)
			{
				zoneLines?.ForEach(delegate(BackgroundLimitLine x)
				{
					chartController.AddLimitLine(YAxis.AxisDependency.Right, x);
				});
			}
		}

		public void ForceUpdateChart()
		{
			if (chartController != null)
			{
				System.Threading.Tasks.Task.Run(async delegate
				{
					await chartController.ApplyChangesAndUpdate().ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		protected override void MadeInactive()
		{
			base.MadeInactive();
			ShouldBeInvalidatingChart = false;
		}

		protected override void MadeActive()
		{
			base.MadeActive();
			ShouldBeInvalidatingChart = true;
			ForceUpdateChart();
		}
	}
