		private void HandleRemainingText1Tapped(object sender, View.TouchEventArgs e)
		{
			if (!isRemainingText1Animating && !isDisposed)
			{
				animationCts = new CancellationTokenSource();
				MarqueeText(remainingText1ScrollView, remainingText1, animationCts.Token, isFirstRemainingText: true);
			}
		}

		private void HandleRemainingText2Tapped(object sender, View.TouchEventArgs e)
		{
			if (!isRemainingText2Animating && !isDisposed)
			{
				animationCts = new CancellationTokenSource();
				MarqueeText(remainingText2ScrollView, remainingText2, animationCts.Token, isFirstRemainingText: false);
			}
		}

		private async Task<bool> MarqueeText(HorizontalScrollView scrollView, TextView textView, System.Threading.CancellationToken ctx, bool isFirstRemainingText)
		{
			RegisterAnimationStart(isFirstRemainingText);
			scrollView.ScrollTo(0, 0);
			TextPaint paint = textView.Paint;
			Rect rect = new Rect();
			string text = textView.Text;
			paint.GetTextBounds(text, 0, text.Length, rect);
			int num = rect.Width() - scrollView.Width;
			if (num <= 0)
			{
				RegisterAnimationStop(isFirstRemainingText);
				return false;
			}
			long duration = (long)System.Math.Round((float)num / 50f * 1000f);
			Animator animator = ObjectAnimator.OfInt(scrollView, "scrollX", num).SetDuration(duration);
			animator.SetInterpolator(new LinearInterpolator());
			Animator animator2 = ObjectAnimator.OfInt(scrollView, "scrollX", default(int)).SetDuration(duration);
			animator2.SetInterpolator(new LinearInterpolator());
			animator2.StartDelay = 1250L;
			AnimatorSet animatorSet = new AnimatorSet();
			animatorSet.PlaySequentially(animator, animator2);
			await animatorSet.StartWithDisposal(ctx);
			RegisterAnimationStop(isFirstRemainingText);
			return true;
		}

		private void RegisterAnimationStart(bool isFirstRemainingText)
		{
			if (isFirstRemainingText)
			{
				isRemainingText1Animating = true;
			}
			else
			{
				isRemainingText2Animating = true;
			}
		}

		private void RegisterAnimationStop(bool isFirstRemainingText)
		{
			if (isFirstRemainingText)
			{
				isRemainingText1Animating = false;
			}
			else
			{
				isRemainingText2Animating = false;
			}
		}

		private void CancelAnimation()
		{
			animationCts?.Cancel();
			animationCts?.Dispose();
			animationCts = null;
		}

