			bindingSet.Bind(phoneHudFlipperContainer3).For((PhoneHudFlipperContainer v) => v.MetricGroup).To((InWorkoutStatsHudViewModel vm) => vm.MetricGroupBottomLeft)
				.OneWay();
			bindingSet.Bind(phoneHudFlipperContainer4).For((PhoneHudFlipperContainer v) => v.MetricGroup).To((InWorkoutStatsHudViewModel vm) => vm.MetricGroupTopRight)
				.OneWay();
			if (phoneHudFlipperContainer5 != null)
			{
				bindingSet.Bind(phoneHudFlipperContainer5).For((PhoneHudFlipperContainer v) => v.MetricGroup).To((InWorkoutStatsHudViewModel vm) => vm.MetricGroupCenterRight)
