		private void SetupGoalConstraintsAndVisibility(PhoneCircleProgress circleProgress)
		{
			bool flag = !base.ViewModel.GoalDistanceMeters.Value.AlmostEqual(0.0);
			circleProgress.FindViewById<TextView>(2131428142).Visibility = ((!flag) ? ViewStates.Gone : ViewStates.Visible);
			circleProgress.FindViewById<TextView>(2131428144).Visibility = ((!flag) ? ViewStates.Gone : ViewStates.Visible);
			circleProgress.FindViewById<TextView>(2131428143).Visibility = ((!flag) ? ViewStates.Gone : ViewStates.Visible);
			ConstraintSet constraintSet = new ConstraintSet();
			constraintSet.Clone(circleProgress);
			float bias = base.Resources.GetFloat(flag ? 2131167067 : 2131167065);
			float bias2 = base.Resources.GetFloat(flag ? 2131167064 : 2131167062);
			constraintSet.SetVerticalBias(2131427753, bias);
			constraintSet.SetVerticalBias(2131427752, bias2);
			constraintSet.ApplyTo(circleProgress);
		}

		private ViewGroup SetupColumn(View parent, INC<bool> showThreeMetricGroups, int threeFlipperResId, int twoFlipperResId)
		{
			ViewGroup viewGroup = parent.FindViewById<ViewGroup>(threeFlipperResId);
			ViewGroup viewGroup2 = parent.FindViewById<ViewGroup>(twoFlipperResId);
			if (showThreeMetricGroups.Value)
			{
				viewGroup2.Visibility = ViewStates.Gone;
				return viewGroup;
			}
			viewGroup.Visibility = ViewStates.Gone;
			return viewGroup2;
		}

		private void HandleTouchEvent(object sender, View.TouchEventArgs e)
		{
			switch (e.Event.ActionMasked)
			{
			case MotionEventActions.Down:
				touchDownEvent = MotionEvent.Obtain(e.Event);
				break;
			case MotionEventActions.Cancel:
				touchDownEvent = null;
				break;
			case MotionEventActions.Up:
				e.Handled = View.TouchesRepresentClick(touchDownEvent, e.Event) && EvaluateClick(e.Event);
				touchDownEvent = null;
				break;
			case MotionEventActions.Move:
				break;
			}
		}

		private bool EvaluateClick(MotionEvent touchUpEvent)
		{
			for (int i = 0; i < flippers.Count; i++)
			{
				if (flippers[i].ContainsStartAndEndTouch(touchDownEvent, touchUpEvent))
				{
					flippers[i].MoveToNextIndex();
					return true;
				}
			}
			return false;
		}

		protected override void CleanUp()
		{
		}
	}
