	internal static class HeadphonePickerUtils
	{
		public static MvxRecyclerView Init<T, TViewModel>(View view, HeadphonePickerViewModel viewModel, Context context, IMvxAndroidBindingContext bindingContext, MvxFluentBindingDescriptionSet<T, TViewModel> bindingSet, bool headLess) where T : class, IMvxBindingContextOwner where TViewModel : HeadphonePickerViewModel
		{
			AppCompatTextView appCompatTextView = view.FindViewById<AppCompatTextView>(2131428186);
			AppCompatTextView appCompatTextView2 = view.FindViewById<AppCompatTextView>(2131428187);
			View view2 = view.FindViewById<View>(2131429609);
			View view3 = view.FindViewById<View>(2131427552);
			AppCompatTextView appCompatTextView3 = view.FindViewById<AppCompatTextView>(2131428534);
			AppCompatTextView appCompatTextView4 = view.FindViewById<AppCompatTextView>(2131428534);
			CircularLoadingView childTarget = view.FindViewById<CircularLoadingView>(2131428532);
			appCompatTextView.Text = viewModel.HeaderText;
			appCompatTextView2.Text = viewModel.InstructionsText;
			appCompatTextView4.Text = viewModel.LoadingText;
			if (headLess)
			{
				appCompatTextView.SetTextColor(ContextCompat.GetColorStateList(context, 2131099986));
				appCompatTextView2.SetTextColor(ContextCompat.GetColorStateList(context, 2131099986));
				appCompatTextView3.SetTextColor(ContextCompat.GetColorStateList(context, 2131099986));
				view2.SetBackgroundResource(2131099983);
				view3.SetBackgroundResource(2131099983);
			}
			MvxRecyclerView mvxRecyclerView = view.FindViewById<MvxRecyclerView>(2131428190);
			mvxRecyclerView.SetLayoutManager(new LinearLayoutManager(context));
			mvxRecyclerView.Adapter = new HeadphonePickerItemAdapter(bindingContext, headLess);
			HeadphoneDeviceLoadingVisibilityConverter converter = new HeadphoneDeviceLoadingVisibilityConverter();
			bindingSet.Bind(mvxRecyclerView).For((MvxRecyclerView x) => x.ItemsSource).To((TViewModel x) => x.Devices);
			bindingSet.Bind(mvxRecyclerView).For((MvxRecyclerView x) => x.ItemClick).To((TViewModel x) => x.HandleConnection);
			bindingSet.Bind(appCompatTextView4).For((AppCompatTextView x) => x.Visibility).To((TViewModel x) => x.Devices.Count)
				.WithConversion(converter);
			bindingSet.Bind(childTarget).For((CircularLoadingView x) => x.Visibility).To((TViewModel x) => x.Devices.Count)
				.WithConversion(converter);
			return mvxRecyclerView;
		}

		public static void CleanUp(MvxRecyclerView headphoneList)
		{
			if (headphoneList != null)
			{
				headphoneList.Adapter = null;
				headphoneList.Dispose();
			}
		}
	}
