		private class ChartHeaderYAxisRenderer : YAxisRenderer
		{
			private readonly float avoidClippedLabelOffset;

			public ChartHeaderYAxisRenderer(Resources resources, ViewPortHandler viewPortHandler, YAxis yAxis, Transformer trans)
				: base(viewPortHandler, yAxis, trans)
			{
				avoidClippedLabelOffset = resources.DisplayMetrics.Density * -8f;
			}

			protected override void DrawYLabels(Canvas canvas, float fixedPosition, float[] positions, float offset)
			{
				for (int i = 0; i < base.MYAxis.MEntryCount; i++)
				{
					string formattedLabel = base.MYAxis.GetFormattedLabel(i);
					if (!base.MYAxis.IsDrawTopYLabelEntryEnabled && i >= base.MYAxis.MEntryCount - 1)
					{
						break;
					}
					canvas.DrawText(formattedLabel, fixedPosition, positions[i * 2 + 1] + offset + avoidClippedLabelOffset, base.MAxisLabelPaint);
				}
			}
		}

		private InWorkoutLineChart chartController;

		private ViewStub chartHeaderViewStub;

		private List<TabletStatsFlipperItem> metricViews;

