		{
			if (base.ViewModel?.ViewModelInitialized != null)
			{
				base.ViewModel.ViewModelInitialized.Changed -= ApplyBindings;
			}
			if (chartController != null)
			{
				chartController.ClearCustomStyleActions();
				chartController.Dispose();
				chartController = null;
