		private void ApplyBindings(object sender = null, EventArgs e = null)
		{
			metricViews = new List<TabletStatsFlipperItem>
			{
				View.FindViewById<TabletStatsFlipperItem>(2131427630),
				View.FindViewById<TabletStatsFlipperItem>(2131427631),
				View.FindViewById<TabletStatsFlipperItem>(2131427632),
				View.FindViewById<TabletStatsFlipperItem>(2131427633)
			};
			if (base.Resources.GetBoolean(2131034118) || base.Resources.GetBoolean(2131034119))
			{
				metricViews[1].Visibility = ViewStates.Gone;
			}
			for (int i = 0; i < System.Math.Min(metricViews.Count, base.ViewModel.Metrics.Count); i++)
			{
				if (metricViews[i] != null)
				{
					metricViews[i].Metric = (MetricBase)base.ViewModel.Metrics[i];
				}
			}
			bool flag = CheckIfTreadmill();
			FrameLayout frameLayout = View.FindViewById<FrameLayout>(2131427629);
			chartController = new InWorkoutLineChart((Context)(object)base.Activity);
