			chartController.Metric2.Scaler = base.ViewModel.Metric2Scaler;
			chartController.CurrentMetric2.Scaler = base.ViewModel.Metric2Scaler;
			if (chartController.Metric2.Scaler != null)
			{
				chartController.Metric2.ReconstructOnUnitChange = true;
				chartController.CurrentMetric2.ReconstructOnUnitChange = true;
			}
			MvxFluentBindingDescriptionSet<ChartsHeaderPageView, ChartsHeaderPageViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<ChartsHeaderPageView, ChartsHeaderPageViewModel>();
			mvxFluentBindingDescriptionSet.Bind(chartController.Metric1).For((ChartMetric x) => x.Metric).To((ChartsHeaderPageViewModel vm) => vm.Metric1);
			mvxFluentBindingDescriptionSet.Bind(chartController.Metric2).For((ChartMetric x) => x.Metric).To((ChartsHeaderPageViewModel vm) => vm.Metric2);
			mvxFluentBindingDescriptionSet.Bind(chartController.Metric3).For((ChartMetric x) => x.Metric).To((ChartsHeaderPageViewModel vm) => vm.Metric3);
			mvxFluentBindingDescriptionSet.Bind(chartController.Metric4).For((ChartMetric x) => x.Metric).To((ChartsHeaderPageViewModel vm) => vm.Metric4);
			mvxFluentBindingDescriptionSet.Bind(chartController.Metric5).For((ChartMetric x) => x.Metric).To((ChartsHeaderPageViewModel vm) => vm.Metric5);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.Current1).To((ChartsHeaderPageViewModel vm) => vm.Current1);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.Current2).To((ChartsHeaderPageViewModel vm) => vm.Current2);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.Current3).To((ChartsHeaderPageViewModel vm) => vm.Current3);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.Current4).To((ChartsHeaderPageViewModel vm) => vm.Current4);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.Current5).To((ChartsHeaderPageViewModel vm) => vm.Current5);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.LeftAxisMax).To((ChartsHeaderPageViewModel vm) => vm.ChartMax);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.LeftAxisMin).To((ChartsHeaderPageViewModel vm) => vm.ChartMin);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.MaxXValue).To((ChartsHeaderPageViewModel vm) => vm.ChartData.TargetValue);
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.IsMetric).To((ChartsHeaderPageViewModel vm) => vm.IsMetric);
			if (base.ViewModel.HasInclineMetric && !flag)
			{
				TextView textView = View.FindViewById<TextView>(2131428316);
				textView.Text = Wolf.Core.Resources.AppStrings.incline.ToUpper();
				textView.Visibility = ViewStates.Visible;
				global::Android.Graphics.Color color = base.ViewModel.ChartData.GetColorForChartGroup(ChartGroupType.Incline, base.ViewModel.CurrentTheme)?.ToNative() ?? global::Android.Graphics.Color.Gray;
				textView.Background.SetTint(color);
			}
			if (base.ViewModel.HasResistanceOrGearMetric)
			{
				TextView textView2 = View.FindViewById<TextView>(2131428975);
				textView2.Text = Wolf.Core.Resources.AppStrings.resistance.ToUpper();
				textView2.Visibility = ViewStates.Visible;
				SplatColor? colorForChartGroup = base.ViewModel.ChartData.GetColorForChartGroup(ChartGroupType.Resistance, base.ViewModel.CurrentTheme);
				if (!colorForChartGroup.HasValue)
				{
					colorForChartGroup = base.ViewModel.ChartData.GetColorForChartGroup(ChartGroupType.Gear, base.ViewModel.CurrentTheme);
				}
				global::Android.Graphics.Color color2 = colorForChartGroup?.ToNative() ?? global::Android.Graphics.Color.Gray;
				textView2.Background.SetTint(color2);
			}
			if (base.ViewModel.HasSpeedMetric && !flag)
			{
				TextView textView3 = View.FindViewById<TextView>(2131429302);
				textView3.Text = Wolf.Core.Resources.AppStrings.speed.ToUpper();
				textView3.Visibility = ViewStates.Visible;
				global::Android.Graphics.Color color3 = base.ViewModel.ChartData.GetColorForChartGroup(ChartGroupType.Speed, base.ViewModel.CurrentTheme)?.ToNative() ?? global::Android.Graphics.Color.Gray;
				textView3.Background.SetTint(color3);
			}
			mvxFluentBindingDescriptionSet.Bind(chartController).For((InWorkoutLineChart x) => x.IsChartInitialized).To((ChartsHeaderPageViewModel vm) => vm.ChartData.DataInitialized);
			mvxFluentBindingDescriptionSet.Bind(this).For((ChartsHeaderPageView x) => x.AddLabelsEnabled).To((ChartsHeaderPageViewModel vm) => vm.ChartData.EnableAddLabels);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private bool CheckIfTreadmill()
		{
			bool flag = false;
			for (int i = 0; i < System.Math.Min(metricViews.Count, base.ViewModel.Metrics.Count); i++)
			{
				if (metricViews[i] != null && base.ViewModel.Metrics[i] is RPMMetric)
				{
					flag = true;
				}
			}
			if (flag || base.ViewModel.HasResistanceOrGearMetric)
			{
				return false;
			}
			TextView textView = View.FindViewById<TextView>(2131429302);
			textView.Visibility = ViewStates.Gone;
			for (int j = 0; j < System.Math.Min(metricViews.Count, base.ViewModel.Metrics.Count); j++)
			{
				if (metricViews[j] == null || !(metricViews[j] is TabletChartsFlipperItem))
				{
					continue;
				}
				metricViews[j].DrawPillLegend();
				IMetric metric = base.ViewModel.Metrics[j];
				if (!(metric is SpeedMetric))
				{
					if (metric is InclineMetric)
					{
						global::Android.Graphics.Color tintColor = base.ViewModel.ChartData.GetColorForChartGroup(ChartGroupType.Incline, base.ViewModel.CurrentTheme)?.ToNative() ?? global::Android.Graphics.Color.Gray;
						metricViews[j].PillLegend.TintColor = tintColor;
					}
				}
				else
				{
					global::Android.Graphics.Color tintColor = base.ViewModel.ChartData.GetColorForChartGroup(ChartGroupType.Speed, base.ViewModel.CurrentTheme)?.ToNative() ?? global::Android.Graphics.Color.Gray;
					metricViews[j].PillLegend.TintColor = tintColor;
				}
			}
			return true;
		}

		private void StyleChart(bool isTreadmill = false)
		{
			ViewPortHandler viewPortHandler = chartController.LineChart.ViewPortHandler;
			YAxis axisLeft = chartController.LineChart.AxisLeft;
			Transformer transformer = chartController.LineChart.RendererLeftYAxis.Transformer;
			ChartAnimator animator = chartController.LineChart.Animator;
			chartController.LineChart.Renderer = new StrokeCapJoinLineChartRenderer(chartController.LineChart, animator, viewPortHandler);
			chartController.LineChart.RendererLeftYAxis = new ChartHeaderYAxisRenderer(base.Resources, viewPortHandler, axisLeft, transformer);
			chartController.ShowLeftAxis = true;
			chartController.ShowRightAxis = false;
			chartController.LineChart.XAxis.SetDrawLabels(enabled: false);
			chartController.LineChart.SetViewPortOffsets(50f, 0f, 0f, 0f);
			chartController.StyleAxisLabels(chartController.LineChart.AxisLeft);
			chartController.LineChart.AxisLeft.SetDrawGridLines(enabled: true);
			if (isTreadmill && base.ViewModel.CurrentTheme == Theme.Dark)
			{
				chartController.LineChart.AxisLeft.GridColor = Colors.NamedD7D5D6.ToNative();
				chartController.LineChart.AxisLeft.AxisLineColor = Colors.NamedD7D5D6.ToNative();
				chartController.CurrentLimitLineColor = Colors.NamedD7D5D6.ToNative();
				axisLeft.TextColor = Colors.NamedD7D5D6.ToNative();
			}
			else
			{
				chartController.LineChart.AxisLeft.GridColor = Colors.Named9797972E.ToNative();
				chartController.LineChart.AxisLeft.AxisLineColor = Colors.Named9797972E.ToNative();
				chartController.CurrentLimitLineColor = Colors.NamedBFBFC0.ToNative();
			}
			chartController.LineChart.AxisLeft.GridLineWidth = 1f;
			chartController.LineChart.AxisLeft.SetDrawAxisLine(enabled: true);
			chartController.LineChart.AxisLeft.AxisLineWidth = 1f;
			chartController.LineChart.AxisLeft.SetLabelCount(5, force: true);
			chartController.LineChart.AxisLeft.SetDrawTopYLabelEntry(enabled: false);
			chartController.Metric1.Axis = YAxis.AxisDependency.Left;
			chartController.Metric2.Axis = YAxis.AxisDependency.Left;
			chartController.Metric3.Axis = YAxis.AxisDependency.Left;
			chartController.Metric4.Axis = YAxis.AxisDependency.Left;
			chartController.Metric5.Axis = YAxis.AxisDependency.Left;
			chartController.Metric1.ShowMetric = base.ViewModel.Metric1Enabled;
			chartController.Metric2.ShowMetric = base.ViewModel.Metric2Enabled;
			chartController.Metric3.ShowMetric = base.ViewModel.Metric3Enabled;
			chartController.Metric4.ShowMetric = base.ViewModel.Metric4Enabled;
			chartController.Metric5.ShowMetric = base.ViewModel.Metric5Enabled;
			chartController.CurrentMetric.ShowMetric = base.ViewModel.Current1Enabled;
			chartController.CurrentMetric2.ShowMetric = base.ViewModel.Current2Enabled;
			chartController.CurrentMetric3.ShowMetric = base.ViewModel.Current3Enabled;
			chartController.CurrentMetric4.ShowMetric = base.ViewModel.Current4Enabled;
			chartController.CurrentMetric5.ShowMetric = base.ViewModel.Current5Enabled;
			ConfigureMetricStyle(chartController.Metric1, chartController, base.ViewModel.Metric1Config);
			ConfigureMetricStyle(chartController.Metric2, chartController, base.ViewModel.Metric2Config);
			ConfigureMetricStyle(chartController.Metric3, chartController, base.ViewModel.Metric3Config);
			ConfigureMetricStyle(chartController.Metric4, chartController, base.ViewModel.Metric4Config);
			ConfigureMetricStyle(chartController.Metric5, chartController, base.ViewModel.Metric5Config);
			ConfigureCurrentStyle(chartController.CurrentMetric, chartController, base.ViewModel.Metric1Config);
			ConfigureCurrentStyle(chartController.CurrentMetric2, chartController, base.ViewModel.Metric2Config);
			ConfigureCurrentStyle(chartController.CurrentMetric3, chartController, base.ViewModel.Metric3Config);
			ConfigureCurrentStyle(chartController.CurrentMetric4, chartController, base.ViewModel.Metric4Config);
			ConfigureCurrentStyle(chartController.CurrentMetric5, chartController, base.ViewModel.Metric5Config);
			chartController.LineChart.SetTouchEnabled(enabled: false);
		}

		private void ConfigureMetricStyle(ChartMetric metric, InWorkoutLineChart chart, ChartMetricConfiguration config)
		{
			metric.CustomStyleMetric = delegate(LineDataSet lineSet)
			{
				chart.StyleMetric(lineSet, config);
			};
		}

		private void ConfigureCurrentStyle(ChartMetric metric, InWorkoutLineChart chart, ChartMetricConfiguration config)
		{
			metric.CustomStyleMetric = delegate(LineDataSet lineSet)
			{
				chart.StyleCurrentValue(lineSet, config);
			};
		}

		public override bool EvaluateClick(MotionEvent start, MotionEvent end)
		{
			return false;
		}

		public void ForceUpdateChart()
		{
			if (chartController != null)
			{
				System.Threading.Tasks.Task.Run(async delegate
				{
					await chartController.ApplyChangesAndUpdate().ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		public async System.Threading.Tasks.Task InflateView()
		{
			if (!isViewInflated)
			{
				await base.ViewModel.OnShownAsync();
				chartHeaderViewStub = View.FindViewById<ViewStub>(2131427637);
				chartHeaderViewStub?.Inflate();
				ApplyBindings();
				isViewInflated = true;
			}
		}
	}
