	public class AndroidMediaAnalyticsData
	{
		public double BandwidthSamples { get; set; }

		public double AverageBitrateEstimate { get; set; }

		public double MinBitrateEstimate { get; set; }

		public double MaxBitrateEstimate { get; set; }

		public int LoadErrorCount { get; set; }

		public int LoadCancelCount { get; set; }

		public int UpstreamDiscardCount { get; set; }

		public int PlaybackStallCount { get; set; }

		public double TotalStallBufferingTimeMs { get; set; }

		public int PosDiscontinuityCount { get; set; }

		public int SeekCount { get; set; }

		public int TimelineChangeCount { get; set; }

		public double InitialLoadTimeMs { get; set; }

		public int DroppedFrameCount { get; set; }

		public int AudioPlaybackStallCount { get; set; }

		public double TotalAudioStallBufferingTimeMs { get; set; }

		public int AudioPositionDiscontinuityCount { get; set; }

		public int SocketTimeoutCount { get; set; }

		public int AudioUnderrunCount { get; set; }

		public int PlayerErrorCount { get; set; }

		public int PlayerErrorOutOfMemoryCount { get; set; }

		public int PlayerErrorRemoteCount { get; set; }

		public int PlayerErrorRendererCount { get; set; }

		public int PlayerErrorSourceCount { get; set; }

		public int PlayerErrorUnexpectedCount { get; set; }

		public int TotalMediaDurationMs { get; set; }

		public int TotalDownloadDurationMs { get; set; }

		public int ManifestDownloadCount { get; set; }

		public int SlowSegmentCount { get; set; }

		public Tuple<int, int> LatestResolution { get; set; }

		public Dictionary<string, int> ResolutionSegmentCounts { get; } = new Dictionary<string, int>();

		public void CountLoadData(LoadEventInfo loadEventInfo, MediaLoadData mediaLoadData)
		{
			if (loadEventInfo == null || mediaLoadData == null)
			{
				return;
			}
			TotalDownloadDurationMs += (int)loadEventInfo.LoadDurationMs;
			if (mediaLoadData.DataType == DataType.Media && mediaLoadData.TrackFormat != null)
			{
				LatestResolution = new Tuple<int, int>(mediaLoadData.TrackFormat.Width, mediaLoadData.TrackFormat.Height);
				string key = $"{LatestResolution.Item1}x{LatestResolution.Item2}ResolutionSegmentCount";
				int num = (int)(mediaLoadData.MediaEndTimeMs - mediaLoadData.MediaStartTimeMs);
				if (ResolutionSegmentCounts.ContainsKey(key))
				{
					ResolutionSegmentCounts[key]++;
				}
				else
				{
					ResolutionSegmentCounts.Add(key, 1);
				}
				if (num <= (int)loadEventInfo.LoadDurationMs)
				{
					SlowSegmentCount++;
				}
				TotalMediaDurationMs += num;
			}
			else if (mediaLoadData.DataType == DataType.Manifest)
			{
				ManifestDownloadCount++;
			}
		}

		public void CountPlayerError(ExoPlaybackExceptionType type)
		{
			PlayerErrorCount++;
			switch (type)
			{
			case ExoPlaybackExceptionType.Remote:
				PlayerErrorRemoteCount++;
				break;
			case ExoPlaybackExceptionType.Renderer:
				PlayerErrorRendererCount++;
				break;
			case ExoPlaybackExceptionType.Source:
				PlayerErrorSourceCount++;
				break;
			case ExoPlaybackExceptionType.Unexpected:
				PlayerErrorUnexpectedCount++;
				break;
			}
		}

		public Dictionary<string, object> ToAnalyticsData()
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			PropertyInfo[] properties = GetType().GetProperties();
			foreach (PropertyInfo propertyInfo in properties)
			{
				if (propertyInfo.PropertyType != typeof(Dictionary<string, int>))
				{
					string key = propertyInfo.Name.Substring(0, 1).ToLower() + propertyInfo.Name.Substring(1);
					dictionary.Add(key, propertyInfo.GetValue(this));
				}
			}
			foreach (KeyValuePair<string, int> resolutionSegmentCount in ResolutionSegmentCounts)
			{
				dictionary.Add(resolutionSegmentCount.Key, resolutionSegmentCount.Value);
			}
			return dictionary;
		}
	}
	public class AndroidMediaAnalyticsService : Java.Lang.Object, IMediaAnalyticsService
	{
		private const string ExoPlayerLogFileName = "exoplayer_log.txt";

