		public IObservable<bool> WhenFirstFrameRendered => _whenFirstFrameRendered.AsObservable();

		public IObservable<AndroidNetworkActivityData> WhenNetworkActivityHandled => _whenNetworkActivityHandled.AsObservable();

		public IObservable<AndroidMediaAnalyticsData> WhenAnalyticsDataUpdated => _whenAnalyticsDataUpdated.AsObservable();

		public Dictionary<string, object> AnalyticsData => storage.Data.ToAnalyticsData();

		public AudioListener AudioListener { get; }

