			{
				wifiListenerDisposable.Disposable = value;
			}
		}

		public AndroidMediaAnalyticsService(IMediaAnalyticsLogService mediaAnalyticsLogService, IWifiService wifiService, IWolfAnalytics wolfAnalytics)
		{
			this.wifiService = wifiService;
			this.mediaAnalyticsLogService = mediaAnalyticsLogService;
			this.wolfAnalytics = wolfAnalytics;
			mediaAnalyticsLogService.Initialize("exoplayer_log.txt");
			AudioListener = new AudioListener(mediaAnalyticsLogService).DisposeWith(disposables);
			AudioRendererEventListener = new AudioRendererEventListener(storage, mediaAnalyticsLogService).DisposeWith(disposables);
			AudioSinkListener = new AudioSinkListener(storage, mediaAnalyticsLogService).DisposeWith(disposables);
			BandwidthMeterEventListener = new BandwidthMeterEventListener(storage, mediaAnalyticsLogService, RaiseNetworkActivityHandled, RaiseAnalyticsDataUpdated).DisposeWith(disposables);
			MediaSourceEventListener = new MediaSourceEventListener(storage, mediaAnalyticsLogService, CheckException, RaiseAnalyticsDataUpdated).DisposeWith(disposables);
			PlayerEventListener = new PlayerEventListener(storage, mediaAnalyticsLogService, CheckException, RaiseAnalyticsDataUpdated, ReportStallEvent).DisposeWith(disposables);
			VideoListener = new Wolf.Android.Hollywood.Listeners.VideoListener(storage, mediaAnalyticsLogService, RaiseFirstFrameRendered).DisposeWith(disposables);
			wifiListenerDisposable.DisposeWith(disposables);
		}

		public void StartWorkout()
		{
			mediaAnalyticsLogService.StartWorkout();
			storage.Data = new AndroidMediaAnalyticsData();
			storage.CurrentTimeline = null;
			WifiListener = new WifiListener(wifiService, mediaAnalyticsLogService);
		}

		public async Task<MediaAnalyticsData> FinishWorkoutAsync(MediaAnalyticsSyncDataObject analyticsDataObject)
		{
			mediaAnalyticsLogService.WriteToLog("FinishWorkoutAsync");
			MediaAnalyticsData result;
			try
			{
				if (analyticsDataObject == null)
				{
					result = MediaAnalyticsData.Empty;
				}
				else
				{
					List<LogFileUploadResult> list = await mediaAnalyticsLogService.UploadLogs(analyticsDataObject.TotalTimeSpentBuffering.TotalSeconds, analyticsDataObject.VideoStutteringCount).ConfigureAwait(continueOnCapturedContext: false);
					MediaAnalyticsData mediaAnalyticsData = new MediaAnalyticsData
					{
						Data = AnalyticsData
					};
					if (list != null && list.Count >= 2)
					{
						mediaAnalyticsData.WolfLogUrl = list[0]?.LogUrl;
						mediaAnalyticsData.VideoPlayerLogUrl = list[1]?.LogUrl;
					}
					result = mediaAnalyticsData;
				}
			}
			finally
			{
				WifiListener = null;
				await mediaAnalyticsLogService.CleanUp().ConfigureAwait(continueOnCapturedContext: false);
			}
			return result;
		}

		private void RaiseAnalyticsDataUpdated()
		{
			_whenAnalyticsDataUpdated.OnNext(storage.Data);
		}

		private void RaiseFirstFrameRendered()
		{
			_whenFirstFrameRendered.OnNext(value: true);
		}

		private void RaiseNetworkActivityHandled(AndroidNetworkActivityData data)
		{
			_whenNetworkActivityHandled.OnNext(data);
		}

		private void ReportStallEvent()
		{
			string latestResolution = "Unknown";
			if (storage?.Data?.LatestResolution != null)
			{
				latestResolution = $"{storage.Data.LatestResolution.Item1}x{storage.Data.LatestResolution.Item2}";
			}
			wolfAnalytics.ReportStallEvent(latestResolution);
		}

		private void CheckException(System.Exception ex)
		{
			if (ex != null)
			{
				if (ex.RelatesTo<SocketTimeoutException>())
				{
					storage.Data.SocketTimeoutCount++;
				}
				ex.RelatesTo<UnknownHostException>();
				ex.RelatesTo<ConnectException>();
				ex.RelatesTo<SSLException>();
				ex.RelatesTo<SSLHandshakeException>();
				ex.RelatesTo<Java.Net.SocketException>();
				ex.RelatesTo<NoRouteToHostException>();
				ex.RelatesTo<ProtocolException>();
				ex.RelatesTo<IllegalStateException>();
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (!disposed)
			{
				disposables.Dispose();
				base.Dispose(disposing);
				disposed = true;
			}
		}

		public async Task<MediaAnalyticsData> SetLiveWorkoutKickout()
		{
			List<LogFileUploadResult> list = await mediaAnalyticsLogService.UploadLogs(0.0, 0, liveWorkoutKickout: true).ConfigureAwait(continueOnCapturedContext: false);
			if (list == null)
			{
				return MediaAnalyticsData.Empty;
			}
			return new MediaAnalyticsData
			{
				WolfLogUrl = list[0]?.LogUrl,
				VideoPlayerLogUrl = list[1]?.LogUrl,
				Data = AnalyticsData
			};
		}
