			isDisabled = false;
			AndroidX.Core.Util.Pair pair = (AndroidX.Core.Util.Pair)view.Tag;
			int num = (int)pair.First;
			int num2 = (int)pair.Second;
			if (!trackGroupsAdaptive[num] || selectionOverride == null || selectionOverride.GroupIndex != num)
			{
				selectionOverride = new DefaultTrackSelector.SelectionOverride(num, num2);
				return;
			}
			bool flag = ((CheckedTextView)view).Checked;
			int length = selectionOverride.Length;
			if (flag)
			{
				if (length == 1)
				{
					selectionOverride = null;
					isDisabled = true;
				}
				else
				{
					SetOverride(num, GetTracksRemoving(selectionOverride, num2), enableRandomAdaptationView.Checked);
				}
			}
			else
			{
				SetOverride(num, GetTracksAdding(selectionOverride, num2), enableRandomAdaptationView.Checked);
			}
		}

		private void SetOverride(int group, int[] tracks, bool enableRandomAdaptation)
		{
			IExoTrackSelectionFactory exoTrackSelectionFactory = ((tracks.Length == 1) ? FIXED_FACTORY : (enableRandomAdaptation ? RANDOM_FACTORY : adaptiveTrackSelectionFactory));
			selectionOverride = new DefaultTrackSelector.SelectionOverride(group, tracks);
		}

		private static int[] GetTracksAdding(DefaultTrackSelector.SelectionOverride _override, int addedTrack)
		{
			List<int> list = new List<int>(_override.Tracks) { addedTrack };
			return list.ToArray();
		}

		private static int[] GetTracksRemoving(DefaultTrackSelector.SelectionOverride _override, int removedTrack)
		{
			int[] array = new int[_override.Length - 1];
			int num = 0;
			for (int i = 0; i < array.Length + 1; i++)
			{
				int num2 = _override.Tracks[i];
				if (num2 != removedTrack)
				{
					array[num++] = num2;
				}
			}
			return array;
		}
	}
