	public static class ExoPlayerLogUtil
	{
		public static string GetDecoderCountersStr(DecoderCounters counters)
		{
			if (counters == null)
			{
				return "null";
			}
			return $"decoderInitCount: {counters.DecoderInitCount}, decoderReleaseCount: {counters.DecoderReleaseCount}, droppedBufferCount: {counters.DroppedBufferCount}, droppedToKeyframeCount: {counters.DroppedToKeyframeCount}, inputBufferCount: {counters.InputBufferCount}, maxConsecutiveDroppedBufferCount: {counters.MaxConsecutiveDroppedBufferCount}, renderedOutputBufferCount: {counters.RenderedOutputBufferCount}, skippedInputBufferCount: {counters.SkippedInputBufferCount}, skippedOutputBufferCount: {counters.SkippedOutputBufferCount}";
		}

		public static string GetFormatStr(Com.Google.Android.Exoplayer2.Format format)
		{
			if (format == null)
			{
				return "null";
			}
			return $"\t\t{format.Id}:\t({format.Width}x{format.Height})@{format.FrameRate}fps, bitrate: {format.Bitrate}, codecs: {format.Codecs}, channels: {format.ChannelCount}, sampleRate: {format.SampleRate}";
		}

		public static string GetMediaPeriodIdStr(MediaSourceMediaPeriodId mediaPeriodId, Timeline timeline)
		{
			if (mediaPeriodId == null)
			{
				return "mediaPeriodId: null";
			}
			if (timeline == null)
			{
				return "timeline: null";
			}
			int num = -1;
			if (!timeline.IsEmpty)
			{
				num = timeline.GetIndexOfPeriod(mediaPeriodId.PeriodUid);
			}
			return $"mediaPeriodId: (periodIndex: {num}, windowSequenceNumber: {mediaPeriodId.WindowSequenceNumber})";
		}

		public static string GetLoadEventInfoStr(LoadEventInfo loadEventInfo)
		{
			if (loadEventInfo == null)
			{
				return "loadEventInfo: null";
			}
			System.Text.StringBuilder stringBuilder = new System.Text.StringBuilder();
			stringBuilder.AppendLine("\t\tResponse headers:");
			foreach (DictionaryEntry responseHeader in loadEventInfo.ResponseHeaders)
			{
				stringBuilder.AppendLine($"\t\t\t{responseHeader.Key}: {((IList)responseHeader.Value)[0]}");
			}
			return $"loadEventInfo: (bytesLoaded: {loadEventInfo.BytesLoaded}, elapsedRealtimeMs: {loadEventInfo.ElapsedRealtimeMs}, loadDurationMs: {loadEventInfo.LoadDurationMs},\n\t\t{GetDataSpecStr(loadEventInfo.DataSpec)},\n\t\t{loadEventInfo.Uri}\n\t\t{stringBuilder})";
		}

		public static string GetDataSpecStr(DataSpec dataSpec)
		{
			if (dataSpec == null)
			{
				return "dataSpec: null";
			}
			return $"dataSpec: (uriPositionOffset: {dataSpec.UriPositionOffset}, position: {dataSpec.Position}, flags: {dataSpec.Flags}, key: {dataSpec.Key}, length: {dataSpec.Length}, position: {dataSpec.Position})";
		}

		public static string GetMediaLoadDataStr(MediaLoadData mediaLoadData)
		{
			if (mediaLoadData == null)
			{
				return "mediaLoadData: null";
			}
			return $"mediaLoadData: (dataType: {mediaLoadData.DataType}, mediaStartTimeMs: {mediaLoadData.MediaStartTimeMs}, mediaEndTimeMs: {mediaLoadData.MediaEndTimeMs}, trackType: {mediaLoadData.TrackType}, trackSelectionReason: {mediaLoadData.TrackSelectionReason}, trackFormat: (\n{GetFormatStr(mediaLoadData.TrackFormat)}\n))";
		}

		public static string GetFormattedDouble(double value, int precision)
		{
			return new DecimalFormat("#0." + ((precision <= 1) ? "0" : ((precision == 2) ? "00" : "000"))).Format(value);
		}

		public static string GetHumanReadableByteCount(long bytes, bool si)
		{
			return GetHumanReadableByteCount(bytes, si, isBits: false);
		}

		public static string GetHumanReadableByteCount(long bytes, bool si, bool isBits)
		{
			int num = (si ? 1024 : 1000);
			if (bytes < num)
			{
				return $"{bytes} KB";
			}
			int num2 = (int)(System.Math.Log(bytes) / System.Math.Log(num));
			string arg = (si ? "kMGTPE" : "KMGTPE")[num2 - 1] + (si ? "" : "i");
			string arg2 = (isBits ? "b" : "B");
			return $"{(double)bytes / System.Math.Pow(num, num2):F1} {arg}{arg2}";
		}

		public static string BuildTrackName(Com.Google.Android.Exoplayer2.Format format)
		{
			string text = (Com.Google.Android.Exoplayer2.Util.MimeTypes.IsVideo(format.SampleMimeType) ? JoinWithSeparator(BuildResolutionString(format), BuildBitrateString(format), BuildTrackIdString(format), BuildSampleMimeTypeString(format)) : ((!Com.Google.Android.Exoplayer2.Util.MimeTypes.IsAudio(format.SampleMimeType)) ? JoinWithSeparator(BuildLanguageString(format), BuildBitrateString(format), BuildTrackIdString(format), BuildSampleMimeTypeString(format)) : JoinWithSeparator(BuildLanguageString(format), BuildAudioPropertyString(format), BuildBitrateString(format), BuildTrackIdString(format), BuildSampleMimeTypeString(format))));
			if (text.Length != 0)
			{
				return text;
			}
			return "unknown";
		}

		private static string JoinWithSeparator(params string[] strs)
		{
			return strs.Aggregate(delegate(string first, string second)
			{
				if (first.Length == 0)
				{
					return second;
				}
				return (second.Length == 0) ? first : (first + ", " + second);
			});
		}

		private static string BuildAudioPropertyString(Com.Google.Android.Exoplayer2.Format format)
		{
			if (format != null && format.ChannelCount != -1 && format.SampleRate != -1)
			{
				return $"{format.ChannelCount}ch, {format.SampleRate}Hz";
			}
			return "";
		}

		private static string BuildBitrateString(Com.Google.Android.Exoplayer2.Format format)
		{
			if (format != null && format.Bitrate != -1)
			{
				return string.Format(CultureInfo.InvariantCulture, "{0}Mbit", (float)format.Bitrate / 1000000f);
			}
			return "";
		}

		private static string BuildLanguageString(Com.Google.Android.Exoplayer2.Format format)
		{
			if (!string.IsNullOrEmpty(format?.Language) && !"und".Equals(format.Language))
			{
				return format.Language;
			}
			return "";
		}

		private static string BuildResolutionString(Com.Google.Android.Exoplayer2.Format format)
		{
			if (format != null && format.Width != -1 && format.Height != -1)
			{
				return $"{format.Width}x{format.Height}";
			}
			return "";
		}

		private static string BuildTrackIdString(Com.Google.Android.Exoplayer2.Format format)
		{
			if (format != null && format.Id != null)
			{
				return "id:" + format.Id;
			}
			return "";
		}

		private static string BuildSampleMimeTypeString(Com.Google.Android.Exoplayer2.Format format)
		{
			if (format != null && format.SampleMimeType != null)
			{
				return format.SampleMimeType;
			}
			return "";
		}
	}
