		private void AttachNewPlayer(SimpleExoPlayer player)
		{
			((Activity)(object)base.Activity)?.RunOnUiThread((System.Action)delegate
			{
				if (exoView != null)
				{
					exoView.Player = player;
				}
			});
			InWorkoutStreamingVideoViewModel viewModel = base.ViewModel;
			if (viewModel == null || !viewModel.PerformDebugBindings)
			{
				return;
			}
			if (Mvx.TryResolve<IMediaAnalyticsService>(out var service))
			{
				AndroidMediaAnalyticsService androidMediaAnalyticsService = (AndroidMediaAnalyticsService)service;
				firstFrameListener = androidMediaAnalyticsService.WhenFirstFrameRendered.Subscribe(delegate
				{
					HandleFirstFrameRendered();
				});
				bitrateEstimateListener = androidMediaAnalyticsService.WhenNetworkActivityHandled.Subscribe(delegate(AndroidNetworkActivityData activityData)
				{
					HandleNetworkActivity(activityData.DownloadedBytes, activityData.EstimatedBitrate);
				});
				analyticsDataListener = androidMediaAnalyticsService.WhenAnalyticsDataUpdated.Subscribe(delegate(AndroidMediaAnalyticsData data)
				{
					HandleAnalyticsDataUpdated(data);
				});
				networkTimer = new System.Threading.Timer(HandleTimeTick, this, TimeSpan.Zero, TimeSpan.FromSeconds(1.0));
			}
			if (Mvx.TryResolve<IVideoBufferMonitoringService>(out var service2))
			{
				bufferStatusListener = service2.WhenVideoBufferStatusChanged.Subscribe(delegate(VideoBufferMonitoringService.VideoBufferingStatus status)
				{
					HandleBufferStatusUpdate(status);
				});
			}
			if (!Mvx.TryResolve<ILocalSettings>(out localSettings))
			{
				iFit.Logger.Log.Warn(base.Tag, "ExoPlayer debug overlay could not find local settings!");
			}
			if (!Mvx.TryResolve<IWorkoutSettings>(out workoutSettings))
			{
				iFit.Logger.Log.Warn(base.Tag, "ExoPlayer debug overlay could not find workoutSettings!");
			}
		}

