			loadingAnimation = ((circularLoadingView != null) ? iFit.Video.Android.JavaExtensions.DisposeSafe(circularLoadingView) : null);
			loadingContainer = iFit.Video.Android.JavaExtensions.DisposeSafe(loadingContainer);
			bufferStatusTextView = iFit.Video.Android.JavaExtensions.DisposeSafe(bufferStatusTextView);
			bufferInstructionsTextView = iFit.Video.Android.JavaExtensions.DisposeSafe(bufferInstructionsTextView);
			CleanUpDebug();
		}

		private void InitializeDebug(View view)
		{
			debugView = view.FindViewById<LinearLayout>(2131428014);
			debugTextView = view.FindViewById<IfitTextView>(2131429738);
