		private void BindDebug(MvxFluentBindingDescriptionSet<InWorkoutStreamingVideoView, InWorkoutStreamingVideoViewModel> set)
		{
			set.Bind(debugView).For((LinearLayout x) => x.Visibility).To((InWorkoutStreamingVideoViewModel vm) => vm.ShouldShowDebugOverlay)
