		private void ShowDebugTrackSelectionDialog(object sender, EventArgs e)
		{
			CombinedAudioVideoPlayer combinedAudioVideoPlayer = base.ViewModel?.MediaService?.Video?.PreBufferedVideoPlayer as CombinedAudioVideoPlayer;
			CustomTrackSelector customTrackSelector = combinedAudioVideoPlayer?.videoTrackSelector;
			MappingTrackSelector.MappedTrackInfo mappedTrackInfo = customTrackSelector?.CurrentMappedTrackInfo;
			if (customTrackSelector != null && mappedTrackInfo != null)
			{
				int.TryParse((string)((Button)sender).Tag, out var result);
				trackSelectionDialog = new DebugTrackSelectionDialog(customTrackSelector, combinedAudioVideoPlayer.TrackSelectionFactory);
