		private void HandleFirstFrameRendered()
		{
			player_stats_other.Text = $"sd:{exoView.Width}x{exoView.Height} wq:{workoutSettings.VideoQuality}";
			UpdateAnalyticsStats();
		}

		private void HandleNetworkActivity(long bytes, long bitrate)
		{
			bytesDownloaded += bytes;
			UpdateStatChart(player_stats_speed_chart, bitrate, global::Android.Graphics.Color.LightGray, "Conn Speed: " + ExoPlayerLogUtil.GetHumanReadableByteCount(bitrate, si: true, isBits: true) + "ps (Avg: " + ExoPlayerLogUtil.GetHumanReadableByteCount(Convert.ToInt64(averageBitrate), si: true, isBits: true) + "ps)");
		}

		private void HandleBufferStatusUpdate(VideoBufferMonitoringService.VideoBufferingStatus status)
		{
			float buffer = status.BufferedSeconds;
			if (Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				service.RequestMainThreadAction(delegate
				{
					UpdateStatChart(player_stats_health_chart, buffer, ColorTemplate.HoloBlue, $"Buffer Health: {buffer} s");
					player_stats_currentpos.Text = $"Current Position: {status.CurrentPosition} s";
				});
			}
		}

		private void HandleTimeTick(object state)
		{
			UpdateStatChart(player_stats_nw_chart, bytesDownloaded, global::Android.Graphics.Color.Cyan, "Network Activity: " + ExoPlayerLogUtil.GetHumanReadableByteCount(bytesDownloaded, si: true));
			bytesDownloaded = 0L;
		}

		private void HandleAnalyticsDataUpdated(AndroidMediaAnalyticsData data)
		{
			loadErrors = data.LoadErrorCount;
			playerErrors = data.PlayerErrorCount;
			playbackStalls = data.PlaybackStallCount;
			timelineChanges = data.TimelineChangeCount;
			seeks = data.SeekCount;
			positionDiscontinuities = data.PosDiscontinuityCount;
			droppedFrames = data.DroppedFrameCount;
			averageBitrate = data.AverageBitrateEstimate;
			UpdateAnalyticsStats();
		}

		private void UpdateAnalyticsStats()
		{
			player_stats_analytics.Text = $"df:{droppedFrames} le:{loadErrors} pe:{playerErrors} st:{playbackStalls} tlc:{timelineChanges} sk:{seeks} pd:{positionDiscontinuities}";
		}

		private void InitStatChart(LineChart chart, float maxValue = 0f / 0f)
		{
			chart.Description.Enabled = false;
			chart.Legend.TextColor = global::Android.Graphics.Color.White;
			chart.SetTouchEnabled(enabled: false);
			chart.DragEnabled = false;
			chart.SetScaleEnabled(enabled: false);
			chart.SetDrawGridBackground(enabled: false);
			chart.SetPinchZoom(enabled: false);
			chart.SetBackgroundColor(global::Android.Graphics.Color.Transparent);
			chart.XAxis.Enabled = false;
			XAxis xAxis = chart.XAxis;
			xAxis.SetDrawLabels(enabled: false);
			xAxis.SetDrawGridLines(enabled: false);
			xAxis.SetAvoidFirstLastClipping(enabled: true);
			xAxis.Position = XAxis.XAxisPosition.Bottom;
			xAxis.Enabled = true;
			YAxis axisRight = chart.AxisRight;
			axisRight.SetDrawLabels(enabled: false);
			axisRight.SetDrawGridLines(enabled: false);
			axisRight.Enabled = true;
			if (!float.IsNaN(maxValue))
			{
				axisRight.AxisMaximum = maxValue * 1.07f;
			}
			axisRight.AxisMinimum = 0f;
			YAxis axisLeft = chart.AxisLeft;
			axisLeft.Enabled = false;
			chart.Data = new LineData();
		}

		private void UpdateStatChart(LineChart chart, float value, int color, string formattedValue)
		{
			ChartData chartData = chart?.Data;
			if (chartData != null)
			{
				LineDataSet lineDataSet = (LineDataSet)chartData.GetDataSetByIndex(0);
				if (lineDataSet == null)
				{
					lineDataSet = CreateDataSetForChart(color);
					chartData.AddDataSet(lineDataSet);
				}
				lineDataSet.Label = formattedValue;
				chartData.AddEntry(new Entry(lineDataSet.EntryCount, value), 0);
				chartData.NotifyDataChanged();
				chart.NotifyDataSetChanged();
				chart.SetVisibleXRangeMaximum(75f);
				chart.MoveViewToX(chartData.EntryCount);
			}
		}

		private LineDataSet CreateDataSetForChart(int color)
		{
			LineDataSet lineDataSet = new LineDataSet(null, "Dynamic Data")
			{
				AxisDependency = YAxis.AxisDependency.Right,
				Color = color,
				LineWidth = 0f,
				FillAlpha = 65,
				FillColor = color
			};
			lineDataSet.SetDrawCircles(enabled: false);
			lineDataSet.SetDrawValues(enabled: false);
			return lineDataSet;
		}

		private void CleanUpDebug()
		{
			debugTextView = iFit.Video.Android.JavaExtensions.DisposeSafe(debugTextView);
			networkTimer?.Dispose();
			networkTimer = null;
			firstFrameListener?.Dispose();
			firstFrameListener = null;
			droppedFramesListener?.Dispose();
			droppedFramesListener = null;
			bitrateEstimateListener?.Dispose();
			bitrateEstimateListener = null;
			bufferStatusListener?.Dispose();
			bufferStatusListener = null;
			analyticsDataListener?.Dispose();
			analyticsDataListener = null;
			if (debugVideoSelectionButton != null)
			{
				debugVideoSelectionButton.Click -= ShowDebugTrackSelectionDialog;
			}
			if (debugAudioSelectionButton != null)
			{
				debugAudioSelectionButton.Click -= ShowDebugTrackSelectionDialog;
			}
			if (debugTextSelectionButton != null)
			{
				debugTextSelectionButton.Click -= ShowDebugTrackSelectionDialog;
			}
		}
	}
	[Service(Name = "com.ifit.wolf.BackgroundVideoService")]
	public class WolfBackgroundVideoService : global::Android.App.Service, AudioManager.IOnAudioFocusChangeListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private const string LogTag = "BackgroundVideoService";

		public const int ServiceRunningNotificationId = 10000;

		public const string ServiceStartedKey = "has_service_been_started";

		public const string BroadcastMessageKey = "broadcast_message";

		public const string NotificationBroadcastAction = "Wolf.VideoPlayback.Notification.Action";

		public const string NotificationChannelId = "ifit_video_background_service";

		public const string NotificationChannelName = "iFIT Video Background Service";

		public const string StartServiceAction = "Wolf.VideoPlayback.Start";

		public const string StopServiceAction = "Wolf.VideoPlayback.Stop";

		public const string RestartTimerAction = "Wolf.VideoPlayback.Restart";

		public const string MainActivityAction = "Wolf.VideoPlayback.MainActivity";

		private const float DuckVolume = 0.2f;

		private IVideoService videoService;

		private IAppLifecycleService lifecycleService;

		private IMediaService mediaService;

		private AudioManager audioManager;

		private AudioFocusRequestClass audioFocusRequest;

		private bool isStarted;

		private PowerManager.WakeLock wakeLock;

		private WifiManager.WifiLock wifiLock;

		private bool cleanedUp;

		public override void OnCreate()
		{
			base.OnCreate();
			System.Threading.Tasks.Task.Run((System.Action)AcquireLocks);
		}

		private void AcquireLocks()
		{
			InitializeServicesIfNeeded(logFailures: true);
			audioManager = (AudioManager)ApplicationContext.GetSystemService("audio");
			if (RequestAudioFocus() != AudioFocusRequest.Granted)
			{
				OnAudioFocusChange(global::Android.Media.AudioFocus.Loss);
			}
			PowerManager powerManager = ApplicationContext.GetSystemService("power") as PowerManager;
			WifiManager wifiManager = ApplicationContext.GetSystemService("wifi") as WifiManager;
			wakeLock = powerManager.NewWakeLock(WakeLockFlags.ScreenBright, "workoutWakeLock");
			wifiLock = wifiManager.CreateWifiLock(WifiMode.FullHighPerf, "workoutWifiLock");
			wakeLock.Acquire();
			wifiLock.Acquire();
		}

		private void InitializeServicesIfNeeded(bool logFailures = false)
		{
			if (videoService == null)
			{
				if (!Mvx.TryResolve<IVideoService>(out videoService) && logFailures)
				{
					iFit.Logger.Log.Error("BackgroundVideoService", "Could not resolve IVideoService in WolfBackgroundVideoService");
				}
				else
				{
					iFit.Logger.Log.Trace("BackgroundVideoService", "Resolved IVideoService in WolfBackgroundVideoService");
				}
			}
			if (lifecycleService == null)
			{
				if (!Mvx.TryResolve<IAppLifecycleService>(out lifecycleService))
				{
					iFit.Logger.Log.Error("BackgroundVideoService", "Could not resolve IAppLifecycleService in WolfBackgroundVideoService");
				}
				else
				{
					lifecycleService.AppStateChanged -= LifecycleService_AppStateChanged;
					lifecycleService.AppStateChanged += LifecycleService_AppStateChanged;
					iFit.Logger.Log.Trace("BackgroundVideoService", "Resolved IAppLifecycleService in WolfBackgroundVideoService");
				}
			}
			if (mediaService == null)
			{
				if (!Mvx.TryResolve<IMediaService>(out mediaService))
				{
					iFit.Logger.Log.Error("BackgroundVideoService", "Could not resolve IMediaService in WolfBackgroundVideoService");
				}
				else
				{
					iFit.Logger.Log.Trace("BackgroundVideoService", "Resolved IMediaService in WolfBackgroundVideoService");
				}
			}
		}

		private void LifecycleService_AppStateChanged(object sender, AppStateEventArgs e)
		{
			if (e.CurrentState == AppLifecycleService.AppState.Foreground && RequestAudioFocus() == AudioFocusRequest.Granted)
			{
				OnAudioFocusChange(global::Android.Media.AudioFocus.Gain);
			}
		}

		public override StartCommandResult OnStartCommand(Intent intent, [GeneratedEnum] StartCommandFlags flags, int startId)
		{
			if (intent == null || intent.Action == null || intent.Action.Equals("Wolf.VideoPlayback.Start"))
			{
				if (intent == null || intent.Action == null)
				{
					iFit.Logger.Log.Trace("BackgroundVideoService", "Got null intent - recovering service and registering for foreground again");
				}
				InitializeServicesIfNeeded();
				if (isStarted)
				{
					iFit.Logger.Log.Trace("BackgroundVideoService", "Ignored start service action - video background service already running");
				}
				else
				{
					isStarted = true;
					RegisterForegroundService();
				}
			}
			else if (intent.Action.Equals("Wolf.VideoPlayback.Stop"))
			{
				iFit.Logger.Log.Trace("BackgroundVideoService", "Stopping video background service");
				StopForeground(removeNotification: true);
				StopSelf();
				isStarted = false;
			}
			return StartCommandResult.Sticky;
		}

		private void RegisterForegroundService()
		{
			iFit.Logger.Log.Trace("BackgroundVideoService", "Starting video background service");
			string channelId = CreateChannel("ifit_video_background_service", "iFIT Video Background Service");
			global::Android.App.Notification notification = new NotificationCompat.Builder(this, channelId).SetContentTitle("iFIT").SetContentText("").SetSmallIcon(2131231670)
				.SetContentIntent(BuildShowWorkoutIntent())
				.SetOngoing(ongoing: true)
				.Build();
			StartForeground(10000, notification);
		}

		private string CreateChannel(string channelId, string channelName)
		{
			if (Build.VERSION.SdkInt < BuildVersionCodes.O)
			{
				return "";
			}
			NotificationChannel channel = new NotificationChannel(channelId, channelName, NotificationImportance.Default);
			NotificationManager notificationManager = (NotificationManager)GetSystemService("notification");
			notificationManager.CreateNotificationChannel(channel);
			return channelId;
		}

		private AudioFocusRequest RequestAudioFocus()
		{
			AudioFocusRequest result = AudioFocusRequest.Failed;
			if (audioManager == null)
			{
				iFit.Logger.Log.Error("BackgroundVideoService", "Unable to request audio focus, audio manager is null");
				return result;
			}
			if (Build.VERSION.SdkInt < BuildVersionCodes.O)
			{
				result = audioManager.RequestAudioFocus(this, global::Android.Media.Stream.Music, global::Android.Media.AudioFocus.Gain);
				iFit.Logger.Log.Trace("BackgroundVideoService", $"Got focus initial value: {result}");
			}
			else
			{
				using (AudioFocusRequestClass.Builder builder = new AudioFocusRequestClass.Builder(global::Android.Media.AudioFocus.Gain))
				{
					using global::Android.Media.AudioAttributes.Builder builder2 = new global::Android.Media.AudioAttributes.Builder();
					builder2.SetUsage(AudioUsageKind.Media).SetContentType(global::Android.Media.AudioContentType.Movie).SetLegacyStreamType(global::Android.Media.Stream.Music);
					builder.SetAudioAttributes(builder2.Build()).SetAcceptsDelayedFocusGain(acceptsDelayedFocusGain: true).SetOnAudioFocusChangeListener(this);
					audioFocusRequest = builder.Build();
				}
				result = audioManager.RequestAudioFocus(audioFocusRequest);
			}
			return result;
		}

		private void ReleaseAudioFocus()
		{
			if (audioManager == null)
			{
				iFit.Logger.Log.Error("BackgroundVideoService", "Unable to release audio focus, audio manager is null");
			}
			else if (Build.VERSION.SdkInt < BuildVersionCodes.O)
			{
				audioManager.AbandonAudioFocus(this);
			}
			else
			{
				audioManager.AbandonAudioFocusRequest(audioFocusRequest);
			}
		}

		private PendingIntent BuildShowWorkoutIntent()
		{
			Mvx.TryResolve<IDeviceInformation>(out var service);
			Type typeFromHandle = typeof(InWorkoutView);
			if (service != null && !service.IsTablet)
			{
				typeFromHandle = typeof(PhoneInWorkoutView);
			}
			Intent intent = new Intent(this, typeFromHandle);
			intent.SetAction("Wolf.VideoPlayback.MainActivity");
			intent.PutExtra("has_service_been_started", value: true);
			return PendingIntent.GetActivity(this, 0, intent, PendingIntentFlags.Mutable | PendingIntentFlags.UpdateCurrent);
		}

		public override IBinder OnBind(Intent intent)
		{
			return null;
		}

		public override void OnTaskRemoved(Intent rootIntent)
		{
			iFit.Logger.Log.Trace("BackgroundVideoService", "OnTaskRemoved");
			base.OnTaskRemoved(rootIntent);
			StopSelf();
			CleanUp();
			global::Android.OS.Process.KillProcess(global::Android.OS.Process.MyPid());
		}

		public override void OnDestroy()
		{
			base.OnDestroy();
			CleanUp();
		}

		private void CleanUp()
		{
			if (!cleanedUp)
			{
				if (lifecycleService != null)
				{
					lifecycleService.AppStateChanged -= LifecycleService_AppStateChanged;
				}
				ReleaseAudioFocus();
				AudioFocusRequestClass audioFocusRequestClass = audioFocusRequest;
				audioFocusRequest = ((audioFocusRequestClass != null) ? iFit.Video.Android.JavaExtensions.DisposeSafe(audioFocusRequestClass) : null);
				audioManager = null;
				videoService = null;
				mediaService = null;
				wakeLock?.Release();
				wifiLock?.Release();
				wakeLock = null;
				wifiLock = null;
				NotificationManager notificationManager = (NotificationManager)GetSystemService("notification");
				notificationManager.Cancel(10000);
				cleanedUp = true;
			}
		}

		public void OnAudioFocusChange(global::Android.Media.AudioFocus focusChange)
		{
			if (mediaService == null)
			{
				ReleaseAudioFocus();
				iFit.Logger.Log.Trace("BackgroundVideoService", "Ignored OnAudioFocusChange - mediaService is null");
				return;
			}
			switch (focusChange)
			{
			case global::Android.Media.AudioFocus.Gain:
				iFit.Logger.Log.Trace("BackgroundVideoService", "Restoring video volume on focus gain");
				mediaService.LockAudioFocus(locked: false);
				break;
			case global::Android.Media.AudioFocus.LossTransient:
				iFit.Logger.Log.Trace("BackgroundVideoService", "Setting 0 volume on transient focus loss");
				mediaService.LockAudioFocus(locked: true);
				break;
			case global::Android.Media.AudioFocus.LossTransientCanDuck:
				iFit.Logger.Log.Trace("BackgroundVideoService", "Ducking volume on transient loss");
				mediaService.LockAudioFocus(locked: true, 0.2f);
				break;
			case global::Android.Media.AudioFocus.Loss:
				iFit.Logger.Log.Trace("BackgroundVideoService", "Setting 0 volume on focus loss");
				ReleaseAudioFocus();
				mediaService.LockAudioFocus(locked: true);
				break;
			default:
				iFit.Logger.Log.Trace("BackgroundVideoService", $"Ignoring focus change: {focusChange}");
				break;
			}
		}
	}
	public class WolfExoPlayerException : System.Exception
	{
		public WolfExoPlayerException(System.Exception innerException)
			: base(CreateExceptionMessage(innerException), innerException)
		{
		}

		private static string CreateExceptionMessage(System.Exception innerException)
		{
			return "Wolf observed ExoPlayer exception: " + innerException.Message;
		}
	}
