		public void OnAudioDisabled(DecoderCounters counters)
		{
			if (!storage.IsAudioInitialLoad && !storage.IsAudioStalled)
			{
				storage.IsAudioStalled = true;
				storage.AudioStallStartTime = DateTime.Now;
				storage.Data.AudioPlaybackStallCount++;
				mediaAnalyticsLogService.WriteToLog("OnAudioDisabled", "!!!! AUDIO STALL DETECTED !!!!");
			}
			mediaAnalyticsLogService.WriteToLog("OnAudioDisabled", counters?.ToString());
		}

		public void OnAudioEnabled(DecoderCounters counters)
		{
			if (storage.IsAudioStalled)
			{
				storage.IsAudioStalled = false;
				double totalMilliseconds = DateTime.Now.Subtract(storage.AudioStallStartTime).TotalMilliseconds;
				storage.Data.TotalAudioStallBufferingTimeMs += totalMilliseconds;
				mediaAnalyticsLogService.WriteToLog("OnAudioEnabled", $"!!!! AUDIO STALL ENDED !!!! Stall Elapsed Time (ms): {totalMilliseconds}");
			}
			mediaAnalyticsLogService.WriteToLog("OnAudioEnabled", counters?.ToString());
		}

