	public class BandwidthMeterEventListener : Java.Lang.Object, IBandwidthMeterEventListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private readonly AndroidMediaAnalyticsStorage storage;

		private readonly IMediaAnalyticsLogService mediaAnalyticsLogService;

		private readonly Action<AndroidNetworkActivityData> raiseNetworkActivityHandledDelegate;

		private readonly System.Action raiseAnalyticsDataUpdatedDelegate;

		public BandwidthMeterEventListener(AndroidMediaAnalyticsStorage storage, IMediaAnalyticsLogService mediaAnalyticsLogService, Action<AndroidNetworkActivityData> raiseNetworkActivityHandledDelegate, System.Action raiseAnalyticsDataUpdatedDelegate)
		{
			this.storage = storage.ThrowIfNull("storage");
			this.mediaAnalyticsLogService = mediaAnalyticsLogService.ThrowIfNull("mediaAnalyticsLogService");
			this.raiseNetworkActivityHandledDelegate = raiseNetworkActivityHandledDelegate.ThrowIfNull("raiseNetworkActivityHandledDelegate");
			this.raiseAnalyticsDataUpdatedDelegate = raiseAnalyticsDataUpdatedDelegate.ThrowIfNull("raiseAnalyticsDataUpdatedDelegate");
		}

		public void OnBandwidthSample(int elapsedMs, long bytes, long bitrate)
		{
			if (bitrate != 1000000)
			{
				storage.Data.AverageBitrateEstimate = (storage.Data.AverageBitrateEstimate * storage.Data.BandwidthSamples + (double)bitrate) / (storage.Data.BandwidthSamples + 1.0);
				storage.Data.BandwidthSamples++;
				if ((double)bitrate < storage.Data.MinBitrateEstimate)
				{
					storage.Data.MinBitrateEstimate = bitrate;
				}
				if ((double)bitrate > storage.Data.MaxBitrateEstimate)
				{
					storage.Data.MaxBitrateEstimate = bitrate;
				}
				raiseAnalyticsDataUpdatedDelegate();
				mediaAnalyticsLogService.WriteToLog("OnBandwidthSample", $"elapsedMs: {elapsedMs}, bytes: {bytes}, bitrate: {bitrate}");
				AndroidNetworkActivityData obj = new AndroidNetworkActivityData(bytes, bitrate);
				raiseNetworkActivityHandledDelegate(obj);
			}
		}
	}
