		public void OnPlayerError(ExoPlaybackException error)
		{
			storage.Data.CountPlayerError(error.Type);
			checkExceptionDelegate(error);
			mediaAnalyticsLogService.WriteToLog("OnPlayerError", error.ToString());
			analyticsDataUpdatedDelegate();
		}

		[Obsolete("deprecated")]
		public void OnPlayerStateChanged(bool playWhenReady, PlaybackState playbackState)
		{
			if (playWhenReady)
			{
				if (storage.IsInitialLoad)
				{
					if (playbackState == PlaybackState.Idle)
					{
						storage.InitialLoadStartTime = DateTime.Now;
					}
				}
				else if (!storage.IsStalled && playbackState == PlaybackState.Buffering)
				{
					storage.IsStalled = true;
					storage.StallStartTime = DateTime.Now;
					storage.Data.PlaybackStallCount++;
					reportStallEventDelegate();
					mediaAnalyticsLogService.WriteToLog("OnPlayerStateChanged", "!!!! STALL DETECTED !!!!");
					analyticsDataUpdatedDelegate();
				}
				else if (storage.IsStalled && playbackState == PlaybackState.Ready)
				{
					storage.IsStalled = false;
					double totalMilliseconds = DateTime.Now.Subtract(storage.StallStartTime).TotalMilliseconds;
					storage.Data.TotalStallBufferingTimeMs += totalMilliseconds;
					mediaAnalyticsLogService.WriteToLog("OnPlayerStateChanged", $"!!!! STALL ENDED !!!! Stall Elapsed Time (ms): {totalMilliseconds}");
				}
			}
			mediaAnalyticsLogService.WriteToLog("OnPlayerStateChanged", $"playWhenReady: {playWhenReady}, playbackState: {(PlaybackStateCode)playbackState}");
		}

		public void OnPositionDiscontinuity(DiscontinuityReason reason)
