		public void OnTimelineChanged(Timeline timeLine, TimelineChangeReason reason)
		{
			storage.Data.TimelineChangeCount++;
			System.Text.StringBuilder stringBuilder = new System.Text.StringBuilder();
			if (timeLine.IsEmpty)
			{
				stringBuilder.Append("timeLine: Empty");
			}
			else
			{
				stringBuilder.Append($"timeLine: (periodCount: {timeLine.PeriodCount}, windowCount: {timeLine.WindowCount})");
			}
			storage.CurrentTimeline = timeLine;
			mediaAnalyticsLogService.WriteToLog("OnTimelineChanged", $"{stringBuilder}, reason: {reason}");
			analyticsDataUpdatedDelegate();
		}

