		public void OnTracksChanged(TrackGroupArray trackGroups, TrackSelectionArray trackSelections)
		{
			System.Text.StringBuilder stringBuilder = new System.Text.StringBuilder();
			if (trackGroups.IsEmpty)
			{
				stringBuilder.Append("trackGroups: Empty");
			}
			else
			{
				stringBuilder.AppendLine($"trackGroups: (count: {trackGroups.Length}, groups:");
				for (int i = 0; i < trackGroups.Length; i++)
				{
					TrackGroup trackGroup = trackGroups.Get(i);
					stringBuilder.AppendLine($"\tGroup {i} Formats:");
					for (int j = 0; j < trackGroup.Length; j++)
					{
						stringBuilder.AppendLine(ExoPlayerLogUtil.GetFormatStr(trackGroup.GetFormat(j)));
					}
				}
				stringBuilder.Append(")");
			}
			System.Text.StringBuilder stringBuilder2 = new System.Text.StringBuilder();
			if (trackSelections.Length < 1)
			{
				stringBuilder2.Append("trackSelections: Empty");
			}
			else
			{
				stringBuilder2.AppendLine($"trackSelections: (count: {trackSelections.Length}, selections:");
				for (int k = 0; k < trackSelections.Length; k++)
				{
					ITrackSelection trackSelection = trackSelections.Get(k);
					if (!(trackSelection is IExoTrackSelection exoTrackSelection))
					{
						stringBuilder2.AppendLine($"\t{k}:\tnull");
						continue;
					}
					stringBuilder2.AppendLine($"\t{k}:\tidx: {exoTrackSelection.SelectedIndex}, idxInGroup: {exoTrackSelection.SelectedIndexInTrackGroup}, reason: {exoTrackSelection.SelectionReason}");
				}
				stringBuilder2.Append(")");
			}
			mediaAnalyticsLogService.WriteToLog("OnTracksChanged", $"{stringBuilder}, {stringBuilder2}");
		}
	}
	public class VideoListener : Java.Lang.Object, IVideoListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private readonly AndroidMediaAnalyticsStorage storage;

		private readonly IMediaAnalyticsLogService mediaAnalyticsLogService;

		private readonly System.Action raiseFirstFrameRenderedDelegate;

		public VideoListener(AndroidMediaAnalyticsStorage storage, IMediaAnalyticsLogService mediaAnalyticsLogService, System.Action raiseFirstFrameRenderedDelegate)
		{
			this.storage = storage.ThrowIfNull("storage");
			this.mediaAnalyticsLogService = mediaAnalyticsLogService.ThrowIfNull("mediaAnalyticsLogService");
			this.raiseFirstFrameRenderedDelegate = raiseFirstFrameRenderedDelegate.ThrowIfNull("raiseFirstFrameRenderedDelegate");
		}

		public void OnRenderedFirstFrame()
		{
			storage.IsInitialLoad = false;
			storage.Data.InitialLoadTimeMs = DateTime.Now.Subtract(storage.InitialLoadStartTime).TotalMilliseconds;
			mediaAnalyticsLogService.WriteToLog("OnRenderedFirstFrame");
			raiseFirstFrameRenderedDelegate();
		}

		public void OnSurfaceSizeChanged(int width, int height)
		{
		}

		public void OnVideoSizeChanged(int width, int height, int unappliedRotationDegrees, float pixelWidthHeightRatio)
		{
			mediaAnalyticsLogService.WriteToLog("OnVideoSizeChanged", $"({width}x{height}), unappliedRotationDegrees: {unappliedRotationDegrees}, pixelWidthHeightRatio: {pixelWidthHeightRatio}");
		}
	}
	public class WifiListener : IDisposable
	{
		private readonly CompositeDisposable disposables = new CompositeDisposable();

		private readonly IMediaAnalyticsLogService mediaAnalyticsLogService;

		private bool disposed;

		public WifiListener(IWifiService wifiService, IMediaAnalyticsLogService mediaAnalyticsLogService)
		{
			this.mediaAnalyticsLogService = mediaAnalyticsLogService;
			wifiService.WhenEnabledChanged.Subscribe(OnWiFiEnabledChanged).DisposeWith(disposables);
			wifiService.WhenNetworkChanged.Subscribe(OnWiFiNetworkChanged).DisposeWith(disposables);
			wifiService.WhenNetworkStateChanged.Subscribe(OnWiFiStateChanged).DisposeWith(disposables);
			wifiService.WhenSignalStrengthChanged.Subscribe(OnWiFiStrengthChanged).DisposeWith(disposables);
		}

		private void OnWiFiEnabledChanged(WifiEnabledState state)
		{
			mediaAnalyticsLogService.WriteToLog("OnWiFiEnabledChanged", state.ToString());
		}

		private void OnWiFiNetworkChanged(WifiNetworkInfo info)
		{
			mediaAnalyticsLogService.WriteToLog("OnWiFiNetworkChanged", $"ssid: {info?.Ssid}, strength: {info?.ConnectionStrength}, security: {info?.Security}");
		}

		private void OnWiFiStateChanged(WifiNetworkState state)
		{
			mediaAnalyticsLogService.WriteToLog("OnWiFiStateChanged", state.ToString());
		}

		private void OnWiFiStrengthChanged(int strength)
		{
			mediaAnalyticsLogService.WriteToLog("OnWiFiStrengthChanged", strength.ToString());
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!disposed && disposing)
			{
				disposables.Dispose();
				disposed = true;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
		}
	}
}
