		private void SetUpSettingsButtonMenu()
		{
			demoModeSettingsButton.Click -= DemoModeSettingsButtonOnClick;
			demoModeSettingsButton.Click += DemoModeSettingsButtonOnClick;
		}

		private void DemoModeSettingsButtonOnClick(object sender, EventArgs e)
		{
			MenuBuilder menuBuilder = new MenuBuilder((Context)(object)this);
			MenuInflater menuInflater = new MenuInflater((Context)(object)this);
			menuInflater.Inflate(2131689473, menuBuilder);
			MenuPopupHelper menuPopupHelper = new MenuPopupHelper((Context)(object)this, menuBuilder, settingsButtonAnchor);
			menuPopupHelper.SetForceShowIcon(forceShowIcon: true);
			menuBuilder.SetCallback(this);
			menuBuilder.FindItem(2131429065).SetTitle(Wolf.Core.Resources.AppStrings.retail_demo_mode_2_marketing_settings_screensaver_volume);
			menuBuilder.FindItem(2131429064).SetTitle(Wolf.Core.Resources.AppStrings.retail_demo_mode_2_marketing_settings_return_to_screensaver);
			menuBuilder.FindItem(2131429063).SetTitle(Wolf.Core.Resources.AppStrings.retail_demo_mode_marketing_exit_demo_mode);
			menuPopupHelper.Show();
		}

		public bool OnMenuItemSelected(MenuBuilder menuBuilder, IMenuItem menuItem)
		{
			switch (menuItem.ItemId)
			{
			case 2131429065:
				base.ViewModel.ScreensaverVolumeMenuItemTap.Execute(null);
				return true;
			case 2131429064:
				base.ViewModel.ReturnToScreensaverMenuItemTap.Execute(null);
				return true;
			case 2131429063:
				base.ViewModel.ExitDemoModeMenuItemTap.Execute(null);
				return true;
			default:
				return false;
			}
		}

