		private void ChangeViewSizesForMirror()
		{
			foreach (RelativeLayout startWorkoutButton in startWorkoutButtons)
			{
				ChangesButtonTextAndIconSize(startWorkoutButton.Id);
			}
			ChangeWorkoutExperienceSectionForMirror(workoutExperienceSectionOneLogo, workoutExperienceSectionOneTitle, workoutExperienceSectionOneBody);
			ChangeWorkoutExperienceSectionForMirror(workoutExperienceSectionTwoLogo, workoutExperienceSectionTwoTitle, workoutExperienceSectionTwoBody);
			ChangeWorkoutExperienceSectionForMirror(workoutExperienceSectionThreeLogo, workoutExperienceSectionThreeTitle, workoutExperienceSectionThreeBody);
			ChangeWorkoutExperienceSectionForMirror(workoutExperienceSectionFourLogo, workoutExperienceSectionFourTitle, workoutExperienceSectionFourBody);
			ChangeWorkoutExperienceSectionForMirror(workoutExperienceSectionFiveLogo, workoutExperienceSectionFiveTitle, workoutExperienceSectionFiveBody);
			ChangeWorkoutExperienceSectionForMirror(workoutExperienceSectionSixLogo, workoutExperienceSectionSixTitle, workoutExperienceSectionSixBody);
		}

		private void ChangesButtonTextAndIconSize(int id)
		{
			RelativeLayout relativeLayout = ((Activity)(object)this).FindViewById<RelativeLayout>(id);
			TextView textView = relativeLayout.FindViewById<TextView>(2131429342);
			if (textView == null)
			{
				return;
			}
			textView.Text = Wolf.Core.Resources.AppStrings.retail_demo_mode_2_repeat_demo_workout_button;
			textView.TextSize = ((Context)(object)this).Resources.GetDimension(2131167535);
			try
			{
				ImageView imageView = relativeLayout.FindViewById<ImageView>(2131429734);
				imageView.LayoutParameters.Width = (int)((Context)(object)this).Resources.GetDimension(2131167533);
				imageView.LayoutParameters.Height = (int)((Context)(object)this).Resources.GetDimension(2131167532);
			}
			catch (System.Exception)
			{
			}
		}

		private void ChangeWorkoutExperienceSectionForMirror(ImageView icon, TextView title, TextView body)
