			icon.LayoutParameters.Height = (int)((Context)(object)this).Resources.GetDimension(2131167519);
			title.TextSize = ((Context)(object)this).Resources.GetDimension(2131167522);
			body.TextSize = ((Context)(object)this).Resources.GetDimension(2131167517);
			if (body.LayoutParameters is RelativeLayout.LayoutParams layoutParams)
			{
				layoutParams.TopMargin = (int)((Context)(object)this).Resources.GetDimension(2131167518);
				body.LayoutParameters = layoutParams;
			}
		}

