		private void SetUnusedFeatureCardViewsInvisible()
		{
			int count = base.ViewModel.MarketingFeatures.Count;
			if (count < 5)
			{
				retailDemoFeaturesSectionFive.Visibility = ViewStates.Gone;
			}
			if (count < 4)
			{
				retailDemoFeaturesSectionFour.Visibility = ViewStates.Gone;
			}
			if (count < 3)
			{
				retailDemoFeaturesSectionThree.Visibility = ViewStates.Gone;
			}
			if (count < 2)
			{
				retailDemoFeaturesSectionTwo.Visibility = ViewStates.Gone;
			}
			if (count < 1)
			{
				retailDemoFeaturesSectionOne.Visibility = ViewStates.Gone;
			}
			if (!base.ViewModel.IsStrengthMirror)
			{
				retailDemoFeaturesSectionThree.Visibility = ViewStates.Gone;
			}
		}

		private void SetPageHeights()
		{
			pageOne = ((Activity)(object)this).FindViewById(base.ViewModel.IsStrengthMirror ? 2131429059 : 2131429042);
			pageOne.LayoutParameters.Height = ScreenHeight;
			SetFeaturesPageHeight();
			pageFour = ((Activity)(object)this).FindViewById(2131429062);
