		protected override void CleanUp()
		{
			base.CleanUp();
			ClearVideo();
			CleanUpViews();
		}

		public void OnScrollChange(View v, int scrollX, int scrollY, int oldScrollX, int oldScrollY)
		{
			Rect rect = new Rect();
			mainScrollView.GetHitRect(rect);
			try
			{
				if (videoMainView.GetLocalVisibleRect(rect) && !isVideoPlaying && base.ViewModel.VideoPlayer.IsReadyToPlay())
				{
					PlayVideo();
				}
				else if (!videoMainView.GetLocalVisibleRect(rect) && isVideoPlaying)
				{
					PauseVideo();
				}
			}
			catch (System.Exception arg)
			{
				global::Android.Util.Log.Error("Video", $"Exception occurred trying to play/pause video: {arg}");
			}
		}

		private void PauseVideo()
		{
			isVideoPlaying = false;
			base.ViewModel.PauseVideoCommand.Execute(null);
		}

		private void PlayVideo()
		{
			isVideoPlaying = true;
			base.ViewModel.PlayVideoCommand.Execute(null);
		}

		private void StopVideo()
		{
			isVideoPlaying = false;
			base.ViewModel.StopVideoCommand.Execute(null);
		}

		private void ClearVideo()
		{
			if (isVideoPlaying)
			{
				StopVideo();
			}
			base.ViewModel.ClearVideoCommand.Execute(null);
		}
	}
	public class RetailDemoModeScreensaverVolumeControlDialogView : BaseDialogFragment<RetailDemoModeScreensaverVolumeControlDialogViewModel>
	{
		private View sampleButtonView;

		private AppCompatTextView sampleButtonTextView;

		private BasicImageView sampleButtonImageView;

		private IfitTextView titleView;

		private IfitTextView descriptionView;

		private MediaPlayer mediaPlayer;

		private bool _playingSampleAudio;

		private string _audioPath;

		private VolumeSeekBar volumeSeekBar;

		protected override int LayoutId => 2131624320;

		public bool PlayingSampleAudio
		{
			get
			{
				return _playingSampleAudio;
			}
			set
			{
				if (_playingSampleAudio != value)
				{
					_playingSampleAudio = value;
					UpdateSampleAudioState();
				}
			}
		}

		public string AudioPath
		{
			get
			{
				return _audioPath;
			}
			set
			{
				_audioPath = value;
				PrepareMediaPlayer();
			}
		}

		public override void OnStart()
		{
			base.OnStart();
			int dimensionPixelSize = base.Resources.GetDimensionPixelSize(2131167551);
			Dialog.Window?.SetLayout(dimensionPixelSize, -2);
		}

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			titleView = view.FindViewById<IfitTextView>(2131429572);
			descriptionView = view.FindViewById<IfitTextView>(2131427851);
			sampleButtonView = view.FindViewById<View>(2131429135);
			sampleButtonTextView = view.FindViewById<AppCompatTextView>(2131429137);
			sampleButtonImageView = view.FindViewById<BasicImageView>(2131429136);
			volumeSeekBar = view.FindViewById<VolumeSeekBar>(2131429752);
			if (volumeSeekBar != null)
			{
				volumeSeekBar.SeekBar.ProgressChanged -= SeekBar_ProgressChanged;
				volumeSeekBar.SeekBar.ProgressChanged += SeekBar_ProgressChanged;
			}
			volumeSeekBar.SeekBar.Max = base.ViewModel.MaxVolumeStep;
			SetBindings(view);
		}

		protected void SetBindings(View view)
		{
			MvxFluentBindingDescriptionSet<RetailDemoModeScreensaverVolumeControlDialogView, RetailDemoModeScreensaverVolumeControlDialogViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<RetailDemoModeScreensaverVolumeControlDialogView, RetailDemoModeScreensaverVolumeControlDialogViewModel>();
			mvxFluentBindingDescriptionSet.Bind(titleView).For((IfitTextView v) => v.Text).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.TitleText);
			mvxFluentBindingDescriptionSet.Bind(descriptionView).For((IfitTextView v) => v.Text).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.MessageText);
			mvxFluentBindingDescriptionSet.Bind(sampleButtonTextView).For((AppCompatTextView v) => v.Text).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SampleButtonText);
			mvxFluentBindingDescriptionSet.Bind(sampleButtonImageView).For((BasicImageView v) => v.ResourceId).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SamplePlaying)
				.WithConversion(new BoolToIntConverter(2131231366, 2131231504));
			mvxFluentBindingDescriptionSet.Bind(sampleButtonImageView).For((BasicImageView v) => v.ScaleX).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SamplePlaying)
				.WithConversion(new BoolToFloatConverter(1f, 1.75f));
			mvxFluentBindingDescriptionSet.Bind(sampleButtonImageView).For((BasicImageView v) => v.ScaleY).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SamplePlaying)
				.WithConversion(new BoolToFloatConverter(1f, 1.75f));
			mvxFluentBindingDescriptionSet.Bind(sampleButtonView).For(sampleButtonView.ClickEvent()).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SampleAudioButtonTouched);
			mvxFluentBindingDescriptionSet.Bind(volumeSeekBar.SeekBar).For((SeekBar x) => x.Progress).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.VolumeStep);
			mvxFluentBindingDescriptionSet.Bind().For((RetailDemoModeScreensaverVolumeControlDialogView v) => v.AudioPath).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SampleAudioPath);
			mvxFluentBindingDescriptionSet.Bind().For((RetailDemoModeScreensaverVolumeControlDialogView v) => v.PlayingSampleAudio).To((RetailDemoModeScreensaverVolumeControlDialogViewModel vm) => vm.SamplePlaying);
			mvxFluentBindingDescriptionSet.Apply();
		}

		protected void SeekBar_ProgressChanged(object sender, SeekBar.ProgressChangedEventArgs e)
		{
			base.ViewModel.VolumeSliderChangedTo(e.Progress);
		}

		private void UpdateSampleAudioState()
		{
			if (mediaPlayer == null)
			{
				PrepareMediaPlayer();
			}
			if (PlayingSampleAudio)
			{
				mediaPlayer.Start();
			}
			else
			{
				mediaPlayer.Pause();
			}
		}

		private void PrepareMediaPlayer()
		{
			try
			{
				mediaPlayer = new MediaPlayer();
				FileDescriptor fD = new FileInputStream(_audioPath).FD;
				mediaPlayer.SetDataSource(fD);
				mediaPlayer.Looping = true;
				mediaPlayer.Prepare();
				mediaPlayer.SetVolume(1f, 1f);
			}
			catch (Java.Lang.Exception ex)
			{
				sampleButtonView.Enabled = false;
				volumeSeekBar.Enabled = false;
				iFit.Logger.Log.Error(base.Tag, "Unable to create Media Player do to exception: " + ex.Message, ex);
			}
		}

		public override void OnDismiss(IDialogInterface dialog)
		{
			try
			{
				mediaPlayer?.Stop();
			}
			catch (IllegalStateException ex)
			{
				iFit.Logger.Log.Error(base.Tag, "Unable to stop Media Player: " + ex.Message, ex);
			}
			finally
			{
				mediaPlayer?.Release();
			}
			base.OnDismiss(dialog);
		}
	}
}
