	public abstract class DemoModeVideoView<TViewModel> : DemoModeViewBase<TViewModel> where TViewModel : DemoModeVideoViewModel
	{
		private bool isDisposed;

		private View loadingView;

		private PlayerView exoView;

		private CircularLoadingView loadingSpinner;

		private Button skipButton;

		private IDisposable playerSub;

		private VolumeSeekBar volumeSeekBar;

		private RelativeLayout screen;

		private bool _showLoadingView;

		protected override bool KeepScreenOn => true;

		protected override StatusTextColorOptions StatusTextColor => StatusTextColorOptions.White;

		protected override int LayoutResId => 2131624324;

		public bool ShowLoadingView
		{
			get
			{
				return _showLoadingView;
			}
			set
			{
				if (_showLoadingView != value)
				{
					_showLoadingView = value;
					ToggleLoadingViewVisible(_showLoadingView);
				}
			}
		}

		protected override void SetupView()
		{
			base.SetupView();
			exoView = ((Activity)(object)this).FindViewById<PlayerView>(2131427995);
			exoView.ResizeMode = 0;
			loadingView = ((Activity)(object)this).FindViewById<View>(2131428537);
			loadingSpinner = ((Activity)(object)this).FindViewById<CircularLoadingView>(2131428901);
			if (base.ViewModel.VideoPlayer is CombinedAudioVideoPlayer combinedAudioVideoPlayer)
			{
				combinedAudioVideoPlayer.VideoPlayer.RepeatMode = RepeatMode.Off;
				combinedAudioVideoPlayer.WhenVideoPlayerChanged.SubscribeAndInvoke(combinedAudioVideoPlayer.VideoPlayer, AttachNewPlayer, ref playerSub);
			}
			skipButton = ((Activity)(object)this).FindViewById<Button>(2131429272);
			skipButton.Text = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_video_skip;
			Button button = ((Activity)(object)this).FindViewById<Button>(2131429587);
			button.Text = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_video_volume;
			volumeSeekBar = ((Activity)(object)this).FindViewById<VolumeSeekBar>(2131429752);
			View volumeGradient = ((Activity)(object)this).FindViewById<View>(2131429753);
			volumeSeekBar.SeekBar.StartTrackingTouch -= VideoVolumeSeekBarOnStartTrackingTouch;
			volumeSeekBar.SeekBar.StartTrackingTouch += VideoVolumeSeekBarOnStartTrackingTouch;
			volumeSeekBar.SeekBar.StopTrackingTouch -= VideoVolumeSeekBarOnStopTrackingTouch;
			volumeSeekBar.SeekBar.StopTrackingTouch += VideoVolumeSeekBarOnStopTrackingTouch;
			volumeSeekBar.SeekBar.ProgressChanged -= SeekBar_ProgressChanged;
			volumeSeekBar.SeekBar.ProgressChanged += SeekBar_ProgressChanged;
			screen = ((Activity)(object)this).FindViewById<RelativeLayout>(2131428591);
			BindViews(this, skipButton, button, volumeSeekBar, volumeGradient, screen);
		}

		protected abstract void VideoVolumeSeekBarOnStartTrackingTouch(object sender, SeekBar.StartTrackingTouchEventArgs e);

		protected abstract void VideoVolumeSeekBarOnStopTrackingTouch(object sender, SeekBar.StopTrackingTouchEventArgs stopTrackingTouchEventArgs);

		protected void SeekBar_ProgressChanged(object sender, SeekBar.ProgressChangedEventArgs e)
		{
			int num = e.Progress;
			if (base.ViewModel.IsAndroidBuiltIn())
			{
				num = SystemVolumeHelper.MapVolume((float)num / 100f);
				volumeSeekBar.SeekBar.SetProgress(num, animate: false);
			}
			base.ViewModel.VideoVolume.Value = (float)num / 100f;
		}

		protected abstract void BindViews(DemoModeVideoView<TViewModel> view, Button skipButton, Button volumeButton, VolumeSeekBar volumeSeekBar, View volumeGradient, RelativeLayout screen);

		public override void OnBackPressed()
		{
		}

		private void AttachNewPlayer(SimpleExoPlayer player)
		{
			if (isDisposed)
			{
				return;
			}
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (exoView != null)
				{
					exoView.Player = player;
				}
			});
		}

		private void ToggleLoadingViewVisible(bool visible)
		{
			if (loadingView != null)
			{
				loadingView.Visibility = ((!visible) ? ViewStates.Gone : ViewStates.Visible);
				if (!visible)
				{
					DeleteLoadingView();
				}
			}
		}

		private void DeleteLoadingView()
		{
			if (!isDisposed)
			{
				loadingSpinner?.Dispose();
				loadingSpinner = null;
				loadingView?.Dispose();
				loadingView = null;
			}
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			CleanUpViews();
			isDisposed = true;
		}

		private void CleanUpViews()
		{
			DeleteLoadingView();
			exoView?.Dispose();
			exoView = null;
			skipButton?.Dispose();
			skipButton = null;
			playerSub?.Dispose();
			playerSub = null;
			volumeSeekBar?.Dispose();
			volumeSeekBar = null;
			screen?.Dispose();
			screen = null;
		}
	}
