		private void HighlightText(IfitTextView textView, string fullStr, string highlightPart)
		{
			SpannableStringBuilder spannableStringBuilder = new SpannableStringBuilder(fullStr);
			if (fullStr.Contains(highlightPart))
			{
				int num = fullStr.IndexOf(highlightPart);
				int end = num + highlightPart.Length;
				IfitCustomTypefaceSpan what = new IfitCustomTypefaceSpan(IfitTypeface.Type.ProximaBold);
				spannableStringBuilder.SetSpan(what, num, end, SpanTypes.InclusiveInclusive);
			}
			textView.TextFormatted = spannableStringBuilder;
		}

