						blueCircle.LayoutParameters.Width = 1;
						blueCircle.LayoutParameters.Height = 1;
						blueCircle.RequestLayout();
					}
					FullAnimationCycle?.Start();
				}
			};
			FullAnimationCycle.Start();
		}

