		{
			MvxFluentBindingDescriptionSet<RetailDemoModeVideoView, RetailDemoModeVideoViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<RetailDemoModeVideoView, RetailDemoModeVideoViewModel>();
			mvxFluentBindingDescriptionSet.Bind(this).For((RetailDemoModeVideoView v) => v.ShowLoadingView).To((RetailDemoModeVideoViewModel vm) => vm.ShowLoading);
			mvxFluentBindingDescriptionSet.Bind(skipButton).For(skipButton.ClickEvent()).To((RetailDemoModeVideoViewModel vm) => vm.SkipVideoButtonTapped);
