				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(volumeButton).For(volumeButton.ClickEvent()).To((RetailDemoModeVideoViewModel vm) => vm.ToggledVolumeButtonTapped);
			mvxFluentBindingDescriptionSet.Bind(volumeButton).For((Button v) => v.Visibility).To((RetailDemoModeVideoViewModel vm) => vm.ShowVolumeButton)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(volumeSeekBar).For((VolumeSeekBar v) => v.Visibility).To((RetailDemoModeVideoViewModel vm) => vm.ShowVolumeBar)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(volumeGradient).For((View v) => v.Visibility).To((RetailDemoModeVideoViewModel vm) => vm.ShowVolumeBar)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(volumeSeekBar.SeekBar).For((SeekBar x) => x.Progress).To((RetailDemoModeVideoViewModel vm) => vm.VideoVolume)
				.WithConversion(new FloatToIntPercentageConverter());
			mvxFluentBindingDescriptionSet.Bind(screen).For(screen.ClickEvent()).To((RetailDemoModeVideoViewModel vm) => vm.ScreenTouched);
			mvxFluentBindingDescriptionSet.Apply();
		}

		protected override void VideoVolumeSeekBarOnStartTrackingTouch(object sender, SeekBar.StartTrackingTouchEventArgs e)
		{
			base.ViewModel?.VideoVolumeTouched();
		}

		protected override void VideoVolumeSeekBarOnStopTrackingTouch(object sender, SeekBar.StopTrackingTouchEventArgs stopTrackingTouchEventArgs)
		{
			base.ViewModel?.VideoVolumeReleased();
		}
	}
