	[Platform(PlatformAttribute.FormFactorType.Tablet, typeof(StrengthMirrorDemoModeScreensaverViewModel))]
	public class StrengthMirrorDemoModeScreensaverView : DemoModeViewBase<StrengthMirrorDemoModeScreensaverViewModel>
	{
		private enum Location
		{
			TopLeft = 1,
			TopRight,
			BottomLeft,
			BottomRight,
			Center
		}

		private const int ButtonMoveTimerMs = 10000;

		private RelativeLayout buttonContainer;

		private RelativeLayout screensaverContainer;

		private ImageView innerCircle;

		private ImageView outerCircle;

		private ImageView maskCircle;

		private ImageView logo;

		private IfitTextView experienceTrainingTextView;

		private IfitTextView touchHereTextView;

		private System.Timers.Timer timer;

		private int locationCounter;

		private bool cleanedUp;

		private bool animationReversed;

		private Animation scaleDown;

		private Animation scaleUpMain;

		private Animation scaleUp;

		private Animation maskScaleUp;

		private Animator fadeIn;

		private Animator fadeOut;

		protected override int LayoutResId => 2131624422;

		protected override void SetupView()
		{
			base.SetupView();
			buttonContainer = ((Activity)(object)this).FindViewById<RelativeLayout>(2131429615);
			screensaverContainer = ((Activity)(object)this).FindViewById<RelativeLayout>(2131429463);
			innerCircle = ((Activity)(object)this).FindViewById<ImageView>(2131428326);
			innerCircle.SetImageResource(2131231921);
			outerCircle = ((Activity)(object)this).FindViewById<ImageView>(2131428739);
			maskCircle = ((Activity)(object)this).FindViewById<ImageView>(2131427516);
			logo = ((Activity)(object)this).FindViewById<ImageView>(2131428574);
			logo.SetImageResource(2131231347);
			experienceTrainingTextView = ((Activity)(object)this).FindViewById<IfitTextView>(2131427729);
			touchHereTextView = ((Activity)(object)this).FindViewById<IfitTextView>(2131429617);
			StartTouchButtonAnimations();
			EnableTimer();
			MvxFluentBindingDescriptionSet<StrengthMirrorDemoModeScreensaverView, StrengthMirrorDemoModeScreensaverViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<StrengthMirrorDemoModeScreensaverView, StrengthMirrorDemoModeScreensaverViewModel>();
			mvxFluentBindingDescriptionSet.Bind(screensaverContainer).For(screensaverContainer.ClickEvent()).To((StrengthMirrorDemoModeScreensaverViewModel vm) => vm.ScreenTapped);
			mvxFluentBindingDescriptionSet.Bind(experienceTrainingTextView).For((IfitTextView x) => x.Text).To((StrengthMirrorDemoModeScreensaverViewModel vm) => vm.ExperienceTraining);
			mvxFluentBindingDescriptionSet.Bind(touchHereTextView).For((IfitTextView x) => x.Text).To((StrengthMirrorDemoModeScreensaverViewModel vm) => vm.TouchHere);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void DisableTimer()
		{
			if (timer != null)
			{
				timer.Elapsed -= MoveButtonLocation;
				timer.Dispose();
				timer = null;
			}
		}

		private void EnableTimer()
		{
			DisableTimer();
			timer = new System.Timers.Timer(10000.0);
			timer.Elapsed += MoveButtonLocation;
			timer.Start();
		}

		private void StartTouchButtonAnimations()
		{
			if (scaleDown != null)
			{
				scaleDown.AnimationEnd -= HandleScaleDownAnimationRepeat;
				scaleDown.Dispose();
			}
			if (scaleUpMain != null)
			{
				scaleUpMain.AnimationEnd -= HandleScaleDownAnimationRepeat;
				scaleUpMain.Dispose();
			}
			scaleDown = AnimationUtils.LoadAnimation((Context)(object)this, 2130772014);
			scaleDown.AnimationEnd += HandleScaleDownAnimationRepeat;
			scaleUpMain = AnimationUtils.LoadAnimation((Context)(object)this, 2130772016);
			scaleUpMain.AnimationEnd += HandleScaleDownAnimationRepeat;
			innerCircle.StartAnimation(scaleUpMain);
			scaleUp?.Dispose();
			scaleUp = AnimationUtils.LoadAnimation((Context)(object)this, 2130772015);
			scaleUp.AnimationEnd += delegate
			{
				outerCircle.Visibility = ViewStates.Invisible;
			};
			maskScaleUp?.Dispose();
			maskScaleUp = AnimationUtils.LoadAnimation((Context)(object)this, 2130772015);
			maskScaleUp.AnimationEnd += delegate
			{
				maskCircle.Visibility = ViewStates.Invisible;
			};
			maskScaleUp.Duration = 400L;
			maskScaleUp.StartOffset = 200L;
		}

		private void HandleScaleDownAnimationRepeat(object sender, EventArgs args)
		{
			if (!cleanedUp)
			{
				if (!animationReversed)
				{
					animationReversed = true;
					innerCircle.StartAnimation(scaleDown);
					outerCircle.StartAnimation(scaleUp);
					maskCircle.StartAnimation(maskScaleUp);
					outerCircle.Visibility = ViewStates.Visible;
					maskCircle.Visibility = ViewStates.Visible;
				}
				else
				{
					animationReversed = false;
					innerCircle.StartAnimation(scaleUpMain);
				}
			}
		}

		private void MoveButtonLocation(object sender, ElapsedEventArgs e)
		{
			((Activity)(object)this).RunOnUiThread((System.Action)delegate
			{
				if (!cleanedUp)
				{
					if (fadeOut != null)
					{
						fadeOut.AnimationEnd -= HandleFadeOutAnimationEnd;
						fadeOut.Dispose();
					}
					fadeOut = (AnimatorSet)AnimatorInflater.LoadAnimator((Context)(object)this, 2130837538);
					fadeOut.SetTarget(buttonContainer);
					fadeIn?.Dispose();
					fadeIn = (AnimatorSet)AnimatorInflater.LoadAnimator((Context)(object)this, 2130837537);
					fadeIn.SetTarget(buttonContainer);
					fadeOut.AnimationEnd += HandleFadeOutAnimationEnd;
					fadeOut.Start();
				}
			});
		}

		private void HandleFadeOutAnimationEnd(object sender, EventArgs args)
		{
			if (!cleanedUp)
			{
				locationCounter = (locationCounter + 1) % 5;
				buttonContainer.LayoutParameters = GetLayoutParamsForLocation(locationCounter);
				fadeIn?.Start();
			}
		}

		private RelativeLayout.LayoutParams GetLayoutParamsForLocation(int l)
		{
			RelativeLayout.LayoutParams layoutParams = buttonContainer.LayoutParameters as RelativeLayout.LayoutParams;
			switch (l)
			{
			case 1:
				layoutParams?.RemoveRule(LayoutRules.CenterInParent);
				layoutParams?.AddRule(LayoutRules.AlignParentLeft);
				layoutParams?.AddRule(LayoutRules.AlignParentTop);
				layoutParams?.SetMargins(16, 16, 0, 0);
				break;
			case 2:
				layoutParams?.RemoveRule(LayoutRules.AlignParentLeft);
				layoutParams?.AddRule(LayoutRules.AlignParentRight);
				layoutParams?.AddRule(LayoutRules.AlignParentTop);
				layoutParams?.SetMargins(0, 16, 16, 0);
				break;
			case 3:
				layoutParams?.RemoveRule(LayoutRules.AlignParentRight);
				layoutParams?.RemoveRule(LayoutRules.AlignParentTop);
				layoutParams?.AddRule(LayoutRules.AlignParentBottom);
				layoutParams?.AddRule(LayoutRules.AlignParentLeft);
				layoutParams?.SetMargins(16, 0, 0, 16);
				break;
			case 4:
				layoutParams?.RemoveRule(LayoutRules.AlignParentLeft);
				layoutParams?.AddRule(LayoutRules.AlignParentBottom);
				layoutParams?.AddRule(LayoutRules.AlignParentRight);
				layoutParams?.SetMargins(0, 0, 16, 16);
				break;
			default:
				layoutParams?.RemoveRule(LayoutRules.AlignParentBottom);
				layoutParams?.RemoveRule(LayoutRules.AlignParentRight);
				layoutParams?.AddRule(LayoutRules.CenterInParent);
				layoutParams?.SetMargins(0, 0, 0, 0);
				break;
			}
			return layoutParams;
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			cleanedUp = true;
			DisableTimer();
			buttonContainer = iFit.Extensions.Android.JavaExtensions.DisposeSafe(buttonContainer);
			innerCircle = iFit.Extensions.Android.JavaExtensions.DisposeSafe(innerCircle);
			logo = iFit.Extensions.Android.JavaExtensions.DisposeSafe(logo);
			touchHereTextView = iFit.Extensions.Android.JavaExtensions.DisposeSafe(touchHereTextView);
			experienceTrainingTextView = iFit.Extensions.Android.JavaExtensions.DisposeSafe(experienceTrainingTextView);
			fadeIn = iFit.Extensions.Android.JavaExtensions.DisposeSafe(fadeIn);
			fadeOut = iFit.Extensions.Android.JavaExtensions.DisposeSafe(fadeOut);
			scaleDown = iFit.Extensions.Android.JavaExtensions.DisposeSafe(scaleDown);
			scaleUp = iFit.Extensions.Android.JavaExtensions.DisposeSafe(scaleUp);
			maskCircle = iFit.Extensions.Android.JavaExtensions.DisposeSafe(maskCircle);
			maskScaleUp = iFit.Extensions.Android.JavaExtensions.DisposeSafe(maskScaleUp);
		}
	}
