namespace Wolf.Android.RetailDemo.Services
{
	public class AndroidOldRetailDemoMode1Service : OldRetailDemoMode1ServiceBase
	{
		private const string PersistentFilesFolderName = ".PersistentFiles";

		private const string AssetFolderName = ".retaildemo";

		private const string SmdmAssetFolderName = ".strengthMirrorDemoAssets";

		private const string MarketingAssetFolderName = "marketing";

		private const string WorkoutAssetFolderName = "workouts";

		private const int FileBufferSize = 8192;

		private static readonly TimeSpan DownloadPartTimeout = TimeSpan.FromSeconds(15.0);

		private string absoluteExternalStorageDirectoryPath;

		private string absoluteAssetDirectoryName;

		private bool isUsingSmdmAssets;

		private bool isUsingPersistentFilesDirectory;

		private string BaseSmdmFolderPath => System.IO.Path.Combine(SDCardPath, ".strengthMirrorDemoAssets");

		protected override string SDCardPath => global::Android.OS.Environment.ExternalStorageDirectory.AbsolutePath;

		protected override string BasePersistentAssetFolderPath
		{
			get
			{
				if (!ShouldUseSmdmAssets)
				{
					return System.IO.Path.Combine(absoluteExternalStorageDirectoryPath, absoluteAssetDirectoryName);
				}
				return BaseSmdmFolderPath;
			}
		}

		protected override string BaseVolatileDataFolderPath
		{
			get
			{
				if (!ShouldUseSmdmAssets)
				{
					return System.IO.Path.Combine(SDCardPath, absoluteAssetDirectoryName);
				}
				return BaseSmdmFolderPath;
			}
		}

		protected override string BaseMarketingAssetFolderPath
		{
			get
			{
				if (!ShouldUseSmdmAssets)
				{
					return System.IO.Path.Combine(BasePersistentAssetFolderPath, "marketing");
				}
				return BaseSmdmFolderPath;
			}
		}

		protected string BaseWorkoutsFolderPath => System.IO.Path.Combine(BasePersistentAssetFolderPath, "workouts");

		public override string AssetFolderPath
		{
			get
			{
				if (!ShouldUseSmdmAssets)
				{
					return GetCurrentConsoleAssetFolderPath();
				}
				return BaseSmdmFolderPath;
			}
		}

		public override string WorkoutsFolderPath => GetCurrentConsoleWorkoutsFolderPath();

		public override bool ShouldUseSmdmAssets => isUsingSmdmAssets;

		public override bool DoesRequireDownloadingContent => !isUsingPersistentFilesDirectory;

		public AndroidOldRetailDemoMode1Service(ICurrentConsoleService currentConsoleService, IFeatureFlagManager featureFlagManager, IWolfAnalytics analytics)
			: base(currentConsoleService, featureFlagManager, analytics)
		{
			CheckIfCanWriteToPersistentFilesDirectory();
			DetermineStorageLocation();
		}

		private void DetermineStorageLocation()
		{
			absoluteAssetDirectoryName = ".strengthMirrorDemoAssets";
			iFit.Logger.Log.Trace(LogTag, "Checking for directory at: " + BaseSmdmFolderPath + "...");
			if (Directory.Exists(BaseSmdmFolderPath))
			{
				iFit.Logger.Log.Trace(LogTag, "Directory exists at: " + BaseSmdmFolderPath);
				iFit.Logger.Log.Trace(LogTag, "SMDM assets detected, setting ShouldUseSmdmAssets true");
				isUsingSmdmAssets = true;
				return;
			}
			absoluteExternalStorageDirectoryPath = System.IO.Path.Combine(global::Android.OS.Environment.RootDirectory.AbsolutePath, "..", ".PersistentFiles");
			absoluteAssetDirectoryName = ".retaildemo";
			isUsingSmdmAssets = false;
			iFit.Logger.Log.Trace(LogTag, "Checking for directory at: " + BaseMarketingAssetFolderPath + "...");
			if (Directory.Exists(BaseMarketingAssetFolderPath))
			{
				iFit.Logger.Log.Trace(LogTag, "Directory exists at: " + BaseMarketingAssetFolderPath);
				isUsingPersistentFilesDirectory = true;
				return;
			}
			absoluteExternalStorageDirectoryPath = SDCardPath;
			iFit.Logger.Log.Trace(LogTag, "Checking for directory at: " + BaseMarketingAssetFolderPath + "...");
			if (Directory.Exists(BaseMarketingAssetFolderPath))
			{
				iFit.Logger.Log.Trace(LogTag, "Directory exists at: " + BaseMarketingAssetFolderPath);
			}
			else
			{
				iFit.Logger.Log.Error(LogTag, "Could not locate AndroidOldRetailDemoMode1Service marketing assets.");
			}
		}

		private void CheckIfCanWriteToPersistentFilesDirectory()
		{
			string pathname = System.IO.Path.Combine(global::Android.OS.Environment.RootDirectory.AbsolutePath, "..", ".PersistentFiles");
			Java.IO.File file = new Java.IO.File(pathname);
			if (file.Exists() && file.CanWrite())
			{
				base.CanWriteToPersistentFilesDirectory = true;
			}
		}

		public override bool CheckStoredAssetsIntegrity()
