		protected override Task<FileDownloadReport> DownloadAndStoreAssetFileIfNecessary(System.Uri assetFileUrl, string assetFilePath, System.Threading.CancellationToken cancellationToken = default(System.Threading.CancellationToken))
		{
			if (string.IsNullOrWhiteSpace(assetFileUrl?.AbsoluteUri))
			{
				throw new ArgumentNullException("assetFileUrl");
			}
			if (string.IsNullOrWhiteSpace(assetFilePath))
			{
				throw new ArgumentNullException("assetFilePath");
			}
			return DownloadAndStoreAssetFileIfNecessaryInternal(assetFileUrl, assetFilePath, cancellationToken);
		}

		private async Task<FileDownloadReport> DownloadAndStoreAssetFileIfNecessaryInternal(System.Uri assetFileUrl, string assetFilePath, System.Threading.CancellationToken cancellationToken = default(System.Threading.CancellationToken))
		{
			using HttpClient client = new HttpClient(new NativeMessageHandler());
			HttpResponseMessage httpResponseMessage = await client.GetAsync(assetFileUrl, HttpCompletionOption.ResponseHeadersRead, cancellationToken).TimeoutAfter(DownloadPartTimeout, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			if (httpResponseMessage == null || !httpResponseMessage.IsSuccessStatusCode)
			{
				throw new WebException("Request was responded to with status code: " + (httpResponseMessage?.StatusCode.ToString() ?? "<unknown>"));
			}
			if (httpResponseMessage.Content == null)
			{
				throw new WebException("Request was responded to with missing content value.");
			}
			cancellationToken.ThrowIfCancellationRequested();
			bool isJsonFile = assetFileUrl.AbsoluteUri.EndsWith(".json");
			long totalData = (httpResponseMessage.Content?.Headers?.ContentLength).GetValueOrDefault();
			if (totalData == 0L && !isJsonFile)
			{
				return new FileDownloadReport
				{
					ResourceBytes = 0L,
					DownloadedBytes = 0L,
					DownloadedSuccessfully = false
				};
			}
			System.IO.FileInfo fileInfo = new System.IO.FileInfo(assetFilePath);
			if (fileInfo.Exists && fileInfo.Length == totalData)
			{
				return new FileDownloadReport
				{
					ResourceBytes = totalData,
					DownloadedBytes = totalData,
					DownloadedSuccessfully = true,
					FilePath = assetFilePath
				};
			}
			long downloadedBytes = 0L;
			FileDownloadProgressChangedOccurred(System.IO.Path.GetFileName(assetFilePath), totalData, downloadedBytes);
			try
			{
				downloadedBytes = await DownloadFileFromHttpResponse(httpResponseMessage, totalData, assetFilePath, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (TaskCanceledException)
			{
				iFit.Logger.Log.Error(LogTag, "RetailDemoModeService DownloadFileFromHttpResponse operation cancelled.");
				throw;
			}
			catch (System.OperationCanceledException)
			{
				iFit.Logger.Log.Error(LogTag, "RetailDemoModeService DownloadFileFromHttpResponse operation cancelled.");
				throw;
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error(LogTag, $"Exception occurred downloading file at {assetFileUrl} to {assetFilePath}", exception);
				System.IO.FileInfo fileInfo2 = new System.IO.FileInfo(assetFilePath);
				return new FileDownloadReport
				{
					ResourceBytes = totalData,
					DownloadedBytes = (fileInfo2.Exists ? fileInfo2.Length : 0),
					DownloadedSuccessfully = false
				};
			}
			if (isJsonFile)
			{
				totalData = downloadedBytes;
			}
			System.IO.FileInfo fileInfo3 = new System.IO.FileInfo(assetFilePath);
			bool downloadedSuccessfully = fileInfo3.Exists && fileInfo3.Length == totalData && fileInfo3.Length == downloadedBytes;
			return new FileDownloadReport
			{
				ResourceBytes = totalData,
				DownloadedBytes = downloadedBytes,
				DownloadedSuccessfully = downloadedSuccessfully,
				FilePath = assetFilePath
			};
		}

		private async Task<long> DownloadFileFromHttpResponse(HttpResponseMessage response, long totalData, string assetFilePath, System.Threading.CancellationToken cancellationToken = default(System.Threading.CancellationToken))
		{
			long downloadedBytes = 0L;
			using (FileStream fileStream = System.IO.File.Open(assetFilePath, FileMode.Create))
			{
				using System.IO.Stream contentStream = await response.Content.ReadAsStreamAsync().TimeoutAfter(DownloadPartTimeout, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				byte[] buffer = new byte[8192];
				bool doneReading = false;
				while (!doneReading)
				{
					cancellationToken.ThrowIfCancellationRequested();
					int bytesRead = await contentStream.ReadAsync(buffer, 0, buffer.Length, cancellationToken).TimeoutAfter(DownloadPartTimeout, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					if (bytesRead < 1)
					{
						doneReading = true;
						continue;
					}
					await fileStream.WriteAsync(buffer, 0, bytesRead, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					downloadedBytes += bytesRead;
					FileDownloadProgressChangedOccurred(System.IO.Path.GetFileName(assetFilePath), totalData, downloadedBytes);
				}
			}
			return downloadedBytes;
		}

		protected override string GetBaseName(string filePath)
		{
			return System.IO.Path.GetFileName(filePath);
		}

		protected override List<string> GetFilePathsInFolder(string folderPath)
		{
			if (DoesFolderExistAtLocation(folderPath))
			{
				return (from x in new DirectoryInfo(folderPath).GetFiles()
					select x.FullName).ToList();
			}
			return new List<string>();
		}

		protected override long GetFileSize(string filePath)
		{
			System.IO.FileInfo fileInfo = new System.IO.FileInfo(filePath);
			if (!fileInfo.Exists)
			{
				throw new FileNotFoundException("File does not exist.", filePath);
			}
			return fileInfo.Length;
		}

