			if (!fileInfo.Exists)
			{
				throw new FileNotFoundException("File does not exist.", filePath);
			}
			return System.IO.File.ReadAllText(filePath);
		}
	}
	public class RetailDemoLocalWorkoutService : RetailDemoLocalWorkoutServiceBase
	{
		private const string PersistentFilesFolderName = ".PersistentFiles";

		private string _absoluteExternalStorageDirectoryPath;

		protected override string AbsoluteExternalStorageDirectoryPath => _absoluteExternalStorageDirectoryPath;

		public RetailDemoLocalWorkoutService()
		{
			DetermineStorageLocation();
		}

		private void DetermineStorageLocation()
		{
			_absoluteExternalStorageDirectoryPath = System.IO.Path.Combine(global::Android.OS.Environment.RootDirectory.AbsolutePath, "..", ".PersistentFiles");
			iFit.Logger.Log.Trace("RetailDemoMode", "Checking for directory at: " + base.AbsoluteWorkoutContentPath + "...");
			if (Directory.Exists(base.AbsoluteWorkoutContentPath))
			{
				iFit.Logger.Log.Trace("RetailDemoMode", "Directory exists at: " + base.AbsoluteWorkoutContentPath);
				return;
			}
			_absoluteExternalStorageDirectoryPath = global::Android.OS.Environment.ExternalStorageDirectory.AbsolutePath;
			iFit.Logger.Log.Trace("RetailDemoMode", "Checking for directory at: " + base.AbsoluteWorkoutContentPath + "...");
			if (Directory.Exists(base.AbsoluteWorkoutContentPath))
			{
				iFit.Logger.Log.Trace("RetailDemoMode", "Directory exists at: " + base.AbsoluteWorkoutContentPath);
			}
			else
			{
				iFit.Logger.Log.Error("RetailDemoMode", "Could not locate RetailDemoLocalWorkoutService assets.");
			}
		}

