namespace Wolf.Android.Source.Views
{
	public abstract class BaseKeyboardResizingView<TViewModel> : BaseActivity<TViewModel> where TViewModel : class, IMvxViewModel
	{
		private ConstraintLayout rootLayout;

		private ViewGroup.LayoutParams rootLayoutParams;

		private bool isBuiltIn;

		protected void SetRootLayout(int rootId, bool alwaysBuiltIn = false)
		{
			isBuiltIn = (Mvx.TryResolve<IDeviceInformation>(out var service) && service.IsBuiltIn && Build.VERSION.SdkInt > BuildVersionCodes.M) || alwaysBuiltIn;
			rootLayout = ((Activity)(object)this).FindViewById<ConstraintLayout>(rootId);
			rootLayoutParams = rootLayout.LayoutParameters;
			if (!isBuiltIn)
			{
				((Activity)(object)this).Window.Attributes.SoftInputMode = SoftInput.AdjustResize;
			}
		}

		protected override void OnPause()
		{
			base.OnPause();
			((Activity)(object)this).Window.DecorView.ViewTreeObserver.GlobalLayout -= ViewTreeObserver_GlobalLayoutForKeyboard;
		}

		protected override void OnResume()
		{
			base.OnResume();
			((Activity)(object)this).Window.DecorView.ViewTreeObserver.GlobalLayout -= ViewTreeObserver_GlobalLayoutForKeyboard;
			((Activity)(object)this).Window.DecorView.ViewTreeObserver.GlobalLayout += ViewTreeObserver_GlobalLayoutForKeyboard;
		}

		private void ViewTreeObserver_GlobalLayoutForKeyboard(object sender, EventArgs e)
		{
			if (rootLayout != null && ((Activity)(object)this).Window != null && isBuiltIn)
			{
				Rect rect = new Rect();
				((Activity)(object)this).Window.DecorView.GetWindowVisibleDisplayFrame(rect);
				int bottom = rect.Bottom;
				int height = rootLayout.Height;
				if (height > bottom)
				{
					AdjustDialogLayoutForKeyboardOpen(bottom);
				}
				if (height < bottom)
				{
					AdjustDialogLayoutForKeyboardClosed();
				}
				rootLayout?.RequestLayout();
			}
		}

		private void AdjustDialogLayoutForKeyboardOpen(int height)
		{
			rootLayoutParams.Height = height;
			rootLayout.LayoutParameters = rootLayoutParams;
		}

		private void AdjustDialogLayoutForKeyboardClosed()
		{
			rootLayoutParams.Height = -1;
			rootLayout.LayoutParameters = rootLayoutParams;
		}
	}
}
