	public class LanguageSelectionView : BaseFragment<LanguageSelectionViewModel>, AdapterView.IOnItemClickListener, IJavaObject, IDisposable, IJavaPeerable
	{
		public class LanguagesListViewAdapter : MvxListViewAdapter<LanguageItem>
		{
			private ArrayList listItemList = new ArrayList();

			public LanguagesListViewAdapter(IntPtr javaReference, JniHandleOwnership transfer)
				: base(javaReference, transfer)
			{
			}

			public LanguagesListViewAdapter(Context context, IMvxAndroidBindingContext bindingContext)
				: base(context, bindingContext, -2147483648)
			{
			}

			protected override IMvxListItemView CreateViewBasedOnInfo(LanguageItem dataContext, int templateId)
			{
				SettingsLanguagesListItem settingsLanguagesListItem = new SettingsLanguagesListItem(base.Context)
				{
					DataContext = dataContext
				};
				listItemList.Add(settingsLanguagesListItem);
				return settingsLanguagesListItem;
			}

			protected override int GetTemplateIdForPosition(int position)
			{
				return 2131624236;
			}

			protected internal void switchRadio(int pos)
			{
				for (int i = 0; i < listItemList.Count; i++)
				{
					SettingsLanguagesListItem settingsLanguagesListItem = (SettingsLanguagesListItem)listItemList[i];
					settingsLanguagesListItem.flipRadioButton(on: false);
					if (i == pos)
					{
						settingsLanguagesListItem.flipRadioButton(on: true);
					}
				}
			}
		}

		private class SettingsLanguagesListItem : LinearLayout, IMvxListItem, IMvxBindingContextOwner, IMvxListItemView, IMvxDataConsumer
		{
			private BasicImageView radio;

			private IfitTextView title;

			public int TemplateId => 2131624236;

			public IMvxBindingContext BindingContext { get; set; }

			public object DataContext
			{
				get
				{
					return BindingContext.DataContext;
				}
				set
				{
					if (BindingContext.DataContext != value)
					{
						BindingContext.DataContext = value;
					}
				}
			}

			public SettingsLanguagesListItem(Context context)
				: base(context)
			{
				Init();
			}

			private void Init()
			{
				LayoutInflater.From(base.Context).Inflate(TemplateId, this, attachToRoot: true);
				title = FindViewById<IfitTextView>(2131428473);
				radio = FindViewById<BasicImageView>(2131428472);
				this.CreateBindingContext();
				BindingContext.DelayBind(delegate
				{
					MvxFluentBindingDescriptionSet<SettingsLanguagesListItem, LanguageItem> mvxFluentBindingDescriptionSet = this.CreateBindingSet<SettingsLanguagesListItem, LanguageItem>();
					mvxFluentBindingDescriptionSet.Bind(title).For((IfitTextView x) => x.Text).To((LanguageItem vm) => vm.Title);
					mvxFluentBindingDescriptionSet.Bind(title).For((IfitTextView x) => x.Typeface).To((LanguageItem vm) => vm.Selected)
						.WithConversion(new BoolToTypeConverter<Typeface>(IfitTypeface.Type.ProximaBold.GetTypeface(), IfitTypeface.Type.ProximaRegular.GetTypeface()));
					mvxFluentBindingDescriptionSet.Bind(radio).For((BasicImageView x) => x.ResourceId).To((LanguageItem vm) => vm.Selected)
						.WithConversion(new BoolToIntConverter(2131231667, 2131231666));
					mvxFluentBindingDescriptionSet.Apply();
				});
			}

			internal void flipRadioButton(bool on)
			{
				if (on)
				{
					radio.ResourceId = 2131231667;
					title.Typeface = IfitTypeface.Type.ProximaBold.GetTypeface();
				}
				else
				{
					radio.ResourceId = 2131231666;
					title.Typeface = IfitTypeface.Type.ProximaRegular.GetTypeface();
				}
			}
		}

		private MvxListView languageListView;

		private IfitButton nextButton;

		private LanguagesListViewAdapter languagesListViewAdapter;

		protected override int LayoutId => 2131624241;

		private int RowHeight => base.Resources.GetDimensionPixelSize(2131167688);

		public override void OnViewCreated(View view, Bundle savedInstanceState)
		{
			base.OnViewCreated(view, savedInstanceState);
			IfitTextView ifitTextView = View.FindViewById<IfitTextView>(2131429186);
			if (ifitTextView != null)
			{
				ifitTextView.Text = Wolf.Core.Resources.AppStrings.select_language_title;
			}
			languageListView = View.FindViewById<MvxListView>(2131427333);
			if (base.ViewModel?.LanguageListInitialized?.Value == true)
			{
				SetListViewHeight();
			}
			else if (base.ViewModel != null)
			{
				base.ViewModel.LanguageListInitialized.Changed += SetListViewHeight;
			}
			if (languageListView != null)
			{
				languagesListViewAdapter = new LanguagesListViewAdapter(Context, base.BindingContext as IMvxAndroidBindingContext);
				languageListView.Adapter = languagesListViewAdapter;
				languageListView.OnItemClickListener = this;
			}
			nextButton = View.FindViewById<IfitButton>(2131428694);
			if (nextButton != null)
			{
				nextButton.Text = Wolf.Core.Resources.AppStrings.next;
			}
			MvxFluentBindingDescriptionSet<LanguageSelectionView, LanguageSelectionViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<LanguageSelectionView, LanguageSelectionViewModel>();
			mvxFluentBindingDescriptionSet.Bind(languageListView).For((MvxListView x) => x.ItemsSource).To((LanguageSelectionViewModel x) => x.Languages);
			mvxFluentBindingDescriptionSet.Bind(nextButton).For(nextButton.ClickEvent()).To((LanguageSelectionViewModel vm) => vm.NextCommand);
			mvxFluentBindingDescriptionSet.Bind(nextButton).For((IfitButton v) => v.Text).To((LanguageSelectionViewModel vm) => vm.CurrentNextLanguage);
			mvxFluentBindingDescriptionSet.Apply();
		}

		private void SetListViewHeight(object sender = null, EventArgs e = null)
		{
			if (languageListView != null && base.ViewModel != null)
			{
				languageListView.LayoutParameters.Height = RowHeight * base.ViewModel.Languages.Value.Count;
			}
		}

		protected override void CleanUp()
		{
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(languageListView);
			iFit.Extensions.Android.JavaExtensions.DisposeSafe(nextButton);
		}

		public void OnItemClick(AdapterView parent, View view, int position, long id)
		{
			base.ViewModel?.DoSelectLanguage(position);
			languagesListViewAdapter.switchRadio(position);
		}
	}
