namespace Wolf.Android.Source.Views.InWorkout.Header
{
	public class InWorkoutHeaderPaginationView : LinearLayout
	{
		public enum Indicator
		{
			Left,
			Right
		}

		private const int AnimationDuration = 500;

		private Indicator _selected;

		private View leftIndicatorView;

		private View rightIndicatorView;

		private int selectedColor;

		private int nonSelectedColor;

		private ILocalSettings localSettings;

		private bool isDisposed;

		public Indicator SelectedIndicator
		{
			get
			{
				return _selected;
			}
			set
			{
				if (_selected != value)
				{
					ToggleSelected();
				}
				_selected = value;
			}
		}

		private int SelectedWidth => (int)Resources.GetDimension(2131167014);

		private int NonSelectedWidth => (int)Resources.GetDimension(2131167013);

		public InWorkoutHeaderPaginationView(Context context)
			: base(context)
		{
			Initialize(context);
		}

		public InWorkoutHeaderPaginationView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize(context);
		}

		public InWorkoutHeaderPaginationView(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Initialize(context);
		}

		public InWorkoutHeaderPaginationView(Context context, IAttributeSet attributeSet, int defStyleAttr, int defStyleRes)
			: base(context, attributeSet, defStyleAttr, defStyleRes)
		{
			Initialize(context);
		}

		private void Initialize(Context context)
		{
			TypedArray typedArray = base.Context.ObtainStyledAttributes(Resource.Styleable.InWorkoutPaginationHeader);
			if (typedArray != null)
			{
				selectedColor = typedArray.GetColor(1, -1);
				nonSelectedColor = typedArray.GetColor(0, -1);
			}
			else
			{
				selectedColor = ContextCompat.GetColor(context, 2131100187);
				nonSelectedColor = ContextCompat.GetColor(context, 2131100185);
			}
			View view = LayoutInflater.From(context).Inflate(2131624123, null, attachToRoot: true);
			leftIndicatorView = view.FindViewById<View>(2131428494);
			rightIndicatorView = view.FindViewById<View>(2131429110);
			((GradientDrawable)leftIndicatorView.Background).SetColor(new global::Android.Graphics.Color(selectedColor));
			((GradientDrawable)rightIndicatorView.Background).SetColor(new global::Android.Graphics.Color(nonSelectedColor));
			LayoutParams layoutParams = new LayoutParams(-1, -1);
			layoutParams.Gravity = GravityFlags.Center;
			AddView(view, layoutParams);
		}

		private void ToggleSelected()
		{
			if (_selected == Indicator.Left)
			{
				AnimateWidthColor(rightIndicatorView, NonSelectedWidth, SelectedWidth, nonSelectedColor, selectedColor);
				AnimateWidthColor(leftIndicatorView, SelectedWidth, NonSelectedWidth, selectedColor, nonSelectedColor);
			}
			else
			{
				AnimateWidthColor(leftIndicatorView, NonSelectedWidth, SelectedWidth, nonSelectedColor, selectedColor);
				AnimateWidthColor(rightIndicatorView, SelectedWidth, NonSelectedWidth, selectedColor, nonSelectedColor);
			}
		}

		private void AnimateWidthColor(View view, int fromWidth, int toWidth, int fromColor, int toColor)
		{
			ValueAnimator widthAnimator = ValueAnimator.OfInt(fromWidth, toWidth);
			widthAnimator.Update += delegate
			{
				int width = (int)widthAnimator.AnimatedValue;
				ViewGroup.LayoutParams layoutParameters = view.LayoutParameters;
				layoutParameters.Width = width;
				view.LayoutParameters = layoutParameters;
			};
			widthAnimator.SetDuration(500L);
			ValueAnimator colorAnimator = ValueAnimator.OfObject(new ArgbEvaluator(), fromColor, toColor);
			colorAnimator.Update += delegate
			{
				int argb = (int)colorAnimator.AnimatedValue;
				((GradientDrawable)view.Background).SetColor(new global::Android.Graphics.Color(argb));
			};
			colorAnimator.SetDuration(500L);
			widthAnimator.Start();
			colorAnimator.Start();
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !isDisposed)
			{
				leftIndicatorView = iFit.Extensions.Android.JavaExtensions.DisposeSafe(leftIndicatorView);
				rightIndicatorView = iFit.Extensions.Android.JavaExtensions.DisposeSafe(rightIndicatorView);
				isDisposed = true;
			}
			base.Dispose(disposing);
		}
	}
}
