namespace Wolf.Android.Source.Services
{
	public class PermissionsServiceAndroid : IPermissionsService
	{
		private const string LogTag = "Permissions";

		public const int PermissionRequestId = 2346;

		private readonly Dictionary<PermissionType, string> PermissionNames = new Dictionary<PermissionType, string>
		{
			{
				PermissionType.AccessCoarseLocation,
				"android.permission.ACCESS_COARSE_LOCATION"
			},
			{
				PermissionType.AccessFineLocation,
				"android.permission.ACCESS_FINE_LOCATION"
			},
			{
				PermissionType.ReadExternalStorage,
				"android.permission.READ_EXTERNAL_STORAGE"
			},
			{
				PermissionType.WriteExternalStorage,
				"android.permission.WRITE_EXTERNAL_STORAGE"
			},
			{
				PermissionType.BluetoothConnect,
				"android.permission.BLUETOOTH_CONNECT"
			},
			{
				PermissionType.BluetoothScan,
				"android.permission.BLUETOOTH_SCAN"
			}
		};

		private readonly Context _context;

		public static PermissionType[] BlePermissions
		{
			get
			{
				if (Build.VERSION.SdkInt < BuildVersionCodes.S)
				{
					return new PermissionType[2]
					{
						PermissionType.AccessCoarseLocation,
						PermissionType.AccessFineLocation
					};
				}
				return new PermissionType[4]
				{
					PermissionType.AccessCoarseLocation,
					PermissionType.AccessFineLocation,
					PermissionType.BluetoothConnect,
					PermissionType.BluetoothScan
				};
			}
		}

		public PermissionsServiceAndroid(Context context)
		{
			_context = context;
		}

		public bool HasPermissions(PermissionType[] permissions)
		{
			if (!VerifyPermissionsAreValid(permissions))
			{
				return false;
			}
			if (Build.VERSION.SdkInt >= BuildVersionCodes.M)
			{
				return permissions.All((PermissionType x) => ContextCompat.CheckSelfPermission(_context, PermissionNames[x]) == Permission.Granted);
			}
			return true;
		}

		public string[] GetStrings(PermissionType[] permissions)
		{
			if (!VerifyPermissionsAreValid(permissions))
			{
				return new string[0];
			}
			return permissions.Select((PermissionType x) => PermissionNames[x]).ToArray();
		}

		private bool VerifyPermissionsAreValid(IEnumerable<PermissionType> permissions)
		{
			foreach (PermissionType permission in permissions)
			{
				if (!PermissionNames.ContainsKey(permission))
				{
					iFit.Logger.Log.Error("Permissions", $"PermissionsServiceAndroid is missing {permission}. It must be added to PermissionsServiceAndroid.PermissionNames");
					return false;
				}
			}
			return true;
		}
	}
}
