	internal class WifiIconConverter : MvxValueConverter<WifiNetworkInfo, int>
	{
		protected override int Convert(WifiNetworkInfo value, Type targetType, object parameter, CultureInfo culture)
		{
			if (value == null)
			{
				return 2131231709;
			}
			bool locked = value.Auth == WifiNetworkInfo.AuthType.IdentityPass || value.Auth == WifiNetworkInfo.AuthType.Pass;
			return LoadWifiIcon(value.WifiRssiLevel, locked);
		}

		protected int LoadWifiIcon(WifiNetworkInfo.RssiLevel rssi, bool locked)
		{
			switch (rssi)
			{
			case WifiNetworkInfo.RssiLevel.NA:
				return 0;
			case WifiNetworkInfo.RssiLevel.One:
				if (locked)
				{
					return 2131231706;
				}
				return 2131231702;
			case WifiNetworkInfo.RssiLevel.Two:
				if (locked)
				{
					return 2131231706;
				}
				return 2131231703;
			case WifiNetworkInfo.RssiLevel.Three:
				if (locked)
				{
					return 2131231707;
				}
				return 2131231704;
			case WifiNetworkInfo.RssiLevel.Four:
				if (locked)
				{
					return 2131231708;
				}
				return 2131231705;
			default:
				return 2131231709;
			}
		}
	}
