	public class AutoCompleteTextViewWithCursorHack : AutoCompleteTextView
	{
		private bool itemClickOverloaded;

		private ICommand _itemClick;

		public const string EnterClickedBindingTag = "OnEnterClickedEvent";

		public new ICommand ItemClick
		{
			get
			{
				return _itemClick;
			}
			set
			{
				_itemClick = value;
				if (_itemClick != null)
				{
					EnsureItemClickOverloaded();
				}
			}
		}

		public string TextWithCursorHack
		{
			get
			{
				return base.Text;
			}
			set
			{
				if (value != null && !value.Equals(base.Text))
				{
					base.Text = value;
					SetSelection(value.Length);
				}
			}
		}

		public event EventHandler OnEnterClickedEvent;

		public event EventHandler TextWithCursorHackChanged;

		private void EnsureItemClickOverloaded()
		{
			if (!itemClickOverloaded)
			{
				itemClickOverloaded = true;
				base.ItemClick += OnItemClick;
			}
		}

		protected virtual void ExecuteCommandOnItem(ICommand command, int position)
		{
			if (command != null)
			{
				Java.Lang.Object item = Adapter.GetItem(position);
				if (item != null && command.CanExecute(item))
				{
					command.Execute(item);
				}
			}
		}

		public AutoCompleteTextViewWithCursorHack(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public AutoCompleteTextViewWithCursorHack(Context context)
			: base(context)
		{
		}

		public AutoCompleteTextViewWithCursorHack(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
		}

