					userImage.SetImageDrawable(value.ToNative());
					loadingIndicator.Visibility = ViewStates.Gone;
					userImage.Visibility = ViewStates.Visible;
				}
				catch (System.Exception ex)
				{
					iFit.Logger.Log.Error("AvatarImage", ex.Message);
				}
			});
		}

