		private void UpdateForDeviceType(Context context, MockType type)
		{
			int id = 0;
			string text = string.Empty;
			switch (type)
			{
			case MockType.Treadmill:
				id = 2131231296;
				text = Wolf.Core.Resources.AppStrings.dashboard_nonconnected_console_treadmill;
				break;
			case MockType.Bike:
			case MockType.SpinBike:
			case MockType.InclineBike:
				id = 2131231278;
				text = Wolf.Core.Resources.AppStrings.dashboard_nonconnected_console_bike;
				break;
			case MockType.Elliptical:
			case MockType.VerticalElliptical:
			case MockType.FreeStrider:
			case MockType.Hybrid:
				id = 2131231280;
				text = Wolf.Core.Resources.AppStrings.dashboard_nonconnected_console_elliptical;
				break;
			case MockType.Rower:
				id = 2131231282;
				text = Wolf.Core.Resources.AppStrings.dashboard_nonconnected_console_rower;
				break;
			case MockType.Strength:
				id = 2131231284;
				text = Wolf.Core.Resources.AppStrings.dashboard_nonconnected_console_strength;
				break;
			}
			Drawable drawable = context.Resources.GetDrawable(id, null);
			icon.SetImageDrawable(drawable);
			title.Text = text;
