	public class WeeklyStat : RelativeLayout, IMvxBindingContextOwner
	{
		private class WeeklyStatImageConverter : MvxValueConverter<WeeklyStatModel.StatType, int>
		{
			protected override int Convert(WeeklyStatModel.StatType value, Type targetType, object parameter, CultureInfo culture)
			{
				return value switch
				{
					WeeklyStatModel.StatType.Calories => 2131231435, 
					WeeklyStatModel.StatType.ActiveTime => 2131231689, 
					WeeklyStatModel.StatType.Distance => 2131231459, 
					WeeklyStatModel.StatType.ElevationGain => 2131231461, 
					WeeklyStatModel.StatType.ActivityLogCount => 2131231422, 
					_ => 0, 
				};
			}
		}

		private ImageView icon;

		private IfitTextView valueText;

		private IfitTextView unit;

		private IfitTextView description;

		public IMvxBindingContext BindingContext { get; set; }

		public WeeklyStatModel DataContext
		{
			get
			{
				return BindingContext.DataContext as WeeklyStatModel;
			}
			set
			{
				if (BindingContext.DataContext != value)
				{
					BindingContext.DataContext = value;
				}
			}
		}

