		{
			LayoutInflater.From(context).Inflate(2131624452, this, attachToRoot: true);
			icon = FindViewById<ImageView>(2131427817);
			valueText = FindViewById<IfitTextView>(2131427819);
			unit = FindViewById<IfitTextView>(2131427818);
			description = FindViewById<IfitTextView>(2131427816);
			BindingContext = new MvxAndroidBindingContext(context, (IMvxLayoutInflaterHolder)context);
			BindingContext.DelayBind(StatBindings);
		}

		private void StatBindings()
		{
			MvxFluentBindingDescriptionSet<WeeklyStat, WeeklyStatModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<WeeklyStat, WeeklyStatModel>();
			mvxFluentBindingDescriptionSet.Bind(icon).For("ImageViewFromResource").To((WeeklyStatModel vm) => vm.Type)
				.WithConversion(new WeeklyStatImageConverter());
			mvxFluentBindingDescriptionSet.Bind(valueText).For((IfitTextView x) => x.Text).To((WeeklyStatModel vm) => vm.ValueText)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(unit).For((IfitTextView x) => x.Text).To((WeeklyStatModel vm) => vm.UnitText)
				.OneWay();
			mvxFluentBindingDescriptionSet.Bind(description).For((IfitTextView x) => x.Text).To((WeeklyStatModel vm) => vm.TypeLabelText)
				.OneWay();
			mvxFluentBindingDescriptionSet.Apply();
		}
	}
	public class DonutView : View
	{
		private Paint gradientPainter;

		private global::Android.Graphics.Path donutPath;

		private global::Android.Graphics.Color gradientStart = global::Android.Graphics.Color.White;

		private global::Android.Graphics.Color gradientStop = global::Android.Graphics.Color.Orange;

		public DonutView(Context context)
			: base(context)
		{
			Initialize();
		}

		public DonutView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize();
		}

		public DonutView(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize();
		}

		private void Initialize()
		{
			gradientPainter = new Paint(PaintFlags.AntiAlias);
		}

		protected override void OnSizeChanged(int w, int h, int oldw, int oldh)
		{
			base.OnSizeChanged(w, h, oldw, oldh);
			ConfigureShader(gradientStart, gradientStop, h);
			donutPath?.Dispose();
			donutPath = new global::Android.Graphics.Path();
			donutPath.SetFillType(global::Android.Graphics.Path.FillType.EvenOdd);
			donutPath.AddCircle((float)w / 2f, (float)h / 2f, (float)w / 2f, global::Android.Graphics.Path.Direction.Cw);
			donutPath.AddCircle((float)w / 2f, (float)h / 2f, (float)w / 4f, global::Android.Graphics.Path.Direction.Cw);
		}

		public void SetGradientColors(global::Android.Graphics.Color start, global::Android.Graphics.Color stop)
		{
			gradientStart = start;
			gradientStop = stop;
			ConfigureShader(gradientStart, gradientStop, base.Height);
		}

		private void ConfigureShader(global::Android.Graphics.Color start, global::Android.Graphics.Color stop, float height)
		{
			LinearGradient shader = new LinearGradient(0f, 0f, 0f, height, start, stop, Shader.TileMode.Mirror);
			gradientPainter.SetShader(shader);
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			canvas.DrawPath(donutPath, gradientPainter);
		}
	}
