		}

		protected abstract void AddBindings(DrawMapBindingSetWrapper bindingSet);

		protected abstract void SetupViews();

		public virtual void OnShown()
		{
		}

		public virtual void OnHidden()
		{
		}

		protected void Init()
		{
			LayoutInflater.From(base.Context).Inflate(LayoutId, this, attachToRoot: true);
			showAnimation = AnimationUtils.LoadAnimation(base.Context, ShowAnimationId);
			hideAnimation = AnimationUtils.LoadAnimation(base.Context, HideAnimationId);
			SetupViews();
		}

		public virtual void Setup(DrawMapView view, DrawMapBindingSetWrapper bindingSet, IMap map)
		{
			this.map = map;
			drawMapView = view;
			AddBindings(bindingSet);
		}

		protected override void OnVisibilityChanged(View changedView, ViewStates visibility)
		{
			try
			{
				switch (visibility)
				{
				case ViewStates.Invisible:
				case ViewStates.Gone:
					if (hideAnimation != null)
					{
						StartAnimation(hideAnimation);
					}
					OnHidden();
					break;
				case ViewStates.Visible:
					if (showAnimation != null)
					{
						StartAnimation(showAnimation);
					}
					OnShown();
					break;
				}
			}
			catch (ObjectDisposedException)
			{
			}
			catch (RuntimeException)
			{
			}
		}
	}
