	public class DrawMapInclineChart : BaseDrawMapWidget
	{
		private bool _expanded = true;

		private CancellationTokenSource previousCancellationTokenSource;

		protected LineChart chart;

		private int _maxHorizontalResolution;

		private List<Tuple<double, double>> _elevationPoints;

		private ScaledXAxisValueFormatter xAxisValueFormatter;

		protected override int LayoutId => 2131624050;

		public int MaxHorizontalResolution
		{
			get
			{
				return _maxHorizontalResolution;
			}
			set
			{
				int num = value.Clamp(2, 2147483647);
				if (num != _maxHorizontalResolution)
				{
					_maxHorizontalResolution = num;
					previousCancellationTokenSource?.Cancel();
					previousCancellationTokenSource = new CancellationTokenSource();
					System.Threading.Tasks.Task.Run(async delegate
					{
						await UpdateChart(previousCancellationTokenSource.Token);
					}, previousCancellationTokenSource.Token);
				}
			}
		}

		public List<Tuple<double, double>> ElevationPoints
		{
			get
			{
				return _elevationPoints;
			}
			set
			{
				if (value != null)
				{
					_elevationPoints = value;
					previousCancellationTokenSource?.Cancel();
					previousCancellationTokenSource = new CancellationTokenSource();
					System.Threading.Tasks.Task.Run(async delegate
					{
						await UpdateChart(previousCancellationTokenSource.Token);
					}, previousCancellationTokenSource.Token);
				}
			}
		}

		protected List<Tuple<double, double>> InclineControls { get; private set; }

		public List<Workout.Control> WorkoutControls
		{
			get
			{
				return null;
			}
			set
			{
				if (value == null)
				{
					return;
				}
				previousCancellationTokenSource?.Cancel();
				previousCancellationTokenSource = new CancellationTokenSource();
				InclineControls = (from c in value
					where c.Type == Workout.Control.ControlType.Incline
					select new Tuple<double, double>(c.At, System.Math.Max(MinInclineValue, System.Math.Min(c.Value, MaxInclineValue)))).ToList();
				if (!previousCancellationTokenSource.Token.IsCancellationRequested)
				{
					System.Threading.Tasks.Task.Run(async delegate
					{
						await UpdateChart(previousCancellationTokenSource.Token);
					}, previousCancellationTokenSource.Token);
				}
			}
		}

		public bool Updating { get; private set; }

		public bool IsMetric
		{
			get
			{
				return (chart.XAxis.ValueFormatter as ScaledXAxisValueFormatter)?.IsMetric ?? false;
			}
			set
			{
				(chart.XAxis.ValueFormatter as ScaledXAxisValueFormatter).IsMetric = value;
			}
		}

		public double MaxInclineValue { get; set; } = 1.7976931348623157E+308;

		public double MinInclineValue { get; set; } = -1.7976931348623157E+308;

		public bool Expanded
		{
			get
			{
				return _expanded;
			}
			set
			{
				_expanded = value;
				SetChartStyling(Expanded);
				ViewGroup.LayoutParams layoutParameters = LayoutParameters;
				layoutParameters.Height = (Expanded ? ((int)Resources.GetDimension(2131165804)) : ((int)Resources.GetDimension(2131165805)));
				LayoutParameters = layoutParameters;
			}
		}

		public event EventHandler<bool> BeganOrFinishedUpdating;

		public DrawMapInclineChart(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public DrawMapInclineChart(Context context)
