		protected override void SetupViews()
		{
			LayoutInflater.From(base.Context).Inflate(LayoutId, this, attachToRoot: true);
			chart = FindViewById<LineChart>(2131428315);
			chart.AxisLeft.SetDrawZeroLine(mDrawZeroLine: false);
