			chart.XAxis.ValueFormatter = xAxisValueFormatter;
			FindViewById<IfitTextView>(2131428317).Text = Wolf.Core.Resources.AppStrings.draw_map_incline;
			MaxHorizontalResolution = base.Width;
		}

		public override void AddBindings(DrawMapBindingSetWrapper bindingSet)
		{
			bindingSet.Bind(this).For((DrawMapInclineChart v) => v.ElevationPoints).To((DrawMapViewModel vm) => vm.RouteElevationPoints)
				.OneWay();
