		public void SetNeedsDisplay()
		{
			chart?.Invalidate();
		}

		private void SetChartStyling(bool isExpanded)
		{
			chart.SetTouchEnabled(enabled: false);
			chart.AxisLeft.Enabled = true;
			chart.AxisLeft.SetDrawGridLines(enabled: false);
			chart.AxisLeft.SetDrawLabels(isExpanded);
			chart.AxisLeft.SetDrawAxisLine(enabled: false);
			chart.AxisLeft.TextColor = Colors.Named2E3134.ToNative();
			chart.AxisRight.Enabled = false;
			chart.AxisRight.SetDrawAxisLine(enabled: false);
			chart.AxisRight.SetDrawGridLines(enabled: false);
			chart.AxisRight.SetDrawLabels(enabled: false);
			chart.XAxis.AxisLineColor = Colors.Named2E31341F.ToNative();
			chart.XAxis.GridColor = global::Android.Graphics.Color.LightGray;
			chart.XAxis.TextColor = Colors.Named2E3134.ToNative();
			chart.XAxis.SetDrawLimitLinesBehindData(isExpanded);
			chart.XAxis.SetDrawGridLines(enabled: false);
			chart.XAxis.Position = XAxis.XAxisPosition.Bottom;
			chart.XAxis.SetDrawLabels(isExpanded);
			chart.Description = null;
			chart.Legend.Enabled = false;
			chart.SetDrawBorders(enabled: false);
		}

		protected double InclineAxisMaximum()
		{
			if (Expanded)
			{
				return MaxInclineValue + 1.0;
			}
			double num = System.Math.Max(System.Math.Abs(InclineControls.Min((Tuple<double, double> t) => t.Item2)), System.Math.Abs(InclineControls.Max((Tuple<double, double> t) => t.Item2)));
			return num + 1.0;
		}

		protected double InclineAxisMinimum()
		{
			if (Expanded)
			{
				return MinInclineValue - 1.0;
			}
			double num = System.Math.Max(System.Math.Abs(InclineControls.Min((Tuple<double, double> t) => t.Item2)), System.Math.Abs(InclineControls.Max((Tuple<double, double> t) => t.Item2)));
			return 0.0 - num - 1.0;
		}

		private void SetAxisMaxMin()
		{
			chart.AxisLeft.SetAxisMaxValue(Convert.ToSingle(InclineAxisMaximum()));
			chart.AxisLeft.SetAxisMinValue(Convert.ToSingle(InclineAxisMinimum()));
			chart.AxisRight.SetAxisMaxValue(Convert.ToSingle(ElevationPoints.Max((Tuple<double, double> t) => t.Item2)));
			chart.AxisRight.SetAxisMinValue(Convert.ToSingle(ElevationPoints.Min((Tuple<double, double> t) => t.Item2)));
			chart.AxisLeft.Granularity = 1f;
			chart.AxisLeft.GranularityEnabled = true;
		}

		public async System.Threading.Tasks.Task UpdateChart(System.Threading.CancellationToken cancellationToken)
		{
			if (ElevationPoints == null || ElevationPoints.Count == 0 || InclineControls == null || InclineControls.Count == 0)
			{
				return;
			}
			(base.Context as Activity).RunOnUiThread(delegate
			{
				Updating = true;
				this.BeganOrFinishedUpdating?.Invoke(this, Updating);
			});
			Task<Tuple<LineDataSet, double>> elevationDataSetTask = Task<Tuple<LineDataSet, double>>.Factory.StartNew(() => LineDataSetForPoints(ElevationPoints, preferSquashingToStretching: true, cancellationToken), cancellationToken);
			Task<Tuple<LineDataSet, double>> inclineControlDataSetTask = Task<Tuple<LineDataSet, double>>.Factory.StartNew(() => LineDataSetForPoints(InclineControls, preferSquashingToStretching: false, cancellationToken), cancellationToken);
			await System.Threading.Tasks.Task.WhenAll<Tuple<LineDataSet, double>>(elevationDataSetTask, inclineControlDataSetTask);
			if (cancellationToken.IsCancellationRequested)
			{
				return;
			}
			SetAxisMaxMin();
			LineDataSet item = elevationDataSetTask.Result.Item1;
			LineDataSet lineDataSet = inclineControlDataSetTask.Result.Item1;
			double item2 = elevationDataSetTask.Result.Item2;
			if (item == null || lineDataSet == null)
			{
				return;
			}
			List<string> list = new List<string>();
			int num = item.Values.Count - 1;
			double meters = (double)num * item2;
			double displayedDistanceValue = GetDisplayedDistanceValue(meters, IsMetric);
			string text = "0";
			if (displayedDistanceValue < 6.0)
			{
				text = "0.0";
			}
			if (displayedDistanceValue < 1.0)
			{
				text = "0.00";
			}
			xAxisValueFormatter.OutputScale = item2;
			string text2 = (IsMetric ? Wolf.Core.Resources.AppStrings.chart_km : Wolf.Core.Resources.AppStrings.chart_miles);
			string format = text2.Replace("{0}", "{0:" + text + "}");
			for (int num2 = 0; num2 <= num; num2++)
			{
				double meters2 = (double)num2 * item2;
				double displayedDistanceValue2 = GetDisplayedDistanceValue(meters2, IsMetric);
				list.Add(string.Format(format, displayedDistanceValue2));
			}
			int num3 = lineDataSet.Values.Count - 1;
			if (num3 < num)
			{
				object obj = lineDataSet.Values[num3];
				List<Entry> list2 = new List<Entry>();
				float previousValue = 0f;
				for (int num4 = 0; num4 < lineDataSet.Values.Count(); num4++)
				{
					float num5 = ConvertToSingle(lineDataSet.Values[num4], previousValue);
					list2.Add(new Entry(num4, num5));
					previousValue = num5;
				}
				list2.Add(new Entry(num, ConvertToSingle(obj, 0f)));
				lineDataSet = new LineDataSet(list2.ToArray(), lineDataSet.Label);
			}
			StyleElevationDataSet(item);
			StyleInclineControlDataSet(lineDataSet);
			LineData data;
			try
			{
				ILineDataSet[] dataSets = new LineDataSet[2] { item, lineDataSet };
				data = new LineData(dataSets);
			}
			catch (IllegalArgumentException ex)
			{
				iFit.Logger.Log.Trace("DrawMap", "Fatal exception in DrawMap Incline chart - " + ex.Message);
				iFit.Logger.Log.Trace("DrawMap", "Max Resolution: " + MaxHorizontalResolution);
				iFit.Logger.Log.Trace("DrawMap", "Raw elevation points: " + ElevationPoints.Count + "   Raw Incline points: " + InclineControls.Count);
				iFit.Logger.Log.Trace("DrawMap", "Elevation Distance: " + ElevationPoints.Last().Item1 + " Incline Distance: " + InclineControls.Last().Item1);
				iFit.Logger.Log.Trace("DrawMap", "Sample Count: " + num);
				iFit.Logger.Log.Trace("DrawMap", "Label count: " + list.Count + "  -  Last label: " + list.Last());
				iFit.Logger.Log.Trace("DrawMap", "Incline Control Count: " + lineDataSet.EntryCount);
				iFit.Logger.Log.Trace("DrawMap", "Elevation Count: " + item.EntryCount);
				return;
			}
			if (!cancellationToken.IsCancellationRequested)
			{
				chart.Data = data;
				(base.Context as Activity).RunOnUiThread(delegate
				{
					SetNeedsDisplay();
					Updating = false;
					this.BeganOrFinishedUpdating?.Invoke(this, Updating);
				});
			}
		}

		private float ConvertToSingle(object obj, float previousValue)
		{
			try
			{
				return Convert.ToSingle(obj);
			}
			catch (System.Exception)
			{
				return previousValue;
			}
		}

		protected Tuple<LineDataSet, double> LineDataSetForPoints(IList<Tuple<double, double>> rawPoints, bool preferSquashingToStretching, System.Threading.CancellationToken cancellationToken)
		{
			bool flag = rawPoints.Count > MaxHorizontalResolution;
			bool flag2 = rawPoints.Last().Item1 > (double)MaxHorizontalResolution;
			if (preferSquashingToStretching)
			{
				flag = flag || flag2;
			}
			Tuple<IEnumerable<Entry>, double> tuple;
			if (!flag)
			{
				tuple = ((!(rawPoints.Count > 1 && flag2)) ? DataEntriesAtEveryPoint(rawPoints, cancellationToken) : StretchAcrossRouteDistance(rawPoints, MaxHorizontalResolution, cancellationToken));
			}
			else
			{
				try
				{
					InterpolatedCoordinatesResult interpolatedCoordinatesResult = null;
					try
					{
						interpolatedCoordinatesResult = CoordinateInterpolation.InterpolateCoordinateList(rawPoints, MaxHorizontalResolution, startWithZeroPoint: true, cancellationToken);
					}
					catch (ArgumentOutOfRangeException ex)
					{
						iFit.Logger.Log.Trace("DrawMap", $"Exception thrown interpolating coordinate list {ex.GetBaseException()}");
					}
					if (interpolatedCoordinatesResult == null || interpolatedCoordinatesResult.WasCancelled)
					{
						return null;
					}
					tuple = new Tuple<IEnumerable<Entry>, double>(interpolatedCoordinatesResult.InterpolatedCoordinateList.Select((Tuple<int, double> p) => new Entry(p.Item1, (float)p.Item2)), interpolatedCoordinatesResult.HorizontalSpaceBetweenPoints);
				}
				catch (System.Exception ex2)
				{
					iFit.Logger.Log.Trace("DrawMap", ex2.Message);
					return null;
				}
			}
			if (cancellationToken.IsCancellationRequested || tuple == null)
			{
				return null;
			}
			IEnumerable<Entry> item = tuple.Item1;
			double item2 = tuple.Item2;
			return new Tuple<LineDataSet, double>(new LineDataSet(item.ToArray(), ""), item2);
		}

		protected static Tuple<IEnumerable<Entry>, double> StretchAcrossRouteDistance(IList<Tuple<double, double>> dataPoints, int maxPoints, System.Threading.CancellationToken cancellationToken)
		{
			List<Tuple<double, double>> list = dataPoints.ToList();
			Tuple<double, double> tuple = list.First();
			Tuple<double, double> tuple2 = list.Last();
			double num = tuple2.Item1 / (double)maxPoints;
			if (tuple.Item1 > 0.01)
			{
				tuple = new Tuple<double, double>(0.0, 0.0);
				list.Insert(0, tuple);
			}
			int num2 = 1;
			Entry[] array = new Entry[maxPoints];
			array[0] = ElevationPointToChartDataEntry(tuple);
			for (int i = 1; i < maxPoints; i++)
			{
				double num3 = (double)i * num;
				int num4 = (int)num3;
				if (num2 >= list.Count)
				{
					break;
				}
				if ((double)num4 >= list[num2].Item1)
				{
					while (list[num2].Item1 < (double)num4)
					{
						num2++;
						if (cancellationToken.IsCancellationRequested)
						{
							return null;
						}
					}
					Tuple<double, double> tuple3 = list[num2 - 1];
					array[i] = ElevationPointToChartDataEntry(new Tuple<double, double>(i, tuple3.Item2));
				}
				else
				{
					array[i] = ElevationPointToChartDataEntry(new Tuple<double, double>(i, array[i - 1].GetY()));
				}
				if (cancellationToken.IsCancellationRequested)
				{
					return null;
				}
			}
			return new Tuple<IEnumerable<Entry>, double>(array.ToList(), num);
		}

		private static Entry ElevationPointToChartDataEntry(Tuple<double, double> elevationPoint)
		{
			int num = (int)elevationPoint.Item1;
			return new Entry(num, (float)elevationPoint.Item2);
		}

		protected static Tuple<IEnumerable<Entry>, double> DataEntriesAtEveryPoint(IList<Tuple<double, double>> dataPoints, System.Threading.CancellationToken cancellationToken)
		{
			List<Tuple<double, double>> list = dataPoints.ToList();
			Tuple<double, double> tuple = list.First();
			List<Entry> list2 = new List<Entry>(list.Count);
			int num = -1;
			Entry entry = null;
			if (tuple.Item1 > 0.01)
			{
				tuple = new Tuple<double, double>(0.0, 0.0);
				list.Insert(0, tuple);
			}
			foreach (Tuple<double, double> item in list)
			{
				if (cancellationToken.IsCancellationRequested)
				{
					return null;
				}
				int num2 = (int)item.Item1;
				if (num == num2 && entry != null && list2.Contains(entry))
				{
					list2.Remove(entry);
				}
				num = num2;
				entry = ElevationPointToChartDataEntry(item);
				list2.Add(entry);
			}
			return new Tuple<IEnumerable<Entry>, double>(list2, 1.0);
		}

		private static double GetDisplayedDistanceValue(double meters, bool isMetric)
		{
			if (!isMetric)
			{
				return UnitUtil.EnsureMiles(DistanceUnit.M, meters);
			}
			return UnitUtil.EnsureKilometers(DistanceUnit.M, meters);
		}

		protected void StyleElevationDataSet(LineDataSet dataSet)
		{
			dataSet.Color = new global::Android.Graphics.Color(46, 49, 52, 12);
			dataSet.AxisDependency = YAxis.AxisDependency.Right;
			dataSet.SetDrawCircles(enabled: false);
			dataSet.SetDrawValues(enabled: false);
			dataSet.SetDrawFilled(filled: true);
			dataSet.SetMode(LineDataSet.Mode.Linear);
			dataSet.FillDrawable = new ColorDrawable(new global::Android.Graphics.Color(46, 49, 52, 31));
		}

		protected void StyleInclineControlDataSet(LineDataSet dataSet)
		{
			dataSet.Color = new global::Android.Graphics.Color(0, 105, 210);
			dataSet.AxisDependency = YAxis.AxisDependency.Left;
			dataSet.SetDrawCircles(enabled: false);
			dataSet.SetDrawValues(enabled: false);
			dataSet.SetDrawFilled(filled: false);
			dataSet.SetMode(LineDataSet.Mode.Stepped);
			dataSet.FillFormatter = new CustomChartFillFormatter();
			dataSet.LineWidth = 1f;
		}
	}
	internal class ScaledXAxisValueFormatter : Java.Lang.Object, IAxisValueFormatter, IJavaObject, IDisposable
	{
		private IChartLabelUtil chartLabelUtil;

		public double OutputScale { get; set; }

		public bool IsMetric { get; set; }

		public ScaledXAxisValueFormatter(IChartLabelUtil chartLabelUtil)
		{
			this.chartLabelUtil = chartLabelUtil;
			OutputScale = 1.0;
		}

		public string GetFormattedValue(float value, AxisBase axis)
		{
			return chartLabelUtil.ResolveLabel((long)((double)value * OutputScale), IsMetric);
		}
	}
