		private void OnMinimizeButtonClicked(object sender, EventArgs e)
		{
			if (isMinimized)
			{
				Animate().TranslationX(0f).SetDuration(500L).Start();
				minimizeArrow.Animate().Rotation(0f).SetDuration(500L)
					.Start();
			}
			else
			{
				Animate().TranslationX(-container.Width).SetDuration(500L).Start();
				minimizeArrow.Animate().Rotation(180f).SetDuration(500L)
					.Start();
			}
			isMinimized = !isMinimized;
		}

		public override void OnHidden()
		{
			base.OnHidden();
			if (minimizeButton != null)
			{
				minimizeButton.Click -= OnMinimizeButtonClicked;
			}
			controls?.OnHidden();
		}

		public override void OnShown()
		{
			base.OnShown();
			if (minimizeButton != null)
			{
				minimizeButton.Click -= OnMinimizeButtonClicked;
				minimizeButton.Click += OnMinimizeButtonClicked;
			}
			controls?.OnShown();
		}
	}
