			Setup(view, bindingSet, map);
		}

		protected override void SetupViews()
		{
			TypedArray typedArray = base.Context.ObtainStyledAttributes(Resource.Styleable.DrawMapSearchBar);
			if (typedArray != null)
			{
				searchBackground = typedArray.GetDrawable(0) as LayerDrawable;
				typedArray.Recycle();
			}
			InputEditText = FindViewById<DrawMapAutoComplete>(2131429163);
			InputEditText.Hint = Wolf.Core.Resources.AppStrings.search_locations;
			clearSearchButton = FindViewById<ImageButton>(2131427664);
			mapTools = FindViewById<ImageButton>(2131428604);
			Adapter = new LocationResultsAdapter(base.Context, 2131624054, new List<LocationResultsJavaObj>());
			InputEditText.Adapter = Adapter;
			Resources resources = base.Context.Resources;
			InputEditText.DropDownHorizontalOffset = -resources.GetDimensionPixelSize(2131165833);
			itemHeight = resources.GetDimensionPixelSize(2131165838);
			shadowHeight = resources.GetDimensionPixelSize(2131165775);
			bottomGradientLeftRight = resources.GetDimensionPixelSize(2131165776);
		}

		protected override void AddBindings(DrawMapBindingSetWrapper bindingSet)
		{
			bindingSet.Bind(mapTools).For(mapTools.ClickEvent()).To((DrawMapViewModel vm) => vm.MapBuilderToolsButtonTapped);
			bindingSet.Bind(this).For((DrawMapSearchBar x) => x.UpdateMapToolsTintColor).To((DrawMapViewModel vm) => vm.UpdateMapToolsTintColor)
				.OneWay();
			bindingSet.Bind(InputEditText).For((DrawMapAutoComplete x) => x.TextWithCursorHack).To((DrawMapViewModel x) => x.SearchText)
				.TwoWay();
			bindingSet.Bind(this).For("OnBoolChanged").To((DrawMapViewModel x) => x.SearchInputFieldFocused);
			bindingSet.Bind(this).For("UpdateSearchResults").To((DrawMapViewModel x) => x.SearchResults);
			bindingSet.Bind(searchProgress).For((ProgressBar v) => v.Alpha).To((DrawMapViewModel vm) => vm.CurrentTextSearching)
				.WithConversion(new BoolToFloatValueConverter());
			bindingSet.Bind(InputEditText).For("OnEnterClickedEvent").To((DrawMapViewModel vm) => vm.SearchCurrentText);
			bindingSet.Bind(InputEditText).For((DrawMapAutoComplete x) => x.ItemClick).To((DrawMapViewModel vm) => vm.CenterMapAtSearchResult);
			bindingSet.Bind(InputEditText).For("SearchComplete").To((DrawMapViewModel vm) => vm.SearchCurrentText);
			bindingSet.Bind(clearSearchButton).For(clearSearchButton.ClickEvent()).To((DrawMapViewModel vm) => vm.ClearSearchText);
			bindingSet.Bind(clearSearchButton).For((ImageButton x) => x.Visibility).To((DrawMapViewModel vm) => vm.HasSearchValue)
				.WithConversion(visibilityConverter);
		}

		public void UpdateSearchResults(List<PlaceAutoComplete.Prediction> results)
		{
			Adapter.SetList(results.Select((PlaceAutoComplete.Prediction x) => new LocationResultsJavaObj(x)).ToList());
			LayerDrawable layerDrawable = searchBackground ?? ((LayerDrawable)ContextCompat.GetDrawable(base.Context, 2131231060));
			Drawable drawable = layerDrawable.FindDrawableByLayerId(2131427909);
			int index = 0;
			for (int num = 0; num < layerDrawable.NumberOfLayers; num++)
			{
				Drawable drawable2 = layerDrawable.GetDrawable(num);
				if (drawable2 == drawable)
				{
					index = num;
					break;
				}
			}
			layerDrawable.SetLayerInset(index, bottomGradientLeftRight, itemHeight * results.Count, bottomGradientLeftRight, 0);
			InputEditText.SetDropDownBackgroundDrawable(layerDrawable);
			InputEditText.DropDownHeight = itemHeight * results.Count + shadowHeight;
		}

		private void OnUpdateMapToolsTintColor(object sender, MvxValueEventArgs<object> e)
		{
			if (viewModel == null || !Mvx.TryResolve<IAndroidThemeService>(out var service))
			{
				return;
			}
			if (viewModel.IsMapToolsHidden.Value)
			{
				mapTools.SetImageResource(2131231627);
				if (!service.IsCurrentThemeDarkVariant())
				{
					mapTools.SetColorFilter(base.Context.GetColorCompat(2131100184));
				}
			}
			else
			{
				mapTools.SetImageResource(2131231625);
				if (!service.IsCurrentThemeDarkVariant())
				{
					mapTools.SetColorFilter(base.Context.GetColorCompat(2131100164));
				}
				else
				{
					mapTools.SetColorFilter(base.Context.GetColorCompat(2131100285));
				}
			}
		}

		public void OnBoolChanged(bool isFocused)
		{
			if (!isFocused)
			{
				InputEditText.ClearFocus();
				((InputMethodManager)base.Context.GetSystemService("input_method")).HideSoftInputFromWindow(InputEditText.WindowToken, HideSoftInputFlags.None);
			}
			else
			{
				InputEditText.RequestFocus();
			}
		}

		public override void OnShown()
		{
			base.OnShown();
			InputEditText.OnShown();
		}

		public override void OnHidden()
		{
			base.OnHidden();
			InputEditText.OnHidden();
		}

		protected override void Dispose(bool disposing)
		{
			if (!disposed && disposing)
			{
				InputEditText?.Dispose();
				InputEditText = null;
			}
			disposed = true;
			base.Dispose(disposing);
		}
	}
