		public void AddBindings(DrawMapBindingSetWrapper bindingSet)
		{
			VisibilityGoneValueConverter converter = new VisibilityGoneValueConverter();
			bindingSet.Bind(outAndBackBtn).For((ClickableIconAndLabel x) => x.Enabled).To((DrawMapViewModel vm) => vm.OutAndBackEnabled);
			bindingSet.Bind(outAndBackBtn).For((ClickableIconAndLabel x) => x.Alpha).To((DrawMapViewModel vm) => vm.OutAndBackEnabled)
				.WithConversion(new BoolToFloatValueConverter(1f, 0.4f));
			bindingSet.Bind(closeLoopBtn).For((ClickableIconAndLabel x) => x.Enabled).To((DrawMapViewModel vm) => vm.CloseLoopEnabled);
			bindingSet.Bind(closeLoopBtn).For((ClickableIconAndLabel x) => x.Alpha).To((DrawMapViewModel vm) => vm.CloseLoopEnabled)
				.WithConversion(new BoolToFloatValueConverter(1f, 0.4f));
			bindingSet.Bind(undoBtn).For((ClickableIconAndLabel x) => x.Enabled).To((DrawMapViewModel vm) => vm.UndoEnabled);
			bindingSet.Bind(undoBtn).For((ClickableIconAndLabel x) => x.Alpha).To((DrawMapViewModel vm) => vm.UndoEnabled)
				.WithConversion(new BoolToFloatValueConverter(1f, 0.4f));
			bindingSet.Bind(searchBtn).For(searchBtn.ClickEvent()).To((DrawMapViewModel vm) => vm.SearchButtonTapped);
			bindingSet.Bind(searchBtn).For((ImageView x) => x.Visibility).To((DrawMapViewModel vm) => vm.SearchEnabled)
				.WithConversion(converter);
