			snapToRoadSwitch.OnHidden();
		}

		public void OnShown()
		{
			outAndBackBtn.Click -= OutAndBackClicked;
			outAndBackBtn.Click += OutAndBackClicked;
			closeLoopBtn.Click -= CloseLoopClicked;
			closeLoopBtn.Click += CloseLoopClicked;
			undoBtn.Click -= UndoClicked;
			undoBtn.Click += UndoClicked;
			snapToRoadSwitch.IsChecked = map.RoadSnapOn;
			snapSeparator.Visibility = (HideSeparator ? ViewStates.Gone : ViewStates.Visible);
			map.OnMapClicked -= MapClickedListener;
			map.OnMapClicked += MapClickedListener;
			snapToRoadSwitch.OnShown();
		}

