		}

		private void OutAndBackClicked(object sender, EventArgs e)
		{
			System.Threading.Tasks.Task.Run(async delegate
			{
				try
				{
					await map.OutAndBack();
				}
				catch (MaxWorkoutDistanceExceededException)
				{
					Activity activity = base.Context as Activity;
					activity.RunOnUiThread(delegate
					{
						Toast.MakeText(activity, Wolf.Core.Resources.AppStrings.draw_map_max_workout_length_error, ToastLength.Long).Show();
					});
				}
			});
		}

		private void CloseLoopClicked(object sender, EventArgs e)
		{
			System.Threading.Tasks.Task.Run(async delegate
			{
				try
				{
					await map.CloseRouteLoop();
				}
				catch (MaxWorkoutDistanceExceededException)
				{
					Activity activity = base.Context as Activity;
					activity.RunOnUiThread(delegate
					{
						Toast.MakeText(activity, Wolf.Core.Resources.AppStrings.draw_map_max_workout_length_error, ToastLength.Long).Show();
					});
				}
			});
		}

		private void UndoClicked(object sender, EventArgs e)
		{
			map.RemoveLastRoutePoint();
		}
	}
