	public class HudStatInfoBox : RelativeLayout, IMvxBindingContextOwner, IDisposable
	{
		private bool isBinding;

		private IfitTextView statValue;

		private IfitTextView statUnit;

		private IfitTextView targetUnit;

		private IfitTextView avgStatValue;

		private IfitTextView avgStatUnit;

		private IfitTextView avgStatLabel;

		private IfitTextView maxStatValue;

		private IfitTextView maxStatUnit;

		private IfitTextView maxStatLabel;

		private IfitTextView metricLabel;

		private const float PixelsPerSecond = 50f;

		private const int DelayBeforeScrollBack = 3000;

		private const int SecondsBetweenAutoScroll = 2;

		private bool isDisposed;

		private HorizontalScrollView _metricLabelScrollView;

		private CancellationTokenSource _animationCts;

		private BasicImageView iconImageView;

		private readonly SemaphoreSlim bindUnbindSlim = new SemaphoreSlim(1, 1);

		private bool IsMarqueeAnimating { get; set; }

		public IMetricGroup MetricGroup
		{
			get
			{
				return BindingContext.DataContext as IMetricGroup;
			}
			set
			{
				if (BindingContext.DataContext != value)
				{
					BindingContext.DataContext = value;
				}
			}
		}

		public IMvxBindingContext BindingContext { get; set; }

		public HudStatInfoBox(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public HudStatInfoBox(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public HudStatInfoBox(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			LayoutInflater.From(context).Inflate(2131624118, this, attachToRoot: true);
			statValue = FindViewById<IfitTextView>(2131428269);
			statUnit = FindViewById<IfitTextView>(2131428268);
			targetUnit = FindViewById<IfitTextView>(2131428267);
			avgStatValue = FindViewById<IfitTextView>(2131428259);
			avgStatUnit = FindViewById<IfitTextView>(2131428258);
			avgStatLabel = FindViewById<IfitTextView>(2131428257);
			maxStatValue = FindViewById<IfitTextView>(2131428265);
			maxStatUnit = FindViewById<IfitTextView>(2131428264);
			maxStatLabel = FindViewById<IfitTextView>(2131428263);
			metricLabel = FindViewById<IfitTextView>(2131428261);
			_metricLabelScrollView = FindViewById<HorizontalScrollView>(2131428262);
			iconImageView = FindViewById<BasicImageView>(2131428260);
			BindingContext = new MvxTaskBasedBindingContext();
		}

		private void ResetAnimation()
		{
			CancelAnimation();
			_animationCts = new CancellationTokenSource();
			ForceUpdateViews();
			AnimateMarqueeAfterTime(_animationCts.Token);
		}

		private async System.Threading.Tasks.Task AnimateMarqueeAfterTime(System.Threading.CancellationToken ctx, int timeDelay = 2)
		{
			_ = 2;
			try
			{
				await System.Threading.Tasks.Task.Delay(TimeSpan.FromSeconds(timeDelay), ctx);
				if (_animationCts != null)
				{
					bool flag = await AnimateMarquees(ctx);
					IsMarqueeAnimating = false;
					if (flag && !ctx.IsCancellationRequested)
					{
						await AnimateMarqueeAfterTime(ctx);
					}
				}
			}
			catch (System.OperationCanceledException)
			{
				IsMarqueeAnimating = false;
			}
		}

		protected virtual async Task<bool> AnimateMarquees(System.Threading.CancellationToken ctx)
		{
			if (isDisposed)
			{
				return false;
			}
			Task<bool> metric = AnimateMarquee(_metricLabelScrollView, metricLabel, ctx);
			try
			{
				await System.Threading.Tasks.Task.WhenAll<bool>(metric);
			}
			catch (System.OperationCanceledException)
			{
				if (isDisposed)
				{
					return false;
				}
				ForceUpdateViews();
				return false;
			}
			return metric.Result;
		}

		protected virtual void ForceUpdateViews()
		{
			if (!isDisposed)
			{
				metricLabel.ForceLayout();
				_metricLabelScrollView.ScrollX = 0;
				_metricLabelScrollView.Invalidate();
				_metricLabelScrollView.RequestLayout();
			}
		}

		private void TextLoaded(object sender, EventArgs e)
		{
			if (!string.IsNullOrEmpty(metricLabel.Text))
			{
				ResetAnimation();
			}
		}

		private async Task<bool> AnimateMarquee(HorizontalScrollView scrollView, TextView textView, System.Threading.CancellationToken ctx)
		{
			scrollView.ScrollTo(0, 0);
			TextPaint paint = textView.Paint;
			Rect rect = new Rect();
			string text = textView.Text;
			paint.GetTextBounds(text, 0, text.Length, rect);
			int scrollingLen = rect.Width() - scrollView.Width;
			return await AnimateWithScrollingLength(scrollingLen, scrollView, ctx);
		}

		private async Task<bool> AnimateWithScrollingLength(int scrollingLen, HorizontalScrollView scrollView, System.Threading.CancellationToken ctx)
		{
			if (scrollingLen <= 0)
			{
				return false;
			}
			IsMarqueeAnimating = true;
			long duration = (long)System.Math.Round((float)scrollingLen / 50f * 1000f);
			Animator animator = ObjectAnimator.OfInt(scrollView, "scrollX", scrollingLen).SetDuration(duration);
			animator.SetInterpolator(new LinearInterpolator());
			Animator animator2 = ObjectAnimator.OfInt(scrollView, "scrollX", default(int)).SetDuration(duration);
			animator2.SetInterpolator(new LinearInterpolator());
			animator2.StartDelay = 3000L;
			AnimatorSet animatorSet = new AnimatorSet();
			animatorSet.PlaySequentially(animator, animator2);
			await animatorSet.StartWithDisposal(ctx);
			return true;
		}

		public void BindProperties()
		{
			if (!isBinding)
			{
				isBinding = true;
				System.Threading.Tasks.Task.Run((Func<System.Threading.Tasks.Task>)BindPropertiesAsync);
			}
		}

		private async System.Threading.Tasks.Task BindPropertiesAsync()
		{
			await UnbindPropertiesAsync().ConfigureAwait(continueOnCapturedContext: false);
			await bindUnbindSlim.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			isBinding = true;
			MvxFluentBindingDescriptionSet<HudStatInfoBox, IMetricGroup> mvxFluentBindingDescriptionSet = this.CreateBindingSet<HudStatInfoBox, IMetricGroup>();
			if (_metricLabelScrollView != null)
			{
				metricLabel.TextChanged -= TextLoaded;
				metricLabel.TextChanged += TextLoaded;
			}
			mvxFluentBindingDescriptionSet.Bind(metricLabel).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Label.Value);
			mvxFluentBindingDescriptionSet.Bind(statValue).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric1.Metric);
			mvxFluentBindingDescriptionSet.Bind(statUnit).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric1.UnitLabel);
			mvxFluentBindingDescriptionSet.Bind(targetUnit).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric1.Target);
			mvxFluentBindingDescriptionSet.Bind(iconImageView).For((BasicImageView x) => x.ResourceId).To((IMetricGroup x) => x.Metric1.HudIcon)
				.WithConversion(new MetricIconValueConverter());
			mvxFluentBindingDescriptionSet.Bind(avgStatValue).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric2.Metric);
			mvxFluentBindingDescriptionSet.Bind(avgStatUnit).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric2.UnitLabel);
			mvxFluentBindingDescriptionSet.Bind(avgStatLabel).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric2.SubtitleLabel);
			mvxFluentBindingDescriptionSet.Bind(maxStatValue).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric3.Metric);
			mvxFluentBindingDescriptionSet.Bind(maxStatUnit).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric3.UnitLabel);
			mvxFluentBindingDescriptionSet.Bind(maxStatLabel).For((IfitTextView x) => x.Text).To((IMetricGroup group) => group.Metric3.SubtitleLabel);
			mvxFluentBindingDescriptionSet.Apply();
			isBinding = false;
			bindUnbindSlim.Release();
		}

		public void UnbindProperties()
		{
			System.Threading.Tasks.Task.Run((Func<System.Threading.Tasks.Task>)UnbindPropertiesAsync);
		}

		private async System.Threading.Tasks.Task UnbindPropertiesAsync()
		{
			await bindUnbindSlim.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			BindingContext?.ClearAllBindings();
			bindUnbindSlim.Release();
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !isDisposed)
			{
				isDisposed = true;
				CancelAnimation();
				BindingContext?.ClearAllBindings();
				BindingContext?.DisposeIfDisposable();
				BindingContext = null;
				statValue?.DisposeIfDisposable();
				statValue = null;
				statUnit?.DisposeIfDisposable();
				statUnit = null;
				targetUnit?.DisposeIfDisposable();
				targetUnit = null;
				iconImageView?.DisposeIfDisposable();
				iconImageView = null;
				avgStatValue?.DisposeIfDisposable();
				avgStatValue = null;
				avgStatUnit?.DisposeIfDisposable();
				avgStatUnit = null;
				avgStatLabel?.DisposeIfDisposable();
				avgStatLabel = null;
				maxStatValue?.DisposeIfDisposable();
				maxStatValue = null;
				maxStatUnit?.DisposeIfDisposable();
				maxStatUnit = null;
				maxStatLabel?.DisposeIfDisposable();
				maxStatLabel = null;
				metricLabel?.DisposeIfDisposable();
				metricLabel = null;
			}
			base.Dispose(disposing);
		}

		private void CancelAnimation()
		{
			_animationCts?.Cancel();
			_animationCts?.Dispose();
			_animationCts = null;
			IsMarqueeAnimating = false;
		}
	}
