	public class IfitMediaPlayer : MediaPlayer, MediaPlayer.IOnPreparedListener, IJavaObject, IDisposable, IJavaPeerable
	{
		public bool IsPrepared;

		public bool IsPreparing;

		public bool shouldStartOnPrepared;

		private IOnPreparedListener OnPreparedListener;

		public IfitMediaPlayer()
		{
			base.SetOnPreparedListener(this);
		}

		public override void SetOnPreparedListener(IOnPreparedListener listener)
		{
			OnPreparedListener = listener;
		}

		public override void Prepare()
		{
			IsPreparing = true;
			base.Prepare();
		}

		public override void PrepareAsync()
		{
			IsPreparing = true;
			base.PrepareAsync();
		}

		public IfitMediaPlayer SafeStart()
		{
			if (IsPlaying)
			{
				return this;
			}
			if (IsPrepared)
			{
				Start();
			}
			else if (IsPreparing)
			{
				shouldStartOnPrepared = true;
			}
			else
			{
				shouldStartOnPrepared = true;
				PrepareAsync();
			}
			return this;
		}

		public IfitMediaPlayer CleanAndReset()
		{
			try
			{
				Stop();
				SetOnPreparedListener(null);
				SetOnInfoListener(null);
				SetOnErrorListener(null);
				Reset();
				Release();
				Dispose();
			}
			catch (ObjectDisposedException)
			{
			}
			return this;
		}

		public void OnPrepared(MediaPlayer mp)
		{
			IsPrepared = true;
			IsPreparing = false;
			if (shouldStartOnPrepared)
			{
				Start();
				shouldStartOnPrepared = false;
