				return _index;
			}
			set
			{
				if (value != _index)
				{
					int index = _index;
					_index = value;
					TransitionToIndex();
					(IMetric, IMetric) tuple = (flipperMetrics[index], flipperMetrics[value]);
					UpdateVisibleFlipperCommand?.Execute(tuple);
				}
			}
		}

		public bool ConnectedToHeartRate
		{
			get
			{
				return _connectedToHeartRate;
			}
			set
			{
				if (_connectedToHeartRate != value && _metrics != null && _metrics.Any((IMetric m) => m.RequiresHeartMonitor))
				{
					_connectedToHeartRate = value;
					RebuildFlippers(_connectedToHeartRate, !_connectedToHeartRate);
				}
			}
		}

		public bool IsInCoolDown
		{
			get
			{
				return _isInCoolDown;
			}
			set
			{
				if (_isInCoolDown != value)
				{
					_isInCoolDown = value;
					RebuildFlippers(_connectedToHeartRate, _isInCoolDown);
				}
			}
		}

		protected abstract int LayoutResId { get; }

		public ICommand UpdateVisibleFlipperCommand { get; set; }

		public BaseFlipperContainer(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		protected BaseFlipperContainer(Context context)
			: this(context, null)
		{
		}

		protected BaseFlipperContainer(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			LayoutInflater.From(context).Inflate(LayoutResId, this, attachToRoot: true);
			firstFlipper = FindViewById<BaseFlipperItem>(2131428078);
			secondFlipper = FindViewById<BaseFlipperItem>(2131429174);
			indicator = FindViewById<FlipperIndicator>(2131428099);
			Mvx.TryResolve<ILocalSettings>(out localSettings);
			Mvx.TryResolve<ICurrentConsoleService>(out currentConsoleService);
			Mvx.TryResolve<IWorkoutSettings>(out workoutSettings);
			AdditionalInit(context, attrs);
		}

		protected abstract void AdditionalInit(Context context, IAttributeSet attrs);

		public override bool OnTouchEvent(MotionEvent e)
		{
			return false;
		}

		public void ClearFlippers()
		{
			flipperMetrics.Clear();
		}

		public void AddFlipper(MetricBase metric, bool heartRateConnected)
		{
			if (heartRateConnected || ForceShowHeartRate || !metric.RequiresHeartMonitor)
			{
				flipperMetrics.Add(metric);
				if (flipperMetrics.Count == 1)
				{
					onSecondFlipper = true;
					secondFlipper.Metric = metric;
				}
				indicator.ItemCount = flipperMetrics.Count;
			}
		}

		public void MoveToNextIndex()
		{
			if (flipperMetrics.Count >= 2 && !isAnimating)
			{
				Index = nextIndex;
			}
		}

		private void RebuildFlippers(bool heartRateConnected = false, bool setIndexToZeroBeforeRebuilding = false)
		{
			Post(delegate
			{
				if (!isDisposed)
				{
					if (setIndexToZeroBeforeRebuilding)
					{
						Index = 0;
					}
					ClearFlippers();
					if ((_metrics?.Count ?? 0) > 0)
					{
						bool flag = _isInCoolDown || workoutSettings?.WorkoutContainer?.WorkoutRunner?.HasStartedCoolDown == true || currentConsoleService?.ActiveConsole?.LatestBasicInfo?.CurrentState == ConsoleState.CoolDown;
						foreach (MetricBase item in _metrics.Select((IMetric m) => m as MetricBase))
						{
							if (!flag || !item.HideInCoolDown)
							{
								AddFlipper(item, heartRateConnected);
							}
						}
						if (flipperMetrics.Count == 1)
						{
							Index = 0;
						}
						indicator.ForceLayout();
					}
					else
					{
						Visibility = ViewStates.Gone;
					}
					if (heartRateConnected)
					{
						SelectHeartRateMetric();
					}
				}
			});
		}

		private void TransitionToIndex()
		{
			indicator.SelectedItem = Index;
			if (flipperMetrics != null && flipperMetrics.Count >= 2)
			{
				if (onSecondFlipper)
				{
					FlipIt(secondFlipper, firstFlipper);
					onSecondFlipper = false;
				}
				else
				{
					FlipIt(firstFlipper, secondFlipper);
					onSecondFlipper = true;
				}
			}
		}

		private bool TryGetMetric(out MetricBase metric)
		{
			metric = flipperMetrics?.ElementAtOrDefault(Index);
			return metric != null;
		}

		private void FlipIt(BaseFlipperItem flipperFrom, BaseFlipperItem flipperTo)
		{
			if (TryGetMetric(out var metric))
			{
				isAnimating = true;
				flipperTo.Metric = metric;
				flipperTo.Animate().SetDuration(0L).TranslationY(flipperTo.Height)
					.Start();
				flipperTo.Animate().SetDuration(300L).TranslationY(0f)
					.Start();
				flipperFrom.Animate().SetDuration(300L).TranslationY(-flipperFrom.Height)
					.WithEndAction(this)
					.Start();
				if (flipperTo is TabletStatsFlipperItem)
				{
					flipperTo.StartMarquee();
				}
			}
		}

		private void SelectHeartRateMetric()
		{
			if (ContainsHeartRateMetric)
			{
				IMetric metric = Metrics?.FirstOrDefault((IMetric x) => x is HeartRateMetric);
				if (metric != null)
				{
					int index = Metrics.IndexOf(metric);
					Index = index;
				}
			}
		}

		public void Run()
		{
			isAnimating = false;
		}

		protected override void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				base.Dispose(disposing);
				if (disposing)
				{
					isDisposed = true;
					ClearFlippers();
					firstFlipper?.Dispose();
					firstFlipper = null;
					secondFlipper?.Dispose();
					secondFlipper = null;
					indicator?.Dispose();
					indicator = null;
					Metrics?.Clear();
					Metrics = null;
					Dispose();
				}
			}
		}
	}
