		private bool _isTrapezoid;

		private bool _scaleSelected;

		private global::Android.Graphics.Color defaultActiveColor => base.Context.GetColorCompat(2131099964);

		private global::Android.Graphics.Color defaultInactiveColor => base.Context.GetColorCompat(2131099965);

		private int defaultSingleWidth => Resources.GetDimensionPixelSize(2131166102);

		private int defaultSpaceWidth => Resources.GetDimensionPixelSize(2131166103);

		public global::Android.Graphics.Color ActiveColor
		{
			private get
			{
				return _activeColor;
			}
			set
			{
				_activeColor = value;
				Invalidate();
			}
