				return _selectedItem;
			}
			set
			{
				_selectedItem = value;
				Invalidate();
			}
		}

		private int SingleWidth
		{
			get
			{
				return _singleWidth;
			}
			set
			{
				_singleWidth = value;
				Invalidate();
			}
		}

		private int SpaceWidth
		{
			get
			{
				return _spaceWidth;
			}
			set
			{
				_spaceWidth = value;
				Invalidate();
			}
		}

		public int MinWidth
		{
			get
			{
				return _minWidth;
			}
			set
			{
				_minWidth = value;
				Invalidate();
			}
		}

		private bool IsTrapezoid
		{
			get
			{
				return _isTrapezoid;
			}
			set
			{
				_isTrapezoid = value;
				Invalidate();
			}
		}

		private bool ScaleSelected
		{
			get
			{
				return _scaleSelected;
			}
			set
			{
				_scaleSelected = value;
				Invalidate();
			}
		}

		public FlipperIndicator(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public FlipperIndicator(Context context)
			: base(context)
		{
			Init(context, null);
		}

		public FlipperIndicator(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public FlipperIndicator(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context, attrs);
		}

		public FlipperIndicator(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			if (attrs == null)
			{
				ConfigureDefaultValues();
				return;
			}
			TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.FlipperIndicator);
			_activeColor = typedArray.GetColor(0, defaultActiveColor);
			_inactiveColor = typedArray.GetColor(1, defaultInactiveColor);
			_singleWidth = typedArray.GetDimensionPixelSize(5, defaultSingleWidth);
			_spaceWidth = typedArray.GetDimensionPixelSize(6, defaultSpaceWidth);
			_isTrapezoid = typedArray.GetBoolean(2, defaultIsTrapezoid);
			_scaleSelected = typedArray.GetBoolean(3, defaultScaleSelected);
			_showSingleItem = typedArray.GetBoolean(4, defaultShowSingleItem);
			typedArray?.Recycle();
			Invalidate();
		}

		protected override void OnMeasure(int widthMeasureSpec, int heightMeasureSpec)
		{
			if (_itemCount != 0)
			{
				SetMeasuredDimension(_itemCount * SingleWidth + (_itemCount - 1) * SpaceWidth, heightMeasureSpec);
			}
			else
			{
				base.OnMeasure(widthMeasureSpec, heightMeasureSpec);
			}
		}

		protected override void OnDraw(Canvas canvas)
		{
			if (IsInEditMode || ItemCount <= 0 || (ItemCount == 1 && !ShowSingleItem))
			{
				return;
			}
			for (int i = 0; i < ItemCount; i++)
			{
				fillPaint.Color = ((i == SelectedItem) ? ActiveColor : InactiveColor);
				fillPaint.AntiAlias = true;
				fillPaint.SetStyle(Paint.Style.Fill);
				if (IsTrapezoid)
				{
					int xPos = CalculateTrapezoidXPos(i);
					DrawTrapezoid(canvas, xPos, fillPaint);
				}
				else
				{
					int xPos2 = CalculateCircleXPos(i);
					DrawCircle(canvas, xPos2, fillPaint, CalculateScaleFactor(ScaleSelected, i == SelectedItem));
				}
			}
		}

		private void DrawTrapezoid(Canvas canvas, int xPos, Paint paint)
		{
			global::Android.Graphics.Path path = new global::Android.Graphics.Path();
			path.Reset();
			path.MoveTo(xPos, base.Height);
			path.LineTo(xPos + SingleWidth - 2, base.Height);
			path.LineTo(xPos + SingleWidth, 0f);
			path.LineTo(xPos + 2, 0f);
			path.Close();
			canvas.DrawPath(path, paint);
		}

		private void DrawCircle(Canvas canvas, int xPos, Paint paint, float scaleFactor)
		{
			float num = (float)SingleWidth / 2f;
			canvas.DrawCircle(xPos, num, scaleFactor * num, paint);
		}

		private int CalculateTrapezoidXPos(int index)
		{
			return index * (SingleWidth + SpaceWidth);
		}

		private int CalculateCircleXPos(int index)
		{
			int num = index * SpaceWidth;
			return num + index * SingleWidth + SingleWidth / 2;
		}

		private float CalculateScaleFactor(bool shouldScale, bool isSelected)
		{
			if (!shouldScale)
			{
				return 1f;
			}
			if (!isSelected)
			{
				return 0.8f;
			}
			return 1f;
		}

		private void ConfigureDefaultValues()
		{
			ActiveColor = defaultActiveColor;
			InactiveColor = defaultInactiveColor;
			SingleWidth = defaultSingleWidth;
			SpaceWidth = defaultSpaceWidth;
			IsTrapezoid = defaultIsTrapezoid;
			ScaleSelected = defaultScaleSelected;
		}
	}
