	public class TabletStatsFlipperItem : BaseFlipperItem
	{
		public HorizontalScrollView FlipperLabelScrollView;

		private bool hasInitialized;

		private bool scrollViewAnimating;

		private const float PixelsPerSecond = 50f;

		private const int DelayBeforeScrollBack = 1250;

		private const int SecondsBetweenAutoScroll = 1;

		private CancellationTokenSource animationCts;

