		public override void StartMarquee()
		{
			if (hasInitialized)
			{
				animationCts?.Cancel();
				animationCts = new CancellationTokenSource();
				AnimateMarqueeAfterTime(animationCts.Token);
			}
		}

		private void TextLoaded(object sender, EventArgs e)
		{
			if (!string.IsNullOrEmpty(base.Label.Text))
			{
				hasInitialized = true;
				StartMarquee();
			}
		}

		private async System.Threading.Tasks.Task AnimateMarqueeAfterTime(System.Threading.CancellationToken ctx)
		{
			_ = 1;
			try
			{
				await System.Threading.Tasks.Task.Delay(TimeSpan.FromSeconds(1.0), ctx);
				if (animationCts != null)
				{
					await MarqueeText(FlipperLabelScrollView, base.Label, animationCts.Token);
				}
			}
			catch (System.OperationCanceledException)
			{
			}
		}

		private async Task<bool> MarqueeText(HorizontalScrollView scrollView, TextView textView, System.Threading.CancellationToken ctx)
		{
			RegisterAnimationStart();
			scrollView.ScrollTo(0, 0);
			TextPaint paint = textView.Paint;
			Rect rect = new Rect();
			string text = textView.Text;
			paint.GetTextBounds(text, 0, text.Length, rect);
			int num = rect.Width() - (scrollView.Width - scrollView.HorizontalFadingEdgeLength);
			if (num <= 0)
			{
				RegisterAnimationStop();
				return false;
			}
			long duration = (long)System.Math.Round((float)num / 50f * 1000f);
			Animator animator = ObjectAnimator.OfInt(scrollView, "scrollX", num).SetDuration(duration);
			animator.SetInterpolator(new LinearInterpolator());
			Animator animator2 = ObjectAnimator.OfInt(scrollView, "scrollX", default(int)).SetDuration(duration);
			animator2.SetInterpolator(new LinearInterpolator());
			animator2.StartDelay = 1250L;
			AnimatorSet animatorSet = new AnimatorSet();
			animatorSet.PlaySequentially(animator, animator2);
			await animatorSet.StartWithDisposal(ctx);
			RegisterAnimationStop();
			return true;
		}

		private void RegisterAnimationStart()
		{
			scrollViewAnimating = true;
		}

		private void RegisterAnimationStop()
		{
			scrollViewAnimating = false;
		}

		private void CancelAnimation()
		{
			RegisterAnimationStop();
			animationCts?.Cancel();
			animationCts?.Dispose();
			animationCts = null;
		}
	}
