	public class InWorkoutProgressAnimation : Animation
	{
		private InWorkoutProgressCircleView progressCircle;

		private float oldTotalProgress;

		private float newTotalProgress;

		private float oldStepProgress;

		private float newStepProgress;

		public InWorkoutProgressAnimation(InWorkoutProgressCircleView progressView, float totalProgress, float stepProgress)
		{
			progressCircle = progressView;
			oldTotalProgress = progressView.TotalProgress;
			newTotalProgress = totalProgress;
			oldStepProgress = progressView.StepProgress;
			newStepProgress = stepProgress;
		}

		protected override void ApplyTransformation(float interpolatedTime, Transformation t)
		{
			base.ApplyTransformation(interpolatedTime, t);
			if (newTotalProgress > 0f)
			{
				float totalProgress = CalculateInterpolatedProgress(oldTotalProgress, newTotalProgress, interpolatedTime);
				progressCircle.TotalProgress = totalProgress;
			}
			if (newStepProgress > 0f)
			{
				float stepProgress = CalculateInterpolatedProgress(oldStepProgress, newStepProgress, interpolatedTime);
				progressCircle.StepProgress = stepProgress;
			}
			progressCircle.RequestLayout();
		}

		private static float CalculateInterpolatedProgress(float oldProgress, float newProgress, float interpolatedTime)
		{
			float num = newProgress - oldProgress;
			return oldProgress + num * interpolatedTime;
		}
	}
	public class InWorkoutProgressCircleView : View
	{
		private const float StartingAngle = 90f;

		private const float FullCircle = 360f;

		private global::Android.Graphics.Color outerEmptyColor;

		private global::Android.Graphics.Color outerFilledColor;

		private global::Android.Graphics.Color innerEmptyColor;

		private global::Android.Graphics.Color innerFilledColor;

		private Paint outerEmptyPaint;

		private Paint outerFilledPaint;

		private Paint innerEmptyPaint;

		private Paint innerFilledPaint;

		private RectF outerRect;

		private RectF innerRect;

		private float _totalProgress;

		private float _stepProgress;

		public float TotalProgress
		{
			get
			{
				return _totalProgress;
			}
			set
			{
				_totalProgress = value;
				Invalidate();
			}
		}

		public float StepProgress
		{
			get
			{
				return _stepProgress;
			}
			set
			{
				_stepProgress = value;
				Invalidate();
			}
		}

		public InWorkoutProgressCircleView(IntPtr ptr, JniHandleOwnership transfer)
			: base(ptr, transfer)
		{
		}

		public InWorkoutProgressCircleView(Context context)
			: base(context)
		{
			Initialize(context, null);
		}

		public InWorkoutProgressCircleView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize(context, attrs);
		}

		public InWorkoutProgressCircleView(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize(context, attrs);
		}

		private void Initialize(Context context, IAttributeSet attrs)
		{
			float strokeWidth = 24f;
			float num = 4f;
			if (context != null && attrs != null)
			{
				TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.InWorkoutProgressCircle);
				strokeWidth = typedArray.GetInt(5, 24);
				num = typedArray.GetInt(4, 4);
				outerEmptyColor = typedArray.GetColor(2, base.Context.GetColorCompat(2131100011));
				outerFilledColor = typedArray.GetColor(3, base.Context.GetColorCompat(2131100013));
				innerEmptyColor = typedArray.GetColor(0, base.Context.GetColorCompat(2131100007));
				innerFilledColor = typedArray.GetColor(1, base.Context.GetColorCompat(2131100009));
			}
			float strokeWidth2 = num / 2f;
			outerEmptyPaint = new Paint
			{
				Color = outerEmptyColor,
				StrokeWidth = strokeWidth,
				AntiAlias = true,
				StrokeCap = Paint.Cap.Square
			};
			outerEmptyPaint.SetStyle(Paint.Style.Stroke);
			outerFilledPaint = new Paint
			{
				Color = outerFilledColor,
				StrokeWidth = strokeWidth,
				AntiAlias = true,
				StrokeCap = Paint.Cap.Square
			};
			outerFilledPaint.SetStyle(Paint.Style.Stroke);
			innerEmptyPaint = new Paint
			{
				Color = innerEmptyColor,
				StrokeWidth = strokeWidth2,
				AntiAlias = true,
				StrokeCap = Paint.Cap.Square
			};
			innerEmptyPaint.SetStyle(Paint.Style.Stroke);
			innerFilledPaint = new Paint
			{
				Color = innerFilledColor,
				StrokeWidth = num,
				AntiAlias = true,
				StrokeCap = Paint.Cap.Square
			};
			innerFilledPaint.SetStyle(Paint.Style.Stroke);
			innerRect = new RectF();
			outerRect = new RectF();
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				outerEmptyPaint?.Dispose();
				outerEmptyPaint = null;
				outerFilledPaint?.Dispose();
				outerFilledPaint = null;
				innerEmptyPaint?.Dispose();
				innerEmptyPaint = null;
				innerFilledPaint?.Dispose();
				innerFilledPaint = null;
				outerRect?.Dispose();
				outerRect = null;
				innerRect?.Dispose();
				innerRect = null;
			}
			base.Dispose(disposing);
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			Rect clipBounds = canvas.ClipBounds;
			int num = clipBounds.CenterX();
			int num2 = clipBounds.CenterY();
			int num3 = System.Math.Min(canvas.Height, canvas.Width);
			float num4 = (float)clipBounds.Height() * 0.06f;
			num3 -= (int)num4;
			int num5 = num3 / 2;
			outerRect.Set(num - num5, num2 - num5, num + num5, num2 + num5);
			innerRect.Set((float)(num - num5) + num4, (float)(num2 - num5) + num4, (float)(num + num5) - num4, (float)(num2 + num5) - num4);
			DrawOuterProgress(canvas);
			DrawInnerProgress(canvas);
		}

		private void DrawOuterProgress(Canvas canvas)
		{
			float sweepAngle = StepProgress * 360f;
			canvas.DrawArc(outerRect, 90f, 360f, useCenter: false, outerEmptyPaint);
			canvas.DrawArc(outerRect, 90f, sweepAngle, useCenter: false, outerFilledPaint);
		}

		private void DrawInnerProgress(Canvas canvas)
		{
			float num = TotalProgress * 360f;
			canvas.DrawArc(innerRect, 90f, 360f, useCenter: false, innerEmptyPaint);
			canvas.DrawArc(innerRect, 90f, num, useCenter: false, innerFilledPaint);
			innerFilledPaint.SetStyle(Paint.Style.Fill);
			DenseVector denseVector = CalculateInnerProgressCoordinates(innerRect, num);
			canvas.DrawCircle(denseVector[0], denseVector[1], 5f, innerFilledPaint);
			innerFilledPaint.SetStyle(Paint.Style.Stroke);
		}

		private static DenseVector CalculateInnerProgressCoordinates(RectF innerRect, float totalProgress)
		{
			double num = System.Math.PI / 180.0 * (double)(0f - totalProgress);
			DenseVector denseVector = new DenseVector(new float[2]
			{
				innerRect.CenterX(),
				innerRect.Bottom
			});
			DenseVector denseVector2 = new DenseVector(new float[2]
			{
				innerRect.CenterX(),
				innerRect.CenterY()
			});
			DenseVector denseVector3 = denseVector - denseVector2;
			float num2 = Convert.ToSingle(System.Math.Cos(num) * (double)denseVector3[0] + System.Math.Sin(num) * (double)denseVector3[1]);
			float num3 = Convert.ToSingle((0.0 - System.Math.Sin(num)) * (double)denseVector3[0] + System.Math.Cos(num) * (double)denseVector3[1]);
			return denseVector2 + new DenseVector(new float[2] { num2, num3 });
		}
	}
