		private void Init(Context context)
		{
			float dimension = context.Resources.GetDimension(2131167057);
			rectOffset = dimension / 2f;
			ovalPaint = new Paint
			{
				Color = context.GetColorCompat(2131100283),
				AntiAlias = true
			};
			arcPaint = new Paint
			{
				Dither = true,
				AntiAlias = true,
				StrokeJoin = Paint.Join.Round,
				StrokeCap = Paint.Cap.Round,
				StrokeWidth = dimension,
				Color = context.GetColorCompat(2131100284)
			};
			arcPaint.SetStyle(Paint.Style.Stroke);
			Post(delegate
			{
				ovalRect = new RectF(rectOffset, rectOffset, (float)base.MeasuredWidth - rectOffset, (float)base.MeasuredHeight - rectOffset);
			});
			SetWillNotDraw(willNotDraw: false);
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			if (ovalRect != null)
			{
				canvas.DrawOval(ovalRect, ovalPaint);
				if (!Progress.AlmostEqual(0.0))
				{
					float num = (float)Progress;
					float sweepAngle = num * 360f;
					canvas.DrawArc(ovalRect, 270f, sweepAngle, useCenter: false, arcPaint);
				}
			}
		}
	}
	public class IfitTrack : View
	{
