		private float TrackWidth => (float)base.Height * 0.03f;

		private float FillWidth => outerRadius - innerRadius;

		private float outerRadius => (float)base.Height / 2f - TrackWidth;

		private float innerRadius => (float)base.Height / 4f;

		private float avgRadius => (outerRadius + innerRadius) / 2f;

		private float leftCenterX => outerRadius + TrackWidth;

		private float rightCenterX => (float)base.Width - outerRadius - TrackWidth;

		private float centerY => (float)base.Height / 2f;

		public double Percentage
		{
			get
			{
				return _percentage;
			}
			set
			{
				SetPercentage(value);
			}
		}

		public bool ShouldBeUpdating { get; set; }

		public IfitTrack(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public IfitTrack(Context context)
			: base(context)
		{
			Init(context, null);
		}

		public IfitTrack(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public IfitTrack(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context, attrs);
		}

		public IfitTrack(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.InWorkoutTrackView);
			if (typedArray != null)
			{
				global::Android.Graphics.Color color = typedArray.GetColor(1, base.Context.GetColorCompat(2131099690));
				global::Android.Graphics.Color color2 = typedArray.GetColor(2, base.Context.GetColorCompat(2131100024));
				global::Android.Graphics.Color color3 = typedArray.GetColor(0, base.Context.GetColorCompat(2131100449));
				SetBackgroundColor(global::Android.Graphics.Color.Transparent);
				SetWillNotDraw(willNotDraw: false);
				trackPaint = new Paint();
				trackPaint.Color = color;
				trackPaint.AntiAlias = true;
				trackPaint.StrokeCap = Paint.Cap.Round;
				trackPaint.SetStyle(Paint.Style.Stroke);
				fillPaint = new Paint();
				fillPaint.Color = color2;
				fillPaint.AntiAlias = true;
				fillPaint.SetStyle(Paint.Style.Stroke);
				backgroundFillPaint = new Paint();
				backgroundFillPaint.Color = color3;
				backgroundFillPaint.AntiAlias = true;
				backgroundFillPaint.SetStyle(Paint.Style.Stroke);
				outlineBox = new RectF();
				leftArchBox = new RectF();
				rightArchBox = new RectF();
			}
		}

		protected override void OnDetachedFromWindow()
		{
			base.OnDetachedFromWindow();
			trackPaint?.Dispose();
			trackPaint = null;
			fillPaint?.Dispose();
			fillPaint = null;
			backgroundFillPaint?.Dispose();
			backgroundFillPaint = null;
			outlineBox?.Dispose();
			outlineBox = null;
			leftArchBox?.Dispose();
			leftArchBox = null;
			rightArchBox?.Dispose();
			rightArchBox = null;
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			if (base.Width != 0 && base.Height != 0)
			{
				fillPaint.StrokeWidth = FillWidth;
				trackPaint.StrokeWidth = TrackWidth;
				backgroundFillPaint.StrokeWidth = FillWidth;
				DrawTrackBackground(canvas);
				if (Percentage <= 0.25)
				{
					DrawBotRect(canvas, Percentage);
				}
				else if (Percentage <= 0.5)
				{
					DrawRightArch(canvas, Percentage);
				}
				else if (Percentage <= 0.75)
				{
					DrawTopRect(canvas, Percentage);
				}
				else if (Percentage <= 1.0)
				{
					DrawLeftArch(canvas, Percentage);
				}
				DrawOutline(canvas);
			}
		}

		private void SetPercentage(double p)
		{
			if (ShouldBeUpdating && !(System.Math.Abs(p - _percentage) < 9.999999974752427E-07))
			{
				_percentage = p.Clamp(0.0, 1.0);
				Post(Invalidate);
			}
		}

		private void DrawTrackBackground(Canvas canvas)
		{
			float num = rightCenterX - leftCenterX;
			canvas.DrawLine(leftCenterX, centerY + avgRadius, leftCenterX + num, centerY + avgRadius, backgroundFillPaint);
			rightArchBox.Set(rightCenterX - avgRadius, centerY - avgRadius, rightCenterX + avgRadius, centerY + avgRadius);
			canvas.DrawArc(rightArchBox, 91f, -182f, useCenter: false, backgroundFillPaint);
			float num2 = rightCenterX - leftCenterX;
			canvas.DrawLine(rightCenterX, centerY - avgRadius, rightCenterX - num2, centerY - avgRadius, backgroundFillPaint);
			leftArchBox.Set(leftCenterX - avgRadius, centerY - avgRadius, leftCenterX + avgRadius, centerY + avgRadius);
			canvas.DrawArc(leftArchBox, 271f, -182f, useCenter: false, backgroundFillPaint);
		}

		private void DrawOutline(Canvas canvas)
		{
			outlineBox.Set(leftCenterX - outerRadius, centerY - outerRadius, leftCenterX + outerRadius, centerY + outerRadius);
			canvas.DrawArc(outlineBox, 90f, 180f, useCenter: false, trackPaint);
			outlineBox.Set(rightCenterX - outerRadius, centerY - outerRadius, rightCenterX + outerRadius, centerY + outerRadius);
			canvas.DrawArc(outlineBox, 270f, 180f, useCenter: false, trackPaint);
			canvas.DrawLine(leftCenterX, centerY - outerRadius, rightCenterX, centerY - outerRadius, trackPaint);
			canvas.DrawLine(leftCenterX, centerY + outerRadius, rightCenterX, centerY + outerRadius, trackPaint);
			outlineBox.Set(leftCenterX - innerRadius, centerY - innerRadius, leftCenterX + innerRadius, centerY + innerRadius);
			canvas.DrawArc(outlineBox, 90f, 180f, useCenter: false, trackPaint);
			outlineBox.Set(rightCenterX - innerRadius, centerY - innerRadius, rightCenterX + innerRadius, centerY + innerRadius);
			canvas.DrawArc(outlineBox, 270f, 180f, useCenter: false, trackPaint);
			canvas.DrawLine(leftCenterX, centerY - innerRadius, rightCenterX, centerY - innerRadius, trackPaint);
			canvas.DrawLine(leftCenterX, centerY + innerRadius, rightCenterX, centerY + innerRadius, trackPaint);
		}

		private void DrawBotRect(Canvas canvas, double percent)
		{
			float num = rightCenterX - leftCenterX;
			float num2 = (float)((double)num * percent * 4.0);
			canvas.DrawLine(leftCenterX, centerY + avgRadius, leftCenterX + num2, centerY + avgRadius, fillPaint);
		}

		private void DrawRightArch(Canvas canvas, double percent)
		{
			DrawBotRect(canvas, 0.25);
			float num = (float)(182.0 * (percent - 0.25) * 4.0);
			rightArchBox.Set(rightCenterX - avgRadius, centerY - avgRadius, rightCenterX + avgRadius, centerY + avgRadius);
			canvas.DrawArc(rightArchBox, 91f, 0f - num, useCenter: false, fillPaint);
		}

		private void DrawTopRect(Canvas canvas, double percent)
		{
			double num = 0.5;
			DrawRightArch(canvas, num);
			float num2 = rightCenterX - leftCenterX;
			float num3 = (float)((double)num2 * (percent - num) * 4.0);
			canvas.DrawLine(rightCenterX, centerY - avgRadius, rightCenterX - num3, centerY - avgRadius, fillPaint);
		}

		private void DrawLeftArch(Canvas canvas, double percent)
		{
			double num = 0.75;
			DrawTopRect(canvas, num);
			float num2 = (float)(182.0 * (percent - num) * 4.0);
			leftArchBox.Set(leftCenterX - avgRadius, centerY - avgRadius, leftCenterX + avgRadius, centerY + avgRadius);
			canvas.DrawArc(leftArchBox, 271f, 0f - num2, useCenter: false, fillPaint);
		}
	}
	public class IncrementDecrement : LinearLayout
	{
		private new const string Tag = "IncrementDecrement";

		private bool lastChangeMadeByUser;

		private IDisposable updateValueSub;

		private IDisposable userInitiatedChangePendingSub;

		private IDisposable decrementTouchSub;

		private IDisposable incrementTouchSub;

		private ImageButton decrementButton;

		private ImageButton incrementButton;

		private TextView controlValue;

		private TextView controlLabel;

		private System.Timers.Timer tapTimer;

		private RepeatTouchListener decrementListener;

		private RepeatTouchListener incrementListener;

		private const int tapTimerIntervalMs = 400;

		private double _currentValue;

		private bool _userInitiatedChangePending;

		private IWorkoutSlider _sliderModel;

		public double CurrentValue
		{
			get
			{
				return _currentValue;
			}
			set
			{
				_currentValue = value;
				if (lastChangeMadeByUser)
				{
					this.CurrentValueChanged?.Invoke(this, EventArgs.Empty);
					lastChangeMadeByUser = false;
				}
			}
		}

		public bool UserInitiatedChangePending
		{
			get
			{
				return _userInitiatedChangePending;
			}
			private set
			{
				_userInitiatedChangePending = value;
				UpdateEnabledStatus();
			}
		}

		public IWorkoutSlider SliderModel
		{
			get
			{
				return _sliderModel;
			}
			set
			{
				_sliderModel = value;
				UpdateFromSliderModel();
				updateValueSub?.Dispose();
				updateValueSub = _sliderModel?.WhenMetricValueChanged?.Subscribe(delegate
				{
					UpdateFromSliderModel();
				}, delegate(System.Exception ex)
				{
					iFit.Logger.Log.Error("IncrementDecrement", "Error in updateValueSub", ex);
				});
				userInitiatedChangePendingSub?.Dispose();
				userInitiatedChangePendingSub = _sliderModel?.WhenUserInitiatedChangePendingChanged?.Subscribe(delegate(bool pending)
				{
					UserInitiatedChangePending = pending;
				}, delegate(System.Exception ex)
				{
					iFit.Logger.Log.Error("IncrementDecrement", "Error in userInitiatedChangePendingSub", ex);
				});
			}
		}

		public event EventHandler CurrentValueChanged;

		public IncrementDecrement(Context context)
			: base(context)
		{
			Initialize(context, null);
		}

		public IncrementDecrement(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize(context, attrs);
		}

		public IncrementDecrement(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize(context, attrs);
		}

		public IncrementDecrement(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Initialize(context, attrs);
		}

		private void Initialize(Context context, IAttributeSet attrs)
		{
			LayoutInflater.From(context).Inflate(2131624124, this, attachToRoot: true);
			decrementButton = FindViewById<ImageButton>(2131427842);
			incrementButton = FindViewById<ImageButton>(2131428320);
			controlValue = FindViewById<TextView>(2131427737);
			controlLabel = FindViewById<TextView>(2131427736);
			decrementListener = new RepeatTouchListener();
			incrementListener = new RepeatTouchListener();
			decrementTouchSub = decrementListener.WhenTouchEnded.SubscribeWithErrorLogging(delegate(RepeatTouchListener x)
			{
				Button_TouchEnded(x);
			});
			incrementTouchSub = incrementListener.WhenTouchEnded.SubscribeWithErrorLogging(delegate(RepeatTouchListener x)
			{
				Button_TouchEnded(x);
			});
			decrementButton.SetOnTouchListener(decrementListener);
			incrementButton.SetOnTouchListener(incrementListener);
			decrementButton.Click += DecrementButton_Click;
			incrementButton.Click += IncrementButton_Click;
			tapTimer = new System.Timers.Timer
			{
				Interval = 400.0,
				AutoReset = false
			};
			tapTimer.Elapsed += HandleTapTimerElapsed;
		}

		private void DecrementButton_Click(object sender, EventArgs e)
		{
			if (!(_currentValue <= _sliderModel.Minimum))
			{
				_sliderModel?.HandleUserTouchedSlider();
				_currentValue = _sliderModel.ClampAndRound(_currentValue - _sliderModel.MetricStepInterval);
				UpdateLabelWithValue(_currentValue);
			}
		}

		private void IncrementButton_Click(object sender, EventArgs e)
		{
			if (!(_currentValue >= _sliderModel.Maximum))
			{
				_sliderModel?.HandleUserTouchedSlider();
				_currentValue = _sliderModel.ClampAndRound(_currentValue + _sliderModel.MetricStepInterval);
				UpdateLabelWithValue(_currentValue);
			}
		}

		private void Button_TouchEnded(RepeatTouchListener listener)
		{
			if (tapTimer != null)
			{
				if (tapTimer.Enabled)
				{
					tapTimer.Stop();
				}
				tapTimer.Start();
			}
		}

		private void UpdateFromSliderModel()
		{
			(base.Context as Activity).RunOnUiThread(delegate
			{
				if (_sliderModel == null)
				{
					Visibility = ViewStates.Gone;
				}
				else
				{
					Visibility = ViewStates.Visible;
					controlLabel.Text = _sliderModel.MetricLabel.ToUpper();
					SetValue(_sliderModel.MetricValue, userInitiated: false);
					UpdateEnabledStatus();
				}
			});
		}

		private void SetValue(double newValue, bool userInitiated)
		{
			newValue = _sliderModel?.ClampAndRound(newValue) ?? 0.0;
			lastChangeMadeByUser = userInitiated;
			CurrentValue = newValue;
			(base.Context as Activity).RunOnUiThread(delegate
			{
				UpdateLabelWithValue(_currentValue);
			});
		}

		private void UpdateLabelWithValue(double newValue)
		{
			double num = _sliderModel.ClampAndRound(newValue);
			controlValue.Text = num.ToString(_sliderModel.DisplayPrecision);
		}

		private bool IsDecrementButtonAtMinimum()
		{
			return _currentValue < _sliderModel.Minimum + _sliderModel.MetricStepInterval;
		}

		private bool IsIncrementButtonAtMaximum()
		{
			return _currentValue > _sliderModel.Maximum - _sliderModel.MetricStepInterval;
		}

		private void UpdateEnabledStatus()
		{
			(base.Context as Activity).RunOnUiThread(delegate
			{
				decrementButton.Enabled = !_userInitiatedChangePending && _sliderModel != null && !IsDecrementButtonAtMinimum();
				incrementButton.Enabled = !_userInitiatedChangePending && _sliderModel != null && !IsIncrementButtonAtMaximum();
			});
		}

		private void HandleTapTimerElapsed(object sender, ElapsedEventArgs e)
		{
			tapTimer.Stop();
			SetValue(_currentValue, userInitiated: true);
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				decrementButton.Click -= DecrementButton_Click;
				incrementButton.Click -= IncrementButton_Click;
				updateValueSub?.Dispose();
				updateValueSub = null;
				userInitiatedChangePendingSub?.Dispose();
				userInitiatedChangePendingSub = null;
				decrementTouchSub?.Dispose();
				decrementListener?.Dispose();
				decrementListener = null;
				decrementTouchSub = null;
				incrementTouchSub?.Dispose();
				incrementTouchSub = null;
				incrementListener?.Dispose();
				incrementListener = null;
				if (tapTimer != null)
				{
					tapTimer.Elapsed -= HandleTapTimerElapsed;
				}
				tapTimer?.Dispose();
				tapTimer = null;
			}
			base.Dispose(disposing);
		}
	}
