	{
		public PhoneInWorkoutViewSwipeHelper HorizontalSwipeHelper { get; set; }

		public PhoneInWorkoutVerticalViewPager(Context context)
			: base(context)
		{
			Initialize();
		}

		public PhoneInWorkoutVerticalViewPager(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize();
		}

		private void Initialize()
		{
			SetPageTransformer(reverseDrawingOrder: true, new VerticalPageTransformer());
		}

		public override bool CanScrollHorizontally(int direction)
		{
			return false;
		}

		public override bool CanScrollVertically(int direction)
		{
			return base.CanScrollHorizontally(direction);
		}

		public override bool OnInterceptTouchEvent(MotionEvent ev)
		{
			if (HorizontalSwipeHelper.IsSwiping || HorizontalSwipeHelper.IsDrawerOpen)
			{
				HorizontalSwipeHelper.OnViewPagerTouched(this, ev);
				return false;
			}
			MotionEvent ev2 = MotionEvent.Obtain(ev);
			bool flag = base.OnInterceptTouchEvent(FlipXY(ev2));
			if (!flag || HorizontalSwipeHelper.IsSwiping || HorizontalSwipeHelper.IsDrawerOpen)
			{
				HorizontalSwipeHelper.OnViewPagerTouched(this, ev);
			}
			return flag;
		}

		public override bool OnTouchEvent(MotionEvent ev)
		{
			bool result = base.OnTouchEvent(FlipXY(ev));
			FlipXY(ev);
			return result;
		}

		private MotionEvent FlipXY(MotionEvent ev)
		{
			int width = base.Width;
			int height = base.Height;
			float x = ev.GetY() / (float)height * (float)width;
			float y = ev.GetX() / (float)width * (float)height;
			ev.SetLocation(x, y);
			return ev;
		}
	}
	public class VerticalPageTransformer : Java.Lang.Object, ViewPager.IPageTransformer, IJavaObject, IDisposable, IJavaPeerable
	{
		public void TransformPage(View view, float position)
		{
			float num = 0.9f;
			int width = view.Width;
			int height = view.Height;
			if (position < -1f)
			{
				view.Alpha = 0f;
			}
			else if (position <= 1f)
			{
				view.Alpha = 1f;
				view.TranslationX = (float)width * (0f - position);
				float translationY = position * (float)height;
				view.TranslationY = translationY;
				float scaleY = (view.ScaleX = 1f - (1f - num) * System.Math.Abs(position));
				view.ScaleY = scaleY;
			}
			else
			{
				view.Alpha = 0f;
			}
		}
	}
