	public class SliderMarks : LinearLayout
	{
		private List<View> marks = new List<View>();

		private Subject<int> _whenMarkTapped = new Subject<int>();

		private int markBackgroundHeight;

		private int markLeftRightPadding;

		public IObservable<int> WhenMarkTapped => _whenMarkTapped;

		public SliderMarks(Context context)
