		private void Initialize()
		{
			Orientation = global::Android.Widget.Orientation.Vertical;
			markBackgroundHeight = Resources.GetDimensionPixelSize(2131168189);
			markLeftRightPadding = Resources.GetDimensionPixelSize(2131168187);
		}

		protected override void Dispose(bool disposing)
		{
			marks.ForEach(delegate(View mark)
			{
				mark.Click -= MarkClicked;
			});
			base.Dispose(disposing);
		}

		public void CreateMarks(IWorkoutSlider slider)
		{
			RemoveAllViews();
			for (int i = 0; i < slider.NumberOfMarks; i++)
			{
				View mark = GetMark(base.Context, this, slider, i);
				marks.Insert(0, mark);
				mark.Click -= MarkClicked;
				mark.Click += MarkClicked;
				AddView(mark);
			}
		}

		private void MarkClicked(object sender, EventArgs e)
		{
			int num = marks.IndexOf(sender as View);
			_whenMarkTapped.OnNext((num >= 0) ? num : 0);
		}

		public View GetMark(Context context, ViewGroup parent, IWorkoutSlider sliderModel, int index)
		{
			IfitTextView ifitTextView = LayoutInflater.FromContext(context).Inflate(2131624416, parent, attachToRoot: false) as IfitTextView;
			ifitTextView.Text = sliderModel.MarkValues[sliderModel.NumberOfMarks - index - 1].ToString();
			return ifitTextView;
		}

		protected override void OnSizeChanged(int w, int h, int oldw, int oldh)
		{
			base.OnSizeChanged(w, h, oldw, oldh);
			int childCount = ChildCount;
			int num = h / childCount;
			int num2 = (num - markBackgroundHeight) / 2;
			for (int i = 0; i < childCount; i++)
			{
				LayerDrawable layerDrawable = GetChildAt(i).Background as LayerDrawable;
				int num3 = layerDrawable?.NumberOfLayers ?? 0;
				for (int j = 0; j < num3; j++)
				{
					layerDrawable?.SetLayerInset(j, markLeftRightPadding, num2, markLeftRightPadding, num2);
				}
			}
		}
	}
	public class SliderThumb : LinearLayout
	{
		private IfitTextView valueTextView;

		private IfitTextView metricTextView;

		private ImageView upButton;

		private ImageView downButton;

		private float scrollStartY;

		private bool haveScrolled;

		public Action<float, bool> Scroll { get; set; }

		public string Value
		{
			get
			{
				return valueTextView.Text;
			}
			set
			{
				valueTextView.Text = value;
			}
		}

		public string MetricText
		{
			get
			{
				return metricTextView.Text;
			}
			set
			{
				metricTextView.Text = value;
			}
		}

		public event EventHandler UpTapped;

		public event EventHandler DownTapped;

		public SliderThumb(Context context)
			: base(context)
		{
			Initialize();
		}

		public SliderThumb(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize();
		}

		public SliderThumb(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize();
		}

		private void Initialize()
		{
			LayoutInflater.FromContext(base.Context).Inflate(2131624417, this, attachToRoot: true);
			valueTextView = FindViewById<IfitTextView>(2131429281);
			metricTextView = FindViewById<IfitTextView>(2131429279);
			upButton = FindViewById<ImageView>(2131429280);
			upButton.Touch += HandleTouches;
			downButton = FindViewById<ImageView>(2131429278);
			downButton.Touch += HandleTouches;
			valueTextView.Touch += HandleTouches;
			metricTextView.Touch += HandleTouches;
		}

		private void HandleTouches(object sender, TouchEventArgs e)
		{
			MotionEventActions action = e.Event.Action;
			float rawY = e.Event.RawY;
			if (action == MotionEventActions.Down)
			{
				scrollStartY = rawY;
				haveScrolled = false;
				return;
			}
			float num = scrollStartY - rawY;
			switch (action)
			{
			case MotionEventActions.Move:
				if (System.Math.Abs(num) > 0f)
				{
					Scroll?.Invoke(num, arg2: false);
					haveScrolled = true;
				}
				break;
			case MotionEventActions.Up:
			case MotionEventActions.Cancel:
				if (haveScrolled)
				{
					Scroll?.Invoke(num, arg2: true);
				}
				else if (sender == upButton)
				{
					this.UpTapped?.Invoke(upButton, EventArgs.Empty);
				}
				else if (sender == downButton)
				{
					this.DownTapped?.Invoke(downButton, EventArgs.Empty);
				}
				break;
			}
		}
	}
