			{
				_svService = value;
				imageBytesSub = _svService?.WhenImageAvailableAtCurrentDistance.Subscribe(delegate(StreetViewImageUpdate x)
				{
					if (_nextImage == null || !_nextImage.Equals(x.RawImage))
					{
