			leftRightPaint = new Paint(PaintFlags.AntiAlias);
			leftRightPaint.SetStyle(Paint.Style.FillAndStroke);
			leftRightPaint.Color = Resources.GetColor(2131100179);
			centerPaint = new Paint(PaintFlags.AntiAlias);
			centerPaint.SetStyle(Paint.Style.Fill);
			centerPaint.Color = Resources.GetColor(2131100225);
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			int width = canvas.Width;
			int height = canvas.Height;
			float density = base.Context.Resources.DisplayMetrics.Density;
			float num = 10f * density;
			leftPath.MoveTo(0f, 0f);
			leftPath.LineTo(num, height);
			leftPath.LineTo(0f, height);
			leftPath.Close();
			canvas.DrawPath(leftPath, leftRightPaint);
			rightPath.MoveTo(width, 0f);
			rightPath.LineTo((float)width - num, height);
			rightPath.LineTo(width, height);
			rightPath.Close();
			canvas.DrawPath(rightPath, leftRightPaint);
			centerPath.MoveTo(0f, 0f);
			centerPath.LineTo(num, height);
			centerPath.LineTo((float)width - num, height);
			centerPath.LineTo(width, 0f);
			centerPath.LineTo(0f, 0f);
			centerPath.Close();
			canvas.DrawPath(centerPath, centerPaint);
		}
	}
