				else
				{
					base.TransformationMethod = SingleLineTransformationMethod.Instance;
				}
				Invalidate();
				SetSelection(base.Text.Length);
			}
		}

		public event EventHandler DrawableLeftClick;

		public event EventHandler DrawableRightClick;

		public event EventHandler FocusChanged;

		public event EventHandler KeyboardClosed;

		public JoinLoginEditTextView(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public JoinLoginEditTextView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public JoinLoginEditTextView(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.JoinLoginEditText);
			try
			{
				SetTypeface(IfitTypeface.GetCustomTypeface((IfitTypeface.Type)typedArray.GetInt(1, 0)), TypefaceStyle.Normal);
				int imeOptions = typedArray.GetInt(0, 1);
				ImeOptions = (ImeAction)imeOptions;
			}
			finally
			{
				typedArray?.Recycle();
			}
			SetOnTouchListener(this);
			base.FocusChange += TypefaceEditText_FocusChange;
		}

		public void SetTypeface(IfitTypeface.Type typeFaceType)
		{
			if (!IsInEditMode)
			{
				SetTypeface(typeFaceType.GetTypeface(), TypefaceStyle.Normal);
			}
		}

		private void TypefaceEditText_FocusChange(object sender, FocusChangeEventArgs e)
		{
			if (!e.HasFocus)
			{
				this.FocusChanged?.Invoke(this, null);
			}
		}

		public bool OnTouch(View v, MotionEvent e)
		{
			if (e.Action == MotionEventActions.Up)
			{
				if (this.DrawableRightClick != null && e.RawX >= (float?)(this.GetAbsoluteRight() - GetCompoundDrawablesRelative()[2]?.Bounds.Width()))
				{
					this.DrawableRightClick(this, new GenericMotionEventArgs(handled: true, e));
					return true;
				}
				if (this.DrawableLeftClick != null && e.RawX <= (float?)GetCompoundDrawablesRelative()[0]?.Bounds.Width())
				{
					this.DrawableLeftClick(this, new GenericMotionEventArgs(handled: true, e));
					return true;
				}
			}
			return false;
		}

		public override bool OnKeyPreIme(Keycode keyCode, KeyEvent e)
		{
			if (keyCode == Keycode.Back)
			{
				this.KeyboardClosed?.Invoke(this, null);
			}
			return base.OnKeyPreIme(keyCode, e);
		}
	}
	public class LabelledTextEntry : RelativeLayout, View.IOnFocusChangeListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private IfitTextView label;

		private AppCompatEditText textEntry;

		private TextInputLayout textLayout;

		private LabelledTextEntry nextTextEntry;

		public string Text => textEntry.Text;

		public int TextViewId => textEntry.Id;

		public LabelledTextEntry(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public LabelledTextEntry(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context);
		}

		public LabelledTextEntry(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Init(context);
		}

		private void Init(Context context)
		{
			LayoutInflater.From(context).Inflate(2131624174, this, attachToRoot: true);
			label = FindViewById<IfitTextView>(2131429690);
			textEntry = FindViewById<AppCompatEditText>(2131429688);
			textLayout = FindViewById<TextInputLayout>(2131429691);
		}

		public void Setup(LabelledTextEntry next, string labelText, string placeholder, string initialText, InputTypes inputTypes = InputTypes.DatetimeVariationNormal)
		{
			nextTextEntry = next;
			label.Text = " " + labelText + "  ";
			if (!string.IsNullOrEmpty(initialText))
			{
				textEntry.Text = initialText;
			}
			else
			{
				textEntry.Hint = placeholder;
			}
			textEntry.OnFocusChangeListener = this;
			textEntry.EditorAction -= CheckForEnterClicked;
			textEntry.EditorAction += CheckForEnterClicked;
			if (inputTypes != InputTypes.DatetimeVariationNormal)
			{
				textEntry.InputType = inputTypes;
			}
		}

		public void ShowError(bool isVisible)
		{
			if (isVisible)
			{
				textLayout.Error = " ";
			}
			else
			{
				textLayout.Error = null;
			}
		}

		public void SetText(string newText)
		{
			textEntry.Text = newText;
		}

		private void CheckForEnterClicked(object sender, TextView.EditorActionEventArgs e)
		{
			if (e.ActionId == ImeAction.Next)
			{
				textEntry.ClearFocus();
				nextTextEntry.textEntry.RequestFocus();
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				label?.DisposeIfDisposable();
				label = null;
				textEntry?.DisposeIfDisposable();
				textEntry = null;
				textLayout?.DisposeIfDisposable();
				textLayout = null;
			}
			base.Dispose(disposing);
		}

		public void OnFocusChange(View? v, bool hasFocus)
		{
			if (!hasFocus)
			{
				ShowError(isVisible: false);
			}
		}
	}
