			titleTextView = itemView.FindViewById<IfitTextView>(2131429572);
			descriptionTextView = itemView.FindViewById<IfitTextView>(2131427851);
			RightImage = itemView.FindViewById<BasicImageView>(2131429719);
		}

		protected override void SetupBindings(MvxFluentBindingDescriptionSet<UserAccountMenuItem, UserAccountMenuItemModel> bindingSet)
		{
			MvxFluentBindingDescriptionSet<UserAccountMenuItem, UserAccountMenuItemModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<UserAccountMenuItem, UserAccountMenuItemModel>();
			mvxFluentBindingDescriptionSet.Bind(titleTextView).For((IfitTextView v) => v.Text).To((UserAccountMenuItemModel vm) => vm.UserTitle);
			mvxFluentBindingDescriptionSet.Bind(descriptionTextView).For((IfitTextView v) => v.Text).To((UserAccountMenuItemModel vm) => vm.DescriptionText);
			mvxFluentBindingDescriptionSet.Bind(descriptionTextView).For((IfitTextView v) => v.Visibility).To((UserAccountMenuItemModel vm) => vm.HasDescription)
				.WithConversion(new MvxVisibilityValueConverter());
			mvxFluentBindingDescriptionSet.Bind(Avatar).For((AvatarImage v) => v.User).To((UserAccountMenuItemModel vm) => vm.ItemUser);
			mvxFluentBindingDescriptionSet.Bind(this).For((UserAccountMenuItem v) => v.RightImageType).To((UserAccountMenuItemModel vm) => vm.RightImageType);
			mvxFluentBindingDescriptionSet.Bind(this).For(itemView.ClickEvent()).To((UserAccountMenuItemModel vm) => vm.SelectedCommand);
			mvxFluentBindingDescriptionSet.Apply();
		}
	}
	public class PickerDialogFragment<T> : global::Android.App.DialogFragment where T : class
	{
		private Subject<T> whenSelectionChanged = new Subject<T>();

		private Subject<bool> whenDialogCanceled = new Subject<bool>();

		private Context context;

		private NumberPicker picker;

		private ObservableCollection<T> values;

		private string title;

		private int widthPx;

		private T selectedValue;

		public IObservable<T> WhenSelectionChanged => whenSelectionChanged;

		public IObservable<bool> WhenDialogCanceled => whenDialogCanceled;

		public PickerDialogFragment(Context context, ObservableCollection<T> values, T selectedValue = null, string title = null, int widthResId = 2131167354)
		{
			this.context = context;
			this.values = values;
			this.title = title;
			this.selectedValue = selectedValue;
			widthPx = context.Resources.GetDimensionPixelSize(widthResId);
		}

		public override Dialog OnCreateDialog(Bundle savedInstanceState)
		{
			picker = new NumberPicker(context);
			picker.MinValue = 0;
			picker.ShowDividers = ShowDividers.Beginning;
			picker.SetDividerDrawable(context.GetDrawable(2131231901));
			picker.MaxValue = values.Count - 1;
			picker.SetDisplayedValues(values.Select((T x) => x.ToString()).ToArray());
			SetDividerColor(picker, base.Activity.GetColorCompat(2131100107));
			if (selectedValue != null)
			{
				picker.Value = values.IndexOf(selectedValue);
			}
			picker.DescendantFocusability = DescendantFocusability.BlockDescendants;
			FrameLayout frameLayout = new FrameLayout(context);
			frameLayout.AddView(picker, new FrameLayout.LayoutParams(widthPx, -2, GravityFlags.Center));
			AndroidX.AppCompat.App.AlertDialog.Builder builder = new AndroidX.AppCompat.App.AlertDialog.Builder(context, 2132017703);
			builder.SetTitle(title).SetView(frameLayout).SetPositiveButton(Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), OnPositiveClick)
				.SetNegativeButton(Wolf.Core.Resources.AppStrings.cancel_title.ToUpper(), OnNegativeClick);
			return builder.Create();
		}

		private void OnPositiveClick(object sender, DialogClickEventArgs e)
		{
			int value = picker.Value;
			whenSelectionChanged?.OnNext(values[value]);
		}

		private void OnNegativeClick(object sender, DialogClickEventArgs e)
		{
			whenDialogCanceled?.OnNext(value: true);
		}

		private void SetDividerColor(NumberPicker numberPicker, int color)
		{
			Field declaredField = Class.FromType(typeof(NumberPicker)).GetDeclaredField("mSelectionDivider");
			declaredField.Accessible = true;
			declaredField.Set(numberPicker, new ColorDrawable(new global::Android.Graphics.Color(color)));
		}
	}
