	public class AccountSelectionAdapter : MvxRecyclerAdapter
	{
		public AccountSelectionAdapter(IMvxAndroidBindingContext bindingContext)
			: base(bindingContext)
		{
		}

		public override RecyclerView.ViewHolder OnCreateViewHolder(ViewGroup parent, int viewType)
		{
			MvxAndroidBindingContext mvxAndroidBindingContext = new MvxAndroidBindingContext(parent.Context, base.BindingContext.LayoutInflaterHolder);
			View itemView = InflateViewForHolder(parent, viewType, mvxAndroidBindingContext);
			return viewType switch
			{
				2131624446 => new AccountSelectionUserViewHolder(itemView, mvxAndroidBindingContext), 
				2131624448 => new AccountSelectionSendInviteViewHolder(itemView, mvxAndroidBindingContext), 
				2131624254 => new AccountSelectionPendingInviteViewHolder(itemView, mvxAndroidBindingContext), 
				2131624447 => new AccountSelectionUserPasswordViewHolder(itemView, mvxAndroidBindingContext), 
				_ => base.OnCreateViewHolder(parent, viewType), 
			};
		}

		public override void OnBindViewHolder(RecyclerView.ViewHolder holder, int position)
		{
			holder.ItemView.LayoutParameters = GetUpdatedLayoutParams(holder.ItemView);
			base.OnBindViewHolder(holder, position);
		}

		public override int GetItemViewType(int position)
		{
			object item = GetItem(position);
			if (!(item is AccountSelectionUserItemModel))
			{
				if (!(item is AccountSelectionSendInviteItemModel))
				{
					if (!(item is AccountSelectionPendingInviteItemModel))
					{
						if (item is AccountSelectionUserPasswordItemModel)
						{
							return 2131624447;
						}
						return 0;
					}
					return 2131624254;
				}
				return 2131624448;
			}
			return 2131624446;
		}

		protected override View InflateViewForHolder(ViewGroup parent, int viewType, IMvxAndroidBindingContext bindingContext)
		{
			return LayoutInflater.FromContext(parent.Context).Inflate(viewType, parent, attachToRoot: false);
		}

		private ViewGroup.LayoutParams GetUpdatedLayoutParams(View view)
		{
			ViewGroup.LayoutParams layoutParameters = view.LayoutParameters;
			int itemSize = GetItemSize(view.Context);
			layoutParameters.Width = itemSize;
			layoutParameters.Height = (int)view.Context.Resources.GetDimension(2131165273);
			return layoutParameters;
		}

		private int GetItemSize(Context context)
		{
			if (Mvx.TryResolve<IDeviceInformation>(out var service))
			{
				float dimension = context.Resources.GetDimension(2131165270);
				return (service.PixelScreenWidth - (int)dimension) / 5;
			}
			return 0;
		}
	}
