	public class SettingsCollection : CardView
	{
		public enum SettingsCollectionType
		{
			Account,
			Equipment,
			About
		}

		private class SettingsAdapter : MvxListViewAdapter<SettingsCollectionCellModel>
		{
			private List<SettingsCollectionCell> cells;

			public SettingsAdapter(IntPtr javaReference, JniHandleOwnership transfer)
				: base(javaReference, transfer)
			{
				cells = new List<SettingsCollectionCell>();
			}

			public SettingsAdapter(Context context, IMvxAndroidBindingContext bindingContext, int layoutResId)
				: base(context, bindingContext, layoutResId)
			{
				cells = new List<SettingsCollectionCell>();
			}

			protected override IMvxListItemView CreateViewBasedOnInfo(SettingsCollectionCellModel dataContext, int templateId)
			{
				SettingsCollectionCell settingsCollectionCell = new SettingsCollectionCell(base.Context);
				settingsCollectionCell.DataContext = dataContext;
				cells.Add(settingsCollectionCell);
				return settingsCollectionCell;
			}

			protected override void Dispose(bool disposing)
			{
				base.Dispose(disposing);
				if (cells == null)
				{
					return;
				}
				foreach (SettingsCollectionCell cell in cells)
				{
					cell.Dispose();
				}
				cells.Clear();
				cells = null;
			}
		}

		private CardView containerView;

		private LinearLayout linearLayout;

		private AbsListView listView;

		private IfitTextView title;

		private int layoutResId;

		public SettingsCollection(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public SettingsCollection(Context context)
			: base(context)
		{
			Init(context);
		}

		public SettingsCollection(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context);
		}

		public SettingsCollection(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context);
		}

		private void Init(Context context)
		{
			Mvx.TryResolve<IDeviceInformation>(out var service);
			layoutResId = ((service != null && service.IsTablet) ? 2131624346 : 2131624345);
			LayoutInflater.From(context).Inflate(layoutResId, this, attachToRoot: true);
			containerView = FindViewById<CardView>(2131429211);
			linearLayout = FindViewById<LinearLayout>(2131429212);
			title = FindViewById<IfitTextView>(2131429205);
			listView = FindViewById<AbsListView>(2131429206);
		}

		public void Init<TView, TViewModel>(SettingsCollectionType collection, IMvxAndroidBindingContext bindingContext, MvxFluentBindingDescriptionSet<TView, TViewModel> bindingSet, string customTitle = null) where TView : PrimarySettingsView<TViewModel> where TViewModel : PrimarySettingsViewModel
		{
			Mvx.TryResolve<IDeviceInformation>(out var service);
			listView.Adapter = new SettingsAdapter(base.Context, bindingContext, layoutResId);
			IMvxAdapter childTarget = listView.Adapter as IMvxAdapter;
			switch (collection)
			{
			case SettingsCollectionType.Account:
				title.Text = customTitle ?? Wolf.Core.Resources.AppStrings.settings_account_label;
				title.Visibility = (string.IsNullOrWhiteSpace(title.Text) ? ViewStates.Gone : ViewStates.Visible);
				bindingSet.Bind(childTarget).For((IMvxAdapter a) => a.ItemsSource).To((TViewModel vm) => vm.AccountList);
				break;
			case SettingsCollectionType.Equipment:
				title.Text = customTitle ?? Wolf.Core.Resources.AppStrings.settings_equipment_label;
				title.Visibility = (string.IsNullOrWhiteSpace(title.Text) ? ViewStates.Gone : ViewStates.Visible);
				bindingSet.Bind(childTarget).For((IMvxAdapter a) => a.ItemsSource).To((TViewModel vm) => vm.EquipmentList);
				break;
			case SettingsCollectionType.About:
				title.Text = customTitle ?? Wolf.Core.Resources.AppStrings.settings_about_label;
				title.Visibility = (string.IsNullOrWhiteSpace(title.Text) ? ViewStates.Gone : ViewStates.Visible);
				bindingSet.Bind(childTarget).For((IMvxAdapter a) => a.ItemsSource).To((TViewModel vm) => vm.AboutList);
				if (service != null && service.IsStrengthMirror)
				{
					ViewGroup.LayoutParams layoutParameters = linearLayout.LayoutParameters;
					layoutParameters.Height = (int)Resources.GetDimension(2131167953);
					linearLayout.LayoutParameters = layoutParameters;
				}
				break;
			}
			title.Text = title.Text.ToUpper();
		}

		public void VerifyHeight()
		{
			if (listView is MvxListView)
			{
				LayoutPhoneHeight();
			}
			else if (listView is MvxGridView)
			{
				LayoutGridHeight();
			}
		}

		private void LayoutPhoneHeight()
		{
			IListAdapter adapter = listView.Adapter;
			int count = adapter.Count;
			int num = 0;
			for (int i = 0; i < count; i++)
			{
				View view = adapter.GetView(i, null, listView);
				view.Measure(0, 0);
				num += view.MeasuredHeight;
			}
			ViewGroup.LayoutParams layoutParameters = listView.LayoutParameters;
			layoutParameters.Height = num;
			listView.LayoutParameters = layoutParameters;
			(listView as MvxListView).DividerHeight = 0;
		}

		private void LayoutGridHeight()
		{
			IListAdapter adapter = listView.Adapter;
			int count = adapter.Count;
			int num = 0;
			int num2 = 0;
			for (int i = 0; i < count; i++)
			{
				View view = adapter.GetView(i, null, listView);
				if (i == 0)
				{
					view.Measure(0, 0);
					num2 = view.MeasuredHeight;
				}
				if (i % 2 == 0)
				{
					num += ((num2 > 0) ? num2 : num);
				}
			}
			ViewGroup.LayoutParams layoutParameters = listView.LayoutParameters;
			layoutParameters.Height = num;
			listView.LayoutParameters = layoutParameters;
		}

		public void CleanUp()
		{
			listView?.Adapter?.Dispose();
			listView.Adapter = null;
			listView?.Dispose();
			listView = null;
			title?.Dispose();
			title = null;
			linearLayout?.Dispose();
			linearLayout = null;
			containerView?.Dispose();
			containerView = null;
		}
	}
