			: base(context, attrs, defStyleAttr)
		{
		}

		protected override void Init(IAttributeSet attrs)
		{
			LayoutInflater.From(base.Context).Inflate(2131624401, this, attachToRoot: true);
			title = FindViewById<IfitTextView>(2131429692);
			content = FindViewById<IfitTextView>(2131429688);
			ActionItem = FindViewById<IfitTextView>(2131429686);
			Spinner = FindViewById<IfitTextView>(2131428424);
			Spinner.Click -= PickerClicked;
			Spinner.Click += PickerClicked;
		}

		private void PickerClicked(object sender, EventArgs e)
		{
			if (Options != null && Options.Count != 0)
			{
				global::Android.App.AlertDialog.Builder builder = new global::Android.App.AlertDialog.Builder(base.Context, 2132017854);
				builder.SetTitle(base.Title);
				NumberPicker picker = new NumberPicker(base.Context);
				picker.MinValue = 0;
				picker.MaxValue = Options.Count - 1;
				if (!string.IsNullOrEmpty(SelectedValue))
				{
					int num = Options.IndexOf(SelectedValue);
					picker.Value = ((num != -1) ? num : 0);
				}
				picker.SetDisplayedValues(Options.ToArray());
				picker.DescendantFocusability = DescendantFocusability.BlockDescendants;
				builder.SetView(picker);
				builder.SetPositiveButton(Wolf.Core.Resources.AppStrings.settings_dialog_Save, delegate
				{
					SelectedValue = Options[picker.Value];
					OnOptionSelected(Options[picker.Value]);
				});
				builder.Show();
			}
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			if (disposing && Spinner != null)
			{
				Spinner.Click -= PickerClicked;
			}
		}
