	public class SettingsScreenBrightness : LinearLayout
	{
		public enum SupportState
		{
			Checking,
			Supported,
			NotSupported
		}

		private static SemaphoreSlim ss = new SemaphoreSlim(1, 1);

		private SeekBar screenBrightnessBar;

		private IfitTextView screenBrightnessText;

		public float InitialBrightnessPercentage
		{
			set
			{
				screenBrightnessBar.Progress = (int)System.Math.Round(255f * value);
			}
		}

		public SupportState State
		{
			set
			{
				SetSupportState(value);
			}
		}

		public SettingsScreenBrightness(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public SettingsScreenBrightness(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(attrs);
		}

		public SettingsScreenBrightness(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(attrs);
		}

		private void Init(IAttributeSet attrs)
		{
			LayoutInflater.From(base.Context).Inflate(2131624396, this, attachToRoot: true);
			screenBrightnessText = FindViewById<IfitTextView>(2131429152);
			screenBrightnessBar = FindViewById<SeekBar>(2131429151);
			screenBrightnessBar.Max = 255;
			screenBrightnessBar.ProgressChanged += OnProgressChanged;
			SetSupportState(SupportState.Checking);
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			if (disposing)
			{
				screenBrightnessBar.ProgressChanged -= OnProgressChanged;
				screenBrightnessBar?.Dispose();
				screenBrightnessBar = null;
				screenBrightnessText?.Dispose();
				screenBrightnessText = null;
			}
		}

		private async void OnProgressChanged(object sender, SeekBar.ProgressChangedEventArgs e)
		{
			await ss.WaitAsync();
			try
			{
				if (e.FromUser)
				{
					float percentage = (float)screenBrightnessBar.Progress / 255f;
					await SetScreenBrightness.SetScreenBrightnessAsync(percentage, saveValue: true);
				}
			}
			finally
			{
				ss.Release();
			}
		}

		private void SetSupportState(SupportState state)
		{
			switch (state)
			{
			case SupportState.Checking:
				screenBrightnessText.Text = Wolf.Core.Resources.AppStrings.settings_check_brightness_support;
				screenBrightnessBar.Visibility = ViewStates.Gone;
				break;
			case SupportState.NotSupported:
				screenBrightnessText.Text = Wolf.Core.Resources.AppStrings.settings_no_brightness_support;
				screenBrightnessBar.Visibility = ViewStates.Gone;
				break;
			case SupportState.Supported:
				screenBrightnessText.Text = Wolf.Core.Resources.AppStrings.settings_screen_brightness;
				screenBrightnessBar.Visibility = ViewStates.Visible;
				break;
			}
		}
	}
