	public class SlottedProgressBar : View
	{
		private int _numberOfSlots = 3;

		private int _slotPixelWidth = 2;

		private global::Android.Graphics.Color _fillColor = new global::Android.Graphics.Color(0, 105, 210);

		private global::Android.Graphics.Color _emptyColor = new global::Android.Graphics.Color(20, 20, 20);

		private int _sectionsFilled;

		private Paint FillPaint;

		private Paint EmptyPaint;

		public int NumberOfSlots
		{
			get
			{
				return _numberOfSlots;
			}
			set
			{
				_numberOfSlots = value;
				Refresh();
			}
		}

		public int SlotPixelWidth
		{
			get
			{
				return _slotPixelWidth;
			}
			set
			{
				_slotPixelWidth = value;
				Refresh();
			}
		}

		public global::Android.Graphics.Color FillColor
		{
			get
			{
				return _fillColor;
			}
			set
			{
				_fillColor = value;
				Refresh();
			}
		}

		public global::Android.Graphics.Color EmptyColor
		{
			get
			{
				return _emptyColor;
			}
			set
			{
				_emptyColor = value;
				Refresh();
			}
		}

		public int SectionsFilled
		{
			get
			{
				return _sectionsFilled;
			}
			set
			{
				_sectionsFilled = ((value > numberOfSections) ? numberOfSections : value);
				Invalidate();
			}
		}

		private int numberOfSections => NumberOfSlots + 1;

		private float capRadius => (float)base.Height / 2f;

		private float slantOffset => capRadius / 2f;

		private float widthMinusSlots => base.Width - NumberOfSlots * SlotPixelWidth;

		private float sectionSize => widthMinusSlots / (float)numberOfSections;

		public SlottedProgressBar(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public SlottedProgressBar(Context context)
			: base(context)
		{
			Init();
		}

		public SlottedProgressBar(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init();
		}

		public SlottedProgressBar(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init();
		}

		public SlottedProgressBar(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Init();
		}

		private void Init()
		{
			SetBackgroundColor(global::Android.Graphics.Color.Transparent);
			SetWillNotDraw(willNotDraw: false);
			Refresh();
		}

		private void Refresh()
		{
			FillPaint = new Paint();
			FillPaint.Color = FillColor;
			FillPaint.AntiAlias = true;
			FillPaint.SetStyle(Paint.Style.Fill);
			EmptyPaint = new Paint();
			EmptyPaint.Color = EmptyColor;
			EmptyPaint.AntiAlias = true;
			EmptyPaint.SetStyle(Paint.Style.Fill);
			Invalidate();
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			if (base.Width != 0 && base.Height != 0)
			{
				float num = 0f;
				for (int i = 1; i <= numberOfSections; i++)
				{
					bool isLeftCap = i == 1;
					bool isRightCap = i == numberOfSections;
					Paint paint = ((i > SectionsFilled) ? EmptyPaint : FillPaint);
					float num2 = num + sectionSize;
					DrawSection(canvas, paint, num, num2, isLeftCap, isRightCap);
					num = num2 + (float)SlotPixelWidth;
				}
			}
		}

		private void DrawSection(Canvas canvas, Paint paint, float startX, float endX, bool isLeftCap, bool isRightCap)
		{
			if (isLeftCap)
			{
				DrawLeftCap(canvas, paint, startX, Midpoint(startX, endX));
			}
			else
			{
				DrawLeftAngle(canvas, paint, startX, Midpoint(startX, endX));
			}
			if (isRightCap)
			{
				DrawRightCap(canvas, paint, Midpoint(startX, endX), endX);
			}
			else
			{
				DrawRightAngle(canvas, paint, Midpoint(startX, endX), endX);
			}
		}

		private void DrawLeftCap(Canvas canvas, Paint paint, float left, float right)
		{
			left += capRadius;
			canvas.DrawCircle(left, capRadius, capRadius, paint);
			global::Android.Graphics.Path path = new global::Android.Graphics.Path();
			path.MoveTo(left, 0f);
			path.LineTo(left, base.Height);
			path.LineTo(right + 1f, base.Height);
			path.LineTo(right + 1f, 0f);
			path.MoveTo(left, 0f);
			canvas.DrawPath(path, paint);
		}

		private void DrawLeftAngle(Canvas canvas, Paint paint, float left, float right)
		{
			global::Android.Graphics.Path path = new global::Android.Graphics.Path();
			path.MoveTo(left + slantOffset, 0f);
			path.LineTo(left - slantOffset, base.Height);
			path.LineTo(right + 1f, base.Height);
			path.LineTo(right + 1f, 0f);
			path.MoveTo(left - slantOffset, 0f);
			canvas.DrawPath(path, paint);
		}

		private void DrawRightCap(Canvas canvas, Paint paint, float left, float right)
		{
			right -= capRadius;
			canvas.DrawCircle(right, capRadius, capRadius, paint);
			global::Android.Graphics.Path path = new global::Android.Graphics.Path();
			path.MoveTo(left, 0f);
			path.LineTo(left, base.Height);
			path.LineTo(right, base.Height);
			path.LineTo(right, 0f);
			path.MoveTo(left, 0f);
			canvas.DrawPath(path, paint);
		}

		private void DrawRightAngle(Canvas canvas, Paint paint, float left, float right)
		{
			global::Android.Graphics.Path path = new global::Android.Graphics.Path();
			path.MoveTo(left, 0f);
			path.LineTo(left, base.Height);
			path.LineTo(right - slantOffset, base.Height);
			path.LineTo(right + slantOffset, 0f);
			path.MoveTo(left, 0f);
			canvas.DrawPath(path, paint);
		}

		private float Midpoint(float a, float b)
		{
			return (a + b) / 2f;
		}

		protected override void OnDetachedFromWindow()
		{
			base.OnDetachedFromWindow();
			FillPaint?.Dispose();
			EmptyPaint?.Dispose();
		}
	}
	public class SourcedViewPager : ViewPager
	{
		private ViewPagerSource source;

		public bool SmoothTransitions { get; set; } = true;

		public bool SwipeLocked { get; set; }

		public SourcedViewPager(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public SourcedViewPager(Context context)
			: base(context)
		{
		}

		public SourcedViewPager(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
		}

		public void BindSource(ViewPagerSource source, AndroidX.Fragment.App.FragmentManager fm)
		{
			this.source = source;
			Adapter = CreateAdapter(source, base.Context, fm);
			base.PageSelected -= OnPageSelected;
			base.PageSelected += OnPageSelected;
			this.source.CurrentPage.Changed += SourcePageChanged;
		}

		private void OnPageSelected(object sender, PageSelectedEventArgs e)
		{
			source.CurrentPage.Value = e.Position;
		}

		private void SourcePageChanged(object sender, EventArgs e)
		{
			if (CurrentItem != source.CurrentPage.Value)
			{
				SetCurrentItem(source.CurrentPage.Value, SmoothTransitions);
			}
		}

		private static MvxViewPagerFragmentAdapter CreateAdapter(ViewPagerSource source, Context context, AndroidX.Fragment.App.FragmentManager fm)
		{
			List<MvxViewPagerFragmentAdapter.FragmentInfo> list = new List<MvxViewPagerFragmentAdapter.FragmentInfo>();
			if (Mvx.TryResolve<IViewTypeLookup>(out var service))
			{
				foreach (Type item in source)
				{
					Type fragmentType = service.GetFragmentType(item);
					if (fragmentType == null)
					{
						iFit.Logger.Log.Warn("MvxTrace", "SourcedViewPager: Could not find fragment type for VM: " + item.Name + "!!");
					}
					else
					{
						list.Add(new MvxViewPagerFragmentAdapter.FragmentInfo(fragmentType, item));
					}
				}
			}
			else
			{
				iFit.Logger.Log.Warn("MvxTrace", "SourcedViewPager: Could not resolve ViewTypeLookup!!");
			}
			return new MvxViewPagerFragmentAdapter(context, list, fm);
		}

		public override bool OnTouchEvent(MotionEvent? e)
		{
			if (!SwipeLocked)
			{
				return base.OnTouchEvent(e);
			}
			return false;
		}

		public override bool OnInterceptTouchEvent(MotionEvent? ev)
		{
			if (!SwipeLocked)
			{
				return base.OnInterceptTouchEvent(ev);
			}
			return false;
		}

		public override bool CanScrollHorizontally(int direction)
		{
			if (!SwipeLocked)
			{
				return base.CanScrollHorizontally(direction);
			}
			return false;
		}
	}
	public class StatInfoBox : RelativeLayout
	{
		private const int DefaultPrecision = 5;

		private IfitTextView valueTextView;

		private IfitTextView labelTextView;

		private ImageView imageView;

		private string formattedValue;

		private string formattedLabel;

		private double _value;

		private int _imageResId;

		private bool _isMetric;

		public StatInfoLabelType LabelType { get; private set; }

		public double Value
		{
			get
			{
				return _value;
			}
			set
			{
				if (!_value.AlmostEqual(value, 5))
				{
					_value = value;
					FormattedValue = LabelType.GetFormattedValue(value);
					if (LabelType == StatInfoLabelType.Pace)
					{
						HandleLabelUpdate();
					}
				}
			}
		}

		public string FormattedValue
		{
			get
			{
				return formattedValue;
			}
			private set
			{
				if (!value.Equals(formattedValue))
				{
					formattedValue = value;
					valueTextView.Text = formattedValue;
				}
			}
		}

		public string FormattedLabel
		{
			get
			{
				return formattedLabel;
			}
			set
			{
				if (!value.Equals(formattedLabel))
				{
					formattedLabel = value;
					labelTextView.Text = formattedLabel;
				}
			}
		}

		public int ImageResId
		{
			get
			{
				return _imageResId;
			}
			set
			{
				if (_imageResId != value)
				{
					_imageResId = value;
					imageView.SetImageResource(_imageResId);
				}
			}
		}

		public bool IsMetric
		{
			get
			{
				return _isMetric;
			}
			set
			{
				if (_isMetric != value)
				{
					_isMetric = value;
					HandleLabelUpdate();
				}
			}
		}

		private void HandleLabelUpdate()
		{
			if (LabelType != StatInfoLabelType.Calories && LabelType != StatInfoLabelType.HeartRate && LabelType != StatInfoLabelType.Incline && LabelType != StatInfoLabelType.Time && LabelType != StatInfoLabelType.Watts)
			{
				bool isSlowPace = false;
				if (LabelType == StatInfoLabelType.Pace)
				{
					isSlowPace = _value >= 3600.0;
				}
				FormattedLabel = LabelType.GetLabel(_isMetric, isSlowPace);
			}
		}

		public StatInfoBox(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public StatInfoBox(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public StatInfoBox(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			LayoutInflater.From(context).Inflate(2131624421, this, attachToRoot: true);
			valueTextView = FindViewById<IfitTextView>(2131429728);
			labelTextView = FindViewById<IfitTextView>(2131428467);
			imageView = FindViewById<ImageView>(2131428295);
			TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.StatInfoBox);
			try
			{
				LabelType = (StatInfoLabelType)typedArray.GetInt(2, 0);
				int resourceId = typedArray.GetResourceId(0, 2131428700);
				if (resourceId == 2131428700)
				{
					throw new ArgumentException("Please specify 'android:src' for StatInfoBox via xml layout!");
				}
				ImageResId = resourceId;
				int dimensionPixelSize = typedArray.GetDimensionPixelSize(1, 0);
				imageView.LayoutParameters.Height = dimensionPixelSize;
				imageView.ClearColorFilter();
				imageView.SetColorFilter(Colors.StatInfoBoxImageColor.ToNative());
				string blankValue = LabelType.GetBlankValue();
				FormattedValue = blankValue;
				FormattedLabel = LabelType.GetLabel();
			}
			finally
			{
				typedArray?.Recycle();
			}
		}

		public void HideLabel()
		{
			labelTextView.Visibility = ViewStates.Gone;
		}
	}
