			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Initialize(context, attrs);
		}

		private void Initialize(Context context, IAttributeSet attrs)
		{
			LayoutInflater.From(context).Inflate(2131624431, this, attachToRoot: true);
			imageView1 = FindViewById<BetterImageView>(2131428300);
			imageView0 = FindViewById<BetterImageView>(2131428299);
			if (context != null && attrs != null)
			{
				TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.SwappingImageView);
				global::Android.Graphics.Color color = typedArray.GetColor(1, global::Android.Graphics.Color.Transparent);
				global::Android.Graphics.Color color2 = typedArray.GetColor(0, global::Android.Graphics.Color.Transparent);
				imageView1.SetBackgroundColor(color);
				imageView0.SetBackgroundColor(color2);
				typedArray.Recycle();
			}
			currentImageView = imageView1;
			hiddenImageView = imageView0;
			imageFadeIn = new AlphaAnimation(0f, 1f)
			{
				Duration = FadeDurationMs,
				StartOffset = FadeOffsetMs
			};
			imageFadeOut = new AlphaAnimation(1f, 0f)
			{
				Duration = FadeDurationMs,
				StartOffset = FadeOffsetMs
			};
			scaleAnimation = new ScaleAnimation(1f, 1f, 1f, 1f, 640f, 360f);
			scaleAnimation.StartOffset = 0L;
			imageFadeOut.AnimationEnd += delegate
			{
				BetterImageView betterImageView = currentImageView;
				currentImageView = hiddenImageView;
				hiddenImageView = betterImageView;
				currentImageView.SetZ(0f);
				hiddenImageView.SetZ(-1f);
				hiddenImageView.ClearAnimation();
				hiddenImageView.Invalidate();
				currentImageView.Invalidate();
			};
			animations = new AnimationSet(shareInterpolator: true);
			if (AnimationEffects.HasFlag(SwapImageEffects.Scale))
			{
				animations.AddAnimation(scaleAnimation);
			}
			animations.AddAnimation(imageFadeOut);
		}

		public void SetScaleAnimation(float endX, float endY)
		{
			AnimationEffects |= SwapImageEffects.Scale;
			animations.Animations.Remove(scaleAnimation);
			scaleAnimation?.Dispose();
			scaleAnimation = new ScaleAnimation(1f, endX, 1f, endY, (float)base.Width / 2f, (float)base.Height / 2f);
			scaleAnimation.Duration = ScaleDurationMs;
			scaleAnimation.StartOffset = 0L;
			animations.AddAnimation(scaleAnimation);
		}

		public void ShowNewImage(byte[] imageData)
		{
			Post(delegate
			{
				try
				{
					LoadInitialImage(imageData);
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		public void ShowNewImage(int imageId)
		{
			Post(delegate
			{
				try
				{
					LoadInitialImage(imageId);
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		public void AnimateToNewImage(int imageId)
		{
			Post(delegate
			{
				try
				{
					if (!initialImageLoaded)
					{
						LoadInitialImage(imageId);
					}
					else
					{
						hiddenImageView.ResourceId = imageId;
						HandleAnimations();
					}
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		public void AnimateToNewImage(byte[] imageData)
		{
			Post(delegate
			{
				try
				{
					if (!initialImageLoaded)
					{
						LoadInitialImage(imageData);
					}
					else
					{
						hiddenImageView.SetBytesAndAnimate(imageData, HandleAnimations);
					}
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}

		public void FadeToNewImage(byte[] imageData)
		{
			if (imageData == null || imageData.Length == 0)
			{
				iFit.Logger.Log.Trace("Images", "Ignoring fade to new image on null / empty byte array");
				return;
			}
			Post(delegate
			{
				try
				{
					if (!initialImageLoaded || currentImageView.Drawable == null)
					{
						LoadInitialImage(imageData);
					}
					else
					{
						BitmapDrawable next = new BitmapDrawable(Resources, BitmapFactory.DecodeByteArray(imageData, 0, imageData.Length));
						HandleFadeSwapAnimation(next);
					}
				}
				catch (ObjectDisposedException)
				{
				}
				catch (System.Exception exception)
				{
					iFit.Logger.Log.Error("Images", "Exception in FadeToNewImage", exception);
				}
			});
		}

		private void LoadInitialImage(int imageId)
		{
			initialImageLoaded = true;
			currentImageView.ResourceId = imageId;
		}

		private void LoadInitialImage(byte[] imageData)
		{
			initialImageLoaded = true;
			currentImageView.ByteArray = imageData;
		}

		private void HandleAnimations()
		{
			try
			{
				if (AnimationEffects.HasFlag(SwapImageEffects.FadeIn))
				{
					hiddenImageView?.StartAnimation(imageFadeIn);
				}
				currentImageView?.StartAnimation(animations);
			}
			catch (ObjectDisposedException)
			{
			}
		}

		private void HandleFadeSwapAnimation(Drawable next)
		{
			TransitionDrawable transitionDrawable = new TransitionDrawable(new Drawable[2]
			{
				currentImageView.Drawable?.Current,
				next
			});
			transitionDrawable.CrossFadeEnabled = true;
			currentImageView.SetImageDrawable(transitionDrawable);
			transitionDrawable.StartTransition(FadeDurationMs);
		}
	}
	public class SwipeDetector : GestureDetector.SimpleOnGestureListener
	{
		private const float MovementDetectionTolerance = 5f;

		private readonly Subject<MotionEvent> _whenSwipeStarted = new Subject<MotionEvent>();

		private readonly Subject<SwipeEvent> _whenSwiping = new Subject<SwipeEvent>();

		private readonly Subject<SwipeEvent> _whenSwipeEnded = new Subject<SwipeEvent>();

		private MotionEvent startSwipeMotionEvent;

		private GestureDetector gestureDetector;

		public IObservable<MotionEvent> WhenSwipeStarted => _whenSwipeStarted;

		public IObservable<SwipeEvent> WhenSwiping => _whenSwiping;

		public IObservable<SwipeEvent> WhenSwipeEnded => _whenSwipeEnded;

		public bool IsSwiping { get; private set; }

		public SwipeDetector(Context context)
		{
			gestureDetector = new GestureDetector(context, this);
		}

		public void HandleTouchEvent(MotionEvent e)
		{
			bool flag = gestureDetector.OnTouchEvent(e);
			if (e.Action == MotionEventActions.Up && !flag && startSwipeMotionEvent != null)
			{
				OnFling(startSwipeMotionEvent, e, 0f, 0f);
			}
		}

		public override bool OnDown(MotionEvent e)
		{
			startSwipeMotionEvent = MotionEvent.Obtain(e);
			IsSwiping = true;
			_whenSwipeStarted.OnNext(e);
			return true;
		}

		public override bool OnScroll(MotionEvent e1, MotionEvent e2, float distanceX, float distanceY)
		{
			if (!IsSwiping)
			{
				return true;
			}
			var (distanceX2, distanceY2) = getDistance(e1, e2);
			_whenSwiping.OnNext(new SwipeEvent
			{
				Start = e1,
				End = e2,
				DistanceX = distanceX2,
				DistanceY = distanceY2
			});
			return true;
		}

		public override bool OnFling(MotionEvent e1, MotionEvent e2, float velocityX, float velocityY)
		{
			IsSwiping = false;
			(float, float) distance = getDistance(e1, e2);
			float item = distance.Item1;
			float item2 = distance.Item2;
			SwipeEvent value = new SwipeEvent
			{
				Start = e1,
				End = e2,
				DistanceX = item,
				DistanceY = item2
			};
			_whenSwipeEnded?.OnNext(value);
			startSwipeMotionEvent = null;
			return true;
		}

		private (float, float) getDistance(MotionEvent e1, MotionEvent e2)
		{
			float num = e1?.RawX ?? 0f;
			float num2 = e1?.RawY ?? 0f;
			float num3 = e2?.RawX ?? 0f;
			float num4 = e2?.RawY ?? 0f;
			return (num3 - num, num4 - num2);
		}
	}
	public class SwipeEvent
	{
		public enum SwipeEventDirection
		{
			Up,
			Down,
			Left,
			Right
		}

		public MotionEvent Start { get; set; }

		public MotionEvent End { get; set; }

		public float DistanceX { get; set; }

		public float DistanceY { get; set; }

		public SwipeEventDirection Direction => ComputeDirection();

		public bool IsVertical
		{
			get
			{
				if (Direction != SwipeEventDirection.Up)
				{
					return Direction == SwipeEventDirection.Down;
				}
				return true;
			}
		}

		private SwipeEventDirection ComputeDirection()
		{
			float num = System.Math.Abs(DistanceX.AlmostEqual(0f) ? 1000f : (DistanceY / DistanceX));
			float num2 = 1f;
			if (num >= num2)
			{
				if (!(DistanceY > 0f))
				{
					return SwipeEventDirection.Down;
				}
				return SwipeEventDirection.Up;
			}
			if (!(DistanceX > 0f))
			{
				return SwipeEventDirection.Right;
			}
			return SwipeEventDirection.Left;
		}
	}
	public class ThumbnailTextureVideoView : RelativeLayout, TextureView.ISurfaceTextureListener, IJavaObject, IDisposable, IJavaPeerable, MediaPlayer.IOnInfoListener, MediaPlayer.IOnErrorListener
	{
		private TextureView texture;

		private Surface textureSurface;

		private ImageView thumbnail;

		private global::Android.Net.Uri uri;

		private string url;

		private static readonly object playerLock = new object();

		public bool Looping { get; set; }

		public IfitMediaPlayer Player { get; set; }

		public ThumbnailTextureVideoView(Context context)
			: base(context)
		{
			Initialize(context);
		}

		public ThumbnailTextureVideoView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize(context);
		}

		public ThumbnailTextureVideoView(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize(context);
		}

		private void Initialize(Context context)
		{
			LayoutParams layoutParams = new LayoutParams(-1, -1);
			layoutParams.AddRule(LayoutRules.AlignParentTop);
			layoutParams.AddRule(LayoutRules.AlignParentRight);
			layoutParams.AddRule(LayoutRules.AlignParentBottom);
			layoutParams.AddRule(LayoutRules.AlignParentLeft);
			texture = new TextureView(context);
			texture.LayoutParameters = layoutParams;
			texture.SurfaceTextureListener = this;
			AddView(texture);
			thumbnail = new ImageView(context);
			thumbnail.LayoutParameters = layoutParams;
			thumbnail.SetScaleType(ImageView.ScaleType.FitXy);
			AddView(thumbnail);
		}

		public void SetUri(global::Android.Net.Uri uri)
		{
			using (MediaMetadataRetriever mediaMetadataRetriever = new MediaMetadataRetriever())
			{
				mediaMetadataRetriever.SetDataSource(base.Context, uri);
				using Bitmap imageBitmap = mediaMetadataRetriever.GetFrameAtTime(0L, Option.ClosestSync);
				thumbnail.SetImageBitmap(imageBitmap);
			}
			this.uri = uri;
		}

		public void SetUrl(string url, Activity activity)
		{
			this.url = url;
			System.Threading.Tasks.Task.Run(delegate
			{
				using MediaMetadataRetriever mediaMetadataRetriever = new MediaMetadataRetriever();
				mediaMetadataRetriever.SetDataSource(url, new Dictionary<string, string>());
				Bitmap thumb = mediaMetadataRetriever.GetFrameAtTime(0L, Option.ClosestSync);
				try
				{
					activity.RunOnUiThread(delegate
					{
						thumbnail.SetImageBitmap(thumb);
					});
				}
				catch (ObjectDisposedException)
				{
				}
				finally
				{
					if (thumb != null)
					{
						((IDisposable)thumb).Dispose();
					}
				}
			});
		}

		private void CreateAndPrepareMediaPlayer()
		{
			bool flag = false;
			lock (playerLock)
			{
				if (url == null && uri == null)
				{
					return;
				}
				if (Player == null)
				{
					Player = new IfitMediaPlayer();
					flag = true;
				}
			}
			Player.Looping = Looping;
			Player.SetOnInfoListener(this);
			Player.SetOnErrorListener(this);
			if (flag)
			{
				if (url != null)
				{
					Player.SetDataSource(url);
				}
				else
				{
					Player.SetDataSource(base.Context, uri);
				}
				Player.PrepareAsync();
			}
		}

		public void ReleasePlayer()
		{
			Player?.CleanAndReset();
			Player = null;
		}

		public void Start()
		{
			CreateAndPrepareMediaPlayer();
			Player.SafeStart();
		}

		public void StopWithoutDestroyPlayer()
		{
			PausePlayer();
			Player?.SeekTo(0);
		}

		public void PausePlayer()
		{
			Player?.SetSurface(null);
			Player?.SetOnInfoListener(null);
			Player?.SetOnErrorListener(null);
			Player?.Pause();
		}

		public void Stop()
		{
			if (Player != null)
			{
				thumbnail.Visibility = ViewStates.Visible;
				Player.Stop();
				ReleasePlayer();
			}
		}

		public void OnSurfaceTextureAvailable(SurfaceTexture surface, int width, int height)
		{
			textureSurface = new Surface(texture.SurfaceTexture);
			CreateAndPrepareMediaPlayer();
			Player?.SetSurface(textureSurface);
		}

		public bool OnSurfaceTextureDestroyed(SurfaceTexture surface)
		{
			return true;
		}

		public void OnSurfaceTextureSizeChanged(SurfaceTexture surface, int width, int height)
		{
		}

		public void OnSurfaceTextureUpdated(SurfaceTexture surface)
		{
		}

		public bool OnInfo(MediaPlayer mp, [GeneratedEnum] MediaInfo what, int extra)
		{
			if (what == MediaInfo.VideoRenderingStart)
			{
				thumbnail.Visibility = ViewStates.Invisible;
				return true;
			}
			return false;
		}

		public bool OnError(MediaPlayer mp, [GeneratedEnum] MediaError what, int extra)
		{
			Visibility = ViewStates.Invisible;
			return true;
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				textureSurface?.Release();
				textureSurface?.Dispose();
				ReleasePlayer();
				texture?.Dispose();
				thumbnail?.Dispose();
			}
			base.Dispose(disposing);
		}
	}
	public class TrapezoidalOverlayView : View
	{
		private static double ScalingFactor;

		private float scale;

		private int topOffset;

		private int bottomOffset;

		private float topRatio;

		private float bottomRatio;

		private global::Android.Graphics.Path path;

		private Paint paint;

		public TrapezoidalOverlayView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			scale = base.Context.Resources.DisplayMetrics.Density;
			TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.TrapezoidalOverlayView);
			global::Android.Graphics.Color color = typedArray.GetColor(2, base.Context.GetColorCompat(2131100092));
			topOffset = typedArray.GetInt(3, 30);
			bottomOffset = typedArray.GetInt(0, 60);
			topRatio = typedArray.GetFloat(4, -1f);
			bottomRatio = typedArray.GetFloat(1, -1f);
			Initialize(color);
		}

		private void Initialize(global::Android.Graphics.Color overlayColor)
		{
			SetWillNotDraw(willNotDraw: false);
			path = new global::Android.Graphics.Path();
			paint = new Paint(PaintFlags.AntiAlias);
			paint.SetStyle(Paint.Style.Fill);
			paint.Color = overlayColor;
		}

		protected override void OnDraw(Canvas canvas)
		{
			base.OnDraw(canvas);
			float num = canvas.Width;
			float y = canvas.Height;
			float x = DetermineTopPathStartX(num);
			float x2 = DetermineBottomPathStartX(num);
			float x3 = num;
			path.MoveTo(x, 0f);
			path.LineTo(x3, 0f);
			path.LineTo(x3, y);
			path.LineTo(x2, y);
			path.LineTo(x, 0f);
			path.Close();
			canvas.DrawPath(path, paint);
		}

		private float DetermineTopPathStartX(float canvasWidth)
		{
			if (topRatio > 0f)
			{
				return canvasWidth * topRatio;
			}
			return canvasWidth / 2f + scale * (float)topOffset;
		}

		private float DetermineBottomPathStartX(float canvasWidth)
		{
			if (bottomRatio > 0f)
			{
				return canvasWidth * bottomRatio;
			}
			return canvasWidth / 2f - scale * (float)bottomOffset;
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				path?.Dispose();
				paint?.Dispose();
			}
			base.Dispose(disposing);
		}
	}
