				{
					observableCollection.CollectionChanged -= Observable_CollectionChanged;
				}
				if (value is ObservableCollection<T> observableCollection2)
				{
					observableCollection2.CollectionChanged += Observable_CollectionChanged;
				}
				SetFlattenedList(value);
			}
		}

		public MvxListViewAdapter(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public MvxListViewAdapter(Context context, IMvxAndroidBindingContext bindingContext, int templateId = -2147483648)
			: base(context, bindingContext)
		{
			this.templateId = templateId;
		}

		protected abstract IMvxListItemView CreateViewBasedOnInfo(T dataContext, int templateId);

		protected virtual int GetTemplateIdForPosition(int position)
		{
			int num = templateId;
			if (num == -2147483648)
			{
				throw new MissingFieldException("Please pass in `templateId` or override `GetTemplateIdForPosition`!!");
			}
			return num;
		}

		protected virtual List<T> FlattenList(IEnumerable itemsSource)
		{
			return itemsSource?.Cast<T>().ToList();
		}

		private void Observable_CollectionChanged(object sender, NotifyCollectionChangedEventArgs e)
		{
			ObservableCollection<T> flattenedList = sender as ObservableCollection<T>;
			SetFlattenedList(flattenedList);
		}

		private void SetFlattenedList(IEnumerable value)
		{
			List<T> list = (List<T>)(base.ItemsSource = FlattenList(value));
			lookup = list;
		}

		public override View GetView(int position, View convertView, ViewGroup parent)
		{
			return GetView(position, convertView, parent, GetTemplateIdForPosition(position));
		}

		protected override IMvxListItemView CreateBindableView(object dataContext, int templateId)
		{
			if (!(dataContext is T dataContext2))
			{
				throw new ArgumentException($"Invalid dataContext type! Expected: {typeof(T)}, Actual: {dataContext?.GetType()}!");
			}
			return CreateViewBasedOnInfo(dataContext2, templateId);
		}
