namespace Wolf.Android.Controls.Maps.GoogleMapWebView
{
	public class GoogleMapsWebViewMap : MapBase
	{
		private class PointData
		{
			public iFit.Api.Google.LatLng Point { get; } = new iFit.Api.Google.LatLng();
		}

		private const string LogTag = "GoogleMapsWebViewMap";

		private readonly IGoogleMapsWebViewBridgeService bridgeService;

		private readonly Subject<object> _whenRouteTooLong = new Subject<object>();

		public IObservable<object> WhenRouteTooLong => _whenRouteTooLong;

		public GoogleMapsWebViewMap(IGoogleMapsWebViewBridgeService bridgeService)
		{
			this.bridgeService = bridgeService;
		}

		public override void Initialized()
		{
			ExposeMyMethods();
			ClearRouteNative();
			RoadSnapOn = true;
			UpdateIsEditable(base.MapIsEditable);
			UpdateRouteColor(base.RouteColor);
			UpdateRouteLineWidth(base.RouteLineWidth);
			UpdateMapCenter(base.MapCenter);
			UpdateZoomLevel(base.ZoomLevel);
			base.Initialized();
		}

		private void ExposeMyMethods()
		{
			bridgeService?.Expose("addRoutePoint", async delegate(PointData data)
			{
				await HandleAddRoutePoint(data);
			});
		}

		private async System.Threading.Tasks.Task HandleAddRoutePoint(PointData pointData)
		{
			if (pointData?.Point == null)
			{
				iFit.Logger.Log.Warn("GoogleMapsWebViewMap", "HandleAddRoutePoint received data object with Point = null");
				return;
			}
			try
			{
				await AddRoutePoint(pointData.Point);
			}
			catch (MaxWorkoutDistanceExceededException value)
			{
				_whenRouteTooLong.OnNext(value);
			}
		}

		public override void AddManyRoutePoints(List<iFit.Api.Google.LatLng> points)
		{
			UpdateWebViewRoutePoints();
		}

		public override void AddNoSnapRoutePoint(iFit.Api.Google.LatLng point)
		{
			UpdateWebViewRoutePoints();
		}

		protected override Shire.Core.Maps.IMarker AddMarkerNative(iFit.Api.Google.LatLng point, byte[] iconBytes, bool isVisible)
		{
			GoogleMapsWebViewMarker googleMapsWebViewMarker = new GoogleMapsWebViewMarker
			{
				Location = point,
				BridgeService = bridgeService
			};
			bridgeService?.AddMarker(googleMapsWebViewMarker.Id, googleMapsWebViewMarker.Location, iconBytes);
			return googleMapsWebViewMarker;
		}

		protected override void ClearRouteNative()
		{
			bridgeService?.ClearRoute();
		}

		protected override void SetRouteNative(IEnumerable<iFit.Api.Google.LatLng> route)
		{
			UpdateWebViewRoutePoints();
		}

		public override void SetZoomLevelFromRoute()
		{
			bridgeService?.SetZoomLevelFromRoute();
		}

		protected override void UpdateIsEditable(bool isEditable)
		{
			bridgeService?.SetIsEditable(isEditable);
		}

		protected override void UpdateMapCenter(iFit.Api.Google.LatLng mapCenter)
		{
			bridgeService?.SetMapCenter(mapCenter);
		}

		protected override void UpdateMapDisplayType(MapType mapType)
		{
			bridgeService?.SetMapType(mapType);
		}

		protected override void UpdateRouteColor(SplatColor routeColor)
		{
			bridgeService?.SetRouteColor(routeColor);
		}

		protected override void UpdateRouteLineWidth(float routeLineWidth)
		{
			bridgeService?.SetRouteLineWidth(routeLineWidth);
		}

		protected override void UpdateZoomLevel(float zoomLevel)
		{
			bridgeService?.SetZoomLevel(zoomLevel);
		}

		public override async System.Threading.Tasks.Task CloseRouteLoop()
		{
			await base.CloseRouteLoop();
			UpdateWebViewRoutePoints();
		}

		public override async System.Threading.Tasks.Task OutAndBack()
		{
			await base.OutAndBack();
			UpdateWebViewRoutePoints();
		}

		public override void RemoveLastRoutePoint()
		{
			base.RemoveLastRoutePoint();
			UpdateWebViewRoutePoints();
		}

		private void UpdateWebViewRoutePoints()
		{
			bridgeService?.SetRoute(base.RoutePoints?.AsEnumerable());
		}
	}
