	public class GoogleMapsWebViewContainer : BaseAndroidMapView, IMvxBindingContextOwner
	{
		private IMap map;

		private ShireWebView googleMapsWebView;

		private View whoopsView;

		private IfitTextView tryAgainBtn;

		private GoogleMapsWebViewViewModel viewModel;

		private IDisposable preloadSub;

		private IDisposable routeTooLongSub;

		public IMvxBindingContext BindingContext { get; set; }

		public GoogleMapsWebViewViewModel DataContext
		{
			get
			{
				return BindingContext.DataContext as GoogleMapsWebViewViewModel;
			}
			set
			{
				if (BindingContext.DataContext != value)
				{
					BindingContext.DataContext = value;
				}
			}
		}

		public override IMap Map => map;

		protected override int MapLayout => 2131624101;

		public GoogleMapsWebViewContainer(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public GoogleMapsWebViewContainer(Context context)
			: base(context)
		{
		}

		public GoogleMapsWebViewContainer(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
		}

		public GoogleMapsWebViewContainer(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
		}

		public GoogleMapsWebViewContainer(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
		}

		protected override void Init()
		{
			map = Mvx.IocConstruct<GoogleMapsWebViewMap>();
			viewModel = Mvx.IocConstruct<GoogleMapsWebViewViewModel>();
			routeTooLongSub = ((GoogleMapsWebViewMap)map).WhenRouteTooLong.Subscribe(MapRouteTooLongError);
			AddWebView();
			AddWhoopsView();
			BindingContext = new MvxAndroidBindingContext(base.Context, (IMvxLayoutInflaterHolder)base.Context);
			BindingContext.DelayBind(CreateBindings);
		}

		private void AddWebView()
		{
			googleMapsWebView = viewModel.GetWebview() as ShireWebView;
			if (googleMapsWebView != null)
			{
				ShireWebChromeClient shireWebChromeClient = (ShireWebChromeClient)googleMapsWebView.WebChromeClient;
				shireWebChromeClient.OpenNewWindowsModally = true;
				shireWebChromeClient.Activity = (Activity)base.Context;
				googleMapsWebView.SetBackgroundColor(global::Android.Graphics.Color.Transparent);
				googleMapsWebView.VerticalScrollBarEnabled = false;
				googleMapsWebView.HorizontalScrollBarEnabled = false;
				FrameLayout.LayoutParams layoutParams = new FrameLayout.LayoutParams(-1, -1);
				AddView(googleMapsWebView, layoutParams);
				preloadSub = viewModel.WhenWebViewPreLoadFinished.Subscribe(delegate
				{
					Map.Initialized();
				});
				googleMapsWebView.EnableChromeDebugging(viewModel.EnableChromeDebugging);
			}
		}

		private void AddWhoopsView()
		{
			whoopsView = LayoutInflater.From(base.Context).Inflate(2131624453, null);
			IfitTextView ifitTextView = whoopsView.FindViewById<IfitTextView>(2131429775);
			ifitTextView.Text = Wolf.Core.Resources.AppStrings.whoops_view_error;
			tryAgainBtn = whoopsView.FindViewById<IfitTextView>(2131429645);
			tryAgainBtn.Text = Wolf.Core.Resources.AppStrings.whoops_view_try_again;
			FrameLayout.LayoutParams layoutParams = new FrameLayout.LayoutParams(-1, -1);
			AddView(whoopsView, layoutParams);
		}

		private void CreateBindings()
		{
			MvxFluentBindingDescriptionSet<GoogleMapsWebViewContainer, GoogleMapsWebViewViewModel> mvxFluentBindingDescriptionSet = this.CreateBindingSet<GoogleMapsWebViewContainer, GoogleMapsWebViewViewModel>();
			mvxFluentBindingDescriptionSet.Bind(tryAgainBtn).For(tryAgainBtn.ClickEvent()).To((GoogleMapsWebViewViewModel vm) => vm.TryAgainClicked);
			mvxFluentBindingDescriptionSet.Bind(whoopsView).For("Visibility").To((GoogleMapsWebViewViewModel vm) => vm.WebviewLoadErrored)
				.WithConversion(new VisibilityGoneValueConverter());
			mvxFluentBindingDescriptionSet.Bind(googleMapsWebView).For("Visibility").To((GoogleMapsWebViewViewModel vm) => vm.WebviewLoadErrored)
				.WithConversion(new VisibilityGoneValueConverter(isReversed: true));
			mvxFluentBindingDescriptionSet.Apply();
		}

		public override void OnDestroy()
		{
			base.OnDestroy();
			RemoveView(googleMapsWebView);
			googleMapsWebView = null;
			routeTooLongSub?.Dispose();
			routeTooLongSub = null;
			preloadSub?.Dispose();
			preloadSub = null;
			viewModel?.Dispose();
			viewModel = null;
		}

		public override void OnCreate(Bundle bundle)
		{
		}

		public override void OnLowMemory()
		{
			googleMapsWebView.ClearCache(includeDiskFiles: false);
		}

		public override void OnTrimMemory(TrimMemory level)
		{
			if (TrimMemory.RunningModerate == level || TrimMemory.RunningLow == level || TrimMemory.RunningCritical == level)
			{
				googleMapsWebView.ClearCache(includeDiskFiles: false);
			}
		}

		public override void OnPause()
		{
		}

		public override void OnResume()
		{
		}

		public override void OnSaveInstanceState(Bundle outState)
		{
		}

		private void MapRouteTooLongError(object arg)
		{
			View view = FindViewById<View>(2131429494);
			if (view != null)
			{
				view.Alpha = 0f;
			}
			Activity activity = base.Context as Activity;
			activity.RunOnUiThread(delegate
			{
				Toast.MakeText(activity, Wolf.Core.Resources.AppStrings.draw_map_max_workout_length_error, ToastLength.Long).Show();
			});
		}
	}
}
namespace Wolf.Android.Controls.InWorkout
{
	public class DebugTachometer : LinearLayout
	{
		private const int MinRpm = 0;

		private const int MaxRpm = 200;

		private const double MinutesPerHour = 60.0;

		private readonly Random random = new Random();

		private readonly Average AvgWatts = new Average();

		private ToggleButton toggleBtn;

		private Button increaseBtn;

		private Button decreaseBtn;

		private TextView rpmText;

		private IRpmFacade rpmFacade;

		private IConsoleBasicInfo latestBasicInfo;

		private int currentTargetRpm;

		private bool tachOn;

		private IDisposable secondTick;

		protected DebugTachometer(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public DebugTachometer(Context context)
			: base(context)
		{
			Init(context);
		}

		public DebugTachometer(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context);
		}

		public DebugTachometer(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context);
		}

		public DebugTachometer(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Init(context);
		}

		private void Init(Context context)
		{
			LayoutInflater.From(context).Inflate(2131624031, this, attachToRoot: true);
			toggleBtn = FindViewById<ToggleButton>(2131427833);
			increaseBtn = FindViewById<Button>(2131427831);
			decreaseBtn = FindViewById<Button>(2131427830);
			rpmText = FindViewById<TextView>(2131427832);
			rpmFacade = Mvx.Resolve<IRpmFacade>();
			if (Mvx.TryResolve<ICurrentConsoleService>(out var service))
			{
				latestBasicInfo = service.Console?.LatestBasicInfo;
				toggleBtn.Click += DoToggleTach;
				increaseBtn.Click += DoIncreaseRpm;
				decreaseBtn.Click += DoDecreaseRpm;
				rpmText.Text = $"{currentTargetRpm}";
			}
		}

		private void DoToggleTach(object sender, EventArgs eventArgs)
		{
			tachOn = !tachOn;
			if (!tachOn)
			{
				currentTargetRpm = 0;
			}
			latestBasicInfo?.SetValue(FitnessValue.Rpm, currentTargetRpm);
			increaseBtn.Enabled = tachOn;
			decreaseBtn.Enabled = tachOn;
			rpmText.Enabled = tachOn;
			if (tachOn)
			{
				StartTick();
			}
			else
			{
				StopTick();
			}
		}

		private void StartTick()
		{
			if (secondTick == null)
			{
				secondTick = Observable.Interval(TimeSpan.FromSeconds(1.0)).Subscribe(delegate
				{
					WorkoutTick();
				});
			}
		}

		private void StopTick()
		{
			secondTick?.Dispose();
			secondTick = null;
			if (rpmFacade.GetMostRecentRpm() != 0)
			{
				rpmFacade.SetRpm(0);
			}
		}

		private void WorkoutTick()
		{
			ConsoleState currentState = latestBasicInfo.CurrentState;
			if (currentState == ConsoleState.Workout || (uint)(currentState - 6) <= 1u)
			{
				UpdateRpm();
			}
		}

		private void DoIncreaseRpm(object sender, EventArgs eventArgs)
		{
			currentTargetRpm = System.Math.Clamp(currentTargetRpm + 5, 0, 200);
			latestBasicInfo?.SetValue(FitnessValue.Rpm, currentTargetRpm);
			rpmText.Text = $"{currentTargetRpm}";
		}

		private void DoDecreaseRpm(object sender, EventArgs eventArgs)
		{
			currentTargetRpm = System.Math.Clamp(currentTargetRpm - 5, 0, 200);
			latestBasicInfo?.SetValue(FitnessValue.Rpm, currentTargetRpm);
			rpmText.Text = $"{currentTargetRpm}";
		}

		private void UpdateRpm()
		{
			int num = System.Math.Clamp(currentTargetRpm + random.Next(-2, 2), 0, 200);
			if (rpmFacade.GetMostRecentRpm() != num)
			{
				rpmFacade.SetRpm(num);
			}
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			if (disposing)
			{
				StopTick();
			}
		}
	}
