		}

		private bool isDisposed;

		private bool isInitialized;

		private readonly Subject<object> _whenTouched = new Subject<object>();

		private readonly Subject<object> _whenReleased = new Subject<object>();

		private InWorkoutConstantWattsButtonType _buttonType;

		private bool enabled = true;

		private bool _isHolding;

		private int _backgroundResource;

		public IObservable<object> WhenTouched => _whenTouched;

		public IObservable<object> WhenReleased => _whenReleased;

		public InWorkoutConstantWattsButtonType ButtonType
		{
			get
			{
				return _buttonType;
			}
			set
			{
				_buttonType = value;
			}
		}

		public override bool Enabled
		{
			get
			{
				return enabled;
			}
			set
			{
				if (!isDisposed)
				{
					enabled = value;
					if (!enabled)
					{
						IsHolding = false;
					}
					Invalidate();
				}
			}
		}

		public bool IsHolding
		{
			get
			{
				return _isHolding;
			}
			private set
			{
				if (!isDisposed)
				{
					_isHolding = value;
					Invalidate();
				}
			}
		}

		public int BackgroundResource
		{
			get
			{
				return _backgroundResource;
			}
			set
			{
				_backgroundResource = value;
				SetBackgroundResource(_backgroundResource);
			}
		}

		public InWorkoutConstantWattsButton(Context context)
			: base(context)
		{
			Init(context, null);
		}

		public InWorkoutConstantWattsButton(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public InWorkoutConstantWattsButton(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context, attrs);
		}

		public InWorkoutConstantWattsButton(Context context, IAttributeSet attrs, int defStyleAttr, int defStyleRes)
			: base(context, attrs, defStyleAttr, defStyleRes)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attributeSet)
		{
			if (!isInitialized)
			{
				TypedArray typedArray = context.ObtainStyledAttributes(attributeSet, Resource.Styleable.InWorkoutConstantWattsButton);
				try
				{
					BackgroundResource = typedArray.GetResourceId(0, 2131231030);
				}
				finally
				{
					typedArray.Recycle();
				}
				base.Touch -= Button_Touch;
				base.Touch += Button_Touch;
				isInitialized = true;
			}
		}

		private void Button_Touch(object sender, TouchEventArgs e)
		{
			if (isDisposed)
			{
				return;
			}
			if (!enabled)
			{
				SetHoldState(isHolding: false);
				return;
			}
			switch (e.Event.Action)
			{
			case MotionEventActions.Down:
				SetHoldState(isHolding: true);
				_whenTouched.OnNext(null);
				break;
			case MotionEventActions.Up:
			case MotionEventActions.Outside:
				SetHoldState(isHolding: false);
				_whenReleased.OnNext(null);
				break;
			case MotionEventActions.Move:
			case MotionEventActions.Cancel:
				break;
			}
		}

		public void SetHoldState(bool isHolding)
		{
			if (!isDisposed)
			{
				Pressed = isHolding && Enabled;
				IsHolding = isHolding;
				Invalidate();
			}
		}

		public void SetBackgroundById(int iconId)
		{
			if (!isDisposed)
			{
				SetBackgroundResource(iconId);
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				base.Touch -= Button_Touch;
				base.Dispose(disposing);
			}
		}
