	public class VolumeSeekBar : LinearLayout
	{
		private IfitTextView label;

		private Drawable onThumb;

		private Drawable offThumb;

		private Drawable disabledThumb;

		private Drawable mutedThumb;

		private Drawable onProgress;

		private Drawable offProgress;

		private SeekBar seekBar;

		public SeekBar SeekBar
		{
			get
			{
				return seekBar;
			}
			private set
			{
				seekBar = value;
			}
		}

		private Drawable OffThumb
		{
			get
			{
				if (SeekBar.Progress != 0 || mutedThumb == null || !AllowMuteBehavior)
				{
					return offThumb;
				}
				return mutedThumb;
			}
		}

		public string Text
		{
			get
			{
				return label.Text;
			}
			set
			{
				if (string.IsNullOrWhiteSpace(value))
				{
					label.Visibility = ViewStates.Gone;
					return;
				}
				label.Visibility = ViewStates.Visible;
				label.Text = value;
			}
		}

		public override bool Enabled
		{
			get
			{
				return base.Enabled;
			}
			set
			{
				base.Enabled = value;
				if (!AllowMuteBehavior || SeekBar.Progress > 0)
				{
					seekBar.Enabled = value;
				}
				if (AllowMuteBehavior && SeekBar.Progress <= 0)
				{
					SeekBar.SetThumb(OffThumb);
				}
				else
				{
					SeekBar.SetThumb(value ? OffThumb : disabledThumb);
				}
				label.Alpha = (value ? 1f : 0.25f);
			}
		}

		public bool AllowMuteBehavior { get; set; }

		public VolumeSeekBar(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public VolumeSeekBar(Context context)
			: base(context)
		{
			Init(context, null);
		}

		public VolumeSeekBar(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Init(context, attrs);
		}

		public VolumeSeekBar(Context context, IAttributeSet attrs, int defStyleAttr)
			: base(context, attrs, defStyleAttr)
		{
			Init(context, attrs);
		}

		private void Init(Context context, IAttributeSet attrs)
		{
			LayoutInflater.From(context).Inflate(2131624450, this, attachToRoot: true);
			SeekBar = FindViewById<SeekBar>(2131428902);
			label = FindViewById<IfitTextView>(2131429755);
			if (attrs != null)
			{
				TypedArray typedArray = context.ObtainStyledAttributes(attrs, Resource.Styleable.VolumeSeekBar);
				try
				{
					if (offThumb == null)
					{
						offThumb = typedArray.GetDrawable(1);
					}
					if (onThumb == null)
					{
						onThumb = typedArray.GetDrawable(4);
					}
					if (disabledThumb == null)
					{
						disabledThumb = typedArray.GetDrawable(2);
					}
					if (mutedThumb == null)
					{
						mutedThumb = typedArray.GetDrawable(3);
					}
				}
				finally
				{
					typedArray?.Recycle();
				}
			}
			offProgress = ContextCompat.GetDrawable(base.Context, 2131231958);
			onProgress = ContextCompat.GetDrawable(base.Context, 2131231959);
			SeekBar.SetThumb(OffThumb);
			SeekBar.ProgressDrawable = offProgress;
		}

		public void SetVolumeSeekBarType(VolumeType volumeSeekBarType, bool isStrengthMirror, bool useHeadlessBikeTheme)
		{
			int id;
			int id2;
			switch (volumeSeekBarType)
			{
			case VolumeType.Music:
				id = (isStrengthMirror ? 2131231608 : 2131231598);
				id2 = (isStrengthMirror ? 2131231606 : (useHeadlessBikeTheme ? 2131231604 : 2131231603));
				break;
			case VolumeType.Trainer:
				id = (isStrengthMirror ? 2131231646 : 2131231640);
				id2 = (isStrengthMirror ? 2131231644 : (useHeadlessBikeTheme ? 2131231642 : 2131231641));
				break;
			default:
				id = (isStrengthMirror ? 2131231582 : 2131231576);
				id2 = (isStrengthMirror ? 2131231580 : (useHeadlessBikeTheme ? 2131231578 : 2131231577));
				break;
			}
			offThumb = ContextCompat.GetDrawable(base.Context, id);
			onThumb = ContextCompat.GetDrawable(base.Context, id2);
			SeekBar.SetThumb(OffThumb);
			SeekBar.ProgressDrawable = offProgress;
			SeekBar.Invalidate();
		}

		protected override void OnAttachedToWindow()
		{
			base.OnAttachedToWindow();
			if (SeekBar != null)
			{
				SeekBar.StopTrackingTouch -= SeekBar_StopTrackingTouch;
				SeekBar.StopTrackingTouch += SeekBar_StopTrackingTouch;
				SeekBar.StartTrackingTouch -= SeekBar_StartTrackingTouch;
				SeekBar.StartTrackingTouch += SeekBar_StartTrackingTouch;
			}
		}

		private void SeekBar_StartTrackingTouch(object sender, SeekBar.StartTrackingTouchEventArgs e)
		{
			SeekBar.SetThumb(onThumb);
			Rect bounds = SeekBar.ProgressDrawable.Bounds;
			SeekBar.ProgressDrawable = onProgress;
			SeekBar.ProgressDrawable.Bounds = bounds;
		}

		private void SeekBar_StopTrackingTouch(object sender, SeekBar.StopTrackingTouchEventArgs e)
		{
			SeekBar.SetThumb(OffThumb);
			Rect bounds = SeekBar.ProgressDrawable.Bounds;
			SeekBar.ProgressDrawable = offProgress;
			SeekBar.ProgressDrawable.Bounds = bounds;
		}

		protected override void OnDetachedFromWindow()
		{
			base.OnDetachedFromWindow();
			if (SeekBar != null)
			{
				SeekBar.StopTrackingTouch -= SeekBar_StopTrackingTouch;
				SeekBar.StartTrackingTouch -= SeekBar_StartTrackingTouch;
			}
		}
	}
