namespace Wolf.Android.Controls.InWorkout.Slider
{
	public class WorkoutSliderView : ConstraintLayout, View.IOnLayoutChangeListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private IDisposable markTappedSub;

		private SliderMarks sliderMarks;

		private SliderThumb sliderThumb;

		private Guideline sliderThumbBottomGuideline;

		private float bottomPercentage = 0f / 0f;

		private float differencePercentage = 0f / 0f;

		private double lastProspectiveValue = 0.0 / 0.0;

		private bool isDisposing;

		private readonly Subject<object> _whenSliderTouched = new Subject<object>();

		private IWorkoutSlider sliderModel;

		public IObservable<object> WhenSliderTouched => _whenSliderTouched;

		public double CurrentValue { get; private set; }

		public IWorkoutSlider SliderModel
		{
			get
			{
				return sliderModel;
			}
			set
			{
				sliderModel = value;
				sliderModel.NumberOfMarks = Resources.GetInteger(2131492947);
				if (sliderModel != null)
				{
					sliderMarks.CreateMarks(sliderModel);
					HandleModelValueChange(sliderModel.MetricValue);
					UpdateThumbSub = sliderModel.WhenMetricValueChanged.Subscribe(delegate(double newValue)
					{
						HandleModelValueChange(newValue);
					});
				}
			}
		}

		private IDisposable UpdateThumbSub { get; set; }

		public event EventHandler SliderActivity;

		public event EventHandler CurrentValueChanged;

		public WorkoutSliderView(Context context)
			: base(context)
		{
			Initialize(context);
		}

		public WorkoutSliderView(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
			Initialize(context);
		}

		public WorkoutSliderView(Context context, IAttributeSet attrs, int defStyle)
			: base(context, attrs, defStyle)
		{
			Initialize(context);
		}

		private void Initialize(Context context)
		{
			Drawable drawable = null;
			TypedArray typedArray = context?.ObtainStyledAttributes(Resource.Styleable.Sliders);
			if (typedArray != null)
			{
				drawable = typedArray.GetDrawable(2);
				typedArray.Recycle();
			}
			else
			{
				drawable = context?.GetDrawable(2131231727);
			}
			LayoutInflater.From(base.Context).Inflate(2131624457, this, attachToRoot: true);
			sliderMarks = FindViewById<SliderMarks>(2131429273);
			markTappedSub = sliderMarks.WhenMarkTapped.Subscribe(MarkTapped);
			sliderThumb = FindViewById<SliderThumb>(2131429274);
			sliderThumb.Background = drawable;
			sliderThumb.Scroll = Scroll;
			sliderThumb.UpTapped += ThumbTappedUp;
			sliderThumb.DownTapped += ThumbTappedDown;
			sliderThumbBottomGuideline = FindViewById<Guideline>(2131429275);
			AddOnLayoutChangeListener(this);
		}

		protected override void Dispose(bool disposing)
		{
			isDisposing = true;
			if (disposing)
			{
				RemoveOnLayoutChangeListener(this);
				UpdateThumbSub?.Dispose();
				sliderMarks?.Dispose();
				sliderMarks = null;
				markTappedSub?.Dispose();
				markTappedSub = null;
			}
			base.Dispose(disposing);
		}

		private void ThumbTappedUp(object sender, EventArgs e)
		{
			if (Enabled)
			{
				SliderModel.StepUp();
				this.SliderActivity?.Invoke(this, EventArgs.Empty);
				_whenSliderTouched.OnNext(null);
			}
		}

		private void ThumbTappedDown(object sender, EventArgs e)
		{
			if (Enabled)
			{
				SliderModel.StepDown();
				this.SliderActivity?.Invoke(this, EventArgs.Empty);
				_whenSliderTouched.OnNext(null);
			}
		}

		private void MarkTapped(int index)
		{
			if (Enabled)
			{
				CurrentValue = sliderModel.MarkValues[index];
				this.CurrentValueChanged?.Invoke(this, EventArgs.Empty);
				UpdateSliderThumb(CurrentValue);
				this.SliderActivity?.Invoke(this, EventArgs.Empty);
				_whenSliderTouched.OnNext(null);
			}
		}

		private void Scroll(float yDifference, bool released)
		{
			if (Enabled)
			{
				double num = SliderModel.ValueRange * (double)(yDifference / (float)sliderMarks.Height);
				double num2 = CurrentValue + num;
				UpdateSliderThumb(num2);
				this.SliderActivity?.Invoke(this, EventArgs.Empty);
				_whenSliderTouched.OnNext(null);
				if (released)
				{
					num2 = sliderModel.ClampAndRound(num2);
					CurrentValue = num2;
					this.CurrentValueChanged?.Invoke(this, EventArgs.Empty);
				}
			}
		}

		public void HandleModelValueChange(double value)
		{
			CurrentValue = value;
			using Handler handler = new Handler(Looper.MainLooper);
			handler.Post(delegate
			{
				UpdateSliderThumb(value);
			});
		}

		private void UpdateSliderThumb(double prospectiveValue)
		{
			if (!isDisposing && SliderModel?.MetricLabel != null && !prospectiveValue.AlmostEqual(lastProspectiveValue, 0.05))
			{
				lastProspectiveValue = prospectiveValue;
				LayoutParams layoutParams = (LayoutParams)sliderThumbBottomGuideline.LayoutParameters;
				double num = (prospectiveValue - sliderModel.Minimum) / SliderModel.ValueRange;
				float num2 = 1f - System.Math.Max((float)((double)bottomPercentage + (double)differencePercentage * num), 0f);
				float num3 = (float)sliderThumb.Height / ((float)base.Height * 1f);
				if (num2 < num3)
				{
					num2 = num3;
				}
				if (double.IsNaN(num2))
				{
					num2 = (float)(1.0 - num);
				}
				layoutParams.GuidePercent = num2;
				sliderThumbBottomGuideline.LayoutParameters = layoutParams;
				double num4 = sliderModel.ClampAndRound(prospectiveValue);
				sliderThumb.Value = num4.ToString(SliderModel.DisplayPrecision);
				sliderThumb.MetricText = SliderModel.MetricLabel;
				if (!IsLayoutRequested)
				{
					RequestLayout();
				}
			}
		}

		public void OnLayoutChange(View v, int left, int top, int right, int bottom, int oldLeft, int oldTop, int oldRight, int oldBottom)
		{
			if (float.IsNaN(bottomPercentage))
			{
				float num = (float)sliderThumb.Height / 2f;
				float num2 = 1f - (sliderMarks.GetY() + num) / (float)base.Height;
				bottomPercentage = 1f - (sliderMarks.GetY() + (float)sliderMarks.Height + num) / (float)base.Height;
				differencePercentage = num2 - bottomPercentage;
			}
		}
	}
}
