			defaultColor = base.Context.GetColorCompat(2131099830);
		}

		private void SetZoneActive(GradientDrawable zoneBackground, bool active, global::Android.Graphics.Color activeColor)
		{
			if (zoneBackground != null)
			{
				if (active)
				{
					zoneBackground.SetColor(activeColor);
				}
				else
				{
					zoneBackground.SetColor(defaultColor);
				}
			}
		}

		private void UpdateActiveZone()
		{
			SetZoneActive(zoneOneLayout.Background as GradientDrawable, CurrentZone == 1, GetZoneColor(1));
			SetZoneActive(zoneTwoLayout.Background as GradientDrawable, CurrentZone == 2, GetZoneColor(2));
			SetZoneActive(zoneThreeLayout.Background as GradientDrawable, CurrentZone == 3, GetZoneColor(3));
			SetZoneActive(zoneFourLayout.Background as GradientDrawable, CurrentZone == 4, GetZoneColor(4));
			SetZoneActive(zoneFiveLayout.Background as GradientDrawable, CurrentZone == 5, GetZoneColor(5));
			Invalidate();
		}

		private global::Android.Graphics.Color GetZoneColor(int zone)
		{
			return zone switch
			{
				1 => base.Context.GetColorCompat(2131100476), 
				2 => base.Context.GetColorCompat(2131100477), 
				3 => base.Context.GetColorCompat(2131100478), 
				4 => base.Context.GetColorCompat(2131100479), 
				5 => base.Context.GetColorCompat(2131100480), 
				_ => defaultColor, 
			};
		}
	}
	public class HRZoneLineChart : BaseLineChart
	{
		private readonly IHRTrainingService hrTrainingService;

		private int circleColor;

		public HRZoneLineChart(Context context, IHRTrainingService hrTrainingService)
			: base(context)
		{
			this.hrTrainingService = hrTrainingService;
		}

		public void StyleBaseLine(LineDataSet set)
		{
			set.SetColor(global::Android.Graphics.Color.White, global::Android.Graphics.Color.White.A);
			set.SetMode(LineDataSet.Mode.Linear);
			set.SetDrawValues(enabled: false);
			set.SetDrawFilled(filled: false);
			set.SetDrawCircles(enabled: false);
			set.LineWidth = 2f;
		}

		public void StyleHistoricalHRMetric(LineDataSet set)
		{
			set.SetMode(LineDataSet.Mode.Linear);
			set.SetDrawValues(enabled: false);
			set.SetDrawFilled(filled: false);
			set.SetDrawCircles(enabled: false);
			set.LineWidth = 2f;
		}

		public void SetHistoricalHRMetricColors(LineDataSet set)
		{
			if (set != null && set.EntryCount > 1)
			{
				int entryCount = set.EntryCount;
				List<int> list = new List<int>(entryCount);
				for (int i = 1; i < entryCount; i++)
				{
					Entry entry = set.GetEntryForIndex(i) as Entry;
					float y = entry.GetY();
					list.Add(BpmToColor(y));
				}
				int[] colors = list.ToArray();
				set.SetColors(colors);
			}
		}

		public void UpdateCurrentCircle(LineDataSet set)
		{
			if (set.EntryCount != 0)
			{
				float y = (set.GetEntryForIndex(0) as Entry).GetY();
				int num = BpmToColor(y);
				if (num != circleColor)
				{
					circleColor = num;
					set.ResetCircleColors();
					set.CircleRadius = 5f;
					set.SetDrawValues(enabled: false);
					set.SetCircleColor(circleColor);
					set.SetCircleColorHole(circleColor);
					base.LineChart.Renderer = new LineChartRenderer(base.LineChart, base.LineChart.Animator, base.LineChart.ViewPortHandler);
				}
			}
		}

		private int BpmToColor(float currBpm)
		{
			double num = hrTrainingService.BpmToInterpolatedZone(currBpm);
			if (num < 0.5)
			{
				return global::Android.Graphics.Color.White;
			}
			if (num < 1.5)
			{
				return AndroidX.Core.Graphics.ColorUtils.BlendARGB(global::Android.Graphics.Color.White, Colors.HRZone1WidgetBackground.ToNative(), (float)(num - 0.5));
			}
			if (num < 2.5)
			{
				return AndroidX.Core.Graphics.ColorUtils.BlendARGB(Colors.HRZone1WidgetBackground.ToNative(), Colors.HRZone2WidgetBackground.ToNative(), (float)(num - 1.5));
			}
			if (num < 3.5)
			{
				return AndroidX.Core.Graphics.ColorUtils.BlendARGB(Colors.HRZone2WidgetBackground.ToNative(), Colors.HRZone3WidgetBackground.ToNative(), (float)(num - 2.5));
			}
			if (num < 4.5)
			{
				return AndroidX.Core.Graphics.ColorUtils.BlendARGB(Colors.HRZone3WidgetBackground.ToNative(), Colors.HRZone4WidgetBackground.ToNative(), (float)(num - 3.5));
			}
			if (num < 5.5)
			{
				return AndroidX.Core.Graphics.ColorUtils.BlendARGB(Colors.HRZone4WidgetBackground.ToNative(), Colors.HRZone5WidgetBackground.ToNative(), (float)(num - 4.5));
			}
			return Colors.HRZone5WidgetBackground.ToNative();
		}

		public void StylePredictedMetric(LineDataSet set)
		{
			global::Android.Graphics.Color color = Colors.HRPredictedLine.ToNative();
			set.SetColor(color, color.A);
			set.SetMode(LineDataSet.Mode.HorizontalBezier);
			set.SetDrawValues(enabled: false);
			set.SetDrawFilled(filled: false);
			set.SetDrawCircles(enabled: false);
			set.LineWidth = 2f;
		}
	}
}
namespace Wolf.Android.Controls.DrawMap
{
	public class DrawMapBindingSetWrapper
	{
		private MvxFluentBindingDescriptionSet<DrawMapView, DrawMapViewModel> bindingSet;

		private bool hasApplyBeenCalled;

		private string applyHasBeenCalledBy;

		public DrawMapBindingSetWrapper(MvxFluentBindingDescriptionSet<DrawMapView, DrawMapViewModel> bindingSet)
		{
			this.bindingSet = bindingSet;
		}

		public MvxFluentBindingDescription<TChildTarget, DrawMapViewModel> Bind<TChildTarget>(TChildTarget target) where TChildTarget : class
		{
			return bindingSet.Bind(target);
		}

		public void Apply([CallerMemberName] string member = "")
		{
			if (hasApplyBeenCalled)
			{
				throw new System.Exception("You are calling Apply from more than one place. This creates multiple bindings and is bad! Called by " + applyHasBeenCalledBy);
			}
			applyHasBeenCalledBy = member;
			bindingSet.Apply();
			hasApplyBeenCalled = true;
		}
	}
