namespace Wolf.Android.BrainBoard
{
	public class WolfUsbDevice : BaseAndroidUsbDevice
	{
		public static readonly IReadOnlyList<int> FitProProductIds = new List<int> { 2, 3 };

		public const int FitProVendorId = 8508;

		private const string DisconnectTag = "Built-In Hardware Disconnected";

		private readonly ReportHelper reporter;

		protected override IReadOnlyList<int> ValidProductIds => FitProProductIds;

		protected override int VendorId { get; } = 8508;

		public WolfUsbDevice(IUsbPermissionService usbPermissionService, IFatalityService fatalityService)
			: base(usbPermissionService, fatalityService)
		{
			reporter = new ReportHelper("Built-In Hardware Disconnected", TimeSpan.FromMinutes(5.0));
			base.WhenConnectionStateChanged.Where((bool connected) => !connected).SubscribeAsync((bool _) => ReportDeviceDisconnect());
		}

		private async System.Threading.Tasks.Task ReportDeviceDisconnect()
		{
			await reporter.Track(new Dictionary<string, object>
			{
				["machinePartNumber"] = reporter.DeviceInformation?.SoftwareNumber,
				["isBuiltIn"] = reporter.DeviceInformation?.IsBuiltIn,
				["version"] = reporter.LocalSettings?.CurrentVersion
			});
		}

		protected override void PermissionGranted()
		{
			Context context = Application.Context;
			Intent intent = new Intent(context, typeof(SplashScreen));
			intent.AddCategory("android.intent.category.DEFAULT");
			intent.AddFlags(ActivityFlags.NewTask);
			context.StartActivity(intent);
		}
	}
}
namespace Wolf.Android.Ble.Headphone
{
	public class WolfHeadphoneConnectionHelper : HeadphoneConnectionHelper
	{
		private readonly IIdleLogoutService idleLogoutService;

		public WolfHeadphoneConnectionHelper(Context context, IHeadphoneScanner scanner, IBleRadioStatusService bleRadioStatusService, HeadphoneDeviceFilterBase filter, ICoreAnalytics coreAnalytics, IPersistentBluetoothDevices persistentBluetoothDevices, IIdleLogoutService idleLogoutService = null)
			: base(context, scanner, bleRadioStatusService, filter, coreAnalytics, persistentBluetoothDevices)
		{
			this.idleLogoutService = idleLogoutService;
		}

		public override void BeginScan(int? timeoutSeconds = null)
		{
			idleLogoutService?.SetActive(active: false);
			base.BeginScan(timeoutSeconds);
		}

		public override void EndScan()
		{
			base.EndScan();
			idleLogoutService?.SetActive(active: true);
		}

		public override async System.Threading.Tasks.Task BondWithDevice(IHeadphone headphone)
		{
			idleLogoutService?.SetActive(active: false);
			await base.BondWithDevice(headphone).ConfigureAwait(continueOnCapturedContext: false);
			idleLogoutService?.SetActive(active: true);
		}
	}
}
