	public class NumberPickerSelectedItemTargetBinding : MvxTargetBinding
	{
		private class ValueChangedListener : Java.Lang.Object, NumberPicker.IOnValueChangeListener, IJavaObject, IDisposable, IJavaPeerable
		{
			private Action<object> fireValueChanged;

			public ValueChangedListener(Action<object> fireValueChanged)
			{
				this.fireValueChanged = fireValueChanged;
			}

			public void OnValueChange(NumberPicker picker, int oldVal, int newVal)
			{
				if (oldVal != newVal)
				{
					string[] displayedValues = picker.GetDisplayedValues();
					fireValueChanged?.Invoke(displayedValues[newVal]);
				}
			}

			protected override void Dispose(bool disposing)
			{
				fireValueChanged = null;
				base.Dispose(disposing);
			}
		}

		private ValueChangedListener valueChangedListener;

		private NumberPicker NumberPicker => (NumberPicker)base.Target;

		public override Type TargetType => typeof(object);

		public override MvxBindingMode DefaultMode => MvxBindingMode.TwoWay;

		public NumberPickerSelectedItemTargetBinding(object target)
			: base(target)
		{
			valueChangedListener = new ValueChangedListener(FireValueChanged);
			NumberPicker.SetOnValueChangedListener(valueChangedListener);
		}

		public override void SetValue(object value)
		{
			string text = value?.ToString();
			if (text == null)
			{
				return;
			}
			string[] displayedValues = NumberPicker.GetDisplayedValues();
			for (int i = 0; i < displayedValues.Length; i++)
			{
				if (displayedValues[i] == text)
				{
					NumberPicker.Value = i;
					break;
				}
			}
		}

		protected override void Dispose(bool isDisposing)
		{
			valueChangedListener?.Dispose();
			valueChangedListener = null;
			NumberPicker.SetOnValueChangedListener(null);
			base.Dispose(isDisposing);
		}
	}
