	public class SwipeTarget : GestureDetector.SimpleOnGestureListener, View.IOnTouchListener, IJavaObject, IDisposable, IJavaPeerable
	{
		private const string Tag = "SwipeTarget";

		private GestureDetector gestureDetector;

		private readonly Subject<object> _swipeLeft = new Subject<object>();

		private readonly Subject<object> _swipeRight = new Subject<object>();

		private bool captureTouch;

		private const int SWIPE_THRESHOLD = 40;

		private const int SWIPE_VELOCITY_THRESHOLD = 40;

		public IObservable<object> SwipeLeft => _swipeLeft;

		public IObservable<object> SwipeRight => _swipeRight;

		public SwipeTarget(View view, bool captureTouch)
		{
			view.SetOnTouchListener(this);
			gestureDetector = new GestureDetector(this);
			this.captureTouch = captureTouch;
		}

		public bool OnTouch(View v, MotionEvent e)
		{
			gestureDetector.OnTouchEvent(e);
			return captureTouch;
		}

		public override bool OnFling(MotionEvent e1, MotionEvent e2, float velocityX, float velocityY)
		{
			bool result = false;
			try
			{
				float value = e2.GetY() - e1.GetY();
				float num = e2.GetX() - e1.GetX();
				if (System.Math.Abs(num) <= System.Math.Abs(value))
				{
					return false;
				}
				if (System.Math.Abs(num) > 40f && System.Math.Abs(velocityX) <= 40f)
				{
					return false;
				}
				if (num < 0f)
				{
					_swipeLeft.OnNext(null);
				}
				else
				{
					_swipeRight.OnNext(null);
				}
				result = true;
			}
			catch (System.Exception exception)
			{
				iFit.Logger.Log.Error("SwipeTarget", "An error occurred in SwipeTarget.OnFling", exception);
			}
			return result;
		}
	}
	public abstract class BaseSwipeTargetBinding : MvxTargetBinding
	{
		protected ICommand _command;

		public override Type TargetType => typeof(ICommand);

		protected View View => (View)base.Target;

		public override MvxBindingMode DefaultMode => MvxBindingMode.OneWay;

		protected SwipeTarget SwipeTarget { get; set; }

		public BaseSwipeTargetBinding(View view, bool captureTouch)
			: base(view)
		{
			SwipeTarget = new SwipeTarget(view, captureTouch);
		}

		protected void RunCommand(bool left)
		{
			if (_command != null && _command.CanExecute(null))
			{
				_command.Execute(left);
			}
		}

		public override void SetValue(object value)
		{
			_command = value as ICommand;
		}
	}
	public class SwipeTargetBinding : BaseSwipeTargetBinding
	{
		protected enum TargetDirection
		{
			Left,
			Right,
			Both
		}

		private IDisposable leftSwipeListener;

		private IDisposable rightSwipeListener;

		public SwipeTargetBinding(View view)
			: base(view, captureTouch: false)
		{
			SetupTargetBinding(TargetDirection.Both);
		}

		protected SwipeTargetBinding(View view, bool captureInput, TargetDirection direction)
			: base(view, captureInput)
		{
			SetupTargetBinding(direction);
		}

		protected void SetupTargetBinding(TargetDirection direction)
		{
			if (direction == TargetDirection.Both || direction == TargetDirection.Left)
			{
				leftSwipeListener?.Dispose();
				leftSwipeListener = base.SwipeTarget.SwipeLeft.Subscribe(delegate
				{
					RunCommand(left: true);
				});
			}
			if (direction == TargetDirection.Both || direction == TargetDirection.Right)
			{
				rightSwipeListener?.Dispose();
				rightSwipeListener = base.SwipeTarget.SwipeRight.Subscribe(delegate
				{
					RunCommand(left: false);
				});
			}
		}

		protected override void Dispose(bool isDisposing)
		{
			base.Dispose(isDisposing);
			leftSwipeListener?.Dispose();
			leftSwipeListener = null;
			rightSwipeListener?.Dispose();
			rightSwipeListener = null;
		}
	}
	public class LeftSwipeTargetBinding : SwipeTargetBinding
	{
		public LeftSwipeTargetBinding(View view)
			: base(view, captureInput: true, TargetDirection.Left)
		{
		}
	}
	public class RightSwipeTargetBinding : SwipeTargetBinding
	{
		public RightSwipeTargetBinding(View view)
			: base(view, captureInput: true, TargetDirection.Right)
		{
		}
	}
