	public class TextColorFromColorTargetBinding : MvxTargetBinding
	{
		private IfitTextView IfitTextView => (IfitTextView)base.Target;

		public override Type TargetType => typeof(global::Android.Graphics.Color);

		public override MvxBindingMode DefaultMode => MvxBindingMode.OneWay;

		public TextColorFromColorTargetBinding(IfitTextView target)
			: base(target)
		{
			if (target == null)
			{
				throw new ArgumentNullException("target", "Object is not of type IfitTextView");
			}
		}

		public override void SetValue(object value)
		{
			if (value is global::Android.Graphics.Color textColor)
			{
				IfitTextView?.SetTextColor(textColor);
			}
		}
	}
	public class TextColorFromResourceTargetBinding : MvxTargetBinding
	{
		private readonly Context context;

		private IfitTextView IfitTextView => (IfitTextView)base.Target;

		public override Type TargetType => typeof(int);

		public override MvxBindingMode DefaultMode => MvxBindingMode.OneWay;

		public TextColorFromResourceTargetBinding(IfitTextView target, Context context)
			: base(target)
		{
			if (target == null)
			{
				throw new ArgumentNullException("target", "Object is not of type IfitTextView");
			}
			this.context = context;
		}

		public override void SetValue(object value)
		{
			int id = (int)value;
			global::Android.Graphics.Color textColor;
			try
			{
				int color = ResourcesCompat.GetColor(context.Resources, id, null);
				textColor = new global::Android.Graphics.Color(color);
			}
			catch (Resources.NotFoundException)
			{
				textColor = global::Android.Graphics.Color.DimGray;
			}
			IfitTextView?.SetTextColor(textColor);
		}
	}
}
namespace Wolf.Android.Webview
{
	public class AndroidWebviewHolderStore : BaseWebviewHolderStore, IWebviewHolderStore
	{
		private readonly System.Timers.Timer timer = new System.Timers.Timer(5000.0);

		public AndroidWebviewHolderStore(ICoreAnalytics coreAnalytics, ICrashReporter crashReporter)
			: base(coreAnalytics, crashReporter)
		{
			timer.Elapsed += delegate
			{
				TimerElapsedEvent();
			};
		}

		protected override IWebView CreateWebView()
		{
			return new ShireWebView(Application.Context);
		}

		protected override IWebView CreateAndLoadWebViewByUrl(string url)
		{
			ShireWebView shireWebView = new ShireWebView(Application.Context);
			if (!string.IsNullOrWhiteSpace(url))
			{
				shireWebView.LoadUrl(url);
			}
			return shireWebView;
		}

		protected override IWebView CreateAndLoadWebViewByHtml(string webviewHtml)
		{
			ShireWebView shireWebView = CreateAndLoadWebViewByUrl(string.Empty) as ShireWebView;
			if (!string.IsNullOrWhiteSpace(webviewHtml))
			{
				shireWebView.LoadDataWithBaseURL(null, webviewHtml, "text/html", null, null);
			}
			return shireWebView;
		}

		protected override void TimerStart()
		{
			timer.Start();
		}

		protected override void TimerStop()
		{
			timer.Stop();
		}

		public override void ClearWebViewCache()
		{
			foreach (KeyValuePair<string, WebviewHolder> item in base.Store.ToList())
			{
				try
				{
					(item.Value.WebView as ShireWebView)?.ClearCache(includeDiskFiles: true);
				}
				catch (ObjectDisposedException ex)
				{
					iFit.Logger.Log.Error("WebView", string.Format("Disposed object in {0}.{1}", this, "ClearWebViewCache"), ex);
					ex.Data.Add("WebviewKey", item.Key);
					ex.Data.Add("StoreObjectUrl", item.Value.Url);
					crashReporter.ReportError(ex.Message, ex, null);
				}
			}
			WebStorage.Instance.DeleteAllData();
		}
	}
}
namespace Wolf.Android.Adapters
{
	public class LazyLoadFragmentPagerAdapter : FragmentStatePagerAdapter
	{
		public class LazyLoadFragmentInfo
		{
			public Type FragmentType { get; set; }

			public Type ViewModelType { get; set; }

			public Func<BaseViewModel, System.Threading.Tasks.Task> Init { get; set; }

			public BaseLazyLoadFragment CachedFragment { get; set; }

			public LazyLoadFragmentInfo(Type fragmentType, Type viewModelType, Func<BaseViewModel, System.Threading.Tasks.Task> init = null)
			{
				FragmentType = fragmentType;
				ViewModelType = viewModelType;
				Init = init;
			}
		}

		public override int Count => Fragments.Count();

		public List<LazyLoadFragmentInfo> Fragments { get; private set; }

		public LazyLoadFragmentPagerAdapter(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public LazyLoadFragmentPagerAdapter(Context context, IEnumerable<LazyLoadFragmentInfo> fragments, AndroidX.Fragment.App.FragmentManager fm)
			: base(fm)
		{
			Fragments = fragments.ToList();
		}

		public void PopulateFragment(int index)
		{
			Fragments[index].CachedFragment.Populate();
		}

		public void PreCacheFragments()
		{
			foreach (LazyLoadFragmentInfo item in Fragments.Where((LazyLoadFragmentInfo fragInfo) => fragInfo.CachedFragment == null))
			{
				GenerateCachedFragment(item);
			}
		}

		public override AndroidX.Fragment.App.Fragment GetItem(int position)
		{
			LazyLoadFragmentInfo lazyLoadFragmentInfo = Fragments[position];
			if (lazyLoadFragmentInfo.CachedFragment == null && !GenerateCachedFragment(lazyLoadFragmentInfo))
			{
				return null;
			}
			return lazyLoadFragmentInfo.CachedFragment;
		}

		private static bool GenerateCachedFragment(LazyLoadFragmentInfo fragInfo)
		{
			fragInfo.CachedFragment = Activator.CreateInstance(fragInfo.FragmentType) as BaseLazyLoadFragment;
			if (fragInfo.CachedFragment == null)
			{
				return false;
			}
			MvxViewModelRequest request = new MvxViewModelRequest(fragInfo.ViewModelType, null, null, null);
			((IMvxView)fragInfo.CachedFragment).ViewModel = Mvx.Resolve<IMvxViewModelLoader>().LoadViewModel(request, null);
			fragInfo.Init?.Invoke(((IMvxView)fragInfo.CachedFragment).ViewModel as BaseViewModel);
			return true;
		}

		public override void RestoreState(IParcelable state, ClassLoader loader)
		{
		}

		protected override void Dispose(bool disposing)
		{
			Fragments?.Clear();
			Fragments = null;
			base.Dispose(disposing);
		}
	}
	public class LazyLoadViewPager : ViewPager
	{
		private ViewPagerSource source;

		public bool SmoothTransitions { get; set; } = true;

		public bool SwipeLocked { get; set; }

		public LazyLoadViewPager(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public LazyLoadViewPager(Context context)
			: base(context)
		{
		}

		public LazyLoadViewPager(Context context, IAttributeSet attrs)
			: base(context, attrs)
		{
		}

		public async Task<LazyLoadFragmentPagerAdapter> CreateAdapter(ViewPagerSource source, AndroidX.Fragment.App.FragmentManager fm)
		{
			this.source = source;
			LazyLoadFragmentPagerAdapter lazyLoadFragmentPagerAdapter = CreateAdapter(source, base.Context, fm);
			lazyLoadFragmentPagerAdapter.PreCacheFragments();
			return lazyLoadFragmentPagerAdapter;
		}

		public void BindAdapter(LazyLoadFragmentPagerAdapter adapter, AndroidX.Fragment.App.FragmentManager fm)
		{
			Adapter = adapter;
			base.PageSelected -= OnPageSelected;
			base.PageSelected += OnPageSelected;
			source.CurrentPage.Changed += SourcePageChanged;
		}

		private void OnPageSelected(object sender, PageSelectedEventArgs e)
		{
			source.CurrentPage.Value = e.Position;
		}

		private void SourcePageChanged(object sender, EventArgs e)
		{
			if (CurrentItem != source.CurrentPage.Value)
			{
				SetCurrentItem(source.CurrentPage.Value, SmoothTransitions);
			}
			(Adapter as LazyLoadFragmentPagerAdapter)?.PopulateFragment(CurrentItem);
		}

		private static LazyLoadFragmentPagerAdapter CreateAdapter(ViewPagerSource source, Context context, AndroidX.Fragment.App.FragmentManager fm)
		{
			List<LazyLoadFragmentPagerAdapter.LazyLoadFragmentInfo> list = new List<LazyLoadFragmentPagerAdapter.LazyLoadFragmentInfo>();
			if (Mvx.TryResolve<IViewTypeLookup>(out var service))
			{
				foreach (Type item in source)
				{
					Type fragmentType = service.GetFragmentType(item);
					if (fragmentType == null)
					{
						iFit.Logger.Log.Warn("MvxTrace", "LazyLoadViewPager: Could not find fragment type for VM: " + item.Name + "!!");
					}
					else
					{
						list.Add(new LazyLoadFragmentPagerAdapter.LazyLoadFragmentInfo(fragmentType, item));
					}
				}
			}
			else
			{
				iFit.Logger.Log.Warn("MvxTrace", "LazyLoadViewPager: Could not resolve ViewTypeLookup!!");
			}
			return new LazyLoadFragmentPagerAdapter(context, list, fm);
		}

		public override bool OnTouchEvent(MotionEvent? e)
		{
			if (!SwipeLocked)
			{
				return base.OnTouchEvent(e);
			}
			return false;
		}

		public override bool OnInterceptTouchEvent(MotionEvent? ev)
		{
			if (!SwipeLocked)
			{
				return base.OnInterceptTouchEvent(ev);
			}
			return false;
		}

		public override bool CanScrollHorizontally(int direction)
		{
			if (!SwipeLocked)
			{
				return base.CanScrollHorizontally(direction);
			}
			return false;
		}

		protected override void Dispose(bool disposing)
		{
			base.Dispose(disposing);
			base.PageSelected -= OnPageSelected;
			if (source?.CurrentPage != null)
			{
				source.CurrentPage.Changed -= SourcePageChanged;
			}
			source = null;
			Adapter = iFit.Extensions.Android.JavaExtensions.DisposeSafe(Adapter);
		}
	}
	public class MvxViewPagerFragmentAdapter : FragmentStatePagerAdapter
	{
		public class FragmentInfo
		{
			public Type FragmentType { get; set; }

			public Type ViewModelType { get; set; }

			public Func<BaseViewModel, System.Threading.Tasks.Task> Init { get; set; }

			public AndroidX.Fragment.App.Fragment CachedFragment { get; set; }

			public FragmentInfo(Type fragmentType, Type viewModelType, Func<BaseViewModel, System.Threading.Tasks.Task> init = null)
			{
				FragmentType = fragmentType;
				ViewModelType = viewModelType;
				Init = init;
			}
		}

		private readonly Context context;

		public override int Count => Fragments.Count();

		public List<FragmentInfo> Fragments { get; private set; }

		public event EventHandler ItemClicked;

		public MvxViewPagerFragmentAdapter(IntPtr javaReference, JniHandleOwnership transfer)
			: base(javaReference, transfer)
		{
		}

		public MvxViewPagerFragmentAdapter(Context context, IEnumerable<FragmentInfo> fragments, AndroidX.Fragment.App.FragmentManager fm)
			: base(fm)
		{
			this.context = context;
			Fragments = fragments.ToList();
		}

		public override AndroidX.Fragment.App.Fragment GetItem(int position)
		{
			FragmentInfo fragmentInfo = Fragments[position];
			if (fragmentInfo.CachedFragment == null)
			{
				fragmentInfo.CachedFragment = Activator.CreateInstance(fragmentInfo.FragmentType) as ShireFragment;
				if (fragmentInfo.CachedFragment == null)
				{
					return null;
				}
				MvxViewModelRequest request = new MvxViewModelRequest(fragmentInfo.ViewModelType, null, null, null);
				((IMvxView)fragmentInfo.CachedFragment).ViewModel = Mvx.Resolve<IMvxViewModelLoader>().LoadViewModel(request, null);
				fragmentInfo.Init?.Invoke(((IMvxView)fragmentInfo.CachedFragment).ViewModel as BaseViewModel);
			}
			if (fragmentInfo.CachedFragment is BaseClickableFragment baseClickableFragment)
			{
				baseClickableFragment.Click -= ViewPagerClicked;
				baseClickableFragment.Click += ViewPagerClicked;
			}
			return fragmentInfo.CachedFragment;
		}

		public void ViewPagerClicked(object sender, EventArgs e)
		{
			this.ItemClicked?.Invoke(sender, e);
		}

		protected virtual string FragmentJavaName(Type fragmentType)
		{
			string text = fragmentType.Namespace ?? "";
			if (text.Length > 0)
			{
				text = text.ToLowerInvariant() + ".";
			}
			return text + fragmentType.Name;
		}

		public override void RestoreState(IParcelable state, ClassLoader loader)
		{
		}
	}
}
